class SudoConductor {

    data class Next(val state: SudoState, val effects: List<Eff>)

    companion object {
        // Used only for bounded replans on protocol violations (missing reply / noop alone)
        private const val MAX_MISSING_REPLY_REPLANS = 2

        // Deterministic “never silent” heartbeat (A)
        private const val SURVIVAL_REPLY = "Sorry — I didn’t catch that clearly; could you please repeat?"
    }

    private fun emitWaveARegressionHookV1(
        hook: String,
        data: Map<String, Any?> = emptyMap()
    ) {
        val payload = linkedMapOf<String, Any?>(
            "type" to "WAVE_A_REGRESSION_HOOK_V1",
            "hook" to hook
        )
        data.forEach { (k, v) ->
            if (v != null) payload[k] = v
        }
        ConversationTelemetry.emit(payload)
    }


    // ============================================================
// BLOCK 1 — FULL REPLACEMENT (legacy-free)
// ============================================================

    private data class IntentResolved(
        val id: String,
        val type: IntentTypeV1,
        val confidence: Double,
        val missing: List<String>,
        val evidenceText: String?,
        val cell: String?,          // "r4c2"
        val cellIndex: Int?,        // 0..80
        val region: RegionRefV1?,   // ROW/COL/BOX + index
        val digit: Int?             // 0..9 (we accept 0 for clear when derived)
    )

    /**
     * Resolve convenience fields from IntentV1 using the new V1 models + compat accessors.
     * No legacy Meaning* types.
     */
    private fun resolveIntent(i: IntentV1): IntentResolved {
        val cell = i.targets.firstOrNull { !it.cell.isNullOrBlank() }?.cell?.trim()
        val idx = i.cellIndexOrNullCompat()
        val region = i.regionOrNullCompat()
        val digit = i.digitOrNullCompat()

        return IntentResolved(
            id = i.id,
            type = i.type,
            confidence = i.confidence,
            missing = i.missing,
            evidenceText = i.evidenceText,
            cell = cell,
            cellIndex = idx,
            region = region,
            digit = digit
        )
    }



    // -----------------------------------------------------------------
    // Local compat / JSON helper layer
    // -----------------------------------------------------------------

    private fun IntentV1.addressesUserAgendaIdCompat(): String? =
        this.addressesUserAgendaId?.trim()?.takeIf { it.isNotBlank() }

    private fun IntentV1.cellIndexOrNullCompat(): Int? =
        this.targets
            .asSequence()
            .mapNotNull { it.cell?.trim() }
            .mapNotNull { cellIndexOf(it) }
            .firstOrNull()

    private fun IntentV1.regionOrNullCompat(): RegionRefV1? =
        this.targets
            .asSequence()
            .mapNotNull { it.region }
            .firstOrNull()

    private fun IntentV1.digitOrNullCompat(): Int? =
        this.payload.digit
            ?: this.payload.digits?.firstOrNull()

    private fun mergedRepairCellIndexV1(
        s: SudoState,
        intent: IntentV1
    ): Int? = intent.cellIndexOrNullCompat() ?: ClarificationKernelV1.cellIndexHintFromPending(s.pending)

    private fun mergedRepairDigitV1(
        s: SudoState,
        intent: IntentV1
    ): Int? = intent.digitOrNullCompat() ?: ClarificationKernelV1.digitHintFromPending(s.pending)

    private fun IntentEnvelopeV1.isUnclearCompat(): Boolean =
        this.intents.isEmpty() &&
                this.freeTalkTopic.isNullOrBlank() &&
                this.freeTalkConfidence < 0.60


    private fun firstNonBlankStringV1(vararg values: String?): String? =
        values.firstOrNull { !it.isNullOrBlank() }?.trim()?.takeIf { it.isNotEmpty() }

    // -----------------------------------------------------------------
    // Phase 1 — Detour routing seam (classification only; no payload changes)
    // -----------------------------------------------------------------

    private data class DetourRoutingSnapshotV1(
        val isAssistantQuestionFollowup: Boolean = false,
        val isRouteFollowing: Boolean = false,
        val isRouteControl: Boolean = false,
        val detourQuestionClass: DetourQuestionClassV1? = null,
        val proofChallengeLaneHint: DetourProofChallengeLaneV1? = null,
        val solvingRoadSemantic: SolvingRoadSemanticV2? = null,
        val topIntentType: IntentTypeV1? = null
    )

    private fun classifyDetourRoutingSnapshotV1(
        env: IntentEnvelopeV1,
        bindRes: com.contextionary.sudoku.conductor.policy.IntentBinderV1.BindResult
    ): DetourRoutingSnapshotV1 =
        DetourRoutingSnapshotV1(
            isAssistantQuestionFollowup = bindRes.diag.didBindAssistantQuestionFollowup,
            isRouteFollowing = bindRes.diag.isRouteFollowingIntent,
            isRouteControl = bindRes.diag.isRouteControlIntent,
            detourQuestionClass = bindRes.diag.detourQuestionClass,
            proofChallengeLaneHint = bindRes.diag.proofChallengeLaneHint,
            solvingRoadSemantic = bindRes.diag.solvingRoadSemantic,
            topIntentType = env.intents.firstOrNull()?.type
        )



    private fun detourVisualPrimaryFocusCellV1(
        ctx: DetourNarrativeContextV1?
    ): String? =
        ctx?.visualContract?.focusCell?.trim()?.takeIf { it.isNotEmpty() }
            ?: ctx?.visualContract?.primaryCells?.firstOrNull()?.cellRef?.trim()?.takeIf { it.isNotEmpty() }

    private fun detourVisualSecondaryFocusCellsV1(
        ctx: DetourNarrativeContextV1?
    ): List<String> =
        ctx?.visualContract?.secondaryCells
            ?.map { it.cellRef.trim() }
            ?.filter { it.isNotEmpty() }
            ?.distinct()
            ?: emptyList()

    private fun detourVisualStoryKindV1(
        ctx: DetourNarrativeContextV1?
    ): String? =
        ctx?.visualContract?.storyKind?.trim()?.takeIf { it.isNotEmpty() }

    private fun detourVisualHouseRefsV1(
        ctx: DetourNarrativeContextV1?
    ): List<String> =
        ctx?.visualContract?.houses
            ?.map { it.houseRef.trim() }
            ?.filter { it.isNotEmpty() }
            ?.distinct()
            ?: emptyList()

    private fun detourVisualDefaultLayersV1(
        ctx: DetourNarrativeContextV1?
    ): List<String> =
        ctx?.visualContract?.defaultAppliedLayers
            ?.map { it.trim() }
            ?.filter { it.isNotEmpty() }
            ?.distinct()
            ?: emptyList()

    private fun detourVisualAvailableLayersV1(
        ctx: DetourNarrativeContextV1?
    ): List<String> =
        ctx?.visualContract?.availableLayers
            ?.map { it.trim() }
            ?.filter { it.isNotEmpty() }
            ?.distinct()
            ?: emptyList()

    private fun detourGenericFallbackFocusCellV1(
        ctx: DetourNarrativeContextV1?
    ): String? =
        ctx?.dominantAtom
            ?.focusCells
            ?.firstOrNull { it.isNotBlank() }
            ?.trim()
            ?.takeIf { it.isNotEmpty() }

    private fun detourGenericFallbackHouseRefsV1(
        ctx: DetourNarrativeContextV1?
    ): List<String> =
        ctx?.dominantAtom
            ?.focusHouses
            ?.map { it.trim() }
            ?.filter { it.isNotEmpty() }
            ?.distinct()
            ?: emptyList()


    private fun choosePrimaryDetourFocusCellV1(
        ctx: DetourNarrativeContextV1?
    ): String? {
        if (ctx == null) return null

        detourVisualPrimaryFocusCellV1(ctx)?.let { return it }

        val policyPrimary =
            ctx.overlayPolicy.primaryFocusCells
                .firstOrNull { it.isNotBlank() }
                ?.trim()
                ?.takeIf { it.isNotEmpty() }

        if (policyPrimary != null) return policyPrimary

        return detourGenericFallbackFocusCellV1(ctx)
    }



    private fun chooseSecondaryDetourFocusCellsV1(
        ctx: DetourNarrativeContextV1?
    ): List<String> {
        if (ctx == null) return emptyList()

        val fromVisual = detourVisualSecondaryFocusCellsV1(ctx)
        if (fromVisual.isNotEmpty()) return fromVisual

        val fromPolicy =
            ctx.overlayPolicy.secondaryFocusCells
                .map { it.trim() }
                .filter { it.isNotEmpty() }
                .distinct()

        if (fromPolicy.isNotEmpty()) return fromPolicy

        return emptyList()
    }



    private fun detourOverlayStoryKindV1(
        ctx: DetourNarrativeContextV1?
    ): String? {
        if (ctx == null) return null

        detourVisualStoryKindV1(ctx)?.let { return it }

        val fromPolicy = firstNonBlankStringV1(ctx.overlayPolicy.expectedSpokenAnchor)
        if (!fromPolicy.isNullOrBlank() && fromPolicy.startsWith("move_proof:", ignoreCase = true)) {
            return fromPolicy.removePrefix("move_proof:").trim().uppercase()
        }

        return null
    }



    private fun detourNativeOverlayFrameIdsV1(
        state: SudoState,
        ctx: DetourNarrativeContextV1?
    ): List<String> {
        if (ctx == null) return emptyList()

        val fromVisualDefault = detourVisualDefaultLayersV1(ctx)
        if (fromVisualDefault.isNotEmpty()) return fromVisualDefault

        val fromVisualAvailable = detourVisualAvailableLayersV1(ctx)
        if (fromVisualAvailable.isNotEmpty()) return fromVisualAvailable

        val hasPrimary =
            !choosePrimaryDetourFocusCellV1(ctx).isNullOrBlank()

        val hasSecondary =
            chooseSecondaryDetourFocusCellsV1(ctx).isNotEmpty()

        val hasHouses =
            detourVisualHouseRefsV1(ctx).isNotEmpty() ||
                    ctx.overlayPolicy.primaryFocusHouses.any { it.isNotBlank() } ||
                    detourGenericFallbackHouseRefsV1(ctx).isNotEmpty()

        val hasDeemphasis =
            ctx.visualContract.deemphasizeCells.isNotEmpty() ||
                    ctx.overlayPolicy.deemphasizeCells.any { it.isNotBlank() }

        val ordered = linkedSetOf<String>()
        ordered += "detour:native"
        if (hasPrimary) ordered += "detour:primary"
        if (hasSecondary) ordered += "detour:secondary"
        if (hasHouses) ordered += "detour:houses"
        if (hasDeemphasis) ordered += "detour:deemphasize"

        return ordered.toList()
    }



    private fun parseDetourHouseRefForOverlayV1(raw: String?): Pair<String, Int>? {
        val s = raw?.trim()?.lowercase() ?: return null
        if (s.isBlank()) return null

        Regex("""^row\s*([1-9])$""").matchEntire(s)?.let {
            val idx = it.groupValues[1].toIntOrNull() ?: return null
            return "row" to idx
        }

        Regex("""^(col|column)\s*([1-9])$""").matchEntire(s)?.let {
            val idx = it.groupValues[2].toIntOrNull() ?: return null
            return "col" to idx
        }

        Regex("""^box\s*([1-9])$""").matchEntire(s)?.let {
            val idx = it.groupValues[1].toIntOrNull() ?: return null
            return "box" to idx
        }

        return null
    }

    private fun activeDetourClarificationCarryV1(
        s: SudoState
    ): UserAgendaItem.Clarification? =
        (s.userAgendaQueue.firstOrNull() as? UserAgendaItem.Clarification)
            ?.takeIf { it.detourQuestionClass != null }

    private fun buildDetourStateScaffoldV1(
        s: SudoState,
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): DetourStateV1? {
        val clarificationCarry = activeDetourClarificationCarryV1(s)

        val rawQuestionClass =
            agendaMaterializationClassFromIntentFamilyV1(
                s = s,
                env = env,
                routing = routing
            ) ?: if (routing.isRouteControl) DetourQuestionClassV1.ROUTE_CONTROL else null
                ?: routing.detourQuestionClass
                ?: clarificationCarry?.detourQuestionClass
                ?: return null

        val forceProofChallenge =
            env.intents.any {
                it.type == IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT
            }

        val questionClass =
            if (forceProofChallenge) DetourQuestionClassV1.PROOF_CHALLENGE
            else rawQuestionClass

        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "PHASE_AWARE_DETOUR_STATE_SCAFFOLD_V1",
                data = mapOf(
                    "turn_id" to s.turnSeq,
                    "phase" to demandRoutingPhaseV1(s).name,
                    "routing_detour_question_class" to (routing.detourQuestionClass?.name ?: "null"),
                    "materialized_detour_question_class" to (questionClass?.name ?: "null")
                )
            )
        }

        fun firstExplicitCellTarget(): String? =
            env.intents.asSequence()
                .flatMap { it.targets.asSequence() }
                .mapNotNull { it.cell?.trim() }
                .firstOrNull { it.isNotBlank() }

        fun firstExplicitDigitTarget(): Int? =
            env.intents.asSequence()
                .mapNotNull { it.digitOrNullCompat() }
                .firstOrNull()

        fun firstTechniqueHint(): String? =
            null

        fun firstSearchScopeHint(): String? =
            firstExplicitRegionRefV1(env)

        val requestedCell =
            firstExplicitCellTarget() ?: clarificationCarry?.carriedCellRef

        val requestedDigit =
            firstExplicitDigitTarget() ?: clarificationCarry?.carriedDigit

        val requestedTechniqueIdOrLabel =
            firstTechniqueHint() ?: clarificationCarry?.carriedTechniqueLabel

        val requestedSearchScope =
            firstSearchScopeHint() ?: clarificationCarry?.carriedRegionRef

        val checkpoint = s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s)
        val pausedFrames =
            checkpoint?.overlayFrameIds?.takeIf { it.isNotEmpty() }
                ?: currentAppliedOverlayFrameIdsOrNull(s).orEmpty()

        val wantsResumePausedRoute = wantsResumePausedRouteV1(env)
        val failedDetourAwaitingRecovery =
            s.detourState?.answerState == DetourAnswerStateV1.FAILED_AWAITING_RECOVERY

        return when {
            questionClass != null -> {
                val base = DetourStateV1(
                    isActive = questionClass != DetourQuestionClassV1.ROUTE_CONTROL,
                    questionClass = questionClass,
                    semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                    answerState = DetourAnswerStateV1.ACTIVE_UNANSWERED,
                    answerFailureReason = null,
                    answeredTurnSeq = null,
                    failedTurnSeq = null,
                    failureRecoveryDecision = DetourFailureRecoveryDecisionV1.NONE,
                    failureRecoveryDecisionTurnSeq = null,
                    anchorStepId = checkpoint?.stepId ?: s.activeRouteContext?.stepId,
                    anchorStage = checkpoint?.storyStage ?: s.narrativeStory?.stage,
                    anchorTargetCell =
                        checkpoint?.targetCellIndex?.let { indexToCell(it) }
                            ?: readSolveStepTargetOrFocusCellV1(s),
                    anchorTechniqueId = checkpoint?.techniqueId ?: s.activeRouteContext?.techniqueId,
                    requestedCell = requestedCell,
                    requestedDigit = requestedDigit,
                    requestedTechniqueIdOrLabel = requestedTechniqueIdOrLabel,
                    requestedSearchScope = requestedSearchScope,
                    pausedStoryAppliedFrameIds = pausedFrames,
                    detourTurnCount = (s.detourState?.detourTurnCount ?: 0) + 1,
                    returnHint =
                        checkpoint?.resumePromptHint
                            ?: when (s.narrativeStory?.stage) {
                                StoryStage.SETUP -> "return_to_setup"
                                StoryStage.CONFRONTATION -> "return_to_confrontation"
                                StoryStage.RESOLUTION -> "return_to_resolution"
                                null -> null
                            }
                )

                val detourFrames = chooseDetourOverlayFrameIdsV1(
                    state = s,
                    nativeCtx = s.detourNarrativeContextV1,
                    restoredCheckpointFrameIds = pausedFrames
                )
                base.copy(detourAppliedFrameIds = detourFrames)
            }

            routing.isRouteFollowing -> s.detourState?.copy(
                isActive = false,
                requestedCell = null,
                requestedDigit = null,
                requestedTechniqueIdOrLabel = null,
                requestedSearchScope = null,
                pendingSolverQueryId = null,
                pendingSolverQueryOp = null,
                detourAppliedFrameIds = emptyList(),
                detourTurnCount = 0,
                answerFailureReason = null,
                failureRecoveryDecision =
                    if (failedDetourAwaitingRecovery || wantsResumePausedRoute) {
                        DetourFailureRecoveryDecisionV1.RETIRE_AND_RESUME
                    } else {
                        DetourFailureRecoveryDecisionV1.NONE
                    },
                failureRecoveryDecisionTurnSeq =
                    if (failedDetourAwaitingRecovery || wantsResumePausedRoute) s.turnSeq else null
            )

            failedDetourAwaitingRecovery -> s.detourState?.copy(
                failureRecoveryDecision = DetourFailureRecoveryDecisionV1.RETRY_DETOUR,
                failureRecoveryDecisionTurnSeq = s.turnSeq
            )

            else -> s.detourState
        }
    }

    private fun chooseDetourOverlayFrameIdsV1(
        state: SudoState,
        nativeCtx: DetourNarrativeContextV1?,
        restoredCheckpointFrameIds: List<String> = emptyList()
    ): List<String> {
        val nativeFrames = detourOverlayFrameIdsFromNativeContextV1(state, nativeCtx)
        val restored = restoredCheckpointFrameIds.filter { it.isNotBlank() }.distinct()
        val current =
            currentAppliedOverlayFrameIdsOrNull(state)
                .orEmpty()
                .filter { it.isNotBlank() }
                .distinct()

        val routeFrames =
            state.routeCheckpointV1?.overlayFrameIds
                ?.map { it.trim() }
                ?.filter { it.isNotBlank() }
                ?.distinct()
                .orEmpty()

        val activeDetour = state.detourState?.isActive == true
        val overlayMode = nativeCtx?.overlayPolicy?.overlayMode

        if (activeDetour && nativeCtx != null) {
            if (nativeFrames.isNotEmpty()) {
                return nativeFrames
            }

            return when (overlayMode) {
                DetourOverlayModeV1.PRESERVE -> {
                    when {
                        restored.isNotEmpty() -> restored
                        current.isNotEmpty() -> current
                        routeFrames.isNotEmpty() -> routeFrames
                        else -> emptyList()
                    }
                }

                DetourOverlayModeV1.CLEAR,
                DetourOverlayModeV1.REPLACE,
                DetourOverlayModeV1.AUGMENT,
                null -> {
                    emptyList()
                }
            }
        }

        if (nativeFrames.isNotEmpty()) {
            return nativeFrames
        }

        if (restored.isNotEmpty()) {
            return restored
        }

        if (current.isNotEmpty()) {
            return current
        }

        if (routeFrames.isNotEmpty()) {
            return routeFrames
        }

        return emptyList()
    }

    private fun applyDetourOverlayOverrideToStateV1(
        s: SudoState
    ): SudoState {
        val ds = s.detourState ?: return s
        if (!ds.isActive) return s

        val detourFrames = ds.detourAppliedFrameIds
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .distinct()

        if (detourFrames.isEmpty()) return s

        val rewritten = rewriteSolvingPacketAppliedFramesV1(
            bundles = s.solvingReadyFactBundlesV1,
            appliedFrameIds = detourFrames
        )

        val overlayOwnerAfter =
            if (s.pending is Pending.UserAgendaBridge) {
                OverlayOwnerV1.USER_OWNER
            } else {
                s.activeOverlayOwnerV1
            }

        return syncCanonicalSolvingPositionV1(
            s.copy(
                solvingReadyFactBundlesV1 = rewritten,
                activeAppliedOverlayFrameIdsV1 = detourFrames,
                activeOverlayOwnerV1 = overlayOwnerAfter,
                activeOverlayReasonV1 = "detour_native_overlay_authority"
            )
        )
    }

