    private data class DetourSolverQuerySpecV1(
        val queryId: String,
        val op: String,
        val payloadJson: String,
        val reason: String
    )

    private fun hasSolverBackedDetourFactsV1(facts: List<FactBundleV1>): Boolean =
        facts.any {
            it.type == FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_CELLS_CANDIDATES_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_HOUSE_CANDIDATE_MAP_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_REASONING_CHECK_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_ALTERNATIVE_TECHNIQUE_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_TECHNIQUE_SCOPE_CHECK_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_LOCAL_MOVE_SEARCH_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_ROUTE_COMPARISON_PACKET_V1 ||
                    it.type == FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1
        }

    private fun solverBackedDetourFactTypeNamesV1(facts: List<FactBundleV1>): String =
        facts.asSequence()
            .map { it.type }
            .filter {
                it == FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_CELLS_CANDIDATES_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_HOUSE_CANDIDATE_MAP_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_REASONING_CHECK_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_ALTERNATIVE_TECHNIQUE_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_TECHNIQUE_SCOPE_CHECK_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_LOCAL_MOVE_SEARCH_PACKET_V1 ||
                        it == FactBundleV1.Type.SOLVER_ROUTE_COMPARISON_PACKET_V1
            }
            .map { it.name }
            .distinct()
            .joinToString(",")

    private fun readSolveStepTargetOrFocusCellV1(s: SudoState): String? {
        val stepObj = runCatching { s.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val targetCell = stepObj?.optString("target_cell")?.trim().orEmpty()
        if (targetCell.isNotBlank()) return targetCell
        val focusCell = stepObj?.optString("focus_cell")?.trim().orEmpty()
        if (focusCell.isNotBlank()) return focusCell
        return null
    }

    private fun readSolveStepTargetOrFocusDigitV1(s: SudoState): Int? {
        val stepObj = runCatching { s.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val targetDigit = stepObj?.optInt("target_digit", -1)?.takeIf { it in 1..9 }
        if (targetDigit != null) return targetDigit
        return stepObj?.optInt("focus_digit", -1)?.takeIf { it in 1..9 }
    }

    private fun buildDetourSolverQuerySpecV1(
        s: SudoState
    ): DetourSolverQuerySpecV1? {
        val ds = s.detourState ?: return null
        if (!ds.isActive) return null
        if (!ds.pendingSolverQueryId.isNullOrBlank()) return null

        val grid81Now = s.grid?.llm?.let { grid81FromLLM(it) } ?: return null
        val routingPhase = demandRoutingPhaseV1(s)

        // Wave 1 / Series 4:
        // Detour clarification admission is now delegated to ClarificationKernelV1.
        // Important rule: proof-like detours must not be admitted on anchor carry alone.
        // A vague utterance such as "why is 7" must clarify instead of silently borrowing
        // the paused step target / prior detour anchor and turning into a proof challenge.

        val explicitRequestedCell = ds.requestedCell?.takeIf { it.isNotBlank() }
        val requestedDigit = ds.requestedDigit ?: readSolveStepTargetOrFocusDigitV1(s)

        val authoritativeQuestionClass = ds.questionClass

        val queryId = "dq:${s.turnSeq}:${authoritativeQuestionClass?.name ?: "UNKNOWN"}"

        if (routingPhase != GridPhase.SOLVING &&
            isSolvingNativeDetourQuestionClassV1(authoritativeQuestionClass)
        ) {
            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "PHASE_GATED_DETOUR_SOLVER_QUERY_SUPPRESSED_V1",
                    data = mapOf(
                        "turn_id" to s.turnSeq,
                        "phase" to routingPhase.name,
                        "question_class" to (authoritativeQuestionClass?.name ?: "null"),
                        "reason" to "solving_native_detour_query_suppressed_outside_solving"
                    )
                )
            }
            return null
        }

        val proofAskKind = ds.proofAskKind
        val proofChallengeLane = ds.proofLaneHint
        val proofChallengeRivalCell = ds.proofRivalCellRef
        val proofChallengeRivalDigit = ds.proofRivalDigit
        val proofChallengeClaimedTechniqueId = ds.proofClaimedTechniqueId
        val proofChallengeObjectHint = ds.proofObjectHint

        val targetAskKind = ds.targetAskKind
        val candidateAskKind = ds.candidateAskKind
        val neighborAskKind = ds.neighborAskKind

        val preferredHouseRefText =
            ds.requestedSearchScope?.takeIf { it.isNotBlank() }

        val preferredHouseRefJson = houseRefJsonFromTextV1(preferredHouseRefText)

        val isHouseScopedMoveProof =
            authoritativeQuestionClass == DetourQuestionClassV1.PROOF_CHALLENGE &&
                    preferredHouseRefJson != null &&
                    (
                            proofAskKind == ProofChallengeAskKindV1.WHERE_DIGIT_CAN_STILL_GO_IN_HOUSE ||
                                    proofAskKind == ProofChallengeAskKindV1.WHAT_BLOCKS_DIGIT_IN_HOUSE ||
                                    proofAskKind == ProofChallengeAskKindV1.WHY_ONLY_PLACE ||
                                    proofAskKind == ProofChallengeAskKindV1.WHY_THIS_NOT_THAT ||
                                    proofChallengeLane == DetourProofChallengeLaneV1.HOUSE_BLOCKER ||
                                    proofChallengeLane == DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS ||
                                    proofChallengeLane == DetourProofChallengeLaneV1.CANDIDATE_POSSIBILITY ||
                                    proofChallengeLane == DetourProofChallengeLaneV1.CANDIDATE_IMPOSSIBILITY
                            )

        val requestedCell =
            when {
                isHouseScopedMoveProof -> explicitRequestedCell
                else -> explicitRequestedCell
            }
        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "DETOUR_F10R_ROUTING_INPUT_V1",
                data = mapOf(

                    "turn_id" to s.turnSeq,
                    "phase" to routingPhase.name,
                    "question_class" to (authoritativeQuestionClass?.name ?: "null"),
                    "detour_state_question_class" to (ds.questionClass?.name ?: "null"),
                    "requested_cell" to (requestedCell ?: "null"),


                    "requested_digit" to (requestedDigit ?: -1),
                    "proof_ask_kind" to (proofAskKind?.name ?: "null"),
                    "proof_challenge_lane" to (proofChallengeLane?.name ?: "null"),
                    "target_ask_kind" to (targetAskKind?.name ?: "null"),
                    "candidate_ask_kind" to (candidateAskKind?.name ?: "null"),
                    "neighbor_ask_kind" to (neighborAskKind?.name ?: "null"),
                    "preferred_house_ref_text" to (preferredHouseRefText ?: "null")
                )
            )
        }

        return when (authoritativeQuestionClass) {
            DetourQuestionClassV1.PROOF_CHALLENGE,
            DetourQuestionClassV1.TARGET_CELL_QUERY -> {
                val requiresCellScopedMoveProof =
                    authoritativeQuestionClass == DetourQuestionClassV1.TARGET_CELL_QUERY ||
                            (authoritativeQuestionClass == DetourQuestionClassV1.PROOF_CHALLENGE && preferredHouseRefJson == null)

                if (requiresCellScopedMoveProof && requestedCell.isNullOrBlank()) return null
                if (!requiresCellScopedMoveProof && requestedDigit == null) return null

                val profile =
                    when (authoritativeQuestionClass) {
                        DetourQuestionClassV1.TARGET_CELL_QUERY ->
                            when (targetAskKind) {
                                TargetCellAskKindV1.WHAT_CHANGED_IN_TARGET -> "TARGET_BEFORE_AFTER"
                                TargetCellAskKindV1.WHAT_REMAINS_IN_TARGET -> "TARGET_BEFORE_AFTER"
                                TargetCellAskKindV1.IS_ONLY_PLACE_FOR_DIGIT -> "ONLY_PLACE_FOR_DIGIT_IN_HOUSE"
                                TargetCellAskKindV1.FINAL_SURVIVING_CANDIDATE -> "WHY_DIGIT"
                                else -> "WHY_TARGET"
                            }

                        else ->
                            when {
                                proofAskKind == ProofChallengeAskKindV1.WHERE_DIGIT_CAN_STILL_GO_IN_HOUSE ->
                                    "DIGIT_LOCATIONS_IN_HOUSE"

                                proofAskKind == ProofChallengeAskKindV1.WHY_ONLY_PLACE ->
                                    "ONLY_PLACE_FOR_DIGIT_IN_HOUSE"

                                proofAskKind == ProofChallengeAskKindV1.WHY_THIS_NOT_THAT ->
                                    "RIVAL_COMPARISON_IN_HOUSE"

                                proofAskKind == ProofChallengeAskKindV1.WHY_TECHNIQUE_APPLIES ->
                                    "TECHNIQUE_LEGITIMACY"

                                proofAskKind == ProofChallengeAskKindV1.WHY_CURRENT_MOVE_BEFORE_OTHER_MOVE ->
                                    "ROUTE_PRIORITY_COMPARISON"

                                proofAskKind == ProofChallengeAskKindV1.WHY_THIS_TARGET ->
                                    "WHY_TARGET"

                                proofChallengeLane == DetourProofChallengeLaneV1.CANDIDATE_POSSIBILITY ->
                                    "WHY_DIGIT"

                                proofChallengeLane == DetourProofChallengeLaneV1.HOUSE_BLOCKER ->
                                    "HOUSE_BLOCKERS"

                                proofChallengeLane == DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS && preferredHouseRefJson != null ->
                                    "DIGIT_LOCATIONS_IN_HOUSE"

                                proofChallengeLane == DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS ->
                                    "WHY_DIGIT"

                                else ->
                                    when (proofAskKind) {
                                        ProofChallengeAskKindV1.WHY_NOT_DIGIT -> "WHY_NOT_DIGIT"
                                        ProofChallengeAskKindV1.WHY_DIGIT -> "WHY_DIGIT"
                                        ProofChallengeAskKindV1.WHAT_BLOCKS_DIGIT_IN_HOUSE -> "HOUSE_BLOCKERS"
                                        else -> if (requestedDigit != null) "WHY_NOT_DIGIT" else "PROVE_ELIMINATION"
                                    }
                            }
                    }

                val payload = JSONObject().apply {
                    put("op", "normalize_detour_query")
                    put("grid81", grid81Now)
                    put(
                        "query",
                        JSONObject().apply {

                            put("query_family", "MOVE_PROOF")
                            put("query_profile", profile)
                            put("user_ask_kind", authoritativeQuestionClass?.name ?: JSONObject.NULL)
                            put("user_question", s.lastUserText ?: JSONObject.NULL)

                            put("challenge_lane", proofChallengeLane?.name ?: JSONObject.NULL)
                            put("proof_ask_kind", proofAskKind?.name ?: JSONObject.NULL)
                            put("proof_object_hint", proofChallengeObjectHint ?: JSONObject.NULL)
                            put("rival_cell", proofChallengeRivalCell ?: JSONObject.NULL)
                            put("rival_digit", proofChallengeRivalDigit ?: JSONObject.NULL)
                            put("claimed_technique_id", proofChallengeClaimedTechniqueId ?: JSONObject.NULL)

                            put("requested_cell", requestedCell ?: JSONObject.NULL)
                            put("requested_digit", requestedDigit ?: JSONObject.NULL)
                            if (preferredHouseRefJson != null) {
                                put("house", preferredHouseRefJson)
                            }

                            put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                            put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                            put("anchor_target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                            put("anchor_target_digit", requestedDigit ?: JSONObject.NULL)
                            put("anchor_technique_id", ds.anchorTechniqueId ?: JSONObject.NULL)

                            put("paused_route_checkpoint_id", "detour:${s.turnSeq}")
                        }
                    )
                }.toString()

                DetourSolverQuerySpecV1(
                    queryId = queryId,
                    op = "normalize_detour_query",
                    payloadJson = payload,
                    reason = when (authoritativeQuestionClass) {
                        DetourQuestionClassV1.TARGET_CELL_QUERY ->
                            "normalized_detour_move_proof_target_cell_query"
                        else ->
                            "normalized_detour_move_proof_challenge"
                    }
                )
            }

            DetourQuestionClassV1.NEIGHBOR_CELL_QUERY,
            DetourQuestionClassV1.CANDIDATE_STATE_QUERY -> {
                val payload = JSONObject().apply {
                    put("op", "normalize_detour_query")
                    put("grid81", grid81Now)
                    put(
                        "query",
                        JSONObject().apply {
                            put("query_family", "LOCAL_INSPECTION")


                            put(
                                "query_profile",
                                when (authoritativeQuestionClass) {
                                    DetourQuestionClassV1.NEIGHBOR_CELL_QUERY ->
                                        when (neighborAskKind) {
                                            NeighborAskKindV1.STAY_IN_REGION -> "TARGET_NEIGHBORHOOD"
                                            NeighborAskKindV1.LOCAL_MOVE_SEARCH -> "LOCAL_EFFECTS"
                                            NeighborAskKindV1.COMPARE_CANDIDATES -> "COMPARE_CANDIDATES"
                                            else -> "NEARBY_CELL_STATUS"
                                        }

                                    else ->
                                        when (candidateAskKind) {
                                            CandidateAskKindV1.DIGIT_LOCATIONS_IN_HOUSE -> "DIGIT_LOCATIONS"
                                            CandidateAskKindV1.HOUSE_CANDIDATE_MAP -> "HOUSE_CANDIDATE_MAP"
                                            CandidateAskKindV1.CANDIDATE_CHANGES -> "LOCAL_EFFECTS"
                                            else -> if (!requestedCell.isNullOrBlank()) "CELL_CANDIDATES" else "TARGET_NEIGHBORHOOD"
                                        }
                                }
                            )


                            put("user_ask_kind", authoritativeQuestionClass?.name ?: JSONObject.NULL)
                            put("user_question", s.lastUserText ?: JSONObject.NULL)

                            put("requested_cell", requestedCell ?: JSONObject.NULL)
                            put("requested_digit", requestedDigit ?: JSONObject.NULL)

                            put(
                                "compare_cell",
                                when {
                                    neighborAskKind == NeighborAskKindV1.COMPARE_CANDIDATES ->
                                        ds.anchorTargetCell ?: JSONObject.NULL
                                    else ->
                                        JSONObject.NULL
                                }
                            )

                            put(
                                "scope_kind",
                                when {
                                    preferredHouseRefJson != null -> "HOUSE"
                                    !requestedCell.isNullOrBlank() -> "CELL"
                                    else -> JSONObject.NULL
                                }
                            )
                            put(
                                "scope_ref",
                                when {
                                    preferredHouseRefText != null -> preferredHouseRefText
                                    !requestedCell.isNullOrBlank() -> requestedCell
                                    else -> JSONObject.NULL
                                }
                            )
                            if (preferredHouseRefJson != null) {
                                put("house", preferredHouseRefJson)
                            }

                            put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                            put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                            put("anchor_target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                            put("anchor_target_digit", requestedDigit ?: JSONObject.NULL)
                            put("anchor_technique_id", ds.anchorTechniqueId ?: JSONObject.NULL)

                            put("paused_route_checkpoint_id", "detour:${s.turnSeq}")
                        }
                    )
                }.toString()

                DetourSolverQuerySpecV1(
                    queryId = queryId,
                    op = "normalize_detour_query",
                    payloadJson = payload,
                    reason = when (authoritativeQuestionClass) {
                        DetourQuestionClassV1.NEIGHBOR_CELL_QUERY ->
                            "normalized_detour_local_inspection_neighbor_query"
                        else ->
                            "normalized_detour_local_inspection_candidate_state_query"
                    }
                )
            }

            DetourQuestionClassV1.USER_REASONING_CHECK -> {
                val cell = requestedCell ?: return null

                val claimedDigits = runCatching {
                    val raw = userTextDigitsFromLastUserTurnV1(s)
                    JSONArray().apply { raw.forEach { put(it) } }
                }.getOrElse { JSONArray() }

                val payload = JSONObject().apply {
                    put("op", "normalize_detour_query")
                    put("grid81", grid81Now)
                    put(
                        "query",
                        JSONObject().apply {
                            put("query_family", "PROPOSAL_VERDICT")
                            put("query_profile", "GENERAL_REASONING_CHECK")
                            put("user_ask_kind", authoritativeQuestionClass?.name ?: JSONObject.NULL)
                            put("user_question", s.lastUserText ?: JSONObject.NULL)

                            put("requested_cell", cell)
                            put("claimed_digits", claimedDigits)
                            put("proposal_text", s.lastUserText ?: JSONObject.NULL)

                            put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                            put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                            put("anchor_target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                            put("anchor_target_digit", requestedDigit ?: JSONObject.NULL)
                            put("anchor_technique_id", ds.anchorTechniqueId ?: JSONObject.NULL)

                            put("paused_route_checkpoint_id", "detour:${s.turnSeq}")
                        }
                    )
                }.toString()

                DetourSolverQuerySpecV1(
                    queryId = queryId,
                    op = "normalize_detour_query",
                    payloadJson = payload,
                    reason = "normalized_detour_proposal_verdict"
                )
            }

            DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY -> {
                val techniqueHint = ds.requestedTechniqueIdOrLabel?.takeIf { it.isNotBlank() }
                val scope = JSONObject().apply {
                    when {
                        !requestedCell.isNullOrBlank() -> {
                            put("type", "cell")
                            put("cell", requestedCell)
                        }
                        ds.anchorTargetCell?.isNotBlank() == true -> {
                            put("type", "cell")
                            put("cell", ds.anchorTargetCell)
                        }
                        else -> {
                            put("type", "global")
                        }
                    }
                }

                val op = if (techniqueHint != null) {
                    "check_technique_in_scope"
                } else {
                    "compare_current_route_to_scope"
                }

                val payload = JSONObject().apply {
                    put("op", op)
                    put("grid81", grid81Now)
                    put(
                        "query",
                        JSONObject().apply {
                            put("requested_technique", techniqueHint ?: JSONObject.NULL)
                            put("cell", requestedCell ?: JSONObject.NULL)
                            put("scope", scope)
                            put("max_results", 3)
                            put(
                                "current_route",
                                JSONObject().apply {
                                    put("technique", ds.anchorTechniqueId ?: JSONObject.NULL)
                                    put("target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                                    put("focus_cell", requestedCell ?: ds.anchorTargetCell ?: JSONObject.NULL)
                                }
                            )
                        }
                    )
                }.toString()

                DetourSolverQuerySpecV1(
                    queryId = queryId,
                    op = op,
                    payloadJson = payload,
                    reason = "detour_solver_backed_alternative_technique_query"
                )
            }

            else -> null
        }
    }

    private fun userTextDigitsFromLastUserTurnV1(s: SudoState): List<Int> {
        val text = s.lastUserText.orEmpty()
        if (text.isBlank()) return emptyList()

        val out = mutableListOf<Int>()
        var token = ""
        fun flush() {
            if (token.isBlank()) return
            val d = token.toIntOrNull()
            if (d != null && d in 1..9 && d !in out) out += d
            token = ""
        }

        text.forEach { ch ->
            if (ch.isDigit()) {
                token += ch
            } else {
                flush()
            }
        }
        flush()
        return out
    }

    private fun buildSolverBackedDetourBundlesFromResultV1(
        op: String,
        resultJson: String
    ): List<FactBundleV1> {
        val root = runCatching { JSONObject(resultJson) }.getOrNull() ?: return emptyList()
        val result = root.optJSONObject("result") ?: JSONObject()

        return when (op) {
            "normalize_detour_query" -> {
                when (result.optString("query_family", "").trim().uppercase()) {
                    "MOVE_PROOF" ->
                        listOf(
                            factNormalizedDetourMoveProofV1(
                                JSONObject().apply {
                                    put("schema_version", "normalized_detour_move_proof_v1")
                                    put("source", "normalize_detour_query")
                                    put("op", op)
                                    put("result", result)
                                }
                            )
                        )

                    "LOCAL_INSPECTION" ->
                        listOf(
                            factNormalizedDetourLocalInspectionV1(
                                JSONObject().apply {
                                    put("schema_version", "normalized_detour_local_inspection_v1")
                                    put("source", "normalize_detour_query")
                                    put("op", op)
                                    put("result", result)
                                }
                            )
                        )

                    "PROPOSAL_VERDICT" ->
                        listOf(
                            factNormalizedDetourProposalVerdictV1(
                                JSONObject().apply {
                                    put("schema_version", "normalized_detour_proposal_verdict_v1")
                                    put("source", "normalize_detour_query")
                                    put("op", op)
                                    put("result", result)
                                }
                            )
                        )

                    else -> emptyList()
                }
            }

            "get_cell_candidates" ->
                listOf(
                    factSolverCellCandidatesPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_cell_candidates_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            "get_cells_candidates" ->
                listOf(
                    factSolverCellsCandidatesPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_cells_candidates_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            "get_house_candidate_map" ->
                listOf(
                    factSolverHouseCandidateMapPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_house_candidate_map_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            "get_digit_blockers_for_cell" ->
                listOf(
                    factSolverCellDigitBlockersPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_cell_digit_blockers_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            "validate_candidate_claim" ->
                listOf(
                    factSolverReasoningCheckPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_reasoning_check_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            "get_next_step_summary",
            "compare_requested_technique_to_next_step" ->
                listOf(
                    factSolverAlternativeTechniquePacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_alternative_technique_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            "check_technique_in_scope" ->
                listOfNotNull(
                    factSolverTechniqueScopeCheckPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_technique_scope_check_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    ),
                    result.optJSONObject("support_snapshot")?.let { support ->
                        factSolverScopedSupportPacketV1(
                            JSONObject().apply {
                                put("schema_version", "solver_scoped_support_packet_v1")
                                put("source", "detour_query")
                                put("op", op)
                                put("result", support)
                            }
                        )
                    }
                )

            "search_local_moves" ->
                listOfNotNull(
                    factSolverLocalMoveSearchPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_local_move_search_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    ),
                    result.optJSONObject("support_snapshot")?.let { support ->
                        factSolverScopedSupportPacketV1(
                            JSONObject().apply {
                                put("schema_version", "solver_scoped_support_packet_v1")
                                put("source", "detour_query")
                                put("op", op)
                                put("result", support)
                            }
                        )
                    }
                )

            "compare_current_route_to_scope" ->
                listOf(
                    factSolverRouteComparisonPacketV1(
                        JSONObject().apply {
                            put("schema_version", "solver_route_comparison_packet_v1")
                            put("source", "detour_query")
                            put("op", op)
                            put("result", result)
                        }
                    )
                )

            else -> emptyList()
        }
    }



    private fun buildNativeDetourNarrativeContextFromFactsV1(
        turnSeq: Long,
        factBundles: List<FactBundleV1>
    ): DetourNarrativeContextV1? {
        val normalizedMoveProof =
            factBundles.firstOrNull { it.type == FactBundleV1.Type.NORMALIZED_DETOUR_MOVE_PROOF_V1 }
                ?.payload
                ?.optJSONObject("result")

        if (normalizedMoveProof != null && normalizedMoveProof.length() > 0) {
            return DetourNarrativeBuilderV1.buildFromNormalizedMoveProof(
                normalized = normalizedMoveProof,
                createdTurnSeq = turnSeq
            )
        }

        val normalizedLocalInspection =
            factBundles.firstOrNull { it.type == FactBundleV1.Type.NORMALIZED_DETOUR_LOCAL_INSPECTION_V1 }
                ?.payload
                ?.optJSONObject("result")

        if (normalizedLocalInspection != null && normalizedLocalInspection.length() > 0) {
            return DetourNarrativeBuilderV1.buildFromNormalizedLocalInspection(
                normalized = normalizedLocalInspection,
                createdTurnSeq = turnSeq
            )
        }

        val normalizedProposalVerdict =
            factBundles.firstOrNull { it.type == FactBundleV1.Type.NORMALIZED_DETOUR_PROPOSAL_VERDICT_V1 }
                ?.payload
                ?.optJSONObject("result")

        if (normalizedProposalVerdict != null && normalizedProposalVerdict.length() > 0) {
            return DetourNarrativeBuilderV1.buildFromNormalizedProposalVerdict(
                normalized = normalizedProposalVerdict,
                createdTurnSeq = turnSeq
            )
        }

        return null
    }

    private fun buildNativeDetourNarrativeFactBundleV1(
        ctx: DetourNarrativeContextV1?
    ): FactBundleV1? {
        if (ctx == null) return null
        return factDetourNarrativeContextV1(ctx.toJson())
    }




    private fun chooseReplyStyleForFactsV1(
        facts: List<FactBundleV1>
    ): ReplyStyleV1 {
        val setupPacket =
            facts.firstOrNull { it.type == FactBundleV1.Type.SETUP_REPLY_PACKET_V1 }?.payload
        if (setupPacket != null) {
            val setupProfile = setupPacket.optString("setup_profile")
            val maxWords =
                when (setupProfile) {
                    "BASE_SINGLES_SETUP" -> 190
                    "FULL_HOUSE_SETUP" -> 100
                    "INTERSECTIONS_SETUP" -> 320
                    else -> 240
                }

            return ReplyStyleV1(
                voice = ReplyVoiceV1.story_coach,
                tone = ReplyToneV1.vivid,
                maxWords = maxWords,
                askOneQuestionMax = true
            )
        }

        val confrontationPacket =
            facts.firstOrNull { it.type == FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1 }?.payload
        if (confrontationPacket != null) {
            val proofProfile = confrontationPacket.optString("proof_profile")
            val maxWords =
                when (proofProfile) {
                    "BASE_SINGLES_PROOF" -> 320
                    "FULL_HOUSE_PROOF" -> 100
                    else -> 460
                }

            return ReplyStyleV1(
                voice = ReplyVoiceV1.story_coach,
                tone = ReplyToneV1.vivid,
                maxWords = maxWords,
                askOneQuestionMax = true
            )
        }

        val resolutionPacket =
            facts.firstOrNull { it.type == FactBundleV1.Type.RESOLUTION_REPLY_PACKET_V1 }?.payload
        if (resolutionPacket != null) {
            return ReplyStyleV1(
                voice = ReplyVoiceV1.coach,
                tone = ReplyToneV1.warm,
                maxWords = 150,
                askOneQuestionMax = true
            )
        }

        return ReplyStyleV1(
            voice = ReplyVoiceV1.friendly,
            tone = ReplyToneV1.natural,
            maxWords = 200,
            askOneQuestionMax = true
        )
    }

    private fun buildDetourSolverFollowUpNextV1(
        sBefore: SudoState,
        userText: String,
        reason: String,
        factBundles: List<FactBundleV1>
    ): Next {
        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "DETOUR_SOLVER_REPLY_BUILD_V1",
                data = mapOf(
                    "turn_id" to sBefore.turnSeq,
                    "reason" to reason,
                    "solver_bundle_types" to solverBackedDetourFactTypeNamesV1(factBundles),
                    "solver_bundle_count" to factBundles.size,
                    "question_class" to (sBefore.detourState?.questionClass?.name ?: "null")
                )
            )
        }

        val replyFactsBase =
            (sBefore.solvingReadyFactBundlesV1 + factBundles).filterNot {
                it.type == FactBundleV1.Type.STEP_CLARIFICATION_PACKET_V1 ||
                        it.type == FactBundleV1.Type.PROOF_CHALLENGE_PACKET_V1 ||
                        it.type == FactBundleV1.Type.USER_REASONING_CHECK_PACKET_V1 ||
                        it.type == FactBundleV1.Type.ALTERNATIVE_TECHNIQUE_PACKET_V1 ||
                        it.type == FactBundleV1.Type.TARGET_CELL_QUERY_PACKET_V1 ||
                        it.type == FactBundleV1.Type.CANDIDATE_STATE_PACKET_V1 ||
                        it.type == FactBundleV1.Type.NEIGHBOR_CELL_QUERY_PACKET_V1 ||
                        it.type == FactBundleV1.Type.RETURN_TO_ROUTE_PACKET_V1
            }

        val phase2DetourBundles = buildPhase2DetourBundlesV1(
            sAfter = sBefore,
            facts = replyFactsBase
        )

        val replyFacts =
            if (phase2DetourBundles.isNotEmpty()) {
                replyFactsBase + phase2DetourBundles
            } else {
                replyFactsBase
            }

        val outcome = DecisionOutcomeV1(
            decisionKind = DecisionKindV1.ANSWERED_GRID_QUESTION,
            summary = reason,
            mutationApplied = null,
            stateMutations = StateMutationsV1(),
            factBundles = replyFacts,
            replyStyle = chooseReplyStyleForFactsV1(replyFacts),
            needsClarification = false,
            clarificationQuestionHint = null
        )

        val headerAfter = buildStateHeader(sBefore)
        val (s2, ctx2) = nextPolicyCtx(
            s = sBefore,
            tickId = 2,
            reason = reason,
            stateHeader = headerAfter,
            turnId = sBefore.turnSeq
        )

        runCatching {
            emitGridFactsNowIfPresent(
                s = s2,
                ctx = ctx2,
                stage = "PRE_TICK2",
                note = reason
            )
        }

        emitPolicyCallTrace(
            traceState = sBefore,
            userText = userText,
            stateHeader = headerAfter,
            reason = reason,
            turnId = sBefore.turnSeq,
            ctx = ctx2,
            extraData = mapOf(
                "decision_kind" to outcome.decisionKind.name,
                "fact_bundle_types" to replyFacts.joinToString(",") { it.type.name }
            )
        )
        emitModelCallBegin(ctx2)

        val enforced = enforceTurnContractAndAttachSnapshot(
            stage = "PRE_TICK2",
            s = s2,
            factsIn = replyFacts,
            rawTextUsedByMaps = false
        )
        val sEnforced = enforced.s
        val factsFinal = enforced.facts

        val sigToStore = storySignatureToStoreForTurnV1(sEnforced)

        val sFinal = if (!sigToStore.isNullOrBlank()) {
            sEnforced.copy(lastStorySignatureV1 = sigToStore)
        } else sEnforced

        val replyExec = buildReplyRequestV1(
            sBefore = sBefore,
            sAfter = sFinal,
            turnId = sBefore.turnSeq,
            userText = userText,
            decision = outcome,
            factBundles = factsFinal
        )

        val effs = mutableListOf<Eff>()

        if (sFinal.solveOverlayVisible && !sFinal.solveStepJson.isNullOrBlank()) {
            val style = sFinal.solveOverlayStyle.ifBlank { "full" }
            val applied = authoritativeAppliedOverlayFrameIdsForRenderV1(sFinal)

            if (applied.isNotEmpty()) {
                val renderDetourNative =
                    shouldRenderDetourNativeOverlayV1(
                        s = sFinal,
                        appliedFrameIds = applied
                    )

                val frameJson =
                    if (renderDetourNative) {
                        buildDetourOverlayCompositeFrameJsonV1(
                            s = sFinal,
                            frameIds = applied,
                            style = style,
                            reason = "detour_native_overlay_pre_tick2"
                        )
                    } else {
                        buildSolveOverlayCompositeFrameJsonV1(
                            s = sFinal,
                            frameIds = applied,
                            style = style,
                            reason = "detour_native_overlay_pre_tick2"
                        )
                    }

                runCatching {
                    val cell66Summary = summarizeOverlayForCellV1(frameJson, 66)

                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "OVERLAY_RENDER_REQUESTED",
                            "session_id" to sFinal.sessionId,
                            "turn_id" to sBefore.turnSeq,
                            "tick_id" to 2,
                            "phase" to sFinal.phase.name,
                            "reason" to "detour_native_overlay_pre_tick2",
                            "frame_id" to (applied.lastOrNull() ?: "none"),
                            "applied_frame_ids" to applied.joinToString(","),
                            "frame_json_sha12" to sha12(frameJson).take(12),
                            "frame_json_len" to frameJson.length,
                            "cell66_summary" to cell66Summary,
                            "frame_json" to frameJson
                        )
                    )
                }

                effs += Eff.RenderSolveOverlay(
                    frameJson = frameJson,
                    style = style,
                    reason = "detour_native_overlay_pre_tick2"
                )
            }
        }

        effs += Eff.CallReplyGenerateV1(
            ctx = ctx2,
            replyRequest = replyExec.replyRequest,
            planResult = replyExec.planResult,
            reason = reason,
            turnId = sBefore.turnSeq
        )

        return Next(
            sFinal,
            effs
        )
    }




