    private fun isRepairFenceSignalV1(signal: RepairSignalV1?): Boolean =
        signal == RepairSignalV1.MISHEARD ||
                signal == RepairSignalV1.MISUNDERSTOOD ||
                signal == RepairSignalV1.CONTRADICTION ||
                signal == RepairSignalV1.LOOP_COMPLAINT ||
                signal == RepairSignalV1.REPEATED_QUESTION

    private fun repairFenceReasonFromSignalV1(signal: RepairSignalV1?): String =
        when (signal) {
            RepairSignalV1.LOOP_COMPLAINT,
            RepairSignalV1.REPEATED_QUESTION ->
                "user_reports_repetition_or_bridge_loop"

            RepairSignalV1.MISHEARD,
            RepairSignalV1.MISUNDERSTOOD,
            RepairSignalV1.CONTRADICTION ->
                "user_reports_wrong_assertion_or_false_apology"

            else ->
                "structured_repair_signal_requested"
        }

    private fun JSONObject.optNestedStringOrNull(vararg path: String): String? {
        if (path.isEmpty()) return null
        var cur: JSONObject = this
        for (i in 0 until path.lastIndex) {
            cur = cur.optJSONObject(path[i]) ?: return null
        }
        return cur.optString(path.last(), null)?.takeIf { it.isNotBlank() }
    }

    private fun canonicalSolveStepEnvelopeForRoutingV1(sAfter: SudoState): JSONObject? {
        val packetStep =
            sAfter.solvingReadyFactBundlesV1
                .firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
                ?.payload

        if (packetStep != null && packetStep.length() > 0) {
            return JSONObject(packetStep.toString())
        }

        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        return envObj?.optJSONObject("step") ?: envObj
    }


    private fun canonicalLeadProofApplicationForRoutingV1(sAfter: SudoState): JSONObject? {
        val stepObj = canonicalSolveStepEnvelopeForRoutingV1(sAfter) ?: return null
        val proof = stepObj.optJSONObject("proof") ?: return null

        proof.optJSONObject("lead_application")?.let { return it }

        val apps = proof.optJSONArray("applications")
        if (apps != null && apps.length() > 0) {
            apps.optJSONObject(0)?.let { return it }
        }

        return null
    }


    private fun canonicalNarrativeTruthForRoutingV1(sAfter: SudoState): JSONObject? {
        val stepObj = canonicalSolveStepEnvelopeForRoutingV1(sAfter) ?: return null
        return stepObj.optJSONObject("evidence")?.optJSONObject("narrative_truth_v2")
            ?: stepObj.optJSONObject("narrative_truth_v2")
    }



    private fun readCanonicalArchetypeWireHintV1(sAfter: SudoState): String? {
        val narrativeTruth = canonicalNarrativeTruthForRoutingV1(sAfter)
        val leadApp = canonicalLeadProofApplicationForRoutingV1(sAfter)

        val directArchetype =
            narrativeTruth?.optNestedStringOrNull("technique", "archetype")
                ?: runCatching {
                    leadApp
                        ?.optJSONObject("narrative")
                        ?.optString("archetype")
                        ?.takeIf { it.isNotBlank() }
                }.getOrNull()

        if (!directArchetype.isNullOrBlank()) return directArchetype

        val originStory =
            narrativeTruth?.optNestedStringOrNull("final_resolution", "origin_story")
                ?.trim()
                ?.uppercase()

        if (!originStory.isNullOrBlank()) {
            return when (originStory) {
                "INTERSECTION", "INTERSECTIONS" -> "INTERSECTIONS"
                "SUBSET", "SUBSETS" -> "SUBSETS"
                else -> null
            }
        }

        val patternType =
            narrativeTruth?.optNestedStringOrNull("trigger_pattern", "pattern_type")
                ?.trim()
                ?.lowercase()
                ?: runCatching {
                    leadApp
                        ?.optJSONObject("pattern")
                        ?.optString("pattern_type")
                        ?.trim()
                        ?.lowercase()
                }.getOrNull()

        if (!patternType.isNullOrBlank()) {
            return when (patternType) {
                "subset" -> "SUBSETS"
                "intersection" -> "INTERSECTIONS"
                "fish" -> "FISH"
                "wing" -> "WINGS"
                "chain" -> "CHAINS"
                else -> null
            }
        }

        val intersectionEvidencePresent =
            narrativeTruth?.optJSONObject("trigger_pattern")?.let { trigger ->
                trigger.optJSONObject("source_house") != null &&
                        trigger.optJSONObject("cross_house") != null &&
                        trigger.optJSONArray("overlap_cells")?.length() ?: 0 > 0
            } == true ||
                    narrativeTruth?.optJSONObject("trigger_bridge")
                        ?.optBoolean("cross_house_now_restricted", false) == true ||
                    narrativeTruth?.optJSONObject("source_confinement_proof")
                        ?.optJSONArray("outside_audit_rows")
                        ?.length() ?: 0 > 0

        if (intersectionEvidencePresent) return "INTERSECTIONS"

        val subtypeHint =
            narrativeTruth?.optNestedStringOrNull("trigger_pattern", "pattern_subtype")
                ?.trim()
                ?.lowercase()
                ?: narrativeTruth?.optNestedStringOrNull("source_confinement_proof", "pattern_subtype")
                    ?.trim()
                    ?.lowercase()

        return when {
            subtypeHint.isNullOrBlank() -> null
            "claiming" in subtypeHint || "pointing" in subtypeHint -> "INTERSECTIONS"
            "subset" in subtypeHint || "pair" in subtypeHint || "triple" in subtypeHint || "quad" in subtypeHint -> "SUBSETS"
            else -> null
        }
    }







    private fun readCanonicalPatternSubtypeHintV1(sAfter: SudoState): String? {
        val narrativeTruth = canonicalNarrativeTruthForRoutingV1(sAfter)
        val leadApp = canonicalLeadProofApplicationForRoutingV1(sAfter)

        return narrativeTruth?.optNestedStringOrNull("trigger_pattern", "pattern_subtype")
            ?: narrativeTruth?.optNestedStringOrNull("source_confinement_proof", "pattern_subtype")
            ?: runCatching {
                leadApp
                    ?.optJSONObject("pattern")
                    ?.optString("pattern_subtype")
                    ?.takeIf { it.isNotBlank() }
            }.getOrNull()
    }




    private fun readCanonicalDirectionModeHintV1(sAfter: SudoState): String? {
        val narrativeTruth = canonicalNarrativeTruthForRoutingV1(sAfter)
        val leadApp = canonicalLeadProofApplicationForRoutingV1(sAfter)

        return narrativeTruth?.optNestedStringOrNull("trigger_pattern", "interaction_kind")
            ?: narrativeTruth?.optNestedStringOrNull("source_confinement_proof", "interaction_kind")
            ?: narrativeTruth?.optNestedStringOrNull("trigger_pattern", "direction_mode")
            ?: runCatching {
                leadApp
                    ?.optJSONObject("pattern")
                    ?.optString("pattern_subtype")
                    ?.takeIf { it.isNotBlank() }
            }.getOrNull()
    }


    private fun spokenIntersectionTechniqueNameFromSubtypeV1(
        patternSubtype: String?,
        overlapCardinality: Int?
    ): String? {
        val subtype = patternSubtype?.trim()?.lowercase()?.replace('-', '_') ?: return null

        return when {
            subtype == "claiming_pair" -> "Claiming Pair"
            subtype == "claiming_triple" -> "Claiming Triple"
            subtype == "pointing_pair" -> "Pointing Pair"
            subtype == "pointing_triple" -> "Pointing Triple"

            subtype.startsWith("claiming_") && overlapCardinality == 2 -> "Claiming Pair"
            subtype.startsWith("claiming_") && overlapCardinality == 3 -> "Claiming Triple"
            subtype.startsWith("pointing_") && overlapCardinality == 2 -> "Pointing Pair"
            subtype.startsWith("pointing_") && overlapCardinality == 3 -> "Pointing Triple"

            subtype == "claiming" && overlapCardinality == 2 -> "Claiming Pair"
            subtype == "claiming" && overlapCardinality == 3 -> "Claiming Triple"
            subtype == "pointing" && overlapCardinality == 2 -> "Pointing Pair"
            subtype == "pointing" && overlapCardinality == 3 -> "Pointing Triple"

            else -> null
        }
    }



    private fun readSetupArchetypeWireV1(sAfter: SudoState): String? =
        readCanonicalArchetypeWireHintV1(sAfter)

    private fun readSetupTechniqueIdV1(sAfter: SudoState): String? {
        val stepObj = canonicalSolveStepEnvelopeForRoutingV1(sAfter)

        return stepObj?.optNestedStringOrNull("technique_info", "technique_id")
            ?: stepObj?.optNestedStringOrNull("technique", "technique_id")
            ?: stepObj?.optNestedStringOrNull("technique", "id")
            ?: sAfter.coachPlan?.techniqueId
            ?: sAfter.activeRouteContext?.techniqueId
    }

    private fun inferSetupProfileFromTechniqueIdV1(techniqueId: String?): SetupDemandProfileV1? {
        val id = techniqueId?.trim()?.lowercase().orEmpty()
        if (id.isBlank()) return null

        return when {
            id == "singles-1" -> SetupDemandProfileV1.FULL_HOUSE_SETUP
            "single" in id -> SetupDemandProfileV1.BASE_SINGLES_SETUP

            "pointing" in id ||
                    "claiming" in id ||
                    "boxed-single" in id ||
                    "singles-boxed" in id ||
                    "singles-pointing" in id ||
                    "intersection" in id ->
                SetupDemandProfileV1.INTERSECTIONS_SETUP

            "subset" in id ||
                    "pair" in id ||
                    "triple" in id ||
                    "quad" in id ||
                    "doubles-" in id ||
                    "triples-" in id ||
                    "quads-" in id ||
                    "multiple_naked" in id ||
                    "multiple_hidden" in id ->
                SetupDemandProfileV1.SUBSETS_SETUP

            "wing" in id ||
                    "chain" in id ||
                    "fish" in id ||
                    "x-wing" in id ||
                    "y-wing" in id ||
                    "remote-pair" in id ||
                    "ab-chain" in id ||
                    "ab-ring" in id ->
                SetupDemandProfileV1.ADVANCED_PATTERN_SETUP

            else -> null
        }
    }

    private fun resolveSetupDemandProfileV1(sAfter: SudoState): SetupDemandProfileV1 {
        val archetype = readSetupArchetypeWireV1(sAfter)?.trim()?.uppercase()
        val subtypeHint = readCanonicalPatternSubtypeHintV1(sAfter)?.trim()?.lowercase().orEmpty()
        val directionHint = readCanonicalDirectionModeHintV1(sAfter)?.trim()?.lowercase().orEmpty()

        if (
            archetype == "INTERSECTIONS" ||
            "claiming" in subtypeHint ||
            "pointing" in subtypeHint ||
            directionHint == "claiming" ||
            directionHint == "pointing"
        ) {
            return SetupDemandProfileV1.INTERSECTIONS_SETUP
        }

        return when (archetype) {
            "FULL_HOUSE" ->
                SetupDemandProfileV1.FULL_HOUSE_SETUP

            "HIDDEN_SINGLES",
            "NAKED_SINGLES",
            "SINGLES" ->
                SetupDemandProfileV1.BASE_SINGLES_SETUP

            "SUBSETS" ->
                SetupDemandProfileV1.SUBSETS_SETUP

            "FISH",
            "WINGS",
            "CHAINS" ->
                SetupDemandProfileV1.ADVANCED_PATTERN_SETUP

            "UNKNOWN" ->
                SetupDemandProfileV1.FALLBACK_SETUP

            else ->
                inferSetupProfileFromTechniqueIdV1(readSetupTechniqueIdV1(sAfter))
                    ?: SetupDemandProfileV1.FALLBACK_SETUP
        }
    }


