    private fun resolveConfrontationNarrationDoctrineV1(
        sAfter: SudoState
    ): ConfrontationNarrationDoctrineV1 {
        return when (resolveConfrontationProofProfileV1(sAfter)) {
            ConfrontationProofProfileV1.BASE_SINGLES_PROOF,
            ConfrontationProofProfileV1.FULL_HOUSE_PROOF ->
                ConfrontationNarrationDoctrineV1.LENS_FIRST

            ConfrontationProofProfileV1.SUBSETS_PROOF,
            ConfrontationProofProfileV1.INTERSECTIONS_PROOF,
            ConfrontationProofProfileV1.ADVANCED_PATTERN_PROOF ->
                ConfrontationNarrationDoctrineV1.PATTERN_FIRST

            ConfrontationProofProfileV1.FALLBACK_PROOF ->
                ConfrontationNarrationDoctrineV1.NEUTRAL
        }
    }

    private fun reasonWithDemandProfilesV1(demand: ReplyDemandResolutionV1): String {
        val suffixes = mutableListOf<String>()
        demand.setupProfile?.let { suffixes += "setup_profile=${it.name}" }
        demand.confrontationProofProfile?.let {
            suffixes += "confrontation_proof_profile=${it.name}"
        }
        demand.resolutionProfile?.let {
            suffixes += "resolution_profile=${it.name}"
        }

        return if (suffixes.isEmpty()) {
            demand.reason
        } else {
            demand.reason + "|" + suffixes.joinToString("|")
        }
    }

    private fun notesWithDemandProfilesV1(
        base: String?,
        demand: ReplyDemandResolutionV1
    ): String? {
        val suffixes = mutableListOf<String>()
        demand.setupProfile?.let { suffixes += "setup_profile=${it.name}" }
        demand.confrontationProofProfile?.let {
            suffixes += "confrontation_proof_profile=${it.name}"
        }
        demand.resolutionProfile?.let {
            suffixes += "resolution_profile=${it.name}"
        }

        if (suffixes.isEmpty()) return base

        val suffix = suffixes.joinToString(" | ")
        return if (base.isNullOrBlank()) {
            suffix
        } else {
            "$base | $suffix"
        }
    }

