        }

    private fun defaultResolutionTechniqueContributionSummaryV1(
        profile: ResolutionProfileV1
    ): String =
        when (profile) {
            ResolutionProfileV1.BASE_SINGLES_RESOLUTION ->
                "This was a direct single-style finish on the target."

            ResolutionProfileV1.FULL_HOUSE_RESOLUTION ->
                "This was a Full House finish: the house itself had reached its final open seat."

            ResolutionProfileV1.SUBSETS_RESOLUTION ->
                "The technique contribution was a subset cleanup that removed key candidates from the target."

            ResolutionProfileV1.INTERSECTIONS_RESOLUTION ->
                "The technique contribution was an intersection cleanup that removed key candidates from the target."

            ResolutionProfileV1.ADVANCED_PATTERN_RESOLUTION ->
                "The technique contribution was a pattern-based cleanup that narrowed the target before the finish."

            ResolutionProfileV1.FALLBACK_RESOLUTION ->
                "The technique contribution was a cleanup step that helped make the final answer forced."
        }

    private fun defaultResolutionFinalForcingSummaryV1(
        profile: ResolutionProfileV1
    ): String =
        when (profile) {
            ResolutionProfileV1.BASE_SINGLES_RESOLUTION ->
                "With the other options gone, the target has only one valid value left."

            ResolutionProfileV1.FULL_HOUSE_RESOLUTION ->
                "With the house down to its last opening, the target has only one valid value left."

            ResolutionProfileV1.SUBSETS_RESOLUTION,
            ResolutionProfileV1.INTERSECTIONS_RESOLUTION,
            ResolutionProfileV1.ADVANCED_PATTERN_RESOLUTION ->
                "After that cleanup, the target collapses to its final single value."

            ResolutionProfileV1.FALLBACK_RESOLUTION ->
                "The remaining constraints now force the final value at the target."
        }






    private fun defaultResolutionOverlayVariantV1(
        profile: ResolutionProfileV1
    ): String =
        when (profile) {
            ResolutionProfileV1.BASE_SINGLES_RESOLUTION ->
                "singles_commit_and_arrival"

            ResolutionProfileV1.FULL_HOUSE_RESOLUTION ->
                "full_house_commit_and_arrival"

            ResolutionProfileV1.SUBSETS_RESOLUTION ->
                "subset_commit_and_arrival"

            ResolutionProfileV1.INTERSECTIONS_RESOLUTION ->
                "intersection_commit_and_arrival"

            ResolutionProfileV1.ADVANCED_PATTERN_RESOLUTION ->
                "advanced_commit_and_arrival"

            ResolutionProfileV1.FALLBACK_RESOLUTION ->
                "generic_commit_and_arrival"
        }

    private fun firstPositiveIntInArrayV1(arr: JSONArray?): Int? {
        if (arr == null) return null
        for (i in 0 until arr.length()) {
            val v = arr.optInt(i, -1)
            if (v in 1..9) return v
        }
        return null
    }

    private fun readSetupTechniqueNameV1(sAfter: SudoState): String? {
        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj

        return stepObj?.optNestedStringOrNull("technique_info", "technique_name")
            ?: stepObj?.optNestedStringOrNull("technique_info", "name")
            ?: stepObj?.optNestedStringOrNull("technique", "technique_name")
            ?: stepObj?.optNestedStringOrNull("technique", "name")
    }

    private fun readSetupTechniqueFamilyV1(sAfter: SudoState): String? {
        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj

        return stepObj?.optNestedStringOrNull("technique_info", "family")
            ?: stepObj?.optNestedStringOrNull("technique", "family")
    }

    private fun readSetupTechniqueRealNameV1(sAfter: SudoState): String? {
        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj

        return stepObj?.optNestedStringOrNull("technique_info", "real_name")
            ?: stepObj?.optNestedStringOrNull("technique_info", "realName")
            ?: stepObj?.optNestedStringOrNull("technique", "real_name")
            ?: stepObj?.optNestedStringOrNull("technique", "realName")
    }

    private fun readSetupTechniqueIsBaseV1(sAfter: SudoState): Boolean? {
        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj
        val info = stepObj?.optJSONObject("technique_info")
            ?: stepObj?.optJSONObject("technique")

        return when {
            info == null -> null
            info.has("is_base") -> info.optBoolean("is_base")
            info.has("isBase") -> info.optBoolean("isBase")
            else -> null
        }
    }

    private fun readSetupTechniqueDifficultyLevelV1(sAfter: SudoState): String? {
        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj

        return stepObj?.optNestedStringOrNull("technique_info", "difficulty_level")
            ?: stepObj?.optNestedStringOrNull("technique_info", "difficultyLevel")
            ?: stepObj?.optNestedStringOrNull("technique", "difficulty_level")
            ?: stepObj?.optNestedStringOrNull("technique", "difficultyLevel")
    }

    private fun readSetupTechniqueShortDefinitionSummaryV1(sAfter: SudoState): String? {
        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj

        val fromTechniqueInfo =
            stepObj?.optJSONObject("technique_info")
                ?.optJSONObject("definition")
                ?.optString("what")
                ?.takeIf { it.isNotBlank() }

        if (!fromTechniqueInfo.isNullOrBlank()) return fromTechniqueInfo

        return stepObj?.optJSONObject("technique")
            ?.optJSONObject("definition")
            ?.optString("what")
            ?.takeIf { it.isNotBlank() }
    }

    private fun buildSetupReplyPacketBundleV1(
        sAfter: SudoState,
        storyContextBundle: FactBundleV1?
    ): FactBundleV1? {
        if (sAfter.mode != SudoMode.GRID_SESSION) return null
        if (sAfter.phase != GridPhase.SOLVING) return null
        if (sAfter.narrativeStory?.stage != StoryStage.SETUP) return null

        val story = storyContextBundle?.payload ?: return null
        val setupProfile = resolveSetupDemandProfileV1(sAfter)
        val archetype = readSetupArchetypeWireV1(sAfter)
        val techniqueId = readSetupTechniqueIdV1(sAfter)
        val techniqueName = readSetupTechniqueNameV1(sAfter)
        val techniqueFamily = readSetupTechniqueFamilyV1(sAfter)
        val techniqueRealName = readSetupTechniqueRealNameV1(sAfter)
        val techniqueIsBase = readSetupTechniqueIsBaseV1(sAfter)
        val techniqueDifficultyLevel = readSetupTechniqueDifficultyLevelV1(sAfter)
        val techniqueShortDefinitionSummary = readSetupTechniqueShortDefinitionSummaryV1(sAfter)


        val canonicalStageTruth =
            buildCanonicalStageTruthV1(
                sAfter = sAfter,
                fallbackTargetCell = story.optJSONObject("setup_target_cell"),
                fallbackPrimaryHouse = story.optJSONObject("setup_primary_house"),
                fallbackTargetDigit =
                    if (!story.isNull("setup_target_digit")) {
                        story.optInt("setup_target_digit", -1).takeIf { it in 1..9 }
                    } else {
                        null
                    }
            )

        val proofArgs =
            canonicalStageTruth.optJSONObject("proof_args") ?: JSONObject()

        val targetResolutionTruth =
            canonicalStageTruth.optJSONObject("target_resolution_truth") ?: JSONObject()

        val canonicalTruthSource =
            canonicalStageTruth.optString("source_of_truth")

        fun cellLabelOf(cell: JSONObject?): String? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            return if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
        }

        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the house"
            }
        }

        fun toCellRefOrNull(value: Any?): JSONObject? =
            when (value) {
                is JSONObject -> {
                    when {
                        value.has("r") && value.has("c") -> JSONObject(value.toString())
                        value.optString("cell").isNotBlank() -> cellRefV1(value.optString("cell"))
                        else -> null
                    }
                }
                is String -> value.takeIf { it.isNotBlank() }?.let { cellRefV1(it) }
                else -> null
            }

        val eliminationKind = targetResolutionTruth.optString("elimination_kind")

        val rawBoundedRows =
            story.optJSONArray("setup_trigger_member_explanation_rows") ?: JSONArray()

        val explanationPayload =
            story.optJSONObject("setup_trigger_explanation_payload") ?: JSONObject()
        val rawMemberProofs =
            explanationPayload.optJSONArray("pattern_member_proofs")
                ?: explanationPayload.optJSONArray("member_proofs")
                ?: JSONArray()

        val patternMemberProofRows = JSONArray().apply {
            for (i in 0 until rawMemberProofs.length()) {
                val proof = rawMemberProofs.optJSONObject(i) ?: continue
                val memberCellRef = toCellRefOrNull(proof.opt("cell"))
                val witnessByDigit = proof.optJSONArray("witness_by_digit") ?: JSONArray()

                val projectedWitnessRows = JSONArray().apply {
                    for (j in 0 until witnessByDigit.length()) {
                        val witness = witnessByDigit.optJSONObject(j) ?: continue
                        val witnessCellRef = toCellRefOrNull(witness.opt("witness_cell"))

                        put(
                            JSONObject().apply {
                                put("digit", witness.opt("digit") ?: JSONObject.NULL)
                                put("witness_cell", witnessCellRef ?: JSONObject.NULL)
                                put(
                                    "via_house",
                                    witness.optJSONObject("via_house") ?: JSONObject.NULL
                                )
                            }
                        )
                    }
                }

                put(
                    JSONObject().apply {
                        put("member_cell", memberCellRef ?: JSONObject.NULL)
                        put(
                            "remaining_candidate_digits",
                            proof.optJSONArray("remaining_candidate_digits") ?: JSONArray()
                        )
                        put(
                            "claimed_candidate_digits",
                            proof.optJSONArray("claimed_candidate_digits") ?: JSONArray()
                        )
                        put("witness_rows", projectedWitnessRows)
                        put("status", proof.opt("status") ?: JSONObject.NULL)
                    }
                )
            }
        }


        val targetTruthSupport = targetResolutionTruth.optJSONObject("support") ?: JSONObject()
        val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
        val peerWitnessPairs = targetTruthSupport.optJSONArray("peer_witness_pairs") ?: JSONArray()
        val peerBlockerRows = targetTruthSupport.optJSONArray("peer_blocker_rows") ?: JSONArray()

        val derivedHouseSetupRows = JSONArray().apply {
            if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                if (peerBlockerRows.length() > 0) {
                    for (i in 0 until peerBlockerRows.length()) {
                        val row = peerBlockerRows.optJSONObject(i) ?: continue
                        val claimedCell = row.optJSONObject("claimed_cell")
                        val witnessCell = row.optJSONObject("cell")
                        val digit = row.opt("digit")
                        val claimedLabel = cellLabelOf(claimedCell) ?: "that rival cell"
                        val witnessLabel = cellLabelOf(witnessCell) ?: "another cell"
                        val groupedSummary =
                            row.optString("because").takeIf { it.isNotBlank() }
                                ?: if (digit != null && digit != JSONObject.NULL) {
                                    "$witnessLabel already blocks $digit for $claimedLabel."
                                } else {
                                    "$witnessLabel blocks that rival location."
                                }

                        val spokenLine =
                            row.optString("spoken_line").takeIf { it.isNotBlank() }
                                ?: if (digit != null && digit != JSONObject.NULL) {
                                    "$claimedLabel cannot take $digit because of $witnessLabel."
                                } else {
                                    "$claimedLabel gets ruled out because of $witnessLabel."
                                }

                        put(
                            JSONObject().apply {
                                put("member_cell", claimedCell ?: JSONObject.NULL)
                                put("surviving_digits", JSONArray())
                                put("grouped_witness_summary", groupedSummary)
                                put("spoken_line", spokenLine)
                            }
                        )
                    }
                } else {
                    for (i in 0 until peerWitnessPairs.length()) {
                        val pair = peerWitnessPairs.optJSONObject(i) ?: continue
                        val claimedCell = pair.optJSONObject("peer_cell")
                        val witnessCell = pair.optJSONObject("witness_cell")
                        val relation = pair.optString("relation")
                        val digit = pair.opt("digit")
                        val claimedLabel = cellLabelOf(claimedCell) ?: "that rival cell"
                        val witnessLabel = cellLabelOf(witnessCell) ?: "another cell"

                        val groupedSummary =
                            when (relation) {
                                "SAME_ROW" -> "$witnessLabel already places $digit in the same row."
                                "SAME_COL" -> "$witnessLabel already places $digit in the same column."
                                "SAME_BOX" -> "$witnessLabel already places $digit in the same box."
                                else -> "$witnessLabel blocks $digit for that rival cell."
                            }

                        val spokenLine =
                            when (relation) {
                                "SAME_ROW" ->
                                    "$claimedLabel cannot take $digit because $witnessLabel already places $digit in the same row."
                                "SAME_COL" ->
                                    "$claimedLabel cannot take $digit because $witnessLabel already places $digit in the same column."
                                "SAME_BOX" ->
                                    "$claimedLabel cannot take $digit because $witnessLabel already places $digit in the same box."
                                else ->
                                    "$claimedLabel gets ruled out for $digit because of $witnessLabel."
                            }

                        put(
                            JSONObject().apply {
                                put("member_cell", claimedCell ?: JSONObject.NULL)
                                put("surviving_digits", JSONArray())
                                put("grouped_witness_summary", groupedSummary)
                                put("spoken_line", spokenLine)
                            }
                        )
                    }
                }
            }
        }

        val boundedRows =
            when {
                rawBoundedRows.length() > 0 -> rawBoundedRows
                derivedHouseSetupRows.length() > 0 -> derivedHouseSetupRows
                else -> JSONArray().apply {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val remaining = houseClaim.optJSONArray("remaining_candidate_cells") ?: JSONArray()
                        val claimed = houseClaim.optJSONArray("claimed_candidate_cells") ?: JSONArray()
                        for (i in 0 until claimed.length()) {
                            val rival = claimed.optJSONObject(i) ?: continue
                            val rivalLabel = cellLabelOf(rival) ?: "that rival cell"
                            put(
                                JSONObject().apply {
                                    put("member_cell", rival)
                                    put("surviving_digits", JSONArray())
                                    put("grouped_witness_summary", "$rivalLabel is still one of the rival locations we need to rule out.")
                                    put("spoken_line", "We still need to test whether $rivalLabel can keep the target digit.")
                                }
                            )
                        }
                    }
                }
            }

        val canSayTargetDigit = story.optBoolean("setup_can_say_target_digit", false)
        val targetDigitValue =
            if (canSayTargetDigit && !story.isNull("setup_target_digit")) {
                story.opt("setup_target_digit")
            } else {
                targetResolutionTruth.opt("digit") ?: JSONObject.NULL
            }

        val isFullHouse =
            archetype?.trim()?.uppercase() == "FULL_HOUSE" ||
                    techniqueId?.trim()?.lowercase() == "singles-1" ||
                    techniqueRealName?.contains("Full House", ignoreCase = true) == true

        val setupOrientationSummary =
            story.optString("setup_target_orientation_summary").takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        if (isFullHouse) {
                            if (digit != null && digit != JSONObject.NULL) {
                                "Let’s step into ${houseLabelOf(house)} for a Full House moment: the house is nearly complete, and digit $digit is looking for the final open seat."
                            } else {
                                "Let’s step into the active house for a Full House moment: the house is nearly complete, and one final seat is still open."
                            }
                        } else if (digit != null && digit != JSONObject.NULL) {
                            "Let’s focus on ${houseLabelOf(house)} and track where digit $digit can still go."
                        } else {
                            "Let’s focus on the active house and track its remaining candidate locations."
                        }
                    } else {
                        null
                    }
                }

        val setupLensSummary =
            story.optString("setup_technique_lens_summary").takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        if (isFullHouse) {
                            "This setup is about noticing a house that has almost finished filling itself, so the technique arrives as the quiet closer."
                        } else {
                            "This setup is about narrowing the house claim until only one location remains for the target digit."
                        }
                    } else {
                        null
                    }
                }

        val setupTriggerOverviewSummary =
            story.optString("setup_trigger_explanation_summary_only").takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        if (isFullHouse) {
                            if (digit != null && digit != JSONObject.NULL) {
                                "Inside ${houseLabelOf(house)}, almost everything is already settled. Full House enters when only one seat is still waiting for digit $digit."
                            } else {
                                "Inside the active house, almost everything is already settled. Full House enters when only one seat is still waiting."
                            }
                        } else if (digit != null && digit != JSONObject.NULL) {
                            "Inside ${houseLabelOf(house)}, digit $digit still looks possible in several cells at first, but the rival locations are starting to fall away."
                        } else {
                            "The active house still has several rival locations, but they are starting to fall away."
                        }
                    } else {
                        null
                    }
                }

        val setupTriggerSummary =
            story.optString("setup_trigger_summary").takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        val remaining = houseClaim.optJSONArray("remaining_candidate_cells") ?: JSONArray()
                        if (isFullHouse) {
                            if (digit != null && digit != JSONObject.NULL && remaining.length() == 1) {
                                "Full House is on stage here: in ${houseLabelOf(house)}, the final open seat is the only place left for $digit."
                            } else {
                                "Full House is on stage here: the house has reached its final open seat."
                            }
                        } else if (digit != null && digit != JSONObject.NULL && remaining.length() == 1) {
                            "The house claim is collapsing: in ${houseLabelOf(house)}, only one location can still take $digit."
                        } else {
                            "The house claim is tightening toward a single remaining location."
                        }
                    } else {
                        null
                    }
                }

        val setupBridgeSummary =
            story.optString("setup_bridge_summary").takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        val focusCell = targetResolutionTruth.optJSONObject("focus_cell")
                        val focusLabel = cellLabelOf(focusCell) ?: "the target"
                        if (isFullHouse) {
                            if (digit != null && digit != JSONObject.NULL) {
                                "That is why Full House matters now: once a house is this complete, the final open seat pulls digit $digit straight onto $focusLabel."
                            } else {
                                "That is why Full House matters now: once a house is this complete, the final open seat quietly pulls the answer into place."
                            }
                        } else if (digit != null && digit != JSONObject.NULL) {
                            "As the rival cells in ${houseLabelOf(house)} get ruled out for $digit, that pressure concentrates onto $focusLabel."
                        } else {
                            "As the rival cells get ruled out, the pressure concentrates onto the remaining location."
                        }
                    } else {
                        null
                    }
                }

        val setupWhyThisMatters =
            story.optString("setup_why_this_matters").takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        if (isFullHouse) {
                            "Full House matters because a nearly completed house does not need a long hunt: the last open seat simply inherits the missing digit."
                        } else {
                            "Once the rival cells in the house are eliminated, the remaining location becomes forced."
                        }
                    } else {
                        null
                    }
                }

        val setupDoctrine =
            when (setupProfile) {
                SetupDemandProfileV1.BASE_SINGLES_SETUP,
                SetupDemandProfileV1.FULL_HOUSE_SETUP ->
                    SetupNarrationDoctrineV1.LENS_FIRST

                SetupDemandProfileV1.SUBSETS_SETUP,
                SetupDemandProfileV1.INTERSECTIONS_SETUP,
                SetupDemandProfileV1.ADVANCED_PATTERN_SETUP ->
                    SetupNarrationDoctrineV1.PATTERN_FIRST

                SetupDemandProfileV1.FALLBACK_SETUP ->
                    SetupNarrationDoctrineV1.NEUTRAL
            }

        val techniqueEntranceLabel =
            if (setupProfile == SetupDemandProfileV1.INTERSECTIONS_SETUP) {
                spokenIntersectionTechniqueNameFromSubtypeV1(
                    patternSubtype =
                        story.optString("pattern_subtype").takeIf { it.isNotBlank() }
                            ?: story.optString("interaction_kind").takeIf { it.isNotBlank() }
                            ?: techniqueRealName?.trim()?.lowercase()?.replace(' ', '_')
                            ?: techniqueName?.trim()?.lowercase()?.replace(' ', '_'),
                    overlapCardinality =
                        story.optInt("overlap_cell_count", -1).takeIf { it in 2..3 }
                )
                    ?: techniqueRealName
                    ?: techniqueName
                    ?: techniqueFamily
                    ?: techniqueId
            } else {
                techniqueRealName
                    ?: techniqueName
                    ?: techniqueFamily
                    ?: techniqueId
            }

        val lensQuestion =
            story.optString("setup_lens_question").takeIf { it.isNotBlank() }
                ?: run {
                    if (setupDoctrine == SetupNarrationDoctrineV1.LENS_FIRST) {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        if (isFullHouse && house != null && digit != null && digit != JSONObject.NULL) {
                            "In ${houseLabelOf(house)}, which final seat is still waiting for digit $digit?"
                        } else if (house != null && digit != null && digit != JSONObject.NULL) {
                            "In ${houseLabelOf(house)}, where can digit $digit still live?"
                        } else if (isFullHouse) {
                            "Which final seat in this house is still waiting to be filled?"
                        } else {
                            "Which location is quietly becoming the only legal seat left?"
                        }
                    } else {
                        null
                    }
                }

        val patternBirthSummary =
            story.optString("setup_pattern_birth_summary").takeIf { it.isNotBlank() }
                ?: run {
                    if (setupDoctrine == SetupNarrationDoctrineV1.PATTERN_FIRST) {
                        setupTriggerOverviewSummary
                    } else {
                        null
                    }
                }

        val patternCompletionMoment =
            story.optString("setup_pattern_completion_moment").takeIf { it.isNotBlank() }
                ?: run {
                    if (
                        setupDoctrine == SetupNarrationDoctrineV1.PATTERN_FIRST &&
                        patternMemberProofRows.length() >= 2
                    ) {
                        "That second matching member is the moment the pattern becomes visible enough to matter."
                    } else {
                        null
                    }
                }

        val whyThisTechniqueNow =
            story.optString("setup_why_this_technique_now").takeIf { it.isNotBlank() }
                ?: run {
                    when (setupDoctrine) {
                        SetupNarrationDoctrineV1.LENS_FIRST ->
                            "This is a good moment for a quiet uniqueness scan: the house is tightening, and one digit is running short of legal seats."

                        SetupNarrationDoctrineV1.PATTERN_FIRST ->
                            "This is a good moment for a pattern-based technique: the local structure is organizing itself into something stronger than isolated candidate notes."

                        SetupNarrationDoctrineV1.NEUTRAL ->
                            setupWhyThisMatters
                    }
                }

        val focusHouse =
            story.optJSONObject("setup_primary_house")
                ?: targetResolutionTruth.optJSONObject("primary_house")
                ?: houseClaim.optJSONObject("house")

        val focusDigit =
            houseClaim.opt("digit")
                ?.takeIf { it != JSONObject.NULL }
                ?: targetDigitValue

        val orderedPatternMembers = JSONArray().apply {
            if (patternMemberProofRows.length() > 0) {
                for (i in 0 until patternMemberProofRows.length()) {
                    val row = patternMemberProofRows.optJSONObject(i) ?: continue
                    put(
                        JSONObject().apply {
                            put("member_cell", row.opt("member_cell") ?: JSONObject.NULL)
                            put(
                                "remaining_candidate_digits",
                                row.optJSONArray("remaining_candidate_digits") ?: JSONArray()
                            )
                            put(
                                "claimed_candidate_digits",
                                row.optJSONArray("claimed_candidate_digits") ?: JSONArray()
                            )
                            put(
                                "witness_rows",
                                row.optJSONArray("witness_rows") ?: JSONArray()
                            )
                        }
                    )
                }
            } else {
                for (i in 0 until boundedRows.length()) {
                    val row = boundedRows.optJSONObject(i) ?: continue
                    put(
                        JSONObject().apply {
                            put("member_cell", row.opt("member_cell") ?: JSONObject.NULL)
                            put(
                                "remaining_candidate_digits",
                                row.optJSONArray("surviving_digits") ?: JSONArray()
                            )
                            put("claimed_candidate_digits", row.optJSONArray("surviving_digits") ?: JSONArray())
                            put("grouped_witness_summary", row.opt("grouped_witness_summary") ?: JSONObject.NULL)
                        }
                    )
                }
            }
        }

        val repeatedCandidateDigits =
            when {
                patternMemberProofRows.length() > 0 ->
                    patternMemberProofRows
                        .optJSONObject(0)
