                                (
                                        closureKind.equals("witness_blocked", ignoreCase = true) ||
                                                closureKind.equals("digit_absent", ignoreCase = true) ||
                                                reasonKind.equals("single_cell_witness", ignoreCase = true) ||
                                                reasonKind.equals("candidate_absent", ignoreCase = true)
                                        )

                    if (!keep) continue

                    val normalized = JSONObject(row.toString())
                    val isExplicitWitness =
                        sourceKind.equals("intersection_outside_witness", ignoreCase = true) &&
                                (
                                        closureKind.equals("witness_blocked", ignoreCase = true) ||
                                                reasonKind.equals("single_cell_witness", ignoreCase = true)
                                        )

                    if (isExplicitWitness) {
                        witnessRows.add(normalized)
                    } else {
                        fallbackRows.add(normalized)
                    }
