    private fun canonicalSolvingStepPacketPayloadV1(sAfter: SudoState): JSONObject? =
        sAfter.solvingReadyFactBundlesV1
            .firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
            ?.payload

    private fun canonicalNarrativeTruthV2FromStateV1(sAfter: SudoState): JSONObject? {
        val stepPacket = canonicalSolvingStepPacketPayloadV1(sAfter)
        val evidence = stepPacket?.optJSONObject("evidence")
        val fromPacket =
            evidence?.optJSONObject("narrative_truth_v2")
                ?.takeIf { it.length() > 0 }
        if (fromPacket != null) return JSONObject(fromPacket.toString())

        val envObj = runCatching { sAfter.solveStepJson?.let { JSONObject(it) } }.getOrNull()
        val stepObj = envObj?.optJSONObject("step") ?: envObj

        val fromEnv =
            stepObj?.optJSONObject("evidence")?.optJSONObject("narrative_truth_v2")
                ?: stepObj?.optJSONObject("narrative_truth_v2")

        return fromEnv?.takeIf { it.length() > 0 }?.let { JSONObject(it.toString()) }
    }

    private fun canonicalProofArgsFromStateV1(sAfter: SudoState): JSONObject {
        val narrativeTruth = canonicalNarrativeTruthV2FromStateV1(sAfter)
        val proofPayload = narrativeTruth?.optJSONObject("proof_payload")
        if (proofPayload != null && proofPayload.length() > 0) {
            return JSONObject(proofPayload.toString())
        }
        return preferredProofAtomArgsV1(sAfter)
    }

    private fun buildCanonicalStageTruthV1(
        sAfter: SudoState,
        fallbackTargetCell: JSONObject?,
        fallbackPrimaryHouse: JSONObject?,
        fallbackTargetDigit: Int?
    ): JSONObject {
        val proofArgs = canonicalProofArgsFromStateV1(sAfter)
        val narrativeTruth = canonicalNarrativeTruthV2FromStateV1(sAfter)
        val targetResolutionTruth =
            buildTargetResolutionTruthV1(
                proofArgs = proofArgs,
                narrativeTruth = narrativeTruth,
                fallbackTargetCell = fallbackTargetCell,
                fallbackPrimaryHouse = fallbackPrimaryHouse,
                fallbackTargetDigit = fallbackTargetDigit
            )

        val hasNarrativeProofPayload =
            narrativeTruth?.optJSONObject("proof_payload")?.length() ?: 0 > 0

        val hasWave1IntersectionStoryTruth =
            narrativeTruth?.optJSONObject("trigger_pattern")?.length() ?: 0 > 0 ||
                    narrativeTruth?.optJSONObject("trigger_explanation")?.length() ?: 0 > 0 ||
                    narrativeTruth?.optJSONObject("trigger_bridge")?.length() ?: 0 > 0 ||
                    narrativeTruth?.optJSONObject("confrontation_summary")?.length() ?: 0 > 0 ||
                    narrativeTruth?.optJSONObject("final_resolution")?.length() ?: 0 > 0 ||
                    narrativeTruth?.optJSONObject("source_confinement_proof")?.length() ?: 0 > 0

        val source =
            when {
                hasNarrativeProofPayload || hasWave1IntersectionStoryTruth ->
                    "packet.evidence.narrative_truth_v2"
                proofArgs.length() > 0 ->
                    "packet.evidence.narrative_atoms_v1_or_stage_fallback"
                else ->
                    "empty"
            }

        return JSONObject().apply {
            put("source_of_truth", source)
            put("narrative_truth_v2", narrativeTruth ?: JSONObject.NULL)
            put("proof_args", proofArgs)
            put("target_resolution_truth", targetResolutionTruth)
        }
    }



    private fun preferredProofAtomArgsV1(sAfter: SudoState): JSONObject {
        val atomsArr = narrativeAtomsArrayFromState(sAfter) ?: JSONArray()
        val ns = sAfter.narrativeStory

        fun argsAt(index: Int): JSONObject? =
            atomsArr
                .optJSONObject(index)
                ?.optJSONObject("claim")
                ?.optJSONObject("args")

        fun hasProofPayload(args: JSONObject?): Boolean {
            if (args == null) return false

            val proofPayload = args.optJSONObject("proof_payload")
            if (proofPayload != null && proofPayload.length() > 0) {
                if (hasProofPayload(proofPayload)) return true
            }

            val support = args.optJSONObject("support")

            return args.has("blocker_rows") ||
                    args.has("peer_witness_rows") ||
                    args.has("witness_by_digit") ||
                    args.has("forcing_summary") ||
                    args.has("claimed_candidate_digits") ||
                    args.has("remaining_candidate_digits") ||
                    args.has("house_claim") ||
                    args.has("remaining_candidate_cells") ||
                    args.has("claimed_candidate_cells") ||
                    args.has("default_candidate_cells") ||
                    args.has("witness_by_cell") ||
                    args.has("peer_witness_pairs") ||
                    (support?.has("witness_by_digit") == true) ||
                    (support?.has("blocker_rows") == true) ||
                    (support?.has("peer_witness_rows") == true) ||
                    (support?.has("forcing_summary") == true) ||
                    (support?.has("witness_by_cell") == true) ||
                    (support?.has("peer_witness_pairs") == true)
        }

        val narrativeTruth = canonicalNarrativeTruthV2FromStateV1(sAfter)
        val narrativeTruthProofPayload = narrativeTruth?.optJSONObject("proof_payload")
        if (hasProofPayload(narrativeTruthProofPayload)) {
            return JSONObject(narrativeTruthProofPayload.toString())
        }

        var witnessEliminationIndex = -1
        for (i in 0 until atomsArr.length()) {
            val a = atomsArr.optJSONObject(i) ?: continue
            if (a.optString("beat_kind") == "WITNESS_ELIMINATION") {
                witnessEliminationIndex = i
                break
            }
        }

        val witnessArgs =
            if (witnessEliminationIndex >= 0) argsAt(witnessEliminationIndex) else null
        if (hasProofPayload(witnessArgs)) return JSONObject(witnessArgs.toString())

        val focusIndex = ns?.focusAtomIndex ?: -1
        val focusArgs =
            if (focusIndex >= 0) argsAt(focusIndex) else null
        if (hasProofPayload(focusArgs)) return JSONObject(focusArgs.toString())

        if (focusArgs != null) return JSONObject(focusArgs.toString())
        if (witnessArgs != null) return JSONObject(witnessArgs.toString())

        return JSONObject()
    }



    private fun buildTargetResolutionTruthV1(
        proofArgs: JSONObject,
        narrativeTruth: JSONObject?,
        fallbackTargetCell: JSONObject?,
        fallbackPrimaryHouse: JSONObject?,
        fallbackTargetDigit: Int?
    ): JSONObject {
        fun cloneObject(obj: JSONObject?): JSONObject? =
            obj?.let { JSONObject(it.toString()) }

        fun cloneArray(arr: JSONArray?): JSONArray =
            arr?.let { JSONArray(it.toString()) } ?: JSONArray()

        fun firstNonEmptyArray(vararg candidates: JSONArray?): JSONArray? {
            for (candidate in candidates) {
                if (candidate != null && candidate.length() > 0) {
                    return JSONArray(candidate.toString())
                }
            }
            return null
        }

        fun firstNonEmptyObject(vararg candidates: JSONObject?): JSONObject? {
            for (candidate in candidates) {
                if (candidate != null && candidate.length() > 0) {
                    return JSONObject(candidate.toString())
                }
            }
            return null
        }

        fun cellLabelOf(cell: JSONObject?): String? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            return if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
        }

        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the house"
            }
        }

        fun boxIndex1to9Of(cell: JSONObject?): Int? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            if (r !in 1..9 || c !in 1..9) return null
            return ((r - 1) / 3) * 3 + ((c - 1) / 3) + 1
        }



        fun relationHouseFromPair(relation: String, witnessCell: JSONObject?): JSONObject? =
            when (relation) {
                "SAME_ROW" ->
                    witnessCell?.opt("r")?.let { row ->
                        JSONObject().apply {
                            put("type", "row")
                            put("index1to9", row)
                        }
                    }
                "SAME_COL" ->
                    witnessCell?.opt("c")?.let { col ->
                        JSONObject().apply {
                            put("type", "col")
                            put("index1to9", col)
                        }
                    }
                "SAME_BOX" ->
                    boxIndex1to9Of(witnessCell)?.let { box ->
                        JSONObject().apply {
                            put("type", "box")
                            put("index1to9", box)
                        }
                    }
                else -> null
            }

        fun normalizePeerWitnessPairsFromWitnessByCell(
            witnessByCell: JSONArray,
            fallbackDigitValue: Any?,
            fallbackHouse: JSONObject?
        ): JSONArray {
            val out = JSONArray()
            for (i in 0 until witnessByCell.length()) {
                val row = witnessByCell.optJSONObject(i) ?: continue
                val claimedCell = row.optJSONObject("claimed_cell")
                val witness = row.optJSONObject("witness") ?: JSONObject()
                val witnessCell = witness.optJSONObject("cell")
                val relation = witness.optString("relation")
                val digit =
                    if (!witness.isNull("digit")) {
                        witness.opt("digit")
                    } else {
                        fallbackDigitValue ?: JSONObject.NULL
                    }

                out.put(
                    JSONObject().apply {
                        put("peer_cell", claimedCell ?: JSONObject.NULL)
                        put("witness_cell", witnessCell ?: JSONObject.NULL)
                        put("relation", relation.ifBlank { JSONObject.NULL as String? } ?: JSONObject.NULL)
                        put("digit", digit)
                        put(
                            "house_scope",
                            relationHouseFromPair(relation, witnessCell)
                                ?: fallbackHouse
                                ?: JSONObject.NULL
                        )
                    }
                )
            }
            return out
        }

        fun normalizePeerWitnessRowsFromPairs(
            peerWitnessPairs: JSONArray,
            fallbackHouse: JSONObject?
        ): JSONArray {
            val out = JSONArray()
            for (i in 0 until peerWitnessPairs.length()) {
                val pair = peerWitnessPairs.optJSONObject(i) ?: continue
                val witnessCell = pair.optJSONObject("witness_cell")
                val relation = pair.optString("relation")
                out.put(
                    JSONObject().apply {
                        put("digit", pair.opt("digit") ?: JSONObject.NULL)
                        put("witness_cell", witnessCell ?: JSONObject.NULL)
                        put("relation", relation.ifBlank { JSONObject.NULL as String? } ?: JSONObject.NULL)
                        put(
                            "relation_house",
                            relationHouseFromPair(relation, witnessCell)
                                ?: fallbackHouse
                                ?: JSONObject.NULL
                        )
                    }
                )
            }
            return out
        }

        fun normalizeHouseBlockerRowsFromPairs(
            peerWitnessPairs: JSONArray,
            fallbackHouse: JSONObject?
        ): JSONArray {
            val out = JSONArray()
            for (i in 0 until peerWitnessPairs.length()) {
                val pair = peerWitnessPairs.optJSONObject(i) ?: continue
                val witnessCell = pair.optJSONObject("witness_cell")
                val relation = pair.optString("relation")

                out.put(
                    JSONObject().apply {
                        put("digit", pair.opt("digit") ?: JSONObject.NULL)
                        put("claimed_cell", pair.optJSONObject("peer_cell") ?: JSONObject.NULL)
                        put("source_kind", "peer_witness")
                        put("witness_cell", witnessCell ?: JSONObject.NULL)
                        put("relation", relation.ifBlank { JSONObject.NULL as String? } ?: JSONObject.NULL)
                        put(
                            "house_scope",
                            relationHouseFromPair(relation, witnessCell)
                                ?: fallbackHouse
                                ?: JSONObject.NULL
                        )
                    }
                )


            }
            return out
        }

        fun normalizePeerBlockerRowsFromPairs(
            peerWitnessPairs: JSONArray,
            fallbackHouse: JSONObject?
        ): JSONArray {
            val out = JSONArray()
            for (i in 0 until peerWitnessPairs.length()) {
                val pair = peerWitnessPairs.optJSONObject(i) ?: continue
                val witnessCell = pair.optJSONObject("witness_cell")
                val relation = pair.optString("relation")
                val digit = pair.opt("digit") ?: JSONObject.NULL
                val witnessLabel = cellLabelOf(witnessCell) ?: "that witness cell"
                val houseScope = relationHouseFromPair(relation, witnessCell) ?: fallbackHouse

                val because =
                    when (relation) {
                        "SAME_ROW" -> "$witnessLabel already occupies that digit in the same row."
                        "SAME_COL" -> "$witnessLabel already occupies that digit in the same column."
                        "SAME_BOX" -> "$witnessLabel already occupies that digit in the same box."
                        else -> "$witnessLabel already blocks that candidate."
                    }

                val spokenLine =
                    when (relation) {
                        "SAME_ROW" -> "In the same row, $witnessLabel already takes $digit."
                        "SAME_COL" -> "In the same column, $witnessLabel already takes $digit."
                        "SAME_BOX" -> "In the same box, $witnessLabel already takes $digit."
                        else -> "$witnessLabel blocks that candidate."
                    }

                out.put(
                    JSONObject().apply {
                        put("digit", digit)
                        put("claimed_cell", pair.optJSONObject("peer_cell") ?: JSONObject.NULL)
                        put("cell", witnessCell ?: JSONObject.NULL)
                        put("house_scope", houseScope ?: JSONObject.NULL)
                        put("because", because)
                        put("spoken_line", spokenLine)
                        put("source_kind", "peer_witness")
                    }
                )
            }
            return out
        }


        fun normalizeHouseOrderedProofLadder(
            blockerRows: JSONArray,
            fallbackHouse: JSONObject?,
            survivingDigit: Any?,
            survivingCell: JSONObject?
        ): JSONArray {
            val out = JSONArray()
            val houseLabel = houseLabelOf(fallbackHouse)
            val survivingCellLabel = cellLabelOf(survivingCell) ?: "the target cell"

            if (blockerRows.length() > 0) {
                val witnessLabels = linkedSetOf<String>()
                for (i in 0 until blockerRows.length()) {
                    val row = blockerRows.optJSONObject(i) ?: continue
                    val witnessLabel = cellLabelOf(row.optJSONObject("cell"))
                    if (!witnessLabel.isNullOrBlank()) {
                        witnessLabels += witnessLabel
                    }
                }

                val witnessSummary =
                    when {
                        witnessLabels.isEmpty() -> "the established witnesses"
                        witnessLabels.size <= 3 -> witnessLabels.joinToString(", ")
                        else -> witnessLabels.take(3).joinToString(", ") + ", and others"
                    }

                out.put(
                    JSONObject().apply {
                        put("step_kind", "peer_cleanup")
                        put(
                            "summary",
                            "In $houseLabel, $witnessSummary rule out the rival cells that were still competing for $survivingDigit."
                        )
                        put("house_scope", fallbackHouse ?: JSONObject.NULL)
                        put("eliminated_digits", JSONArray())
                        put("supporting_rows", JSONArray(blockerRows.toString()))
                        put("surviving_digit", JSONObject.NULL)
                    }
                )
            }

            out.put(
                JSONObject().apply {
                    put("step_kind", "target_collapse")
                    put(
                        "summary",
                        "After those rival cells are eliminated in $houseLabel, only $survivingCellLabel remains for $survivingDigit."
                    )
                    put("surviving_digit", survivingDigit ?: JSONObject.NULL)
                    put("surviving_cell", survivingCell ?: JSONObject.NULL)
                    put("house_scope", fallbackHouse ?: JSONObject.NULL)
                }
            )

            return out
        }





        val proofRoot = proofArgs.optJSONObject("proof_payload") ?: proofArgs


        val nestedHouseClaim = proofRoot.optJSONObject("house_claim") ?: JSONObject()
        val nestedSupport = proofRoot.optJSONObject("support") ?: JSONObject()
        val nestedCellOutcome = proofRoot.optJSONObject("cell_outcome") ?: JSONObject()

        val proofIntersectionControl = proofRoot.optJSONObject("intersection_control") ?: JSONObject()
        val narrativeProofPayload = narrativeTruth?.optJSONObject("proof_payload") ?: JSONObject()
        val narrativeIntersectionControl =
            narrativeProofPayload.optJSONObject("intersection_control") ?: JSONObject()
        val intersectionControl =
            if (proofIntersectionControl.length() > 0) {
                proofIntersectionControl
            } else {
                narrativeIntersectionControl
            }

        val triggerBridge = narrativeTruth?.optJSONObject("trigger_bridge") ?: JSONObject()
        val targetRelation = triggerBridge.optJSONObject("target_relation") ?: JSONObject()
        val sweepRelation = triggerBridge.optJSONObject("sweep_relation") ?: JSONObject()
        val finalResolution = narrativeTruth?.optJSONObject("final_resolution") ?: JSONObject()
        val finalCellOutcome = finalResolution.optJSONObject("cell_outcome") ?: JSONObject()


        val explicitResolutionKind =
            targetRelation.optString("resolution_kind")
                .ifBlank { triggerBridge.optString("resolution_kind") }
                .ifBlank { finalResolution.optString("kind") }
                .ifBlank {
                    narrativeTruth
                        ?.optJSONObject("target")
                        ?.optString("final_resolution_kind")
                        .orEmpty()
                }
                .ifBlank { proofRoot.optString("downstream_resolution_kind") }
                .ifBlank { proofRoot.optString("resolution_kind") }
                .ifBlank { proofRoot.optString("elimination_kind") }

        val downstreamKind =
            explicitResolutionKind.ifBlank {
                when {
                    nestedCellOutcome.length() > 0 ||
                            finalCellOutcome.length() > 0 ||
                            targetRelation.optString("kind") == "cleanup_target_cell" ||
                            proofRoot.has("remaining_candidate_digits") ||
                            proofRoot.has("claimed_candidate_digits") -> {
                        "CELL_CANDIDATE_DIGITS"
                    }
                    nestedHouseClaim.length() > 0 ||
                            proofRoot.has("remaining_candidate_cells") ||
                            proofRoot.has("claimed_candidate_cells") ||
                            proofRoot.has("default_candidate_cells") ||
                            nestedSupport.has("peer_witness_pairs") ||
                            nestedSupport.has("witness_by_cell") -> {
                        "HOUSE_CANDIDATE_CELLS_FOR_DIGIT"
                    }
                    else -> {
                        "HOUSE_CANDIDATE_CELLS_FOR_DIGIT"
                    }
                }
            }

        val out = JSONObject()
        out.put("elimination_kind", downstreamKind)

        if (downstreamKind == "CELL_CANDIDATE_DIGITS") {
            val resolvedFocusCell =
                proofRoot.optJSONObject("target_cell")
                    ?: nestedCellOutcome.optJSONObject("cell")
                    ?: targetRelation.optJSONObject("focus_cell")
                    ?: finalCellOutcome.optJSONObject("cell")
                    ?: fallbackTargetCell

            val resolvedPrimaryHouse =
                sweepRelation.optJSONObject("house")
                    ?: fallbackPrimaryHouse

            val resolvedDigit =
                when {
                    !targetRelation.isNull("target_digit") -> targetRelation.opt("target_digit")
                    fallbackTargetDigit != null -> fallbackTargetDigit
                    !proofRoot.isNull("digit") -> proofRoot.opt("digit")
                    else -> JSONObject.NULL
                }

            val remainingCandidateDigits =
                firstNonEmptyArray(
                    nestedCellOutcome.optJSONArray("remaining_candidate_digits"),
                    finalCellOutcome.optJSONArray("remaining_candidate_digits"),
                    targetRelation.optJSONArray("remaining_candidate_digits"),
                    proofRoot.optJSONArray("remaining_candidate_digits"),
                    nestedSupport.optJSONArray("remaining_candidate_digits")
                ) ?: JSONArray()

            val claimedCandidateDigits =
                firstNonEmptyArray(
                    nestedCellOutcome.optJSONArray("claimed_candidate_digits"),
                    finalCellOutcome.optJSONArray("claimed_candidate_digits"),
                    targetRelation.optJSONArray("claimed_candidate_digits"),
                    proofRoot.optJSONArray("claimed_candidate_digits"),
                    nestedSupport.optJSONArray("claimed_candidate_digits")
                ) ?: JSONArray()

            val cellOutcome = JSONObject().apply {
                put("cell", resolvedFocusCell ?: JSONObject.NULL)
                put("remaining_candidate_digits", remainingCandidateDigits)
                put("claimed_candidate_digits", claimedCandidateDigits)
            }

            val forcingSummary =
                firstNonEmptyObject(
                    proofRoot.optJSONObject("forcing_summary"),
                    nestedSupport.optJSONObject("forcing_summary")
                ) ?: JSONObject().apply {
                    put("remaining_candidate_digits", cloneArray(remainingCandidateDigits))
                    put("claimed_candidate_digits", cloneArray(claimedCandidateDigits))
                }

            val support = JSONObject().apply {
                put(
                    "witness_by_digit",
                    proofRoot.optJSONArray("witness_by_digit")
                        ?: nestedSupport.optJSONArray("witness_by_digit")
                        ?: JSONArray()
                )
                put(
                    "blocker_rows",
                    proofRoot.optJSONArray("blocker_rows")
                        ?: nestedSupport.optJSONArray("blocker_rows")
                        ?: JSONArray()
                )
                put(
                    "peer_witness_rows",
                    proofRoot.optJSONArray("peer_witness_rows")
                        ?: nestedSupport.optJSONArray("peer_witness_rows")
                        ?: JSONArray()
                )
                put("forcing_summary", forcingSummary)
            }

            out.put("focus_cell", resolvedFocusCell ?: JSONObject.NULL)
            out.put("primary_house", resolvedPrimaryHouse ?: JSONObject.NULL)
            out.put("digit", resolvedDigit)
            out.put("cell_outcome", cellOutcome)
            out.put("support", support)
            return out
        }

        val resolvedDigit =
            when {
                !nestedHouseClaim.isNull("digit") -> nestedHouseClaim.opt("digit")
                fallbackTargetDigit != null -> fallbackTargetDigit
                !proofRoot.isNull("digit") -> proofRoot.opt("digit")
                else -> JSONObject.NULL
            }

        val remainingCandidateCells =
            firstNonEmptyArray(
                nestedHouseClaim.optJSONArray("remaining_candidate_cells"),
                proofRoot.optJSONArray("remaining_candidate_cells")
            ) ?: JSONArray()

        val claimedCandidateCells =
            firstNonEmptyArray(
                nestedHouseClaim.optJSONArray("claimed_candidate_cells"),
                proofRoot.optJSONArray("claimed_candidate_cells")
            ) ?: JSONArray()

        val defaultCandidateCells =
            firstNonEmptyArray(
                nestedHouseClaim.optJSONArray("default_candidate_cells"),
                proofRoot.optJSONArray("default_candidate_cells"),
                if (claimedCandidateCells.length() > 0 || remainingCandidateCells.length() > 0) {
                    JSONArray().apply {
                        for (i in 0 until claimedCandidateCells.length()) {
                            put(claimedCandidateCells.opt(i))
                        }
                        for (i in 0 until remainingCandidateCells.length()) {
                            put(remainingCandidateCells.opt(i))
                        }
                    }
                } else {
                    null
                }
            ) ?: JSONArray()

        val resolvedHouse =
            cloneObject(finalResolution.optJSONObject("target_house"))
                ?: cloneObject(finalResolution.optJSONObject("primary_house"))
                ?: cloneObject(nestedHouseClaim.optJSONObject("house"))
                ?: cloneObject(proofRoot.optJSONObject("house"))
                ?: cloneObject(fallbackPrimaryHouse)

        val explicitPeerWitnessPairs =
            firstNonEmptyArray(
                nestedSupport.optJSONArray("peer_witness_pairs"),
                proofRoot.optJSONArray("peer_witness_pairs")
            )

        val witnessByCell =
            firstNonEmptyArray(
                nestedSupport.optJSONArray("witness_by_cell"),
                proofRoot.optJSONArray("witness_by_cell")
            ) ?: JSONArray()

        val peerWitnessPairs =
            explicitPeerWitnessPairs
                ?: normalizePeerWitnessPairsFromWitnessByCell(
                    witnessByCell = witnessByCell,
                    fallbackDigitValue = resolvedDigit,
                    fallbackHouse = resolvedHouse
                )

        val peerWitnessRows =
            firstNonEmptyArray(
                proofRoot.optJSONArray("peer_witness_rows"),
                nestedSupport.optJSONArray("peer_witness_rows")
            ) ?: normalizePeerWitnessRowsFromPairs(peerWitnessPairs, resolvedHouse)

        val blockerRows =
            firstNonEmptyArray(
                proofRoot.optJSONArray("blocker_rows"),
                nestedSupport.optJSONArray("blocker_rows")
            ) ?: normalizeHouseBlockerRowsFromPairs(peerWitnessPairs, resolvedHouse)


        val peerBlockerRows =
            firstNonEmptyArray(
                proofRoot.optJSONArray("peer_blocker_rows"),
                nestedSupport.optJSONArray("peer_blocker_rows"),
                intersectionControl.optJSONArray("ordinary_witness_group")
            ) ?: normalizePeerBlockerRowsFromPairs(peerWitnessPairs, resolvedHouse)


        val forcingSummary =
            firstNonEmptyObject(
                proofRoot.optJSONObject("forcing_summary"),
                nestedSupport.optJSONObject("forcing_summary")
            ) ?: JSONObject().apply {
                put("remaining_candidate_cells", cloneArray(remainingCandidateCells))
                put("claimed_candidate_cells", cloneArray(claimedCandidateCells))
            }

        val resolvedFocusCell =
            finalResolution.optJSONObject("focus_cell")
                ?: proofRoot.optJSONObject("target_cell")
                ?: fallbackTargetCell
                ?: run {
                    if (remainingCandidateCells.length() == 1) {
                        remainingCandidateCells.optJSONObject(0)
                    } else {
                        null
                    }
                }

        val orderedProofLadder =
            firstNonEmptyArray(
                proofRoot.optJSONArray("ordered_proof_ladder"),
                nestedSupport.optJSONArray("ordered_proof_ladder"),
                intersectionControl.optJSONArray("ordered_proof_ladder")
            ) ?: normalizeHouseOrderedProofLadder(
                blockerRows = peerBlockerRows,
                fallbackHouse = resolvedHouse,
                survivingDigit = resolvedDigit,
                survivingCell = resolvedFocusCell
            )

        val support = JSONObject().apply {
            put("peer_witness_rows", peerWitnessRows)
            put("peer_witness_pairs", peerWitnessPairs)
            put("blocker_rows", blockerRows)
            put("forcing_summary", forcingSummary)
            put(
                "technique_blocker_rows",
                firstNonEmptyArray(
                    proofRoot.optJSONArray("technique_blocker_rows"),
                    nestedSupport.optJSONArray("technique_blocker_rows"),
                    intersectionControl.optJSONArray("hero_elimination_group")
                ) ?: JSONArray()
            )
            put("peer_blocker_rows", peerBlockerRows)
            put("ordered_proof_ladder", orderedProofLadder)
            put(
                "ordinary_witness_first_required",
                nestedSupport.optBoolean("ordinary_witness_first_required", false) ||
                        intersectionControl.optJSONArray("ordinary_witness_group")?.length() ?: 0 > 0
            )
            put(
                "technique_finishing_cut_required",
                nestedSupport.optBoolean("technique_finishing_cut_required", false) ||
                        intersectionControl.optJSONArray("hero_elimination_group")?.length() ?: 0 > 0
            )
            put(
                "actor_structure",
                nestedSupport.optString("actor_structure").takeIf { it.isNotBlank() }
                    ?: "First the ordinary Sudoku blockers clear the obvious rivals. Then the intersection pattern delivers the decisive territorial cut."
            )
            put(
                "target_spotlight_line",
                nestedSupport.optString("target_spotlight_line").takeIf { it.isNotBlank() }
                    ?: intersectionControl.optString("target_spotlight_line").takeIf { it.isNotBlank() }
                    ?: JSONObject.NULL
            )
            put(
                "survivor_reveal_line",
                nestedSupport.optString("survivor_reveal_line").takeIf { it.isNotBlank() }
                    ?: intersectionControl.optString("survivor_reveal_line").takeIf { it.isNotBlank() }
                    ?: JSONObject.NULL
            )
        }

        val houseClaim = JSONObject().apply {
            put("digit", resolvedDigit)
            put("house", resolvedHouse ?: JSONObject.NULL)
            put("remaining_candidate_cells", remainingCandidateCells)
            put("claimed_candidate_cells", claimedCandidateCells)
            put("default_candidate_cells", defaultCandidateCells)
        }

        out.put("focus_cell", resolvedFocusCell ?: JSONObject.NULL)
        out.put("primary_house", resolvedHouse ?: JSONObject.NULL)
        out.put("digit", resolvedDigit)
        out.put("house_claim", houseClaim)
        out.put("support", support)
        return out
    }

    private fun defaultConfrontationCollapseSummaryFromTruthV1(
        targetResolutionTruth: JSONObject,
        fallbackSurvivingDigit: Int?
    ): String {
        val kind = targetResolutionTruth.optString("elimination_kind")

        return if (kind == "CELL_CANDIDATE_DIGITS") {
            val cellOutcome = targetResolutionTruth.optJSONObject("cell_outcome") ?: JSONObject()
            val remaining = cellOutcome.optJSONArray("remaining_candidate_digits") ?: JSONArray()
            val surviving = if (remaining.length() == 1) remaining.opt(0) else fallbackSurvivingDigit

            if (surviving != null && surviving != JSONObject.NULL) {
                "After combining the technique’s effect with the remaining blockers on the target, only $surviving remains."
            } else {
                "After combining the technique’s effect with the remaining blockers on the target, only one candidate remains."
            }
        } else {
            val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
            val digit = houseClaim.opt("digit")
            val remainingCells = houseClaim.optJSONArray("remaining_candidate_cells") ?: JSONArray()

            if (digit != JSONObject.NULL && remainingCells.length() == 1) {
                "After combining the technique’s effect with the remaining witnesses in the house, only one cell is left for $digit."
            } else {
                "After combining the technique’s effect with the remaining witnesses in the house, the target is reduced to a single remaining location."
            }
        }
    }

    private fun defaultResolutionRecapSummaryFromTruthV1(
        targetResolutionTruth: JSONObject,
        archetype: String? = null
    ): String {
        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the house"
            }
        }

        fun cellLabelOf(cell: JSONObject?): String? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            return if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
        }

        return when (targetResolutionTruth.optString("elimination_kind")) {
            "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" -> {
                val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
                val house = houseClaim.optJSONObject("house")
                val digit = houseClaim.opt("digit")
                val focusCell =
                    targetResolutionTruth.optJSONObject("focus_cell")
                        ?: houseClaim.optJSONArray("remaining_candidate_cells")?.optJSONObject(0)
                val focusLabel = cellLabelOf(focusCell) ?: "the target cell"

                if (archetype?.trim()?.uppercase() == "FULL_HOUSE") {
                    if (digit != null && digit != JSONObject.NULL) {
                        "Full House closes the scene neatly here: in ${houseLabelOf(house)}, the final open seat belonged to $digit, so only $focusLabel was left."
                    } else {
                        "Full House closes the scene neatly here: the house had one final open seat, and it led straight to $focusLabel."
                    }
                } else if (archetype?.trim()?.uppercase() == "INTERSECTIONS" && digit != null && digit != JSONObject.NULL) {
                    "In ${houseLabelOf(house)}, the rival locations for $digit were cleared until only $focusLabel was left standing."
                } else if (digit != null && digit != JSONObject.NULL) {
                    "In ${houseLabelOf(house)}, the rival locations for $digit were ruled out until only $focusLabel was left."
                } else {
                    "In ${houseLabelOf(house)}, the rival locations were ruled out until only $focusLabel was left."
                }
            }

            else ->
                "The technique removed part of the pressure, the remaining witnesses removed the rest, and the target finished as a single."
        }
    }

    private fun defaultResolutionTechniqueContributionFromTruthV1(
        targetResolutionTruth: JSONObject,
        archetype: String?
    ): String {
        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the house"
            }
        }

        return when (targetResolutionTruth.optString("elimination_kind")) {
            "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" -> {
                val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
                val house = houseClaim.optJSONObject("house")
                val digit = houseClaim.opt("digit")
                if (archetype?.trim()?.uppercase() == "FULL_HOUSE") {
                    if (digit != null && digit != JSONObject.NULL) {
                        "The technique contribution was Full House itself: it recognized that ${houseLabelOf(house)} was down to its last open seat for $digit."
                    } else {
                        "The technique contribution was Full House itself: it recognized that the active house was down to its last open seat."
                    }
                } else if (digit != null && digit != JSONObject.NULL) {
                    "The technique contribution was to narrow ${houseLabelOf(house)} until only one location could still take $digit."
                } else {
                    "The technique contribution was to narrow the active house until only one location remained."
                }
            }

            else ->
                if (archetype == "SUBSETS" || archetype == "INTERSECTIONS") {
                    "The technique contribution was a cleanup that removed some target candidates, but not the whole proof by itself."
                } else {
                    "The technique contribution was to remove part of the target’s remaining ambiguity."
                }
        }
    }

    private fun defaultResolutionFinalForcingFromTruthV1(
        targetResolutionTruth: JSONObject,
        commitDigit: Int?,
        archetype: String? = null
    ): String {
        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the house"
            }
        }

        fun cellLabelOf(cell: JSONObject?): String? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            return if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
        }

        return when (targetResolutionTruth.optString("elimination_kind")) {
            "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" -> {
                val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
                val house = houseClaim.optJSONObject("house")
                val focusCell =
                    targetResolutionTruth.optJSONObject("focus_cell")
                        ?: houseClaim.optJSONArray("remaining_candidate_cells")?.optJSONObject(0)
                val focusLabel = cellLabelOf(focusCell) ?: "the target cell"
                val digit =
                    when {
                        !houseClaim.isNull("digit") -> houseClaim.opt("digit")
                        commitDigit != null -> commitDigit
                        else -> JSONObject.NULL
                    }

                if (archetype?.trim()?.uppercase() == "FULL_HOUSE") {
                    if (digit != JSONObject.NULL) {
                        "Once ${houseLabelOf(house)} reached its final opening, only $focusLabel remained for $digit."
                    } else {
                        "Once the house reached its final opening, only the target location remained."
                    }
                } else if (digit != JSONObject.NULL) {
                    "Once the rival cells in ${houseLabelOf(house)} were ruled out, only $focusLabel remained for $digit."
                } else {
                    "Once the rival cells in ${houseLabelOf(house)} were ruled out, only the target location remained."
                }
            }

            else ->
                if (commitDigit != null) {
                    "Once the remaining wrong candidates were removed, $commitDigit was the only value left for the target."
                } else {
                    "Once the remaining wrong candidates were removed, the target was forced to a single value."
                }
        }
    }


    private fun buildIntersectionResolutionCausalRecapV1(
        targetResolutionTruth: JSONObject,
        commitCell: JSONObject?,
        commitDigit: Int?
    ): JSONObject {
        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the active house"
            }
        }

        fun cellLabelOf(cell: JSONObject?): String? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            return if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
        }

        val support = targetResolutionTruth.optJSONObject("support") ?: JSONObject()
        val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
        val houseBattlefieldProof = support.optJSONObject("house_battlefield_proof") ?: JSONObject()
        val primaryHouse =
            houseBattlefieldProof.optJSONObject("battlefield_house")
                ?: targetResolutionTruth.optJSONObject("battlefield_house")
                ?: targetResolutionTruth.optJSONObject("primary_house")
                ?: houseClaim.optJSONObject("house")
        val sourceHouse = targetResolutionTruth.optJSONObject("source_house")

        val sourceOverlap = targetResolutionTruth.optJSONArray("source_overlap_cells") ?: JSONArray()
        val peerRows = support.optJSONArray("peer_blocker_rows") ?: JSONArray()
        val techniqueRows = support.optJSONArray("technique_blocker_rows") ?: JSONArray()
        val focusCell =
            targetResolutionTruth.optJSONObject("focus_cell")
                ?: commitCell

        val finalRival =
            techniqueRows.optJSONObject(0)?.optJSONObject("claimed_cell")
                ?: techniqueRows.optJSONObject(0)?.optJSONObject("forbidden_cell")

        val overlapSummary =
            if (sourceOverlap.length() >= 2) {
                val labels =
                    buildList {
                        for (i in 0 until sourceOverlap.length()) {
                            val label = cellLabelOf(sourceOverlap.optJSONObject(i))
                            if (!label.isNullOrBlank()) add(label)
                        }
                    }
                if (labels.isNotEmpty()) labels.joinToString(" or ") else null
            } else {
                null
            }

        val ordinaryGroundworkLine: String? =
            if (peerRows.length() > 0 && commitDigit != null) {
                "The standard blockers did the groundwork in ${houseLabelOf(primaryHouse)}, clearing away the obvious rival seats for $commitDigit."
            } else if (peerRows.length() > 0) {
                "The standard blockers did the groundwork in ${houseLabelOf(primaryHouse)}, clearing away the obvious rival seats."
            } else {
                null
            }

        val decisiveCutLine: String? =
            when {
                finalRival != null && commitDigit != null && sourceHouse != null -> {
                    val rivalLabel = cellLabelOf(finalRival) ?: "the last competing seat"
                    if (!overlapSummary.isNullOrBlank()) {
                        "The final cut came from the intersection pattern: once ${houseLabelOf(sourceHouse)} had already claimed $commitDigit inside $overlapSummary, $rivalLabel had to let that digit go."
                    } else {
                        "The final cut came from the intersection pattern: once ${houseLabelOf(sourceHouse)} had already claimed $commitDigit in the overlap, $rivalLabel had to let that digit go."
                    }
                }

                techniqueRows.length() > 0 && sourceHouse != null -> {
                    "The final cut came from the intersection pattern, which reached out from ${houseLabelOf(sourceHouse)} and removed the last competing seat."
                }

                else -> null
            }

        val survivorLine: String? =
            if (commitDigit != null && focusCell != null && primaryHouse != null) {
                val focusLabel = cellLabelOf(focusCell) ?: "the target cell"
                "That left only $focusLabel standing for $commitDigit in ${houseLabelOf(primaryHouse)}."
            } else {
                null
            }

        return JSONObject().apply {
            put("battlefield_house", primaryHouse ?: JSONObject.NULL)
            put("source_house", sourceHouse ?: JSONObject.NULL)
            put("source_overlap_cells", sourceOverlap)
            put("final_removed_rival", finalRival ?: JSONObject.NULL)
            put("ordinary_groundwork_line", ordinaryGroundworkLine ?: JSONObject.NULL)
            put("decisive_cut_line", decisiveCutLine ?: JSONObject.NULL)
            put("survivor_line", survivorLine ?: JSONObject.NULL)
            put(
                "birthplace_vs_battleground_line",
                when {
                    sourceHouse != null && primaryHouse != null ->
                        "The trap was born in ${houseLabelOf(sourceHouse)}, but the victory was won in ${houseLabelOf(primaryHouse)}."
                    else -> JSONObject.NULL
                }
            )
        }
    }

    private fun buildIntersectionResolutionStructuralLessonV1(
        targetResolutionTruth: JSONObject,
        commitDigit: Int?
    ): JSONObject {
        fun houseLabelOf(house: JSONObject?): String {
            val type = house?.optString("type").orEmpty()
            val index = house?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the active house"
            }
        }

        val sourceHouse = targetResolutionTruth.optJSONObject("source_house")
        val primaryHouse =
            targetResolutionTruth.optJSONObject("primary_house")
                ?: targetResolutionTruth.optJSONObject("house_claim")?.optJSONObject("house")

        val pressurePrincipleLine =
            if (commitDigit != null) {
                "When a digit is trapped in the overlap between a line and a box, that confinement sends consequences outward."
            } else {
                "When a pattern traps the answer in an overlap, that confinement sends consequences outward."
            }

        val memoryRuleLine =
            when {
                sourceHouse != null && primaryHouse != null ->
                    "The lesson here is: first find the trap, then follow its pressure to the real battleground."
                else ->
                    "The lesson here is to follow the pressure a confinement creates, not just the place where the pattern first appears."
            }

        val structuralInsightLine =
            when {
                sourceHouse != null && primaryHouse != null ->
                    "The pattern may be born in ${houseLabelOf(sourceHouse)}, but its decisive effect lands in ${houseLabelOf(primaryHouse)}."
                else ->
                    "The pattern may be born in one place, but its decisive effect can land somewhere else."
            }

        return JSONObject().apply {
            put("pressure_principle_line", pressurePrincipleLine)
            put("memory_rule_line", memoryRuleLine)
            put("structural_insight_line", structuralInsightLine)
        }
    }







    private fun buildConfrontationReplyPacketBundleV1(
        sAfter: SudoState,
        storyContextBundle: FactBundleV1?
    ): FactBundleV1? {
        if (sAfter.mode != SudoMode.GRID_SESSION) return null
        if (sAfter.phase != GridPhase.SOLVING) return null
        if (sAfter.narrativeStory?.stage != StoryStage.CONFRONTATION) return null


        fun proofRowLimit(profile: ConfrontationProofProfileV1): Int =
            when (profile) {
                ConfrontationProofProfileV1.BASE_SINGLES_PROOF -> 5
                ConfrontationProofProfileV1.FULL_HOUSE_PROOF -> 3
                ConfrontationProofProfileV1.SUBSETS_PROOF -> 6
                ConfrontationProofProfileV1.INTERSECTIONS_PROOF -> 6
                ConfrontationProofProfileV1.ADVANCED_PATTERN_PROOF -> 6
                ConfrontationProofProfileV1.FALLBACK_PROOF -> 4
            }

        val story = storyContextBundle?.payload ?: return null
        val proofProfile = resolveConfrontationProofProfileV1(sAfter)
        val confrontationDoctrine = resolveConfrontationNarrationDoctrineV1(sAfter)


        val archetype = readSetupArchetypeWireV1(sAfter)
        val techniqueId = readSetupTechniqueIdV1(sAfter)
        val techniqueName = readSetupTechniqueNameV1(sAfter)
        val techniqueFamily = readSetupTechniqueFamilyV1(sAfter)
        val techniqueRealName = readSetupTechniqueRealNameV1(sAfter)
        val techniqueIsBase = readSetupTechniqueIsBaseV1(sAfter)
        val techniqueDifficultyLevel = readSetupTechniqueDifficultyLevelV1(sAfter)
        val techniqueShortDefinitionSummary = readSetupTechniqueShortDefinitionSummaryV1(sAfter)

        val targetCell =
            story.optJSONObject("confrontation_target_cell")
        val primaryHouse =
            story.optJSONObject("confrontation_primary_house")
        val targetDigit =
            if (!story.isNull("confrontation_target_digit")) story.optInt("confrontation_target_digit", -1).takeIf { it in 1..9 } else null

        val canonicalStageTruth =
            buildCanonicalStageTruthV1(
                sAfter = sAfter,
                fallbackTargetCell = targetCell,
                fallbackPrimaryHouse = primaryHouse,
                fallbackTargetDigit = targetDigit
            )

        val proofArgs =
            canonicalStageTruth.optJSONObject("proof_args") ?: JSONObject()

        val targetResolutionTruth =
            canonicalStageTruth.optJSONObject("target_resolution_truth") ?: JSONObject()

        val canonicalTruthSource =
            canonicalStageTruth.optString("source_of_truth")

        fun cellLabelOf(cell: JSONObject?): String? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            return if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
        }

        fun boxIndex1to9Of(cell: JSONObject?): Int? {
            val r = cell?.optInt("r", -1) ?: -1
            val c = cell?.optInt("c", -1) ?: -1
            if (r !in 1..9 || c !in 1..9) return null
            return ((r - 1) / 3) * 3 + ((c - 1) / 3) + 1
        }

        fun houseScopeFromBlockerRow(row: JSONObject, fallbackTargetCell: JSONObject?): JSONObject? {
            row.optJSONObject("relation_house")?.let { return JSONObject(it.toString()) }
            row.optJSONObject("house")?.let { return JSONObject(it.toString()) }

            return when (row.optString("relation")) {
                "SAME_ROW" -> {
                    val r = fallbackTargetCell?.optInt("r", -1) ?: -1
                    if (r in 1..9) houseRefV1(RegionKindV1.ROW, r) else null
                }
                "SAME_COL" -> {
                    val c = fallbackTargetCell?.optInt("c", -1) ?: -1
                    if (c in 1..9) houseRefV1(RegionKindV1.COL, c) else null
                }
                "SAME_BOX" -> {
                    val box = boxIndex1to9Of(fallbackTargetCell)
                    if (box != null) houseRefV1(RegionKindV1.BOX, box) else null
                }
                else -> null
            }
        }

        fun houseScopeLabel(scope: JSONObject?): String {
            val type = scope?.optString("type").orEmpty()
            val index = scope?.optInt("index1to9", -1) ?: -1
            return when {
                type == "row" && index in 1..9 -> "row $index"
                type == "col" && index in 1..9 -> "column $index"
                type == "box" && index in 1..9 -> "box $index"
                else -> "the house"
            }
        }

        fun digitListLabel(digits: List<Int>): String =
            when (digits.size) {
                0 -> ""
                1 -> digits[0].toString()
                2 -> "${digits[0]} and ${digits[1]}"
                else -> digits.dropLast(1).joinToString(", ") + ", and " + digits.last()
            }

        fun normalizeConfrontationProofRow(
            row: JSONObject,
            fallbackTargetCell: JSONObject?,
            techniqueDisplayName: String?
        ): JSONObject {
            val digit = row.opt("digit") ?: JSONObject.NULL
            val witnessCell = row.optJSONObject("witness_cell")
            val houseScope = houseScopeFromBlockerRow(row, fallbackTargetCell)
            val sourceKind = row.optString("source_kind")
            val targetLabel = cellLabelOf(fallbackTargetCell) ?: "the target"
            val witnessLabel = cellLabelOf(witnessCell)
            val houseLabel = houseScopeLabel(houseScope)

            val because =
                when (sourceKind) {
                    "subset_witness" ->
                        "The ${techniqueDisplayName ?: "technique"} locks these digits into its pattern cells."
                    "peer_witness" ->
                        if (witnessLabel != null) "$witnessLabel already occupies that digit in $houseLabel."
                        else "That digit is already occupied in $houseLabel."
                    else ->
                        if (witnessLabel != null) "$witnessLabel blocks that digit in $houseLabel."
                        else "That digit is blocked in $houseLabel."
                }

            val spokenLine =
                when (sourceKind) {
                    "subset_witness" -> {
                        val subsetCells = row.optJSONArray("subset_cells") ?: JSONArray()
                        val subsetLabels =
                            buildList {
                                for (i in 0 until subsetCells.length()) {
                                    val cell = subsetCells.optJSONObject(i) ?: continue
                                    cellLabelOf(cell)?.let { add(it) }
                                }
                            }
                        val subsetHouse = houseScopeLabel(row.optJSONObject("house"))
                        if (digit != JSONObject.NULL) {
                            "Because the ${techniqueDisplayName ?: "pattern"} locks ${digit} into ${subsetLabels.joinToString(" and ")} in $subsetHouse, $targetLabel cannot keep $digit."
                        } else {
                            "Because the ${techniqueDisplayName ?: "pattern"} locks its digits into its pattern cells, $targetLabel must release that option."
                        }
                    }
                    "peer_witness" -> {
                        if (digit != JSONObject.NULL && witnessLabel != null) {
                            "In $houseLabel, $witnessLabel already takes ${digit}, so $targetLabel cannot be ${digit}."
                        } else if (digit != JSONObject.NULL) {
                            "In $houseLabel, ${digit} is already accounted for, so $targetLabel cannot be ${digit}."
                        } else {
                            "$houseLabel blocks that option from $targetLabel."
                        }
                    }
                    else -> {
                        if (digit != JSONObject.NULL) {
                            "$houseLabel removes ${digit} from $targetLabel."
                        } else {
                            "$houseLabel removes that option from $targetLabel."
                        }
                    }
                }

            return JSONObject().apply {
                put("digit", digit)
                put("cell", witnessCell ?: JSONObject.NULL)
                put("house_scope", houseScope ?: JSONObject.NULL)
                put("because", because)
                put("spoken_line", spokenLine)
                put("source_kind", if (sourceKind.isNotBlank()) sourceKind else JSONObject.NULL)
            }

        }

        val targetTruthSupport =
            targetResolutionTruth.optJSONObject("support")
                ?: JSONObject().also { targetResolutionTruth.put("support", it) }

        fun deriveCellBlockerRowsFromWitnessByDigit(
            witnessByDigit: JSONArray,
            fallbackTargetCell: JSONObject?,
            techniqueDisplayName: String?
        ): JSONArray {
            val out = JSONArray()
            val targetLabel = cellLabelOf(fallbackTargetCell) ?: "the target"

            for (i in 0 until witnessByDigit.length()) {
                val row = witnessByDigit.optJSONObject(i) ?: continue
                val digit = row.opt("digit") ?: JSONObject.NULL
                val witness = row.optJSONObject("witness") ?: JSONObject()

                when (witness.optString("kind")) {
                    "subset_group" -> {
                        val subsetCells = witness.optJSONArray("cells") ?: JSONArray()
                        val subsetHouse = witness.optJSONObject("house")
                        val subsetHouseLabel = houseScopeLabel(subsetHouse)

                        val subsetLabels =
                            buildList {
                                for (j in 0 until subsetCells.length()) {
                                    val cell = subsetCells.optJSONObject(j) ?: continue
                                    cellLabelOf(cell)?.let { add(it) }
                                }
                            }

                        val because =
                            if (digit != JSONObject.NULL) {
                                "The ${techniqueDisplayName ?: "technique"} locks $digit into ${subsetLabels.joinToString(" and ")} in $subsetHouseLabel."
                            } else {
                                "The ${techniqueDisplayName ?: "technique"} locks its digits into its pattern cells."
                            }

                        val spokenLine =
                            if (digit != JSONObject.NULL) {
                                "Because the ${techniqueDisplayName ?: "pattern"} locks $digit into ${subsetLabels.joinToString(" and ")} in $subsetHouseLabel, $targetLabel cannot keep $digit."
                            } else {
                                "Because the ${techniqueDisplayName ?: "pattern"} locks its digits into its pattern cells, $targetLabel must release that option."
                            }

                        out.put(
                            JSONObject().apply {
                                put("digit", digit)
                                put("cell", JSONObject.NULL)
                                put("house_scope", subsetHouse ?: JSONObject.NULL)
                                put("because", because)
                                put("spoken_line", spokenLine)
                                put("source_kind", "subset_witness")
                                put("subset_cells", JSONArray(subsetCells.toString()))
                                put("house", subsetHouse ?: JSONObject.NULL)
                            }
                        )
                    }

                    "single_cell" -> {
                        val witnessCell = witness.optJSONObject("cell")
                        val relation = witness.optString("relation")

                        val houseScope =
                            when (relation) {
                                "SAME_ROW" -> {
                                    val r = fallbackTargetCell?.optInt("r", -1) ?: -1
                                    if (r in 1..9) houseRefV1(RegionKindV1.ROW, r) else null
                                }
                                "SAME_COL" -> {
                                    val c = fallbackTargetCell?.optInt("c", -1) ?: -1
                                    if (c in 1..9) houseRefV1(RegionKindV1.COL, c) else null
                                }
                                "SAME_BOX" -> {
                                    val box = boxIndex1to9Of(fallbackTargetCell)
                                    if (box != null) houseRefV1(RegionKindV1.BOX, box) else null
                                }
                                else -> null
                            }

                        val witnessLabel = cellLabelOf(witnessCell) ?: "that witness cell"
                        val houseLabel = houseScopeLabel(houseScope)

                        val because =
                            if (digit != JSONObject.NULL) {
                                "$witnessLabel already occupies $digit in $houseLabel."
                            } else {
                                "$witnessLabel already blocks that option in $houseLabel."
                            }

                        val spokenLine =
                            if (digit != JSONObject.NULL) {
                                "In $houseLabel, $witnessLabel already takes $digit, so $targetLabel cannot be $digit."
                            } else {
                                "In $houseLabel, $witnessLabel blocks that option from $targetLabel."
                            }

                        out.put(
                            JSONObject().apply {
                                put("digit", digit)
                                put("cell", witnessCell ?: JSONObject.NULL)
                                put("house_scope", houseScope ?: JSONObject.NULL)
                                put("because", because)
                                put("spoken_line", spokenLine)
                                put("source_kind", "peer_witness")
                                put("relation", if (relation.isNotBlank()) relation else JSONObject.NULL)
                            }
                        )
                    }
                }
            }

            return out
        }


        val rawHouseBattlefieldProof =
            targetTruthSupport.optJSONObject("house_battlefield_proof")
                ?: canonicalStageTruth.optJSONObject("proof_payload")
                    ?.optJSONObject("intersection_control")
                    ?.optJSONObject("house_battlefield_proof")
                ?: JSONObject()

        val rawBlockerRows =
            rawHouseBattlefieldProof.optJSONArray("blocker_rows")
                ?: targetTruthSupport.optJSONArray("blocker_rows")
                ?: JSONArray()

        val rawPeerBlockerRows =
            rawHouseBattlefieldProof.optJSONArray("ordinary_blocker_rows")
                ?: targetTruthSupport.optJSONArray("peer_blocker_rows")
                ?: JSONArray()

        val rawPeerWitnessRows = targetTruthSupport.optJSONArray("peer_witness_rows") ?: JSONArray()
        val rawPeerWitnessPairs = targetTruthSupport.optJSONArray("peer_witness_pairs") ?: JSONArray()
        val rawWitnessByDigit = targetTruthSupport.optJSONArray("witness_by_digit") ?: JSONArray()
        val rawTechniqueBlockerRows =
            rawHouseBattlefieldProof.optJSONArray("technique_finishing_rows")
                ?: targetTruthSupport.optJSONArray("technique_blocker_rows")
                ?: JSONArray()

        val techniqueDisplayName =
            techniqueRealName
                ?: techniqueName
                ?: techniqueId

        val eliminationKind = targetResolutionTruth.optString("elimination_kind")
        val houseClaim = targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()

        val normalizedTechniqueBlockerRows = JSONArray()
        val normalizedPeerBlockerRows = JSONArray()

        if (eliminationKind == "CELL_CANDIDATE_DIGITS") {
            val effectiveCellRows =
                if (rawBlockerRows.length() > 0) {
                    rawBlockerRows
                } else {
                    deriveCellBlockerRowsFromWitnessByDigit(
                        witnessByDigit = rawWitnessByDigit,
                        fallbackTargetCell = targetCell,
                        techniqueDisplayName = techniqueDisplayName
                    )
                }

            for (i in 0 until effectiveCellRows.length()) {
                val row = effectiveCellRows.optJSONObject(i) ?: continue

                val normalized =
                    if (row.has("spoken_line") && row.has("because") && row.has("house_scope")) {
                        JSONObject(row.toString())
                    } else {
                        normalizeConfrontationProofRow(
                            row = row,
                            fallbackTargetCell = targetCell,
                            techniqueDisplayName = techniqueDisplayName
                        )
                    }

                when (row.optString("source_kind")) {
                    "subset_witness" -> normalizedTechniqueBlockerRows.put(normalized)
                    "peer_witness" -> normalizedPeerBlockerRows.put(normalized)
                    else -> normalizedPeerBlockerRows.put(normalized)
                }
            }

            if (normalizedPeerBlockerRows.length() == 0) {
                for (i in 0 until rawPeerWitnessRows.length()) {
                    val row = rawPeerWitnessRows.optJSONObject(i) ?: continue
                    val normalized =
                        normalizeConfrontationProofRow(
                            row = row,
                            fallbackTargetCell = targetCell,
                            techniqueDisplayName = techniqueDisplayName
                        )
                    normalizedPeerBlockerRows.put(normalized)
                }
            }

            if (normalizedTechniqueBlockerRows.length() == 0) {
                for (i in 0 until rawTechniqueBlockerRows.length()) {
                    val row = rawTechniqueBlockerRows.optJSONObject(i) ?: continue
                    val normalized =
                        if (row.has("spoken_line") && row.has("because") && row.has("house_scope")) {
                            JSONObject(row.toString())
                        } else {
                            normalizeConfrontationProofRow(
                                row = row,
                                fallbackTargetCell = targetCell,
                                techniqueDisplayName = techniqueDisplayName
                            )
                        }
                    normalizedTechniqueBlockerRows.put(normalized)
                }
            }
        } else {
            if (rawPeerBlockerRows.length() > 0) {
                for (i in 0 until rawPeerBlockerRows.length()) {
                    val row = rawPeerBlockerRows.optJSONObject(i) ?: continue
                    val normalized =
                        if (row.has("spoken_line") && row.has("because") && row.has("house_scope")) {
                            JSONObject(row.toString())
                        } else {
                            normalizeConfrontationProofRow(
                                row = row,
                                fallbackTargetCell = targetCell,
                                techniqueDisplayName = techniqueDisplayName
                            )
                        }
                    normalizedPeerBlockerRows.put(normalized)
                }
            } else {
                for (i in 0 until rawPeerWitnessPairs.length()) {
                    val pair = rawPeerWitnessPairs.optJSONObject(i) ?: continue
                    val claimedCell = pair.optJSONObject("peer_cell")
                    val witnessCell = pair.optJSONObject("witness_cell")
                    val relation = pair.optString("relation")
                    val digit = pair.opt("digit") ?: targetResolutionTruth.opt("digit") ?: JSONObject.NULL

                    val houseScope =
                        when (relation) {
                            "SAME_ROW" -> {
                                val r = claimedCell?.optInt("r", -1) ?: -1
                                if (r in 1..9) houseRefV1(RegionKindV1.ROW, r) else null
                            }
                            "SAME_COL" -> {
                                val c = claimedCell?.optInt("c", -1) ?: -1
                                if (c in 1..9) houseRefV1(RegionKindV1.COL, c) else null
                            }
                            "SAME_BOX" -> {
                                val box = boxIndex1to9Of(claimedCell)
                                if (box != null) houseRefV1(RegionKindV1.BOX, box) else null
                            }
                            else -> null
                        }

                    val claimedLabel = cellLabelOf(claimedCell) ?: "that rival cell"
                    val witnessLabel = cellLabelOf(witnessCell) ?: "another cell"
                    val houseLabel = houseScopeLabel(houseScope)

                    val because =
                        if (digit != JSONObject.NULL) {
                            "$claimedLabel is blocked for $digit because $witnessLabel already places $digit in $houseLabel."
                        } else {
                            "$claimedLabel is blocked by $witnessLabel in $houseLabel."
                        }

                    val spokenLine =
                        if (digit != JSONObject.NULL) {
                            "$claimedLabel cannot take $digit because $witnessLabel already places $digit in $houseLabel."
                        } else {
                            "$claimedLabel gets ruled out because of $witnessLabel in $houseLabel."
                        }

                    normalizedPeerBlockerRows.put(
                        JSONObject().apply {
                            put("digit", digit)
                            put("cell", witnessCell ?: JSONObject.NULL)
                            put("claimed_cell", claimedCell ?: JSONObject.NULL)
                            put("house_scope", houseScope ?: JSONObject.NULL)
                            put("because", because)
                            put("spoken_line", spokenLine)
                            put("source_kind", "peer_witness")
                        }
                    )
                }
            }

            if (normalizedPeerBlockerRows.length() == 0) {
                for (i in 0 until rawPeerWitnessRows.length()) {
                    val row = rawPeerWitnessRows.optJSONObject(i) ?: continue
                    val normalized =
                        normalizeConfrontationProofRow(
                            row = row,
                            fallbackTargetCell = targetCell,
                            techniqueDisplayName = techniqueDisplayName
                        )
                    normalizedPeerBlockerRows.put(normalized)
                }
            }

            if (normalizedTechniqueBlockerRows.length() == 0) {
                for (i in 0 until rawTechniqueBlockerRows.length()) {
                    val row = rawTechniqueBlockerRows.optJSONObject(i) ?: continue
                    val normalized =
                        if (row.has("spoken_line") && row.has("because") && row.has("house_scope")) {
                            JSONObject(row.toString())
                        } else {
                            normalizeConfrontationProofRow(
                                row = row,
                                fallbackTargetCell = targetCell,
                                techniqueDisplayName = techniqueDisplayName
                            )
                        }
                    normalizedTechniqueBlockerRows.put(normalized)
                }
            }
        }

        targetTruthSupport.put("technique_blocker_rows", normalizedTechniqueBlockerRows)
        targetTruthSupport.put("peer_blocker_rows", normalizedPeerBlockerRows)


        val orderedProofLadderFromBattlefield =
            rawHouseBattlefieldProof.optJSONArray("ordered_proof_ladder")
                ?.takeIf { it.length() > 0 }
                ?.let { JSONArray(it.toString()) }

        val orderedProofLadder =
            orderedProofLadderFromBattlefield ?: JSONArray().apply {
                if (eliminationKind == "CELL_CANDIDATE_DIGITS") {
                    val targetLabel = cellLabelOf(targetCell) ?: "the target"
                    val patternFirst =
                        confrontationDoctrine == ConfrontationNarrationDoctrineV1.PATTERN_FIRST

                    if (patternFirst && normalizedPeerBlockerRows.length() > 0) {
                        val groupedPeerDigits = JSONArray()
                        val groupedPeerSupport = JSONArray()

                        for (i in 0 until normalizedPeerBlockerRows.length()) {
                            val row = normalizedPeerBlockerRows.optJSONObject(i) ?: continue
                            val digit = row.opt("digit")
                            if (digit is Int) groupedPeerDigits.put(digit)
                            groupedPeerSupport.put(JSONObject(row.toString()))
                        }

                        put(
                            JSONObject().apply {
                                put("step_kind", "ordinary_witness_ensemble")
                                put(
                                    "summary",
                                    "Before the ${techniqueDisplayName ?: "technique"} acts, the ordinary witnesses already thin the crowd around $targetLabel."
                                )
                                put("house_scope", JSONObject.NULL)
                                put("eliminated_digits", groupedPeerDigits)
                                put("supporting_rows", groupedPeerSupport)
                            }
                        )
                    } else {
                        for (i in 0 until normalizedPeerBlockerRows.length()) {
                            val row = normalizedPeerBlockerRows.optJSONObject(i) ?: continue
                            val digit = row.opt("digit")
                            val eliminatedDigits =
                                JSONArray().apply {
                                    if (digit is Int) put(digit)
                                }

                            put(
                                JSONObject().apply {
                                    put("step_kind", "peer_cleanup")
                                    put(
                                        "summary",
                                        row.optString("spoken_line").takeIf { it.isNotBlank() }
                                            ?: row.optString("because").takeIf { it.isNotBlank() }
                                            ?: "A remaining witness removes another option from $targetLabel."
                                    )
                                    put("house_scope", row.opt("house_scope") ?: JSONObject.NULL)
                                    put("eliminated_digits", eliminatedDigits)
                                    put(
                                        "supporting_rows",
                                        JSONArray().apply {
                                            put(JSONObject(row.toString()))
                                        }
                                    )
                                }
                            )
                        }
                    }

                    if (patternFirst && normalizedTechniqueBlockerRows.length() > 0) {
                        val groupedTechniqueDigits = JSONArray()
                        val groupedTechniqueSupport = JSONArray()

                        for (i in 0 until normalizedTechniqueBlockerRows.length()) {
                            val row = normalizedTechniqueBlockerRows.optJSONObject(i) ?: continue
                            val digit = row.opt("digit")
                            if (digit is Int) groupedTechniqueDigits.put(digit)
                            groupedTechniqueSupport.put(JSONObject(row.toString()))
                        }

                        put(
                            JSONObject().apply {
                                put("step_kind", "technique_finishing_cut")
                                put(
                                    "summary",
                                    "Now the ${techniqueDisplayName ?: "technique"} closes the last important exits around $targetLabel."
                                )
                                put("house_scope", JSONObject.NULL)
                                put("eliminated_digits", groupedTechniqueDigits)
                                put("supporting_rows", groupedTechniqueSupport)
                            }
                        )
                    } else {
                        for (i in 0 until normalizedTechniqueBlockerRows.length()) {
                            val row = normalizedTechniqueBlockerRows.optJSONObject(i) ?: continue
                            val digit = row.opt("digit")
                            val eliminatedDigits =
                                JSONArray().apply {
                                    if (digit is Int) put(digit)
                                }

                            put(
                                JSONObject().apply {
                                    put("step_kind", "technique_effect")
                                    put(
                                        "summary",
                                        row.optString("spoken_line").takeIf { it.isNotBlank() }
                                            ?: row.optString("because").takeIf { it.isNotBlank() }
                                            ?: "The ${techniqueDisplayName ?: "technique"} removes one option from $targetLabel."
                                    )
                                    put("house_scope", row.opt("house_scope") ?: JSONObject.NULL)
                                    put("eliminated_digits", eliminatedDigits)
                                    put(
                                        "supporting_rows",
                                        JSONArray().apply {
                                            put(JSONObject(row.toString()))
                                        }
                                    )
                                }
                            )
                        }
                    }

                    val remainingDigits =
                        targetResolutionTruth
                            .optJSONObject("cell_outcome")
                            ?.optJSONArray("remaining_candidate_digits")
                            ?: JSONArray()

                    val survivingDigit =
                        if (remainingDigits.length() == 1) remainingDigits.opt(0) else targetDigit ?: JSONObject.NULL

                    put(
                        JSONObject().apply {
                            put("step_kind", "target_collapse")
                            put(
                                "summary",
                                if (survivingDigit != JSONObject.NULL) {
                                    "When the dust settles around $targetLabel, only $survivingDigit is still standing."
                                } else {
                                    "When the dust settles, only one option remains in $targetLabel."
                                }
                            )
                            put("surviving_digit", survivingDigit)
                            put(
                                "supporting_rows",
                                JSONArray().apply {
                                    for (i in 0 until normalizedPeerBlockerRows.length()) {
                                        put(JSONObject((normalizedPeerBlockerRows.optJSONObject(i) ?: JSONObject()).toString()))
                                    }
                                    for (i in 0 until normalizedTechniqueBlockerRows.length()) {
                                        put(JSONObject((normalizedTechniqueBlockerRows.optJSONObject(i) ?: JSONObject()).toString()))
                                    }
                                }
                            )
                        }
                    )
                } else {
                    val digit = houseClaim.opt("digit")
                    val house = houseClaim.optJSONObject("house")

                    if (confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST) {
                        put(
                            JSONObject().apply {
                                put("step_kind", "lens_question_reanchor")
                                put(
                                    "summary",
                                    if (digit != null && digit != JSONObject.NULL && house != null) {
                                        "Keep asking the hidden-single question inside ${houseScopeLabel(house)}: where can $digit still live?"
                                    } else if (house != null) {
                                        "Keep the live search inside ${houseScopeLabel(house)} and let the rival seats fall away."
                                    } else {
                                        "Keep the live house/digit search active and let the rival seats fall away."
                                    }
                                )
                                put("house_scope", house ?: JSONObject.NULL)
                                put("surviving_digit", digit ?: JSONObject.NULL)
                                put("supporting_rows", JSONArray())
                            }
                        )
                    }

                    for (i in 0 until normalizedPeerBlockerRows.length()) {
                        val row = normalizedPeerBlockerRows.optJSONObject(i) ?: continue
                        val claimedCell = row.optJSONObject("claimed_cell")

                        put(
                            JSONObject().apply {
                                put(
                                    "step_kind",
                                    if (confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST) {
                                        "rival_seat_falls"
                                    } else {
                                        "peer_cleanup"
                                    }
                                )
                                put(
                                    "summary",
                                    row.optString("spoken_line").takeIf { it.isNotBlank() }
                                        ?: row.optString("because").takeIf { it.isNotBlank() }
                                        ?: "One rival seat loses the right to hold the digit."
                                )
                                put("house_scope", row.opt("house_scope") ?: JSONObject.NULL)
                                put("eliminated_digits", JSONArray())
                                put(
                                    "claimed_cells",
                                    JSONArray().apply {
                                        put(claimedCell ?: JSONObject.NULL)
                                    }
                                )
                                put(
                                    "supporting_rows",
                                    JSONArray().apply {
                                        put(JSONObject(row.toString()))
                                    }
                                )
                            }
                        )
                    }

                    val remainingCells = houseClaim.optJSONArray("remaining_candidate_cells") ?: JSONArray()
                    val survivingCell = if (remainingCells.length() == 1) remainingCells.optJSONObject(0) else null
                    val survivingLabel = cellLabelOf(survivingCell) ?: "the remaining cell"

                    put(
                        JSONObject().apply {
                            put("step_kind", "target_collapse")
                            put(
                                "summary",
                                if (digit != null && digit != JSONObject.NULL && house != null) {
                                    "After the rival seats disappear in ${houseScopeLabel(house)}, only $survivingLabel is left for $digit."
                                } else if (digit != null && digit != JSONObject.NULL) {
                                    "After the rival seats disappear, only one location is left for $digit."
                                } else {
                                    "After ruling out the rival cells, only one location remains in the house."
                                }
                            )
                            put("surviving_digit", digit ?: JSONObject.NULL)
                            put("surviving_cell", survivingCell ?: JSONObject.NULL)
                            put("house_scope", house ?: JSONObject.NULL)
                        }
                    )
                }
            }



        targetTruthSupport.put("ordered_proof_ladder", orderedProofLadder)

        val boundedTargetProofRows =
            JSONArray().apply {
                val orderedRows = JSONArray().apply {
                    if (confrontationDoctrine == ConfrontationNarrationDoctrineV1.PATTERN_FIRST) {
                        for (i in 0 until normalizedPeerBlockerRows.length()) {
                            put(JSONObject((normalizedPeerBlockerRows.optJSONObject(i) ?: JSONObject()).toString()))
                        }
                        for (i in 0 until normalizedTechniqueBlockerRows.length()) {
                            put(JSONObject((normalizedTechniqueBlockerRows.optJSONObject(i) ?: JSONObject()).toString()))
                        }
                    } else {
                        for (i in 0 until normalizedTechniqueBlockerRows.length()) {
                            put(JSONObject((normalizedTechniqueBlockerRows.optJSONObject(i) ?: JSONObject()).toString()))
                        }
                        for (i in 0 until normalizedPeerBlockerRows.length()) {
                            put(JSONObject((normalizedPeerBlockerRows.optJSONObject(i) ?: JSONObject()).toString()))
                        }
                    }
                }

                for (i in 0 until orderedRows.length()) {
                    if (length() >= proofRowLimit(proofProfile)) break
                    val row = orderedRows.optJSONObject(i) ?: continue
                    put(JSONObject(row.toString()))
                }
            }

        val liveFocusCell =
            targetResolutionTruth.optJSONObject("focus_cell")
                ?: targetCell

        val livePrimaryHouse =
            targetResolutionTruth.optJSONObject("primary_house")
                ?: houseClaim.optJSONObject("house")
                ?: primaryHouse

        val liveDigitFromTruth =
            if (!targetResolutionTruth.isNull("digit")) {
                targetResolutionTruth.opt("digit")
            } else {
                houseClaim.opt("digit")
            }

        val canSayTargetDigit = story.optBoolean("confrontation_can_say_target_digit", false)
        val targetDigitValue =
            when {
                !canSayTargetDigit -> JSONObject.NULL
                liveDigitFromTruth != null && liveDigitFromTruth != JSONObject.NULL -> liveDigitFromTruth
                targetDigit != null -> targetDigit
                else -> JSONObject.NULL
            }

        val isFullHouse =
            archetype?.trim()?.uppercase() == "FULL_HOUSE" ||
                    techniqueId?.trim()?.lowercase() == "singles-1" ||
                    techniqueRealName?.contains("Full House", ignoreCase = true) == true

        val triggerReferenceSummary =
            story.optString("confrontation_trigger_reference_summary")
                .takeIf { it.isNotBlank() }
                ?: run {
                    if (proofProfile == ConfrontationProofProfileV1.INTERSECTIONS_PROOF &&
                        eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT"
                    ) {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        if (digit != null && digit != JSONObject.NULL && house != null) {
                            "Now let’s move to the battlefield: ${houseScopeLabel(house)}. We are looking for one thing only: where can $digit still sit there?"
                        } else {
                            "Now let’s move to the battlefield and see which seat is still legally available."
                        }
                    } else if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        if (isFullHouse) {
                            if (digit != null && digit != JSONObject.NULL) {
                                "Now Full House steps in directly: in ${houseScopeLabel(house)}, we are checking which final seat is still open for $digit."
                            } else {
                                "Now Full House steps in directly: we are checking which final seat in the active house is still open."
                            }
                        } else if (digit != null && digit != JSONObject.NULL) {
                            "Let’s use the live picture in ${houseScopeLabel(house)} and track which rival cells can still pretend to hold $digit."
                        } else {
                            "Let’s use the live picture in the active house and track which rival cells are still competing."
                        }
                    } else {
                        null
                    }
                }

        val triggerEffectSummary =
            story.optString("confrontation_trigger_effect_summary")
                .takeIf { it.isNotBlank() }
                ?: run {
                    if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                        val house = houseClaim.optJSONObject("house")
                        val digit = houseClaim.opt("digit")
                        if (isFullHouse) {
                            if (digit != null && digit != JSONObject.NULL) {
                                "Because ${houseScopeLabel(house)} has reached its final opening, Full House quietly claims that last seat for $digit."
                            } else {
                                "Because the house has reached its final opening, Full House quietly claims that last seat."
                            }
                        } else if (digit != null && digit != JSONObject.NULL) {
                            "Each witness removes one more rival location for $digit until only the target cell remains."
                        } else {
                            "Each witness removes one more rival location until only the target cell remains."
                        }
                    } else {
                        null
                    }
                }

        val collapseSummary =
            story.optString("confrontation_collapse_summary")
                .takeIf { it.isNotBlank() }
                ?: if (isFullHouse && eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                    val house = houseClaim.optJSONObject("house")
                    val digit = houseClaim.opt("digit")
                    val focusLabel = cellLabelOf(targetCell) ?: "the target"
                    if (digit != null && digit != JSONObject.NULL) {
                        "At this point the house is effectively complete: in ${houseScopeLabel(house)}, only $focusLabel is still available for $digit."
                    } else {
                        "At this point the house is effectively complete: only the target cell is still available."
                    }
                } else {
                    defaultConfrontationCollapseSummaryFromTruthV1(
                        targetResolutionTruth = targetResolutionTruth,
                        fallbackSurvivingDigit = targetDigit
                    )
                }

        val packet = ConfrontationReplyPacketV1(
            proofProfile = proofProfile,
            confrontationDoctrine = confrontationDoctrine,
            archetype = archetype,
            technique = JSONObject().apply {
                put("id", techniqueId ?: JSONObject.NULL)
                put("name", techniqueName ?: JSONObject.NULL)
                put("real_name", techniqueRealName ?: JSONObject.NULL)
                put("family", techniqueFamily ?: JSONObject.NULL)
                put("archetype", archetype ?: JSONObject.NULL)
                put("is_base", techniqueIsBase ?: JSONObject.NULL)
                put("difficulty_level", techniqueDifficultyLevel ?: JSONObject.NULL)
                put("short_definition_summary", techniqueShortDefinitionSummary ?: JSONObject.NULL)
            },
            target = JSONObject().apply {
                put("cell", liveFocusCell ?: JSONObject.NULL)
                put("primary_house", livePrimaryHouse ?: JSONObject.NULL)
                put("target_digit", targetDigitValue)
                put("can_say_target_digit", canSayTargetDigit)
                put("spoiler_level", story.opt("confrontation_spoiler_level") ?: JSONObject.NULL)
            },
            triggerReference = JSONObject().apply {
                put(
                    "summary",
                    triggerReferenceSummary ?: JSONObject.NULL
                )
                put("trigger_kind", story.opt("confrontation_trigger_kind") ?: JSONObject.NULL)
                put("pattern", story.optJSONObject("confrontation_trigger_pattern") ?: JSONObject.NULL)
                put("reference_only", story.optBoolean("confrontation_trigger_reference_only", true))
                put("pattern_reteach_forbidden", story.optBoolean("confrontation_pattern_reteach_forbidden", true))
            },
            triggerEffect = JSONObject().apply {
                put(
                    "summary",
                    triggerEffectSummary ?: JSONObject.NULL
                )
                put("payload", story.optJSONObject("confrontation_summary_payload") ?: JSONObject.NULL)
            },
            targetResolutionTruth = targetResolutionTruth,
            targetProofRows = boundedTargetProofRows,
            collapse = JSONObject().apply {
                val remainingCandidateDigits =
                    targetResolutionTruth.optJSONObject("cell_outcome")?.optJSONArray("remaining_candidate_digits")
                        ?: JSONArray()

                val survivingDigit =
                    if (remainingCandidateDigits.length() == 1) {
                        remainingCandidateDigits.opt(0)
                    } else {
                        targetDigit ?: JSONObject.NULL
                    }

                put("summary", collapseSummary)
                put(
                    "remaining_candidate_digits",
                    if (remainingCandidateDigits.length() > 0) remainingCandidateDigits else JSONObject.NULL
                )
                put("surviving_digit", survivingDigit)
                put("can_say_target_digit", canSayTargetDigit)
                put(
                    "is_single_after_cleanup",
                    targetResolutionTruth.optString("elimination_kind") == "CELL_CANDIDATE_DIGITS" &&
                            remainingCandidateDigits.length() == 1
                )
                put(
                    "two_layer_honesty_line",
                    story.optString("confrontation_two_layer_honesty_line").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
            },
            preCommitLine = JSONObject().apply {
                put(
                    "summary",
                    story.optString("confrontation_pre_commit_line").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
                put(
                    "claim_code",
                    story.optString("confrontation_claim_code").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
                put("spoiler_level", story.opt("confrontation_spoiler_level") ?: JSONObject.NULL)
            },
            cta = JSONObject().apply {
                put(
                    "kind",
                    story.optString("confrontation_cta_kind").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
            },
            support = JSONObject().apply {
                val targetLabel = cellLabelOf(targetCell) ?: "the target"
                val targetDigitForSpeech =
                    targetResolutionTruth
                        .optJSONObject("cell_outcome")
                        ?.optJSONArray("remaining_candidate_digits")
                        ?.takeIf { it.length() == 1 }
                        ?.opt(0)
                        ?: targetDigit
                        ?: JSONObject.NULL

                put("confrontation_doctrine", confrontationDoctrine.name)
                put("doctrine_is_lens_first", confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST)
                put("doctrine_is_pattern_first", confrontationDoctrine == ConfrontationNarrationDoctrineV1.PATTERN_FIRST)

                put(
                    "actor_structure",
                    if (confrontationDoctrine == ConfrontationNarrationDoctrineV1.PATTERN_FIRST &&
                        normalizedPeerBlockerRows.length() > 0 &&
                        normalizedTechniqueBlockerRows.length() > 0
                    ) {
                        "DUET"
                    } else {
                        "SOLO"
                    }
                )
                put(
                    "ordinary_witness_first_required",
                    confrontationDoctrine == ConfrontationNarrationDoctrineV1.PATTERN_FIRST &&
                            normalizedPeerBlockerRows.length() > 0
                )
                put(
                    "technique_finishing_cut_required",
                    confrontationDoctrine == ConfrontationNarrationDoctrineV1.PATTERN_FIRST &&
                            normalizedTechniqueBlockerRows.length() > 0
                )


                val lensHouse =
                    rawHouseBattlefieldProof.optJSONObject("battlefield_house")
                        ?: targetResolutionTruth.optJSONObject("battlefield_house")
                        ?: targetResolutionTruth.optJSONObject("house_claim")?.optJSONObject("house")
                        ?: primaryHouse

                val lensDigit =
                    rawHouseBattlefieldProof.opt("battlefield_digit")
                        .takeIf { it != null && it != JSONObject.NULL }
                        ?: (if (targetDigitValue != JSONObject.NULL) targetDigitValue else null)
                        ?: targetResolutionTruth
                            .optJSONObject("house_claim")
                            ?.opt("digit")
                        ?: targetDigit
                        ?: JSONObject.NULL

                put(
                    "target_spotlight_line",
                    rawHouseBattlefieldProof.optString("battlefield_intro_line").takeIf { it.isNotBlank() }
                        ?: if (confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST) {
                            if (isFullHouse && lensDigit != JSONObject.NULL && lensHouse != null) {
                                "Keep the live spotlight on ${houseScopeLabel(lensHouse)} as Full House walks toward the last open seat for $lensDigit."
                            } else if (lensDigit != JSONObject.NULL && lensHouse != null) {
                                "Keep the live spotlight on ${houseScopeLabel(lensHouse)} and on where digit $lensDigit can still live there."
                            } else if (lensHouse != null) {
                                "Keep the live spotlight on ${houseScopeLabel(lensHouse)} and the target search it contains."
                            } else {
                                "Keep the live spotlight on the active house/digit search."
                            }
                        } else if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" && lensDigit != JSONObject.NULL && lensHouse != null) {
                            "Now let’s move to the battlefield: ${houseScopeLabel(lensHouse)}. We are looking for one thing only: where can $lensDigit still sit there?"
                        } else if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" && lensHouse != null) {
                            "Now let’s move to the battlefield: ${houseScopeLabel(lensHouse)}. We are looking for the one seat that is still legally available."
                        } else {
                            "Our spotlight is on $targetLabel."
                        }
                )
                put(
                    "survivor_reveal_line",
                    rawHouseBattlefieldProof.optString("survivor_reveal_line").takeIf { it.isNotBlank() }
                        ?: if (isFullHouse && confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST && lensDigit != JSONObject.NULL && lensHouse != null) {
                            "Full House now arrives at the finish: in ${houseScopeLabel(lensHouse)}, the last open seat belongs to $lensDigit."
                        } else if (confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST && lensDigit != JSONObject.NULL && lensHouse != null) {
                            "After the rival seats fall away in ${houseScopeLabel(lensHouse)}, only one legal home is still left for $lensDigit."
                        } else if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" && lensDigit != JSONObject.NULL && lensHouse != null) {
                            "And now the standoff is over: in ${houseScopeLabel(lensHouse)}, only one seat is left standing for $lensDigit."
                        } else if (targetDigitForSpeech != JSONObject.NULL) {
                            "When the dust settles, only $targetDigitForSpeech is still standing in $targetLabel."
                        } else {
                            "When the dust settles, only one option is still standing in $targetLabel."
                        }
                )

                put(
                    "lens_house_label",
                    lensHouse?.let { houseScopeLabel(it) } ?: JSONObject.NULL
                )
                put(
                    "birthplace_house",
                    rawHouseBattlefieldProof.opt("birthplace_house")
                        ?: canonicalStageTruth.optJSONObject("proof_payload")
                            ?.optJSONObject("intersection_control")
                            ?.opt("birthplace_house")
                        ?: JSONObject.NULL
                )
                put(
                    "battlefield_house",
                    rawHouseBattlefieldProof.opt("battlefield_house")
                        ?: lensHouse
                        ?: JSONObject.NULL
                )
                put(
                    "birthplace_overlap_cells",
                    rawHouseBattlefieldProof.opt("birthplace_overlap_cells")
                        ?: canonicalStageTruth.optJSONObject("proof_payload")
                            ?.optJSONObject("intersection_control")
                            ?.opt("birthplace_overlap_cells")
                        ?: JSONObject.NULL
                )
                put("lens_digit", lensDigit)

                put(
                    "rival_seat_walk_required",
                    confrontationDoctrine == ConfrontationNarrationDoctrineV1.LENS_FIRST && !isFullHouse
                )

                put("target_proof_row_count", boundedTargetProofRows.length())

                put("has_target_proof_rows", boundedTargetProofRows.length() > 0)
                put("technique_blocker_row_count", normalizedTechniqueBlockerRows.length())
                put("peer_blocker_row_count", normalizedPeerBlockerRows.length())
                put("ordered_proof_ladder_step_count", orderedProofLadder.length())
                put("has_technique_blocker_rows", normalizedTechniqueBlockerRows.length() > 0)
                put("has_peer_blocker_rows", normalizedPeerBlockerRows.length() > 0)
                put("has_ordered_proof_ladder", orderedProofLadder.length() > 0)
                put("has_trigger_reference_summary", triggerReferenceSummary != null)
                put("has_trigger_effect_summary", triggerEffectSummary != null)
                put("has_collapse_summary", collapseSummary.isNotBlank())
                put("has_two_layer_honesty_line", story.optString("confrontation_two_layer_honesty_line").isNotBlank())
                put("has_pre_commit_line", story.optString("confrontation_pre_commit_line").isNotBlank())
                put("has_cta_kind", story.optString("confrontation_cta_kind").isNotBlank())
                put("has_target_resolution_truth", targetResolutionTruth.length() > 0)
                put(
                    "target_resolution_kind",
                    targetResolutionTruth.optString("elimination_kind").ifBlank { JSONObject.NULL as String? }
                )
                put(
                    "overlay_variant",
                    story.optString("confrontation_overlay_variant").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
                put("canonical_truth_source", canonicalTruthSource)
            }
        )

        return factConfrontationReplyPacketV1(packet)
    }





    private fun buildResolutionReplyPacketBundleV1(
        sAfter: SudoState,
        storyContextBundle: FactBundleV1?
    ): FactBundleV1? {
        if (sAfter.mode != SudoMode.GRID_SESSION) return null
        if (sAfter.phase != GridPhase.SOLVING) return null
        if (sAfter.narrativeStory?.stage != StoryStage.RESOLUTION) return null

        fun recapMaxBeats(profile: ResolutionProfileV1): Int =
            when (profile) {
                ResolutionProfileV1.BASE_SINGLES_RESOLUTION -> 1
                ResolutionProfileV1.FULL_HOUSE_RESOLUTION -> 1
                ResolutionProfileV1.SUBSETS_RESOLUTION -> 2
                ResolutionProfileV1.INTERSECTIONS_RESOLUTION -> 2
                ResolutionProfileV1.ADVANCED_PATTERN_RESOLUTION -> 2
                ResolutionProfileV1.FALLBACK_RESOLUTION -> 1
            }

        fun compactMode(profile: ResolutionProfileV1): String =
            when (profile) {
                ResolutionProfileV1.BASE_SINGLES_RESOLUTION -> "direct_finish_v1"
                ResolutionProfileV1.FULL_HOUSE_RESOLUTION -> "full_house_finish_v1"
                ResolutionProfileV1.SUBSETS_RESOLUTION -> "technique_plus_full_basis_v1"
                ResolutionProfileV1.INTERSECTIONS_RESOLUTION -> "technique_plus_full_basis_v1"
                ResolutionProfileV1.ADVANCED_PATTERN_RESOLUTION -> "pattern_plus_full_basis_v1"
                ResolutionProfileV1.FALLBACK_RESOLUTION -> "compact_recap_v1"
            }

        val story = storyContextBundle?.payload ?: return null
        val resolutionProfile = resolveResolutionProfileV1(sAfter)
        val archetype = readSetupArchetypeWireV1(sAfter)
        val techniqueId = readSetupTechniqueIdV1(sAfter)
        val techniqueName = readSetupTechniqueNameV1(sAfter)
        val techniqueFamily = readSetupTechniqueFamilyV1(sAfter)
        val techniqueRealName = readSetupTechniqueRealNameV1(sAfter)
        val techniqueIsBase = readSetupTechniqueIsBaseV1(sAfter)
        val techniqueDifficultyLevel = readSetupTechniqueDifficultyLevelV1(sAfter)
        val techniqueShortDefinitionSummary = readSetupTechniqueShortDefinitionSummaryV1(sAfter)

        val commitCell = story.optJSONObject("resolution_commit_cell")
        val commitDigit =
            if (!story.isNull("resolution_commit_digit")) story.optInt("resolution_commit_digit", -1).takeIf { it in 1..9 } else null

        val canonicalStageTruth =
            buildCanonicalStageTruthV1(
                sAfter = sAfter,
                fallbackTargetCell = commitCell,
                fallbackPrimaryHouse = null,
                fallbackTargetDigit = commitDigit
            )

        val proofArgs =
            canonicalStageTruth.optJSONObject("proof_args") ?: JSONObject()

        val fullResolutionBasis =
            canonicalStageTruth.optJSONObject("target_resolution_truth") ?: JSONObject()

        val canonicalTruthSource =
            canonicalStageTruth.optString("source_of_truth")

        val resolutionCommitAuthorized =
            story.optBoolean("resolution_commit_authorized", false)

        val recapSummary =
            story.optString("resolution_recap_summary")
                .takeIf { it.isNotBlank() }
                ?: defaultResolutionRecapSummaryFromTruthV1(
                    targetResolutionTruth = fullResolutionBasis,
                    archetype = archetype
                )

        val techniqueContributionSummary =
            story.optString("resolution_technique_contribution_summary")
                .takeIf { it.isNotBlank() }
                ?: defaultResolutionTechniqueContributionFromTruthV1(
                    targetResolutionTruth = fullResolutionBasis,
                    archetype = archetype
                )

        val finalForcingSummary =
            story.optString("resolution_final_forcing_summary")
                .takeIf { it.isNotBlank() }
                ?: defaultResolutionFinalForcingFromTruthV1(
                    targetResolutionTruth = fullResolutionBasis,
                    commitDigit = commitDigit,
                    archetype = archetype
                )

        val honestyLine =
            story.optString("resolution_two_layer_honesty_line")
                .takeIf { it.isNotBlank() }

        val intersectionCausalRecap =
            if (resolutionProfile == ResolutionProfileV1.INTERSECTIONS_RESOLUTION) {
                buildIntersectionResolutionCausalRecapV1(
                    targetResolutionTruth = fullResolutionBasis,
                    commitCell = commitCell,
                    commitDigit = commitDigit
                )
            } else {
                JSONObject()
            }

        val intersectionStructuralLesson =
            if (resolutionProfile == ResolutionProfileV1.INTERSECTIONS_RESOLUTION) {
                buildIntersectionResolutionStructuralLessonV1(
                    targetResolutionTruth = fullResolutionBasis,
                    commitDigit = commitDigit
                )
            } else {
                JSONObject()
            }

        val commitAppliedOnBoard = isRevealAlreadyAppliedOnBoardV1(sAfter)
        val resolutionRepairMode =
            resolutionCommitAuthorized && !commitAppliedOnBoard

        val presentStateSummary =
            when {
                resolutionRepairMode && commitCell != null && commitDigit != null -> {
                    val rr = commitCell.optInt("r", -1)
                    val cc = commitCell.optInt("c", -1)
                    if (rr in 1..9 && cc in 1..9) {
                        "We have reached the placement step for r${rr}c${cc} = $commitDigit, but that value is not written on the grid yet."
                    } else {
                        "We have reached the placement step, but the board does not show the committed value yet."
                    }
                }

                resolutionRepairMode -> {
                    "We have reached the placement step, but the board update has not completed yet."
                }

                else ->
                    story.optString("resolution_present_state_line")
                        .takeIf { it.isNotBlank() }
                        ?: if (commitCell != null && commitDigit != null) {
                            val rr = commitCell.optInt("r", -1)
                            val cc = commitCell.optInt("c", -1)
                            if (rr in 1..9 && cc in 1..9) {
                                "So now we can place it: r${rr}c${cc} = $commitDigit."
                            } else {
                                "So now we can place the answer in the target."
                            }
                        } else {
                            "So now we can commit the answer."
                        }
            }

        val postCommitSummary =
            when {
                resolutionRepairMode ->
                    "The proof is complete, but the board update still needs to be settled before moving to the next step."

                else ->
                    story.optString("resolution_post_commit_grid_delta_summary")
                        .takeIf { it.isNotBlank() }
                        ?: "That target is now fixed, so we can move to the next solving step."
            }


        val packet = ResolutionReplyPacketV1(
            resolutionProfile = resolutionProfile,
            archetype = archetype,
            technique = JSONObject().apply {
                put("id", techniqueId ?: JSONObject.NULL)
                put("name", techniqueName ?: JSONObject.NULL)
                put("real_name", techniqueRealName ?: JSONObject.NULL)
                put("family", techniqueFamily ?: JSONObject.NULL)
                put("archetype", archetype ?: JSONObject.NULL)
                put("is_base", techniqueIsBase ?: JSONObject.NULL)
                put("difficulty_level", techniqueDifficultyLevel ?: JSONObject.NULL)
                put("short_definition_summary", techniqueShortDefinitionSummary ?: JSONObject.NULL)
            },
            commit = JSONObject().apply {
                put("cell", commitCell ?: JSONObject.NULL)
                put("digit", commitDigit ?: JSONObject.NULL)
                put("authorized", resolutionCommitAuthorized)
                put(
                    "present_state_language_required",
                    story.optBoolean("resolution_present_state_language_required", resolutionCommitAuthorized)
                )
                put(
                    "commit_truth_source",
                    story.optString("resolution_commit_truth_source").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
                put(
                    "claim_code",
                    story.optString("resolution_claim_code").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
                put("spoiler_level", story.opt("resolution_spoiler_level") ?: JSONObject.NULL)
            },
            recap = JSONObject().apply {
                put("summary", recapSummary)
                put("compact_mode", compactMode(resolutionProfile))
                put("max_beats", recapMaxBeats(resolutionProfile))
            },
            techniqueContribution = JSONObject().apply {
                put("summary", techniqueContributionSummary)
                put(
                    "kind",
                    when (fullResolutionBasis.optString("elimination_kind")) {
                        "HOUSE_CANDIDATE_CELLS_FOR_DIGIT" -> "house_narrowing"
                        else -> "partial_cleanup"
                    }
                )
            },
            fullResolutionBasis = fullResolutionBasis,
            finalForcing = JSONObject().apply {
                put("summary", finalForcingSummary)
                put(
                    "resolution_kind",
                    fullResolutionBasis.optString("elimination_kind")
                        .ifBlank { story.optString("resolution_claim_code") }
                )
                put("surviving_digit", commitDigit ?: JSONObject.NULL)
            },
            honesty = JSONObject().apply {
                put("two_layer_honesty_line", honestyLine ?: JSONObject.NULL)
                put(
                    "must_distinguish_technique_from_finish",
                    !honestyLine.isNullOrBlank() ||
                            resolutionProfile == ResolutionProfileV1.INTERSECTIONS_RESOLUTION
                )
            },
            causalRecap = JSONObject().apply {
                if (resolutionProfile == ResolutionProfileV1.INTERSECTIONS_RESOLUTION) {
                    put("battlefield_house", intersectionCausalRecap.opt("battlefield_house") ?: JSONObject.NULL)
                    put("source_house", intersectionCausalRecap.opt("source_house") ?: JSONObject.NULL)
                    put("source_overlap_cells", intersectionCausalRecap.opt("source_overlap_cells") ?: JSONArray())
                    put("final_removed_rival", intersectionCausalRecap.opt("final_removed_rival") ?: JSONObject.NULL)
                    put("ordinary_groundwork_line", intersectionCausalRecap.opt("ordinary_groundwork_line") ?: JSONObject.NULL)
                    put("decisive_cut_line", intersectionCausalRecap.opt("decisive_cut_line") ?: JSONObject.NULL)
                    put("survivor_line", intersectionCausalRecap.opt("survivor_line") ?: JSONObject.NULL)
                    put(
                        "birthplace_vs_battleground_line",
                        intersectionCausalRecap.opt("birthplace_vs_battleground_line") ?: JSONObject.NULL
                    )
                }
            },
            structuralLesson = JSONObject().apply {
                if (resolutionProfile == ResolutionProfileV1.INTERSECTIONS_RESOLUTION) {
                    put(
                        "pressure_principle_line",
                        intersectionStructuralLesson.opt("pressure_principle_line") ?: JSONObject.NULL
                    )
                    put(
                        "memory_rule_line",
                        intersectionStructuralLesson.opt("memory_rule_line") ?: JSONObject.NULL
                    )
                    put(
                        "structural_insight_line",
                        intersectionStructuralLesson.opt("structural_insight_line") ?: JSONObject.NULL
                    )
                }
            },
            presentStateLine = JSONObject().apply {
                put("summary", presentStateSummary)
            },
            postCommit = JSONObject().apply {
                put("board_delta_summary", postCommitSummary)
                put("placement_count", 1)
            },
            cta = JSONObject().apply {
                put(
                    "kind",
                    when {
                        resolutionRepairMode -> "RESOLUTION_REPAIR"
                        else ->
                            story.optString("resolution_cta_kind").takeIf { it.isNotBlank() }
                                ?: "NEXT_STEP"
                    }
                )
            },
            support = JSONObject().apply {
                put("has_commit", resolutionCommitAuthorized)
                put("has_recap", recapSummary.isNotBlank())
                put("has_technique_contribution", techniqueContributionSummary.isNotBlank())
                put("has_full_resolution_basis", fullResolutionBasis.length() > 0)
                put("has_final_forcing", finalForcingSummary.isNotBlank())
                put("has_honesty", !honestyLine.isNullOrBlank())
                put("has_causal_recap", intersectionCausalRecap.length() > 0)
                put("has_structural_lesson", intersectionStructuralLesson.length() > 0)
                put("has_present_state_line", presentStateSummary.isNotBlank())
                put("has_post_commit_summary", postCommitSummary.isNotBlank())
                put("has_cta_kind", true)
                put("apply_confirmed_on_board", commitAppliedOnBoard)
                put("resolution_repair_mode", resolutionRepairMode)
                put("cost_mode", "bounded_compact_packet_v2")
                put("recap_max_beats", recapMaxBeats(resolutionProfile))
                put(
                    "resolution_kind",
                    fullResolutionBasis.optString("elimination_kind").ifBlank { JSONObject.NULL as String? }
                )
                put(
                    "overlay_variant",
                    story.optString("resolution_overlay_variant").takeIf { it.isNotBlank() }
                        ?: JSONObject.NULL
                )
                put("canonical_truth_source", canonicalTruthSource)
            }
        )

        return factResolutionReplyPacketV1(packet)
    }



    // ---------------------------------------------------------------------
    // Phase 2 — Detour packet builders (cheap supported classes only)
    // ---------------------------------------------------------------------

    private fun findFactPayloadByTypeV1(
        facts: List<FactBundleV1>,
        type: FactBundleV1.Type
    ): JSONObject? = facts.firstOrNull { it.type == type }?.payload

    private fun deepCopyJsonV1(src: JSONObject?): JSONObject? =
        src?.let { JSONObject(it.toString()) }

    private fun activeStageReplyPacketPayloadV1(
        sAfter: SudoState,
        facts: List<FactBundleV1>
    ): JSONObject? =
        when (sAfter.narrativeStory?.stage) {
            StoryStage.SETUP ->
                findFactPayloadByTypeV1(facts, FactBundleV1.Type.SETUP_REPLY_PACKET_V1)

            StoryStage.CONFRONTATION ->
                findFactPayloadByTypeV1(facts, FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1)

            StoryStage.RESOLUTION ->
                findFactPayloadByTypeV1(facts, FactBundleV1.Type.RESOLUTION_REPLY_PACKET_V1)

            null -> null
        }

    private fun shouldEmitReturnToRouteArtifactV1(sAfter: SudoState): Boolean {
        val authorityOwner = sAfter.activeTurnAuthorityDecisionV1.owner
        val boundaryStatus = sAfter.activeRouteBoundaryDecisionV1.status
        val routeReturnAllowed = sAfter.activeTurnAuthorityDecisionV1.routeReturnAllowed

        if (!routeReturnAllowed) return false

        return when {
            authorityOwner == TurnAuthorityOwnerV1.USER_DETOUR_OWNER &&
                    boundaryStatus == RouteBoundaryStatusV1.PAUSED_AT_CHECKPOINT -> true

            authorityOwner == TurnAuthorityOwnerV1.REPAIR_OWNER &&
                    boundaryStatus == RouteBoundaryStatusV1.BLOCKED_BY_REPAIR -> true

            else -> false
        }
    }

    private fun buildReturnToRoutePacketBundleV1(
        sAfter: SudoState
    ): FactBundleV1? {
        val ds = sAfter.detourState ?: return null
        val q = ds.questionClass ?: return null
        if (!shouldEmitReturnToRouteArtifactV1(sAfter)) return null

        return factReturnToRoutePacketV1(
            JSONObject().apply {
                put("schema_version", "return_to_route_packet_v1")
                put("question_class", q.name)
                put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                put("anchor_target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                put("anchor_technique_id", ds.anchorTechniqueId ?: JSONObject.NULL)
                put("return_hint", ds.returnHint ?: JSONObject.NULL)
                put(
                    "next_route_question",
                    when (ds.anchorStage) {
                        StoryStage.SETUP -> "Want to go back to the setup and see why this pattern matters?"
                        StoryStage.CONFRONTATION -> "Want to go back to the proof and keep following the logic?"
                        StoryStage.RESOLUTION -> "Want to go back to the finish and lock in the step?"
                        null -> "Want to go back to the main solving route?"
                    }
                )
            }
        )
    }

    private fun candidateFactMatchesCellV1(
        payload: JSONObject,
        cellRef: String?
    ): Boolean {
        val wanted = cellRef?.trim().orEmpty()
        if (wanted.isBlank()) return false

        val cell = payload.optString("cell").trim()
        if (cell.equals(wanted, ignoreCase = true)) return true

        val targetCell = payload.optString("target_cell").trim()
        if (targetCell.equals(wanted, ignoreCase = true)) return true

        return false
    }

    private fun buildProofChallengePacketBundleV1(
        sAfter: SudoState,
        facts: List<FactBundleV1>
    ): FactBundleV1? {
        val ds = sAfter.detourState ?: return null
        if (!ds.isActive) return null
        if (ds.questionClass != DetourQuestionClassV1.PROOF_CHALLENGE) return null

        val stepPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.SOLVING_STEP_PACKET_V1)
        val stageReplyPayload = activeStageReplyPacketPayloadV1(sAfter, facts)
        val storyPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.STORY_CONTEXT_V1)

        val requestedCell =
            ds.requestedCell
                ?: stepPayload?.optString("target_cell")?.takeIf {
                    it.isNotBlank() && ds.requestedCell != null
                }
                ?: stepPayload?.optString("focus_cell")?.takeIf {
                    it.isNotBlank() && ds.requestedCell != null
                }

        val requestedDigit =
            ds.requestedDigit
                ?: stepPayload?.optInt("target_digit").takeIf { (it ?: 0) in 1..9 }
                ?: stepPayload?.optInt("focus_digit").takeIf { (it ?: 0) in 1..9 }

        val candidateCellFacts = facts
            .filter { it.type == FactBundleV1.Type.CANDIDATE_STATE_CELL }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val matchingCellFacts = candidateCellFacts.filter { candidateFactMatchesCellV1(it, requestedCell) }

        val houseCandidateFacts = facts
            .filter { it.type == FactBundleV1.Type.HOUSE_CANDIDATE_MAP }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val digitFrequencyPayload =
            deepCopyJsonV1(findFactPayloadByTypeV1(facts, FactBundleV1.Type.DIGIT_CANDIDATE_FREQUENCY))

        return factProofChallengePacketV1(
            JSONObject().apply {
                put("schema_version", "proof_challenge_packet_v1")
                put("question_class", ds.questionClass?.name ?: JSONObject.NULL)
                put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)

                put(
                    "claim_under_test",
                    JSONObject().apply {
                        put("cell", requestedCell ?: JSONObject.NULL)
                        put("digit", requestedDigit ?: JSONObject.NULL)
                        put("challenge_kind", "cell_digit_or_local_step_claim")
                    }
                )

                put(
                    "current_step_context",
                    JSONObject().apply {
                        put("target_cell", stepPayload?.opt("target_cell") ?: JSONObject.NULL)
                        put("target_digit", stepPayload?.opt("target_digit") ?: JSONObject.NULL)
                        put("focus_cell", stepPayload?.opt("focus_cell") ?: JSONObject.NULL)
                        put("focus_digit", stepPayload?.opt("focus_digit") ?: JSONObject.NULL)
                        put("technique", stepPayload?.opt("technique") ?: JSONObject.NULL)
                        put("label", stepPayload?.opt("label") ?: JSONObject.NULL)
                        put("subset", stepPayload?.opt("subset") ?: JSONObject.NULL)
                        put("intersection", stepPayload?.opt("intersection") ?: JSONObject.NULL)
                        put("houses", stepPayload?.opt("houses") ?: JSONObject.NULL)
                        put("proof", stepPayload?.opt("proof") ?: JSONObject.NULL)
                        put("eliminations", stepPayload?.opt("eliminations") ?: JSONObject.NULL)
                    }
                )

                put(
                    "candidate_truth",
                    JSONArray().apply {
                        matchingCellFacts.take(3).forEach { put(it) }
                    }
                )

                put(
                    "house_candidate_maps",
                    JSONArray().apply {
                        houseCandidateFacts.take(3).forEach { put(it) }
                    }
                )

                put("digit_candidate_frequency", digitFrequencyPayload ?: JSONObject())

                put(
                    "story_context",
                    JSONObject().apply {
                        put("focus_atom_index", storyPayload?.opt("focus_atom_index") ?: JSONObject.NULL)
                        put("atoms_in_scope_this_turn", storyPayload?.optJSONArray("atoms_in_scope_this_turn") ?: JSONArray())
                    }
                )

                put("active_stage_reply_packet", deepCopyJsonV1(stageReplyPayload) ?: JSONObject())

                put(
                    "verdict_hint",
                    when {
                        requestedCell.isNullOrBlank() -> ReasoningVerdictV1.UNKNOWN.name
                        matchingCellFacts.isEmpty() -> ReasoningVerdictV1.UNKNOWN.name
                        else -> ReasoningVerdictV1.VALID.name
                    }
                )

                put(
                    "answer_contract",
                    JSONObject().apply {
                        put("answer_first", true)
                        put("prefer_local_grid_truth", true)
                        put("avoid_global_search", true)
                        put("one_question_max", true)
                    }
                )
            }
        )
    }



    private fun candidateDigitsFromFactV1(payload: JSONObject?): List<Int> {
        if (payload == null) return emptyList()

        val digits = payload.optJSONArray("digits")
        if (digits != null) {
            val out = mutableListOf<Int>()
            for (i in 0 until digits.length()) {
                val d = digits.optInt(i)
                if (d in 1..9) out += d
            }
            if (out.isNotEmpty()) return out
        }

        val mask = payload.optInt("mask", 0)
        if (mask == 0) return emptyList()

        val out = mutableListOf<Int>()
        for (d in 1..9) {
            if ((mask and (1 shl (d - 1))) != 0) out += d
        }
        return out
    }

    private fun inferReasoningProposalKindV1(
        ds: DetourStateV1,
        requestedCell: String?,
        requestedDigit: Int?
    ): DetourUserProposalKindV1 =
        when {
            !ds.requestedTechniqueIdOrLabel.isNullOrBlank() ->
                DetourUserProposalKindV1.PROPOSED_PATTERN

            requestedCell != null && requestedDigit != null ->
                DetourUserProposalKindV1.PROPOSED_ELIMINATION

            requestedDigit != null ->
                DetourUserProposalKindV1.PROPOSED_HOUSE_CLAIM

            else ->
                DetourUserProposalKindV1.GENERAL_REASONING_CHECK
        }

    private fun inferReasoningVerdictHintV1(
        ds: DetourStateV1,
        stepPayload: JSONObject?,
        requestedCell: String?,
        requestedDigit: Int?,
        matchingCellFacts: List<JSONObject>
    ): ReasoningVerdictV1 {
        val requestedTechnique = ds.requestedTechniqueIdOrLabel?.trim().orEmpty().lowercase()
        val currentTechniqueId = stepPayload?.optString("technique")?.trim().orEmpty().lowercase()
        val currentTechniqueLabel = stepPayload?.optString("label")?.trim().orEmpty().lowercase()

        if (
            requestedTechnique.isNotBlank() &&
            (requestedTechnique == currentTechniqueId || requestedTechnique == currentTechniqueLabel)
        ) {
            return ReasoningVerdictV1.VALID
        }

        if (
            requestedTechnique.isNotBlank() &&
            currentTechniqueId.isNotBlank() &&
            requestedTechnique != currentTechniqueId &&
            requestedTechnique != currentTechniqueLabel
        ) {
            return ReasoningVerdictV1.VALID_BUT_NOT_CURRENT_ROUTE
        }

        if (requestedCell.isNullOrBlank()) {
            return ReasoningVerdictV1.UNKNOWN
        }

        val primaryFact = matchingCellFacts.firstOrNull()
        if (primaryFact == null) {
            return ReasoningVerdictV1.UNKNOWN
        }

        val liveDigits = candidateDigitsFromFactV1(primaryFact)

        if (requestedDigit != null) {
            return when {
                liveDigits.isEmpty() ->
                    ReasoningVerdictV1.UNKNOWN

                requestedDigit !in liveDigits ->
                    ReasoningVerdictV1.INVALID

                else ->
                    ReasoningVerdictV1.PARTIALLY_VALID
            }
        }

        return ReasoningVerdictV1.PARTIALLY_VALID
    }

    private fun inferReasoningVerdictReasonV1(
        ds: DetourStateV1,
        stepPayload: JSONObject?,
        requestedCell: String?,
        requestedDigit: Int?,
        matchingCellFacts: List<JSONObject>,
        verdict: ReasoningVerdictV1
    ): String? {
        val requestedTechnique = ds.requestedTechniqueIdOrLabel?.trim().orEmpty()
        val currentTechniqueId = stepPayload?.optString("technique")?.trim().orEmpty()
        val currentTechniqueLabel = stepPayload?.optString("label")?.trim().orEmpty()
        val primaryFact = matchingCellFacts.firstOrNull()
        val liveDigits = candidateDigitsFromFactV1(primaryFact)

        return when (verdict) {
            ReasoningVerdictV1.VALID ->
                when {
                    requestedTechnique.isNotBlank() ->
                        "Your idea matches the technique the current route is already using."

                    requestedCell != null && requestedDigit != null ->
                        "Your claim fits the current local board truth for $requestedCell and digit $requestedDigit."

                    else ->
                        "Your idea is supported by the current local board truth."
                }

            ReasoningVerdictV1.INVALID ->
                when {
                    requestedCell != null && requestedDigit != null && liveDigits.isNotEmpty() ->
                        "That proposal does not match the current cell truth: $requestedCell does not currently carry digit $requestedDigit as a live candidate."

                    else ->
                        "That proposal does not line up with the current board truth."
                }

            ReasoningVerdictV1.VALID_BUT_NOT_CURRENT_ROUTE ->
                when {
                    requestedTechnique.isNotBlank() && currentTechniqueId.isNotBlank() ->
                        "Your idea may be reasonable, but it is not the same as the route's current technique (${currentTechniqueLabel.ifBlank { currentTechniqueId }})."

                    else ->
                        "Your idea may work locally, but it is not the route the app is currently pursuing."
                }

            ReasoningVerdictV1.PARTIALLY_VALID ->
                when {
                    requestedCell != null && requestedDigit != null && liveDigits.contains(requestedDigit) ->
                        "Digit $requestedDigit is still live in $requestedCell, so the cell truth alone does not yet prove that it should be eliminated."

                    requestedCell != null ->
                        "Part of your idea matches the local board truth, but the supplied facts do not yet prove the full claim."

                    else ->
                        "Part of your idea matches the current board truth, but the supplied facts do not settle the whole claim."
                }

            ReasoningVerdictV1.UNKNOWN ->
                when {
                    requestedCell == null ->
                        "I still do not have a reliable enough local target to judge that idea."

                    matchingCellFacts.isEmpty() ->
                        "I do not yet have enough local truth for that cell to judge the idea cleanly."

                    else ->
                        "The supplied local truth is not enough yet to judge that idea cleanly."
                }
        }
    }

    private fun buildReasoningWhatIsCorrectV1(
        requestedCell: String?,
        requestedDigit: Int?,
        matchingCellFacts: List<JSONObject>,
        verdict: ReasoningVerdictV1
    ): JSONArray {
        val primaryFact = matchingCellFacts.firstOrNull()
        val liveDigits = candidateDigitsFromFactV1(primaryFact)

        return JSONArray().apply {
            requestedCell?.let {
                put("We are checking the local truth of $it.")
            }
            requestedDigit?.let {
                put("The asked digit is $it.")
            }
            if (requestedCell != null && requestedDigit != null && liveDigits.contains(requestedDigit)) {
                put("Digit $requestedDigit is currently still listed as a live candidate in $requestedCell.")
            }
            if (verdict == ReasoningVerdictV1.VALID_BUT_NOT_CURRENT_ROUTE) {
                put("The idea can be discussed locally even though it is not the route's current move.")
            }
        }
    }

    private fun buildReasoningWhatIsIncorrectV1(
        requestedCell: String?,
        requestedDigit: Int?,
        matchingCellFacts: List<JSONObject>,
        verdict: ReasoningVerdictV1
    ): JSONArray {
        val primaryFact = matchingCellFacts.firstOrNull()
        val liveDigits = candidateDigitsFromFactV1(primaryFact)

        return JSONArray().apply {
            if (verdict == ReasoningVerdictV1.INVALID &&
                requestedCell != null &&
                requestedDigit != null &&
                liveDigits.isNotEmpty() &&
                requestedDigit !in liveDigits
            ) {
                put("Digit $requestedDigit is not currently a live candidate in $requestedCell.")
            }

            if (verdict == ReasoningVerdictV1.PARTIALLY_VALID &&
                requestedCell != null &&
                requestedDigit != null &&
                liveDigits.contains(requestedDigit)
            ) {
                put("The supplied facts do not yet show the blocking proof that would justify removing digit $requestedDigit from $requestedCell.")
            }

            if (verdict == ReasoningVerdictV1.UNKNOWN) {
                put("The current packet does not yet supply enough scoped proof to settle the idea cleanly.")
            }
        }
    }

    private fun inferReasoningRouteAlignmentV1(
        ds: DetourStateV1,
        stepPayload: JSONObject?,
        verdict: ReasoningVerdictV1
    ): String? {
        val currentTechniqueId = stepPayload?.optString("technique")?.trim().orEmpty()
        val currentTechniqueLabel = stepPayload?.optString("label")?.trim().orEmpty()

        return when (verdict) {
            ReasoningVerdictV1.VALID ->
                "aligned_with_current_route"

            ReasoningVerdictV1.VALID_BUT_NOT_CURRENT_ROUTE ->
                "locally_plausible_but_not_current_route"

            ReasoningVerdictV1.INVALID ->
                "conflicts_with_current_board_truth"

            ReasoningVerdictV1.PARTIALLY_VALID ->
                if (!ds.requestedTechniqueIdOrLabel.isNullOrBlank() ||
                    currentTechniqueId.isNotBlank() ||
                    currentTechniqueLabel.isNotBlank()
                ) {
                    "needs_more_proof_before_route_alignment"
                } else {
                    "local_check_not_yet_complete"
                }

            ReasoningVerdictV1.UNKNOWN ->
                "insufficient_scope_for_route_alignment"
        }
    }

    private fun buildUserReasoningCheckPacketBundleV1(
        sAfter: SudoState,
        facts: List<FactBundleV1>
    ): FactBundleV1? {
        val ds = sAfter.detourState ?: return null
        if (!ds.isActive) return null
        if (ds.questionClass != DetourQuestionClassV1.USER_REASONING_CHECK) return null

        val stepPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.SOLVING_STEP_PACKET_V1)
        val stageReplyPayload = activeStageReplyPacketPayloadV1(sAfter, facts)
        val storyPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.STORY_CONTEXT_V1)

        val requestedCell =
            ds.requestedCell
                ?: ds.anchorTargetCell
                ?: stepPayload?.optString("target_cell")?.takeIf { it.isNotBlank() }
                ?: stepPayload?.optString("focus_cell")?.takeIf { it.isNotBlank() }

        val requestedDigit =
            ds.requestedDigit
                ?: stepPayload?.optInt("target_digit").takeIf { (it ?: 0) in 1..9 }
                ?: stepPayload?.optInt("focus_digit").takeIf { (it ?: 0) in 1..9 }

        val candidateCellFacts = facts
            .filter { it.type == FactBundleV1.Type.CANDIDATE_STATE_CELL }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val matchingCellFacts = candidateCellFacts.filter { candidateFactMatchesCellV1(it, requestedCell) }
        val primaryCellFact = matchingCellFacts.firstOrNull()
        val liveDigits = candidateDigitsFromFactV1(primaryCellFact)

        val houseCandidateFacts = facts
            .filter { it.type == FactBundleV1.Type.HOUSE_CANDIDATE_MAP }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val digitFrequencyPayload =
            deepCopyJsonV1(findFactPayloadByTypeV1(facts, FactBundleV1.Type.DIGIT_CANDIDATE_FREQUENCY))

        val proposalKind = inferReasoningProposalKindV1(
            ds = ds,
            requestedCell = requestedCell,
            requestedDigit = requestedDigit
        )

        val verdict = inferReasoningVerdictHintV1(
            ds = ds,
            stepPayload = stepPayload,
            requestedCell = requestedCell,
            requestedDigit = requestedDigit,
            matchingCellFacts = matchingCellFacts
        )

        val verdictReason = inferReasoningVerdictReasonV1(
            ds = ds,
            stepPayload = stepPayload,
            requestedCell = requestedCell,
            requestedDigit = requestedDigit,
            matchingCellFacts = matchingCellFacts,
            verdict = verdict
        )

        val whatIsCorrect = buildReasoningWhatIsCorrectV1(
            requestedCell = requestedCell,
            requestedDigit = requestedDigit,
            matchingCellFacts = matchingCellFacts,
            verdict = verdict
        )

        val whatIsIncorrect = buildReasoningWhatIsIncorrectV1(
            requestedCell = requestedCell,
            requestedDigit = requestedDigit,
            matchingCellFacts = matchingCellFacts,
            verdict = verdict
        )

        val proposalText =
            when {
                requestedCell != null && requestedDigit != null ->
                    "Check whether digit $requestedDigit can be removed from $requestedCell."

                requestedCell != null ->
                    "Check the user's local reasoning about $requestedCell."

                !ds.requestedTechniqueIdOrLabel.isNullOrBlank() ->
                    "Check whether ${ds.requestedTechniqueIdOrLabel} fits here."

                else ->
                    "Check the user's proposed local Sudoku reasoning."
            }

        val proposalScope =
            when {
                requestedCell != null && requestedDigit != null ->
                    "$requestedCell / digit $requestedDigit"

                requestedCell != null ->
                    requestedCell

                requestedDigit != null ->
                    "digit $requestedDigit"

                else ->
                    ds.anchorStage?.name
            }

        val routeAlignment = inferReasoningRouteAlignmentV1(
            ds = ds,
            stepPayload = stepPayload,
            verdict = verdict
        )

        val missingCondition =
            when (verdict) {
                ReasoningVerdictV1.PARTIALLY_VALID ->
                    if (requestedCell != null && requestedDigit != null && liveDigits.contains(requestedDigit)) {
                        "A concrete blocking proof is still needed before digit $requestedDigit can be removed from $requestedCell."
                    } else {
                        "The current packet does not yet prove the full claim."
                    }

                ReasoningVerdictV1.UNKNOWN ->
                    "A tighter scoped proof or cleaner local target is still needed."

                else ->
                    null
            }

        return factUserReasoningCheckPacketV1(
            JSONObject().apply {
                put("schema_version", "user_reasoning_check_packet_v1")
                put("question_class", ds.questionClass?.name ?: JSONObject.NULL)
                put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)

                put("proposal_kind", proposalKind.name)
                put("proposal_text", proposalText)
                put("proposal_scope", proposalScope ?: JSONObject.NULL)
                put("target_cell", requestedCell ?: JSONObject.NULL)
                put("target_digit", requestedDigit ?: JSONObject.NULL)
                put("step_id", ds.anchorStepId ?: JSONObject.NULL)
                put("story_stage", ds.anchorStage?.name ?: JSONObject.NULL)

                put(
                    "user_claim",
                    JSONObject().apply {
                        put("cell", requestedCell ?: JSONObject.NULL)
                        put("digit", requestedDigit ?: JSONObject.NULL)
                        put("technique_hint", ds.requestedTechniqueIdOrLabel ?: JSONObject.NULL)
                        put("claim_kind", proposalKind.name)
                    }
                )

                put(
                    "proposal_under_test",
                    JSONObject().apply {
                        put("proposal_kind", proposalKind.name)
                        put("target_cell", requestedCell ?: JSONObject.NULL)
                        put("target_digit", requestedDigit ?: JSONObject.NULL)
                        put("target_house", JSONObject.NULL)
                        put("technique_hint", ds.requestedTechniqueIdOrLabel ?: JSONObject.NULL)
                    }
                )

                put(
                    "current_route",
                    JSONObject().apply {
                        put("target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                        put("technique_id", ds.anchorTechniqueId ?: JSONObject.NULL)
                        put("stage", ds.anchorStage?.name ?: JSONObject.NULL)
                    }
                )

                put(
                    "current_step_context",
                    JSONObject().apply {
                        put("target_cell", stepPayload?.opt("target_cell") ?: JSONObject.NULL)
                        put("target_digit", stepPayload?.opt("target_digit") ?: JSONObject.NULL)
                        put("focus_cell", stepPayload?.opt("focus_cell") ?: JSONObject.NULL)
                        put("focus_digit", stepPayload?.opt("focus_digit") ?: JSONObject.NULL)
                        put("technique", stepPayload?.opt("technique") ?: JSONObject.NULL)
                        put("label", stepPayload?.opt("label") ?: JSONObject.NULL)
                        put("subset", stepPayload?.opt("subset") ?: JSONObject.NULL)
                        put("intersection", stepPayload?.opt("intersection") ?: JSONObject.NULL)
                        put("houses", stepPayload?.opt("houses") ?: JSONObject.NULL)
                        put("proof", stepPayload?.opt("proof") ?: JSONObject.NULL)
                        put("eliminations", stepPayload?.opt("eliminations") ?: JSONObject.NULL)
                    }
                )

                put(
                    "candidate_truth",
                    JSONArray().apply {
                        matchingCellFacts.take(3).forEach { put(it) }
                    }
                )

                put(
                    "house_candidate_maps",
                    JSONArray().apply {
                        houseCandidateFacts.take(3).forEach { put(it) }
                    }
                )

                put("digit_candidate_frequency", digitFrequencyPayload ?: JSONObject())

                put(
                    "verdict_truth",
                    JSONObject().apply {
                        put("verdict", verdict.name)
                        put("verdict_class", verdict.name)
                        put("needs_clarification", false)
                        put("clarification_reason", JSONObject.NULL)
                    }
                )

                put("verdict", verdict.name)
                put("verdict_hint", verdict.name)
                put("verdict_reason", verdictReason ?: JSONObject.NULL)
                put("what_is_correct", whatIsCorrect)
                put("what_is_incorrect", whatIsIncorrect)
                put("missing_condition", missingCondition ?: JSONObject.NULL)
                put("route_alignment", routeAlignment ?: JSONObject.NULL)

                put(
                    "proof_basis",
                    JSONObject().apply {
                        put("decisive_blocker_cell", JSONObject.NULL)
                        put("decisive_blocker_house", JSONObject.NULL)
                        put(
                            "supporting_house_maps",
                            JSONArray().apply {
                                houseCandidateFacts.take(3).forEach { put(it) }
                            }
                        )
                        put(
                            "candidate_receipts",
                            JSONArray().apply {
                                if (primaryCellFact != null) put(primaryCellFact)
                            }
                        )
                        put("route_conflict_if_any", routeAlignment ?: JSONObject.NULL)
                    }
                )

                put(
                    "support_rows",
                    JSONArray().apply {
                        if (requestedCell != null) {
                            put(
                                JSONObject().apply {
                                    put("kind", "target_cell")
                                    put("text", "Target cell: $requestedCell")
                                }
                            )
                        }
                        if (requestedCell != null && liveDigits.isNotEmpty()) {
                            put(
                                JSONObject().apply {
                                    put("kind", "candidate_truth")
                                    put("text", "Live candidates in $requestedCell: ${liveDigits.joinToString(", ")}")
                                }
                            )
                        }
                        verdictReason?.let { reason ->
                            put(
                                JSONObject().apply {
                                    put("kind", "verdict_reason")
                                    put("text", reason)
                                }
                            )
                        }
                    }
                )

                put(
                    "story_context",
                    JSONObject().apply {
                        put("focus_atom_index", storyPayload?.opt("focus_atom_index") ?: JSONObject.NULL)
                        put("atoms_in_scope_this_turn", storyPayload?.optJSONArray("atoms_in_scope_this_turn") ?: JSONArray())
                    }
                )

                put("active_stage_reply_packet", deepCopyJsonV1(stageReplyPayload) ?: JSONObject())

                put(
                    "spoken_contract",
                    JSONObject().apply {
                        put("answer_first", true)
                        put("state_verdict_early", true)
                        put("justify_with_local_proof", true)
                        put("avoid_validator_jargon", true)
                    }
                )

                put(
                    "answer_contract",
                    JSONObject().apply {
                        put("answer_first", true)
                        put("check_local_truth_first", true)
                        put("allow_affirm_or_correct", true)
                        put("allow_valid_but_not_current_route", true)
                        put("one_question_max", true)
                    }
                )
            }
        )
    }


    private fun inferAlternativeMoveRelationV1(
        ds: DetourStateV1,
        stepPayload: JSONObject?
    ): AlternativeMoveRelationV1 {
        val requestedTechnique = ds.requestedTechniqueIdOrLabel?.trim().orEmpty().lowercase()
        val currentTechniqueId = stepPayload?.optString("technique")?.trim().orEmpty().lowercase()
        val currentTechniqueLabel = stepPayload?.optString("label")?.trim().orEmpty().lowercase()

        return when {
            requestedTechnique.isBlank() ->
                AlternativeMoveRelationV1.UNKNOWN

            requestedTechnique == currentTechniqueId || requestedTechnique == currentTechniqueLabel ->
                AlternativeMoveRelationV1.SAME_MOVE

            currentTechniqueId.isNotBlank() &&
                    requestedTechnique != currentTechniqueId &&
                    requestedTechnique != currentTechniqueLabel ->
                AlternativeMoveRelationV1.ALTERNATIVE_MOVE

            else ->
                AlternativeMoveRelationV1.UNKNOWN
        }
    }

    private fun buildAlternativeTechniquePacketBundleV1(
        sAfter: SudoState,
        facts: List<FactBundleV1>
    ): FactBundleV1? {
        val ds = sAfter.detourState ?: return null
        if (!ds.isActive) return null
        if (ds.questionClass != DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY) return null

        val stepPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.SOLVING_STEP_PACKET_V1)
        val stageReplyPayload = activeStageReplyPacketPayloadV1(sAfter, facts)
        val storyPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.STORY_CONTEXT_V1)

        val requestedCell =
            ds.requestedCell
                ?: ds.anchorTargetCell
                ?: stepPayload?.optString("target_cell")?.takeIf { it.isNotBlank() }
                ?: stepPayload?.optString("focus_cell")?.takeIf { it.isNotBlank() }

        val requestedDigit =
            ds.requestedDigit
                ?: stepPayload?.optInt("target_digit").takeIf { (it ?: 0) in 1..9 }
                ?: stepPayload?.optInt("focus_digit").takeIf { (it ?: 0) in 1..9 }

        val candidateCellFacts = facts
            .filter { it.type == FactBundleV1.Type.CANDIDATE_STATE_CELL }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val matchingCellFacts = candidateCellFacts.filter { candidateFactMatchesCellV1(it, requestedCell) }

        val houseCandidateFacts = facts
            .filter { it.type == FactBundleV1.Type.HOUSE_CANDIDATE_MAP }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val digitFrequencyPayload =
            deepCopyJsonV1(findFactPayloadByTypeV1(facts, FactBundleV1.Type.DIGIT_CANDIDATE_FREQUENCY))

        val relation = inferAlternativeMoveRelationV1(ds, stepPayload)

        return factAlternativeTechniquePacketV1(
            JSONObject().apply {
                put("schema_version", "alternative_technique_packet_v1")
                put("question_class", ds.questionClass?.name ?: JSONObject.NULL)
                put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)

                put(
                    "query",
                    JSONObject().apply {
                        put("cell", requestedCell ?: JSONObject.NULL)
                        put("digit", requestedDigit ?: JSONObject.NULL)
                        put("requested_technique", ds.requestedTechniqueIdOrLabel ?: JSONObject.NULL)
                        put("search_scope", ds.requestedSearchScope ?: "local")
                    }
                )

                put(
                    "current_route",
                    JSONObject().apply {
                        put("target_cell", ds.anchorTargetCell ?: JSONObject.NULL)
                        put("technique_id", ds.anchorTechniqueId ?: JSONObject.NULL)
                        put("stage", ds.anchorStage?.name ?: JSONObject.NULL)
                    }
                )

                put(
                    "current_step_context",
                    JSONObject().apply {
                        put("target_cell", stepPayload?.opt("target_cell") ?: JSONObject.NULL)
                        put("target_digit", stepPayload?.opt("target_digit") ?: JSONObject.NULL)
                        put("focus_cell", stepPayload?.opt("focus_cell") ?: JSONObject.NULL)
                        put("focus_digit", stepPayload?.opt("focus_digit") ?: JSONObject.NULL)
                        put("technique", stepPayload?.opt("technique") ?: JSONObject.NULL)
                        put("label", stepPayload?.opt("label") ?: JSONObject.NULL)
                        put("subset", stepPayload?.opt("subset") ?: JSONObject.NULL)
                        put("intersection", stepPayload?.opt("intersection") ?: JSONObject.NULL)
                        put("houses", stepPayload?.opt("houses") ?: JSONObject.NULL)
                        put("proof", stepPayload?.opt("proof") ?: JSONObject.NULL)
                        put("eliminations", stepPayload?.opt("eliminations") ?: JSONObject.NULL)
                    }
                )

                put(
                    "local_candidate_truth",
                    JSONArray().apply {
                        matchingCellFacts.take(4).forEach { put(it) }
                    }
                )

                put(
                    "house_candidate_maps",
                    JSONArray().apply {
                        houseCandidateFacts.take(3).forEach { put(it) }
                    }
                )

                put("digit_candidate_frequency", digitFrequencyPayload ?: JSONObject())

                put(
                    "story_context",
                    JSONObject().apply {
                        put("focus_atom_index", storyPayload?.opt("focus_atom_index") ?: JSONObject.NULL)
                        put("atoms_in_scope_this_turn", storyPayload?.optJSONArray("atoms_in_scope_this_turn") ?: JSONArray())
                    }
                )

                put("active_stage_reply_packet", deepCopyJsonV1(stageReplyPayload) ?: JSONObject())
                put("relation_to_current_route", relation.name)

                put(
                    "answer_contract",
                    JSONObject().apply {
                        put("answer_first", true)
                        put("prefer_local_scope", true)
                        put("avoid_global_search", (ds.requestedSearchScope ?: "local") != "global")
                        put("allow_same_move", true)
                        put("allow_alternative_move", true)
                        put("allow_unknown", true)
                        put("one_question_max", true)
                    }
                )
            }
        )
    }



    private fun buildPhase2DetourBundlesV1(
        sAfter: SudoState,
        facts: List<FactBundleV1>
    ): List<FactBundleV1> {
        val ds = sAfter.detourState ?: return emptyList()
        val q = ds.questionClass ?: return emptyList()
        if (!ds.isActive) return emptyList()

        // Keep building the detour-specific semantic packet even when live
        // solver-backed facts are present. The reply projector should receive
        // both:
        //   1) the semantic detour packet (proof/neighbor/target/etc.)
        //   2) the raw solver-backed local truth packet(s)
        // so the assistant can answer the local question directly and still
        // offer a clean bridge back to the paused route.

        if (q == DetourQuestionClassV1.PROOF_CHALLENGE) {
            return listOfNotNull(
                buildProofChallengePacketBundleV1(sAfter, facts),
                buildReturnToRoutePacketBundleV1(sAfter)
            )
        }

        if (q == DetourQuestionClassV1.USER_REASONING_CHECK) {
            return listOfNotNull(
                buildUserReasoningCheckPacketBundleV1(sAfter, facts),
                buildReturnToRoutePacketBundleV1(sAfter)
            )
        }

        if (q == DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY) {
            return listOfNotNull(
                buildAlternativeTechniquePacketBundleV1(sAfter, facts),
                buildReturnToRoutePacketBundleV1(sAfter)
            )
        }

        val stepPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.SOLVING_STEP_PACKET_V1)
        val storyPayload = findFactPayloadByTypeV1(facts, FactBundleV1.Type.STORY_CONTEXT_V1)
        val stageReplyPayload = activeStageReplyPacketPayloadV1(sAfter, facts)

        val candidateCellFacts = facts
            .filter { it.type == FactBundleV1.Type.CANDIDATE_STATE_CELL }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val houseCandidateFacts = facts
            .filter { it.type == FactBundleV1.Type.HOUSE_CANDIDATE_MAP }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val cellsWithNCandsFacts = facts
            .filter {
                it.type == FactBundleV1.Type.CELLS_WITH_N_CANDS_SET ||
                        it.type == FactBundleV1.Type.BIVALUE_CELLS_SET
            }
            .mapNotNull { deepCopyJsonV1(it.payload) }

        val digitFrequencyPayload =
            deepCopyJsonV1(findFactPayloadByTypeV1(facts, FactBundleV1.Type.DIGIT_CANDIDATE_FREQUENCY))

        val targetCell =
            ds.anchorTargetCell
                ?: stepPayload?.optString("target_cell")?.takeIf { it.isNotBlank() }
                ?: stepPayload?.optString("focus_cell")?.takeIf { it.isNotBlank() }

        val matchingTargetCandidateFacts = candidateCellFacts.filter {
            val cell = it.optString("cell")
            !cell.isNullOrBlank() && !targetCell.isNullOrBlank() && cell.equals(targetCell, ignoreCase = true)
        }

        val neighborCandidateFacts = candidateCellFacts.filter {
            val cell = it.optString("cell")
            cell.isNotBlank() && (targetCell.isNullOrBlank() || !cell.equals(targetCell, ignoreCase = true))
        }

        val supportedPacket = when (q) {
            DetourQuestionClassV1.STEP_CLARIFICATION ->
                factStepClarificationPacketV1(
                    JSONObject().apply {
                        put("schema_version", "step_clarification_packet_v1")
                        put("question_class", q.name)
                        put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                        put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                        put("target_cell", targetCell ?: JSONObject.NULL)
                        put(
                            "technique",
                            JSONObject().apply {
                                put("id", stepPayload?.opt("technique") ?: JSONObject.NULL)
                                put("label", stepPayload?.opt("label") ?: JSONObject.NULL)
                                put("focus_cell", stepPayload?.opt("focus_cell") ?: JSONObject.NULL)
                                put("focus_digit", stepPayload?.opt("focus_digit") ?: JSONObject.NULL)
                                put("target_digit", stepPayload?.opt("target_digit") ?: JSONObject.NULL)
                            }
                        )
                        put(
                            "story_context",
                            JSONObject().apply {
                                put("focus_atom_index", storyPayload?.opt("focus_atom_index") ?: JSONObject.NULL)
                                put("atoms_in_scope_this_turn", storyPayload?.optJSONArray("atoms_in_scope_this_turn") ?: JSONArray())
                                put("required_end_cta_options", storyPayload?.optJSONArray("required_end_cta_options") ?: JSONArray())
                            }
                        )
                        put(
                            "step_context",
                            JSONObject().apply {
                                put("why_now", stepPayload?.opt("why_now") ?: JSONObject.NULL)
                                put("headline", stepPayload?.opt("headline") ?: JSONObject.NULL)
                                put("setup", stepPayload?.opt("setup") ?: JSONObject.NULL)
                                put("pattern", stepPayload?.opt("pattern") ?: JSONObject.NULL)
                                put("subset", stepPayload?.opt("subset") ?: JSONObject.NULL)
                                put("intersection", stepPayload?.opt("intersection") ?: JSONObject.NULL)
                                put("houses", stepPayload?.opt("houses") ?: JSONObject.NULL)
                            }
                        )
                        put("active_stage_reply_packet", deepCopyJsonV1(stageReplyPayload) ?: JSONObject())
                    }
                )

            DetourQuestionClassV1.TARGET_CELL_QUERY ->
                factTargetCellQueryPacketV1(
                    JSONObject().apply {
                        put("schema_version", "target_cell_query_packet_v1")
                        put("question_class", q.name)
                        put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                        put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                        put("target_cell", targetCell ?: JSONObject.NULL)
                        put("target_digit", stepPayload?.opt("target_digit") ?: JSONObject.NULL)
                        put("focus_cell", stepPayload?.opt("focus_cell") ?: JSONObject.NULL)
                        put("focus_digit", stepPayload?.opt("focus_digit") ?: JSONObject.NULL)
                        put("matching_candidate_facts", JSONArray().apply {
                            matchingTargetCandidateFacts.take(3).forEach { put(it) }
                        })
                        put("house_candidate_maps", JSONArray().apply {
                            houseCandidateFacts.take(2).forEach { put(it) }
                        })
                        put(
                            "step_context",
                            JSONObject().apply {
                                put("houses", stepPayload?.opt("houses") ?: JSONObject.NULL)
                                put("proof", stepPayload?.opt("proof") ?: JSONObject.NULL)
                                put("eliminations", stepPayload?.opt("eliminations") ?: JSONObject.NULL)
                                put("cta", stepPayload?.opt("cta") ?: JSONObject.NULL)
                            }
                        )
                        put("active_stage_reply_packet", deepCopyJsonV1(stageReplyPayload) ?: JSONObject())
                    }
                )

            DetourQuestionClassV1.CANDIDATE_STATE_QUERY ->
                factCandidateStatePacketV1(
                    JSONObject().apply {
                        put("schema_version", "candidate_state_packet_v1")
                        put("question_class", q.name)
                        put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                        put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                        put("target_cell", targetCell ?: JSONObject.NULL)
                        put("candidate_state_cells", JSONArray().apply {
                            candidateCellFacts.take(6).forEach { put(it) }
                        })
                        put("house_candidate_maps", JSONArray().apply {
                            houseCandidateFacts.take(3).forEach { put(it) }
                        })
                        put("cells_with_n_candidates", JSONArray().apply {
                            cellsWithNCandsFacts.take(2).forEach { put(it) }
                        })
                        put("digit_candidate_frequency", digitFrequencyPayload ?: JSONObject())
                    }
                )

            DetourQuestionClassV1.NEIGHBOR_CELL_QUERY ->
                factNeighborCellQueryPacketV1(
                    JSONObject().apply {
                        put("schema_version", "neighbor_cell_query_packet_v1")
                        put("question_class", q.name)
                        put("anchor_step_id", ds.anchorStepId ?: JSONObject.NULL)
                        put("anchor_stage", ds.anchorStage?.name ?: JSONObject.NULL)
                        put("target_cell", targetCell ?: JSONObject.NULL)
                        put("neighbor_candidate_facts", JSONArray().apply {
                            neighborCandidateFacts.take(4).forEach { put(it) }
                        })
                        put("house_candidate_maps", JSONArray().apply {
                            houseCandidateFacts.take(2).forEach { put(it) }
                        })
                        put(
                            "step_context",
                            JSONObject().apply {
                                put("subset", stepPayload?.opt("subset") ?: JSONObject.NULL)
                                put("intersection", stepPayload?.opt("intersection") ?: JSONObject.NULL)
                                put("houses", stepPayload?.opt("houses") ?: JSONObject.NULL)
                                put("eliminations", stepPayload?.opt("eliminations") ?: JSONObject.NULL)
                            }
                        )
                        put("active_stage_reply_packet", deepCopyJsonV1(stageReplyPayload) ?: JSONObject())
                    }
                )

            else -> null
        }

        val returnPacket =
            when (q) {
                DetourQuestionClassV1.STEP_CLARIFICATION,
                DetourQuestionClassV1.TARGET_CELL_QUERY,
                DetourQuestionClassV1.CANDIDATE_STATE_QUERY,
                DetourQuestionClassV1.NEIGHBOR_CELL_QUERY -> buildReturnToRoutePacketBundleV1(sAfter)

                else -> null
            }

        return listOfNotNull(supportedPacket, returnPacket)
    }

    private fun emitAuthorityConflictTelemetryV1(
        s: SudoState,
        domain: String,
        winner: String,
        suppressed: String,
        reason: String,
        extra: Map<String, Any?> = emptyMap()
    ) {
        ConversationTelemetry.emit(
            buildMap {
                put("type", "AUTHORITY_CONFLICT_V1")
                put("turn_id", s.turnSeq)
                put("phase", s.phase.name)
                put("domain", domain)
                put("winner", winner)
                put("suppressed", suppressed)
                put("reason", reason)
                put("turn_authority_owner", s.activeTurnAuthorityDecisionV1.owner.name)
                put("route_boundary_status", s.activeRouteBoundaryDecisionV1.status.name)
                putAll(extra)
            }
        )
    }

    private fun emitConstitutionInvariantTelemetryV1(
        s: SudoState,
        invariant: String,
        ok: Boolean,
        detail: String
    ) {
        ConversationTelemetry.emit(
            mapOf(
                "type" to "CONSTITUTION_INVARIANT_V1",
                "turn_id" to s.turnSeq,
                "phase" to s.phase.name,
                "turn_authority_owner" to s.activeTurnAuthorityDecisionV1.owner.name,
                "route_boundary_status" to s.activeRouteBoundaryDecisionV1.status.name,
                "invariant" to invariant,
                "ok" to ok,
                "detail" to detail
            )
        )
    }

    private fun demandRoutingPhaseV1(s: SudoState): GridPhase = s.phase

