    )

    private fun buildReplyDemandSignalsV1(
        sAfter: SudoState,
        decision: DecisionOutcomeV1?
    ): ReplyDemandSignalsV1 {
        val routingPhase = demandRoutingPhaseV1(sAfter)

        val pendingAfter = normalizePendingForReplyRoutingV1(sAfter.pending)
        val pendingKind = pendingSummary(pendingAfter)
        val solvingHead = currentQueuedSolvingHead(sAfter)
        val solvingRail = effectiveSolvingRailStateV1(sAfter)
        val canonicalPosition = resolveCanonicalSolvingStepPositionV1(sAfter)
        val canonicalIssues = validateCanonicalSolvingPositionV1(sAfter, canonicalPosition)
        val canonicalLegal = canonicalIssues.isEmpty()

        val authoritativeStoryStage =
            canonicalPosition?.stage ?: authoritativeStoryStageV1(
                solvingHead = solvingHead,
                pending = pendingAfter,
                story = sAfter.narrativeStory
            )
        val storyStage =
            canonicalPosition?.stage?.name
                ?: authoritativeStoryStage?.name


        val setupProfile =
            if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
                resolveSetupDemandProfileV1(sAfter)
            } else {
                null
            }

        val confrontationProofProfile =
            if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
                resolveConfrontationProofProfileV1(sAfter)
            } else {
                null
            }

        val resolutionProfile =
            if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
                resolveResolutionProfileV1(sAfter)
            } else {
                null
            }

        val canonicalArchetypeHint =
            if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
                readSetupArchetypeWireV1(sAfter)
            } else {
                null
            }

        val canonicalPatternSubtypeHint =
            if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
                readCanonicalPatternSubtypeHintV1(sAfter)
            } else {
                null
            }

        val canonicalDirectionModeHint =
            if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
                readCanonicalDirectionModeHintV1(sAfter)
            } else {
                null
            }


        val userAgendaHead = sAfter.userAgendaQueue.firstOrNull()
        val appAgendaHead = sAfter.appAgendaQueue.firstOrNull()

        val authorityOwner = sAfter.activeTurnAuthorityDecisionV1.owner
        val isAuthorityAppRouteOwner =
            authorityOwner == TurnAuthorityOwnerV1.APP_ROUTE_OWNER
        val isAuthorityUserDetourOwner =
            authorityOwner == TurnAuthorityOwnerV1.USER_DETOUR_OWNER
        val isAuthorityUserRouteJumpOwner =
            authorityOwner == TurnAuthorityOwnerV1.USER_ROUTE_JUMP_OWNER
        val isAuthorityRepairOwner =
            authorityOwner == TurnAuthorityOwnerV1.REPAIR_OWNER

        val routeBoundaryStatus = sAfter.activeRouteBoundaryDecisionV1.status
        val isBoundaryReleasedToNextStep =
            routeBoundaryStatus == RouteBoundaryStatusV1.RELEASED_TO_NEXT_STEP
        val isBoundaryBlockedByRepair =
            routeBoundaryStatus == RouteBoundaryStatusV1.BLOCKED_BY_REPAIR

        val usesAppRouteDemandFamily =
            isAuthorityAppRouteOwner || isBoundaryReleasedToNextStep
        val usesRouteJumpDemandFamily =
            isAuthorityUserRouteJumpOwner && !isBoundaryReleasedToNextStep
        val usesDetourDemandFamily =
            (isAuthorityUserDetourOwner || isAuthorityRepairOwner) && !isBoundaryBlockedByRepair

        val solvingSupportSubtype: ReplyDemandCategoryV1? = when {
            isAuthorityUserRouteJumpOwner && userAgendaHead is UserAgendaItem.RouteControl ->
                ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL
            else -> null
        }

        val detourSubtype: ReplyDemandCategoryV1? = when (userAgendaHead) {
            is UserAgendaItem.ProofChallenge -> ReplyDemandCategoryV1.DETOUR_PROOF_CHALLENGE
            is UserAgendaItem.TargetCellQuery -> ReplyDemandCategoryV1.DETOUR_TARGET_CELL_QUERY
            is UserAgendaItem.NeighborCellQuery -> ReplyDemandCategoryV1.DETOUR_NEIGHBOR_CELL_QUERY
            is UserAgendaItem.UserReasoningCheck -> ReplyDemandCategoryV1.DETOUR_REASONING_CHECK
            is UserAgendaItem.AlternativeTechniqueQuery -> ReplyDemandCategoryV1.DETOUR_ALTERNATIVE_TECHNIQUE
            is UserAgendaItem.RouteComparisonQuery -> ReplyDemandCategoryV1.DETOUR_ROUTE_COMPARISON
            is UserAgendaItem.GeneralQuestion ->
                if (isUnsupportedDetourTopicV1(userAgendaHead.topic)) {
                    ReplyDemandCategoryV1.CAPABILITY_ANSWER
                } else {
                    null
                }
            else -> null
        }

        val hasCandidateFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.CANDIDATE_STATE_CELL,
                    FactBundleV1.Type.CELLS_WITH_N_CANDS_SET,
                    FactBundleV1.Type.BIVALUE_CELLS_SET,
                    FactBundleV1.Type.HOUSE_CANDIDATE_MAP,
                    FactBundleV1.Type.DIGIT_CANDIDATE_FREQUENCY,
                    FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1,
                    FactBundleV1.Type.SOLVER_CELLS_CANDIDATES_PACKET_V1,
                    FactBundleV1.Type.SOLVER_HOUSE_CANDIDATE_MAP_PACKET_V1,
                    FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1,
                    FactBundleV1.Type.CANDIDATE_STATE_PACKET_V1 -> true
                    else -> false
                }
            } == true

        val hasOcrTrustFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.OCR_CONFIDENCE_CELL,
                    FactBundleV1.Type.OCR_CONFIDENCE_SUMMARY,
                    FactBundleV1.Type.FOCUS_CELL_SNAPSHOT,
                    FactBundleV1.Type.MISMATCH_EXPLANATION,
                    FactBundleV1.Type.CONFLICT_EXPLANATION -> true
                    else -> false
                }
            } == true

        val hasContentsFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.GRID_SNAPSHOT,
                    FactBundleV1.Type.CELL_STATUS_BUNDLE,
                    FactBundleV1.Type.HOUSE_STATUS_BUNDLE,
                    FactBundleV1.Type.HOUSES_COMPLETION_RANKING,
                    FactBundleV1.Type.DIGIT_LOCATIONS_BUNDLE -> true
                    else -> false
                }
            } == true

        val hasChangelogFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.RECENT_MUTATION_RESULT -> true
                    else -> false
                }
            } == true

        val hasMutationFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.RECENT_MUTATION_RESULT -> true
                    else -> false
                }
            } == true

        val hasSolvingSupportFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.STEP_CLARIFICATION_PACKET_V1,
                    FactBundleV1.Type.RETURN_TO_ROUTE_PACKET_V1,
                    FactBundleV1.Type.HANDOVER_NOTE_V1,
                    FactBundleV1.Type.STORY_CONTEXT_V1,
                    FactBundleV1.Type.CTA_PACKET_V1,
                    FactBundleV1.Type.SOLVING_STEP_PACKET_V1,
                    FactBundleV1.Type.SETUP_REPLY_PACKET_V1,
                    FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1,
                    FactBundleV1.Type.RESOLUTION_REPLY_PACKET_V1 -> true
                    else -> false
                }
            } == true

        val hasDetourFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.PROOF_CHALLENGE_PACKET_V1,
                    FactBundleV1.Type.TARGET_CELL_QUERY_PACKET_V1,
                    FactBundleV1.Type.NEIGHBOR_CELL_QUERY_PACKET_V1,
                    FactBundleV1.Type.USER_REASONING_CHECK_PACKET_V1,
                    FactBundleV1.Type.ALTERNATIVE_TECHNIQUE_PACKET_V1,
                    FactBundleV1.Type.SOLVER_REASONING_CHECK_PACKET_V1,
                    FactBundleV1.Type.SOLVER_ALTERNATIVE_TECHNIQUE_PACKET_V1,
                    FactBundleV1.Type.SOLVER_LOCAL_MOVE_SEARCH_PACKET_V1,
                    FactBundleV1.Type.SOLVER_ROUTE_COMPARISON_PACKET_V1,
                    FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1,
                    FactBundleV1.Type.SOLVER_TECHNIQUE_SCOPE_CHECK_PACKET_V1,
                    FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1,
                    FactBundleV1.Type.SOLVER_CELLS_CANDIDATES_PACKET_V1,
                    FactBundleV1.Type.SOLVER_HOUSE_CANDIDATE_MAP_PACKET_V1,
                    FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1 -> true
                    else -> false
                }
            } == true

        val hasValidationFacts =
            decision?.factBundles?.any {
                when (it.type) {
                    FactBundleV1.Type.STRUCTURAL_VALIDITY,
                    FactBundleV1.Type.CONFLICT_SET,
                    FactBundleV1.Type.DUPLICATES_BY_HOUSE,
                    FactBundleV1.Type.UNRESOLVED_SET,
                    FactBundleV1.Type.MISMATCH_SET,
                    FactBundleV1.Type.OCR_CONFIDENCE_CELL,
                    FactBundleV1.Type.OCR_CONFIDENCE_SUMMARY,
                    FactBundleV1.Type.SEAL_STATUS,
                    FactBundleV1.Type.RECENT_MUTATION_RESULT -> true
                    else -> false
                }
            } == true

        val hasResolutionReplyPacket =
            decision?.factBundles?.any { it.type == FactBundleV1.Type.RESOLUTION_REPLY_PACKET_V1 } == true

        val hasConfrontationReplyPacket =
            decision?.factBundles?.any { it.type == FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1 } == true

        val hasSetupReplyPacket =
            decision?.factBundles?.any { it.type == FactBundleV1.Type.SETUP_REPLY_PACKET_V1 } == true

        val packetSolvingCategory: ReplyDemandCategoryV1? =
            if (usesAppRouteDemandFamily || usesRouteJumpDemandFamily) {
                when {
                    hasResolutionReplyPacket -> ReplyDemandCategoryV1.SOLVING_RESOLUTION
                    hasConfrontationReplyPacket -> ReplyDemandCategoryV1.SOLVING_CONFRONTATION
                    hasSetupReplyPacket -> ReplyDemandCategoryV1.SOLVING_SETUP
                    else -> null
                }
            } else {
                null
            }

        val canonicalSolvingCategory: ReplyDemandCategoryV1? =
            if (isAuthorityAppRouteOwner) {
                when (canonicalPosition?.kind) {
                    CanonicalSolvingPositionKindV1.SETUP ->
                        ReplyDemandCategoryV1.SOLVING_SETUP

                    CanonicalSolvingPositionKindV1.CONFRONTATION ->
                        ReplyDemandCategoryV1.SOLVING_CONFRONTATION

                    CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                    CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT ->
                        ReplyDemandCategoryV1.SOLVING_RESOLUTION

                    null -> null
                }
            } else {
                null
            }

        val solvingPacketMismatch =
            packetSolvingCategory != null &&
                    canonicalSolvingCategory != null &&
                    packetSolvingCategory != canonicalSolvingCategory

        return ReplyDemandSignalsV1(
            routingPhase = routingPhase,
            pendingAfter = pendingAfter,
            pendingKind = pendingKind,
            solvingHead = solvingHead,
            solvingRail = solvingRail,
            canonicalPosition = canonicalPosition,
            canonicalIssues = canonicalIssues,
            canonicalLegal = canonicalLegal,
            authoritativeStoryStage = authoritativeStoryStage,
            storyStage = storyStage,
            setupProfile = setupProfile,
            confrontationProofProfile = confrontationProofProfile,
            resolutionProfile = resolutionProfile,
            userAgendaHead = userAgendaHead,
            appAgendaHead = appAgendaHead,
            authorityOwner = authorityOwner,
            isAuthorityAppRouteOwner = isAuthorityAppRouteOwner,
            isAuthorityUserDetourOwner = isAuthorityUserDetourOwner,
            isAuthorityUserRouteJumpOwner = isAuthorityUserRouteJumpOwner,
            isAuthorityRepairOwner = isAuthorityRepairOwner,
            routeBoundaryStatus = routeBoundaryStatus,
            isBoundaryReleasedToNextStep = isBoundaryReleasedToNextStep,
            isBoundaryBlockedByRepair = isBoundaryBlockedByRepair,
            usesAppRouteDemandFamily = usesAppRouteDemandFamily,
            usesRouteJumpDemandFamily = usesRouteJumpDemandFamily,
            usesDetourDemandFamily = usesDetourDemandFamily,
            solvingSupportSubtype = solvingSupportSubtype,
            detourSubtype = detourSubtype,
            hasCandidateFacts = hasCandidateFacts,
            hasOcrTrustFacts = hasOcrTrustFacts,
            hasContentsFacts = hasContentsFacts,
            hasChangelogFacts = hasChangelogFacts,
            hasMutationFacts = hasMutationFacts,
            hasSolvingSupportFacts = hasSolvingSupportFacts,
            hasDetourFacts = hasDetourFacts,
            hasValidationFacts = hasValidationFacts,
            hasResolutionReplyPacket = hasResolutionReplyPacket,
            hasConfrontationReplyPacket = hasConfrontationReplyPacket,
            hasSetupReplyPacket = hasSetupReplyPacket,
            packetSolvingCategory = packetSolvingCategory,
            canonicalSolvingCategory = canonicalSolvingCategory,
            solvingPacketMismatch = solvingPacketMismatch
        )
    }

    private fun IntentEnvelopeV1?.hasIntentTypeV1(vararg types: IntentTypeV1): Boolean {
        val allowed = types.toSet()
        return this?.intents?.any { it.type in allowed } == true
    }

    private fun IntentEnvelopeV1?.hasOnlyIntentTypeV1(type: IntentTypeV1): Boolean =
        this?.intents?.isNotEmpty() == true && this.intents.all { it.type == type }

    private fun hasConversationContextFactsForFreeTalkV1(signals: ReplyDemandSignalsV1): Boolean =
        signals.hasValidationFacts ||
                signals.hasCandidateFacts ||
                signals.hasOcrTrustFacts ||
                signals.hasContentsFacts ||
                signals.hasChangelogFacts ||
                signals.hasSolvingSupportFacts ||
                signals.hasDetourFacts

    private fun isStructuredPreferenceChangeTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.REQUEST_FAST_MODE,
            IntentTypeV1.REQUEST_TEACH_MODE,
            IntentTypeV1.SET_ONE_QUESTION_MAX,
            IntentTypeV1.SET_EVIDENCE_VERBOSITY,
            IntentTypeV1.SET_NOTATION_STYLE,
            IntentTypeV1.SET_DIGIT_STYLE
        )

    private fun isStructuredModeChangeTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(IntentTypeV1.REQUEST_MODE_CHANGE)

    private fun isStructuredPauseResumeTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.PAUSE_ASSISTANT,
            IntentTypeV1.RESUME_ASSISTANT
        )

    private fun isStructuredValidateOnlyOrSolveOnlyTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.REQUEST_ONLY_VALIDATE,
            IntentTypeV1.REQUEST_ONLY_SOLVE
        )

    private fun isStructuredFocusRedirectTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.REQUEST_FOCUS_ON_ISSUE_TYPE,
            IntentTypeV1.REQUEST_FOCUS_ON_AREA,
            IntentTypeV1.REQUEST_FOCUS_CHANGE,
            IntentTypeV1.SWITCH_FOCUS_CELL,
            IntentTypeV1.SWITCH_FOCUS_REGION
        )

    private fun isStructuredHintPolicyChangeTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(IntentTypeV1.REQUEST_HINT_LEVEL)

    private fun isStructuredMetaStateTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.META_APP_QUESTION,
            IntentTypeV1.ASK_WHAT_YOU_KNOW_NOW,
            IntentTypeV1.ASK_WHAT_YOU_DONT_KNOW,
            IntentTypeV1.REQUEST_SUMMARY_DASHBOARD,
            IntentTypeV1.REQUEST_EXPORT_STATE
        )

    private fun isStructuredCapabilityTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(IntentTypeV1.CAPABILITY_CHECK)

    private fun isStructuredGlossaryTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(IntentTypeV1.ASK_WHAT_DO_YOU_MEAN_BY_HOUSE)

    private fun isStructuredUiHelpTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.ASK_UI_HELP,
            IntentTypeV1.ASK_UI_LEGEND
        )

    private fun isStructuredCoordinateHelpTurnV1(envelope: IntentEnvelopeV1?): Boolean =
        envelope.hasIntentTypeV1(
            IntentTypeV1.ASK_COORDINATES_HELP,
            IntentTypeV1.ASK_HOW_TO_LOCATE_CELL,
            IntentTypeV1.ASK_BOX_INDEX_MAPPING,
            IntentTypeV1.ASK_COORDINATE_TRANSLATION
        )

    private fun isStructuredSmallTalkBridgeTurnV1(
        envelope: IntentEnvelopeV1?,
        signals: ReplyDemandSignalsV1
    ): Boolean =
        envelope.hasOnlyIntentTypeV1(IntentTypeV1.FREE_TALK) &&
                hasConversationContextFactsForFreeTalkV1(signals)

    private fun isStructuredFreeTalkNonGridTurnV1(
        envelope: IntentEnvelopeV1?,
        signals: ReplyDemandSignalsV1
    ): Boolean =
        envelope.hasOnlyIntentTypeV1(IntentTypeV1.FREE_TALK) &&
                !hasConversationContextFactsForFreeTalkV1(signals)

    private fun hasMaterializedClarificationPendingV1(
        pendingAfter: Pending?
    ): Boolean {
        val ask = pendingAfter as? Pending.AskClarification ?: return false
        return ask.prompt.isNotBlank()
    }

    private fun resolveReplyDemandCategoryForConfirmingPhaseV1(
        sAfter: SudoState,
        decision: DecisionOutcomeV1?,
        signals: ReplyDemandSignalsV1,
        pendingSubtype: ReplyDemandCategoryV1?,
        isPendingClarification: Boolean,
        isConfirmFinalizeGate: Boolean,
        isConfirmRetakeGate: Boolean,
        isConfirmMismatchGate: Boolean,
        isConfirmConflictGate: Boolean,
        isConfirmNotUniqueGate: Boolean,
        isConfirmExactMatchGate: Boolean,
        isConfirmStatusSummary: Boolean,
        isPauseResumeTurn: Boolean,
        isValidateOnlyOrSolveOnlyTurn: Boolean,
        isFocusRedirectTurn: Boolean,
        isHintPolicyChangeTurn: Boolean,
        isModeChangeTurn: Boolean,
        isPreferenceChangeTurn: Boolean,
        isMetaStateTurn: Boolean,
        isCapabilityTurn: Boolean,
        isGlossaryTurn: Boolean,
        isUiHelpTurn: Boolean,
        isCoordinateHelpTurn: Boolean,
        isSmallTalkBridgeTurn: Boolean,
        isFreeTalkNonGridTurn: Boolean,
        openingTurn: Boolean
    ): ReplyDemandResolutionV1? {
        val phase = signals.routingPhase
        if (sAfter.mode != SudoMode.GRID_SESSION) return null
        if (phase != GridPhase.CONFIRMING && phase != GridPhase.SEALING) return null

        val phaseName = phase.name
        val pendingKind = signals.pendingKind
        val storyStage = signals.storyStage

        if (openingTurn) {
            return ReplyDemandResolutionV1(
                category = ReplyDemandCategoryV1.ONBOARDING_OPENING,
                reason = "opening_turn_after_grid_capture",
                phase = phaseName,
                pendingKind = pendingKind,
                storyStage = storyStage,
                openingTurn = true
            )
        }

        return when {
            isPendingClarification ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.PENDING_CLARIFICATION,
                    reason = "confirming_phase_bounded_clarification_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            pendingSubtype != null ->
                ReplyDemandResolutionV1(
                    category = pendingSubtype,
                    reason = "confirming_phase_bounded_pending_transactional_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmFinalizeGate ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_FINALIZE_GATE,
                    reason = "confirming_phase_finalize_gate",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmRetakeGate ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_RETAKE_GATE,
                    reason = "confirming_phase_retake_gate",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmMismatchGate ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_MISMATCH_GATE,
                    reason = "confirming_phase_mismatch_gate",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmConflictGate ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_CONFLICT_GATE,
                    reason = "confirming_phase_conflict_gate",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmNotUniqueGate ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_NOT_UNIQUE_GATE,
                    reason = "confirming_phase_not_unique_gate",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmExactMatchGate ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_EXACT_MATCH_GATE,
                    reason = "confirming_phase_exact_match_gate",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isConfirmStatusSummary ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CONFIRM_STATUS_SUMMARY,
                    reason = "confirming_phase_status_summary",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isPauseResumeTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.ASSISTANT_PAUSE_RESUME,
                    reason = "confirming_phase_pause_or_resume_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isValidateOnlyOrSolveOnlyTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.VALIDATE_ONLY_OR_SOLVE_ONLY,
                    reason = "confirming_phase_validate_only_or_solve_only_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isFocusRedirectTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.FOCUS_REDIRECT,
                    reason = "confirming_phase_focus_redirect_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isHintPolicyChangeTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.HINT_POLICY_CHANGE,
                    reason = "confirming_phase_hint_policy_change_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isModeChangeTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.MODE_CHANGE,
                    reason = "confirming_phase_mode_change_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isPreferenceChangeTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.PREFERENCE_CHANGE,
                    reason = "confirming_phase_preference_change_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isMetaStateTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.META_STATE_ANSWER,
                    reason = "confirming_phase_meta_state_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isCapabilityTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.CAPABILITY_ANSWER,
                    reason = "confirming_phase_capability_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isGlossaryTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.GLOSSARY_ANSWER,
                    reason = "confirming_phase_glossary_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isUiHelpTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.UI_HELP_ANSWER,
                    reason = "confirming_phase_ui_help_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isCoordinateHelpTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.COORDINATE_HELP_ANSWER,
                    reason = "confirming_phase_coordinate_help_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isSmallTalkBridgeTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.SMALL_TALK_BRIDGE,
                    reason = "confirming_phase_small_talk_bridge_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            isFreeTalkNonGridTurn ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.FREE_TALK_NON_GRID,
                    reason = "confirming_phase_non_grid_free_talk_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            signals.hasCandidateFacts ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.GRID_CANDIDATE_ANSWER,
                    reason = "confirming_phase_candidate_question_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            signals.hasOcrTrustFacts ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.GRID_OCR_TRUST_ANSWER,
                    reason = "confirming_phase_ocr_trust_question_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            signals.hasContentsFacts ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.GRID_CONTENTS_ANSWER,
                    reason = "confirming_phase_contents_question_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            signals.hasChangelogFacts &&
                    decision?.decisionKind == DecisionKindV1.ANSWERED_GRID_QUESTION ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.GRID_CHANGELOG_ANSWER,
                    reason = "confirming_phase_changelog_question_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            decision?.decisionKind == DecisionKindV1.ANSWERED_GRID_QUESTION || signals.hasValidationFacts ->
                ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.GRID_VALIDATION_ANSWER,
                    reason = "confirming_phase_validation_or_inspection_question_turn",
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )

            else ->
                ReplyDemandResolutionV1(
                    category = when {
                        isSmallTalkBridgeTurn -> ReplyDemandCategoryV1.SMALL_TALK_BRIDGE
                        isFreeTalkNonGridTurn -> ReplyDemandCategoryV1.FREE_TALK_NON_GRID
                        else -> ReplyDemandCategoryV1.META_STATE_ANSWER
                    },
                    reason = when {
                        isSmallTalkBridgeTurn -> "confirming_phase_residual_small_talk_bridge_bucket"
                        isFreeTalkNonGridTurn -> "confirming_phase_residual_non_grid_free_talk_bucket"
                        else -> "confirming_phase_residual_meta_state_bucket"
                    },
                    phase = phaseName,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )
        }
    }

    private fun resolveReplyDemandCategoryForConfirmingPhaseEntryV1(
        sBefore: SudoState,
        sAfter: SudoState,
        userText: String,
        openingTurn: Boolean,
        decision: DecisionOutcomeV1? = null,
        envelope: IntentEnvelopeV1? = null
    ): ReplyDemandResolutionV1 {
        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "CONFIRMING_PHASE_DEMAND_RESOLVER_ENTRY_V1",
                data = mapOf(
                    "turn_id" to sAfter.turnSeq,
                    "phase" to demandRoutingPhaseV1(sAfter).name,
                    "opening_turn" to openingTurn,
                    "decision_kind" to (decision?.decisionKind?.name ?: "null")
                )
            )
        }

        val signals = buildReplyDemandSignalsV1(
            sAfter = sAfter,
            decision = decision
        )

        val pendingAfter = signals.pendingAfter
        val pendingKind = signals.pendingKind
        val storyStage = signals.storyStage
        val userAgendaHead = signals.userAgendaHead
        val appAgendaHead = signals.appAgendaHead

        val isPreferenceChangeTurn =
            isStructuredPreferenceChangeTurnV1(envelope)

        val isModeChangeTurn =
            isStructuredModeChangeTurnV1(envelope)

        val isPauseResumeTurn =
            isStructuredPauseResumeTurnV1(envelope)

        val isValidateOnlyOrSolveOnlyTurn =
            isStructuredValidateOnlyOrSolveOnlyTurnV1(envelope)

        val isFocusRedirectTurn =
            isStructuredFocusRedirectTurnV1(envelope)

        val isHintPolicyChangeTurn =
            isStructuredHintPolicyChangeTurnV1(envelope)

        val isMetaStateTurn =
            isStructuredMetaStateTurnV1(envelope)

        val isCapabilityTurn =
            isStructuredCapabilityTurnV1(envelope)

        val isGlossaryTurn =
            isStructuredGlossaryTurnV1(envelope)

        val isUiHelpTurn =
            isStructuredUiHelpTurnV1(envelope)

        val isCoordinateHelpTurn =
            isStructuredCoordinateHelpTurnV1(envelope)

        val isSmallTalkBridgeTurn =
            isStructuredSmallTalkBridgeTurnV1(envelope, signals)

        val isFreeTalkNonGridTurn =
            isStructuredFreeTalkNonGridTurnV1(envelope, signals)

        val isPendingClarification =
            ClarificationKernelV1.isClarificationSovereign(
                pendingAfter = pendingAfter,
                userAgendaHead = userAgendaHead,
                decisionAskedClarification = decision?.decisionKind == DecisionKindV1.ASKED_CLARIFICATION,
                decisionNeedsClarification = decision?.needsClarification == true
            )

        val isConfirmFinalizeGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    (pendingAfter is Pending.ConfirmStartSolving ||
                            appAgendaHead is AppAgendaItem.FinalizeValidationStartSolving)

        val isConfirmRetakeGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    (pendingAfter is Pending.ConfirmRetake ||
                            appAgendaHead is AppAgendaItem.RetakeDecision ||
                            appAgendaHead is AppAgendaItem.ProposeRetake)

        val isConfirmMismatchGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    (
                            appAgendaHead is AppAgendaItem.MismatchReview ||
                                    appAgendaHead is AppAgendaItem.ProposeEdit ||
                                    pendingAfter is Pending.ConfirmEdit
                            )

        val isConfirmConflictGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    (
                            appAgendaHead is AppAgendaItem.ConflictReview ||
                                    appAgendaHead is AppAgendaItem.AskConfirmCell ||
                                    pendingAfter is Pending.AskCellValue
                            )

        val isConfirmNotUniqueGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    !isConfirmConflictGate &&
                    (
                            pendingAfter is Pending.ConfirmValidate ||
                                    appAgendaHead is AppAgendaItem.ConfirmValidationExactMatch
                            ) &&
                    decision?.factBundles?.any { it.type == FactBundleV1.Type.SEAL_STATUS } == true &&
                    decision.factBundles.any {
                        val payload = it.payload
                        payload.optBoolean("has_multiple_solutions", false) ||
                                payload.optString("uniqueness", "").equals("NOT_UNIQUE", ignoreCase = true)
                    }

        val isConfirmExactMatchGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    !isConfirmConflictGate &&
                    !isConfirmNotUniqueGate &&
                    (
                            pendingAfter is Pending.ConfirmValidate ||
                                    pendingAfter is Pending.VisualVerifyMatch ||
                                    appAgendaHead is AppAgendaItem.ConfirmValidationExactMatch ||
                                    appAgendaHead is AppAgendaItem.VisualVerificationRequest
                            )

        val isConfirmStatusSummary =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    !isConfirmConflictGate &&
                    !isConfirmNotUniqueGate &&
                    !isConfirmExactMatchGate &&
                    (
                            decision?.decisionKind == DecisionKindV1.REQUESTED_SEAL ||
                                    userText.isNotBlank()
                            )

        val pendingSubtype: ReplyDemandCategoryV1? = when {
            pendingAfter is Pending.ConfirmValidate ||
                    pendingAfter is Pending.ConfirmStartSolving ||
                    pendingAfter is Pending.ConfirmRetake ||
                    pendingAfter is Pending.ConfirmEdit ||
                    pendingAfter is Pending.AskCellValue ->
                ReplyDemandCategoryV1.CONFIRMING_VALIDATION_SUMMARY

            else -> null
        }

        return resolveReplyDemandCategoryForConfirmingPhaseV1(
            sAfter = sAfter,
            decision = decision,
            signals = signals,
            pendingSubtype = pendingSubtype,
            isPendingClarification = isPendingClarification,
            isConfirmFinalizeGate = isConfirmFinalizeGate,
            isConfirmRetakeGate = isConfirmRetakeGate,
            isConfirmMismatchGate = isConfirmMismatchGate,
            isConfirmConflictGate = isConfirmConflictGate,
            isConfirmNotUniqueGate = isConfirmNotUniqueGate,
            isConfirmExactMatchGate = isConfirmExactMatchGate,
            isConfirmStatusSummary = isConfirmStatusSummary,
            isPauseResumeTurn = isPauseResumeTurn,
            isValidateOnlyOrSolveOnlyTurn = isValidateOnlyOrSolveOnlyTurn,
            isFocusRedirectTurn = isFocusRedirectTurn,
            isHintPolicyChangeTurn = isHintPolicyChangeTurn,
            isModeChangeTurn = isModeChangeTurn,
            isPreferenceChangeTurn = isPreferenceChangeTurn,
            isMetaStateTurn = isMetaStateTurn,
            isCapabilityTurn = isCapabilityTurn,
            isGlossaryTurn = isGlossaryTurn,
            isUiHelpTurn = isUiHelpTurn,
            isCoordinateHelpTurn = isCoordinateHelpTurn,
            isSmallTalkBridgeTurn = isSmallTalkBridgeTurn,
            isFreeTalkNonGridTurn = isFreeTalkNonGridTurn,
            openingTurn = openingTurn
        ) ?: ReplyDemandResolutionV1(
            category = ReplyDemandCategoryV1.META_STATE_ANSWER,
            reason = "confirming_phase_entry_unexpected_null_resolution",
            phase = demandRoutingPhaseV1(sAfter).name,
            pendingKind = signals.pendingKind,
            storyStage = signals.storyStage,
            openingTurn = openingTurn
        )
    }

    private fun resolveReplyDemandCategoryV1(
        sBefore: SudoState,
        sAfter: SudoState,
        userText: String,
        openingTurn: Boolean,
        decision: DecisionOutcomeV1? = null,
        envelope: IntentEnvelopeV1? = null
    ): ReplyDemandResolutionV1 {
        val routingPhase = demandRoutingPhaseV1(sAfter)

        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "PHASE_SCOPED_DEMAND_RESOLVER_DISPATCH_V1",
                data = mapOf(
                    "turn_id" to sAfter.turnSeq,
                    "phase" to routingPhase.name,
                    "target_resolver" to when (routingPhase) {
                        GridPhase.CONFIRMING, GridPhase.SEALING -> "confirming_phase_entry"
                        GridPhase.SOLVING -> "solving_phase_resolver"
                    }
                )
            )
        }

        return when (routingPhase) {
            GridPhase.CONFIRMING,
            GridPhase.SEALING ->
                resolveReplyDemandCategoryForConfirmingPhaseEntryV1(
                    sBefore = sBefore,
                    sAfter = sAfter,
                    userText = userText,
                    openingTurn = openingTurn,
                    decision = decision
                )

            GridPhase.SOLVING ->
                resolveReplyDemandCategoryForSolvingPhaseV1(
                    sBefore = sBefore,
                    sAfter = sAfter,
                    userText = userText,
                    openingTurn = openingTurn,
                    decision = decision,
                    envelope = envelope
                )
        }
    }

    private fun resolveReplyDemandCategoryForSolvingPhaseV1(
        sBefore: SudoState,
        sAfter: SudoState,
        userText: String,
        openingTurn: Boolean,
        decision: DecisionOutcomeV1? = null,
        envelope: IntentEnvelopeV1? = null
    ): ReplyDemandResolutionV1 {
        val routingPhase = demandRoutingPhaseV1(sAfter)

        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "SOLVING_PHASE_DEMAND_RESOLVER_ENTERED_V1",
                data = mapOf(
                    "turn_id" to sAfter.turnSeq,
                    "phase" to routingPhase.name,
                    "opening_turn" to openingTurn,
                    "decision_kind" to (decision?.decisionKind?.name ?: "null"),
                    "resolver_contract" to "solving_phase_only"
                )
            )
        }

        runCatching {
            ConversationTelemetry.emit(
                mapOf(
                    "type" to "DEMAND_ROUTING_PHASE_V1",
                    "turn_id" to sAfter.turnSeq,
                    "phase" to sAfter.phase.name,
                    "routing_phase" to routingPhase.name,
                    "opening_turn" to openingTurn,
                    "decision_kind" to (decision?.decisionKind?.name ?: "null"),
                    "user_agenda_head" to (sAfter.userAgendaQueue.firstOrNull()?.javaClass?.simpleName ?: "null"),
                    "app_agenda_head" to (sAfter.appAgendaQueue.firstOrNull()?.javaClass?.simpleName ?: "null"),
                    "pending_after" to pendingSummary(normalizePendingForReplyRoutingV1(sAfter.pending))
                )
            )
        }

        val signals = buildReplyDemandSignalsV1(
            sAfter = sAfter,
            decision = decision
        )

        val pendingAfter = signals.pendingAfter
        val pendingKind = signals.pendingKind
        val solvingHead = signals.solvingHead
        val solvingRail = signals.solvingRail
        val canonicalPosition = signals.canonicalPosition
        val canonicalIssues = signals.canonicalIssues
        val canonicalLegal = signals.canonicalLegal

        if (sAfter.mode == SudoMode.GRID_SESSION && sAfter.phase == GridPhase.SOLVING) {
            ConversationTelemetry.emit(
                mapOf(
                    "type" to "SOLVING_CANONICAL_STATE",
                    "turn_id" to sAfter.turnSeq,
                    "phase" to sAfter.phase.name,
                    "authority_owner" to sAfter.activeTurnAuthorityDecisionV1.owner.name,
                    "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                    "canonical_stage" to (canonicalPosition?.stage?.name ?: "null"),
                    "head_kind" to (canonicalPosition?.headKind?.name ?: "null"),
                    "pending_kind" to (canonicalPosition?.pendingKind?.name ?: "null"),
                    "canonical_legal" to canonicalLegal,
                    "issues" to canonicalIssues.joinToString(",")
                )
            )
        }

        if (canonicalIssues.isNotEmpty()) {
            ConversationTelemetry.emit(
                mapOf(
                    "type" to "SOLVING_POSITION_VIOLATION",
                    "turn_id" to sAfter.turnSeq,
                    "phase" to sAfter.phase.name,
                    "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                    "canonical_stage" to (canonicalPosition?.stage?.name ?: "null"),
                    "head_kind" to (canonicalPosition?.headKind?.name ?: "null"),
                    "pending_kind" to (canonicalPosition?.pendingKind?.name ?: "null"),
                    "issues" to canonicalIssues.joinToString(",")
                )
            )
        }

        val authoritativeStoryStage = signals.authoritativeStoryStage
        val storyStage = signals.storyStage

        val setupProfile = signals.setupProfile
        val confrontationProofProfile = signals.confrontationProofProfile
        val resolutionProfile = signals.resolutionProfile

        val userAgendaHead = signals.userAgendaHead
        val appAgendaHead = signals.appAgendaHead

        val authorityOwner = signals.authorityOwner
        val isAuthorityAppRouteOwner = signals.isAuthorityAppRouteOwner
        val isAuthorityUserDetourOwner = signals.isAuthorityUserDetourOwner
        val isAuthorityUserRouteJumpOwner = signals.isAuthorityUserRouteJumpOwner
        val isAuthorityRepairOwner = signals.isAuthorityRepairOwner

        val routeBoundaryStatus = signals.routeBoundaryStatus
        val isBoundaryReleasedToNextStep = signals.isBoundaryReleasedToNextStep
        val isBoundaryBlockedByRepair = signals.isBoundaryBlockedByRepair

        val usesAppRouteDemandFamily = signals.usesAppRouteDemandFamily
        val usesRouteJumpDemandFamily = signals.usesRouteJumpDemandFamily
        val usesDetourDemandFamily = signals.usesDetourDemandFamily

        emitConstitutionInvariantTelemetryV1(
            s = sAfter,
            invariant = "DET0UR_OWNER_MUST_NOT_USE_APP_ROUTE_DEMAND_FAMILY",
            ok = !(isAuthorityUserDetourOwner && usesAppRouteDemandFamily),
            detail = "detourOwner=$isAuthorityUserDetourOwner appRouteDemandFamily=$usesAppRouteDemandFamily"
        )

        emitConstitutionInvariantTelemetryV1(
            s = sAfter,
            invariant = "ROUTE_JUMP_OWNER_SHOULD_NOT_CARRY_RETURN_TO_ROUTE_WHEN_BOUNDARY_RELEASED",
            ok = !(isAuthorityUserRouteJumpOwner &&
                    isBoundaryReleasedToNextStep &&
                    sAfter.activeTurnAuthorityDecisionV1.routeReturnAllowed),
            detail = "routeJumpOwner=$isAuthorityUserRouteJumpOwner boundaryReleased=$isBoundaryReleasedToNextStep routeReturnAllowed=${sAfter.activeTurnAuthorityDecisionV1.routeReturnAllowed}"
        )

        emitConstitutionInvariantTelemetryV1(
            s = sAfter,
            invariant = "REPAIR_BLOCK_MUST_PREVENT_ADVANCE",
            ok = !(isAuthorityRepairOwner && sAfter.activeRouteBoundaryDecisionV1.advanceAllowed),
            detail = "repairOwner=$isAuthorityRepairOwner boundaryAdvanceAllowed=${sAfter.activeRouteBoundaryDecisionV1.advanceAllowed}"
        )

        val solvingSupportSubtype = signals.solvingSupportSubtype
        val detourSubtype = signals.detourSubtype

        val hasCandidateFacts = signals.hasCandidateFacts
        val hasOcrTrustFacts = signals.hasOcrTrustFacts
        val hasContentsFacts = signals.hasContentsFacts
        val hasChangelogFacts = signals.hasChangelogFacts
        val hasMutationFacts = signals.hasMutationFacts
        val hasSolvingSupportFacts = signals.hasSolvingSupportFacts
        val hasDetourFacts = signals.hasDetourFacts
        val hasValidationFacts = signals.hasValidationFacts

        val hasResolutionReplyPacket = signals.hasResolutionReplyPacket
        val hasConfrontationReplyPacket = signals.hasConfrontationReplyPacket
        val hasSetupReplyPacket = signals.hasSetupReplyPacket

        val packetSolvingCategory = signals.packetSolvingCategory
        val canonicalSolvingCategory = signals.canonicalSolvingCategory
        val solvingPacketMismatch = signals.solvingPacketMismatch

        val solvingSupportPacketCategory: ReplyDemandCategoryV1? = when {
            isAuthorityUserRouteJumpOwner &&
                    decision?.factBundles?.any { it.type == FactBundleV1.Type.RETURN_TO_ROUTE_PACKET_V1 } == true ->
                ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL

            isAuthorityUserRouteJumpOwner &&
                    decision?.factBundles?.any { it.type == FactBundleV1.Type.STEP_CLARIFICATION_PACKET_V1 } == true ->
                ReplyDemandCategoryV1.SOLVING_STAGE_ELABORATION

            else -> null
        }

        if (!usesAppRouteDemandFamily && canonicalSolvingCategory != null) {
            emitAuthorityConflictTelemetryV1(
                s = sAfter,
                domain = "reply_demand",
                winner = authorityOwner.name,
                suppressed = canonicalSolvingCategory.name,
                reason = "owner_first_demand_suppressed_canonical_solving_category",
                extra = mapOf(
                    "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                    "canonical_stage" to (canonicalPosition?.stage?.name ?: "null")
                )
            )
        }

        if (!usesRouteJumpDemandFamily && solvingSupportPacketCategory != null) {
            emitAuthorityConflictTelemetryV1(
                s = sAfter,
                domain = "reply_demand",
                winner = authorityOwner.name,
                suppressed = solvingSupportPacketCategory.name,
                reason = "owner_first_demand_suppressed_support_packet_category",
                extra = mapOf(
                    "pending_kind" to pendingKind,
                    "user_agenda_head" to (userAgendaHead?.javaClass?.simpleName ?: "null")
                )
            )
        }

        if (isBoundaryReleasedToNextStep && isAuthorityUserRouteJumpOwner) {
            emitAuthorityConflictTelemetryV1(
                s = sAfter,
                domain = "reply_demand",
                winner = "BOUNDARY_RELEASED_TO_NEXT_STEP",
                suppressed = "USER_ROUTE_JUMP_OWNER",
                reason = "boundary_release_overrides_route_jump_family",
                extra = mapOf(
                    "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                    "pending_kind" to pendingKind
                )
            )
        }

        val detourPacketCategory: ReplyDemandCategoryV1? = when {
            decision?.factBundles?.any { it.type == FactBundleV1.Type.SOLVER_ROUTE_COMPARISON_PACKET_V1 } == true ->
                ReplyDemandCategoryV1.DETOUR_ROUTE_COMPARISON

            decision?.factBundles?.any { it.type == FactBundleV1.Type.SOLVER_LOCAL_MOVE_SEARCH_PACKET_V1 } == true ->
                ReplyDemandCategoryV1.DETOUR_LOCAL_MOVE_SEARCH

            decision?.factBundles?.any {
                it.type == FactBundleV1.Type.ALTERNATIVE_TECHNIQUE_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_ALTERNATIVE_TECHNIQUE_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_TECHNIQUE_SCOPE_CHECK_PACKET_V1
            } == true ->
                ReplyDemandCategoryV1.DETOUR_ALTERNATIVE_TECHNIQUE

            decision?.factBundles?.any {
                it.type == FactBundleV1.Type.USER_REASONING_CHECK_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_REASONING_CHECK_PACKET_V1
            } == true ->
                ReplyDemandCategoryV1.DETOUR_REASONING_CHECK

            decision?.factBundles?.any { it.type == FactBundleV1.Type.NEIGHBOR_CELL_QUERY_PACKET_V1 } == true ->
                ReplyDemandCategoryV1.DETOUR_NEIGHBOR_CELL_QUERY

            decision?.factBundles?.any { it.type == FactBundleV1.Type.TARGET_CELL_QUERY_PACKET_V1 } == true ->
                ReplyDemandCategoryV1.DETOUR_TARGET_CELL_QUERY

            decision?.factBundles?.any {
                it.type == FactBundleV1.Type.PROOF_CHALLENGE_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_CELLS_CANDIDATES_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_HOUSE_CANDIDATE_MAP_PACKET_V1 ||
                        it.type == FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1
            } == true ->
                ReplyDemandCategoryV1.DETOUR_PROOF_CHALLENGE

            else -> null
        }

        fun solvingPhaseGridQuestionResolutionV1(
            reason: String,
            stage: StoryStage?
        ): ReplyDemandResolutionV1 {
            val category =
                when {
                    detourPacketCategory != null ->
                        detourPacketCategory

                    detourSubtype != null ->
                        detourSubtype

                    userAgendaHead is UserAgendaItem.CandidateStateQuery ->
                        ReplyDemandCategoryV1.DETOUR_NEIGHBOR_CELL_QUERY

                    userAgendaHead is UserAgendaItem.ProofChallenge ->
                        ReplyDemandCategoryV1.DETOUR_PROOF_CHALLENGE

                    userAgendaHead is UserAgendaItem.TargetCellQuery ->
                        ReplyDemandCategoryV1.DETOUR_TARGET_CELL_QUERY

                    userAgendaHead is UserAgendaItem.NeighborCellQuery ->
                        ReplyDemandCategoryV1.DETOUR_NEIGHBOR_CELL_QUERY

                    userAgendaHead is UserAgendaItem.UserReasoningCheck ->
                        ReplyDemandCategoryV1.DETOUR_REASONING_CHECK

                    userAgendaHead is UserAgendaItem.AlternativeTechniqueQuery ->
                        ReplyDemandCategoryV1.DETOUR_ALTERNATIVE_TECHNIQUE

                    userAgendaHead is UserAgendaItem.RouteComparisonQuery ->
                        ReplyDemandCategoryV1.DETOUR_ROUTE_COMPARISON

                    isAuthorityRepairOwner ->
                        ReplyDemandCategoryV1.REPAIR_CONTRADICTION

                    else ->
                        when (stage ?: authoritativeStoryStage ?: StoryStage.CONFRONTATION) {
                            StoryStage.SETUP -> ReplyDemandCategoryV1.SOLVING_SETUP
                            StoryStage.CONFRONTATION -> ReplyDemandCategoryV1.SOLVING_CONFRONTATION
                            StoryStage.RESOLUTION -> ReplyDemandCategoryV1.SOLVING_RESOLUTION
                        }
                }

            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "SOLVING_PHASE_GRID_QUESTION_REMAPPED_V1",
                    data = mapOf(
                        "turn_id" to sAfter.turnSeq,
                        "phase" to sAfter.phase.name,
                        "reason" to reason,
                        "resolved_category" to category.name,
                        "user_agenda_head" to (userAgendaHead?.javaClass?.simpleName ?: "null"),
                        "detour_subtype" to (detourSubtype?.name ?: "null"),
                        "detour_packet_category" to (detourPacketCategory?.name ?: "null"),
                        "authoritative_story_stage" to (stage?.name ?: authoritativeStoryStage?.name ?: "null")
                    )
                )
            }

            return ReplyDemandResolutionV1(
                category = category,
                reason = reason,
                phase = sAfter.phase.name,
                pendingKind = pendingKind,
                storyStage = (stage ?: authoritativeStoryStage)?.name ?: storyStage,
                openingTurn = false
            )
        }

        val isPreferenceChangeTurn =
            isStructuredPreferenceChangeTurnV1(envelope)

        val isModeChangeTurn =
            isStructuredModeChangeTurnV1(envelope)

        val isPauseResumeTurn =
            isStructuredPauseResumeTurnV1(envelope)

        val isValidateOnlyOrSolveOnlyTurn =
            isStructuredValidateOnlyOrSolveOnlyTurnV1(envelope)

        val isFocusRedirectTurn =
            isStructuredFocusRedirectTurnV1(envelope)

        val isHintPolicyChangeTurn =
            isStructuredHintPolicyChangeTurnV1(envelope)

        val isMetaStateTurn =
            isStructuredMetaStateTurnV1(envelope)

        val isCapabilityTurn =
            isStructuredCapabilityTurnV1(envelope)

        val isGlossaryTurn =
            isStructuredGlossaryTurnV1(envelope)

        val isUiHelpTurn =
            isStructuredUiHelpTurnV1(envelope)

        val isCoordinateHelpTurn =
            isStructuredCoordinateHelpTurnV1(envelope)

        val isSmallTalkBridgeTurn =
            isStructuredSmallTalkBridgeTurnV1(envelope, signals)

        val isFreeTalkNonGridTurn =
            isStructuredFreeTalkNonGridTurnV1(envelope, signals)

        val isPendingClarification =
            ClarificationKernelV1.isClarificationSovereign(
                pendingAfter = pendingAfter,
                userAgendaHead = userAgendaHead,
                decisionAskedClarification = decision?.decisionKind == DecisionKindV1.ASKED_CLARIFICATION,
                decisionNeedsClarification = decision?.needsClarification == true
            )

        val isConfirmFinalizeGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    (pendingAfter is Pending.ConfirmStartSolving ||
                            appAgendaHead is AppAgendaItem.FinalizeValidationStartSolving)

        val isConfirmRetakeGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    (pendingAfter is Pending.ConfirmRetake ||
                            appAgendaHead is AppAgendaItem.RetakeDecision ||
                            appAgendaHead is AppAgendaItem.ProposeRetake)

        val isConfirmMismatchGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    (
                            appAgendaHead is AppAgendaItem.MismatchReview ||
                                    appAgendaHead is AppAgendaItem.ProposeEdit ||
                                    pendingAfter is Pending.ConfirmEdit
                            )

        val isConfirmConflictGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    (
                            appAgendaHead is AppAgendaItem.ConflictReview ||
                                    appAgendaHead is AppAgendaItem.AskConfirmCell ||
                                    pendingAfter is Pending.AskCellValue
                            )

        val isConfirmNotUniqueGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    !isConfirmConflictGate &&
                    (
                            appAgendaHead is AppAgendaItem.RecommendDifferentGrid
                            )

        val isConfirmExactMatchGate =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    !isConfirmConflictGate &&
                    !isConfirmNotUniqueGate &&
                    (pendingAfter is Pending.ConfirmValidate ||
                            pendingAfter is Pending.VisualVerifyMatch ||
                            appAgendaHead is AppAgendaItem.ConfirmValidationExactMatch ||
                            appAgendaHead is AppAgendaItem.VisualVerificationRequest)

        val pendingSubtype = when {
            pendingAfter is Pending.ConfirmCellAsIs -> ReplyDemandCategoryV1.PENDING_CELL_CONFIRM_AS_IS
            pendingAfter is Pending.ConfirmCellToDigit -> ReplyDemandCategoryV1.PENDING_CELL_CONFIRM_TO_DIGIT
            pendingAfter is Pending.ConfirmRegionAsIs -> ReplyDemandCategoryV1.PENDING_REGION_CONFIRM_AS_IS
            pendingAfter is Pending.ConfirmRegionToDigits -> ReplyDemandCategoryV1.PENDING_REGION_CONFIRM_TO_DIGITS
            pendingAfter is Pending.ProvideDigit -> ReplyDemandCategoryV1.PENDING_DIGIT_PROVIDE

            // Compatibility with older broader pending forms still present in the codebase
            pendingAfter is Pending.ConfirmEdit -> ReplyDemandCategoryV1.PENDING_CELL_CONFIRM_TO_DIGIT
            pendingAfter is Pending.AskCellValue -> ReplyDemandCategoryV1.PENDING_DIGIT_PROVIDE
            pendingAfter is Pending.ConfirmInterpretation -> ReplyDemandCategoryV1.PENDING_INTERPRETATION_CONFIRM

            else -> null
        }

        val isConfirmStatusSummary =
            sAfter.mode == SudoMode.GRID_SESSION &&
                    (sAfter.phase == GridPhase.CONFIRMING || sAfter.phase == GridPhase.SEALING) &&
                    !isPendingClarification &&
                    !isConfirmFinalizeGate &&
                    !isConfirmRetakeGate &&
                    !isConfirmMismatchGate &&
                    !isConfirmConflictGate &&
                    !isConfirmNotUniqueGate &&
                    !isConfirmExactMatchGate &&
                    (
                            decision?.decisionKind == DecisionKindV1.REQUESTED_SEAL ||
                                    userText.isNotBlank()
                            )

        if (openingTurn) {
            return ReplyDemandResolutionV1(
                category = ReplyDemandCategoryV1.ONBOARDING_OPENING,
                reason = "opening_turn_after_grid_capture",
                phase = routingPhase.name,
                pendingKind = pendingKind,
                storyStage = storyStage,
                openingTurn = true
            )
        }

        val repairSignal = envelope?.repairSignalCompat() ?: envelope?.repairSignal

        if (isRepairFenceSignalV1(repairSignal)) {
            return ReplyDemandResolutionV1(
                category = ReplyDemandCategoryV1.REPAIR_CONTRADICTION,
                reason = repairFenceReasonFromSignalV1(repairSignal),
                phase = routingPhase.name,
                pendingKind = pendingKind,
                storyStage = storyStage,
                openingTurn = false
            )
        }

        if (isPendingClarification) {
            return ReplyDemandResolutionV1(
                category = ReplyDemandCategoryV1.PENDING_CLARIFICATION,
                reason = ClarificationKernelV1.clarificationSovereigntyReason(
                    pendingAfter = pendingAfter,
                    userAgendaHead = userAgendaHead,
                    decisionAskedClarification = decision?.decisionKind == DecisionKindV1.ASKED_CLARIFICATION,
                    decisionNeedsClarification = decision?.needsClarification == true
                ),
                phase = sAfter.phase.name,
                pendingKind = pendingKind,
                storyStage = storyStage,
                openingTurn = false
            )
        }

        if (routingPhase != GridPhase.SOLVING) {
            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "SOLVING_PHASE_RESOLVER_CALLED_OUTSIDE_SOLVING_V1",
                    data = mapOf(
                        "turn_id" to sAfter.turnSeq,
                        "phase" to routingPhase.name,
                        "reason" to "solving_phase_resolver_should_only_be_used_in_solving"
                    )
                )
            }
        }

        if (
            (isAuthorityUserDetourOwner || isAuthorityUserRouteJumpOwner) &&
            pendingAfter is Pending.UserAgendaBridge
        ) {
            if (sAfter.mode == SudoMode.GRID_SESSION) {
                val userHead = sAfter.userAgendaQueue.firstOrNull()

                val bridgePhase: GridPhase =
                    userHead?.checkpointPhase
                        ?: sAfter.routeCheckpointV1?.phase
                        ?: sAfter.phase

                val bridgeStoryStage: StoryStage? =
                    canonicalPosition?.stage
                        ?: authoritativeStoryStage
                        ?: userHead?.checkpointStoryStage
                        ?: sAfter.routeCheckpointV1?.storyStage

                val postResolutionMismatch =
                    userHead is UserAgendaItem.TargetCellQuery &&
                            bridgePhase == GridPhase.SOLVING &&
                            bridgeStoryStage == StoryStage.RESOLUTION

                if (
                    isAuthorityUserRouteJumpOwner &&
                    bridgePhase == GridPhase.SOLVING &&
                    !postResolutionMismatch
                ) {
                    return when (bridgeStoryStage ?: StoryStage.CONFRONTATION) {
                        StoryStage.SETUP -> ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.SOLVING_SETUP,
                            reason = "route_jump_owner_reenters_paused_setup_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = StoryStage.SETUP.name,
                            openingTurn = false,
                            setupProfile = setupProfile
                        )

                        StoryStage.RESOLUTION -> ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.SOLVING_RESOLUTION,
                            reason = "route_jump_owner_reenters_paused_resolution_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = StoryStage.RESOLUTION.name,
                            openingTurn = false,
                            resolutionProfile = resolutionProfile
                        )

                        else -> ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.SOLVING_CONFRONTATION,
                            reason = "route_jump_owner_reenters_paused_confrontation_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = StoryStage.CONFRONTATION.name,
                            openingTurn = false,
                            confrontationProofProfile = confrontationProofProfile
                        )
                    }
                }

                return when {
                    isPendingClarification ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.PENDING_CLARIFICATION,
                            reason = "user_owner_detour_requires_bounded_clarification",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    pendingSubtype != null ->
                        ReplyDemandResolutionV1(
                            category = pendingSubtype,
                            reason = "user_owner_detour_requires_bounded_pending_transactional_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    detourPacketCategory != null || detourSubtype != null || hasDetourFacts ->
                        ReplyDemandResolutionV1(
                            category = detourPacketCategory
                                ?: detourSubtype
                                ?: ReplyDemandCategoryV1.DETOUR_PROOF_CHALLENGE,
                            reason = when {
                                detourPacketCategory != null ->
                                    "user_owner_solving_detour_authorized_by_packet_first_selection"
                                else ->
                                    "user_owner_solving_detour_uses_wave4_detour_contract"
                            },
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isAuthorityUserRouteJumpOwner &&
                            (solvingSupportPacketCategory != null || solvingSupportSubtype != null || hasSolvingSupportFacts) ->
                        ReplyDemandResolutionV1(
                            category = when {
                                solvingSupportPacketCategory != null -> solvingSupportPacketCategory
                                solvingSupportSubtype != null -> solvingSupportSubtype
                                pendingAfter is Pending.ReturnToRoute -> ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL
                                pendingAfter is Pending.AfterResolution -> ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL
                                pendingAfter is Pending.SolveIntroAction -> ReplyDemandCategoryV1.SOLVING_STAGE_ELABORATION
                                else -> ReplyDemandCategoryV1.SOLVING_STAGE_ELABORATION
                            },
                            reason = when {
                                solvingSupportPacketCategory != null ->
                                    "route_jump_owner_in_lane_solving_support_authorized_by_packet_first_selection"
                                else ->
                                    "route_jump_owner_in_lane_solving_support_uses_wave4_support_contract"
                            },
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isPauseResumeTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.ASSISTANT_PAUSE_RESUME,
                            reason = "user_owner_pause_or_resume_turn_uses_wave5_control_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isValidateOnlyOrSolveOnlyTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.VALIDATE_ONLY_OR_SOLVE_ONLY,
                            reason = "user_owner_validate_only_or_solve_only_turn_uses_wave5_control_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isFocusRedirectTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.FOCUS_REDIRECT,
                            reason = "user_owner_focus_redirect_turn_uses_wave5_control_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isHintPolicyChangeTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.HINT_POLICY_CHANGE,
                            reason = "user_owner_hint_policy_change_turn_uses_wave5_control_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isModeChangeTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.MODE_CHANGE,
                            reason = "user_owner_mode_change_turn_uses_wave5_control_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isPreferenceChangeTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.PREFERENCE_CHANGE,
                            reason = "user_owner_preference_change_turn_uses_wave5_control_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isMetaStateTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.META_STATE_ANSWER,
                            reason = "user_owner_meta_state_turn_uses_wave5_meta_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isCapabilityTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.CAPABILITY_ANSWER,
                            reason = "user_owner_capability_turn_uses_wave5_meta_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isGlossaryTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.GLOSSARY_ANSWER,
                            reason = "user_owner_glossary_turn_uses_wave5_help_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isUiHelpTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.UI_HELP_ANSWER,
                            reason = "user_owner_ui_help_turn_uses_wave5_help_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isCoordinateHelpTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.COORDINATE_HELP_ANSWER,
                            reason = "user_owner_coordinate_help_turn_uses_wave5_help_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isSmallTalkBridgeTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.SMALL_TALK_BRIDGE,
                            reason = "user_owner_small_talk_bridge_turn_uses_wave5_small_talk_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    isFreeTalkNonGridTurn ->
                        ReplyDemandResolutionV1(
                            category = ReplyDemandCategoryV1.FREE_TALK_NON_GRID,
                            reason = "user_owner_non_grid_free_talk_turn_uses_wave5_free_talk_contract",
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )

                    userHead is UserAgendaItem.CandidateStateQuery || hasCandidateFacts ->
                        solvingPhaseGridQuestionResolutionV1(
                            reason = "user_owner_solving_phase_candidate_question_remapped_to_solving_category",
                            stage = bridgeStoryStage
                        )

                    hasOcrTrustFacts ->
                        solvingPhaseGridQuestionResolutionV1(
                            reason = "user_owner_solving_phase_trust_question_remapped_to_solving_category",
                            stage = bridgeStoryStage
                        )

                    hasContentsFacts ->
                        solvingPhaseGridQuestionResolutionV1(
                            reason = "user_owner_solving_phase_contents_question_remapped_to_solving_category",
                            stage = bridgeStoryStage
                        )

                    hasChangelogFacts &&
                            (decision?.decisionKind == DecisionKindV1.ANSWERED_GRID_QUESTION) ->
                        solvingPhaseGridQuestionResolutionV1(
                            reason = when {
                                postResolutionMismatch ->
                                    "user_owner_post_resolution_change_question_remapped_to_solving_category"
                                else ->
                                    "user_owner_solving_phase_change_question_remapped_to_solving_category"
                            },
                            stage = bridgeStoryStage
                        )

                    decision?.decisionKind == DecisionKindV1.ANSWERED_GRID_QUESTION || hasValidationFacts ->
                        solvingPhaseGridQuestionResolutionV1(
                            reason = when {
                                postResolutionMismatch ->
                                    "user_owner_post_resolution_grid_question_remapped_to_solving_category"
                                else ->
                                    "user_owner_solving_phase_grid_question_remapped_to_solving_category"
                            },
                            stage = bridgeStoryStage
                        )

                    else ->
                        ReplyDemandResolutionV1(
                            category = when {
                                isSmallTalkBridgeTurn -> ReplyDemandCategoryV1.SMALL_TALK_BRIDGE
                                isFreeTalkNonGridTurn -> ReplyDemandCategoryV1.FREE_TALK_NON_GRID
                                else -> ReplyDemandCategoryV1.META_STATE_ANSWER
                            },
                            reason = when {
                                isSmallTalkBridgeTurn ->
                                    "user_owner_detour_bridge_small_talk_bridge_fallback"
                                isFreeTalkNonGridTurn ->
                                    "user_owner_detour_bridge_non_grid_free_talk_fallback"
                                postResolutionMismatch ->
                                    "user_owner_post_resolution_meta_fallback_after_mismatch_detour"
                                else ->
                                    "user_owner_detour_bridge_meta_state_fallback"
                            },
                            phase = bridgePhase.name,
                            pendingKind = pendingKind,
                            storyStage = bridgeStoryStage?.name,
                            openingTurn = false
                        )
                }
            }
        }





        if (
            sAfter.mode == SudoMode.GRID_SESSION &&
            sAfter.phase == GridPhase.SOLVING &&
            usesAppRouteDemandFamily
        ) {
            if (solvingPacketMismatch) {
                ConversationTelemetry.emit(
                    mapOf(
                        "type" to "SOLVING_DEMAND_PACKET_CANONICAL_MISMATCH",
                        "turn_id" to sAfter.turnSeq,
                        "phase" to sAfter.phase.name,
                        "packet_category" to (packetSolvingCategory?.name ?: "null"),
                        "canonical_category" to (canonicalSolvingCategory?.name ?: "null"),
                        "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                        "pending_kind" to pendingKind
                    )
                )
            }

            if (isBoundaryReleasedToNextStep) {
                return ReplyDemandResolutionV1(
                    category = ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL,
                    reason = "wave7_boundary_release_requests_next_step_handoff",
                    phase = routingPhase.name,
                    pendingKind = pendingKind,
                    storyStage = storyStage,
                    openingTurn = false
                )
            }

            return when {
                canonicalSolvingCategory == ReplyDemandCategoryV1.SOLVING_RESOLUTION ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_RESOLUTION,
                        reason = when {
                            packetSolvingCategory == ReplyDemandCategoryV1.SOLVING_RESOLUTION ->
                                "solving_phase_resolution_authorized_by_canonical_position_packet_aligned"

                            packetSolvingCategory != null ->
                                "solving_phase_resolution_authorized_by_canonical_position_packet_ignored"

                            else ->
                                "solving_phase_resolution_authorized_by_canonical_position"
                        },
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = storyStage,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        resolutionProfile = resolutionProfile
                    )

                canonicalSolvingCategory == ReplyDemandCategoryV1.SOLVING_CONFRONTATION ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_CONFRONTATION,
                        reason = when {
                            packetSolvingCategory == ReplyDemandCategoryV1.SOLVING_CONFRONTATION ->
                                "solving_phase_confrontation_authorized_by_canonical_position_packet_aligned"

                            packetSolvingCategory != null ->
                                "solving_phase_confrontation_authorized_by_canonical_position_packet_ignored"

                            else ->
                                "solving_phase_confrontation_authorized_by_canonical_position"
                        },
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = storyStage,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        confrontationProofProfile = confrontationProofProfile
                    )

                canonicalSolvingCategory == ReplyDemandCategoryV1.SOLVING_SETUP ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_SETUP,
                        reason = when {
                            packetSolvingCategory == ReplyDemandCategoryV1.SOLVING_SETUP ->
                                "solving_phase_setup_authorized_by_canonical_position_packet_aligned"

                            packetSolvingCategory != null ->
                                "solving_phase_setup_authorized_by_canonical_position_packet_ignored"

                            else ->
                                "solving_phase_setup_authorized_by_canonical_position"
                        },
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = storyStage,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        setupProfile = setupProfile
                    )

                packetSolvingCategory == ReplyDemandCategoryV1.SOLVING_RESOLUTION ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_RESOLUTION,
                        reason = "solving_phase_resolution_fallback_authorized_by_reply_packet_without_canonical_position",
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = StoryStage.RESOLUTION.name,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        resolutionProfile = resolutionProfile
                    )

                packetSolvingCategory == ReplyDemandCategoryV1.SOLVING_CONFRONTATION ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_CONFRONTATION,
                        reason = "solving_phase_confrontation_fallback_authorized_by_reply_packet_without_canonical_position",
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = StoryStage.CONFRONTATION.name,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        confrontationProofProfile = confrontationProofProfile
                    )

                packetSolvingCategory == ReplyDemandCategoryV1.SOLVING_SETUP ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_SETUP,
                        reason = "solving_phase_setup_fallback_authorized_by_reply_packet_without_canonical_position",
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = StoryStage.SETUP.name,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        setupProfile = setupProfile
                    )

                else ->
                    ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.SOLVING_SETUP,
                        reason = "solving_phase_missing_canonical_position_and_reply_packet_fallback_to_setup",
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = storyStage,
                        openingTurn = false,
                        canonicalPositionKind = canonicalPosition?.kind?.name,
                        canonicalLegal = canonicalLegal,
                        setupProfile = setupProfile
                    )
            }
        }

        if (sAfter.mode == SudoMode.GRID_SESSION && userText.isNotBlank()) {
            if (usesRouteJumpDemandFamily) {
                if (isPendingClarification) {
                    return ReplyDemandResolutionV1(
                        category = ReplyDemandCategoryV1.PENDING_CLARIFICATION,
                        reason = "route_jump_owner_bounded_clarification_turn",
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = storyStage,
                        openingTurn = false
                    )
                }

                if (pendingSubtype != null) {
                    return ReplyDemandResolutionV1(
                        category = pendingSubtype,
                        reason = "route_jump_owner_bounded_pending_transactional_turn",
                        phase = sAfter.phase.name,
                        pendingKind = pendingKind,
                        storyStage = storyStage,
                        openingTurn = false
                    )
                }

                if (solvingSupportPacketCategory != null || solvingSupportSubtype != null || (sAfter.phase == GridPhase.SOLVING && hasSolvingSupportFacts)) {
                    return ReplyDemandResolutionV1(
                        category = when {
                            solvingSupportPacketCategory != null -> solvingSupportPacketCategory
                            solvingSupportSubtype != null -> solvingSupportSubtype
                            pendingAfter is Pending.ReturnToRoute -> ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL
                            pendingAfter is Pending.AfterResolution -> ReplyDemandCategoryV1.SOLVING_ROUTE_CONTROL
                            pendingAfter is Pending.SolveIntroAction -> ReplyDemandCategoryV1.SOLVING_STAGE_ELABORATION
                            else -> ReplyDemandCategoryV1.SOLVING_STAGE_ELABORATION
                        },
                        reason = when {
                            solvingSupportPacketCategory != null ->
                                "route_jump_owner_support_family_authorized_by_packet_first_selection"
                            else ->
