    private fun normalizePendingForReplyRoutingV1(pending: Pending?): Pending? {
        return when (pending) {
            is Pending.ConfirmEdit ->
                Pending.ConfirmCellToDigit(
                    cellIndex = pending.cellIndex,
                    proposedDigit = pending.proposedDigit,
                    prompt = pending.prompt,
                    source = pending.source
                )

            is Pending.AskCellValue ->
                Pending.ProvideDigit(
                    cellIndex = pending.cellIndex,
                    prompt = pending.prompt
                )

            is Pending.ConfirmInterpretation ->
                pending

            else ->
                pending
        }
    }

    private fun resolveReplyDemandContractV1(
        demand: ReplyDemandResolutionV1
    ): ReplyDemandContractV1 {
        return ReplyDemandContractsV1.forDemand(demand)
    }


    private fun estimateTokensFromChars(chars: Int): Int =
        if (chars <= 0) 0 else (chars + 3) / 4

    private fun jsonHasUsefulValue(obj: JSONObject?, vararg keys: String): Boolean {
        if (obj == null) return false
        for (key in keys) {
            if (!obj.has(key) || obj.isNull(key)) continue
            when (val v = obj.opt(key)) {
                is String -> if (v.isNotBlank()) return true
                is JSONArray -> if (v.length() > 0) return true
                is JSONObject -> if (v.length() > 0) return true
                null -> Unit
                else -> return true
            }
        }
        return false
    }

    private fun emitSetupCoverageTelemetryV1(
        turnId: Long,
        demand: ReplyDemandResolutionV1,
        replyRequest: ReplyRequestV1,
        planResult: ReplyAssemblyPlannerV1.PlanResultV1
    ) {
        if (demand.category != ReplyDemandCategoryV1.SOLVING_SETUP) return

        val packetPayload = replyRequest.facts
            .firstOrNull { it.type == FactBundleV1.Type.SETUP_REPLY_PACKET_V1 }
            ?.payload

        val selectedChannelNames = planResult.plan.selectedChannels.map { it.name }.toSet()
        val projectedByName = planResult.projectedChannels.associateBy { it.channel.name }

        val handoverLen = projectedByName["HANDOVER_NOTE_MINI"]?.payload?.toString()?.length ?: 0
        val glossaryLen = projectedByName["GLOSSARY_MINI"]?.payload?.toString()?.length ?: 0
        val continuityLen = projectedByName["CONTINUITY_SHORT"]?.payload?.toString()?.length ?: 0
        val supportTotalLen = handoverLen + glossaryLen + continuityLen

        val fallbackReason =
            when {
                packetPayload == null ->
                    "missing_setup_reply_packet_bundle"

                "SETUP_REPLY_PACKET" !in selectedChannelNames ->
                    "setup_packet_channel_not_selected"

                projectedByName["SETUP_REPLY_PACKET"] == null ->
                    "setup_packet_channel_not_projected"

                else ->
                    null
            }

        if (packetPayload == null) {
            ConversationTelemetry.emit(
                mapOf(
                    "type" to "SETUP_REPLY_COVERAGE",
                    "turn_id" to turnId,
                    "tick_id" to 2,
                    "demand_category" to when (demand.category) {
                        ReplyDemandCategoryV1.CONFIRMING_VALIDATION_SUMMARY -> "CONFIRM_STATUS_SUMMARY"
                        ReplyDemandCategoryV1.FREE_TALK_IN_GRID_SESSION -> "META_STATE_ANSWER"
                        else -> demand.category.name
                    },
                    "raw_demand_category" to demand.category.name,
                    "rollout_mode" to planResult.plan.rolloutMode,
                    "setup_profile" to (demand.setupProfile?.name ?: "UNKNOWN"),
                    "setup_packet_len" to 0,
                    "setup_packet_sha12" to JSONObject.NULL,
                    "setup_packet_has_target" to false,
                    "setup_packet_has_orientation" to false,
                    "setup_packet_has_lens" to false,
                    "setup_packet_has_trigger_overview" to false,
                    "setup_packet_has_bounded_rows" to false,
                    "setup_packet_bounded_row_count" to 0,
                    "setup_packet_has_trigger_statement" to false,
                    "setup_packet_has_bridge" to false,
                    "setup_packet_has_setup_only_line" to false,
                    "setup_packet_has_cta" to false,
                    "setup_handover_len" to handoverLen,
                    "setup_glossary_len" to glossaryLen,
                    "setup_continuity_len" to continuityLen,
                    "setup_support_total_len" to supportTotalLen,
                    "setup_fallback_reason" to (fallbackReason ?: JSONObject.NULL)
                )
            )
            return
        }

        val packetJson = packetPayload.toString()
        val setupProfile = packetPayload.optString("setup_profile").ifBlank {
            demand.setupProfile?.name ?: "UNKNOWN"
        }

        val target = packetPayload.optJSONObject("target")
        val orientation = packetPayload.optJSONObject("orientation")
        val lens = packetPayload.optJSONObject("lens")
        val triggerOverview = packetPayload.optJSONObject("trigger_overview")
        val boundedRows = packetPayload.optJSONArray("bounded_trigger_rows") ?: JSONArray()
        val triggerStatement = packetPayload.optJSONObject("trigger_statement")
        val bridge = packetPayload.optJSONObject("bridge")
        val setupOnlyLine = packetPayload.optJSONObject("setup_only_line")
        val cta = packetPayload.optJSONObject("cta")

        ConversationTelemetry.emit(
            mapOf(
                "type" to "SETUP_REPLY_COVERAGE",
                "turn_id" to turnId,
                "tick_id" to 2,
                "demand_category" to when (demand.category) {
                    ReplyDemandCategoryV1.CONFIRMING_VALIDATION_SUMMARY -> "CONFIRM_STATUS_SUMMARY"
                    ReplyDemandCategoryV1.FREE_TALK_IN_GRID_SESSION -> "META_STATE_ANSWER"
                    else -> demand.category.name
                },
                "raw_demand_category" to demand.category.name,
                "rollout_mode" to planResult.plan.rolloutMode,
                "setup_profile" to setupProfile,
                "setup_packet_len" to packetJson.length,
                "setup_packet_sha12" to sha12(packetJson).take(12),
                "setup_packet_has_target" to jsonHasUsefulValue(target, "cell", "primary_house", "target_digit"),
                "setup_packet_has_orientation" to jsonHasUsefulValue(
                    orientation,
                    "summary",
                    "target_cell",
                    "primary_house"
                ),
                "setup_packet_has_lens" to jsonHasUsefulValue(
                    lens,
                    "summary",
                    "setup_role",
                    "trigger_kind",
                    "can_name_pattern",
                    "must_include_bounded_trigger_member_explanation"
                ),
                "setup_packet_has_trigger_overview" to jsonHasUsefulValue(
                    triggerOverview,
                    "summary",
                    "pattern",
                    "explanation_payload",
                    "intro_route"
                ),
                "setup_packet_has_bounded_rows" to (boundedRows.length() > 0),
                "setup_packet_bounded_row_count" to boundedRows.length(),
                "setup_packet_has_trigger_statement" to jsonHasUsefulValue(
                    triggerStatement,
                    "summary",
                    "pattern_kind",
                    "pattern"
                ),
                "setup_packet_has_bridge" to jsonHasUsefulValue(
                    bridge,
                    "summary",
                    "why_this_matters",
                    "payload",
                    "final_resolution_setup_summary"
                ),
                "setup_packet_has_setup_only_line" to jsonHasUsefulValue(
                    setupOnlyLine,
                    "summary",
                    "spoiler_level",
                    "claim_code"
                ),
                "setup_packet_has_cta" to jsonHasUsefulValue(cta, "kind"),
                "setup_handover_len" to handoverLen,
                "setup_glossary_len" to glossaryLen,
                "setup_continuity_len" to continuityLen,
                "setup_support_total_len" to supportTotalLen,
                "setup_fallback_reason" to (fallbackReason ?: JSONObject.NULL)
            )
        )
    }

    private fun emitConfrontationCoverageTelemetryV1(
        turnId: Long,
        demand: ReplyDemandResolutionV1,
        replyRequest: ReplyRequestV1,
        planResult: ReplyAssemblyPlannerV1.PlanResultV1
    ) {
        if (demand.category != ReplyDemandCategoryV1.SOLVING_CONFRONTATION) return

        val packetPayload = replyRequest.facts
            .firstOrNull { it.type == FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1 }
            ?.payload

        val selectedChannelNames = planResult.plan.selectedChannels.map { it.name }.toSet()
        val projectedByName = planResult.projectedChannels.associateBy { it.channel.name }

        val glossaryLen = projectedByName["GLOSSARY_MINI"]?.payload?.toString()?.length ?: 0
        val continuityLen = projectedByName["CONTINUITY_SHORT"]?.payload?.toString()?.length ?: 0
        val techniqueCardLen = projectedByName["TECHNIQUE_CARD_MINI"]?.payload?.toString()?.length ?: 0
        val supportTotalLen = glossaryLen + continuityLen + techniqueCardLen

        val fallbackReason =
            when {
                packetPayload == null ->
                    "missing_confrontation_reply_packet_bundle"

                "CONFRONTATION_REPLY_PACKET" !in selectedChannelNames ->
                    "confrontation_packet_channel_not_selected"

                projectedByName["CONFRONTATION_REPLY_PACKET"] == null ->
                    "confrontation_packet_channel_not_projected"

                else ->
                    null
            }

        if (packetPayload == null) {
            ConversationTelemetry.emitConfrontationReplyCoverage(
                turnId = turnId,
                tickId = 2,
                demandCategory = demand.category.name,
                rolloutMode = planResult.plan.rolloutMode,
                proofProfile = demand.confrontationProofProfile?.name,
                packetLen = 0,
                packetSha12 = null,
                packetSelected = "CONFRONTATION_REPLY_PACKET" in selectedChannelNames,
                packetProjected = projectedByName["CONFRONTATION_REPLY_PACKET"] != null,
                hasTarget = false,
                hasTriggerReference = false,
                hasTriggerEffect = false,
                hasCollapse = false,
                hasPreCommitLine = false,
                hasCta = false,
                rawProofRowCount = 0,
                boundedProofRowCount = 0,
                proofRowLimit = 0,
                proofRowsTruncated = false,
                supportLen = supportTotalLen,
                actorStructure = null,
                ordinaryWitnessFirstRequired = false,
                techniqueFinishingCutRequired = false,
                hasTargetSpotlightLine = false,
                hasSurvivorRevealLine = false,
                ladderFirstStepKind = null,
                ladderSecondStepKind = null,
                overlayVariant = null,
                fallbackReason = fallbackReason
            )
            return
        }

        val packetJson = packetPayload.toString()
        val proofProfile = packetPayload.optString("proof_profile").ifBlank {
            demand.confrontationProofProfile?.name ?: "UNKNOWN"
        }

        val target = packetPayload.optJSONObject("target")
        val triggerReference = packetPayload.optJSONObject("trigger_reference")
        val triggerEffect = packetPayload.optJSONObject("trigger_effect")
        val collapse = packetPayload.optJSONObject("collapse")
        val preCommitLine = packetPayload.optJSONObject("pre_commit_line")
        val cta = packetPayload.optJSONObject("cta")
        val support = packetPayload.optJSONObject("support")
        val targetProofRows = packetPayload.optJSONArray("target_proof_rows") ?: JSONArray()

        val rawProofRowCount =
            support?.optInt("raw_target_proof_row_count", targetProofRows.length())
                ?: targetProofRows.length()

        val boundedProofRowCount =
            support?.optInt("target_proof_row_count", targetProofRows.length())
                ?: targetProofRows.length()

        val proofRowLimit =
            support?.optInt("proof_row_limit", 0) ?: 0

        val proofRowsTruncated =
            support?.optBoolean("proof_rows_truncated", false) ?: false

        val overlayVariant =
            support?.optString("overlay_variant").takeIf { !it.isNullOrBlank() }

        val actorStructure =
            support?.optString("actor_structure").takeIf { !it.isNullOrBlank() }

        val ordinaryWitnessFirstRequired =
            support?.optBoolean("ordinary_witness_first_required", false) ?: false

        val techniqueFinishingCutRequired =
            support?.optBoolean("technique_finishing_cut_required", false) ?: false

        val hasTargetSpotlightLine =
            !(support?.optString("target_spotlight_line").isNullOrBlank())

        val hasSurvivorRevealLine =
            !(support?.optString("survivor_reveal_line").isNullOrBlank())

        val orderedProofLadder =
            packetPayload.optJSONArray("ordered_proof_ladder") ?: JSONArray()

        val ladderFirstStepKind =
            orderedProofLadder.optJSONObject(0)?.optString("step_kind")?.takeIf { it.isNotBlank() }

        val ladderSecondStepKind =
            orderedProofLadder.optJSONObject(1)?.optString("step_kind")?.takeIf { it.isNotBlank() }

        ConversationTelemetry.emitConfrontationReplyCoverage(
            turnId = turnId,
            tickId = 2,
            demandCategory = demand.category.name,
            rolloutMode = planResult.plan.rolloutMode,
            proofProfile = proofProfile,
            packetLen = packetJson.length,
            packetSha12 = sha12(packetJson).take(12),
            packetSelected = "CONFRONTATION_REPLY_PACKET" in selectedChannelNames,
            packetProjected = projectedByName["CONFRONTATION_REPLY_PACKET"] != null,
            hasTarget = jsonHasUsefulValue(
                target,
                "cell",
                "primary_house",
                "target_digit"
            ),
            hasTriggerReference = jsonHasUsefulValue(
                triggerReference,
                "summary",
                "trigger_kind",
                "pattern"
            ),
            hasTriggerEffect = jsonHasUsefulValue(
                triggerEffect,
                "summary",
                "payload"
            ),
            hasCollapse = jsonHasUsefulValue(
                collapse,
                "summary",
                "remaining_candidate_digits",
                "surviving_digit",
                "two_layer_honesty_line"
            ),
            hasPreCommitLine = jsonHasUsefulValue(
                preCommitLine,
                "summary",
                "claim_code",
                "spoiler_level"
            ),
            hasCta = jsonHasUsefulValue(cta, "kind"),
            rawProofRowCount = rawProofRowCount,
            boundedProofRowCount = boundedProofRowCount,
            proofRowLimit = proofRowLimit,
            proofRowsTruncated = proofRowsTruncated,
            supportLen = supportTotalLen,
            actorStructure = actorStructure,
            ordinaryWitnessFirstRequired = ordinaryWitnessFirstRequired,
            techniqueFinishingCutRequired = techniqueFinishingCutRequired,
            hasTargetSpotlightLine = hasTargetSpotlightLine,
            hasSurvivorRevealLine = hasSurvivorRevealLine,
            ladderFirstStepKind = ladderFirstStepKind,
            ladderSecondStepKind = ladderSecondStepKind,
            overlayVariant = overlayVariant,
            fallbackReason = fallbackReason
        )
    }



