    private fun emitReplyWasteAuditV1(
        turnId: Long,
        demand: ReplyDemandResolutionV1,
        planResult: ReplyAssemblyPlannerV1.PlanResultV1
    ) {
        val contract = planResult.plan.contract ?: return

        val selectedPromptModules = planResult.plan.selectedPromptModules.map { it.name }
        val selectedChannels = planResult.plan.selectedChannels.map { it.name }
        val forbiddenChannels = contract.forbiddenChannels.map { it.name }.sorted()

        val excludedChannels = contract.forbiddenChannels.map { it.name }.sorted()

        val channelChars = linkedMapOf<String, Int>()
        val channelTokens = linkedMapOf<String, Int>()

        var totalDynamicChars = 0
        var totalDynamicTokens = 0

        for (entry in planResult.projectedChannels) {
            val txt = entry.payload.toString()
            val chars = txt.length
            val tokens = estimateTokensFromChars(chars)
            channelChars[entry.channel.name] = chars
            channelTokens[entry.channel.name] = tokens
            totalDynamicChars += chars
            totalDynamicTokens += tokens
        }

        val charBudget = contract.budget.softCharBudget
        val tokenBudget = contract.budget.softTokenBudget

        val charOverrun = if (charBudget != null) max(0, totalDynamicChars - charBudget) else 0
        val tokenOverrun = if (tokenBudget != null) max(0, totalDynamicTokens - tokenBudget) else 0

        val warnings = mutableListOf<String>()

        val selectedSet = selectedChannels.toSet()
        val forbiddenSelected = selectedSet.intersect(forbiddenChannels.toSet())
        if (forbiddenSelected.isNotEmpty()) {
            warnings += "forbidden_channels_selected:${forbiddenSelected.sorted().joinToString(",")}"
        }

        val stepSliceCount = selectedChannels.count { it.endsWith("_STEP_SLICE") }
        if (stepSliceCount > 1) {
            warnings += "multiple_step_slices_selected"
        }

        val storySliceCount = selectedChannels.count { it.endsWith("_STORY_SLICE") }
        if (storySliceCount > 1) {
            warnings += "multiple_story_slices_selected"
        }

        if (demand.category == ReplyDemandCategoryV1.SOLVING_CONFRONTATION) {
            if ("CONFRONTATION_REPLY_PACKET" !in selectedSet) {
                warnings += "missing_confrontation_reply_packet_channel"
            }

            if ("CONFRONTATION_STORY_SLICE" in selectedSet) {
                warnings += "legacy_confrontation_story_slice_selected"
            }

            if ("CONFRONTATION_STEP_SLICE" in selectedSet) {
                warnings += "legacy_confrontation_step_slice_selected"
            }

            val packetProjection = planResult.projectedChannels
                .firstOrNull { it.channel == ReplySupplyChannelV1.CONFRONTATION_REPLY_PACKET }
                ?.payload

            if (packetProjection == null || packetProjection.length() == 0) {
                warnings += "missing_confrontation_reply_packet_projection"
            } else {
                val support = packetProjection.optJSONObject("support")
                val proofRowsTruncated =
                    support?.optBoolean("proof_rows_truncated", false) ?: false
                val rawRows =
                    support?.optInt("raw_target_proof_row_count", 0) ?: 0
                val boundedRows =
                    support?.optInt("target_proof_row_count", 0) ?: 0

                if (proofRowsTruncated) {
                    warnings += "confrontation_proof_rows_truncated:$rawRows->$boundedRows"
                }

                if (boundedRows <= 0) {
                    warnings += "confrontation_packet_has_no_target_proof_rows"
                }

                val targetResolutionTruth =
                    packetProjection.optJSONObject("target_resolution_truth") ?: JSONObject()
                val houseClaim =
                    targetResolutionTruth.optJSONObject("house_claim") ?: JSONObject()
                val targetSupport =
                    targetResolutionTruth.optJSONObject("support") ?: JSONObject()

                val houseClaimedCount =
                    houseClaim.optJSONArray("claimed_candidate_cells")?.length() ?: 0
                val houseRemainingCount =
                    houseClaim.optJSONArray("remaining_candidate_cells")?.length() ?: 0
                val housePeerPairsCount =
                    targetSupport.optJSONArray("peer_witness_pairs")?.length() ?: 0
                val housePeerBlockerCount =
                    targetSupport.optJSONArray("peer_blocker_rows")?.length() ?: 0
                val ladderCount =
                    targetSupport.optJSONArray("ordered_proof_ladder")?.length() ?: 0
                val eliminationKind =
                    targetResolutionTruth.optString("elimination_kind")

                if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                    if (houseClaimedCount <= 0) {
                        warnings += "confrontation_house_claim_missing_claimed_candidate_cells"
                    }
                    if (houseRemainingCount <= 0) {
                        warnings += "confrontation_house_claim_missing_remaining_candidate_cells"
                    }
                    if (housePeerPairsCount <= 0 && housePeerBlockerCount <= 0) {
                        warnings += "confrontation_house_claim_missing_witness_support"
                    }
                    if (ladderCount <= 1) {
                        warnings += "confrontation_house_claim_ladder_too_thin"
                    }
                }

                val collapse = packetProjection.optJSONObject("collapse")
                val preCommitLine = packetProjection.optJSONObject("pre_commit_line")
                val cta = packetProjection.optJSONObject("cta")

                val actorStructure =
                    support?.optString("actor_structure").takeIf { !it.isNullOrBlank() }

                val ordinaryWitnessFirstRequired =
                    support?.optBoolean("ordinary_witness_first_required", false) ?: false

                val techniqueFinishingCutRequired =
                    support?.optBoolean("technique_finishing_cut_required", false) ?: false

                val hasTargetSpotlightLine =
                    !(support?.optString("target_spotlight_line").isNullOrBlank())

                val hasSurvivorRevealLine =
                    !(support?.optString("survivor_reveal_line").isNullOrBlank())

                val ladder =
                    packetProjection.optJSONArray("ordered_proof_ladder") ?: JSONArray()

                val ladderFirstStepKind =
                    ladder.optJSONObject(0)?.optString("step_kind").orEmpty()

                val ladderSecondStepKind =
                    ladder.optJSONObject(1)?.optString("step_kind").orEmpty()

                val hasCollapse =
                    collapse != null && (
                            !collapse.optString("summary").isNullOrBlank() ||
                                    !collapse.isNull("surviving_digit") ||
                                    !collapse.isNull("remaining_candidate_digits")
                            )

                val hasPreCommit =
                    preCommitLine != null && (
                            !preCommitLine.optString("summary").isNullOrBlank() ||
                                    !preCommitLine.optString("claim_code").isNullOrBlank()
                            )

                val hasCta =
                    cta != null && !cta.optString("kind").isNullOrBlank()

                if (!hasTargetSpotlightLine) {
                    warnings += "confrontation_packet_missing_target_spotlight_support"
                }

                if (!hasSurvivorRevealLine) {
                    warnings += "confrontation_packet_missing_survivor_reveal_support"
                }

                if (support?.optBoolean("doctrine_is_pattern_first", false) == true) {
                    val peerCount = support.optInt("peer_blocker_row_count", 0)
                    val techniqueCount = support.optInt("technique_blocker_row_count", 0)

                    if (peerCount > 0 && techniqueCount > 0 && actorStructure != "DUET") {
                        warnings += "confrontation_pattern_first_missing_duet_structure"
                    }

                    if (peerCount > 0 && !ordinaryWitnessFirstRequired) {
                        warnings += "confrontation_pattern_first_missing_witness_first_flag"
                    }

                    if (techniqueCount > 0 && !techniqueFinishingCutRequired) {
                        warnings += "confrontation_pattern_first_missing_finishing_cut_flag"
                    }

                    if (peerCount > 0 && ladderFirstStepKind != "ordinary_witness_ensemble" && ladderFirstStepKind != "peer_cleanup") {
                        warnings += "confrontation_pattern_first_wrong_first_ladder_step:$ladderFirstStepKind"
                    }

                    if (techniqueCount > 0 && ladder.length() > 1 &&
                        ladderSecondStepKind != "technique_finishing_cut" &&
                        ladderSecondStepKind != "technique_effect"
                    ) {
                        warnings += "confrontation_pattern_first_wrong_second_ladder_step:$ladderSecondStepKind"
                    }

                    if (peerCount > 0 && techniqueCount > 0 &&
                        (ladderFirstStepKind == "technique_finishing_cut" || ladderFirstStepKind == "technique_effect")
                    ) {
                        warnings += "confrontation_pattern_first_technique_acts_too_early"
                    }
                }

                if (support?.optBoolean("doctrine_is_lens_first", false) == true) {
                    val fallbackMode =
                        support.optString("sparse_packet_fallback_mode").ifBlank { null }

                    if (support.optBoolean("rival_seat_walk_required", false) &&
                        ladderFirstStepKind != "lens_question_reanchor" &&
                        ladderFirstStepKind != "rival_seat_falls" &&
                        ladderFirstStepKind != "peer_cleanup"
                    ) {
                        warnings += "confrontation_lens_first_missing_lens_opening_shape:$ladderFirstStepKind"
                    }

                    if (support.opt("lens_digit") == null || support.opt("lens_digit") == JSONObject.NULL) {
                        warnings += "confrontation_lens_first_missing_lens_digit_support"
                    }

                    if (support.optString("lens_house_label").isBlank()) {
                        warnings += "confrontation_lens_first_missing_lens_house_support"
                    }

                    if (packetProjection.optJSONArray("target_proof_rows")?.length() == 0 &&
                        fallbackMode.isNullOrBlank()
                    ) {
                        warnings += "confrontation_sparse_packet_missing_fallback_mode"
                    }
                }

                val collapseSummary =
                    collapse?.optString("summary").orEmpty()

                val survivorRevealLine =
                    support?.optString("survivor_reveal_line").orEmpty()

                if (!hasCollapse) {
                    warnings += "confrontation_packet_missing_collapse_truth"
                }

                if (hasCollapse &&
                    collapseSummary.contains("After all these eliminations", ignoreCase = true)
                ) {
                    warnings += "confrontation_collapse_summary_too_flat"
                }

                if (hasSurvivorRevealLine && survivorRevealLine.isBlank()) {
                    warnings += "confrontation_missing_survivor_reveal_energy"
                }

                if (!hasPreCommit) {
                    warnings += "confrontation_packet_missing_pre_commit_boundary"
                }
                if (!hasCta) {
                    warnings += "confrontation_packet_missing_cta"
                }
            }
        }

        if (demand.category == ReplyDemandCategoryV1.SOLVING_RESOLUTION) {
            if ("RESOLUTION_REPLY_PACKET" !in selectedSet) {
                warnings += "missing_resolution_reply_packet_channel"
            }

            if ("RESOLUTION_STORY_SLICE" in selectedSet) {
                warnings += "legacy_resolution_story_slice_selected"
            }

            if ("RESOLUTION_STEP_SLICE" in selectedSet) {
                warnings += "legacy_resolution_step_slice_selected"
            }

            val packetProjection = planResult.projectedChannels
                .firstOrNull { it.channel == ReplySupplyChannelV1.RESOLUTION_REPLY_PACKET }
                ?.payload

            if (packetProjection == null || packetProjection.length() == 0) {
                warnings += "missing_resolution_reply_packet_projection"
            } else {
                val recap = packetProjection.optJSONObject("recap")
                val techniqueContribution = packetProjection.optJSONObject("technique_contribution")
                val finalForcing = packetProjection.optJSONObject("final_forcing")
                val honesty = packetProjection.optJSONObject("honesty")
                val presentStateLine = packetProjection.optJSONObject("present_state_line")
                val postCommit = packetProjection.optJSONObject("post_commit")
                val cta = packetProjection.optJSONObject("cta")

                val hasRecap =
                    recap != null && !recap.optString("summary").isNullOrBlank()

                val hasTechniqueContribution =
                    techniqueContribution != null && !techniqueContribution.optString("summary").isNullOrBlank()

                val hasFinalForcing =
                    finalForcing != null && !finalForcing.optString("summary").isNullOrBlank()

                val hasPresentStateLine =
                    presentStateLine != null && !presentStateLine.optString("summary").isNullOrBlank()

                val hasPostCommit =
                    postCommit != null && !postCommit.optString("board_delta_summary").isNullOrBlank()

                val hasCta =
                    cta != null && !cta.optString("kind").isNullOrBlank()

                val compactMode =
                    recap?.optString("compact_mode").orEmpty()

                val recapMaxBeats =
                    recap?.optInt("max_beats", 0) ?: 0

                if (!hasRecap) {
                    warnings += "resolution_packet_missing_recap"
                }
                if (!hasTechniqueContribution) {
                    warnings += "resolution_packet_missing_technique_contribution"
                }
                if (!hasFinalForcing) {
                    warnings += "resolution_packet_missing_final_forcing"
                }
                if (!hasPresentStateLine) {
                    warnings += "resolution_packet_missing_present_state_line"
                }
                if (!hasPostCommit) {
                    warnings += "resolution_packet_missing_post_commit_summary"
                }
                if (!hasCta) {
                    warnings += "resolution_packet_missing_cta"
                }
                if (compactMode.isBlank()) {
                    warnings += "resolution_packet_missing_compact_mode"
                }
                if (recapMaxBeats <= 0) {
                    warnings += "resolution_packet_missing_recap_max_beats"
                }

                val hasHonesty =
                    honesty != null && !honesty.optString("two_layer_honesty_line").isNullOrBlank()

                if (!hasHonesty) {
                    warnings += "resolution_packet_missing_two_layer_honesty_line"
                }

                val fullResolutionBasis =
                    packetProjection.optJSONObject("full_resolution_basis") ?: JSONObject()
                val houseClaim =
                    fullResolutionBasis.optJSONObject("house_claim") ?: JSONObject()
                val eliminationKind =
                    fullResolutionBasis.optString("elimination_kind")

                if (eliminationKind == "HOUSE_CANDIDATE_CELLS_FOR_DIGIT") {
                    val houseClaimedCount =
                        houseClaim.optJSONArray("claimed_candidate_cells")?.length() ?: 0
                    val houseRemainingCount =
                        houseClaim.optJSONArray("remaining_candidate_cells")?.length() ?: 0

                    if (houseClaimedCount <= 0) {
                        warnings += "resolution_house_claim_missing_claimed_candidate_cells"
                    }
                    if (houseRemainingCount <= 0) {
                        warnings += "resolution_house_claim_missing_remaining_candidate_cells"
                    }

                    val recapSummary =
                        recap?.optString("summary").orEmpty()
                    val finalForcingSummary =
                        finalForcing?.optString("summary").orEmpty()

                    if (recapSummary.isBlank()) {
                        warnings += "resolution_house_claim_missing_truth_based_recap"
                    }
                    if (finalForcingSummary.isBlank()) {
                        warnings += "resolution_house_claim_missing_truth_based_final_forcing"
                    }
                }
            }
        }

        if (charOverrun > 0) {
            warnings += "char_budget_exceeded:$charOverrun"
        }
        if (tokenOverrun > 0) {
            warnings += "token_budget_exceeded:$tokenOverrun"
        }

        ConversationTelemetry.emitReplyWasteAudit(
            turnId = turnId,
            tickId = 2,
            demandCategory = demand.category.name,
            rolloutMode = planResult.plan.rolloutMode,
            selectedPromptModules = selectedPromptModules,
            selectedChannels = selectedChannels,
            forbiddenChannels = forbiddenChannels,
            excludedChannels = excludedChannels,
            channelChars = channelChars,
            channelTokens = channelTokens,
            totalDynamicChars = totalDynamicChars,
            totalDynamicTokens = totalDynamicTokens,
            softCharBudget = charBudget,
            softTokenBudget = tokenBudget,
            charOverrun = charOverrun,
            tokenOverrun = tokenOverrun,
            warnings = warnings
        )
    }


    /**
     * Phase 6 — telemetry emission from an already-built planner result.
     *
     * Still non-invasive:
     * - the planner computes selected modules/channels + projections
     * - we emit those for inspection
     * - legacy payload assembly remains in effect until Phase 7 rollout
     */
    private fun emitProjectedReplyChannelsV1(
        turnId: Long,
        demand: ReplyDemandResolutionV1,
        planResult: ReplyAssemblyPlannerV1.PlanResultV1
    ) {
        val projected = linkedMapOf<String, String>()

        for (entry in planResult.projectedChannels) {
            projected[entry.channel.name] = entry.payload.toString()
        }

        ConversationTelemetry.emitReplyProjectedChannels(
            turnId = turnId,
            tickId = 2,
            demandCategory = demand.category.name,
            channels = projected
        )
    }

    private fun cellIndexOf(cell: String?): Int? {
        val s = cell?.trim()?.lowercase() ?: return null
        val m = Regex("""r([1-9])c([1-9])""").matchEntire(s) ?: return null
        val r = m.groupValues[1].toIntOrNull() ?: return null
        val c = m.groupValues[2].toIntOrNull() ?: return null
        return (r - 1) * 9 + (c - 1)
    }

    private fun cellRefV1(cell: String?): JSONObject {
        val normalized = cell?.trim()?.lowercase().orEmpty()
        val idx = cellIndexOf(normalized)
        val r = if (idx != null) (idx / 9) + 1 else JSONObject.NULL
        val c = if (idx != null) (idx % 9) + 1 else JSONObject.NULL

        return JSONObject().apply {
            put("cell", normalized)
            put("cellIndex", idx ?: JSONObject.NULL)
            put("r", r)
            put("c", c)
        }
    }

    private fun digitRefV1(digit: Int): JSONObject =
        JSONObject().apply {
            put("digit", digit)
        }

    private fun houseRefV1(kind: RegionKindV1, index: Int): JSONObject =
        JSONObject().apply {
            put(
                "type",
                when (kind) {
                    RegionKindV1.ROW -> "row"
                    RegionKindV1.COL -> "col"
                    RegionKindV1.BOX -> "box"
                }
            )
            put("index1to9", index)
        }

    private fun RegionRefV1.toJson(): JSONObject =
        houseRefV1(this.kind, this.index)

    private fun jsonArrayOfObjects(items: List<JSONObject>): JSONArray =
        JSONArray().apply {
            items.forEach { put(JSONObject(it.toString())) }
        }

    private fun FactBundleV1.toJson(): JSONObject =
        JSONObject().apply {
            put("type", this@toJson.type.name)
            put("payload", JSONObject(this@toJson.payload.toString()))
        }

    private fun factRecoveryPacketV1(
        kind: String,
        facts: JSONObject,
        cta: CtaPacketV1
    ): FactBundleV1 =
        FactBundleV1(
            type = FactBundleV1.Type.RECOVERY_PACKET_V1,
            payload = JSONObject().apply {
                put("kind", kind)
                put("facts", JSONObject(facts.toString()))
                put("cta", cta.toJson())
            }
        )

