    sealed class PlannedOpV1 {
        data class ApplyCellEdit(val cellIndex: Int, val digit: Int, val source: String) : PlannedOpV1()

        /**
         * Confirmation is NOT an edit. It locks / marks the value as confirmed (even if unchanged).
         */
        data class ConfirmCellValue(val cellIndex: Int, val digit: Int, val source: String) : PlannedOpV1()

        data class Undo(val source: String) : PlannedOpV1()
        data class Redo(val source: String) : PlannedOpV1()

        data class AddCandidate(val cellIndex: Int, val digit: Int, val source: String) : PlannedOpV1()
        data class RemoveCandidate(val cellIndex: Int, val digit: Int, val source: String) : PlannedOpV1()

        /**
         * Idempotent full candidate set.
         */
        data class SetCandidatesMask(val cellIndex: Int, val mask: Int, val source: String) : PlannedOpV1()

        /**
         * AGENDA 6: Finalize validation presentation (pure UI cleanup: remove WIP artifacts).
         * This is NOT a digit mutation.
         */
        data class FinalizeValidationPresentation(
            val reason: String,
            val source: String
        ) : PlannedOpV1()

        // ✅ SOLVING control: request engine to compute the next human step (no grid mutation).
        data class ComputeSolveStep(
            val grid81: String,
            val gridHash12: String,
            val reason: String,
            val force: Boolean
        ) : PlannedOpV1()
    }

    private fun expireUserAgendaIfStale(s: SudoState, env: IntentEnvelopeV1): SudoState {
        var q = s.userAgendaQueue
        if (q.isEmpty()) return s

        var changed = false

        // Phase 9: mini-agendas can survive beyond one turn.
        // We only stale-drop resolved/cancelled items, or very old untouched open items.
        while (q.isNotEmpty()) {
            val head = q.first()

            val shouldDrop =
                when (head.status) {
                    UserAgendaStatusV1.RESOLVED,
                    UserAgendaStatusV1.CANCELLED -> true

                    UserAgendaStatusV1.OPEN -> {
                        val age = s.turnSeq - head.createdTurnSeq
                        age >= 3L && !head.allowsFollowUp
                    }

                    UserAgendaStatusV1.PARTIALLY_ANSWERED -> {
                        val touched = head.lastTouchedTurnSeq ?: head.createdTurnSeq
                        val ageSinceTouch = s.turnSeq - touched
                        ageSinceTouch >= 4L
                    }
                }

            if (!shouldDrop) break

            q = q.drop(1)
            changed = true
        }

        if (q.isEmpty()) {
            val pendingAfter = ClarificationKernelV1.clarificationPendingAfterConsumption(s.pending)
            return if (changed) s.copy(userAgendaQueue = q, pending = pendingAfter) else s
        }

        // Expire rule (spec):
        // - If asked on turn T, and user does NOT address it on turn T+1, expire on T+1.
        // => In the state for turnSeq = current turn, expire any head that was askedTurnSeq <= turnSeq-1 and not addressed.

        while (q.isNotEmpty()) {
            val head = q.first()
            if (head !is UserAgendaItem.Clarification) break

            val asked = head.askedTurnSeq ?: break // not asked yet -> do not expire
            val eligibleToExpire = asked <= (s.turnSeq - 1)
            if (!eligibleToExpire) break

            val resolution =
                ClarificationKernelV1.assessResolutionForHead(
                    head = head,
                    intents = env.intents
                )
            if (resolution is ClarificationResolutionAssessmentV1.Resolved) break

            // Expire head
            q = q.drop(1)
            changed = true
        }

        if (!changed) return s

        // Clear pending ONLY if it was a clarification prompt (do not nuke other pending types)
        val pendingAfter = ClarificationKernelV1.clarificationPendingAfterConsumption(s.pending)

        return s.copy(
            userAgendaQueue = q,
            pending = pendingAfter
        )
    }




    private fun consumeUserAgendaHeadIfAddressed(s: SudoState, env: IntentEnvelopeV1): SudoState {
        val head = s.userAgendaQueue.firstOrNull()
        if (head !is UserAgendaItem.Clarification) return s

        val resolution =
            ClarificationKernelV1.assessResolutionForHead(
                head = head,
                intents = env.intents
            )

        return when (resolution) {
            is ClarificationResolutionAssessmentV1.Resolved ->
                s.copy(
                    userAgendaQueue = s.userAgendaQueue.drop(1),
                    pending = ClarificationKernelV1.clarificationPendingAfterConsumption(s.pending)
                )

            is ClarificationResolutionAssessmentV1.PartiallyResolved,
            is ClarificationResolutionAssessmentV1.NotResolved -> s
        }
    }



    private data class DupeHouse(val kind: String, val index: Int, val digit: Int, val cells: List<Int>)
    private data class ConflictItem(val cell: Int, val digit: Int, val peers: List<Int>, val reason: String)

    private fun computeDuplicatesByHouse(grid: IntArray): List<DupeHouse> {
        val out = mutableListOf<DupeHouse>()

        fun scanHouse(kind: String, index: Int, idxs: List<Int>) {
            val map = mutableMapOf<Int, MutableList<Int>>()
            idxs.forEach { i ->
                val d = grid.getOrNull(i)?.coerceIn(0, 9) ?: 0
                if (d in 1..9) map.getOrPut(d) { mutableListOf() }.add(i)
            }
            map.forEach { (d, cells) ->
                if (cells.size >= 2) out.add(DupeHouse(kind, index, d, cells))
            }
        }

        for (r in 1..9) scanHouse("ROW", r, (0 until 9).map { c -> (r - 1) * 9 + c })
        for (c in 1..9) scanHouse("COL", c, (0 until 9).map { r -> r * 9 + (c - 1) })
        for (b in 1..9) {
            val br = (b - 1) / 3
            val bc = (b - 1) % 3
            val r0 = br * 3
            val c0 = bc * 3
            val idxs = mutableListOf<Int>()
            for (dr in 0..2) for (dc in 0..2) idxs += (r0 + dr) * 9 + (c0 + dc)
            scanHouse("BOX", b, idxs)
        }
        return out
    }

    private fun computeConflictSet(grid: IntArray): List<ConflictItem> {
        val dupes = computeDuplicatesByHouse(grid)
        val items = mutableListOf<ConflictItem>()

        dupes.forEach { h ->
            // Each cell conflicts with all other cells in that duplicate set
            h.cells.forEach { cell ->
                val peers = h.cells.filter { it != cell }
                items.add(
                    ConflictItem(
                        cell = cell,
                        digit = h.digit,
                        peers = peers,
                        reason = "DUPLICATE_${h.kind}_${h.index}"
                    )
                )
            }
        }
        // Deduplicate by (cell,digit,reason)
        return items.distinctBy { Triple(it.cell, it.digit, it.reason) }
    }




