// Phase 5 — SOLVING agenda machine (table-driven reducer)
// ============================================================
    private enum class SolvingAgendaKindV1 {
        STEP_INTRO,
        ATOM_WALK,
        COMMIT_DECISION,
        COMMIT_APPLY,
        POST_COMMIT,
        DETOUR_FREE_TALK
    }

    private data class SolvingTransitionKey(
        val agenda: SolvingAgendaKindV1,
        val intent: IntentTypeV1
    )

    private sealed class SolvingTransition {
        data object NoOp : SolvingTransition()
        data object AdvanceAtom : SolvingTransition()
        data object ToCommitDecision : SolvingTransition()
        data object ApplyCommit : SolvingTransition()
        data object NextStep : SolvingTransition()
        data object TeachTechnique : SolvingTransition()
        data object BackToIntro : SolvingTransition()
        data object BackToConfrontation : SolvingTransition()
    }

    private data class SolvingAgendaResult(
        val newActiveAgenda: AppAgendaItem.Solving? = null,
        val newPending: Pending? = null,
        val advanceToNextStep: Boolean = false,
        val factBundles: List<FactBundleV1> = emptyList()
    )

    // Central transition table (ONE place to control SOLVING behavior)
    // Central transition table (ONE place to control SOLVING behavior)
    private val SOLVING_TRANSITIONS_V1: Map<SolvingTransitionKey, SolvingTransition> = buildMap {

        val stayAndElaborateIntents = listOf(
            IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION,
            IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION,
            IntentTypeV1.REQUEST_CURRENT_STAGE_COLLAPSE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_EXAMPLE,
            IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT,
            IntentTypeV1.ASK_WHY_THIS_CELL,
            IntentTypeV1.REQUEST_REASONING_CHECK
        )

        val repeatStageIntents = listOf(
            IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT,
            IntentTypeV1.REQUEST_CURRENT_STAGE_REPHRASE,
            IntentTypeV1.SOLVE_PAUSE
        )

        // --------------------------------------------------------
        // STEP_INTRO (North Star SETUP)
        // --------------------------------------------------------
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, IntentTypeV1.SOLVE_CONTINUE),
            SolvingTransition.AdvanceAtom
        )

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT),
            SolvingTransition.ToCommitDecision
        )

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, IntentTypeV1.SOLVE_ACCEPT_LOCK_IN),
            SolvingTransition.ToCommitDecision
        )

        for (it in stayAndElaborateIntents) {
            put(
                SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, it),
                SolvingTransition.NoOp
            )
        }

        for (it in repeatStageIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, it), SolvingTransition.NoOp)
        }

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE),
            SolvingTransition.NoOp
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP),
            SolvingTransition.NoOp
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.STEP_INTRO, IntentTypeV1.REQUEST_STEP_BACK),
            SolvingTransition.NoOp
        )

        // --------------------------------------------------------
        // ATOM_WALK (North Star CONFRONTATION)
        // --------------------------------------------------------
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, IntentTypeV1.SOLVE_CONTINUE),
            SolvingTransition.AdvanceAtom
        )

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT),
            SolvingTransition.ToCommitDecision
        )

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, IntentTypeV1.SOLVE_ACCEPT_LOCK_IN),
            SolvingTransition.ToCommitDecision
        )

        for (it in stayAndElaborateIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, it), SolvingTransition.NoOp)
        }

        for (it in repeatStageIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, it), SolvingTransition.NoOp)
        }

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE),
            SolvingTransition.BackToIntro
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP),
            SolvingTransition.BackToIntro
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.ATOM_WALK, IntentTypeV1.REQUEST_STEP_BACK),
            SolvingTransition.BackToIntro
        )

        // --------------------------------------------------------
        // COMMIT_DECISION (North Star RESOLUTION boundary)
        // --------------------------------------------------------
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, IntentTypeV1.SOLVE_CONTINUE),
            SolvingTransition.ApplyCommit
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT),
            SolvingTransition.ApplyCommit
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, IntentTypeV1.SOLVE_ACCEPT_LOCK_IN),
            SolvingTransition.ApplyCommit
        )

        for (it in stayAndElaborateIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, it), SolvingTransition.NoOp)
        }

        for (it in repeatStageIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, it), SolvingTransition.NoOp)
        }

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE),
            SolvingTransition.BackToConfrontation
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP),
            SolvingTransition.BackToConfrontation
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_DECISION, IntentTypeV1.REQUEST_STEP_BACK),
            SolvingTransition.BackToConfrontation
        )

        // --------------------------------------------------------
        // COMMIT_APPLY (resolution apply scheduled / waiting for board truth)
        // --------------------------------------------------------
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, IntentTypeV1.SOLVE_CONTINUE),
            SolvingTransition.ApplyCommit
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT),
            SolvingTransition.ApplyCommit
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, IntentTypeV1.SOLVE_ACCEPT_LOCK_IN),
            SolvingTransition.ApplyCommit
        )

        for (it in stayAndElaborateIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, it), SolvingTransition.NoOp)
        }

        for (it in repeatStageIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, it), SolvingTransition.NoOp)
        }

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE),
            SolvingTransition.BackToConfrontation
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP),
            SolvingTransition.BackToConfrontation
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.COMMIT_APPLY, IntentTypeV1.REQUEST_STEP_BACK),
            SolvingTransition.BackToConfrontation
        )

        // --------------------------------------------------------
        // POST_COMMIT (North Star completed-step resolution)
        // --------------------------------------------------------
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, IntentTypeV1.SOLVE_CONTINUE),
            SolvingTransition.NextStep
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP),
            SolvingTransition.NextStep
        )

        for (it in stayAndElaborateIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, it), SolvingTransition.NoOp)
        }

        for (it in repeatStageIntents) {
            put(SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, it), SolvingTransition.NoOp)
        }

        put(
            SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE),
            SolvingTransition.BackToConfrontation
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP),
            SolvingTransition.BackToConfrontation
        )
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, IntentTypeV1.REQUEST_STEP_BACK),
            SolvingTransition.BackToConfrontation
        )

        // Broad technique teaching remains an explicit side action after resolution.
        put(
            SolvingTransitionKey(SolvingAgendaKindV1.POST_COMMIT, IntentTypeV1.ASK_TECHNIQUE_OVERVIEW),
            SolvingTransition.TeachTechnique
        )
    }

    private fun currentQueuedSolvingHead(s: SudoState): AppAgendaItem.Solving? =
        s.appAgendaQueue.firstOrNull() as? AppAgendaItem.Solving

    private fun atomicSolveIntroPendingV1(
        s: SudoState,
        stage: StoryStage,
        atomIndex: Int,
        atomsCount: Int,
        isLastHint: Boolean
    ): Pending =
        when (stage) {
            StoryStage.SETUP ->
                Pending.SolveIntroAction.SetupAction(
                    stepId = s.solveStepId ?: "",
                    atomIndex = atomIndex,
                    atomsCount = atomsCount,
                    isLastHint = isLastHint,
                    prompt = "",
                    gridHash12 = (s.solveStepGridHash12 ?: "").take(12),
                    options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                        .forStoryStage(stage)
                        .options
                )

            StoryStage.CONFRONTATION ->
                Pending.SolveIntroAction.ConfrontationAction(
                    stepId = s.solveStepId ?: "",
                    atomIndex = atomIndex,
                    atomsCount = atomsCount,
                    isLastHint = isLastHint,
                    prompt = "",
                    gridHash12 = (s.solveStepGridHash12 ?: "").take(12),
                    options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                        .forStoryStage(stage)
                        .options
                )

            StoryStage.RESOLUTION ->
                Pending.SolveIntroAction.ConfrontationAction(
                    stepId = s.solveStepId ?: "",
                    atomIndex = atomIndex,
                    atomsCount = atomsCount,
                    isLastHint = isLastHint,
                    prompt = "",
                    gridHash12 = (s.solveStepGridHash12 ?: "").take(12),
                    options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                        .forStoryStage(StoryStage.CONFRONTATION)
                        .options
                )
        }

    private fun atomicApplyHintPendingV1(
        s: SudoState
    ): Pending.ApplyHintNow =
        Pending.ApplyHintNow(
            stepId = s.solveStepId ?: "",
            prompt = "",
            gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
        )

    private fun atomicAfterResolutionPendingV1(
        s: SudoState
    ): Pending.AfterResolution =
        Pending.AfterResolution(
            stepId = s.solveStepId ?: "",
            prompt = "",
            gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
        )

    private fun currentCommittedResolutionPlacementV1(
        s: SudoState
    ): Pair<Int, Int>? {
        val isPostCommitState =
            s.pending is Pending.AfterResolution ||
                    currentQueuedSolvingHead(s) is AppAgendaItem.Solving.PostCommitChoice

        if (!isPostCommitState) return null

        val reveal = s.coachPlan?.reveal
        if (reveal != null) {
            return reveal.placementCellIndex to reveal.placementDigit
        }

        val idx = s.coachPlan?.targetCellIndex
        val digit = s.coachPlan?.targetDigit
        return if (idx != null && digit != null) idx to digit else null
    }

    private fun hasGenericPostCommitContinueIntentV1(
        intents: List<IntentV1>
    ): Boolean =
        intents.any {
            when (it.type) {
                IntentTypeV1.SOLVE_CONTINUE,
                IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP,
                IntentTypeV1.CONFIRM_YES -> true
                else -> false
            }
        }

    private fun isPostCommitContinuationIntentV1(
        intent: IntentTypeV1?
    ): Boolean =
        intent == IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP ||
                intent == IntentTypeV1.SOLVE_CONTINUE ||
                intent == IntentTypeV1.CONFIRM_YES

    private fun isDelayedAutoCommitEchoIntentV1(
        s: SudoState,
        allIntents: List<IntentV1>,
        intent: IntentV1
    ): Boolean {
        if (!hasGenericPostCommitContinueIntentV1(allIntents)) return false

        val (placementIdx, placementDigit) =
            currentCommittedResolutionPlacementV1(s) ?: return false

        return when (intent.type) {
            IntentTypeV1.EDIT_CELL,
            IntentTypeV1.CONFIRM_CELL_TO_DIGIT -> {
                val idx = intent.cellIndexOrNullCompat()
                val digit = intent.digitOrNullCompat()
                idx == placementIdx && digit == placementDigit
            }

            else -> false
        }
    }

    private fun hasFactBundleKindV1(
        bundles: List<FactBundleV1>,
        kind: String
    ): Boolean =
        bundles.any { fb ->
            fb.type == FactBundleV1.Type.OTHER &&
                    fb.payload.optString("kind") == kind
        }



    private fun materializeNarrativeStoryForBoundaryV1(
        s: SudoState,
        pending: Pending?,
        activeAgenda: AppAgendaItem.Solving?,
        previousStory: NarrativeStoryContext?,
        advanceToNextStep: Boolean,
        preserveStageOnStayAndElaborate: Boolean
    ): NarrativeStoryContext? {
        if (advanceToNextStep) return null

        val story0 = previousStory

        val atomsCountFromAgenda =
            when (activeAgenda) {
                is AppAgendaItem.Solving.AtomWalk -> activeAgenda.atomCount
                else -> null
            }

        return when (pending) {
            is Pending.SolveIntroAction -> {
                val atomsCount = (story0?.atomsCount ?: pending.atomsCount).coerceAtLeast(1)
                val stage = pending.stage
                val proofIndices = proofAtomIndicesForStoryV1(atomsCount)

                val focus = defaultFocusAtomIndexForStageV1(
                    stage = stage,
                    atomsCount = atomsCount,
                    preferredProofAtomIndex = pending.atomIndex
                )

                val readyForCommit =
                    when (stage) {
                        StoryStage.CONFRONTATION ->
                            proofIndices.isNotEmpty() && (focus >= proofIndices.last())

                        StoryStage.RESOLUTION -> true
                        StoryStage.SETUP -> false
                    }

                NarrativeStoryContext(
                    stepId = pending.stepId,
                    gridHash12 = pending.gridHash12,
                    stage = stage,
                    atomsCount = atomsCount,
                    focusAtomIndex = focus,
                    discussedAtomIndices = narrationAtomIndicesForStageV1(
                        stage = stage,
                        atomsCount = atomsCount
                    ),
                    readyForCommit = readyForCommit,
                    createdTurnSeq = story0?.createdTurnSeq ?: s.turnSeq
                )
            }

            is Pending.ApplyHintNow -> {
                val atomsCount =
                    (story0?.atomsCount ?: atomsCountFromAgenda ?: s.solveAtomsCount).coerceAtLeast(1)

                NarrativeStoryContext(
                    stepId = pending.stepId.ifBlank { story0?.stepId ?: (s.solveStepId ?: "") },
                    gridHash12 = pending.gridHash12.ifBlank {
                        story0?.gridHash12 ?: (s.solveStepGridHash12 ?: "").take(12)
                    },
                    stage = StoryStage.RESOLUTION,
                    atomsCount = atomsCount,
                    focusAtomIndex = defaultFocusAtomIndexForStageV1(
                        stage = StoryStage.RESOLUTION,
                        atomsCount = atomsCount
                    ),
                    discussedAtomIndices = narrationAtomIndicesForStageV1(
                        stage = StoryStage.RESOLUTION,
                        atomsCount = atomsCount
                    ),
                    readyForCommit = true,
                    createdTurnSeq = story0?.createdTurnSeq ?: s.turnSeq
                )
            }

            is Pending.AfterResolution -> {
                val atomsCount =
                    (story0?.atomsCount ?: atomsCountFromAgenda ?: s.solveAtomsCount).coerceAtLeast(1)

                NarrativeStoryContext(
                    stepId = pending.stepId.ifBlank { story0?.stepId ?: (s.solveStepId ?: "") },
                    gridHash12 = pending.gridHash12.ifBlank {
                        story0?.gridHash12 ?: (s.solveStepGridHash12 ?: "").take(12)
                    },
                    stage = StoryStage.RESOLUTION,
                    atomsCount = atomsCount,
                    focusAtomIndex = defaultFocusAtomIndexForStageV1(
                        stage = StoryStage.RESOLUTION,
                        atomsCount = atomsCount
                    ),
                    discussedAtomIndices = narrationAtomIndicesForStageV1(
                        stage = StoryStage.RESOLUTION,
                        atomsCount = atomsCount
                    ),
                    readyForCommit = true,
                    createdTurnSeq = story0?.createdTurnSeq ?: s.turnSeq
                )
            }

            else -> {
                if (preserveStageOnStayAndElaborate && story0 != null) {
                    val n = story0.atomsCount.coerceAtLeast(1)
                    val stage = story0.stage

                    story0.copy(
                        focusAtomIndex = defaultFocusAtomIndexForStageV1(
                            stage = stage,
                            atomsCount = n,
                            preferredProofAtomIndex = story0.focusAtomIndex
                        ),
                        discussedAtomIndices = narrationAtomIndicesForStageV1(
                            stage = stage,
                            atomsCount = n
                        )
                    )
                } else {
                    story0
                }
            }
        }
    }

    private fun applyAtomicSolvingTransitionV1(
        s: SudoState,
        transition: SolvingTransition,
        route: ActiveRouteContextV2,
        stepIndex: Int,
        atomsCountRaw: Int,
        currentAtomIndex: Int,
        currentGridHash12OrNull: () -> String?
    ): SolvingAgendaResult {
        fun mkStepIntro(route: ActiveRouteContextV2, stepIndex: Int): AppAgendaItem.Solving.StepIntro =
            AppAgendaItem.Solving.StepIntro(
                agendaId = "sa:intro:${s.turnSeq}",
                createdAtMs = System.currentTimeMillis(),
                createdTurnSeq = s.turnSeq,
                stepIndex = stepIndex,
                route = route
            )

        fun mkAtomWalk(
            route: ActiveRouteContextV2,
            stepIndex: Int,
            atomIndex: Int,
            atomCount: Int
        ): AppAgendaItem.Solving.AtomWalk =
            AppAgendaItem.Solving.AtomWalk(
                agendaId = "sa:atomwalk:${s.turnSeq}:$atomIndex",
                createdAtMs = System.currentTimeMillis(),
                createdTurnSeq = s.turnSeq,
                stepIndex = stepIndex,
                route = route,
                atomIndex = atomIndex,
                atomCount = atomCount
            )

        fun mkCommitDecision(
            route: ActiveRouteContextV2,
            stepIndex: Int,
            commitAtomIndex: Int,
            opsCount: Int
        ): AppAgendaItem.Solving.CommitDecision =
            AppAgendaItem.Solving.CommitDecision(
                agendaId = "sa:commit:${s.turnSeq}",
                createdAtMs = System.currentTimeMillis(),
                createdTurnSeq = s.turnSeq,
                stepIndex = stepIndex,
                route = route,
                commitAtomIndex = commitAtomIndex,
                opsCount = opsCount
            )

        fun mkCommitApply(
            route: ActiveRouteContextV2,
            stepIndex: Int,
            commitReason: String
        ): AppAgendaItem.Solving.CommitApply =
            AppAgendaItem.Solving.CommitApply(
                agendaId = "sa:apply:${s.turnSeq}",
                createdAtMs = System.currentTimeMillis(),
                createdTurnSeq = s.turnSeq,
                stepIndex = stepIndex,
                route = route,
                commitReason = commitReason
            )

        fun mkPostCommit(
            route: ActiveRouteContextV2,
            stepIndex: Int
        ): AppAgendaItem.Solving.PostCommitChoice =
            AppAgendaItem.Solving.PostCommitChoice(
                agendaId = "sa:post:${s.turnSeq}",
                createdAtMs = System.currentTimeMillis(),
                createdTurnSeq = s.turnSeq,
                stepIndex = stepIndex,
                route = route
            )

        val atomsCount = atomsCountRaw.coerceAtLeast(1)
        val proofIndices = proofAtomIndicesForStoryV1(atomsCount)
        val commitAtomIndex = (atomsCount - 1).coerceAtLeast(0)
        val canonicalPosition = resolveCanonicalSolvingStepPositionV1(s)

        fun canonicalBoundaryTransitionV1(
            requested: SolvingTransition,
            canonicalKind: CanonicalSolvingPositionKindV1?
        ): SolvingTransition =
            when (requested) {
                SolvingTransition.NoOp -> SolvingTransition.NoOp

                SolvingTransition.AdvanceAtom ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.SETUP,
                        CanonicalSolvingPositionKindV1.CONFRONTATION,
                        null -> SolvingTransition.AdvanceAtom

                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> SolvingTransition.NoOp
                    }

                SolvingTransition.ToCommitDecision ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.CONFRONTATION ->
                            if (
                                canonicalPosition?.readyForCommit == true ||
                                proofIndices.isEmpty() ||
                                currentAtomIndex >= (proofIndices.lastOrNull() ?: 0)
                            ) {
                                SolvingTransition.ToCommitDecision
                            } else {
                                SolvingTransition.AdvanceAtom
                            }

                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                        null -> SolvingTransition.ToCommitDecision

                        CanonicalSolvingPositionKindV1.SETUP -> SolvingTransition.AdvanceAtom
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> SolvingTransition.NoOp
                    }

                SolvingTransition.ApplyCommit ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                        null -> SolvingTransition.ApplyCommit

                        CanonicalSolvingPositionKindV1.SETUP,
                        CanonicalSolvingPositionKindV1.CONFRONTATION,
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> SolvingTransition.NoOp
                    }

                SolvingTransition.NextStep ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT,
                        null -> SolvingTransition.NextStep

                        CanonicalSolvingPositionKindV1.SETUP,
                        CanonicalSolvingPositionKindV1.CONFRONTATION,
                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT -> SolvingTransition.NoOp
                    }

                SolvingTransition.TeachTechnique ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT,
                        null -> SolvingTransition.TeachTechnique

                        CanonicalSolvingPositionKindV1.SETUP,
                        CanonicalSolvingPositionKindV1.CONFRONTATION,
                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT -> SolvingTransition.NoOp
                    }

                SolvingTransition.BackToIntro ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.CONFRONTATION,
                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT,
                        null -> SolvingTransition.BackToIntro

                        CanonicalSolvingPositionKindV1.SETUP -> SolvingTransition.NoOp
                    }

                SolvingTransition.BackToConfrontation ->
                    when (canonicalKind) {
                        CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                        CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT,
                        null -> SolvingTransition.BackToConfrontation

                        CanonicalSolvingPositionKindV1.SETUP,
                        CanonicalSolvingPositionKindV1.CONFRONTATION -> SolvingTransition.NoOp
                    }
            }

        val boundaryTransition =
            canonicalBoundaryTransitionV1(
                requested = transition,
                canonicalKind = canonicalPosition?.kind
            )

        return when (boundaryTransition) {
            SolvingTransition.NoOp -> SolvingAgendaResult()

            SolvingTransition.NextStep -> {
                SolvingAgendaResult(
                    newActiveAgenda = mkStepIntro(route, stepIndex + 1),
                    newPending = null,
                    advanceToNextStep = true
                )
            }

            SolvingTransition.AdvanceAtom -> {
                when (canonicalPosition?.kind) {
                    CanonicalSolvingPositionKindV1.SETUP -> {
                        val firstProofAtom = proofIndices.firstOrNull() ?: 0
                        val confrontationIsLastHint = proofIndices.size <= 1

                        SolvingAgendaResult(
                            newActiveAgenda = mkAtomWalk(
                                route = route,
                                stepIndex = stepIndex,
                                atomIndex = firstProofAtom,
                                atomCount = atomsCount
                            ),
                            newPending = atomicSolveIntroPendingV1(
                                s = s,
                                stage = StoryStage.CONFRONTATION,
                                atomIndex = firstProofAtom,
                                atomsCount = atomsCount,
                                isLastHint = confrontationIsLastHint
                            )
                        )
                    }

                    CanonicalSolvingPositionKindV1.CONFRONTATION -> {
                        if (proofIndices.isEmpty()) {
                            SolvingAgendaResult(
                                newActiveAgenda = mkCommitDecision(
                                    route = route,
                                    stepIndex = stepIndex,
                                    commitAtomIndex = commitAtomIndex,
                                    opsCount = 1
                                ),
                                newPending = atomicApplyHintPendingV1(s)
                            )
                        } else {
                            val currentProofPos = proofIndices.indexOf(currentAtomIndex)
                            val nextProofAtom =
                                when {
                                    currentProofPos < 0 -> proofIndices.first()
                                    currentProofPos >= proofIndices.lastIndex -> proofIndices.last()
                                    else -> proofIndices[currentProofPos + 1]
                                }

                            val alreadyAtLastProof = currentAtomIndex >= proofIndices.last()

                            if (alreadyAtLastProof) {
                                SolvingAgendaResult(
                                    newActiveAgenda = mkCommitDecision(
                                        route = route,
                                        stepIndex = stepIndex,
                                        commitAtomIndex = commitAtomIndex,
                                        opsCount = 1
                                    ),
                                    newPending = atomicApplyHintPendingV1(s)
                                )
                            } else {
                                SolvingAgendaResult(
                                    newActiveAgenda = mkAtomWalk(
                                        route = route,
                                        stepIndex = stepIndex,
                                        atomIndex = nextProofAtom,
                                        atomCount = atomsCount
                                    ),
                                    newPending = atomicSolveIntroPendingV1(
                                        s = s,
                                        stage = StoryStage.CONFRONTATION,
                                        atomIndex = nextProofAtom,
                                        atomsCount = atomsCount,
                                        isLastHint = (nextProofAtom >= proofIndices.last())
                                    )
                                )
                            }
                        }
                    }

                    CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                    CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT,
                    null -> {
                        val firstProofAtom = proofIndices.firstOrNull() ?: 0
                        SolvingAgendaResult(
                            newActiveAgenda = mkAtomWalk(
                                route = route,
                                stepIndex = stepIndex,
                                atomIndex = firstProofAtom,
                                atomCount = atomsCount
                            ),
                            newPending = atomicSolveIntroPendingV1(
                                s = s,
                                stage = StoryStage.CONFRONTATION,
                                atomIndex = firstProofAtom,
                                atomsCount = atomsCount,
                                isLastHint = proofIndices.size <= 1
                            )
                        )
                    }
                }
            }

            SolvingTransition.ApplyCommit -> {
                val cp = s.coachPlan
                val reveal = cp?.reveal

                val curHash12 = currentGridHash12OrNull()
                val boundHash12 = (s.coachPlanGridHash12 ?: (s.solveStepGridHash12 ?: "")).take(12)
                val hashMismatch =
                    (curHash12 != null && boundHash12.isNotBlank() && curHash12 != boundHash12)

                val commitAgenda = mkCommitApply(
                    route = route,
                    stepIndex = stepIndex,
                    commitReason = "apply_commit_requested_waiting_for_board_truth"
                )

                val commitPending = atomicApplyHintPendingV1(s)

                if (reveal == null || hashMismatch) {
                    SolvingAgendaResult(
                        newActiveAgenda = commitAgenda,
                        newPending = commitPending,
                        factBundles = listOf(
                            FactBundleV1(
                                type = FactBundleV1.Type.OTHER,
                                payload = org.json.JSONObject().apply {
                                    put("kind", "solve_commit_deferred_same_step_retained")
                                    put("reason", if (reveal == null) "reveal_missing" else "grid_hash_mismatch")
                                    put("bound_hash12", boundHash12)
                                    put("current_hash12", curHash12 ?: org.json.JSONObject.NULL)
                                    put("step_id", s.solveStepId ?: org.json.JSONObject.NULL)
                                }
                            )
                        )
                    )
                } else {
                    SolvingAgendaResult(
                        newActiveAgenda = commitAgenda,
                        newPending = commitPending
                    )
                }
            }

            SolvingTransition.TeachTechnique -> {
                SolvingAgendaResult(
                    newActiveAgenda = mkPostCommit(route, stepIndex),
                    newPending = atomicAfterResolutionPendingV1(s),
                    advanceToNextStep = false,
                    factBundles = listOf(
                        FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = org.json.JSONObject().put("kind", "teach_technique_requested")
                        )
                    )
                )
            }

            SolvingTransition.BackToIntro -> {
                SolvingAgendaResult(
                    newActiveAgenda = mkStepIntro(route, stepIndex),
                    newPending = atomicSolveIntroPendingV1(
                        s = s,
                        stage = StoryStage.SETUP,
                        atomIndex = 0,
                        atomsCount = atomsCount,
                        isLastHint = false
                    )
                )
            }

            SolvingTransition.BackToConfrontation -> {
                val firstProofAtom = proofIndices.firstOrNull() ?: 0

                SolvingAgendaResult(
                    newActiveAgenda = mkAtomWalk(
                        route = route,
                        stepIndex = stepIndex,
                        atomIndex = firstProofAtom,
                        atomCount = atomsCount
                    ),
                    newPending = atomicSolveIntroPendingV1(
                        s = s,
                        stage = StoryStage.CONFRONTATION,
                        atomIndex = firstProofAtom,
                        atomsCount = atomsCount,
                        isLastHint = (proofIndices.size <= 1)
                    )
                )
            }

            SolvingTransition.ToCommitDecision -> {
                SolvingAgendaResult(
                    newActiveAgenda = mkCommitDecision(
                        route = route,
                        stepIndex = stepIndex,
                        commitAtomIndex = commitAtomIndex,
                        opsCount = 1
                    ),
                    newPending = atomicApplyHintPendingV1(s)
                )
            }
        }
    }

    private fun currentUserAgendaHead(s: SudoState): UserAgendaItem? =
        s.userAgendaQueue.firstOrNull()

    private fun storyStageFromSolvingHeadV1(
        head: AppAgendaItem.Solving?
    ): StoryStage? =
        when (head) {
            is AppAgendaItem.Solving.StepIntro -> StoryStage.SETUP

            is AppAgendaItem.Solving.AtomWalk -> StoryStage.CONFRONTATION

            // Architectural principle:
            // commit/apply boundary belongs to RESOLUTION, not to late CONFRONTATION.
            is AppAgendaItem.Solving.CommitDecision,
            is AppAgendaItem.Solving.CommitApply,
            is AppAgendaItem.Solving.PostCommitChoice -> StoryStage.RESOLUTION

            else -> null
        }

    private fun authoritativeStoryStageFromRouteV1(
        solvingHead: AppAgendaItem.Solving?,
        story: NarrativeStoryContext?
    ): StoryStage? =
    // Architectural rule:
    // story stage is the only stage authority.
        // Route / agenda objects may support execution, but must never supply stage.
        story?.stage

    private fun authoritativeStepIdV1(
        solvingHead: AppAgendaItem.Solving?,
        story: NarrativeStoryContext?,
        activeRoute: ActiveRouteContext?,
        solveStepId: String?,
        coachPlanStepId: String?
    ): String? =
        solvingHead?.route?.stepId?.takeIf { it.isNotBlank() }
            ?: story?.stepId?.takeIf { it.isNotBlank() }
            ?: activeRoute?.stepId?.takeIf { it.isNotBlank() }
            ?: solveStepId?.takeIf { it.isNotBlank() }
            ?: coachPlanStepId?.takeIf { it.isNotBlank() }

    private fun authoritativeGridHash12V1(
        solvingHead: AppAgendaItem.Solving?,
        story: NarrativeStoryContext?,
        activeRoute: ActiveRouteContext?,
        solveStepGridHash12: String?,
        coachPlanGridHash12: String?
    ): String? =
        solvingHead?.route?.gridHash12?.takeIf { it.isNotBlank() }
            ?: story?.gridHash12?.takeIf { it.isNotBlank() }
            ?: activeRoute?.gridHash12?.takeIf { it.isNotBlank() }
            ?: solveStepGridHash12?.takeIf { it.isNotBlank() }?.take(12)
            ?: coachPlanGridHash12?.takeIf { it.isNotBlank() }?.take(12)

    private fun canonicalSolvingHeadKindV1(
        head: AppAgendaItem.Solving?
    ): CanonicalSolvingHeadKindV1 =
        when (head) {
            null -> CanonicalSolvingHeadKindV1.NONE
            is AppAgendaItem.Solving.StepIntro -> CanonicalSolvingHeadKindV1.STEP_INTRO
            is AppAgendaItem.Solving.AtomWalk -> CanonicalSolvingHeadKindV1.ATOM_WALK
            is AppAgendaItem.Solving.CommitDecision -> CanonicalSolvingHeadKindV1.COMMIT_DECISION
            is AppAgendaItem.Solving.CommitApply -> CanonicalSolvingHeadKindV1.COMMIT_APPLY
            is AppAgendaItem.Solving.PostCommitChoice -> CanonicalSolvingHeadKindV1.POST_COMMIT_CHOICE
            else -> CanonicalSolvingHeadKindV1.NONE
        }

    private fun canonicalSolvingPendingKindV1(
        pending: Pending?
    ): CanonicalSolvingPendingKindV1 =
        when (pending) {
            null -> CanonicalSolvingPendingKindV1.NONE
            is Pending.SolveIntroAction -> CanonicalSolvingPendingKindV1.SOLVE_INTRO_ACTION
            is Pending.ApplyHintNow -> CanonicalSolvingPendingKindV1.APPLY_HINT_NOW
            is Pending.AfterResolution -> CanonicalSolvingPendingKindV1.AFTER_RESOLUTION
            is Pending.SolveStepMissing -> CanonicalSolvingPendingKindV1.SOLVE_STEP_MISSING
            else -> CanonicalSolvingPendingKindV1.OTHER
        }

    private fun computeCanonicalSolvingStepPositionV1(
        s: SudoState
    ): CanonicalSolvingStepPositionV1? {
        if (s.phase != GridPhase.SOLVING) return null

        val solvingHead = currentQueuedSolvingHead(s)
        val pending = s.pending
        val story = s.narrativeStory
        val rail = effectiveSolvingRailStateV1(s)

        val stageFromPendingOrHead: StoryStage? =
            when (pending) {
                is Pending.AfterResolution -> StoryStage.RESOLUTION
                is Pending.ApplyHintNow -> StoryStage.RESOLUTION
                is Pending.SolveIntroAction -> pending.stage
                else -> storyStageFromSolvingHeadV1(solvingHead)
            }

        val stage: StoryStage =
            stageFromPendingOrHead
                ?: story?.stage
                ?: return null

        val isFreshSetupBoundary =
            (pending is Pending.SolveIntroAction.SetupAction) ||
                    (stage == StoryStage.SETUP && solvingHead is AppAgendaItem.Solving.StepIntro)

        val isFreshConfrontationBoundary =
            (pending is Pending.SolveIntroAction.ConfrontationAction) ||
                    (stage == StoryStage.CONFRONTATION && solvingHead is AppAgendaItem.Solving.AtomWalk)

        val kind =
            when {
                isFreshSetupBoundary ->
                    CanonicalSolvingPositionKindV1.SETUP

                isFreshConfrontationBoundary ->
                    CanonicalSolvingPositionKindV1.CONFRONTATION

                pending is Pending.AfterResolution ||
                        solvingHead is AppAgendaItem.Solving.PostCommitChoice ||
                        rail?.boundary == SolvingRailBoundaryV1.POST_COMMIT ->
                    CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT

                pending is Pending.ApplyHintNow ||
                        solvingHead is AppAgendaItem.Solving.CommitDecision ||
                        solvingHead is AppAgendaItem.Solving.CommitApply ->
                    CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT

                stage == StoryStage.CONFRONTATION ->
                    CanonicalSolvingPositionKindV1.CONFRONTATION

                stage == StoryStage.SETUP ->
                    CanonicalSolvingPositionKindV1.SETUP

                else ->
                    CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT
            }

        val stepId =
            authoritativeStepIdV1(
                solvingHead = solvingHead,
                story = story,
                activeRoute = s.activeRouteContext,
                solveStepId = s.solveStepId,
                coachPlanStepId = s.coachPlanStepId
            )

        val gridHash12 =
            authoritativeGridHash12V1(
                solvingHead = solvingHead,
                story = story,
                activeRoute = s.activeRouteContext,
                solveStepGridHash12 = s.solveStepGridHash12,
                coachPlanGridHash12 = s.coachPlanGridHash12
            )?.take(12)

        val focusAtomIndex =
            story?.focusAtomIndex
                ?: when (pending) {
                    is Pending.SolveIntroAction -> pending.atomIndex
                    is Pending.ApplyHintNow -> s.solveAtomIndex
                    is Pending.AfterResolution -> s.solveAtomIndex
                    else -> when (solvingHead) {
                        is AppAgendaItem.Solving.AtomWalk -> solvingHead.atomIndex
                        else -> s.solveAtomIndex
                    }
                }

        val atomsCount =
            story?.atomsCount
                ?: when (pending) {
                    is Pending.SolveIntroAction -> pending.atomsCount
                    else -> when (solvingHead) {
                        is AppAgendaItem.Solving.AtomWalk -> solvingHead.atomCount
                        else -> null
                    }
                }

        val readyForCommit =
            when {
                story != null -> story.readyForCommit
                kind == CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT -> true
                kind == CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> true
                else -> false
            }

        return CanonicalSolvingStepPositionV1(
            kind = kind,
            stepId = stepId,
            gridHash12 = gridHash12,
            stage = when (kind) {
                CanonicalSolvingPositionKindV1.SETUP -> StoryStage.SETUP
                CanonicalSolvingPositionKindV1.CONFRONTATION -> StoryStage.CONFRONTATION
                CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> StoryStage.RESOLUTION
            },
            headKind = canonicalSolvingHeadKindV1(solvingHead),
            pendingKind = canonicalSolvingPendingKindV1(pending),
            focusAtomIndex = focusAtomIndex,
            atomsCount = atomsCount,
            readyForCommit = readyForCommit
        )
    }

    private fun authoritativeCanonicalSolvingStepPositionV1(
        s: SudoState
    ): CanonicalSolvingStepPositionV1? {
        if (s.phase != GridPhase.SOLVING) return null

        val stored = s.canonicalSolvingPositionV1
        val computed = computeCanonicalSolvingStepPositionV1(s)

        return when {
            stored == null -> computed
            computed == null -> stored
            stored == computed -> stored
            else -> computed
        }
    }

    private fun syncCanonicalSolvingPositionV1(
        s: SudoState
    ): SudoState =
        s.copy(canonicalSolvingPositionV1 = computeCanonicalSolvingStepPositionV1(s))

    private fun resolveCanonicalSolvingStepPositionV1(
        s: SudoState
    ): CanonicalSolvingStepPositionV1? =
        authoritativeCanonicalSolvingStepPositionV1(s)

    private fun rawBoundaryBeforePosV1(
        s: SudoState
    ): CanonicalSolvingStepPositionV1? =
        resolveCanonicalSolvingStepPositionV1(s)

    private fun canonicalStageForKindV1(
        kind: CanonicalSolvingPositionKindV1
    ): StoryStage =
        when (kind) {
            CanonicalSolvingPositionKindV1.SETUP -> StoryStage.SETUP
            CanonicalSolvingPositionKindV1.CONFRONTATION -> StoryStage.CONFRONTATION
            CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
            CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> StoryStage.RESOLUTION
        }

    private fun checkpointToCanonicalBeforePosV1(
        checkpoint: RouteCheckpointV1
    ): CanonicalSolvingStepPositionV1? {
        val kind = checkpoint.canonicalPositionKind ?: return null
        val stepId = checkpoint.stepId?.takeIf { it.isNotBlank() } ?: return null

        val stage =
            checkpoint.storyStage?.takeIf {
                canonicalStageForKindV1(kind) == it
            } ?: canonicalStageForKindV1(kind)

        return CanonicalSolvingStepPositionV1(
            kind = kind,
            stepId = stepId,
            gridHash12 = checkpoint.gridHash12?.takeIf { it.isNotBlank() },
            stage = stage,
            headKind = checkpoint.canonicalHeadKind ?: CanonicalSolvingHeadKindV1.NONE,
            pendingKind = checkpoint.canonicalPendingKind ?: CanonicalSolvingPendingKindV1.NONE,
            focusAtomIndex = checkpoint.focusAtomIndex,
            atomsCount = checkpoint.atomsCount,
            readyForCommit = checkpoint.readyForCommit
        )
    }

    private fun isTrustedBoundaryBeforePosV1(
        pos: CanonicalSolvingStepPositionV1?
    ): Boolean {
        if (pos == null) return false
        if (pos.stepId.isNullOrBlank()) return false

        val expectedStage = canonicalStageForKindV1(pos.kind)
        if (pos.stage != expectedStage) return false

        return true
    }

    private fun isTrustedCheckpointBeforePosV1(
        pos: CanonicalSolvingStepPositionV1?
    ): Boolean =
        isTrustedBoundaryBeforePosV1(pos)

    private fun checkpointBoundaryBeforePosV1(
        s: SudoState
    ): CanonicalSolvingStepPositionV1? {
        val checkpoint = s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s)
        if (checkpoint == null) return null

        val checkpointPos = checkpointToCanonicalBeforePosV1(checkpoint)
        return checkpointPos?.takeIf { isTrustedCheckpointBeforePosV1(it) }
    }

    private fun classifyBoundaryGuardModeV1(
        sBeforePlan: SudoState,
        sAfterPlan: SudoState,
        userText: String,
        boundaryReturnAcceptedV1: Boolean = false,
        boundaryResumePolicyV1: BoundaryResumePolicyV1? = null
    ): BoundaryGuardModeV1 {
        if (sBeforePlan.phase != GridPhase.SOLVING || sAfterPlan.phase != GridPhase.SOLVING) {
            return BoundaryGuardModeV1.NORMAL_PROGRESS
        }

        if (boundaryReturnAcceptedV1) {
            return when (boundaryResumePolicyV1) {
                BoundaryResumePolicyV1.RESTORE_PAUSED_ROUTE ->
                    BoundaryGuardModeV1.RESTORE_PAUSED_ROUTE

                BoundaryResumePolicyV1.RECOMPUTE_FROM_CURRENT_TRUTH ->
                    BoundaryGuardModeV1.RECOMPUTE_FROM_CURRENT_TRUTH

                null ->
                    BoundaryGuardModeV1.NORMAL_PROGRESS
            }
        }

        return BoundaryGuardModeV1.NORMAL_PROGRESS
    }

    private fun chooseEffectiveBoundaryBeforeV1(
        mode: BoundaryGuardModeV1,
        rawBeforePos: CanonicalSolvingStepPositionV1?,
        checkpointBeforePos: CanonicalSolvingStepPositionV1?,
        restoredRouteBeforePos: CanonicalSolvingStepPositionV1?
    ): Triple<CanonicalSolvingStepPositionV1?, EffectiveBoundaryBeforeSourceV1, String> =
        when (mode) {
            BoundaryGuardModeV1.RESTORE_PAUSED_ROUTE -> {
                when {
                    isTrustedBoundaryBeforePosV1(restoredRouteBeforePos) ->
                        Triple(
                            restoredRouteBeforePos,
                            EffectiveBoundaryBeforeSourceV1.RESTORED_ROUTE_BEFORE,
                            "restored_route_before"
                        )

                    isTrustedBoundaryBeforePosV1(checkpointBeforePos) ->
                        Triple(
                            checkpointBeforePos,
                            EffectiveBoundaryBeforeSourceV1.CHECKPOINT_BEFORE,
                            "checkpoint_before_fallback"
                        )

                    else ->
                        Triple(
                            rawBeforePos,
                            EffectiveBoundaryBeforeSourceV1.RAW_BEFORE,
                            "raw_before_restore_fallback"
                        )
                }
            }

            BoundaryGuardModeV1.RECOMPUTE_FROM_CURRENT_TRUTH ->
                Triple(
                    null,
                    EffectiveBoundaryBeforeSourceV1.NONE_RECOMPUTE,
                    "same_step_guard_disabled_recompute"
                )

            BoundaryGuardModeV1.NORMAL_PROGRESS ->
                Triple(
                    rawBeforePos,
                    EffectiveBoundaryBeforeSourceV1.RAW_BEFORE,
                    "raw_before_default"
                )
        }

    private fun isBoundaryRecomputeReplanV1(
        boundaryReturnAcceptedV1: Boolean,
        boundaryResumePolicyV1: BoundaryResumePolicyV1?,
        context: BoundaryGuardContextV1
    ): Boolean =
        boundaryReturnAcceptedV1 &&
                boundaryResumePolicyV1 == BoundaryResumePolicyV1.RECOMPUTE_FROM_CURRENT_TRUTH &&
                context.mode == BoundaryGuardModeV1.RECOMPUTE_FROM_CURRENT_TRUTH &&
                !context.sameStepGuardEnabled

    private fun buildBoundaryGuardContextV1(
        sBeforePlan: SudoState,
        sAfterPlan: SudoState,
        userText: String,
        boundaryReturnAcceptedV1: Boolean = false,
        boundaryResumePolicyV1: BoundaryResumePolicyV1? = null
    ): BoundaryGuardContextV1 {
        val rawBeforePos = rawBoundaryBeforePosV1(sBeforePlan)
        val checkpointBeforePos = checkpointBoundaryBeforePosV1(sBeforePlan)
        val afterPos = resolveCanonicalSolvingStepPositionV1(sAfterPlan)
        val mode = classifyBoundaryGuardModeV1(
            sBeforePlan = sBeforePlan,
            sAfterPlan = sAfterPlan,
            userText = userText,
            boundaryReturnAcceptedV1 = boundaryReturnAcceptedV1,
            boundaryResumePolicyV1 = boundaryResumePolicyV1
        )

        // Series 4:
        // Until Series 5 rewires the final guard, "restored route before" is modeled
        // as the trusted paused-route checkpoint position for accepted restore turns.
        val restoredRouteBeforePos =
            if (mode == BoundaryGuardModeV1.RESTORE_PAUSED_ROUTE) {
                checkpointBeforePos
            } else {
                null
            }

        val (effectiveBeforePos, beforeSource, trustSource) =
            chooseEffectiveBoundaryBeforeV1(
                mode = mode,
                rawBeforePos = rawBeforePos,
                checkpointBeforePos = checkpointBeforePos,
                restoredRouteBeforePos = restoredRouteBeforePos
            )

        return BoundaryGuardContextV1(
            mode = mode,
            rawBeforePos = rawBeforePos,
            checkpointBeforePos = checkpointBeforePos,
            restoredRouteBeforePos = restoredRouteBeforePos,
            effectiveBeforePos = effectiveBeforePos,
            afterPos = afterPos,
            beforeSource = beforeSource,
            sameStepGuardEnabled = mode != BoundaryGuardModeV1.RECOMPUTE_FROM_CURRENT_TRUTH,
            trustSource = trustSource
        )
    }

    private fun canonicalPositionSummaryV1(
        pos: CanonicalSolvingStepPositionV1?
    ): String =
        if (pos == null) {
            "null"
        } else {
            listOfNotNull(
                "kind=${pos.kind.name}",
                "stage=${pos.stage.name}",
                pos.stepId?.let { "stepId=$it" },
                pos.gridHash12?.let { "gridHash12=$it" },
                "head=${pos.headKind.name}",
                "pending=${pos.pendingKind.name}",
                pos.focusAtomIndex?.let { "focus=$it" },
                pos.atomsCount?.let { "atoms=$it" },
                "readyForCommit=${pos.readyForCommit}"
            ).joinToString("|")
        }

    private fun routeCheckpointSummaryV1(
        checkpoint: RouteCheckpointV1?
    ): String =
        if (checkpoint == null) {
            "null"
        } else {
            listOfNotNull(
                "routeId=${checkpoint.routeId}",
                "phase=${checkpoint.phase.name}",
                checkpoint.stepId?.let { "stepId=$it" },
                checkpoint.storyStage?.let { "storyStage=${it.name}" },
                checkpoint.canonicalPositionKind?.let { "kind=${it.name}" },
                checkpoint.canonicalHeadKind?.let { "head=${it.name}" },
                checkpoint.canonicalPendingKind?.let { "pending=${it.name}" },
                checkpoint.gridHash12?.let { "gridHash12=$it" },
                checkpoint.focusAtomIndex?.let { "focus=${it}" },
                checkpoint.atomsCount?.let { "atoms=$it" },
                "readyForCommit=${checkpoint.readyForCommit}",
                "routeVersion=${checkpoint.routeVersion}"
            ).joinToString("|")
        }

    private fun softenBoundaryGuardRollbackV1(
        sBeforePlan: SudoState,
        sAfterPlan: SudoState,
        context: BoundaryGuardContextV1,
        boundaryReturnAcceptedV1: Boolean,
        boundaryResumePolicyV1: BoundaryResumePolicyV1?
    ): Pair<SudoState, Map<String, Any?>>? {
        if (!boundaryReturnAcceptedV1) return null
        if (boundaryResumePolicyV1 != BoundaryResumePolicyV1.RESTORE_PAUSED_ROUTE) return null
        if (context.mode != BoundaryGuardModeV1.RESTORE_PAUSED_ROUTE) return null

        val trustedBefore = context.effectiveBeforePos ?: return null

        val repairedStory =
            sAfterPlan.narrativeStory?.let { story ->
                if (story.stepId == trustedBefore.stepId) {
                    story.copy(
                        stage = trustedBefore.stage,
                        focusAtomIndex = trustedBefore.focusAtomIndex ?: story.focusAtomIndex,
                        readyForCommit = trustedBefore.readyForCommit
                    )
                } else {
                    story
                }
            }

        val repairedDetourState =
            sAfterPlan.detourState?.copy(isActive = false)

        val repairedOverlayOwner =
            if (sAfterPlan.activeOverlayOwnerV1 == OverlayOwnerV1.USER_OWNER) {
                OverlayOwnerV1.CHECKPOINT_RESTORE
            } else {
                sAfterPlan.activeOverlayOwnerV1
            }

        val repaired = syncCanonicalSolvingPositionV1(
            sAfterPlan.copy(
                detourState = repairedDetourState,
                narrativeStory = repairedStory,
                canonicalSolvingPositionV1 = trustedBefore,
                activeOverlayOwnerV1 = repairedOverlayOwner
            )
        )

        return repaired to mapOf(
            "final_boundary_guard_softened" to true,
            "guard_mode" to context.mode.name,
            "effective_before_source" to context.beforeSource.name,
            "repair_strategy" to "preserve_after_plan_restore_route_clamp_to_effective_before",
            "before_kind" to trustedBefore.kind.name,
            "same_step_id" to trustedBefore.stepId
        )
    }

    private fun storedCanonicalDriftViolationsV1(
        s: SudoState
    ): List<String> {
        if (s.phase != GridPhase.SOLVING) return emptyList()

        val stored = s.canonicalSolvingPositionV1
        val computed = computeCanonicalSolvingStepPositionV1(s)

        if (stored == null && computed == null) return emptyList()
        if (stored == null && computed != null) return listOf("stored_canonical_missing")
        if (stored != null && computed == null) return listOf("computed_canonical_missing")
        if (stored == computed) return emptyList()

        val issues = mutableListOf<String>()

        if (stored?.kind != computed?.kind) {
            issues += "stored_canonical_kind_mismatch"
        }
        if (stored?.stage != computed?.stage) {
            issues += "stored_canonical_stage_mismatch"
        }
        if (stored?.stepId != computed?.stepId) {
            issues += "stored_canonical_step_id_mismatch"
        }
        if (stored?.gridHash12 != computed?.gridHash12) {
            issues += "stored_canonical_grid_hash_mismatch"
        }
        if (stored?.headKind != computed?.headKind) {
            issues += "stored_canonical_head_mismatch"
        }
        if (stored?.pendingKind != computed?.pendingKind) {
            issues += "stored_canonical_pending_mismatch"
        }
        if (stored?.focusAtomIndex != computed?.focusAtomIndex) {
            issues += "stored_canonical_focus_atom_mismatch"
        }
        if (stored?.atomsCount != computed?.atomsCount) {
            issues += "stored_canonical_atoms_count_mismatch"
        }
        if (stored?.readyForCommit != computed?.readyForCommit) {
            issues += "stored_canonical_ready_for_commit_mismatch"
        }

        return issues
    }

    private fun validateCanonicalSolvingPositionV1(
        s: SudoState,
        pos: CanonicalSolvingStepPositionV1?
    ): List<String> {
        if (s.phase != GridPhase.SOLVING || pos == null) return emptyList()

        val issues = mutableListOf<String>()

        when (pos.kind) {
            CanonicalSolvingPositionKindV1.SETUP -> {
                if (pos.stage != StoryStage.SETUP) {
                    issues += "setup_position_requires_setup_stage"
                }
                if (pos.pendingKind == CanonicalSolvingPendingKindV1.APPLY_HINT_NOW ||
                    pos.pendingKind == CanonicalSolvingPendingKindV1.AFTER_RESOLUTION
                ) {
                    issues += "setup_position_cannot_use_resolution_pending"
                }
                if (pos.headKind == CanonicalSolvingHeadKindV1.COMMIT_DECISION ||
                    pos.headKind == CanonicalSolvingHeadKindV1.COMMIT_APPLY ||
                    pos.headKind == CanonicalSolvingHeadKindV1.POST_COMMIT_CHOICE
                ) {
                    issues += "setup_position_should_not_have_resolution_head"
                }
            }

            CanonicalSolvingPositionKindV1.CONFRONTATION -> {
                if (pos.stage != StoryStage.CONFRONTATION) {
                    issues += "confrontation_position_requires_confrontation_stage"
                }
                if (pos.pendingKind == CanonicalSolvingPendingKindV1.APPLY_HINT_NOW ||
                    pos.pendingKind == CanonicalSolvingPendingKindV1.AFTER_RESOLUTION
                ) {
                    issues += "confrontation_position_cannot_use_resolution_pending"
                }
                if (pos.headKind == CanonicalSolvingHeadKindV1.POST_COMMIT_CHOICE) {
                    issues += "confrontation_position_should_not_have_post_commit_head"
                }
            }

            CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT -> {
                if (pos.stage != StoryStage.RESOLUTION) {
                    issues += "resolution_commit_position_requires_resolution_stage"
                }
                if (pos.pendingKind == CanonicalSolvingPendingKindV1.SOLVE_INTRO_ACTION) {
                    issues += "resolution_commit_position_should_not_keep_solve_intro_action"
                }
            }

            CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> {
                if (pos.stage != StoryStage.RESOLUTION) {
                    issues += "resolution_post_commit_position_requires_resolution_stage"
                }
                if (pos.pendingKind == CanonicalSolvingPendingKindV1.SOLVE_INTRO_ACTION) {
                    issues += "resolution_post_commit_position_should_not_keep_solve_intro_action"
                }
            }
        }

        if (pos.kind == CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT &&
            pos.headKind == CanonicalSolvingHeadKindV1.ATOM_WALK
        ) {
            issues += "post_commit_position_should_not_have_atom_walk_head"
        }

        if (pos.kind == CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT &&
            pos.headKind == CanonicalSolvingHeadKindV1.POST_COMMIT_CHOICE
        ) {
            issues += "resolution_commit_position_should_not_have_post_commit_head"
        }

        return issues
    }

    private fun canonicalBoundaryOrderV1(
        kind: CanonicalSolvingPositionKindV1
    ): Int =
        when (kind) {
            CanonicalSolvingPositionKindV1.SETUP -> 0
            CanonicalSolvingPositionKindV1.CONFRONTATION -> 1
            CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT -> 2
            CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> 3
        }

    private fun isIllegalCanonicalBoundaryTransitionV1(
        beforePos: CanonicalSolvingStepPositionV1?,
        afterPos: CanonicalSolvingStepPositionV1?,
        userText: String,
        allowRepeat: Boolean = false
    ): Boolean {
        if (beforePos == null || afterPos == null) return false
        if (beforePos.stepId.isNullOrBlank()) return false
        if (beforePos.stepId != afterPos.stepId) return false

        if (allowRepeat || userExplicitlyAskedRepeatV1(userText)) return false

        val beforeOrder = canonicalBoundaryOrderV1(beforePos.kind)
        val afterOrder = canonicalBoundaryOrderV1(afterPos.kind)

        if (afterOrder == beforeOrder) return false

        if (afterOrder < beforeOrder) {
            return true
        }

        if (afterOrder > beforeOrder + 1) {
            return true
        }

        if (
            beforePos.kind == CanonicalSolvingPositionKindV1.CONFRONTATION &&
            afterPos.kind == CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT &&
            !beforePos.readyForCommit
        ) {
            return true
        }

        return false
    }

    private fun deriveSolvingRailStateV1(
        phase: GridPhase,
        solvingHead: AppAgendaItem.Solving?,
        pending: Pending?,
        story: NarrativeStoryContext?,
        activeRoute: ActiveRouteContext?,
        solveStepId: String?,
        coachPlanStepId: String?,
        solveStepGridHash12: String?,
        coachPlanGridHash12: String?,
        pendingSolveStepAutocoach: PendingSolveStepAutocoach?,
        solveStepStatus: SolveStepStatus,
        activeTurnOwnerV1: TurnOwnerV1
    ): SolvingRailStateV1? {
        if (phase != GridPhase.SOLVING) return null

        val stage: StoryStage? =
            story?.stage ?: when (pending) {
                is Pending.AfterResolution -> StoryStage.RESOLUTION
                is Pending.ApplyHintNow -> StoryStage.RESOLUTION
                is Pending.SolveIntroAction -> pending.stage
                else -> storyStageFromSolvingHeadV1(solvingHead)
            }

        val hasNextStepInFlight =
            solveStepStatus == SolveStepStatus.COMPUTING &&
                    pendingSolveStepAutocoach?.reason == "solve_next_step_requested"

        val boundary =
            when {
                hasNextStepInFlight ->
                    SolvingRailBoundaryV1.NEXT_STEP_IN_FLIGHT

                pending is Pending.AfterResolution ||
                        solvingHead is AppAgendaItem.Solving.PostCommitChoice ->
                    SolvingRailBoundaryV1.POST_COMMIT

                pending is Pending.ApplyHintNow ||
                        solvingHead is AppAgendaItem.Solving.CommitDecision ||
                        solvingHead is AppAgendaItem.Solving.CommitApply ->
                    SolvingRailBoundaryV1.COMMIT_DECISION

                stage == StoryStage.CONFRONTATION ->
                    SolvingRailBoundaryV1.CONFRONTATION

                stage == StoryStage.SETUP ->
                    SolvingRailBoundaryV1.SETUP

                else ->
                    SolvingRailBoundaryV1.NONE
            }

        val owner =
            when {
                activeTurnOwnerV1 == TurnOwnerV1.USER_OWNER &&
                        pending is Pending.UserAgendaBridge ->
                    SolvingRailOwnerV1.USER_DETOUR

                phase == GridPhase.SOLVING ->
                    SolvingRailOwnerV1.APP_MAINLINE

                else ->
                    SolvingRailOwnerV1.NONE
            }

        return SolvingRailStateV1(
            stepId = authoritativeStepIdV1(
                solvingHead = solvingHead,
                story = story,
                activeRoute = activeRoute,
                solveStepId = solveStepId,
                coachPlanStepId = coachPlanStepId
            ),
            gridHash12 = authoritativeGridHash12V1(
                solvingHead = solvingHead,
                story = story,
                activeRoute = activeRoute,
                solveStepGridHash12 = solveStepGridHash12,
                coachPlanGridHash12 = coachPlanGridHash12
            )?.take(12),
            stage = stage,
            boundary = boundary,
            owner = owner,
            journeyStepNumber = activeRoute?.journeyStepNumber,
            hasNextStepInFlight = hasNextStepInFlight
        )
    }

    private fun effectiveSolvingRailStateV1(s: SudoState): SolvingRailStateV1? =
        s.solvingRailStateV1 ?: deriveSolvingRailStateV1(
            phase = s.phase,
            solvingHead = currentQueuedSolvingHead(s),
            pending = s.pending,
            story = s.narrativeStory,
            activeRoute = s.activeRouteContext,
            solveStepId = s.solveStepId,
            coachPlanStepId = s.coachPlanStepId,
            solveStepGridHash12 = s.solveStepGridHash12,
            coachPlanGridHash12 = s.coachPlanGridHash12,
            pendingSolveStepAutocoach = s.pendingSolveStepAutocoach,
            solveStepStatus = s.solveStepStatus,
            activeTurnOwnerV1 = s.activeTurnOwnerV1
        )

    private fun authoritativeStoryStageV1(
        solvingHead: AppAgendaItem.Solving?,
        pending: Pending?,
        story: NarrativeStoryContext?
    ): StoryStage? =
    // Architectural rule:
    // story stage is the only stage authority.
        // Pending / solving head may influence execution details, but never stage.
        story?.stage

    private fun isReadyForNextStepBoundaryV1(
        s: SudoState
    ): Boolean {
        if (s.phase != GridPhase.SOLVING) return false

        val rail = effectiveSolvingRailStateV1(s)
        val revealAppliedOnBoard = isRevealAlreadyAppliedOnBoardV1(s)

        return when {
            rail?.boundary == SolvingRailBoundaryV1.POST_COMMIT -> true
            rail?.boundary == SolvingRailBoundaryV1.NEXT_STEP_IN_FLIGHT -> true

            // Self-heal stale commit-boundary state when board truth already
            // shows the reveal has landed.
            rail?.boundary == SolvingRailBoundaryV1.COMMIT_DECISION && revealAppliedOnBoard -> true

            s.pending is Pending.AfterResolution -> true
            s.pending is Pending.ApplyHintNow && revealAppliedOnBoard -> true

            currentQueuedSolvingHead(s) is AppAgendaItem.Solving.PostCommitChoice -> true
            currentQueuedSolvingHead(s) is AppAgendaItem.Solving.CommitApply && revealAppliedOnBoard -> true
            currentQueuedSolvingHead(s) is AppAgendaItem.Solving.CommitDecision && revealAppliedOnBoard -> true

            else -> false
        }
    }

    private fun isExplicitNextStepAutocoachV1(
        s: SudoState,
        incomingGridHash12: String? = null
    ): Boolean {
        val latch = s.pendingSolveStepAutocoach ?: return false

        val kindOk = latch.requestKind == SolveStepRequestKindV1.NEXT_STEP_CONTINUATION
        val allowOk = latch.allowReplaceLockedStep
        val hashOk =
            incomingGridHash12 == null ||
                    latch.gridHash12.take(12) == incomingGridHash12.take(12)

        return kindOk && allowOk && hashOk
    }

    private fun shouldDeferSolveProgressionForUserDetourV1(
        s: SudoState
    ): Boolean {
        if (s.phase != GridPhase.SOLVING) return false

        val ownerBlocks =
            s.activeTurnOwnerV1 == TurnOwnerV1.USER_OWNER

        val pendingBlocks =
            s.pending is Pending.UserAgendaBridge

        val queueBlocks =
            s.userAgendaQueue.isNotEmpty()

        return ownerBlocks || pendingBlocks || queueBlocks
    }

    private fun isSolveStepLockedForResolutionV1(
        s: SudoState
    ): Boolean {
        if (s.phase != GridPhase.SOLVING) return false

        val rail = effectiveSolvingRailStateV1(s)

        return when (rail?.boundary) {
            SolvingRailBoundaryV1.COMMIT_DECISION,
            SolvingRailBoundaryV1.POST_COMMIT,
            SolvingRailBoundaryV1.NEXT_STEP_IN_FLIGHT -> true

            else -> false
        }
    }



