    private fun emitControlTruthInvariantAuditV1(
        turnId: Long,
        tickId: Int,
        sAfter: SudoState,
        replyDemand: ReplyDemandResolutionV1,
        facts: List<FactBundleV1>,
        storyHeader: ReplyStoryCtxV1?
    ) {
        runCatching {
            val solvingHead = currentQueuedSolvingHead(sAfter)
            val authoritativeStage =
                authoritativeStoryStageV1(
                    solvingHead = solvingHead,
                    pending = sAfter.pending,
                    story = sAfter.narrativeStory
                )?.name

            val authoritativeStepId =
                authoritativeStepIdV1(
                    solvingHead = solvingHead,
                    story = sAfter.narrativeStory,
                    activeRoute = sAfter.activeRouteContext,
                    solveStepId = sAfter.solveStepId,
                    coachPlanStepId = sAfter.coachPlanStepId
                )

            val repairLeaks = repairForbiddenFactTypeNamesV1(facts)
            val repairLeakPresent =
                replyDemand.category == ReplyDemandCategoryV1.REPAIR_CONTRADICTION &&
                        repairLeaks.isNotEmpty()

            ConversationTelemetry.emitPolicyTrace(
                tag = "CONTROL_TRUTH_INVARIANT_AUDIT",
                data = mapOf(
                    "session_id" to sAfter.sessionId,
                    "turn_id" to turnId,
                    "tick_id" to tickId,
                    "phase" to sAfter.phase.name,
                    "owner" to sAfter.activeTurnOwnerV1.name,
                    "turn_authority_owner" to sAfter.activeTurnAuthorityDecisionV1.owner.name,
                    "turn_authority_reason" to sAfter.activeTurnAuthorityDecisionV1.reason,
                    "turn_authority_evidence" to TurnAuthorityArbiterV1.evidenceSummary(sAfter.activeTurnAuthorityDecisionV1),
                    "turn_pending_status" to sAfter.activeTurnAuthorityDecisionV1.pendingAuthorityStatus.name,
                    "turn_resumed_pending_kind" to (sAfter.activeTurnAuthorityDecisionV1.resumedPendingKind ?: "null"),
                    "turn_route_return_allowed" to sAfter.activeTurnAuthorityDecisionV1.routeReturnAllowed,
                    "route_boundary_status" to sAfter.activeRouteBoundaryDecisionV1.status.name,
                    "route_boundary_reason" to sAfter.activeRouteBoundaryDecisionV1.reason,
                    "route_boundary_from" to (sAfter.activeRouteBoundaryDecisionV1.fromCheckpointKind ?: "null"),
                    "route_boundary_to" to (sAfter.activeRouteBoundaryDecisionV1.toCheckpointKind ?: "null"),
                    "route_boundary_paused" to sAfter.activeRouteBoundaryDecisionV1.routePaused,
                    "route_boundary_advance_allowed" to sAfter.activeRouteBoundaryDecisionV1.advanceAllowed,
                    "pending_after" to (sAfter.pending?.javaClass?.simpleName ?: "null"),
                    "queue_head" to (solvingHead?.javaClass?.simpleName ?: "null"),

                    "reply_demand_category" to when (replyDemand.category) {
                        ReplyDemandCategoryV1.CONFIRMING_VALIDATION_SUMMARY -> "CONFIRM_STATUS_SUMMARY"
                        ReplyDemandCategoryV1.FREE_TALK_IN_GRID_SESSION -> "META_STATE_ANSWER"
                        else -> replyDemand.category.name
                    },
                    "raw_reply_demand_category" to replyDemand.category.name,
                    "reply_demand_story_stage" to (replyDemand.storyStage ?: "null"),

                    "authoritative_story_stage" to (authoritativeStage ?: "null"),
                    "story_header_stage" to (storyHeader?.stage ?: "null"),
                    "authoritative_step_id" to (authoritativeStepId ?: "null"),
                    "story_header_step_id" to (storyHeader?.stepId ?: "null"),
                    "resolution_lock_active" to isSolveStepLockedForResolutionV1(sAfter).toString(),
                    "repair_leak_present" to repairLeakPresent.toString(),
                    "repair_leak_fact_types" to if (repairLeaks.isEmpty()) "none" else repairLeaks.joinToString(","),
                    "stage_matches_authority" to (
                            (replyDemand.storyStage == null || replyDemand.storyStage == authoritativeStage) &&
                                    (storyHeader?.stage == null || storyHeader.stage == authoritativeStage)
                            ).toString(),
                    "step_matches_authority" to (
                            storyHeader?.stepId == null || storyHeader.stepId == authoritativeStepId
                            ).toString()
                )
            )
        }
    }

    private fun touchUserAgendaItemV1(
        item: UserAgendaItem,
        status: UserAgendaStatusV1? = null,
        lastTouchedTurnSeq: Long? = null
    ): UserAgendaItem =
        when (item) {
            is UserAgendaItem.Clarification -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.ProofChallenge -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.CandidateStateQuery -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.TargetCellQuery -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.NeighborCellQuery -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.UserReasoningCheck -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.AlternativeTechniqueQuery -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.RouteComparisonQuery -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.RouteControl -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.OverlayControl -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )

            is UserAgendaItem.GeneralQuestion -> item.copy(
                status = status ?: item.status,
                lastTouchedTurnSeq = lastTouchedTurnSeq ?: item.lastTouchedTurnSeq
            )
        }

    private fun markHeadUserAgendaPartiallyAnsweredV1(
        q: List<UserAgendaItem>,
        turnSeq: Long
    ): List<UserAgendaItem> {
        if (q.isEmpty()) return q
        val head = q.first()
        if (!head.allowsFollowUp) return q.drop(1)

        val updated = touchUserAgendaItemV1(
            item = head,
            status = UserAgendaStatusV1.PARTIALLY_ANSWERED,
            lastTouchedTurnSeq = turnSeq
        )
        return listOf(updated) + q.drop(1)
    }

    private fun resolveHeadUserAgendaV1(
        q: List<UserAgendaItem>,
        turnSeq: Long
    ): List<UserAgendaItem> {
        if (q.isEmpty()) return q
        val updated = touchUserAgendaItemV1(
            item = q.first(),
            status = UserAgendaStatusV1.RESOLVED,
            lastTouchedTurnSeq = turnSeq
        )
        return q.drop(1)
    }

    private fun flushUserDetourBacklogForRouteReturnV1(
        q: List<UserAgendaItem>,
        turnSeq: Long
    ): List<UserAgendaItem> {
        if (q.isEmpty()) return q

        q.forEach { item ->
            touchUserAgendaItemV1(
                item = item,
                status = UserAgendaStatusV1.RESOLVED,
                lastTouchedTurnSeq = turnSeq
            )
        }

        return emptyList()
    }

    private fun resolveHeadUserAgendaIfSatisfiedByOpsV1(
        q: List<UserAgendaItem>,
        ops: List<PlannedOpV1>,
        turnSeq: Long
    ): List<UserAgendaItem> {
        if (q.isEmpty() || ops.isEmpty()) return q

        val head = q.first()

        return when (head) {
            is UserAgendaItem.Clarification -> {
                val clarificationSatisfiedByOps =
                    ClarificationKernelV1.isClarificationSatisfiedByOps(
                        head = head,
                        ops = ops
                    )

                if (clarificationSatisfiedByOps) {
                    resolveHeadUserAgendaV1(q, turnSeq)
                } else {
                    q
                }
            }

            is UserAgendaItem.ProofChallenge,
            is UserAgendaItem.CandidateStateQuery,
            is UserAgendaItem.TargetCellQuery,
            is UserAgendaItem.NeighborCellQuery,
            is UserAgendaItem.UserReasoningCheck,
            is UserAgendaItem.AlternativeTechniqueQuery,
            is UserAgendaItem.RouteComparisonQuery,
            is UserAgendaItem.RouteControl,
            is UserAgendaItem.OverlayControl,
            is UserAgendaItem.GeneralQuestion -> q
        }
    }

    private fun isPersistentUserAgendaItemV1(
        item: UserAgendaItem?
    ): Boolean =
        item is UserAgendaItem.Clarification

    private fun pruneNonPersistentUserAgendaItemsV1(
        q: List<UserAgendaItem>
    ): List<UserAgendaItem> =
        q.filter { isPersistentUserAgendaItemV1(it) }


