        if (detourState == null) return null
        if (item == null) {
            return detourState.copy(
                semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                activeAgendaId = null,
                activeAgendaKind = null,
                proofAskKind = null,
                proofLaneHint = null,
                proofRivalCellRef = null,
                proofRivalDigit = null,
                proofClaimedTechniqueId = null,
                proofObjectHint = null,
                targetAskKind = null,
                candidateAskKind = null,
