                detourState.copy(
                    semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                    activeAgendaId = item.id,
                    activeAgendaKind = item::class.java.simpleName ?: "ProofChallenge",
                    proofAskKind = item.askKind,
                    proofLaneHint = item.laneHint,
                    proofRivalCellRef = item.rivalCellRef,
                    proofRivalDigit = item.rivalDigit,
                    proofClaimedTechniqueId = item.claimedTechniqueId,
                    proofObjectHint = item.proofObjectHint,
