                    neighborAskKind = null
                )

            is UserAgendaItem.TargetCellQuery ->
                detourState.copy(
                    semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                    activeAgendaId = item.id,
                    activeAgendaKind = item::class.java.simpleName ?: "TargetCellQuery",
                    proofAskKind = null,
                    proofLaneHint = null,
                    proofRivalCellRef = null,
                    proofRivalDigit = null,
                    proofClaimedTechniqueId = null,
                    proofObjectHint = null,
                    targetAskKind = item.askKind,
                    candidateAskKind = null,
                    neighborAskKind = null
                )

            is UserAgendaItem.CandidateStateQuery ->
                detourState.copy(
                    semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                    activeAgendaId = item.id,
                    activeAgendaKind = item::class.java.simpleName ?: "CandidateStateQuery",
                    proofAskKind = null,
                    proofLaneHint = null,
                    proofRivalCellRef = null,
                    proofRivalDigit = null,
                    proofClaimedTechniqueId = null,
                    proofObjectHint = null,
                    targetAskKind = null,
                    candidateAskKind = item.askKind,
                    neighborAskKind = null
                )

            is UserAgendaItem.NeighborCellQuery ->
                detourState.copy(
                    semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                    activeAgendaId = item.id,
                    activeAgendaKind = item::class.java.simpleName ?: "NeighborCellQuery",
                    proofAskKind = null,
                    proofLaneHint = null,
                    proofRivalCellRef = null,
                    proofRivalDigit = null,
                    proofClaimedTechniqueId = null,
                    proofObjectHint = null,
                    targetAskKind = null,
                    candidateAskKind = null,
                    neighborAskKind = item.askKind
                )

            else ->
                detourState.copy(
                    semanticSource = DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE,
                    activeAgendaId = item.id,
                    activeAgendaKind = item::class.java.simpleName ?: "UserAgenda",
