    private fun detourTurnRecordFromStateV1(
        detourState: DetourStateV1?,
        turnSeq: Long
    ): DetourTurnRecordV1? {
        val ds = detourState ?: return null
        if (ds.questionClass == null) return null

        return DetourTurnRecordV1(
            turnSeq = turnSeq,
            questionClass = ds.questionClass,
            agendaId = ds.activeAgendaId,
            agendaKind = ds.activeAgendaKind,
            requestedCell = ds.requestedCell,
            requestedDigit = ds.requestedDigit,
            requestedSearchScope = ds.requestedSearchScope,
            answerState = ds.answerState,
            failureReason = ds.answerFailureReason,
            anchorStepId = ds.anchorStepId,
            anchorStage = ds.anchorStage
        )
    }

    private fun appendDetourTurnHistoryV1(
        history: List<DetourTurnRecordV1>,
        record: DetourTurnRecordV1?
    ): List<DetourTurnRecordV1> {
        if (record == null) return history
        val withoutSameTurn = history.filterNot { it.turnSeq == record.turnSeq }
        return (withoutSameTurn + record).takeLast(24)
    }

    private fun detourAgendaKindFromQuestionClassV1(
        klass: DetourQuestionClassV1?
    ): String =
        when (klass) {
            DetourQuestionClassV1.PROOF_CHALLENGE -> "proof_challenge"
            DetourQuestionClassV1.TARGET_CELL_QUERY -> "target_cell_query"
            DetourQuestionClassV1.NEIGHBOR_CELL_QUERY -> "neighbor_cell_query"
            DetourQuestionClassV1.CANDIDATE_STATE_QUERY -> "candidate_state_query"
            DetourQuestionClassV1.USER_REASONING_CHECK -> "user_reasoning_check"
            DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY -> "alternative_technique_query"
            DetourQuestionClassV1.ROUTE_COMPARISON_QUERY -> "route_comparison_query"
            DetourQuestionClassV1.STEP_CLARIFICATION -> "step_clarification"
            DetourQuestionClassV1.ROUTE_CONTROL -> "route_control"
            DetourQuestionClassV1.OVERLAY_CONTROL -> "overlay_control"
            DetourQuestionClassV1.GENERAL_QUESTION -> "general_question"
            DetourQuestionClassV1.REPAIR_QUESTION -> "repair_question"
            DetourQuestionClassV1.UNSUPPORTED_DETOUR -> "unsupported_detour"
            null -> "detour"
        }

    private fun defaultPromptForDetourStateV1(
        ds: DetourStateV1
    ): String {
        val cellRef = ds.requestedCell?.takeIf { it.isNotBlank() } ?: ds.anchorTargetCell
        val digit = ds.requestedDigit
        val scope = ds.requestedSearchScope?.takeIf { it.isNotBlank() }

        return when (ds.questionClass) {
            DetourQuestionClassV1.PROOF_CHALLENGE ->
                when {
                    !cellRef.isNullOrBlank() && digit != null ->
                        "Answer the user’s proof question about why $cellRef cannot be $digit."
                    !cellRef.isNullOrBlank() ->
                        "Answer the user’s proof question about $cellRef."
                    !scope.isNullOrBlank() && digit != null ->
                        "Answer the user’s proof question about digit $digit in $scope."
                    else ->
                        "Answer the user’s proof question."
                }

            DetourQuestionClassV1.TARGET_CELL_QUERY ->
                "Answer the user’s target-cell question${cellRef?.let { " about $it" } ?: ""}."

            DetourQuestionClassV1.NEIGHBOR_CELL_QUERY ->
                "Answer the user’s nearby-cell question${cellRef?.let { " about $it" } ?: ""}."

            DetourQuestionClassV1.CANDIDATE_STATE_QUERY ->
                when {
                    !cellRef.isNullOrBlank() ->
                        "Answer the user’s candidate-state question for $cellRef."
                    !scope.isNullOrBlank() && digit != null ->
                        "Answer the user’s candidate-location question for digit $digit in $scope."
                    !scope.isNullOrBlank() ->
                        "Answer the user’s candidate-map question for $scope."
                    else ->
                        "Answer the user’s candidate-state question."
                }

            DetourQuestionClassV1.USER_REASONING_CHECK ->
                "Check the user’s reasoning${cellRef?.let { " for $it" } ?: ""} and answer directly."

            DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY ->
                "Answer the user’s alternative-technique question truthfully and locally."

            DetourQuestionClassV1.ROUTE_COMPARISON_QUERY ->
                "Compare the user’s idea to the coached route and answer whether they are the same route or a different one."

            DetourQuestionClassV1.STEP_CLARIFICATION ->
                "Clarify the current coached step for the user."

            DetourQuestionClassV1.ROUTE_CONTROL ->
                "Handle the user’s route-control request."

            DetourQuestionClassV1.OVERLAY_CONTROL ->
                "Answer the user while respecting the requested visual focus."

            DetourQuestionClassV1.REPAIR_QUESTION ->
                "Repair the current conversation state and answer the user safely."

            DetourQuestionClassV1.UNSUPPORTED_DETOUR ->
                "Answer the user’s question conservatively and truthfully."

            DetourQuestionClassV1.GENERAL_QUESTION, null ->
                "Answer the user’s question."
        }
    }

    private fun pendingFromActiveDetourStateV1(
        ds: DetourStateV1?
    ): Pending.UserAgendaBridge? {
        val detourState = ds ?: return null
        if (!detourState.isActive) return null
        if (detourState.semanticSource != DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE) return null

        val primaryCellRef =
            detourState.requestedCell?.takeIf { it.isNotBlank() }
                ?: detourState.anchorTargetCell?.takeIf { it.isNotBlank() }

        val idx = parseCellRefToIndexV1(primaryCellRef)
        val rowHint = idx?.let { (it / 9) + 1 }
        val colHint = idx?.let { (it % 9) + 1 }

        val expectedAnswerKind =
            when (detourState.questionClass) {
                DetourQuestionClassV1.USER_REASONING_CHECK -> "YES_NO_OR_FREEFORM"
                else -> "FREEFORM_STRUCTURED"
            }

        return Pending.UserAgendaBridge(
            userAgendaId = detourState.activeAgendaId
                ?: "detour:${detourState.questionClass?.name ?: "UNKNOWN"}",
            agendaKind = detourState.activeAgendaKind
                ?: detourAgendaKindFromQuestionClassV1(detourState.questionClass),
            prompt = defaultPromptForDetourStateV1(detourState),
            expectedAnswerKind = expectedAnswerKind,
            rowHint = rowHint,
            colHint = colHint,
            digitHint = detourState.requestedDigit,
            cellRef = primaryCellRef,
            agendaStatus = detourState.answerState.name,
            allowsFollowUp = false,
            options = listOf(PendingChoiceId.RETURN_TO_ROUTE)
        )
    }

    private fun reconcilePendingFromActiveDetourStateV1(
        pending: Pending?,
        detourState: DetourStateV1?
    ): Pending? {
        val detourPending = pendingFromActiveDetourStateV1(detourState)
        return detourPending ?: pending
    }

    private fun emitDetourIsolationInvariantV1(
        s: SudoState,
        stage: String
    ) {
        val ds = s.detourState
        val pending = s.pending

        val activeDetour = ds?.isActive == true
        val bridgeActive = pending is Pending.UserAgendaBridge
        val nonPersistentHeadsPresent =
            s.userAgendaQueue.any { !isPersistentUserAgendaItemV1(it) }

        val expectedAgendaId = ds?.activeAgendaId
        val actualAgendaId = (pending as? Pending.UserAgendaBridge)?.userAgendaId

        val ok =
            if (activeDetour && bridgeActive) {
                !nonPersistentHeadsPresent &&
                        (expectedAgendaId == null || expectedAgendaId == actualAgendaId) &&
                        ds?.semanticSource == DetourSemanticSourceV1.CURRENT_TURN_DETOUR_STATE
            } else {
                !nonPersistentHeadsPresent
            }

        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "DETOUR_TRANSACTION_ISOLATION_INVARIANT_V1",
                data = mapOf(
                    "turn_id" to s.turnSeq,
                    "stage" to stage,
                    "ok" to ok,
                    "active_detour" to activeDetour,
                    "bridge_active" to bridgeActive,
                    "detour_semantic_source" to (ds?.semanticSource?.name ?: "null"),
                    "detour_question_class" to (ds?.questionClass?.name ?: "null"),
                    "expected_agenda_id" to (expectedAgendaId ?: "null"),
                    "actual_bridge_agenda_id" to (actualAgendaId ?: "null"),
                    "non_persistent_heads_present" to nonPersistentHeadsPresent,
                    "user_queue_size" to s.userAgendaQueue.size,
                    "pending_type" to (pending?.javaClass?.simpleName ?: "null")
                )
            )
        }
    }

    private fun isLikelyFollowUpToUserAgendaHeadV1(
        env: IntentEnvelopeV1,
        head: UserAgendaItem?
    ): Boolean {
        if (head !is UserAgendaItem.Clarification) return false
        if (env.intents.isEmpty()) return false

        val types = env.intents.map { it.type }.toSet()

        if (
            types.contains(IntentTypeV1.SOLVE_CONTINUE) ||
            types.contains(IntentTypeV1.REQUEST_REVALIDATE) ||
            types.contains(IntentTypeV1.REQUEST_ONLY_VALIDATE)
        ) {
            return false
        }

        val explicitAddress = env.intents.any { it.addressesUserAgendaIdCompat() == head.id }
        if (explicitAddress) return true

        return true
    }

    private fun hasActiveClarificationInQueueV1(
        q: List<UserAgendaItem>
    ): Boolean =
        q.any {
            it is UserAgendaItem.Clarification &&
                    it.status != UserAgendaStatusV1.RESOLVED &&
                    it.status != UserAgendaStatusV1.CANCELLED
        }

    private fun clarificationStillOwnsTurnV1(
        q: List<UserAgendaItem>,
        env: IntentEnvelopeV1,
        newPending: Pending?
    ): Boolean {
        val head = q.firstOrNull()
        val activeClarification =
            head as? UserAgendaItem.Clarification
                ?: q.firstOrNull {
                    it is UserAgendaItem.Clarification &&
                            it.status != UserAgendaStatusV1.RESOLVED &&
                            it.status != UserAgendaStatusV1.CANCELLED
                } as? UserAgendaItem.Clarification

        if (activeClarification == null) return false

        if (newPending is Pending.AskClarification) return true

        if (isLikelyFollowUpToUserAgendaHeadV1(env, activeClarification)) return true

        return activeClarification.status == UserAgendaStatusV1.OPEN ||
                activeClarification.status == UserAgendaStatusV1.PARTIALLY_ANSWERED
    }



    private fun resolveTurnOwnerV1(
        userAgendaQueue: List<UserAgendaItem>,
        appAgendaQueue: List<AppAgendaItem>
    ): TurnOwnerV1 =
        when {
            userAgendaQueue.isNotEmpty() -> TurnOwnerV1.USER_OWNER
            appAgendaQueue.isNotEmpty() -> TurnOwnerV1.APP_OWNER
            else -> TurnOwnerV1.NONE
        }





    private fun routeReturnPromptForPendingV1(pending: Pending?): String =
        when (pending) {
            is Pending.SolveIntroAction -> pending.prompt
            is Pending.AfterResolution -> pending.prompt
            is Pending.ApplyHintNow -> pending.prompt
            is Pending.UserAgendaBridge -> pending.prompt
            is Pending.ReturnToRoute -> pending.prompt
            else -> "We can return to the paused route whenever you're ready."
        }

    /**
     * Constitutional pending reconciliation.
     *
     * Pending never owns the turn.
     * It survives only in ways allowed by the sovereign owner:
     *  - detour may suspend it
     *  - repair may subordinate it
     *  - route-jump may transform it
     *  - app-route may continue it
     *
     * Must-pass regression hooks:
     *  - DETOUR_SUSPENDS_ROUTE_CONTINUATION_PENDING
     *  - ROUTE_JUMP_TRANSFORMS_ROUTE_CONTINUATION_PENDING
     *  - REPAIR_SUBORDINATES_ROUTE_CONTINUATION_PENDING
     *  - APP_ROUTE_CAN_KEEP_PENDING_ACTIVE
     */
    private fun reconcilePendingAfterAuthorityV1(
        pending: Pending?,
        authorityDecision: TurnAuthorityDecisionV1
    ): Pending? {
        if (pending == null) return null

        return when (authorityDecision.pendingAuthorityStatus) {
            PendingAuthorityStatusV1.SUSPENDED,
            PendingAuthorityStatusV1.SUBORDINATED ->
                when (pending) {
                    is Pending.ReturnToRoute -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to pending.javaClass.simpleName,
                                "change_kind" to "kept_existing_return_to_route"
                            )
                        )
                        pending
                    }

                    is Pending.SolveIntroAction,
                    is Pending.AfterResolution,
                    is Pending.ApplyHintNow,
                    is Pending.UserAgendaBridge -> {
                        val wrapped = Pending.ReturnToRoute(
                            resumePending = pending,
                            prompt = routeReturnPromptForPendingV1(pending)
                        )
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to wrapped.javaClass.simpleName,
                                "change_kind" to "wrapped_as_return_to_route"
                            )
                        )
                        wrapped
                    }

                    else -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to pending.javaClass.simpleName,
                                "change_kind" to "left_unchanged_under_suspension_or_subordination"
                            )
                        )
                        pending
                    }
                }

            PendingAuthorityStatusV1.TRANSFORMED ->
                when (pending) {
                    is Pending.ReturnToRoute -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to (pending.resumePending?.javaClass?.simpleName ?: "null"),
                                "change_kind" to "resumed_return_to_route_payload"
                            )
                        )
                        pending.resumePending
                    }

                    is Pending.UserAgendaBridge -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to "null",
                                "change_kind" to "cleared_user_agenda_bridge"
                            )
                        )
                        null
                    }

                    is Pending.AfterResolution -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to "null",
                                "change_kind" to "cleared_after_resolution"
                            )
                        )
                        null
                    }

                    is Pending.ApplyHintNow -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to "null",
                                "change_kind" to "cleared_apply_hint_now"
                            )
                        )
                        null
                    }

                    else -> {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                                "owner" to authorityDecision.owner.name,
                                "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                                "pending_before" to pending.javaClass.simpleName,
                                "pending_after" to pending.javaClass.simpleName,
                                "change_kind" to "left_unchanged_under_transform"
                            )
                        )
                        pending
                    }
                }

            PendingAuthorityStatusV1.ACTIVE,
            PendingAuthorityStatusV1.CLEARED,
            PendingAuthorityStatusV1.NONE -> {
                ConversationTelemetry.emit(
                    mapOf(
                        "type" to "PENDING_AUTHORITY_RECONCILE_V1",
                        "owner" to authorityDecision.owner.name,
                        "pending_status" to authorityDecision.pendingAuthorityStatus.name,
                        "pending_before" to pending.javaClass.simpleName,
                        "pending_after" to pending.javaClass.simpleName,
                        "change_kind" to "left_active_or_none"
                    )
                )
                pending
            }
        }
    }

    private fun parseCellRefToIndexV1(cellRef: String?): Int? {
        val t = cellRef?.trim()?.lowercase() ?: return null
        val m = Regex("""r\s*([1-9])\s*c\s*([1-9])""").find(t) ?: return null
        val r = m.groupValues.getOrNull(1)?.toIntOrNull() ?: return null
        val c = m.groupValues.getOrNull(2)?.toIntOrNull() ?: return null
        return ((r - 1) * 9 + (c - 1)).takeIf { it in 0..80 }
    }

    private fun defaultPromptForUserAgendaItemV1(item: UserAgendaItem): String =
        when (item) {
            is UserAgendaItem.Clarification ->
                item.prompt

            is UserAgendaItem.ProofChallenge ->
                when {
                    !item.cellRef.isNullOrBlank() && item.digit != null ->
                        "Answer the user’s proof question about why ${item.cellRef} cannot be ${item.digit}."
                    !item.cellRef.isNullOrBlank() ->
                        "Answer the user’s proof question about ${item.cellRef}."
                    else ->
                        item.prompt ?: "Answer the user’s proof question."
                }

            is UserAgendaItem.CandidateStateQuery ->
                when {
                    item.cellRefs.isNotEmpty() ->
                        "Answer the user’s candidate question for ${item.cellRefs.joinToString()}."
                    !item.houseRef.isNullOrBlank() && item.digit != null ->
                        "Answer the user’s candidate-location question for digit ${item.digit} in ${item.houseRef}."
                    !item.houseRef.isNullOrBlank() ->
                        "Answer the user’s candidate-map question for ${item.houseRef}."
                    else ->
                        "Answer the user’s candidate-state question."
                }

            is UserAgendaItem.TargetCellQuery ->
                "Answer the user’s target-cell question${item.targetCellRef?.let { " about $it" } ?: ""}."

            is UserAgendaItem.NeighborCellQuery ->
                "Answer the user’s nearby-cell question${item.neighborCellRef?.let { " about $it" } ?: ""}."

            is UserAgendaItem.UserReasoningCheck ->
                "Check the user’s reasoning${item.cellRef?.let { " for $it" } ?: ""} and answer directly."

            is UserAgendaItem.AlternativeTechniqueQuery ->
                "Answer the user’s alternative-technique question truthfully and locally."

            is UserAgendaItem.RouteComparisonQuery ->
                "Compare the user’s idea to the coached route and answer whether they are the same route or a different one."

            is UserAgendaItem.RouteControl ->
                item.prompt ?: "Handle the user’s route-control request."

            is UserAgendaItem.OverlayControl ->
                "Answer the user while respecting the requested visual focus."

            is UserAgendaItem.GeneralQuestion ->
                when {
                    isUnsupportedDetourTopicV1(item.topic) ->
                        item.prompt
                            ?: "Acknowledge the user’s Sudoku question honestly, say this question type is not yet supported reliably, avoid guessing, and offer one bounded follow-up or return to the paused move."

                    else ->
                        item.prompt ?: "Answer the user’s question."
                }
        }

    private fun pendingFromUserAgendaHeadV1(item: UserAgendaItem): Pending {
        fun rowOf(idx: Int?): Int? = idx?.let { (it / 9) + 1 }
        fun colOf(idx: Int?): Int? = idx?.let { (it % 9) + 1 }

        return when (item) {
            is UserAgendaItem.Clarification -> {
                val carriedIdx = parseCellRefToIndexV1(item.carriedCellRef)
                Pending.AskClarification(
                    kind =
                        when {
                            item.missing.any { it.equals("digit", ignoreCase = true) } &&
                                    item.missing.none {
                                        it.equals("cell", ignoreCase = true) ||
                                                it.equals("row", ignoreCase = true) ||
                                                it.equals("column", ignoreCase = true) ||
                                                it.equals("col", ignoreCase = true) ||
                                                it.equals("target", ignoreCase = true)
                                    } -> ClarifyKind.DIGIT

                            item.missing.any {
                                it.equals("cell", ignoreCase = true) ||
                                        it.equals("row", ignoreCase = true) ||
                                        it.equals("column", ignoreCase = true) ||
                                        it.equals("col", ignoreCase = true) ||
                                        it.equals("target", ignoreCase = true) ||
                                        it.equals("scope", ignoreCase = true)
                            } -> ClarifyKind.POSITION

                            else -> ClarifyKind.WORKFLOW
                        },
                    rowHint = carriedIdx?.let { (it / 9) + 1 },
                    colHint = carriedIdx?.let { (it % 9) + 1 },
                    digitHint = item.carriedDigit,
                    prompt = item.prompt
                )
            }

            is UserAgendaItem.RouteControl -> {
                val prompt = item.prompt ?: when (item.control) {
                    UserRouteControlKindV1.RESUME_ROUTE -> "Resume the paused route."
                    UserRouteControlKindV1.RETURN_TO_ORIGINAL_MOVE -> "Return to the original move."
                    UserRouteControlKindV1.CONTINUE_ROUTE -> "Continue the route."
                    UserRouteControlKindV1.PAUSE_ROUTE -> "Pause the route."
                    UserRouteControlKindV1.ABANDON_ROUTE -> "Abandon the current route."
                }

                Pending.UserAgendaBridge(
                    userAgendaId = item.id,
                    agendaKind = "route_control",
                    prompt = prompt,
                    expectedAnswerKind = "CHOICE",
                    options = listOf(PendingChoiceId.RETURN_TO_ROUTE)
                )
            }

            else -> {
                val primaryCellRef: String? =
                    when (item) {
                        is UserAgendaItem.ProofChallenge -> item.cellRef
                        is UserAgendaItem.CandidateStateQuery -> item.cellRefs.firstOrNull()
                        is UserAgendaItem.TargetCellQuery -> item.targetCellRef
                        is UserAgendaItem.NeighborCellQuery -> item.neighborCellRef ?: item.anchorCellRef
                        is UserAgendaItem.UserReasoningCheck -> item.cellRef
                        is UserAgendaItem.AlternativeTechniqueQuery -> item.cellRef
                        is UserAgendaItem.OverlayControl -> item.focusCellRef
                        is UserAgendaItem.GeneralQuestion -> null
                        is UserAgendaItem.RouteComparisonQuery -> null
                        is UserAgendaItem.RouteControl -> null
                        is UserAgendaItem.Clarification -> null
                    }

                val idx = parseCellRefToIndexV1(primaryCellRef)

                Pending.UserAgendaBridge(
                    userAgendaId = item.id,
                    agendaKind = item::class.java.simpleName ?: "UserAgenda",
                    prompt = defaultPromptForUserAgendaItemV1(item),
                    agendaStatus = item.status.name,
                    allowsFollowUp = item.allowsFollowUp,
                    expectedAnswerKind = when (item) {
                        is UserAgendaItem.CandidateStateQuery -> "FREEFORM_STRUCTURED"
                        is UserAgendaItem.ProofChallenge -> "FREEFORM_STRUCTURED"
                        is UserAgendaItem.UserReasoningCheck -> "YES_NO_OR_FREEFORM"
                        is UserAgendaItem.RouteComparisonQuery -> "FREEFORM_STRUCTURED"
                        else -> "FREEFORM_STRUCTURED"
                    },
                    rowHint = rowOf(idx),
                    colHint = colOf(idx),
                    digitHint = when (item) {
                        is UserAgendaItem.ProofChallenge -> item.digit
                        is UserAgendaItem.CandidateStateQuery -> item.digit
                        is UserAgendaItem.TargetCellQuery -> item.digit
                        is UserAgendaItem.OverlayControl -> item.digit
                        else -> null
                    },
                    cellRef = primaryCellRef,
                    options = if (item.allowsFollowUp) {
                        listOf(PendingChoiceId.RETURN_TO_ROUTE)
                    } else {
                        emptyList()
                    }
                )
            }
        }
    }


    private fun pendingFromAppAgendaHeadV1(
        s: SudoState,
        appHead: AppAgendaItem?,
        pendingCandidate: Pending?
    ): Pending? {
        if (pendingCandidate != null && pendingCandidate !is Pending.UserAgendaBridge) {
            return pendingCandidate
        }

        return when (appHead) {
            null -> pendingCandidate

            is AppAgendaItem.RetakeDecision ->
                Pending.ConfirmRetake(
                    strength = appHead.strength,
                    prompt = buildConfirmRetakePrompt(appHead.strength)
                )

            is AppAgendaItem.MismatchReview ->
                Pending.ConfirmEdit(
                    cellIndex = appHead.cellIndex,
                    proposedDigit = appHead.expectedDigit,
                    source = "app_agenda",
                    prompt =
                        "I think ${indexToCell(appHead.cellIndex)} should be ${appHead.expectedDigit} " +
                                "(it currently shows ${appHead.scannedDigit}). Should I change it?"
                )

            is AppAgendaItem.ConflictReview ->
                Pending.AskCellValue(
                    cellIndex = appHead.cellIndex,
                    prompt = "What digit is at ${indexToCell(appHead.cellIndex)}?"
                )

            is AppAgendaItem.ConfirmValidationExactMatch ->
                Pending.ConfirmValidate(
                    prompt = "The grid looks consistent, and I can solve it uniquely from what’s on screen. Before we begin, does the on-screen grid match your puzzle exactly?"
                )

            is AppAgendaItem.VisualVerificationRequest ->
                Pending.VisualVerifyMatch(
                    prompt =
                        "Please explain that I’m not seeing rule conflicts on screen, but the current givens still do not produce a single unique solution. Say that the most likely cause is one or more missing or misread givens from the scan, then ask the user to compare paper vs screen carefully and either confirm a perfect match or provide exact cell corrections."
                )

            is AppAgendaItem.FinalizeValidationStartSolving ->
                pendingCandidate

            is AppAgendaItem.RecommendDifferentGrid ->
                Pending.WaitForTap(
                    prompt =
                        "Please explain that the on-screen grid now appears to match the paper, but these givens still do not lead to one unique standard solution. Briefly justify why that usually means either an overlooked wrong/missing given or a source puzzle issue, then recommend capturing a different puzzle.",
                    digitHint = null,
                    confidence = 0.90f
                )

            is AppAgendaItem.Solving ->
                pendingCandidate

            is AppAgendaItem.ProposeRetake ->
                Pending.ConfirmRetake(
                    strength = appHead.strength,
                    prompt = buildConfirmRetakePrompt(appHead.strength)
                )

            is AppAgendaItem.ProposeEdit ->
                Pending.ConfirmEdit(
                    cellIndex = appHead.cellIndex,
                    proposedDigit = appHead.expectedDigit,
                    source = "app_agenda",
                    prompt =
                        "I think ${indexToCell(appHead.cellIndex)} should be ${appHead.expectedDigit} " +
                                "(it currently shows ${appHead.scannedDigit}). Should I change it?"
                )

            is AppAgendaItem.AskConfirmCell ->
                Pending.AskCellValue(
                    cellIndex = appHead.cellIndex,
                    prompt = "What digit is at ${indexToCell(appHead.cellIndex)}?"
                )
        }
    }




    private fun derivePendingProjectionV1(
        s: SudoState,
        owner: TurnOwnerV1,
        userAgendaQueue: List<UserAgendaItem>,
        appAgendaQueue: List<AppAgendaItem>,
        pendingCandidate: Pending?
    ): Pending? =
        when (owner) {
            TurnOwnerV1.USER_OWNER -> {
                val userHead = userAgendaQueue.firstOrNull()
                when {
                    pendingCandidate is Pending.AskClarification &&
                            userHead is UserAgendaItem.Clarification -> pendingCandidate

                    userHead != null -> pendingFromUserAgendaHeadV1(userHead)
                    else -> pendingCandidate
                }
            }

            TurnOwnerV1.APP_OWNER -> {
                val appHead = appAgendaQueue.firstOrNull()
                pendingFromAppAgendaHeadV1(
                    s = s,
                    appHead = appHead,
                    pendingCandidate = pendingCandidate
                )
            }

            TurnOwnerV1.NONE -> pendingCandidate
        }



    private fun atomFrameForCellRefV1(
        s: SudoState,
        cellRef: String?
    ): List<String> {
        val idx = parseCellRefToIndexV1(cellRef) ?: return emptyList()
        val atomIdx = runCatching { findAtomIndexForCell(s, idx) }.getOrNull() ?: return emptyList()
        return listOf("ov:atom:$atomIdx")
    }

    private fun detourOverlayFrameIdsFromNativeContextV1(
        state: SudoState,
        ctx: DetourNarrativeContextV1?
    ): List<String> {
        if (ctx == null) return emptyList()

        val nativeFrames = detourNativeOverlayFrameIdsV1(state, ctx)
        if (nativeFrames.isNotEmpty()) return nativeFrames

        val hasAnyDetourFocus =
            ctx.overlayPolicy.primaryFocusCells.isNotEmpty() ||
                    ctx.overlayPolicy.secondaryFocusCells.isNotEmpty() ||
                    ctx.overlayPolicy.primaryFocusHouses.isNotEmpty() ||
                    ctx.overlayPolicy.deemphasizeCells.isNotEmpty() ||
                    ctx.dominantAtom.focusCells.isNotEmpty() ||
                    ctx.dominantAtom.focusHouses.isNotEmpty()

        return if (hasAnyDetourFocus) {
            listOf("detour:native")
        } else {
            emptyList()
        }
    }

    private fun checkpointFramesV1(checkpoint: RouteCheckpointV1?): List<String> =
        checkpoint?.overlayFrameIds
            ?.map { it.trim() }
            ?.filter { it.isNotBlank() }
            ?.distinct()
            .orEmpty()

    private fun storyFramesV1(story: NarrativeStoryContext?): List<String> =
        story?.let { storyOverlayFrameIdsFromStoryV1(it) }
            ?.map { it.trim() }
            ?.filter { it.isNotBlank() }
            ?.distinct()
            .orEmpty()

    private fun overlayContractFromUserAgendaHeadV1(
        s: SudoState,
        userHead: UserAgendaItem?,
        checkpoint: RouteCheckpointV1?
    ): OverlayContractV1 {
        if (userHead == null) {
            return OverlayContractV1(
                kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                frameIds = checkpointFramesV1(checkpoint),
                reason = "no_user_head_restore_checkpoint"
            )
        }

        val nativeDetourFrames =
            detourOverlayFrameIdsFromNativeContextV1(
                state = s,
                ctx = s.detourNarrativeContextV1
            )

        val detourFrames =
            nativeDetourFrames
                .ifEmpty {
                    s.detourState
                        ?.takeIf { it.isActive && it.detourAppliedFrameIds.isNotEmpty() }
                        ?.detourAppliedFrameIds
                        ?.map { it.trim() }
                        ?.filter { it.isNotBlank() }
                        ?.distinct()
                        .orEmpty()
                }

        val checkpointFrames = checkpointFramesV1(checkpoint)

        fun resolvedFramesForCell(cellRef: String?): List<String> =
            detourFrames
                .ifEmpty { atomFrameForCellRefV1(s, cellRef) }
                .ifEmpty { checkpointFrames }

        return when (userHead) {
            is UserAgendaItem.Clarification ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                    frameIds = checkpointFrames,
                    reason = "clarification_restore_checkpoint"
                )

            is UserAgendaItem.RouteControl -> {
                val handoverMode = s.detourNarrativeContextV1?.handbackPolicy?.handoverMode
                if (handoverMode == DetourHandoverModeV1.HOLD_FOCUS_HERE ||
                    handoverMode == DetourHandoverModeV1.AWAIT_USER_CONTROL
                ) {
                    OverlayContractV1(
                        kind = OverlayContractKindV1.PRESERVE_CURRENT,
                        frameIds = detourFrames.ifEmpty { checkpointFrames },
                        focusCellRef = detourFrames.firstOrNull(),
                        reason = "route_control_preserve_detour_focus"
                    )
                } else {
                    OverlayContractV1(
                        kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                        frameIds = checkpointFrames,
                        reason = "route_control_restore_checkpoint"
                    )
                }
            }

            is UserAgendaItem.GeneralQuestion ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                    frameIds = checkpointFrames,
                    reason = "general_question_restore_checkpoint"
                )

            is UserAgendaItem.OverlayControl -> {
                val focusCell = userHead.focusCellRef
                val focusFrames = resolvedFramesForCell(focusCell)

                when (userHead.control) {
                    OverlayControlKindV1.PRESERVE_CURRENT,
                    OverlayControlKindV1.STAY_ON_CURRENT_REGION ->
                        OverlayContractV1(
                            kind = OverlayContractKindV1.PRESERVE_CURRENT,
                            frameIds = checkpointFrames,
                            focusCellRef = focusCell,
                            reason = "overlay_control_preserve_current"
                        )

                    OverlayControlKindV1.HIGHLIGHT_CELL,
                    OverlayControlKindV1.HIGHLIGHT_BLOCKER,
                    OverlayControlKindV1.HIGHLIGHT_ALTERNATIVE_AREA,
                    OverlayControlKindV1.COMPARE_MY_AREA_TO_YOURS ->
                        OverlayContractV1(
                            kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                            frameIds = focusFrames,
                            focusCellRef = focusCell,
                            reason = "overlay_control_spotlight_cell"
                        )
                }
            }

            is UserAgendaItem.ProofChallenge ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                    frameIds = resolvedFramesForCell(userHead.cellRef),
                    focusCellRef = userHead.cellRef,
                    reason = "proof_challenge_spotlight_cell"
                )

            is UserAgendaItem.CandidateStateQuery ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                    frameIds = resolvedFramesForCell(userHead.cellRefs.firstOrNull()),
                    focusCellRef = userHead.cellRefs.firstOrNull(),
                    reason = "candidate_state_spotlight_cell"
                )

            is UserAgendaItem.TargetCellQuery ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                    frameIds = resolvedFramesForCell(userHead.targetCellRef),
                    focusCellRef = userHead.targetCellRef,
                    reason = "target_cell_spotlight_cell"
                )

            is UserAgendaItem.NeighborCellQuery ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                    frameIds = resolvedFramesForCell(userHead.neighborCellRef ?: userHead.anchorCellRef),
                    focusCellRef = userHead.neighborCellRef ?: userHead.anchorCellRef,
                    reason = "neighbor_cell_spotlight_cell"
                )

            is UserAgendaItem.UserReasoningCheck ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                    frameIds = resolvedFramesForCell(userHead.cellRef),
                    focusCellRef = userHead.cellRef,
                    reason = "reasoning_check_spotlight_cell"
                )

            is UserAgendaItem.AlternativeTechniqueQuery ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.SPOTLIGHT_CELL,
                    frameIds = resolvedFramesForCell(userHead.cellRef),
                    focusCellRef = userHead.cellRef,
                    reason = "alternative_technique_spotlight_cell"
                )

            is UserAgendaItem.RouteComparisonQuery ->
                OverlayContractV1(
                    kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                    frameIds = detourFrames.ifEmpty { checkpointFrames },
                    reason = "route_comparison_restore_checkpoint"
                )
        }
    }

    private fun overlayContractFromAppAgendaHeadV1(
        s: SudoState,
        appHead: AppAgendaItem?,
        story: NarrativeStoryContext?,
        checkpoint: RouteCheckpointV1?
    ): OverlayContractV1 {
        val storyFrames = storyFramesV1(story)
        val checkpointFrames = checkpointFramesV1(checkpoint)

        return when (appHead) {
            null -> OverlayContractV1(
                kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                frameIds = checkpointFrames.ifEmpty { storyFrames },
                reason = "no_app_head_restore_checkpoint"
            )

            is AppAgendaItem.Solving -> OverlayContractV1(
                kind = OverlayContractKindV1.SHOW_STORY_SCOPE,
                frameIds = storyFrames.ifEmpty { checkpointFrames },
                reason = "app_solving_story_scope"
            )

            else -> OverlayContractV1(
                kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                frameIds = checkpointFrames.ifEmpty { storyFrames },
                reason = "app_non_solving_restore_checkpoint"
            )
        }
    }

    private fun resolveOverlayContractV1(
        s: SudoState,
        owner: TurnOwnerV1,
        userAgendaQueue: List<UserAgendaItem>,
        appAgendaQueue: List<AppAgendaItem>,
        story: NarrativeStoryContext?,
        checkpoint: RouteCheckpointV1?
    ): Pair<OverlayOwnerV1, OverlayContractV1> =
        when (owner) {
            TurnOwnerV1.USER_OWNER -> {
                OverlayOwnerV1.USER_OWNER to overlayContractFromUserAgendaHeadV1(
                    s = s,
                    userHead = userAgendaQueue.firstOrNull(),
                    checkpoint = checkpoint
                )
            }

            TurnOwnerV1.APP_OWNER -> {
                OverlayOwnerV1.APP_OWNER to overlayContractFromAppAgendaHeadV1(
                    s = s,
                    appHead = appAgendaQueue.firstOrNull(),
                    story = story,
                    checkpoint = checkpoint
                )
            }

            TurnOwnerV1.NONE -> {
                OverlayOwnerV1.CHECKPOINT_RESTORE to OverlayContractV1(
                    kind = OverlayContractKindV1.RESTORE_CHECKPOINT,
                    frameIds = checkpointFramesV1(checkpoint),
                    reason = "no_owner_restore_checkpoint"
                )
            }
        }

    private fun frameIdsFromOverlayContractV1(
        contract: OverlayContractV1,
        checkpoint: RouteCheckpointV1?
    ): List<String> =
        when (contract.kind) {
            OverlayContractKindV1.CLEAR ->
                emptyList()

            OverlayContractKindV1.PRESERVE_CURRENT,
            OverlayContractKindV1.RESTORE_CHECKPOINT ->
                contract.frameIds
                    .ifEmpty { checkpointFramesV1(checkpoint) }
                    .map { it.trim() }
                    .filter { it.isNotBlank() }
                    .distinct()

            OverlayContractKindV1.SHOW_STORY_SCOPE,
            OverlayContractKindV1.SPOTLIGHT_CELL,
            OverlayContractKindV1.SHOW_ATOM_FRAME ->
                contract.frameIds
                    .map { it.trim() }
                    .filter { it.isNotBlank() }
                    .distinct()
        }




    private fun firstExplicitCellTargetV1(env: IntentEnvelopeV1): String? =
        env.intents.asSequence()
            .flatMap { it.targets.asSequence() }
            .mapNotNull { it.cell?.trim() }
            .firstOrNull { it.isNotBlank() }


    private fun firstExplicitCell2TargetV1(env: IntentEnvelopeV1): String? =
        env.intents.asSequence()
            .flatMap { it.targets.asSequence() }
            .mapNotNull { it.cell2?.trim() }
            .firstOrNull { it.isNotBlank() }

    private fun isUnsupportedDetourTopicV1(topic: String?): Boolean =
        topic?.trim()?.equals("unsupported_detour", ignoreCase = true) == true


    private fun firstExplicitDigitTargetV1(env: IntentEnvelopeV1): Int? =
        env.intents.asSequence()
            .mapNotNull { it.digitOrNullCompat() }
            .firstOrNull()

    private fun firstExplicitRegionRefV1(env: IntentEnvelopeV1): String? =
        env.intents.asSequence()
            .mapNotNull { it.regionOrNullCompat() }
            .firstOrNull()
            ?.let { r ->
                when (r.kind) {
                    RegionKindV1.ROW -> "row ${r.index}"
                    RegionKindV1.COL -> "column ${r.index}"
                    RegionKindV1.BOX -> "box ${r.index}"
                }
            }

    private fun firstDetourSemanticFamilyV1(env: IntentEnvelopeV1): DetourSemanticFamilyV1? =
        env.intents.asSequence()
            .mapNotNull { it.payload.detourSemanticFamily }
            .firstOrNull()

    private fun hasScopedSudokuAnchorForProofV1(
        explicitCell: String?,
        explicitDigit: Int?,
        explicitRegion: String?
    ): Boolean =
        explicitCell != null ||
                (explicitDigit != null && explicitRegion != null) ||
                (explicitCell != null && explicitDigit != null)

    private fun semanticFamilyImpliesProofChallengeV1(
        semanticFamily: DetourSemanticFamilyV1?
    ): Boolean =
        when (semanticFamily) {
            DetourSemanticFamilyV1.PROOF_BLOCKER_AT_CELL,
            DetourSemanticFamilyV1.PROOF_DIGIT_IN_HOUSE,
            DetourSemanticFamilyV1.PROPOSAL_VERDICT -> true

            else -> false
        }

    private fun semanticFamilyImpliesTargetCellQueryV1(
        semanticFamily: DetourSemanticFamilyV1?
    ): Boolean =
        semanticFamily == DetourSemanticFamilyV1.TARGETED_EXPLANATION

    private fun semanticFamilyImpliesCandidateStateQueryV1(
        semanticFamily: DetourSemanticFamilyV1?
    ): Boolean =
        semanticFamily == DetourSemanticFamilyV1.CANDIDATE_STATE

    private fun shouldPreferProofChallengeOverReasoningCheckV1(
        topType: IntentTypeV1,
        semanticFamily: DetourSemanticFamilyV1?,
        explicitCell: String?,
        explicitDigit: Int?,
        explicitRegion: String?
    ): Boolean {
        val reasoningCheckIntent =
            topType == IntentTypeV1.REQUEST_REASONING_CHECK ||
                    topType == IntentTypeV1.CHECK_PROPOSED_DIGIT_IN_CELL ||
                    topType == IntentTypeV1.CHECK_PROPOSED_CANDIDATE_SET_IN_CELL ||
                    topType == IntentTypeV1.CHECK_PROPOSED_ELIMINATION_IN_SCOPE ||
                    topType == IntentTypeV1.CHECK_PROPOSED_TECHNIQUE_APPLIES_HERE ||
                    topType == IntentTypeV1.CHECK_PROPOSED_ROUTE_EQUIVALENCE

        if (!reasoningCheckIntent) return false

        if (semanticFamilyImpliesProofChallengeV1(semanticFamily)) {
            return true
        }

        return when (topType) {
            IntentTypeV1.CHECK_PROPOSED_DIGIT_IN_CELL,
            IntentTypeV1.CHECK_PROPOSED_CANDIDATE_SET_IN_CELL,
            IntentTypeV1.CHECK_PROPOSED_ELIMINATION_IN_SCOPE ->
                hasScopedSudokuAnchorForProofV1(
                    explicitCell = explicitCell,
                    explicitDigit = explicitDigit,
                    explicitRegion = explicitRegion
                )

            else -> false
        }
    }

    private fun shouldTreatRequestExplanationAsProofChallengeV1(
        semanticFamily: DetourSemanticFamilyV1?,
        explicitCell: String?,
        explicitDigit: Int?,
        explicitRegion: String?
    ): Boolean {
        if (semanticFamilyImpliesProofChallengeV1(semanticFamily)) {
            return true
        }

        return explicitDigit != null && (explicitCell != null || explicitRegion != null)
    }

    private fun houseRefJsonFromTextV1(raw: String?): JSONObject? {
        val s = raw?.trim()?.lowercase() ?: return null
        if (s.isBlank()) return null

        val row = Regex("""^row\s+([1-9])$""").matchEntire(s)
        if (row != null) {
            val idx = row.groupValues[1].toIntOrNull() ?: return null
            return houseRefV1(RegionKindV1.ROW, idx)
        }

        val col = Regex("""^(col|column)\s+([1-9])$""").matchEntire(s)
        if (col != null) {
            val idx = col.groupValues[2].toIntOrNull() ?: return null
            return houseRefV1(RegionKindV1.COL, idx)
        }

        val box = Regex("""^box\s+([1-9])$""").matchEntire(s)
        if (box != null) {
            val idx = box.groupValues[1].toIntOrNull() ?: return null
            return houseRefV1(RegionKindV1.BOX, idx)
        }

        return null
    }

    private fun routeControlKindFromEnvV1(env: IntentEnvelopeV1): UserRouteControlKindV1 {
        val ranked = env.intents.sortedWith(compareByDescending<IntentV1> { it.confidence }.thenBy { it.id })
        val top = ranked.firstOrNull()?.type
        return when (top) {
            IntentTypeV1.SOLVE_CONTINUE -> UserRouteControlKindV1.CONTINUE_ROUTE
            else -> UserRouteControlKindV1.RETURN_TO_ORIGINAL_MOVE
        }
    }

    private fun wantsResumePausedRouteV1(env: IntentEnvelopeV1): Boolean {
        if (env.intents.isEmpty()) return false

        val types = env.intents.map { it.type }
        val hasResumeIntent =
            types.any {
                it == IntentTypeV1.SOLVE_CONTINUE ||
                        it == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT
            }

        if (!hasResumeIntent) return false

        val allowedCompanionTypes = setOf(
            IntentTypeV1.SOLVE_CONTINUE,
            IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT,
            IntentTypeV1.SMALL_TALK
        )

        val hasSubstantiveNonResumeContent =
            types.any { it !in allowedCompanionTypes }

        return !hasSubstantiveNonResumeContent
    }

    private fun unresolvedClarificationHeadV1(
        queue: List<UserAgendaItem>
    ): UserAgendaItem.Clarification? =
        (queue.firstOrNull() as? UserAgendaItem.Clarification)
            ?.takeIf { it.status != UserAgendaStatusV1.RESOLVED }

    private fun hasSubstantiveClarificationFillIntentV1(
        env: IntentEnvelopeV1
    ): Boolean {
        if (env.intents.isEmpty()) return false

        val safeRouteOnlyTypes = setOf(
            IntentTypeV1.UNKNOWN,
            IntentTypeV1.CONFIRM_YES,
            IntentTypeV1.CONFIRM_NO,
            IntentTypeV1.SOLVE_CONTINUE,
            IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT,
            IntentTypeV1.SOLVE_ACCEPT_LOCK_IN,
            IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP,
            IntentTypeV1.SOLVE_PAUSE,
            IntentTypeV1.SMALL_TALK
        )

        return env.intents.any { intent ->
            intent.type == IntentTypeV1.PROVIDE_DIGIT ||
                    intent.type !in safeRouteOnlyTypes
        }
    }

    private fun failedDetourExplicitRetireRequestedV1(
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): Boolean =
        routing.isRouteFollowing || wantsResumePausedRouteV1(env)

    private fun detourBridgeReturnGateV1(
        s: SudoState,
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): Pair<Boolean, String> {
        val unresolvedClarification =
            unresolvedClarificationHeadV1(s.userAgendaQueue)

        if (unresolvedClarification != null && hasSubstantiveClarificationFillIntentV1(env)) {
            return false to "clarification_fill_turn_must_stay_in_detour"
        }

        val state = s.detourState?.answerState
        return when (state) {
            null,
            DetourAnswerStateV1.ANSWERED_READY_TO_RETURN ->
                true to "answered_ready_to_return_or_absent"

            DetourAnswerStateV1.FAILED_AWAITING_RECOVERY ->
                if (failedDetourExplicitRetireRequestedV1(env, routing)) {
                    true to "failed_detour_explicitly_retired"
                } else {
                    false to "failed_detour_requires_explicit_retire"
                }

            DetourAnswerStateV1.ACTIVE_UNANSWERED ->
                false to "detour_not_answered_yet"
        }
    }

    private fun shouldReturnFromPartiallyAnsweredHeadForDebugV1(
        env: IntentEnvelopeV1,
        head: UserAgendaItem?
    ): Boolean {
        if (head == null) return false
        if (head.status != UserAgendaStatusV1.PARTIALLY_ANSWERED) return false
        if (!head.allowsFollowUp) return true

        val hasRouteReturnIntent =
            env.intents.any { intent ->
                intent.type == IntentTypeV1.SOLVE_CONTINUE ||
                        intent.type == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT ||
                        intent.type == IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP ||
                        intent.type == IntentTypeV1.SOLVE_ACCEPT_LOCK_IN
            }

        if (!hasRouteReturnIntent) return false

        val looksLikeFollowUp =
            isLikelyFollowUpToUserAgendaHeadV1(env, head)

        return !looksLikeFollowUp
    }


    private fun isPostResolutionMismatchReportV1(
        s: SudoState,
        env: IntentEnvelopeV1
    ): Boolean {
        val hasMismatchIntent =
            env.intents.any { it.type == IntentTypeV1.GRID_MISMATCH_REPORT }

        if (!hasMismatchIntent) return false
        if (s.phase != GridPhase.SOLVING) return false

        val storyStageNow = s.narrativeStory?.stage
        val pendingNow = s.pending

        val resolutionJustSpoken =
            storyStageNow == StoryStage.RESOLUTION ||
                    pendingNow is Pending.AfterResolution

        return resolutionJustSpoken
    }





    private fun preferredDetourPacketTypesV1(
        detourQuestionClass: String?,
        pending: Pending?
    ): List<FactBundleV1.Type> {
        val allowsReturnToRoute =
            pending is Pending.UserAgendaBridge &&
                    pending.options.contains(PendingChoiceId.RETURN_TO_ROUTE)

        val base = when (detourQuestionClass?.trim()?.uppercase()) {
            "STEP_CLARIFICATION" -> listOf(
                FactBundleV1.Type.STEP_CLARIFICATION_PACKET_V1
            )

            "PROOF_CHALLENGE" -> listOf(
                FactBundleV1.Type.PROOF_CHALLENGE_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1,
                FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1
            )

            "TARGET_CELL_QUERY" -> listOf(
                FactBundleV1.Type.TARGET_CELL_QUERY_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1,
                FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1
            )

            "NEIGHBOR_CELL_QUERY" -> listOf(
                FactBundleV1.Type.NEIGHBOR_CELL_QUERY_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELL_DIGIT_BLOCKERS_PACKET_V1,
                FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1
            )

            "CANDIDATE_STATE_QUERY" -> listOf(
                FactBundleV1.Type.CANDIDATE_STATE_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELL_CANDIDATES_PACKET_V1,
                FactBundleV1.Type.SOLVER_CELLS_CANDIDATES_PACKET_V1
            )

            "USER_REASONING_CHECK" -> listOf(
                FactBundleV1.Type.USER_REASONING_CHECK_PACKET_V1,
                FactBundleV1.Type.SOLVER_REASONING_CHECK_PACKET_V1,
                FactBundleV1.Type.SOLVER_SCOPED_SUPPORT_PACKET_V1
            )

            "ALTERNATIVE_TECHNIQUE" -> listOf(
                FactBundleV1.Type.ALTERNATIVE_TECHNIQUE_PACKET_V1,
                FactBundleV1.Type.SOLVER_ALTERNATIVE_TECHNIQUE_PACKET_V1,
                FactBundleV1.Type.SOLVER_ROUTE_COMPARISON_PACKET_V1
            )

            "RETURN_TO_ROUTE" -> listOf(
                FactBundleV1.Type.RETURN_TO_ROUTE_PACKET_V1
            )

            else -> emptyList()
        }

        return if (allowsReturnToRoute &&
            detourQuestionClass?.trim()?.uppercase() != "RETURN_TO_ROUTE"
        ) {
            base + listOf(FactBundleV1.Type.RETURN_TO_ROUTE_PACKET_V1)
        } else {
            base
        }
    }


    private fun activeDetourQuestionClassV1(
        s: SudoState,
        pending: Pending?
    ): String? {
        val ds = s.detourState

        if (pending is Pending.ReturnToRoute) {
            return "RETURN_TO_ROUTE"
        }

        if (ds?.isActive == true) {
            return when (ds.questionClass) {
                DetourQuestionClassV1.TARGET_CELL_QUERY -> "TARGET_CELL_QUERY"
                DetourQuestionClassV1.NEIGHBOR_CELL_QUERY -> "NEIGHBOR_CELL_QUERY"
                DetourQuestionClassV1.CANDIDATE_STATE_QUERY -> "CANDIDATE_STATE_QUERY"
                DetourQuestionClassV1.PROOF_CHALLENGE -> "PROOF_CHALLENGE"
                DetourQuestionClassV1.USER_REASONING_CHECK -> "USER_REASONING_CHECK"
                DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY -> "ALTERNATIVE_TECHNIQUE"
                DetourQuestionClassV1.ROUTE_COMPARISON_QUERY -> "ALTERNATIVE_TECHNIQUE"
                DetourQuestionClassV1.STEP_CLARIFICATION -> "STEP_CLARIFICATION"

                DetourQuestionClassV1.GENERAL_QUESTION -> "GENERAL_QUESTION"
                DetourQuestionClassV1.REPAIR_QUESTION -> "GENERAL_QUESTION"
                DetourQuestionClassV1.UNSUPPORTED_DETOUR -> "UNSUPPORTED_DETOUR"
                DetourQuestionClassV1.OVERLAY_CONTROL -> "GENERAL_QUESTION"

                DetourQuestionClassV1.ROUTE_CONTROL -> "RETURN_TO_ROUTE"
                null -> null
            }
        }

        val head = s.userAgendaQueue.firstOrNull()
        return when (head) {
            is UserAgendaItem.Clarification -> null
            is UserAgendaItem.RouteControl ->
                if (pending is Pending.UserAgendaBridge &&
                    pending.options.contains(PendingChoiceId.RETURN_TO_ROUTE)
                ) {
                    "RETURN_TO_ROUTE"
                } else null
            else -> null
        }
    }

    private fun authoritativeDetourQuestionClassV1(
        userHead: UserAgendaItem?,
        fallback: DetourQuestionClassV1?
    ): DetourQuestionClassV1? =
        when (userHead) {
            is UserAgendaItem.ProofChallenge -> DetourQuestionClassV1.PROOF_CHALLENGE
            is UserAgendaItem.TargetCellQuery -> DetourQuestionClassV1.TARGET_CELL_QUERY
            is UserAgendaItem.NeighborCellQuery -> DetourQuestionClassV1.NEIGHBOR_CELL_QUERY
            is UserAgendaItem.CandidateStateQuery -> DetourQuestionClassV1.CANDIDATE_STATE_QUERY
            is UserAgendaItem.UserReasoningCheck -> DetourQuestionClassV1.USER_REASONING_CHECK
            is UserAgendaItem.AlternativeTechniqueQuery -> DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY
            is UserAgendaItem.RouteComparisonQuery -> DetourQuestionClassV1.ROUTE_COMPARISON_QUERY
            is UserAgendaItem.OverlayControl -> DetourQuestionClassV1.OVERLAY_CONTROL
            is UserAgendaItem.RouteControl -> DetourQuestionClassV1.ROUTE_CONTROL
            is UserAgendaItem.GeneralQuestion ->
                when {
                    userHead.topic == "step_clarification" ->
                        DetourQuestionClassV1.STEP_CLARIFICATION

                    isUnsupportedDetourTopicV1(userHead.topic) ->
                        DetourQuestionClassV1.UNSUPPORTED_DETOUR

                    else ->
                        DetourQuestionClassV1.GENERAL_QUESTION
                }
            is UserAgendaItem.Clarification -> fallback
            null -> fallback
        }

    private fun isSolvingNativeDetourQuestionClassV1(
        klass: DetourQuestionClassV1?
    ): Boolean =
        when (klass) {
            DetourQuestionClassV1.PROOF_CHALLENGE,
            DetourQuestionClassV1.TARGET_CELL_QUERY,
            DetourQuestionClassV1.NEIGHBOR_CELL_QUERY,
            DetourQuestionClassV1.CANDIDATE_STATE_QUERY,
            DetourQuestionClassV1.USER_REASONING_CHECK,
            DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY,
            DetourQuestionClassV1.ROUTE_COMPARISON_QUERY,
            DetourQuestionClassV1.STEP_CLARIFICATION -> true

            else -> false
        }




    private fun isDirectAppOwnedIntentForAgendaV1(t: IntentTypeV1): Boolean =
        com.contextionary.sudoku.conductor.policy.isDirectAppOwnedIntentForAgendaV1(t)

    private fun isRouteJumpIntentForAgendaV1(t: IntentTypeV1): Boolean =
        com.contextionary.sudoku.conductor.policy.isUserRouteJumpIntentForAgendaV1(t)

    private fun agendaMaterializationClassForConfirmingPhaseV1(
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): DetourQuestionClassV1? {
        val topIntent = env.intents.firstOrNull() ?: return null
        val topType = topIntent.type

        if (isDirectAppOwnedIntentForAgendaV1(topType)) {
            return null
        }

        if (routing.isRouteControl || isRouteJumpIntentForAgendaV1(topType)) {
            return DetourQuestionClassV1.ROUTE_CONTROL
        }

        when (topType) {
            IntentTypeV1.SWITCH_FOCUS_CELL,
            IntentTypeV1.SWITCH_FOCUS_REGION ->
                return DetourQuestionClassV1.OVERLAY_CONTROL

            IntentTypeV1.ASK_CELL_CANDIDATES,
            IntentTypeV1.ASK_CANDIDATE_COUNT_CELL,
            IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP,
            IntentTypeV1.ASK_CANDIDATE_FREQUENCY,
            IntentTypeV1.ASK_CANDIDATES_OVERVIEW,
            IntentTypeV1.ASK_CANDIDATES_CELL_OVERVIEW,
            IntentTypeV1.ASK_CANDIDATES_DISTRIBUTION,
            IntentTypeV1.ASK_DIGIT_LOCATIONS,
            IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE,
            IntentTypeV1.ASK_CELL_STATUS ->
                return DetourQuestionClassV1.CANDIDATE_STATE_QUERY

            else -> Unit
        }

        routing.detourQuestionClass?.let { binderClass ->
            return when (binderClass) {
                DetourQuestionClassV1.ROUTE_CONTROL,
                DetourQuestionClassV1.OVERLAY_CONTROL,
                DetourQuestionClassV1.CANDIDATE_STATE_QUERY,
                DetourQuestionClassV1.GENERAL_QUESTION,
                DetourQuestionClassV1.REPAIR_QUESTION,
                DetourQuestionClassV1.UNSUPPORTED_DETOUR -> binderClass

                else -> DetourQuestionClassV1.GENERAL_QUESTION
            }
        }

        return when (topType) {
            IntentTypeV1.REQUEST_EXPLANATION,
            IntentTypeV1.REQUEST_REASONING_CHECK,
            IntentTypeV1.REPORT_BUG_OR_WRONG_ASSERTION,
            IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT,
            IntentTypeV1.ASK_WHY_THIS_CELL,
            IntentTypeV1.CAPABILITY_CHECK,
            IntentTypeV1.META_APP_QUESTION,
            IntentTypeV1.FREE_TALK,
            IntentTypeV1.SOLVE_PAUSE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION,
            IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION,
            IntentTypeV1.REQUEST_CURRENT_STAGE_COLLAPSE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_EXAMPLE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT,
            IntentTypeV1.REQUEST_CURRENT_STAGE_REPHRASE,
            IntentTypeV1.ASK_SOLVABILITY_STATUS,
            IntentTypeV1.ASK_PROGRESS_METRICS,
            IntentTypeV1.ASK_IF_STUCK,
            IntentTypeV1.ASK_IF_GUESS_REQUIRED,
            IntentTypeV1.ASK_DIFFICULTY_ESTIMATE,
            IntentTypeV1.ASK_CELL_VALUE,
            IntentTypeV1.ASK_ROW_CONTENTS,
            IntentTypeV1.ASK_COL_CONTENTS,
            IntentTypeV1.ASK_BOX_CONTENTS,
            IntentTypeV1.ASK_HOUSE_COMPLETION,
            IntentTypeV1.ASK_HOUSE_MISSING_DIGITS,
            IntentTypeV1.ASK_DIGIT_COUNT_GLOBAL,
            IntentTypeV1.ASK_EMPTY_HOUSES,
            IntentTypeV1.ASK_NEARLY_COMPLETE_HOUSES,
            IntentTypeV1.ASK_HOUSE_OVERVIEW,
            IntentTypeV1.ASK_HOUSE_RANKING,
            IntentTypeV1.ASK_DIGIT_OVERVIEW,
            IntentTypeV1.ASK_DIGIT_IN_HOUSE_OVERVIEW,
            IntentTypeV1.ASK_GRID_CONTENTS_OVERVIEW,
            IntentTypeV1.ASK_COMPLETE_HOUSES_COUNT,
            IntentTypeV1.ASK_COMPLETE_HOUSES_LIST,
            IntentTypeV1.ASK_HOUSES_COMPLETION_RANKING,
            IntentTypeV1.ASK_STRUCTURAL_VALIDITY,
            IntentTypeV1.ASK_CONFLICTS_GLOBAL,
            IntentTypeV1.ASK_CONFLICTS_IN_HOUSE,
            IntentTypeV1.ASK_CONFLICT_DETAILS_CELL,
            IntentTypeV1.ASK_DUPLICATES_IN_HOUSE,
            IntentTypeV1.ASK_UNRESOLVED_CELLS,
            IntentTypeV1.ASK_INVALID_REASON_EXPLAIN,
            IntentTypeV1.ASK_IF_RETAKE_NEEDED,
            IntentTypeV1.ASK_SEAL_STATUS,
            IntentTypeV1.ASK_CONFLICTS_OVERVIEW,
            IntentTypeV1.ASK_VALIDATION_OVERVIEW,
            IntentTypeV1.ASK_PROBLEM_CELLS_OVERVIEW,
            IntentTypeV1.ASK_MISMATCH_OVERVIEW,
            IntentTypeV1.ASK_RETAKE_GUIDANCE,
            IntentTypeV1.ASK_WHAT_CHANGED_RECENTLY,
            IntentTypeV1.ASK_SOURCE_OF_DIGIT,
            IntentTypeV1.ASK_OCR_CONFIDENCE_CELL,
            IntentTypeV1.ASK_OCR_CONFIDENCE_SUMMARY,
            IntentTypeV1.ASK_TRUST_OVERVIEW,
            IntentTypeV1.ASK_CELL_TRUST_DETAILS,
            IntentTypeV1.ASK_PROVENANCE_OVERVIEW,
            IntentTypeV1.ASK_UI_LEGEND,
            IntentTypeV1.ASK_HOW_TO_LOCATE_CELL,
            IntentTypeV1.ASK_BOX_INDEX_MAPPING,
            IntentTypeV1.ASK_COORDINATE_TRANSLATION,
            IntentTypeV1.ASK_WHAT_DO_YOU_MEAN_BY_HOUSE,
            IntentTypeV1.ASK_UI_HELP,
            IntentTypeV1.ASK_COORDINATES_HELP,
            IntentTypeV1.ASK_WHAT_YOU_KNOW_NOW,
            IntentTypeV1.ASK_WHAT_YOU_DONT_KNOW,
            IntentTypeV1.REQUEST_EXPORT_STATE ->
                DetourQuestionClassV1.GENERAL_QUESTION

            else ->
                if (isUserDetourIntentForAgendaV1(topType)) {
                    DetourQuestionClassV1.UNSUPPORTED_DETOUR
                } else {
                    null
                }
        }
    }

    private fun agendaMaterializationClassForSolvingPhaseV1(
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): DetourQuestionClassV1? {
        val topIntent = env.intents.firstOrNull() ?: return null
        val topType = topIntent.type

        if (isDirectAppOwnedIntentForAgendaV1(topType)) {
            return null
        }

        if (routing.isRouteControl || isRouteJumpIntentForAgendaV1(topType)) {
            return DetourQuestionClassV1.ROUTE_CONTROL
        }

        val explicitCell = firstExplicitCellTargetV1(env)
        val explicitDigit = firstExplicitDigitTargetV1(env)
        val explicitRegion = firstExplicitRegionRefV1(env)
        val semanticFamily = firstDetourSemanticFamilyV1(env)

        when (topType) {
            IntentTypeV1.REQUEST_REASONING_CHECK,
            IntentTypeV1.CHECK_PROPOSED_DIGIT_IN_CELL,
            IntentTypeV1.CHECK_PROPOSED_CANDIDATE_SET_IN_CELL,
            IntentTypeV1.CHECK_PROPOSED_ELIMINATION_IN_SCOPE,
            IntentTypeV1.CHECK_PROPOSED_TECHNIQUE_APPLIES_HERE,
            IntentTypeV1.CHECK_PROPOSED_ROUTE_EQUIVALENCE ->
                return if (
                    shouldPreferProofChallengeOverReasoningCheckV1(
                        topType = topType,
                        semanticFamily = semanticFamily,
                        explicitCell = explicitCell,
                        explicitDigit = explicitDigit,
                        explicitRegion = explicitRegion
                    )
                ) {
                    DetourQuestionClassV1.PROOF_CHALLENGE
                } else {
                    DetourQuestionClassV1.USER_REASONING_CHECK
                }

            IntentTypeV1.REPORT_BUG_OR_WRONG_ASSERTION,
            IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT,
            IntentTypeV1.ASK_WHY_NOT_DIGIT_IN_CELL,
            IntentTypeV1.ASK_WHY_DIGIT_IN_CELL,
            IntentTypeV1.ASK_WHAT_BLOCKS_DIGIT_IN_HOUSE ->
                return DetourQuestionClassV1.PROOF_CHALLENGE

            IntentTypeV1.ASK_WHY_THIS_CELL,
            IntentTypeV1.ASK_WHY_THIS_CELL_IS_TARGET_FOR_DIGIT,
            IntentTypeV1.ASK_WHY_THIS_CELL_NOT_OTHER_CELL ->
                return when {
                    explicitDigit != null || explicitCell != null ->
                        DetourQuestionClassV1.PROOF_CHALLENGE
                    else ->
                        DetourQuestionClassV1.TARGET_CELL_QUERY
                }

            IntentTypeV1.ASK_ONLY_PLACE_FOR_DIGIT_IN_HOUSE ->
                return DetourQuestionClassV1.PROOF_CHALLENGE

            IntentTypeV1.ASK_WHY_CURRENT_MOVE_BEFORE_OTHER_MOVE,
            IntentTypeV1.ASK_WHY_THIS_TECHNIQUE_APPLIES_HERE ->
                return DetourQuestionClassV1.PROOF_CHALLENGE

            IntentTypeV1.ASK_TECHNIQUES_NEEDED,
            IntentTypeV1.ASK_SOLVING_OVERVIEW,
            IntentTypeV1.ASK_TECHNIQUE_OVERVIEW,
            IntentTypeV1.ASK_STUCK_HELP,
            IntentTypeV1.ASK_ADVANCED_PATTERN_HELP,
            IntentTypeV1.ASK_HIDDEN_SINGLE_LOCATIONS,
            IntentTypeV1.ASK_NAKED_SINGLE_LOCATIONS,
            IntentTypeV1.ASK_NAKED_PAIR_LOCATIONS,
            IntentTypeV1.ASK_HIDDEN_PAIR_LOCATIONS,
            IntentTypeV1.ASK_POINTING_PAIR_TRIPLE,
            IntentTypeV1.ASK_BOX_LINE_REDUCTION,
            IntentTypeV1.ASK_XWING_CANDIDATE ->
                return DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY

            IntentTypeV1.ASK_COMPARE_CANDIDATES_BETWEEN_CELLS ->
                return DetourQuestionClassV1.NEIGHBOR_CELL_QUERY

            IntentTypeV1.ASK_ALTERNATIVE_TECHNIQUE_FOR_CURRENT_SPOT ->
                return DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY

            IntentTypeV1.ASK_COMPARE_CURRENT_ROUTE_WITH_ALTERNATIVE_ROUTE ->
                return DetourQuestionClassV1.ROUTE_COMPARISON_QUERY

            IntentTypeV1.ASK_OTHER_LOCAL_MOVE_EXISTS ->
                return DetourQuestionClassV1.NEIGHBOR_CELL_QUERY

            IntentTypeV1.REQUEST_EXPLANATION ->
                return when {
                    shouldTreatRequestExplanationAsProofChallengeV1(
                        semanticFamily = semanticFamily,
                        explicitCell = explicitCell,
                        explicitDigit = explicitDigit,
                        explicitRegion = explicitRegion
                    ) ->
                        DetourQuestionClassV1.PROOF_CHALLENGE

                    semanticFamilyImpliesTargetCellQueryV1(semanticFamily) || explicitCell != null ->
                        DetourQuestionClassV1.TARGET_CELL_QUERY

                    semanticFamilyImpliesCandidateStateQueryV1(semanticFamily) || explicitRegion != null ->
                        DetourQuestionClassV1.CANDIDATE_STATE_QUERY

                    else ->
                        DetourQuestionClassV1.GENERAL_QUESTION
                }

            IntentTypeV1.ASK_CELL_CANDIDATES,
            IntentTypeV1.ASK_CELL_CANDIDATES_EXACT,
            IntentTypeV1.ASK_CANDIDATE_COUNT_CELL,
            IntentTypeV1.ASK_CELL_CANDIDATE_COUNT_EXACT,
            IntentTypeV1.ASK_CELLS_WITH_N_CANDIDATES,
            IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP,
            IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP_EXACT,
            IntentTypeV1.ASK_CANDIDATE_FREQUENCY,
            IntentTypeV1.ASK_CANDIDATES_OVERVIEW,
            IntentTypeV1.ASK_CANDIDATES_CELL_OVERVIEW,
            IntentTypeV1.ASK_CANDIDATES_DISTRIBUTION,
            IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE,
            IntentTypeV1.ASK_CELL_STATUS,
            IntentTypeV1.ASK_WHAT_CHANGED_IN_SCOPE_RECENTLY ->
                return DetourQuestionClassV1.CANDIDATE_STATE_QUERY

            IntentTypeV1.ASK_DIGIT_LOCATIONS,
            IntentTypeV1.ASK_DIGIT_LOCATIONS_IN_HOUSE_EXACT ->
                return when {
                    explicitDigit != null && explicitRegion != null ->
                        DetourQuestionClassV1.PROOF_CHALLENGE
                    else ->
                        DetourQuestionClassV1.CANDIDATE_STATE_QUERY
                }

            else -> Unit
        }

        routing.detourQuestionClass?.let { return it }

        return when (topType) {
            IntentTypeV1.REQUEST_REASONING_CHECK,
            IntentTypeV1.CHECK_PROPOSED_DIGIT_IN_CELL,
            IntentTypeV1.CHECK_PROPOSED_CANDIDATE_SET_IN_CELL,
            IntentTypeV1.CHECK_PROPOSED_ELIMINATION_IN_SCOPE,
            IntentTypeV1.CHECK_PROPOSED_TECHNIQUE_APPLIES_HERE,
            IntentTypeV1.CHECK_PROPOSED_ROUTE_EQUIVALENCE ->
                if (
                    shouldPreferProofChallengeOverReasoningCheckV1(
                        topType = topType,
                        semanticFamily = semanticFamily,
                        explicitCell = explicitCell,
                        explicitDigit = explicitDigit,
                        explicitRegion = explicitRegion
                    )
                ) {
                    DetourQuestionClassV1.PROOF_CHALLENGE
                } else {
                    DetourQuestionClassV1.USER_REASONING_CHECK
                }

            IntentTypeV1.REPORT_BUG_OR_WRONG_ASSERTION,
            IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT,
            IntentTypeV1.ASK_WHY_NOT_DIGIT_IN_CELL,
            IntentTypeV1.ASK_WHY_DIGIT_IN_CELL,
            IntentTypeV1.ASK_WHAT_BLOCKS_DIGIT_IN_HOUSE ->
                DetourQuestionClassV1.PROOF_CHALLENGE

            IntentTypeV1.ASK_WHY_THIS_CELL,
            IntentTypeV1.ASK_WHY_THIS_CELL_IS_TARGET_FOR_DIGIT,
            IntentTypeV1.ASK_WHY_THIS_CELL_NOT_OTHER_CELL ->
                if (explicitDigit != null || explicitCell != null) {
                    DetourQuestionClassV1.PROOF_CHALLENGE
                } else {
                    DetourQuestionClassV1.TARGET_CELL_QUERY
                }

            IntentTypeV1.ASK_ONLY_PLACE_FOR_DIGIT_IN_HOUSE ->
                DetourQuestionClassV1.PROOF_CHALLENGE

            IntentTypeV1.SWITCH_FOCUS_CELL,
            IntentTypeV1.SWITCH_FOCUS_REGION ->
                DetourQuestionClassV1.OVERLAY_CONTROL


            IntentTypeV1.CAPABILITY_CHECK,
            IntentTypeV1.META_APP_QUESTION,
            IntentTypeV1.FREE_TALK,
            IntentTypeV1.SOLVE_PAUSE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION,
            IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION,
            IntentTypeV1.REQUEST_CURRENT_STAGE_COLLAPSE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_EXAMPLE,
            IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT,
            IntentTypeV1.REQUEST_CURRENT_STAGE_REPHRASE,
            IntentTypeV1.ASK_SOLVABILITY_STATUS,
            IntentTypeV1.ASK_PROGRESS_METRICS,
            IntentTypeV1.ASK_IF_STUCK,
            IntentTypeV1.ASK_IF_GUESS_REQUIRED,
            IntentTypeV1.ASK_DIFFICULTY_ESTIMATE,
            IntentTypeV1.ASK_NEXT_MOVE_EXACT,
            IntentTypeV1.ASK_CELL_VALUE,
            IntentTypeV1.ASK_CELL_VALUE_EXACT,
            IntentTypeV1.ASK_CELL_STATUS,
            IntentTypeV1.ASK_ROW_CONTENTS,
            IntentTypeV1.ASK_COL_CONTENTS,
            IntentTypeV1.ASK_BOX_CONTENTS,
            IntentTypeV1.ASK_HOUSE_COMPLETION,
            IntentTypeV1.ASK_HOUSE_MISSING_DIGITS,
            IntentTypeV1.ASK_DIGIT_LOCATIONS,
            IntentTypeV1.ASK_DIGIT_LOCATIONS_IN_HOUSE_EXACT ->
                if (explicitDigit != null && explicitRegion != null) {
                    DetourQuestionClassV1.PROOF_CHALLENGE
                } else {
                    DetourQuestionClassV1.CANDIDATE_STATE_QUERY
                }

            IntentTypeV1.REQUEST_EXPLANATION ->
                if (
                    shouldTreatRequestExplanationAsProofChallengeV1(
                        semanticFamily = semanticFamily,
                        explicitCell = explicitCell,
                        explicitDigit = explicitDigit,
                        explicitRegion = explicitRegion
                    )
                ) {
                    DetourQuestionClassV1.PROOF_CHALLENGE
                } else if (semanticFamilyImpliesTargetCellQueryV1(semanticFamily) || explicitCell != null) {
                    DetourQuestionClassV1.TARGET_CELL_QUERY
                } else if (semanticFamilyImpliesCandidateStateQueryV1(semanticFamily) || explicitRegion != null) {
                    DetourQuestionClassV1.CANDIDATE_STATE_QUERY
                } else {
                    DetourQuestionClassV1.GENERAL_QUESTION
                }

            IntentTypeV1.ASK_DIGIT_COUNT_GLOBAL,
            IntentTypeV1.ASK_DIGIT_COUNT_GLOBAL,
            IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE,
            IntentTypeV1.ASK_EMPTY_HOUSES,
            IntentTypeV1.ASK_NEARLY_COMPLETE_HOUSES,
            IntentTypeV1.ASK_HOUSE_OVERVIEW,
            IntentTypeV1.ASK_HOUSE_RANKING,
            IntentTypeV1.ASK_DIGIT_OVERVIEW,
            IntentTypeV1.ASK_DIGIT_IN_HOUSE_OVERVIEW,
            IntentTypeV1.ASK_GRID_CONTENTS_OVERVIEW,
            IntentTypeV1.ASK_COMPLETE_HOUSES_COUNT,
            IntentTypeV1.ASK_COMPLETE_HOUSES_LIST,
            IntentTypeV1.ASK_HOUSES_COMPLETION_RANKING,
            IntentTypeV1.ASK_STRUCTURAL_VALIDITY,
            IntentTypeV1.ASK_CONFLICTS_GLOBAL,
            IntentTypeV1.ASK_CONFLICTS_IN_HOUSE,
            IntentTypeV1.ASK_CONFLICT_DETAILS_CELL,
            IntentTypeV1.ASK_DUPLICATES_IN_HOUSE,
            IntentTypeV1.ASK_UNRESOLVED_CELLS,
            IntentTypeV1.ASK_INVALID_REASON_EXPLAIN,
            IntentTypeV1.ASK_IF_RETAKE_NEEDED,
            IntentTypeV1.ASK_SEAL_STATUS,
            IntentTypeV1.ASK_CONFLICTS_OVERVIEW,
            IntentTypeV1.ASK_VALIDATION_OVERVIEW,
            IntentTypeV1.ASK_PROBLEM_CELLS_OVERVIEW,
            IntentTypeV1.ASK_MISMATCH_OVERVIEW,
            IntentTypeV1.ASK_RETAKE_GUIDANCE,
            IntentTypeV1.ASK_WHAT_CHANGED_RECENTLY,
            IntentTypeV1.ASK_WHAT_CHANGED_IN_SCOPE_RECENTLY,
            IntentTypeV1.ASK_SOURCE_OF_DIGIT,
            IntentTypeV1.ASK_SOURCE_OF_DIGIT_IN_CELL_EXACT,
            IntentTypeV1.ASK_OCR_CONFIDENCE_CELL,


            IntentTypeV1.ASK_OCR_CONFIDENCE_SUMMARY,
            IntentTypeV1.ASK_TRUST_OVERVIEW,
            IntentTypeV1.ASK_CELL_TRUST_DETAILS,
            IntentTypeV1.ASK_PROVENANCE_OVERVIEW,
            IntentTypeV1.ASK_UI_LEGEND,
            IntentTypeV1.ASK_HOW_TO_LOCATE_CELL,
            IntentTypeV1.ASK_BOX_INDEX_MAPPING,
            IntentTypeV1.ASK_COORDINATE_TRANSLATION,
            IntentTypeV1.ASK_WHAT_DO_YOU_MEAN_BY_HOUSE,
            IntentTypeV1.ASK_UI_HELP,
            IntentTypeV1.ASK_COORDINATES_HELP,
            IntentTypeV1.ASK_WHAT_YOU_KNOW_NOW,
            IntentTypeV1.ASK_WHAT_YOU_DONT_KNOW,
            IntentTypeV1.REQUEST_EXPORT_STATE ->
                DetourQuestionClassV1.GENERAL_QUESTION

            else ->
                if (isUserDetourIntentForAgendaV1(topType)) {
                    DetourQuestionClassV1.UNSUPPORTED_DETOUR
                } else {
                    null
                }
        }
    }

    private fun agendaMaterializationClassFromIntentFamilyV1(
        s: SudoState,
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): DetourQuestionClassV1? =
        when (demandRoutingPhaseV1(s)) {
            GridPhase.CONFIRMING,
            GridPhase.SEALING ->
                agendaMaterializationClassForConfirmingPhaseV1(
                    env = env,
                    routing = routing
                )

            GridPhase.SOLVING ->
                agendaMaterializationClassForSolvingPhaseV1(
                    env = env,
                    routing = routing
                )
        }

    private fun buildUserAgendaItemFromDetourV1(
        s: SudoState,
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): UserAgendaItem? {
        val questionClass =
            agendaMaterializationClassFromIntentFamilyV1(
                s = s,
                env = env,
                routing = routing
            ) ?: return null

        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "PHASE_AWARE_MATERIALIZATION_V1",
                data = mapOf(
                    "turn_id" to s.turnSeq,
                    "phase" to demandRoutingPhaseV1(s).name,
                    "top_intent_type" to (env.intents.firstOrNull()?.type?.name ?: "null"),
                    "routing_detour_question_class" to (routing.detourQuestionClass?.name ?: "null"),
                    "materialized_detour_question_class" to questionClass.name
                )
            )
        }

        val topIntent = env.intents.firstOrNull() ?: return null
        val checkpoint = s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s)

        val idSuffix = "${s.turnSeq}:${topIntent.id}"

        val clarificationCarry = activeDetourClarificationCarryV1(s)

        val resolvedCellRef =
            firstExplicitCellTargetV1(env)

        val resolvedDigit =
            firstExplicitDigitTargetV1(env)

        val resolvedRegionRef =
            firstExplicitRegionRefV1(env)


        val resolvedTechniqueLabel =
            topIntent.payload.technique?.trim()?.takeIf { it.isNotBlank() }

        val resolvedRivalCellRef =
            firstExplicitCell2TargetV1(env)

        val mergedCellRef = resolvedCellRef ?: clarificationCarry?.carriedCellRef
        val mergedDigit = resolvedDigit ?: clarificationCarry?.carriedDigit
        val mergedRegionRef = resolvedRegionRef ?: clarificationCarry?.carriedRegionRef
        val mergedTechniqueLabel = resolvedTechniqueLabel ?: clarificationCarry?.carriedTechniqueLabel
        val mergedRivalCellRef = resolvedRivalCellRef

        val effectiveProofLaneHint =
            when {
                topIntent.type == IntentTypeV1.ASK_WHY_CURRENT_MOVE_BEFORE_OTHER_MOVE &&
                        !mergedRivalCellRef.isNullOrBlank() ->
                    DetourProofChallengeLaneV1.RIVAL_COMPARISON

                topIntent.type == IntentTypeV1.ASK_WHY_THIS_TECHNIQUE_APPLIES_HERE ||
                        topIntent.type == IntentTypeV1.CHECK_PROPOSED_TECHNIQUE_APPLIES_HERE ->
                    DetourProofChallengeLaneV1.TECHNIQUE_LEGITIMACY

                else ->
                    routing.proofChallengeLaneHint
            }

        val anchorCellRef =
            checkpoint?.targetCellIndex?.let { indexToCell(it) }
                ?: readSolveStepTargetOrFocusCellV1(s)

        fun baseCheckpointRouteId() = checkpoint?.routeId
        fun baseCheckpointPhase() = checkpoint?.phase
        fun baseCheckpointAppAgendaKind() = checkpoint?.appAgendaKind
        fun baseCheckpointStepId() = checkpoint?.stepId
        fun baseCheckpointStoryStage() = checkpoint?.storyStage



        if (isPostResolutionMismatchReportV1(s, env)) {
            val targetIdx =
                s.activeRouteContext?.targetCellIndex
                    ?: s.coachPlan?.reveal?.placementCellIndex
                    ?: s.focusCellIndex

            val targetCellRef =
                targetIdx?.let { indexToCell(it) } ?: resolvedCellRef

            val targetDigit =
                s.coachPlan?.reveal?.placementDigit
                    ?.takeIf { it in 1..9 }

            return UserAgendaItem.TargetCellQuery(
                id = "ua:post_resolution_mismatch:$idSuffix",
                intentId = topIntent.id,
                targetCellRef = targetCellRef,
                digit = targetDigit,
                askKind = TargetCellAskKindV1.WHY_THIS_TARGET,
                createdTurnSeq = s.turnSeq,
                checkpointRouteId = baseCheckpointRouteId(),
                checkpointPhase = baseCheckpointPhase(),
                checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                checkpointStepId = baseCheckpointStepId(),
                checkpointStoryStage = baseCheckpointStoryStage(),
                status = UserAgendaStatusV1.OPEN
            )
        }

        val routingPhase = demandRoutingPhaseV1(s)

        val detourAdmission =
            ClarificationKernelV1.assessDetourQuestionAdmission(
                questionClass = questionClass,
                routingPhase = routingPhase,
                explicitCellRef = mergedCellRef,
                explicitDigit = mergedDigit,
                explicitRegionRef = mergedRegionRef,
                anchorCellRef = anchorCellRef,
                techniqueLabel = mergedTechniqueLabel
            )

        detourAdmission.clarification?.let { clar ->
            return UserAgendaItem.Clarification(
                id = "ua:clarify_detour:$idSuffix",
                intentId = topIntent.id,
                missing = clar.missing,
                askedTurnSeq = s.turnSeq,
                createdTurnSeq = s.turnSeq,
                prompt = clar.prompt,
                detourQuestionClass = questionClass,
                carriedCellRef = mergedCellRef,
                carriedDigit = mergedDigit,
                carriedRegionRef = mergedRegionRef,
                carriedTechniqueLabel = mergedTechniqueLabel,
                checkpointRouteId = baseCheckpointRouteId(),
                checkpointPhase = baseCheckpointPhase(),
                checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                checkpointStepId = baseCheckpointStepId(),
                checkpointStoryStage = baseCheckpointStoryStage(),
                status = UserAgendaStatusV1.OPEN
            )
        }



        return when (questionClass) {
            DetourQuestionClassV1.STEP_CLARIFICATION ->
                UserAgendaItem.GeneralQuestion(
                    id = "ua:general:$idSuffix",
                    intentId = topIntent.id,
                    topic = "step_clarification",
                    prompt = topIntent.payload.rawText,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.PROOF_CHALLENGE ->
                UserAgendaItem.ProofChallenge(
                    id = "ua:proof:$idSuffix",
                    intentId = topIntent.id,
                    cellRef = mergedCellRef,
                    digit = mergedDigit,
                    houseRef = mergedRegionRef,
                    askKind = when {
                        topIntent.type == IntentTypeV1.ASK_WHY_CURRENT_MOVE_BEFORE_OTHER_MOVE ->
                            ProofChallengeAskKindV1.WHY_CURRENT_MOVE_BEFORE_OTHER_MOVE

                        topIntent.type == IntentTypeV1.ASK_WHY_THIS_TECHNIQUE_APPLIES_HERE ->
                            ProofChallengeAskKindV1.WHY_TECHNIQUE_APPLIES

                        topIntent.type == IntentTypeV1.ASK_DIGIT_LOCATIONS_IN_HOUSE_EXACT ->
                            ProofChallengeAskKindV1.WHERE_DIGIT_CAN_STILL_GO_IN_HOUSE

                        topIntent.type == IntentTypeV1.ASK_WHY_THIS_CELL_IS_TARGET_FOR_DIGIT ||
                                topIntent.type == IntentTypeV1.ASK_WHY_THIS_CELL ->
                            ProofChallengeAskKindV1.WHY_THIS_TARGET

                        effectiveProofLaneHint == DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS &&
                                topIntent.type == IntentTypeV1.ASK_ONLY_PLACE_FOR_DIGIT_IN_HOUSE ->
                            ProofChallengeAskKindV1.WHY_ONLY_PLACE

                        effectiveProofLaneHint == DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS &&
                                !mergedRegionRef.isNullOrBlank() ->
                            ProofChallengeAskKindV1.WHERE_DIGIT_CAN_STILL_GO_IN_HOUSE

                        effectiveProofLaneHint == DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS ->
                            ProofChallengeAskKindV1.WHY_FORCED_IN_CELL

                        effectiveProofLaneHint == DetourProofChallengeLaneV1.RIVAL_COMPARISON ->
                            ProofChallengeAskKindV1.WHY_THIS_NOT_THAT

                        effectiveProofLaneHint == DetourProofChallengeLaneV1.TECHNIQUE_LEGITIMACY ->
                            ProofChallengeAskKindV1.WHY_TECHNIQUE_APPLIES

                        effectiveProofLaneHint == DetourProofChallengeLaneV1.NON_PROOF_OR_NOT_ESTABLISHED ->
                            ProofChallengeAskKindV1.IS_THIS_LOCALLY_PROVED

                        topIntent.type == IntentTypeV1.ASK_WHY_NOT_DIGIT_IN_CELL ||
                                topIntent.type == IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT ->
                            ProofChallengeAskKindV1.WHY_NOT_DIGIT

                        topIntent.type == IntentTypeV1.ASK_WHY_DIGIT_IN_CELL ->
                            ProofChallengeAskKindV1.WHY_DIGIT

                        topIntent.type == IntentTypeV1.ASK_WHAT_BLOCKS_DIGIT_IN_HOUSE ->
                            ProofChallengeAskKindV1.WHAT_BLOCKS_DIGIT_IN_HOUSE

                        else ->
                            ProofChallengeAskKindV1.PROVE_ELIMINATION
                    },
                    laneHint = effectiveProofLaneHint,
                    rivalCellRef = mergedRivalCellRef,
                    rivalDigit = if (effectiveProofLaneHint == DetourProofChallengeLaneV1.RIVAL_COMPARISON) mergedDigit else null,
                    claimedTechniqueId = if (effectiveProofLaneHint == DetourProofChallengeLaneV1.TECHNIQUE_LEGITIMACY) mergedTechniqueLabel else null,
                    proofObjectHint = when (effectiveProofLaneHint) {
                        DetourProofChallengeLaneV1.CANDIDATE_IMPOSSIBILITY -> "CELL_CANNOT_BE_DIGIT"
                        DetourProofChallengeLaneV1.CANDIDATE_POSSIBILITY -> "CELL_CAN_BE_DIGIT"
                        DetourProofChallengeLaneV1.FORCEDNESS_OR_UNIQUENESS ->
                            if (!mergedRegionRef.isNullOrBlank()) {
                                "CELL_IS_ONLY_PLACE_FOR_DIGIT_IN_HOUSE"
                            } else {
                                "DIGIT_SURVIVES_RIVAL_CANDIDATES_IN_CELL"
                            }

                        DetourProofChallengeLaneV1.RIVAL_COMPARISON -> "CELL_A_WINS_OVER_CELL_B_FOR_DIGIT"
                        DetourProofChallengeLaneV1.HOUSE_BLOCKER -> "HOUSE_BLOCKS_DIGIT_FOR_TARGET"
                        DetourProofChallengeLaneV1.TECHNIQUE_LEGITIMACY -> "TECHNIQUE_CLAIM_IS_VALID"
                        DetourProofChallengeLaneV1.ELIMINATION_LEGITIMACY -> "ELIMINATION_IS_LEGAL"
                        DetourProofChallengeLaneV1.NON_PROOF_OR_NOT_ESTABLISHED -> "LOCAL_PROOF_INSUFFICIENT"
                        null -> null
                    },
                    prompt = topIntent.payload.rawText,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.TARGET_CELL_QUERY ->
                UserAgendaItem.TargetCellQuery(
                    id = "ua:target:$idSuffix",
                    intentId = topIntent.id,
                    targetCellRef = resolvedCellRef,
                    digit = resolvedDigit,
                    askKind = when (topIntent.type) {
                        IntentTypeV1.ASK_WHAT_CHANGED_RECENTLY,
                        IntentTypeV1.ASK_WHAT_CHANGED_IN_SCOPE_RECENTLY ->
                            TargetCellAskKindV1.WHAT_CHANGED_IN_TARGET

                        IntentTypeV1.ASK_CELL_STATUS ->
                            TargetCellAskKindV1.WHAT_REMAINS_IN_TARGET

                        IntentTypeV1.ASK_ONLY_PLACE_FOR_DIGIT_IN_HOUSE ->
                            TargetCellAskKindV1.IS_ONLY_PLACE_FOR_DIGIT

                        else ->
                            TargetCellAskKindV1.WHY_THIS_TARGET
                    },
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.NEIGHBOR_CELL_QUERY ->
                UserAgendaItem.NeighborCellQuery(
                    id = "ua:neighbor:$idSuffix",
                    intentId = topIntent.id,
                    anchorCellRef = anchorCellRef,
                    neighborCellRef = resolvedCellRef,
                    askKind = when (topIntent.type) {
                        IntentTypeV1.ASK_COMPARE_CANDIDATES_BETWEEN_CELLS ->
                            NeighborAskKindV1.COMPARE_CANDIDATES

                        IntentTypeV1.ASK_OTHER_LOCAL_MOVE_EXISTS ->
                            NeighborAskKindV1.LOCAL_MOVE_SEARCH

                        else ->
                            if (resolvedRegionRef != null && resolvedCellRef == null) {
                                NeighborAskKindV1.STAY_IN_REGION
                            } else {
                                NeighborAskKindV1.NEARBY_EFFECT
                            }
                    },
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.CANDIDATE_STATE_QUERY ->
                UserAgendaItem.CandidateStateQuery(
                    id = "ua:cands:$idSuffix",
                    intentId = topIntent.id,
                    cellRefs = listOfNotNull(resolvedCellRef),
                    houseRef = resolvedRegionRef,
                    digit = resolvedDigit,
                    askKind = when (topIntent.type) {
                        IntentTypeV1.ASK_CANDIDATE_COUNT_CELL,
                        IntentTypeV1.ASK_CELL_CANDIDATE_COUNT_EXACT ->
                            CandidateAskKindV1.CELL_CANDIDATE_COUNT

                        IntentTypeV1.ASK_DIGIT_LOCATIONS,
                        IntentTypeV1.ASK_DIGIT_LOCATIONS_IN_HOUSE_EXACT,
                        IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE ->
                            CandidateAskKindV1.DIGIT_LOCATIONS_IN_HOUSE

                        IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP,
                        IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP_EXACT,
                        IntentTypeV1.ASK_CANDIDATES_OVERVIEW,
                        IntentTypeV1.ASK_CANDIDATES_DISTRIBUTION,
                        IntentTypeV1.ASK_CANDIDATE_FREQUENCY ->
                            CandidateAskKindV1.HOUSE_CANDIDATE_MAP

                        IntentTypeV1.ASK_CELL_STATUS,
                        IntentTypeV1.ASK_CELL_CANDIDATES,
                        IntentTypeV1.ASK_CELL_CANDIDATES_EXACT,
                        IntentTypeV1.ASK_CANDIDATES_CELL_OVERVIEW ->
                            CandidateAskKindV1.CELL_CANDIDATES

                        IntentTypeV1.ASK_WHAT_CHANGED_RECENTLY,
                        IntentTypeV1.ASK_WHAT_CHANGED_IN_SCOPE_RECENTLY ->
                            CandidateAskKindV1.CANDIDATE_CHANGES

                        else -> if (resolvedRegionRef != null && resolvedDigit != null) {
                            CandidateAskKindV1.DIGIT_LOCATIONS_IN_HOUSE
                        } else if (resolvedRegionRef != null) {
                            CandidateAskKindV1.HOUSE_CANDIDATE_MAP
                        } else {
                            CandidateAskKindV1.CELL_CANDIDATES
                        }
                    },
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.USER_REASONING_CHECK ->
                UserAgendaItem.UserReasoningCheck(
                    id = "ua:reasoning:$idSuffix",
                    intentId = topIntent.id,
                    cellRef = resolvedCellRef,
                    proposedDigits = topIntent.payload.digits ?: emptyList(),
                    prompt = topIntent.payload.rawText,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.ALTERNATIVE_TECHNIQUE_QUERY ->
                UserAgendaItem.AlternativeTechniqueQuery(
                    id = "ua:alttech:$idSuffix",
                    intentId = topIntent.id,
                    cellRef = resolvedCellRef,
                    regionRef = resolvedRegionRef,
                    requestedTechniqueIdOrLabel = resolvedTechniqueLabel,
                    askKind = AlternativeTechniqueAskKindV1.IS_THIS_ALTERNATIVE_VALID,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.ROUTE_COMPARISON_QUERY ->
                UserAgendaItem.RouteComparisonQuery(
                    id = "ua:routecmp:$idSuffix",
                    intentId = topIntent.id,
                    compareScope = resolvedRegionRef ?: if (resolvedCellRef != null) "cell" else "local",
                    userIdeaLabel = resolvedTechniqueLabel,
                    askKind = RouteCompareAskKindV1.SAME_ROUTE_OR_DIFFERENT,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.OVERLAY_CONTROL ->
                UserAgendaItem.OverlayControl(
                    id = "ua:overlay:$idSuffix",
                    intentId = topIntent.id,
                    control = OverlayControlKindV1.PRESERVE_CURRENT,
                    focusCellRef = resolvedCellRef,
                    regionRef = resolvedRegionRef,
                    digit = resolvedDigit,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.GENERAL_QUESTION,
            DetourQuestionClassV1.REPAIR_QUESTION ->
                UserAgendaItem.GeneralQuestion(
                    id = "ua:general:$idSuffix",
                    intentId = topIntent.id,
                    topic = questionClass.name.lowercase(),
                    prompt = topIntent.payload.rawText,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.ROUTE_CONTROL ->
                UserAgendaItem.RouteControl(
                    id = "ua:routectl:$idSuffix",
                    intentId = topIntent.id,
                    control = routeControlKindFromEnvV1(env),
                    prompt = topIntent.payload.rawText,
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN
                )

            DetourQuestionClassV1.UNSUPPORTED_DETOUR ->
                UserAgendaItem.GeneralQuestion(
                    id = "ua:unsupported:$idSuffix",
                    intentId = topIntent.id,
                    topic = "unsupported_detour",
                    prompt =
                        "Acknowledge the user’s Sudoku question honestly. Explain that this question type is not yet supported reliably in this version, do not guess, and offer either one different question or a return to the paused move.",
                    createdTurnSeq = s.turnSeq,
                    checkpointRouteId = baseCheckpointRouteId(),
                    checkpointPhase = baseCheckpointPhase(),
                    checkpointAppAgendaKind = baseCheckpointAppAgendaKind(),
                    checkpointStepId = baseCheckpointStepId(),
                    checkpointStoryStage = baseCheckpointStoryStage(),
                    status = UserAgendaStatusV1.OPEN,
                    allowsFollowUp = true
                )
        }
    }

    private fun currentAppAgendaHead(s: SudoState): AppAgendaItem? =
        s.appAgendaQueue.firstOrNull()




    private fun appAgendaKindNameV1(item: AppAgendaItem?): String? =
        when (item) {
            null -> null

            is AppAgendaItem.RetakeDecision -> "RetakeDecision"
            is AppAgendaItem.MismatchReview -> "MismatchReview"
            is AppAgendaItem.ConflictReview -> "ConflictReview"
            is AppAgendaItem.ConfirmValidationExactMatch -> "ConfirmValidationExactMatch"
            is AppAgendaItem.VisualVerificationRequest -> "VisualVerificationRequest"
            is AppAgendaItem.RecommendDifferentGrid -> "RecommendDifferentGrid"
            is AppAgendaItem.FinalizeValidationStartSolving -> "FinalizeValidationStartSolving"

            is AppAgendaItem.Solving.StepIntro -> "StepIntro"
            is AppAgendaItem.Solving.AtomWalk -> "AtomWalk"
            is AppAgendaItem.Solving.CommitDecision -> "CommitDecision"
            is AppAgendaItem.Solving.CommitApply -> "CommitApply"
            is AppAgendaItem.Solving.PostCommitChoice -> "PostCommitChoice"
            is AppAgendaItem.Solving.TechniqueTeach -> "TechniqueTeach"
            is AppAgendaItem.Solving.DetourFreeTalk -> "LegacyDetourFreeTalk"
            is AppAgendaItem.Solving.Walkback -> "Walkback"
            is AppAgendaItem.Solving.RecoveryRecomputeStep -> "RecoveryRecomputeStep"

            is AppAgendaItem.ProposeRetake -> "ProposeRetake"
            is AppAgendaItem.ProposeEdit -> "ProposeEdit"
            is AppAgendaItem.AskConfirmCell -> "AskConfirmCell"
        }






    private fun appAgendaStableIdV1(item: AppAgendaItem?): String? =
        when (item) {
            null -> null

            is AppAgendaItem.Solving -> item.agendaId

            is AppAgendaItem.RetakeDecision ->
                "aa:retake:${item.createdTurnSeq}"

            is AppAgendaItem.MismatchReview ->
                "aa:mismatch:${item.createdTurnSeq}:${item.cellIndex}"

            is AppAgendaItem.ConflictReview ->
                "aa:conflict:${item.createdTurnSeq}:${item.cellIndex}"

            is AppAgendaItem.ConfirmValidationExactMatch ->
                "aa:confirm_validate:${item.createdTurnSeq}"

            is AppAgendaItem.VisualVerificationRequest ->
                "aa:visual_verify:${item.createdTurnSeq}"

            is AppAgendaItem.RecommendDifferentGrid ->
                "aa:recommend_grid:${item.createdTurnSeq}"

            is AppAgendaItem.FinalizeValidationStartSolving ->
                "aa:start_solving:${item.createdTurnSeq}"

            is AppAgendaItem.ProposeRetake ->
                "aa:legacy_retake:${item.createdTurnSeq}"

            is AppAgendaItem.ProposeEdit ->
                "aa:legacy_edit:${item.createdTurnSeq}:${item.cellIndex}"

            is AppAgendaItem.AskConfirmCell ->
                "aa:legacy_confirm:${item.createdTurnSeq}:${item.cellIndex}"
        }


    private fun deriveRouteCheckpointV1(
        s: SudoState,
        phaseOverride: GridPhase? = null,
        focusIdxOverride: Int? = null,
        appQueueOverride: List<AppAgendaItem>? = null,
        storyOverride: NarrativeStoryContext? = null,
        activeRouteOverride: ActiveRouteContext? = null
    ): RouteCheckpointV1? {
        val phase = phaseOverride ?: s.phase
        val appHead = (appQueueOverride ?: s.appAgendaQueue).firstOrNull()
        val solvingHead = appHead as? AppAgendaItem.Solving
        val story = storyOverride ?: s.narrativeStory
        val activeRoute = activeRouteOverride ?: s.activeRouteContext
        val focusIdx = focusIdxOverride ?: s.focusCellIndex

        val stepId =
            authoritativeStepIdV1(
                solvingHead = solvingHead,
                story = story,
                activeRoute = activeRoute,
                solveStepId = s.solveStepId,
                coachPlanStepId = s.coachPlanStepId
            )

        val storyStage =
            authoritativeStoryStageFromRouteV1(
                solvingHead = solvingHead,
                story = story
            )

        val checkpointState =
            s.copy(
                phase = phase,
                appAgendaQueue = appQueueOverride ?: s.appAgendaQueue,
                narrativeStory = story,
                activeRouteContext = activeRoute
            )

        val canonicalPosition =
            resolveCanonicalSolvingStepPositionV1(checkpointState)

        val targetCellIndex =
            activeRoute?.targetCellIndex
                ?: s.coachPlan?.targetCellIndex

        val techniqueId =
            solvingHead?.route?.techniqueId
                ?: activeRoute?.techniqueId
                ?: s.coachPlan?.techniqueId

        val appAgendaId = appAgendaStableIdV1(appHead)
        val appAgendaKind = appAgendaKindNameV1(appHead)

        if (
            stepId.isNullOrBlank() &&
            appAgendaId.isNullOrBlank() &&
            appAgendaKind.isNullOrBlank() &&
            storyStage == null &&
            focusIdx == null
        ) {
            return s.routeCheckpointV1
        }

        val overlayFrames =
            currentAppliedOverlayFrameIdsOrNull(s).orEmpty()

        val routeIdSeed = listOfNotNull(
            stepId?.takeIf { it.isNotBlank() },
            appAgendaId?.takeIf { it.isNotBlank() },
            storyStage?.name,
            focusIdx?.toString()
        ).joinToString("|")

        val routeId =
            if (routeIdSeed.isNotBlank()) routeIdSeed
            else "route:${s.turnSeq}"

        val resumePromptHint =
            when (storyStage) {
                StoryStage.SETUP -> "resume_setup"
                StoryStage.CONFRONTATION -> "resume_confrontation"
                StoryStage.RESOLUTION -> "resume_resolution"
                null -> when (phase) {
                    GridPhase.CONFIRMING -> "resume_confirming"
                    GridPhase.SEALING -> "resume_sealing"
                    GridPhase.SOLVING -> "resume_solving"
                }
            }

        val previous = s.routeCheckpointV1
        val versionBump =
            if (
                previous == null ||
                previous.routeId != routeId ||
                previous.appAgendaKind != appAgendaKind ||
                previous.stepId != stepId ||
                previous.storyStage != storyStage
            ) 1 else 0

        return RouteCheckpointV1(
            routeId = routeId,
            phase = phase,
            appAgendaItemId = appAgendaId,
            appAgendaKind = appAgendaKind,
            stepId = stepId,
            storyStage = canonicalPosition?.stage ?: storyStage,
            focusCellIndex = focusIdx,
            targetCellIndex = targetCellIndex,
            targetDigit = null,
            techniqueId = techniqueId,
            overlayFrameIds = overlayFrames,
            replyDemandKind = s.pending?.javaClass?.simpleName,
            resumePromptHint = resumePromptHint,
            canonicalPositionKind = canonicalPosition?.kind,
            canonicalHeadKind = canonicalPosition?.headKind,
            canonicalPendingKind = canonicalPosition?.pendingKind,
            gridHash12 = canonicalPosition?.gridHash12 ?: s.solveStepGridHash12?.take(12),
            focusAtomIndex = canonicalPosition?.focusAtomIndex,
            atomsCount = canonicalPosition?.atomsCount,
            readyForCommit = canonicalPosition?.readyForCommit == true,
            createdTurnSeq = s.turnSeq,
            routeVersion = (previous?.routeVersion ?: 0) + versionBump
        )
    }



    private fun deriveSolvingAgendaKindV1(s: SudoState): SolvingAgendaKindV1 {
        val rail = effectiveSolvingRailStateV1(s)
        val solvingHead = currentQueuedSolvingHead(s)
        val storyStage = s.narrativeStory?.stage

        if (s.phase == GridPhase.SOLVING) {
            return when (storyStage) {
                StoryStage.SETUP ->
                    SolvingAgendaKindV1.STEP_INTRO

                StoryStage.CONFRONTATION ->
                    SolvingAgendaKindV1.ATOM_WALK

                StoryStage.RESOLUTION ->
                    when {
                        rail?.boundary == SolvingRailBoundaryV1.POST_COMMIT ||
                                rail?.boundary == SolvingRailBoundaryV1.NEXT_STEP_IN_FLIGHT ||
                                s.pending is Pending.AfterResolution ||
                                solvingHead is AppAgendaItem.Solving.PostCommitChoice ->
                            SolvingAgendaKindV1.POST_COMMIT

                        else ->
                            SolvingAgendaKindV1.COMMIT_DECISION
                    }

                null ->
                    SolvingAgendaKindV1.STEP_INTRO
            }
        }

        return when (val a = solvingHead) {

            is AppAgendaItem.Solving.StepIntro -> SolvingAgendaKindV1.STEP_INTRO
            is AppAgendaItem.Solving.AtomWalk -> SolvingAgendaKindV1.ATOM_WALK
            is AppAgendaItem.Solving.CommitDecision -> SolvingAgendaKindV1.COMMIT_DECISION
            is AppAgendaItem.Solving.CommitApply -> SolvingAgendaKindV1.COMMIT_APPLY
            is AppAgendaItem.Solving.PostCommitChoice -> SolvingAgendaKindV1.POST_COMMIT

            is AppAgendaItem.Solving.DetourFreeTalk -> SolvingAgendaKindV1.DETOUR_FREE_TALK
            is AppAgendaItem.Solving.TechniqueTeach -> SolvingAgendaKindV1.POST_COMMIT
            is AppAgendaItem.Solving.Walkback -> SolvingAgendaKindV1.ATOM_WALK
            is AppAgendaItem.Solving.RecoveryRecomputeStep -> SolvingAgendaKindV1.STEP_INTRO
            null -> SolvingAgendaKindV1.STEP_INTRO
        }
    }




    // Handler per agenda kind (one function each)
    // Handler per agenda kind (one function each)
    private fun handleSolvingAgendaV1(
        s: SudoState,
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1,
        hasIntent: (IntentTypeV1) -> Boolean,
        currentGridHash12OrNull: () -> String?
    ): SolvingAgendaResult {

        if (s.phase != GridPhase.SOLVING) return SolvingAgendaResult()




        // Phase 1 + 2:
        // Solving-road progression now consumes a simpler semantic bucket:
        // - detour / route-control
        // - repeat current stage
        // - continue roadmap
        //
        // Ordinary route-following language no longer needs to preserve
        // show-me vs reveal vs next at the app-road level.
        // -------------------------------

        val solvingAgendaKind = deriveSolvingAgendaKindV1(s)
        val solvingHead = currentQueuedSolvingHead(s)
        val storyNow = s.narrativeStory
        val stageNow =
            authoritativeStoryStageV1(
                solvingHead = solvingHead,
                pending = s.pending,
                story = storyNow
            )

        val canonicalPosition = resolveCanonicalSolvingStepPositionV1(s)

        val commitBoundaryActive =
            canonicalPosition?.kind == CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT ||
                    (s.pending is Pending.ApplyHintNow) ||
                    solvingHead is AppAgendaItem.Solving.CommitDecision ||
                    solvingHead is AppAgendaItem.Solving.CommitApply ||
                    (stageNow == StoryStage.RESOLUTION)

        val afterResolutionActive =
            canonicalPosition?.kind == CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT ||
                    (s.pending is Pending.AfterResolution) ||
                    (solvingHead is AppAgendaItem.Solving.PostCommitChoice)

        val pendingIsSolveStepMissing = (s.pending is Pending.SolveStepMissing)
        val solvingRoadSemantic = routing.solvingRoadSemantic

        // Sequence-first invariant:
        // the synthetic solve_step_ready autocoach event is not a user-owned "continue"
        // signal and must never consume the SETUP beat of a newly prepared step.
        val isSolveStepReadyAutocoachEvent =
            env.rawUserText?.trim()?.startsWith("[EVENT] solve_step_ready") == true

        val freezeAtSetupForSolveStepReadyEvent =
            isSolveStepReadyAutocoachEvent &&
                    stageNow == StoryStage.SETUP &&
                    s.pending is Pending.SolveIntroAction &&
                    solvingHead is AppAgendaItem.Solving.StepIntro

        fun normalizedIntentForContinueRoadmap(): IntentTypeV1 =
            IntentTypeV1.SOLVE_CONTINUE

        fun normalizedIntentForRepeatCurrentStage(): IntentTypeV1 =
            IntentTypeV1.SOLVE_PAUSE

        fun normalizeSolvingIntent(raw: IntentTypeV1): IntentTypeV1 {
            return when (solvingRoadSemantic) {
                SolvingRoadSemanticV2.CONTINUE_FORWARD -> {
                    when (raw) {
                        IntentTypeV1.SOLVE_ACCEPT_LOCK_IN,
                        IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP,
                        IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT,
                        IntentTypeV1.SOLVE_CONTINUE,
                        IntentTypeV1.CONFIRM_YES -> raw

                        else -> normalizedIntentForContinueRoadmap()
                    }
                }

                SolvingRoadSemanticV2.STAY_AND_ELABORATE -> {
                    when (raw) {
                        IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION,
                        IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION,
                        IntentTypeV1.REQUEST_CURRENT_STAGE_COLLAPSE,
                        IntentTypeV1.REQUEST_CURRENT_STAGE_EXAMPLE,
                        IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT,
                        IntentTypeV1.ASK_WHY_THIS_CELL,
                        IntentTypeV1.REQUEST_REASONING_CHECK -> raw

                        else -> IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION
                    }
                }

                SolvingRoadSemanticV2.REPEAT_CURRENT_STAGE -> {
                    when (raw) {
                        IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT,
                        IntentTypeV1.REQUEST_CURRENT_STAGE_REPHRASE,
                        IntentTypeV1.SOLVE_PAUSE -> raw

                        else -> normalizedIntentForRepeatCurrentStage()
                    }
                }

                SolvingRoadSemanticV2.GO_BACKWARD -> {
                    when (raw) {
                        IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE,
                        IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP,
                        IntentTypeV1.REQUEST_STEP_BACK -> raw

                        else -> IntentTypeV1.REQUEST_STEP_BACK
                    }
                }

                SolvingRoadSemanticV2.DETOUR_OR_ROUTE_CONTROL,
                null -> {
                    raw
                }
            }
        }

        val ranked = env.intents.sortedWith(
            compareByDescending<IntentV1> { it.confidence }.thenBy { it.id }
        )

        val pickedRaw: IntentTypeV1? =
            when (solvingRoadSemantic) {
                SolvingRoadSemanticV2.CONTINUE_FORWARD ->
                    when {
                        afterResolutionActive &&
                                ranked.any {
                                    it.type == IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP ||
                                            it.type == IntentTypeV1.SOLVE_CONTINUE ||
                                            it.type == IntentTypeV1.CONFIRM_YES
                                } ->
                            IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP

                        commitBoundaryActive &&
                                ranked.any {
                                    it.type == IntentTypeV1.SOLVE_ACCEPT_LOCK_IN ||
                                            it.type == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT ||
                                            it.type == IntentTypeV1.CONFIRM_YES
                                } ->
                            IntentTypeV1.SOLVE_ACCEPT_LOCK_IN

                        canonicalPosition?.kind == CanonicalSolvingPositionKindV1.CONFRONTATION &&
                                canonicalPosition.readyForCommit &&
                                ranked.any {
                                    it.type == IntentTypeV1.SOLVE_ACCEPT_LOCK_IN ||
                                            it.type == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT ||
                                            it.type == IntentTypeV1.CONFIRM_YES
                                } ->
                            IntentTypeV1.SOLVE_ACCEPT_LOCK_IN

                        else ->
                            ranked.firstOrNull {
                                it.type == IntentTypeV1.SOLVE_ACCEPT_LOCK_IN ||
                                        it.type == IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP ||
                                        it.type == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT ||
                                        it.type == IntentTypeV1.SOLVE_CONTINUE ||
                                        it.type == IntentTypeV1.CONFIRM_YES
                            }?.type ?: IntentTypeV1.SOLVE_CONTINUE
                    }

                SolvingRoadSemanticV2.STAY_AND_ELABORATE ->
                    ranked.firstOrNull {
                        it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_COLLAPSE ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_EXAMPLE ||
                                it.type == IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT ||
                                it.type == IntentTypeV1.ASK_WHY_THIS_CELL ||
                                it.type == IntentTypeV1.REQUEST_REASONING_CHECK
                    }?.type ?: IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION

                SolvingRoadSemanticV2.REPEAT_CURRENT_STAGE ->
                    ranked.firstOrNull {
                        it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_REPHRASE ||
                                it.type == IntentTypeV1.SOLVE_PAUSE
                    }?.type ?: IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT

                SolvingRoadSemanticV2.GO_BACKWARD ->
                    ranked.firstOrNull {
                        it.type == IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE ||
                                it.type == IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP ||
                                it.type == IntentTypeV1.REQUEST_STEP_BACK
                    }?.type ?: IntentTypeV1.REQUEST_STEP_BACK

                SolvingRoadSemanticV2.DETOUR_OR_ROUTE_CONTROL,
                null ->
                    ranked.firstOrNull {
                        it.type == IntentTypeV1.SOLVE_CONTINUE ||
                                it.type == IntentTypeV1.SOLVE_PAUSE ||
                                it.type == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT ||
                                it.type == IntentTypeV1.REQUEST_EXPLANATION ||
                                it.type == IntentTypeV1.REQUEST_REASONING_CHECK ||
                                it.type == IntentTypeV1.ASK_TECHNIQUE_OVERVIEW ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_COLLAPSE ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_EXAMPLE ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_REPEAT ||
                                it.type == IntentTypeV1.REQUEST_CURRENT_STAGE_REPHRASE ||
                                it.type == IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STAGE ||
                                it.type == IntentTypeV1.REQUEST_GO_TO_PREVIOUS_STEP ||
                                it.type == IntentTypeV1.REQUEST_STEP_BACK ||
                                it.type == IntentTypeV1.SOLVE_ACCEPT_LOCK_IN ||
                                it.type == IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP
                    }?.type
            }

        val picked: IntentTypeV1? = pickedRaw?.let { normalizeSolvingIntent(it) }

        fun isNormalizedCommitAccept(intent: IntentTypeV1?): Boolean =
            intent == IntentTypeV1.SOLVE_CONTINUE ||
                    intent == IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT ||
                    intent == IntentTypeV1.SOLVE_ACCEPT_LOCK_IN

        val pickedIsCommitAccept = isNormalizedCommitAccept(picked)

        val agendaKind = deriveSolvingAgendaKindV1(s)

        val transition =
            when {
                freezeAtSetupForSolveStepReadyEvent ->
                    SolvingTransition.NoOp

                picked == null ->
                    SolvingTransition.NoOp

                else ->
                    SOLVING_TRANSITIONS_V1[SolvingTransitionKey(agendaKind, picked)]
                        ?: SolvingTransition.NoOp
            }

        val manualApplyContractActive =
            s.pending is Pending.ApplyHintNow ||
                    solvingHead is AppAgendaItem.Solving.CommitDecision ||
                    solvingHead is AppAgendaItem.Solving.CommitApply

        val authoritativePostCommitContinue =
            afterResolutionActive &&
                    !manualApplyContractActive &&
                    isPostCommitContinuationIntentV1(picked)

        val transitionEffective =
            if (authoritativePostCommitContinue) {
                SolvingTransition.NextStep
            } else {
                transition
            }

        val postCommitContinuationBlockerReason =
            when {
                isPostCommitContinuationIntentV1(picked) && manualApplyContractActive ->
                    "manual_apply_contract_active"

                isPostCommitContinuationIntentV1(picked) && !afterResolutionActive ->
                    "not_truthfully_post_commit"

                else ->
                    null
            }

        if (authoritativePostCommitContinue) {
            emitWaveARegressionHookV1(
                hook = "POST_COMMIT_CONTINUATION_AUTHORIZED",
                data = mapOf(
                    "turn_id" to s.turnSeq,
                    "picked_intent" to (picked?.name ?: "null"),
                    "agenda_kind" to agendaKind.toString(),
                    "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                    "original_transition" to transition.toString(),
                    "effective_transition" to transitionEffective.toString(),
                    "pending_type" to (s.pending?.javaClass?.simpleName ?: "null"),
                    "queue_head" to (solvingHead?.javaClass?.simpleName ?: "null")
                )
            )
        }

        // Minimal route context for agenda (use existing activeRouteContext fields if present)
        val route = s.activeRouteContext?.let {
            ActiveRouteContextV2(
                gridHash12 = it.gridHash12,
                stepId = it.stepId,
                techniqueId = it.techniqueId,
                targetCell = it.targetCellIndex?.let { idx -> "r${(idx / 9) + 1}c${(idx % 9) + 1}" }
            )
        } ?: ActiveRouteContextV2(gridHash12 = (s.solveStepGridHash12 ?: "").take(12))

        val stepIndex = s.solveStepSeq.toInt()

        val atomsCount = s.solveAtomsCount.takeIf { it > 0 } ?: (s.narrativeStory?.atomsCount ?: 0)
        val currentAtomIndex =
            (s.pending as? Pending.SolveIntroAction)?.atomIndex ?: (s.narrativeStory?.focusAtomIndex ?: 0)

        val baseResult = applyAtomicSolvingTransitionV1(
            s = s,
            transition = transitionEffective,
            route = route,
            stepIndex = stepIndex,
            atomsCountRaw = atomsCount,
            currentAtomIndex = currentAtomIndex,
            currentGridHash12OrNull = currentGridHash12OrNull
        )

        if (authoritativePostCommitContinue) {
            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "POST_COMMIT_CONTINUATION_AUTHORITY_OVERRIDE",
                    data = mapOf(
                        "turn_id" to s.turnSeq,
                        "picked_intent" to (picked?.name ?: "null"),
                        "agenda_kind" to agendaKind.toString(),
                        "canonical_kind" to (canonicalPosition?.kind?.name ?: "null"),
                        "original_transition" to transition.toString(),
                        "effective_transition" to transitionEffective.toString(),
                        "pending_type" to (s.pending?.javaClass?.simpleName ?: "null"),
                        "queue_head" to (solvingHead?.javaClass?.simpleName ?: "null"),
                        "override_applied" to (transitionEffective == SolvingTransition.NextStep)
                    )
                )
            }
        }

        return if (postCommitContinuationBlockerReason != null) {
            val extraFacts =
                listOf(
                    FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = org.json.JSONObject().apply {
                            put("kind", "post_commit_continuation_blocked_v1")
                            put("reason", postCommitContinuationBlockerReason)
                            put("picked_intent", picked?.name ?: JSONObject.NULL)
                            put("after_resolution_active", afterResolutionActive)
                            put("manual_apply_contract_active", manualApplyContractActive)
                        }
                    )
                )

            if (isPostCommitContinuationIntentV1(picked)) {
                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "POST_COMMIT_CONTINUATION_BLOCKED",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "reason" to postCommitContinuationBlockerReason,
                            "picked_intent" to (picked?.name ?: "null"),
                            "after_resolution_active" to afterResolutionActive,
                            "manual_apply_contract_active" to manualApplyContractActive,
                            "pending_type" to (s.pending?.javaClass?.simpleName ?: "null"),
                            "queue_head" to (solvingHead?.javaClass?.simpleName ?: "null")
                        )
                    )
                }
            }

            baseResult.copy(
                factBundles = baseResult.factBundles + extraFacts
            )
        } else {
            baseResult
        }
    }






    private fun planFromIntentEnvelopeV1(
        s: SudoState,
        env: IntentEnvelopeV1,
        routing: DetourRoutingSnapshotV1
    ): PlanV1 {
        val ops = mutableListOf<PlannedOpV1>()

        // Queues (copy)
        var userQ = s.userAgendaQueue.toMutableList()
        var appQ = s.appAgendaQueue.toMutableList()

        // PATCH 5: audit breadcrumbs for agenda transitions within this plan build.
        var agendaConsumedCount = 0
        var agendaPushedCount = 0
        val agendaConsumedTypes = mutableListOf<String>()
        val agendaPushedTypes = mutableListOf<String>()

        // Defaults: keep mode/phase/focus unless changed
        var newMode: SudoMode? = null
        var newPhase: GridPhase? = null
        var newFocusIdx: Int? = null
        var newPending: Pending? = s.pending

// Phase 4: narrative story transition (SETUP/CONFRONTATION/RESOLUTION)
        var newNarrativeStory: NarrativeStoryContext? = s.narrativeStory

// Phase 2: DecisionMemory — retake fork decision computed this turn (if any).
        var retakeDecisionUpdate: RetakeDecisionV1? = null

        // -------------------------
        // Phase 4: SOLVING-only deterministic state mutations (intent-driven)
        // -------------------------
        var newSolveAtomIndex: Int? = null

// Phase 7/8: whether we should advance to a fresh step compute in SOLVING
        var newAdvanceToNextStep: Boolean? = null

        // ✅ Phase 2: sticky guidance mode update (per step; set once when UNSET)
        var newSolveGuidanceMode: SolveGuidanceModeV1? = null

        var newSolveSkipRemaining: Int? = null
        var newSolveSkipTotal: Int? = null
        var newSolveSkipStartJourneyStep: Int? = null
        var newSolveSkipEndJourneyStep: Int? = null

        // Series 3 — explicit detour-return resume semantics for the final boundary guard.
        var boundaryReturnAcceptedV1 = false
        var boundaryResumePolicyV1: BoundaryResumePolicyV1? = null
        var boundaryResumeCheckpointStepIdV1: String? = null
        var boundaryTruthChangedOnReturnV1: Boolean? = null

        // Track B / Phase B1 — single authoritative planner-level commit outcome.
        var resolutionCommitOutcomeV1 = ResolutionCommitOutcomeV1.NONE
        var resolutionCommitCellIndexV1: Int? = null
        var resolutionCommitDigitV1: Int? = null
        var delayedAutoCommitEchoSuppressedV1 = false

        // PATCH 2.3.7: Visual verification result (persisted into final state by caller via PlanV1).
        // null = not decided this turn
        var userConfirmedPerfectMatchUpdate: Boolean? = null


        var newActiveSolvingAgenda: AppAgendaItem.Solving? = null


        // ------------------------------------------------------------
        // Phase 3 — materialize user detours before owner arbitration
        // Constitutional rule:
        // - detours do not persist semantically across turns
        // - only clarification may remain as an active user-owned head
        // ------------------------------------------------------------
        userQ = pruneNonPersistentUserAgendaItemsV1(userQ).toMutableList()

        val currentUserHeadBeforeDetour = userQ.firstOrNull()
        val wantsResumePausedRoute = wantsResumePausedRouteV1(env)

        val userDetourItem =
            when {
                wantsResumePausedRoute -> null
                else ->
                    buildUserAgendaItemFromDetourV1(
                        s = s,
                        env = env,
                        routing = routing
                    )
            }

        if (userDetourItem != null) {
            userQ = (
                    listOf(userDetourItem) +
                            userQ.filter { isPersistentUserAgendaItemV1(it) && it.id != userDetourItem.id }
                    ).toMutableList()
        }

        val currentUserHead = userQ.firstOrNull()
        val currentUserHeadIsFollowUp =
            isLikelyFollowUpToUserAgendaHeadV1(env, currentUserHead)
        val shouldReturnFromPartiallyAnsweredHeadForDebug =
            shouldReturnFromPartiallyAnsweredHeadForDebugV1(env, currentUserHead)
        val detourReturnDebugIntentTypes =
            env.intents.map { it.type.name }
        val detourReturnDebugUserQSizeBeforeEarlyBlock = userQ.size
        val detourReturnDebugPendingBeforeEarlyBlock =
            newPending?.javaClass?.simpleName ?: "null"

        userQ =
            when {
                currentUserHead == null -> userQ

                wantsResumePausedRoute -> {
                    resolveHeadUserAgendaV1(userQ, s.turnSeq).toMutableList()
                }

                currentUserHead is UserAgendaItem.Clarification &&
                        currentUserHead.status == UserAgendaStatusV1.PARTIALLY_ANSWERED &&
                        env.intents.isNotEmpty() &&
                        !currentUserHeadIsFollowUp -> {
                    resolveHeadUserAgendaV1(userQ, s.turnSeq).toMutableList()
                }

                currentUserHead is UserAgendaItem.Clarification &&
                        currentUserHead.status != UserAgendaStatusV1.RESOLVED &&
                        currentUserHead.status != UserAgendaStatusV1.CANCELLED &&
                        currentUserHeadIsFollowUp &&
                        env.intents.isNotEmpty() -> {
                    markHeadUserAgendaPartiallyAnsweredV1(userQ, s.turnSeq).toMutableList()
                }

                else -> userQ
            }

        val detourReturnDebugUserQSizeAfterEarlyBlock = userQ.size

        userQ = resolveHeadUserAgendaIfSatisfiedByOpsV1(
            q = userQ,
            ops = ops,
            turnSeq = s.turnSeq
        ).toMutableList()

        val detourReturnDebugUserQSizeAfterOpsResolution = userQ.size

        runCatching {
            com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                tag = "DETOUR_RETURN_DEBUG_EARLY",
                data = mapOf(
                    "turn_id" to s.turnSeq,
                    "wantsResumePausedRoute" to wantsResumePausedRoute,
                    "shouldReturnFromPartiallyAnsweredHead" to shouldReturnFromPartiallyAnsweredHeadForDebug,
                    "currentUserHeadId" to (currentUserHead?.id ?: "null"),
                    "currentUserHeadKind" to (currentUserHead?.javaClass?.simpleName ?: "null"),
                    "currentUserHeadStatus" to (currentUserHead?.status?.name ?: "null"),
                    "currentUserHeadAllowsFollowUp" to (currentUserHead?.allowsFollowUp ?: false),
                    "currentUserHeadIsFollowUp" to currentUserHeadIsFollowUp,
                    "intentTypes" to detourReturnDebugIntentTypes.joinToString(","),
                    "userQSizeBeforeEarlyBlock" to detourReturnDebugUserQSizeBeforeEarlyBlock,
                    "userQSizeAfterEarlyBlock" to detourReturnDebugUserQSizeAfterEarlyBlock,
                    "userQSizeAfterOpsResolution" to detourReturnDebugUserQSizeAfterOpsResolution,
                    "pendingBeforeEarlyBlockType" to detourReturnDebugPendingBeforeEarlyBlock,
                    "pendingAfterEarlyBlockType" to (newPending?.javaClass?.simpleName ?: "null")
                )
            )
        }

        if (isPostResolutionMismatchReportV1(s, env) && newPending is Pending.AfterResolution) {
            newPending = null
        }


        val ownerAfterTick1 =
            resolveTurnOwnerV1(
                userAgendaQueue = userQ,
                appAgendaQueue = appQ
            )

        val freezeAppRouteForUserTurn =
            ((newPhase ?: s.phase) == GridPhase.SOLVING) &&
                    ownerAfterTick1 == TurnOwnerV1.USER_OWNER

        var newPrefs: UserPrefsV1? = null
        var prefsChanged = false

        fun applyPrefs(p: UserPrefsV1) {
            newPrefs = p
            prefsChanged = true
        }

        val factBundles = mutableListOf<FactBundleV1>()

        // ------------------------------------------------------------
// ✅ Phase 2: Sticky guidance mode within current step.
// - Only update when we are SOLVING AND current mode is UNSET
// - SOLVE_CONTINUE => GUIDE
// - SOLVE_PAUSE    => TRY_SELF
// ------------------------------------------------------------
        runCatching {
            val phaseNow = (newPhase ?: s.phase)
            val solvingAgendaKind = deriveSolvingAgendaKindV1(s)
            val isSolvePending =
                solvingAgendaKind == SolvingAgendaKindV1.STEP_INTRO ||
                        solvingAgendaKind == SolvingAgendaKindV1.ATOM_WALK

            if (phaseNow == GridPhase.SOLVING && isSolvePending && s.solveGuidanceMode == SolveGuidanceModeV1.UNSET) {
                val hasTry = env.intents.any { it.type == IntentTypeV1.SOLVE_PAUSE }
                val hasGuide = env.intents.any {
                    it.type == IntentTypeV1.SOLVE_CONTINUE ||
                            it.type == IntentTypeV1.REQUEST_EXPLANATION
                } || (routing.solvingRoadSemantic == SolvingRoadSemanticV2.CONTINUE_FORWARD)

                newSolveGuidanceMode = when {
                    hasTry -> SolveGuidanceModeV1.TRY_SELF
                    hasGuide -> SolveGuidanceModeV1.GUIDE
                    else -> null
                }
            }
        }

        // ------------------------------------------------------------
// Phase 0 — Turn Contract Snapshot (observability; no behavior change)
// ------------------------------------------------------------
        fun pendingKindId(p: Pending?): String {
            return when (p) {
                null -> "none"
                is Pending.ConfirmRetake -> "confirm_retake"
                is Pending.ConfirmEdit -> "confirm_edit"
                is Pending.AskCellValue -> "ask_cell_value"
                is Pending.VisualVerifyMatch -> "visual_verify_match"
                is Pending.ConfirmStartSolving -> "confirm_start_solving"
                is Pending.ConfirmValidate -> "confirm_validate"
                is Pending.WaitForTap -> "wait_for_tap"
                is Pending.ConfirmInterpretation -> "confirm_interpretation"
                is Pending.AskClarification -> "ask_clarification"
                is Pending.SolveIntroAction -> "solve_intro_action"
                is Pending.AfterResolution -> "after_resolution"
                is Pending.ApplyHintNow -> "apply_hint_now"
                is Pending.SolveStepMissing -> "solve_step_missing"
                else -> p::class.java.simpleName
            }
        }

        fun agendaHeadId(a0: AppAgendaItem?): String {
            return when (a0) {
                null -> "none"
                else -> a0::class.java.simpleName
            }
        }

        fun emitTurnContractSnapshot(tag: String, opsPlannedCount: Int) {
            val phaseNow = (newPhase ?: s.phase).name
            val modeNow = (newMode ?: s.mode).name

            val a0 = appQ.firstOrNull()
            val ua0 = userQ.firstOrNull()

            // ------------------------------------------------------------
            // Phase 3: proof validity in contract snapshot (compute OUTSIDE payload.apply)
            // ------------------------------------------------------------
            val proofOk: Boolean = runCatching {
                val pkt = s.solvingReadyFactBundlesV1
                    .firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
                    ?.payload

                val verdictOk = pkt
                    ?.optJSONObject("evidence")
                    ?.optJSONObject("proof_verdict_v1")
                    ?.optBoolean("ok", false) ?: false

                val hasRecovery =
                    s.solvingReadyFactBundlesV1.any { it.type == FactBundleV1.Type.RECOVERY_PACKET_V1 }

                if ((newPhase ?: s.phase) == GridPhase.SOLVING) (verdictOk || hasRecovery) else true
            }.getOrElse { true }

            val solveResolutionApplyEmittedV1 =
                ops.any { op ->
                    op is PlannedOpV1.ApplyCellEdit && op.source == "solve_resolution_apply"
                }

            val autoCommitApplyHintHybridViolationV1 =
                resolutionCommitOutcomeV1 == ResolutionCommitOutcomeV1.APP_AUTO_COMMIT &&
                        newPending is Pending.ApplyHintNow

            val manualApplyWithApplyOpViolationV1 =
                resolutionCommitOutcomeV1 == ResolutionCommitOutcomeV1.MANUAL_APPLY_REQUIRED &&
                        solveResolutionApplyEmittedV1

            val postCommitContinuationRequestedV1 =
                hasGenericPostCommitContinueIntentV1(env.intents)

            val postCommitContinuationAuthoritativeV1 =
                newAdvanceToNextStep == true &&
                        !(newPending is Pending.ApplyHintNow)

            val queueHeadAfterV1 = newActiveSolvingAgenda ?: appQ.firstOrNull()

            val stayedPostCommitWithoutBlockerV1 =
                postCommitContinuationRequestedV1 &&
                        !postCommitContinuationAuthoritativeV1 &&
                        newPending is Pending.AfterResolution &&
                        queueHeadAfterV1 is AppAgendaItem.Solving.PostCommitChoice &&
                        !hasFactBundleKindV1(factBundles, "post_commit_continuation_blocked_v1")

            val duplicateSameCellApplyWithoutJustificationV1 =
                solveResolutionApplyEmittedV1 &&
                        run {
                            val priorPlacement = currentCommittedResolutionPlacementV1(s)
                            priorPlacement != null &&
                                    priorPlacement.first == resolutionCommitCellIndexV1 &&
                                    priorPlacement.second == resolutionCommitDigitV1 &&
                                    !hasFactBundleKindV1(factBundles, "duplicate_resolution_apply_justified_v1")
                        }

            val contractViolationsV1 = mutableListOf<String>().apply {
                if (autoCommitApplyHintHybridViolationV1) {
                    add("auto_commit_cannot_leave_apply_hint_now")
                }
                if (manualApplyWithApplyOpViolationV1) {
                    add("manual_apply_required_cannot_emit_resolution_apply_op")
                }
                if (stayedPostCommitWithoutBlockerV1) {
                    add("post_commit_continuation_requested_but_stayed_without_blocker")
                }
                if (duplicateSameCellApplyWithoutJustificationV1) {
                    add("duplicate_same_cell_apply_without_explicit_justification")
                }
            }

            val payload = JSONObject().apply {
                put("tag", tag)

                put("session_id", s.sessionId)
                put("turn_seq", s.turnSeq)
                put("mode", modeNow)
                put("phase", phaseNow)

                put("grid_hash12", s.solveStepGridHash12 ?: JSONObject.NULL)
                put("solve_step_id", s.solveStepId ?: JSONObject.NULL)
                put("solve_step_seq", s.solveStepSeq)

                put("app_agenda_head", agendaHeadId(a0))
                put("user_agenda_head", ua0?.let { it::class.java.simpleName } ?: JSONObject.NULL)

                put("detour_answer_state_v1", s.detourState?.answerState?.name ?: JSONObject.NULL)
                put("detour_answer_failure_reason_v1", s.detourState?.answerFailureReason ?: JSONObject.NULL)
                put(
                    "detour_failure_recovery_decision_v1",
                    s.detourState?.failureRecoveryDecision?.name ?: JSONObject.NULL
                )
                put(
                    "detour_failure_recovery_decision_turn_seq_v1",
                    s.detourState?.failureRecoveryDecisionTurnSeq ?: JSONObject.NULL
                )

                put("pending_kind", pendingKindId(newPending))
                put("ops_planned_count", opsPlannedCount)

                put("resolution_commit_outcome_v1", resolutionCommitOutcomeV1.name)
                put("resolution_commit_cell_index_v1", resolutionCommitCellIndexV1 ?: JSONObject.NULL)
                put("resolution_commit_digit_v1", resolutionCommitDigitV1 ?: JSONObject.NULL)
                put(
                    "auto_commit_apply_hint_hybrid_violation_v1",
                    autoCommitApplyHintHybridViolationV1
                )
                put(
                    "manual_apply_with_apply_op_violation_v1",
                    manualApplyWithApplyOpViolationV1
                )
                put(
                    "delayed_auto_commit_echo_suppressed_v1",
                    delayedAutoCommitEchoSuppressedV1
                )
                put(
                    "post_commit_continuation_requested_v1",
                    postCommitContinuationRequestedV1
                )
                put(
                    "post_commit_continuation_authoritative_v1",
                    postCommitContinuationAuthoritativeV1
                )
                put(
                    "post_commit_continuation_stayed_without_blocker_v1",
                    stayedPostCommitWithoutBlockerV1
                )
                put(
                    "duplicate_same_cell_apply_without_justification_v1",
                    duplicateSameCellApplyWithoutJustificationV1
                )
                put(
                    "contract_violations_v1",
                    JSONArray().apply { contractViolationsV1.forEach { put(it) } }
                )

                put("proof_valid", proofOk)

                // quick breadcrumbs for refactors
                put("pending_reply_v1_present", (s.pendingReplyV1 != null))
                put("pending_tick2_present", (s.pendingTick2 != null))
                put("narrative_story_present", (newNarrativeStory != null))
            }

            factBundles += FactBundleV1(
                type = FactBundleV1.Type.TURN_CONTRACT_SNAPSHOT_V1,
                payload = payload
            )

            if (contractViolationsV1.isNotEmpty()) {
                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "SOLVING_CONTRACT_VIOLATION_V1",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "tag" to tag,
                            "violations" to contractViolationsV1.joinToString(","),
                            "resolution_commit_outcome_v1" to resolutionCommitOutcomeV1.name,
                            "pending_kind" to pendingKindId(newPending),
                            "solve_resolution_apply_emitted_v1" to solveResolutionApplyEmittedV1,
                            "post_commit_continuation_requested_v1" to postCommitContinuationRequestedV1,
                            "post_commit_continuation_authoritative_v1" to postCommitContinuationAuthoritativeV1
                        )
                    )
                }
            }

            // Telemetry mirror (easy to query without parsing bundles)
            ConversationTelemetry.emitKv(
                "TURN_CONTRACT_SNAPSHOT",
                "tag" to tag,
                "session_id" to s.sessionId,
                "turn_id" to s.turnSeq,
                "mode" to modeNow,
                "phase" to phaseNow,
                "app_agenda_head" to agendaHeadId(a0),
                "pending_kind" to pendingKindId(newPending),
                "ops_planned_count" to opsPlannedCount,
                "proof_valid" to proofOk,
                "contract_violation_count_v1" to contractViolationsV1.size
            )
        }

        // ------------------------------------------------------------
// Milestone 7 — Tick2 expectations for WHY / TEACH requests:
// enforce "bundle-driven" behavior (no invention)
// ------------------------------------------------------------
        fun hasIntent(type: IntentTypeV1): Boolean = env.intents.any { it.type == type }

        val askedWhy =
            hasIntent(IntentTypeV1.REQUEST_EXPLANATION) ||
                    hasIntent(IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT) ||
                    hasIntent(IntentTypeV1.REPORT_BUG_OR_WRONG_ASSERTION)

        val askedTeachTechnique =
            hasIntent(IntentTypeV1.ASK_TECHNIQUES_NEEDED) ||
                    hasIntent(IntentTypeV1.ASK_TECHNIQUE_OVERVIEW) ||
                    hasIntent(IntentTypeV1.REQUEST_TEACH_MODE)

        if (askedWhy) {
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = JSONObject().apply {
                    put("kind", "milestone7_why_contract")
                    put(
                        "note",
                        "WHY request: Tick2 must cite concrete evidence from SOLVING_STEP_PACKET only. If SOLVING_STEP_PACKET is not present, say you do not have proof yet and ask for the next step/hint (do not guess)."
                    )
                }
            )
        }

// ✅ Phase 4: Zoom to the relevant narrative atom when user asks about a specific cell.
// No keyword parsing: we use Tick1 targets + deterministic narrative_atoms_v1 mapping.
        runCatching {
            if (s.phase == GridPhase.SOLVING) {
                val story = s.narrativeStory
                val targetCellStr: String? =
                    env.intents.firstOrNull { it.targets.isNotEmpty() }?.targets?.firstOrNull()?.cell

                val targetIdx = cellIndexOf(targetCellStr)
                if (targetIdx != null && story != null) {
                    val atomIdx = findAtomIndexForCell(s, targetIdx)
                    if (atomIdx != null && atomIdx >= 1) {
                        // CONFRONTATION zoom
                        newNarrativeStory = story.copy(
                            stage = StoryStage.CONFRONTATION,
                            focusAtomIndex = atomIdx,
                            discussedAtomIndices = listOf(atomIdx),
                            readyForCommit = false
                        )

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = JSONObject().apply {
                                put("kind", "story_zoom_atom")
                                if (targetCellStr != null) put(
                                    "cell",
                                    targetCellStr
                                ) else put("cell", JSONObject.NULL)
                                put("cell_index", targetIdx.toInt())
                                put("atom_index", atomIdx.toInt())
                                put(
                                    "note",
                                    "User asked about a specific cell. Zoom into the corresponding narrative atom. Keep spotlight visible too."
                                )
                            }
                        )
                    }
                }
            }
        }.getOrNull()

        if (askedTeachTechnique) {
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = JSONObject().apply {
                    put("kind", "milestone7_teach_contract")
                    put(
                        "note",
                        "TEACH request: Tick2 must use TEACHING_CARD only (recognition/application/pitfalls). If TEACHING_CARD is missing, ask for a step that includes it (do not invent)."
                    )
                }
            )
        }

// Emit prefs snapshot at most once per plan build.
        var prefsSnapshotEmitted = false
        fun emitPrefsSnapshotIfNeeded() {
            if (!prefsChanged || prefsSnapshotEmitted) return
            prefsSnapshotEmitted = true

            val p = newPrefs ?: s.prefs
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.PREFERENCES_SNAPSHOT,
                payload = JSONObject().apply {
                    put("language", p.language)
                    put("notation", p.notation)
                    put("evidence_verbosity", p.evidenceVerbosity)
                    put("hint_level", p.hintLevel)
                    put("teach_mode", p.teachMode)
                    put("fast_mode", p.fastMode)
                    put("one_question_max", p.oneQuestionMax)
                    put("only_validate", p.onlyValidate)
                    put("only_solve", p.onlySolve)
                }
            )
        }

        val llm = s.grid?.llm

        // ------------------------------------------------------------
// Helper: region indices (index 1..9)
// ------------------------------------------------------------
        fun regionIndices(r: RegionRefV1): List<Int> {
            val idx = r.index.coerceIn(1, 9) - 1
            return when (r.kind) {
                RegionKindV1.ROW -> (0 until 9).map { c -> idx * 9 + c }
                RegionKindV1.COL -> (0 until 9).map { rr -> rr * 9 + idx }
                RegionKindV1.BOX -> {
                    val boxRow = idx / 3
                    val boxCol = idx % 3
                    val r0 = boxRow * 3
                    val c0 = boxCol * 3
                    val out = mutableListOf<Int>()
                    for (dr in 0..2) for (dc in 0..2) out += (r0 + dr) * 9 + (c0 + dc)
                    out
                }
            }
        }

        // ------------------------------------------------------------
// Helper: candidates mask from digits 1..9
// ------------------------------------------------------------
        fun maskFromDigits(digits: List<Int>): Int {
            var m = 0
            for (d in digits) {
                if (d in 1..9) m = m or (1 shl (d - 1))
            }
            return m
        }

        fun digitsFromMask(mask: Int): List<Int> {
            val out = mutableListOf<Int>()
            for (d in 1..9) if ((mask and (1 shl (d - 1))) != 0) out += d
            return out
        }

        fun computeCandidateMask(grid: IntArray, idx: Int): Int {
            val d0 = grid.getOrNull(idx)?.coerceIn(0, 9) ?: 0
            if (d0 in 1..9) return 0

            val r = idx / 9
            val c = idx % 9
            val used = BooleanArray(10)

            fun mark(i: Int) {
                val d = grid.getOrNull(i)?.coerceIn(0, 9) ?: 0
                if (d in 1..9) used[d] = true
            }

            // row/col
            for (cc in 0 until 9) mark(r * 9 + cc)
            for (rr in 0 until 9) mark(rr * 9 + c)

            // box
            val br = (r / 3) * 3
            val bc = (c / 3) * 3
            for (dr in 0..2) for (dc in 0..2) mark((br + dr) * 9 + (bc + dc))

            var m = 0
            for (d in 1..9) if (!used[d]) m = m or (1 shl (d - 1))
            return m
        }

        // ------------------------------------------------------------
// Technique: Naked Singles
// ------------------------------------------------------------
        data class NakedSingle(val cellIdx: Int, val digit: Int)

        fun detectNakedSingles(grid: IntArray): List<NakedSingle> {
            val out = mutableListOf<NakedSingle>()
            for (i in 0 until 81) {
                if ((grid.getOrNull(i)?.coerceIn(0, 9) ?: 0) != 0) continue
                val m = computeCandidateMask(grid, i)
                val ds = digitsFromMask(m)
                if (ds.size == 1) out += NakedSingle(i, ds[0])
            }
            return out
        }

        // ------------------------------------------------------------
// Technique: Hidden Singles in a house
// ------------------------------------------------------------
        data class HiddenSingle(val house: RegionRefV1, val cellIdx: Int, val digit: Int)

        fun detectHiddenSingles(grid: IntArray): List<HiddenSingle> {
            val out = mutableListOf<HiddenSingle>()

            fun scanHouse(h: RegionRefV1) {
                val idxs = regionIndices(h)
                // digit -> positions
                val pos = Array(10) { mutableListOf<Int>() }
                for (idx in idxs) {
                    if ((grid.getOrNull(idx)?.coerceIn(0, 9) ?: 0) != 0) continue
                    val m = computeCandidateMask(grid, idx)
                    for (d in 1..9) {
                        if ((m and (1 shl (d - 1))) != 0) pos[d].add(idx)
                    }
                }
                for (d in 1..9) {
                    if (pos[d].size == 1) out += HiddenSingle(h, pos[d][0], d)
                }
            }

            for (k in 1..9) {
                scanHouse(RegionRefV1(RegionKindV1.ROW, k))
                scanHouse(RegionRefV1(RegionKindV1.COL, k))
                scanHouse(RegionRefV1(RegionKindV1.BOX, k))
            }
            return out
        }

// ------------------------------------------------------------
// 0) Remove addressed clarifications (if model tagged them)
// ------------------------------------------------------------
        val explicitlyAddressedClarificationIds =
            env.intents
                .mapNotNull { it.addressesUserAgendaId?.trim()?.takeIf { v -> v.isNotBlank() } }
                .toSet()

        if (explicitlyAddressedClarificationIds.isNotEmpty()) {
            userQ =
                userQ.filterNot {
                    (it is UserAgendaItem.Clarification) &&
                            explicitlyAddressedClarificationIds.contains(it.id)
                }.toMutableList()
        }

// ------------------------------------------------------------
// 1) Gate: only ask "missing intent" clarification if the user
// actually attempted a GRID instruction/question and we failed to bind it.
//
// IMPORTANT:
// - If Tick1 produced "free talk only" (no intents, but freeTalkTopic/confidence),
//   do NOT create user agenda. Let app agenda drive instead.
// ------------------------------------------------------------
        val rawIntents0 = env.intents.sortedByDescending { it.confidence }

        val isExactMatchSignoffRoute =
            (s.phase == GridPhase.CONFIRMING) &&
                    (
                            s.pending is Pending.ConfirmValidate ||
                                    s.pending is Pending.VisualVerifyMatch ||
                                    appQ.firstOrNull() is AppAgendaItem.ConfirmValidationExactMatch
                            )

        val rawIntents =
            if (
                isExactMatchSignoffRoute &&
                rawIntents0.any { it.type == IntentTypeV1.CONFIRM_GRID_MATCH_EXACT }
            ) {
                rawIntents0.filterNot {
                    it.type == IntentTypeV1.CONFIRM_REGION_AS_IS ||
                            it.type == IntentTypeV1.CONFIRM_REGION_TO_DIGITS
                }
            } else {
                rawIntents0
            }

        delayedAutoCommitEchoSuppressedV1 =
            rawIntents.any { isDelayedAutoCommitEchoIntentV1(s, rawIntents, it) }

        val intents =
            if (delayedAutoCommitEchoSuppressedV1) {
                rawIntents.filterNot { isDelayedAutoCommitEchoIntentV1(s, rawIntents, it) }
            } else {
                rawIntents
            }

        val top = intents.firstOrNull()

        if (delayedAutoCommitEchoSuppressedV1) {
            val placement = currentCommittedResolutionPlacementV1(s)
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = org.json.JSONObject().apply {
                    put("kind", "post_commit_delayed_auto_commit_echo_suppressed")
                    put("reason", "generic_continue_after_auto_commit_must_not_be_consumed_as_edit_confirmation")
                    put("cell_index", placement?.first ?: JSONObject.NULL)
                    put("digit", placement?.second ?: JSONObject.NULL)
                }
            )
        }

        val isFreeTalkOnly =
            (top == null) &&
                    !env.isUnclearCompat() &&
                    !env.freeTalkTopic.isNullOrBlank() &&
                    (env.freeTalkConfidence >= 0.60)

// ---------------------------------------------------
// PHASE 3.D: Free-talk-only bridge
//
// Hard rule: no regex meaning parsing here.
// We rely only on Tick1 IntentTypeV1 (post-binder).
// ---------------------------------------------------

// If isFreeTalkOnly == true: fall through.
// We will acknowledge free talk in Tick2 narration,
// AND still let app agenda select the next CTA.

        // ------------------------------------------------------------
        // 2) Step 1 — Execute clear user-authored grid actions
        //    (Multiple actions allowed; still only one question max.)
        // ------------------------------------------------------------
        fun enqueueClarification(
            intent: IntentV1,
            missing: List<String>,
            prompt: String,
            kind: ClarifyKind,
            rowHint: Int? = null,
            colHint: Int? = null,
            digitHint: Int? = null
        ) {
            val id = "ua:${s.turnSeq}:${userQ.count { it is UserAgendaItem.Clarification }}"
            val askedAlready =
                userQ.any { (it is UserAgendaItem.Clarification) && it.askedTurnSeq == s.turnSeq }
            val checkpoint = s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s)


            val carriedCellRef =
                parseCellRefToIndexV1(
                    intent.targets
                        .asSequence()
                        .mapNotNull { it.cell?.trim() }
                        .firstOrNull()
                )?.let { idx -> "r${(idx / 9) + 1}c${(idx % 9) + 1}" }
                    ?: if (rowHint != null && colHint != null) "r${rowHint}c${colHint}" else null

            val carriedRegionRef =
                intent.targets
                    .asSequence()
                    .mapNotNull { it.region }
                    .firstOrNull()
                    ?.let { region ->
                        when (region.kind) {
                            RegionKindV1.ROW -> "row ${region.index}"
                            RegionKindV1.COL -> "column ${region.index}"
                            RegionKindV1.BOX -> "box ${region.index}"
                        }
                    }

            val carriedDigit =
                digitHint ?: intent.payload.digit ?: intent.payload.digits?.firstOrNull()


            val clar = UserAgendaItem.Clarification(
                id = id,
                intentId = intent.id,
                missing = missing,
                askedTurnSeq = if (!askedAlready) s.turnSeq else null, // ask only ONE per turn
                createdTurnSeq = s.turnSeq,
                prompt = prompt,

                detourQuestionClass = when (intent.type) {
                    IntentTypeV1.REQUEST_REASONING_CHECK,
                    IntentTypeV1.CHECK_PROPOSED_DIGIT_IN_CELL,
                    IntentTypeV1.CHECK_PROPOSED_CANDIDATE_SET_IN_CELL,
                    IntentTypeV1.CHECK_PROPOSED_ELIMINATION_IN_SCOPE,
                    IntentTypeV1.CHECK_PROPOSED_TECHNIQUE_APPLIES_HERE,
                    IntentTypeV1.CHECK_PROPOSED_ROUTE_EQUIVALENCE -> DetourQuestionClassV1.USER_REASONING_CHECK

                    IntentTypeV1.REQUEST_EXPLANATION -> DetourQuestionClassV1.PROOF_CHALLENGE
                    else -> null
                },
                carriedCellRef = carriedCellRef,
                carriedDigit = carriedDigit,
                carriedRegionRef = carriedRegionRef,
                carriedTechniqueLabel = intent.payload.technique,

                checkpointRouteId = checkpoint?.routeId,
                checkpointPhase = checkpoint?.phase,
                checkpointAppAgendaKind = checkpoint?.appAgendaKind,
                checkpointStepId = checkpoint?.stepId,
                checkpointStoryStage = checkpoint?.storyStage,
                status = UserAgendaStatusV1.OPEN
            )
            userQ.add(0, clar)

            // Only set newPending if we haven’t already asked something this turn.
            if (!askedAlready) {
                newPending = Pending.AskClarification(
                    kind = kind,
                    rowHint = rowHint,
                    colHint = colHint,
                    digitHint = digitHint,
                    prompt = prompt
                )
            }
        }

        // If the user explicitly switches focus, treat it as a first-class control intent.
        val focusIntent =
            intents.firstOrNull { it.type == IntentTypeV1.SWITCH_FOCUS_CELL || it.type == IntentTypeV1.SWITCH_FOCUS_REGION }
        if (focusIntent != null) {
            when (focusIntent.type) {
                IntentTypeV1.SWITCH_FOCUS_CELL -> {
                    val admission = ClarificationKernelV1.assessFocusCellAction(focusIntent)
                    val clar = admission.clarification
                    if (clar != null) {
                        enqueueClarification(
                            focusIntent,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        newFocusIdx = admission.cellIndex
                    }
                }

                IntentTypeV1.SWITCH_FOCUS_REGION -> {
                    val admission = ClarificationKernelV1.assessFocusRegionAction(focusIntent)
                    val clar = admission.clarification
                    if (clar != null) {
                        enqueueClarification(
                            focusIntent,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        // Focus becomes first cell of the region (UI anchor)
                        newFocusIdx = admission.region?.let { regionIndices(it).firstOrNull() }
                    }
                }

                else -> Unit
            }
        }

        // Apply clear actions (edits / confirms / undo/redo / candidates)
        for (i in intents) {
            when (i.type) {
                IntentTypeV1.EDIT_CELL -> {
                    val admission = ClarificationKernelV1.assessEditCellAction(s, i)
                    val idx = admission.cellIndex
                    val digit = admission.digit
                    val clar = admission.clarification

                    if (clar != null) {
                        if (idx != null) newFocusIdx = idx
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        // Cross-cell safety: this is a user override if different from current focus
                        val isOverride =
                            (s.focusCellIndex != null && idx != null && idx != s.focusCellIndex)
                        ops += PlannedOpV1.ApplyCellEdit(
                            cellIndex = idx!!,
                            digit = digit!!.coerceIn(0, 9),
                            source = if (isOverride) "override_intent" else "user_intent"
                        )
                        newPending = null
                        newFocusIdx = idx
                    }
                }

                IntentTypeV1.CLEAR_CELL -> {
                    val admission = ClarificationKernelV1.assessClearCellAction(s, i)
                    val idx = admission.cellIndex
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        ops += PlannedOpV1.ApplyCellEdit(
                            cellIndex = idx!!,
                            digit = 0,
                            source = "user_intent"
                        )
                        newPending = null
                        newFocusIdx = idx
                    }
                }

                IntentTypeV1.CONFIRM_CELL_TO_DIGIT -> {
                    val admission = ClarificationKernelV1.assessConfirmCellToDigitAction(s, i)
                    val idx = admission.cellIndex
                    val digit = admission.digit
                    val clar = admission.clarification

                    if (clar != null) {
                        if (idx != null) newFocusIdx = idx
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        ops += PlannedOpV1.ConfirmCellValue(
                            cellIndex = idx!!,
                            digit = digit!!.coerceIn(0, 9),
                            source = "user_intent"
                        )
                        newPending = null
                        newFocusIdx = idx
                    }
                }

                IntentTypeV1.CONFIRM_CELL_AS_IS -> {
                    val admission = ClarificationKernelV1.assessConfirmCellAsIsAction(s, i)
                    val idx = admission.cellIndex
                    val rowHint = admission.rowHint
                    val colHint = admission.colHint
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        // ✅ Robustness: if we are currently in a ConfirmEdit pending for this cell,
                        // do NOT "confirm as-is" from llm.correctedGrid (can confirm the wrong scanned digit).
                        val p = s.pending as? Pending.ConfirmEdit
                        if (p != null && p.cellIndex.coerceIn(0, 80) == idx) {
                            // No-op here; let Pending.ConfirmEdit resolution interpret this as acceptance/rejection.
                            // (See Patch 2B below.)
                        } else {
                            val d = llm?.correctedGrid?.getOrNull(idx!!) ?: 0
                            if (d !in 1..9) {
                                enqueueClarification(
                                    i,
                                    listOf("digit"),
                                    ClarificationKernelV1.buildRepairClarificationPrompt(
                                        actionVerb = "confirm",
                                        rowHint = rowHint,
                                        colHint = colHint,
                                        needCell = false,
                                        needDigit = true
                                    ),
                                    ClarifyKind.DIGIT,
                                    rowHint = rowHint,
                                    colHint = colHint
                                )
                            } else {
                                val confirmedIdx = idx!!
                                ops += PlannedOpV1.ConfirmCellValue(
                                    cellIndex = confirmedIdx,
                                    digit = d,
                                    source = "user_intent"
                                )
                                newPending = null
                                newFocusIdx = confirmedIdx
                            }
                        }
                    }
                }

                IntentTypeV1.CONFIRM_REGION_AS_IS -> {
                    val admission = ClarificationKernelV1.assessConfirmRegionAsIsAction(i)
                    val r = admission.region
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        val cells = regionIndices(r!!)
                        val digits = cells.map { idx -> llm?.correctedGrid?.getOrNull(idx) ?: 0 }
                        val any = digits.any { it in 1..9 }
                        if (!any) {
                            enqueueClarification(
                                i,
                                listOf("digits"),
                                "That region looks empty—do you want to confirm specific digits?",
                                ClarifyKind.YESNO
                            )
                        } else {
                            for (k in cells.indices) {
                                val d = digits[k]
                                if (d in 1..9) {
                                    ops += PlannedOpV1.ConfirmCellValue(
                                        cellIndex = cells[k],
                                        digit = d,
                                        source = "user_intent"
                                    )
                                }
                            }
                            newPending = null
                            newFocusIdx = cells.firstOrNull()
                        }
                    }
                }

                IntentTypeV1.CONFIRM_REGION_TO_DIGITS -> {
                    val admission = ClarificationKernelV1.assessConfirmRegionToDigitsAction(i)
                    val r = admission.region
                    val digits = admission.digits
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        val cells = regionIndices(r!!)
                        for (k in 0 until 9) {
                            val d = digits!![k]
                            if (d in 1..9) ops += PlannedOpV1.ConfirmCellValue(
                                cellIndex = cells[k],
                                digit = d,
                                source = "user_intent"
                            )
                        }
                        newPending = null
                        newFocusIdx = cells.firstOrNull()
                    }
                }

                IntentTypeV1.CONFIRM_GRID_MATCH_EXACT -> {
                    // No-op here.
                    // This intent is resolved later by the exact-match confirming gate logic,
                    // not as a cell/region mutation action.
                }

                IntentTypeV1.REQUEST_REVALIDATE -> {
                    // Phase 1 invariant: user text does not drive Maps. Tick1 must emit this intent.
                    // Return to CONFIRMING so the user can re-validate or fix scan issues.
                    if (s.phase == GridPhase.SOLVING) {
                        newPhase = GridPhase.CONFIRMING
                        newPending = null

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = JSONObject().apply {
                                put("kind", "request_revalidate")
                                put(
                                    "note",
                                    "User requested re-validation: returning to CONFIRMING."
                                )
                            }
                        )
                    }
                }

                IntentTypeV1.UNDO -> {
                    ops += PlannedOpV1.Undo(source = "user_intent")
                    newPending = null
                }

                IntentTypeV1.REDO -> {
                    ops += PlannedOpV1.Redo(source = "user_intent")
                    newPending = null
                }

                IntentTypeV1.CAND_ADD -> {
                    val admission = ClarificationKernelV1.assessCandidateAddAction(i)
                    val idx = admission.cellIndex
                    val digits = admission.digits
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        for (d in digits!!) if (d in 1..9) ops += PlannedOpV1.AddCandidate(
                            cellIndex = idx!!,
                            digit = d,
                            source = "user_intent"
                        )
                        newPending = null
                        newFocusIdx = idx
                    }
                }

                IntentTypeV1.CAND_REMOVE -> {
                    val admission = ClarificationKernelV1.assessCandidateRemoveAction(i)
                    val idx = admission.cellIndex
                    val digits = admission.digits
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        for (d in digits!!) if (d in 1..9) ops += PlannedOpV1.RemoveCandidate(
                            cellIndex = idx!!,
                            digit = d,
                            source = "user_intent"
                        )
                        newPending = null
                        newFocusIdx = idx
                    }
                }

                IntentTypeV1.CAND_SET -> {
                    val admission = ClarificationKernelV1.assessCandidateSetAction(i)
                    val idx = admission.cellIndex
                    val digits = admission.digits
                    val clar = admission.clarification

                    if (clar != null) {
                        enqueueClarification(
                            i,
                            clar.missing,
                            clar.prompt,
                            clar.kind,
                            rowHint = clar.rowHint,
                            colHint = clar.colHint,
                            digitHint = clar.digitHint
                        )
                    } else {
                        ops += PlannedOpV1.SetCandidatesMask(
                            cellIndex = idx!!,
                            mask = maskFromDigits(digits!!),
                            source = "user_intent"
                        )
                        newPending = null
                        newFocusIdx = idx
                    }
                }


                IntentTypeV1.SET_LANGUAGE -> {
                    val lang = i.payload.language?.trim()?.lowercase()
                    if (!lang.isNullOrBlank()) applyPrefs(
                        (newPrefs ?: s.prefs).copy(language = lang)
                    )
                }

                IntentTypeV1.SET_NOTATION_STYLE -> {
                    val notation = i.payload.notation?.trim()
                    if (!notation.isNullOrBlank()) applyPrefs(
                        (newPrefs ?: s.prefs).copy(notation = notation)
                    )
                }

                IntentTypeV1.SET_EVIDENCE_VERBOSITY -> {
                    val v = i.payload.evidenceVerbosity?.trim()
                    if (!v.isNullOrBlank()) applyPrefs(
                        (newPrefs ?: s.prefs).copy(evidenceVerbosity = v)
                    )
                }

                IntentTypeV1.REQUEST_HINT_LEVEL -> {
                    val h = i.payload.hintLevel?.trim()
                    if (!h.isNullOrBlank()) applyPrefs((newPrefs ?: s.prefs).copy(hintLevel = h))
                }

                IntentTypeV1.REQUEST_TEACH_MODE -> {
                    applyPrefs((newPrefs ?: s.prefs).copy(teachMode = true, fastMode = false))
                }

                IntentTypeV1.REQUEST_FAST_MODE -> {
                    applyPrefs((newPrefs ?: s.prefs).copy(fastMode = true, teachMode = false))
                }

                IntentTypeV1.REQUEST_MODE_CHANGE -> {
                    // Umbrella: apply whichever flags the model provided; otherwise clarify.
                    val fast = i.payload.fastMode
                    val teach = i.payload.teachMode
                    if (fast == null && teach == null) {
                        enqueueClarification(
                            i,
                            listOf("mode"),
                            ClarificationKernelV1.promptForModeChange(),
                            ClarifyKind.WORKFLOW
                        )
                    } else {
                        val next = (newPrefs ?: s.prefs).copy(
                            fastMode = fast ?: (newPrefs ?: s.prefs).fastMode,
                            teachMode = teach ?: (newPrefs ?: s.prefs).teachMode
                        )
                        applyPrefs(next)
                    }
                }


                IntentTypeV1.SET_ONE_QUESTION_MAX -> {
                    val b = i.payload.oneQuestionMax
                    if (b != null) applyPrefs((newPrefs ?: s.prefs).copy(oneQuestionMax = b))
                }

                IntentTypeV1.REQUEST_ONLY_VALIDATE -> {
                    applyPrefs((newPrefs ?: s.prefs).copy(onlyValidate = true, onlySolve = false))
                }

                IntentTypeV1.REQUEST_ONLY_SOLVE -> {
                    applyPrefs((newPrefs ?: s.prefs).copy(onlySolve = true, onlyValidate = false))
                }

                IntentTypeV1.SWAP_TWO_CELLS -> {
                    if (llm == null) {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "no_grid_loaded")
                                put("note", "Swap requires a loaded grid.")
                            }
                        )
                    } else {
                        // ----------------------------
                        // 1) Try to resolve the two cells to swap
                        //    Supported shapes:
                        //      A) targets[0].cell + targets[1].cell
                        //      B) targets[0].cell + targets[0].cell2   (new cell2 support)
                        //      C) fallback: parse from raw_text
                        // ----------------------------

                        // Shape A: two separate targets
                        val aIdxFromTargets: Int? = cellIndexOf(i.targets.getOrNull(0)?.cell)
                        val bIdxFromTargets: Int? = cellIndexOf(i.targets.getOrNull(1)?.cell)

                        // Shape B: single target with (cell + cell2)
                        val aIdxFromCell2Shape: Int? = cellIndexOf(i.targets.getOrNull(0)?.cell)
                        val bIdxFromCell2Shape: Int? = cellIndexOf(i.targets.getOrNull(0)?.cell2)

                        // Shape C: parse two rNcM occurrences from raw text
                        fun parseTwoCellsFromText(raw: String?): Pair<Int, Int>? {
                            val s0 = raw ?: return null
                            val re = Regex("""r\s*([1-9])\s*c\s*([1-9])""", RegexOption.IGNORE_CASE)
                            val hits = re.findAll(s0).take(2).toList()
                            if (hits.size < 2) return null

                            fun toIdx(m: MatchResult): Int {
                                val r = m.groupValues[1].toInt().coerceIn(1, 9)
                                val c = m.groupValues[2].toInt().coerceIn(1, 9)
                                return (r - 1) * 9 + (c - 1)
                            }
                            return toIdx(hits[0]) to toIdx(hits[1])
                        }

                        // Choose best available pair (A) OR (B) OR (C)
                        val swapPair: Pair<Int, Int>? =
                            if (aIdxFromTargets != null && bIdxFromTargets != null) {
                                aIdxFromTargets to bIdxFromTargets
                            } else if (aIdxFromCell2Shape != null && bIdxFromCell2Shape != null) {
                                aIdxFromCell2Shape to bIdxFromCell2Shape
                            } else {
                                parseTwoCellsFromText(i.payload.rawText)
                            }

                        val aIdx: Int? = swapPair?.first
                        val bIdx: Int? = swapPair?.second

                        // ----------------------------
                        // 2) If missing, ask clarification
                        // ----------------------------
                        if (aIdx == null || bIdx == null) {
                            enqueueClarification(
                                i,
                                listOf("cell_a", "cell_b"),
                                "Which two cells should I swap? (Example: “swap r1c2 and r3c2”)",
                                ClarifyKind.POSITION
                            )
                        } else {
                            // ----------------------------
                            // 3) Apply swap
                            // ----------------------------
                            val aVal = llm.correctedGrid.getOrNull(aIdx)?.coerceIn(0, 9) ?: 0
                            val bVal = llm.correctedGrid.getOrNull(bIdx)?.coerceIn(0, 9) ?: 0

                            ops += PlannedOpV1.ApplyCellEdit(
                                cellIndex = aIdx,
                                digit = bVal,
                                source = "swap"
                            )
                            ops += PlannedOpV1.ApplyCellEdit(
                                cellIndex = bIdx,
                                digit = aVal,
                                source = "swap"
                            )

                            factBundles += FactBundleV1(
                                type = FactBundleV1.Type.RECENT_MUTATION_RESULT,
                                payload = JSONObject().apply {
                                    put("kind", "swap_two_cells")
                                    put("cell_a", indexToCell(aIdx)); put(
                                    "from_a",
                                    aVal
                                ); put("to_a", bVal)
                                    put("cell_b", indexToCell(bIdx)); put(
                                    "from_b",
                                    bVal
                                ); put("to_b", aVal)
                                }
                            )
                        }
                    }
                }

                IntentTypeV1.MASS_CLEAR_SCOPE -> {
                    if (llm == null) {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "no_grid_loaded")
                                put("note", "Mass clear requires a loaded grid.")
                            }
                        )
                    } else {
                        val scope = i.payload.scope
                        val r = i.regionOrNullCompat()

                        val idxs: List<Int> = when {
                            r != null -> regionIndices(r)
                            scope.equals("NON_GIVENS", ignoreCase = true) ->
                                (0 until 81).filter { llm.truthIsGiven.getOrNull(it) != true }

                            scope.equals("GLOBAL", ignoreCase = true) || scope.isNullOrBlank() ->
                                (0 until 81).toList()

                            else -> (0 until 81).toList()
                        }

                        val toClear = idxs.take(81)

                        toClear.forEach { idx ->
                            val cur = llm.correctedGrid.getOrNull(idx)?.coerceIn(0, 9) ?: 0
                            if (cur in 1..9) ops += PlannedOpV1.ApplyCellEdit(
                                cellIndex = idx,
                                digit = 0,
                                source = "mass_clear"
                            )
                        }

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.RECENT_MUTATION_RESULT,
                            payload = JSONObject().apply {
                                put("kind", "mass_clear")
                                put("scope", scope ?: (r?.kind?.name ?: "GLOBAL"))
                                put("cleared_count", toClear.size)
                            }
                        )
                    }
                }

                IntentTypeV1.LOCK_GIVENS_FROM_SCAN -> {
                    if (llm == null) {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "no_grid_loaded")
                                put("note", "Lock givens requires a loaded grid.")
                            }
                        )
                    } else {
                        // Semantic-only in this build: acknowledge truth, do not mutate.
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "lock_givens_semantic_only")
                                put(
                                    "note",
                                    "This build already treats scan givens as givens via truthIsGiven; an explicit lock layer is not implemented yet."
                                )
                            }
                        )
                    }
                }


                else -> Unit
            }
        }


        // ✅ Deterministic multi-intent / multi-op behavior (Phase-4 stability):
// - If this is a BULK CONFIRM (all ops are ConfirmCellValue), allow all (needed for bulk confirmation).
// - Otherwise, apply exactly ONE op this turn and acknowledge the rest deterministically so they are not “lost”.
        val allConfirmOps = ops.isNotEmpty() && ops.all { it is PlannedOpV1.ConfirmCellValue }
        if (!allConfirmOps && ops.size > 1) {
            val keep = ops.first()
            val deferred = ops.drop(1)

            // Shrink ops to one (Phase-4 latch remains simple/stable).
            ops.clear()
            ops += keep

            // Deterministic acknowledgment bundle for deferred actions.
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = JSONObject().apply {
                    put("deferred_ops_count", deferred.size)
                    put("deferred_ops_preview", JSONArray().apply {
                        deferred.take(3).forEach { put(it::class.java.simpleName) }
                    })
                    put(
                        "note",
                        "Multiple ops detected; executing one op this turn (Phase-4 stability) and acknowledging deferred ops deterministically."
                    )
                }
            )
        }

        emitPrefsSnapshotIfNeeded()

        // If we scheduled any clarification to ask this turn, stop here (one question max).
        val askedThisTurn = userQ.firstOrNull()
            .let { it is UserAgendaItem.Clarification && it.askedTurnSeq == s.turnSeq }
        if (askedThisTurn) {
            emitTurnContractSnapshot(
                tag = "return_user_agenda_clarification",
                opsPlannedCount = ops.size
            )
            return PlanV1(
                ops = ops,
                userAgendaQueue = userQ,
                appAgendaQueue = appQ,
                newPending = newPending,
                newMode = newMode,
                newPhase = newPhase,
                newFocusIdx = newFocusIdx,

                // Phase 5: persist active SOLVING agenda head
                newActiveSolvingAgenda = newActiveSolvingAgenda,

                newSolveAtomIndex = newSolveAtomIndex,
                newSolveGuidanceMode = newSolveGuidanceMode,

                newSolveSkipRemaining = newSolveSkipRemaining,
                newSolveSkipTotal = newSolveSkipTotal,
                newSolveSkipStartJourneyStep = newSolveSkipStartJourneyStep,
                newSolveSkipEndJourneyStep = newSolveSkipEndJourneyStep,

                newUserConfirmedPerfectMatch = userConfirmedPerfectMatchUpdate,
                newPrefs = newPrefs,
                factBundles = factBundles,
                summary = "asked_user_agenda_clarification ops=${ops.size}"
            )
        }


        // ------------------------------------------------------------
// PATCH 2 — Step 2: Resolve current Pending deterministically
//            + consume the corresponding App agenda head.
//
// Invariant:
// - If Pending is resolved this turn, clear it and consume the appQ head that created it.
// - If Pending needs clarification, we will already have set Pending.AskClarification earlier (and return).
// ------------------------------------------------------------

        val pendingBeforeTurn = s.pending

        fun consumeAppAgendaHeadIfMatches(predicate: (AppAgendaItem) -> Boolean) {
            val head = appQ.firstOrNull() ?: return
            if (predicate(head)) {
                appQ.removeAt(0)
                agendaConsumedCount += 1
                agendaConsumedTypes += head::class.java.simpleName
            }
        }

        fun pushFront(item: AppAgendaItem) {
            appQ.add(0, item)
            agendaPushedCount += 1
            agendaPushedTypes += item::class.java.simpleName
        }

// hasIntent(...) is already defined earlier in this method (Phase 3.D block).
// Reuse it here to avoid duplicate local function overloads.

// Dialog acts from user bind to Pending types.
        val answeredYes = hasIntent(IntentTypeV1.CONFIRM_YES)
        val answeredNo = hasIntent(IntentTypeV1.CONFIRM_NO)
        val answeredGridMatchExact = hasIntent(IntentTypeV1.CONFIRM_GRID_MATCH_EXACT)

// explicit fork intents for ConfirmRetake
        val choseRetake = hasIntent(IntentTypeV1.CHOOSE_RETAKE)
        val choseKeepScan = hasIntent(IntentTypeV1.CHOOSE_KEEP_SCAN)

// Phase 1 invariant: Maps never inspects raw user text.
// If we are waiting for a TAP (Pending.WaitForTap), we ONLY advance when Tick1 emits
// a structured intent that carries a target (focus cell/region, edit intent, etc.).
// Otherwise we keep the pending and let Tick2 repeat the instruction.

// Phase 5 / Wave 2:
// Pending.ReturnToRoute is now a true restoration boundary.
// Returning means: pop the detour wrapper and restore the saved app-owned pending if available.
        if (pendingBeforeTurn is Pending.ReturnToRoute) {

            val wantsReturn =
                wantsResumePausedRouteV1(env) ||
                        answeredYes ||
                        hasIntent(IntentTypeV1.SOLVE_PAUSE) ||
                        hasIntent(IntentTypeV1.REQUEST_EXPLANATION) ||
                        hasIntent(IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT) ||
                        hasIntent(IntentTypeV1.SOLVE_CONTINUE)

            if (wantsReturn) {

                val checkpoint =
                    s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s)

                // Pop detour agenda head if present.
                consumeAppAgendaHeadIfMatches { a ->
                    a is AppAgendaItem.Solving.DetourFreeTalk
                }

                if (userQ.firstOrNull() is UserAgendaItem.RouteControl) {
                    userQ = resolveHeadUserAgendaV1(userQ, s.turnSeq).toMutableList()
                }

                val restoredAppQueue =
                    restoreQueuedSolvingHeadFromCheckpointV1(
                        s = s,
                        queue = appQ,
                        checkpoint = checkpoint
                    )

                appQ = restoredAppQueue.toMutableList()

                val restoredPending =
                    pendingBeforeTurn.resumePending
                        ?: restorePendingFromCheckpointV1(
                            s = s,
                            queue = restoredAppQueue,
                            checkpoint = checkpoint,
                            preferred = null
                        )

                newPending = restoredPending

                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = JSONObject().apply {
                        put("kind", "solving_detour_returned")
                        put(
                            "note",
                            "Returned from detour and restored the app-owned route immediately."
                        )
                        put(
                            "restored_pending_type",
                            restoredPending?.javaClass?.simpleName ?: JSONObject.NULL
                        )
                    }
                )

                if (checkpoint != null) {
                    factBundles += FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = JSONObject().apply {
                            put("kind", "route_restored_checkpoint_receipt")
                            put("phase", checkpoint.phase.name)
                            put("app_agenda_kind", checkpoint.appAgendaKind ?: JSONObject.NULL)
                            put("step_id", checkpoint.stepId ?: JSONObject.NULL)
                            put("story_stage", checkpoint.storyStage?.name ?: JSONObject.NULL)
                            put("resume_prompt_hint", checkpoint.resumePromptHint ?: JSONObject.NULL)
                            put("resume_reason", "user_requested_return_to_main_road")
                        }
                    )
                }

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "SOLVING_DETOUR_RETURNED",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "queue_head_after_pop" to ((appQ.firstOrNull())?.javaClass?.simpleName
                                ?: "null"),
                            "pending_after_pop" to (restoredPending?.javaClass?.simpleName
                                ?: "null"),
                            "reason" to "detour_wrapper_removed_and_route_restored_from_checkpoint",
                            "continuity_lane_after" to "app_route",
                            "resume_prompt_hint" to (checkpoint?.resumePromptHint ?: "none"),
                            "resume_story_stage" to (checkpoint?.storyStage?.name ?: "none"),
                            "resume_canonical_position_kind" to (checkpoint?.canonicalPositionKind?.name ?: "none"),
                            "resume_canonical_head_kind" to (checkpoint?.canonicalHeadKind?.name ?: "none")
                        )
                    )
                }

            } else {
                // Stay in detour; Tick2 will answer free talk and end with RETURN_TO_ROUTE CTA.
                newPending = pendingBeforeTurn
            }
        }

// Wave 2:
// If a user detour bridge offers RETURN_TO_ROUTE and the user accepts,
// resolve the detour head and restore the app-owned route immediately.
        // Wave 2:
// If a user detour bridge offers RETURN_TO_ROUTE and the user accepts,
// resolve the detour head and restore the app-owned route immediately.
        if (pendingBeforeTurn is Pending.UserAgendaBridge) {

            val bridgeAllowsReturn =
                pendingBeforeTurn.options.contains(PendingChoiceId.RETURN_TO_ROUTE)

            val (returnAllowedByDetourState, returnGateReasonV1) =
                detourBridgeReturnGateV1(
                    s = s,
                    env = env,
                    routing = routing
                )

            val wantsReturnFromBridgeRaw =
                bridgeAllowsReturn && (
                        wantsResumePausedRouteV1(env) ||
                                answeredYes ||
                                hasIntent(IntentTypeV1.SOLVE_CONTINUE) ||
                                hasIntent(IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP) ||
                                hasIntent(IntentTypeV1.SOLVE_ACCEPT_LOCK_IN) ||
                                hasIntent(IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT)
                        )

            val wantsReturnFromBridge =
                wantsReturnFromBridgeRaw && returnAllowedByDetourState

            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "DETOUR_RETURN_DEBUG_BRIDGE",
                    data = mapOf(
                        "turn_id" to s.turnSeq,
                        "bridgeAllowsReturn" to bridgeAllowsReturn,
                        "wantsReturnFromBridgeRaw" to wantsReturnFromBridgeRaw,
                        "returnAllowedByDetourState" to returnAllowedByDetourState,
                        "returnGateReasonV1" to returnGateReasonV1,
                        "detourAnswerStateV1" to (s.detourState?.answerState?.name ?: "null"),
                        "wantsReturnFromBridge" to wantsReturnFromBridge,
                        "pendingBeforeType" to pendingBeforeTurn.javaClass.simpleName,
                        "bridgeUserAgendaId" to pendingBeforeTurn.userAgendaId,
                        "bridgeOptions" to pendingBeforeTurn.options.joinToString(",") { it.toString() },
                        "answeredYes" to answeredYes,
                        "wantsResumePausedRoute" to wantsResumePausedRouteV1(env),
                        "hasSolveContinue" to hasIntent(IntentTypeV1.SOLVE_CONTINUE),
                        "hasSolveAcceptNextStep" to hasIntent(IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP),
                        "hasSolveAcceptLockIn" to hasIntent(IntentTypeV1.SOLVE_ACCEPT_LOCK_IN),
                        "hasSolveStepRevealDigit" to hasIntent(IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT),
                        "userQSizeBeforeBridgeBlock" to userQ.size,
                        "appQSizeBeforeBridgeBlock" to appQ.size,
                        "newPendingBeforeBridgeBlockType" to (newPending?.javaClass?.simpleName ?: "null")
                    )
                )
            }

            if (wantsReturnFromBridge) {
                val checkpoint =
                    s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s)

                val currentGridHash12OnReturn =
                    runCatching {
                        s.grid?.llm?.let { sha12(grid81FromLLM(it)).take(12) }
                    }.getOrNull()

                val pausedRouteTruthStillMatches =
                    checkpoint?.gridHash12?.take(12) == null ||
                            currentGridHash12OnReturn == null ||
                            checkpoint.gridHash12.take(12) == currentGridHash12OnReturn.take(12)

                val resumePolicyV1 =
                    if (pausedRouteTruthStillMatches) {
                        BoundaryResumePolicyV1.RESTORE_PAUSED_ROUTE
                    } else {
                        BoundaryResumePolicyV1.RECOMPUTE_FROM_CURRENT_TRUTH
                    }

                boundaryReturnAcceptedV1 = true
                boundaryResumePolicyV1 = resumePolicyV1
                boundaryResumeCheckpointStepIdV1 = checkpoint?.stepId
                boundaryTruthChangedOnReturnV1 = !pausedRouteTruthStillMatches

                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = JSONObject().apply {
                        put("kind", "user_agenda_bridge_truth_validity_check")
                        put("paused_route_grid_hash12", checkpoint?.gridHash12 ?: JSONObject.NULL)
                        put("current_grid_hash12", currentGridHash12OnReturn ?: JSONObject.NULL)
                        put("truth_unchanged", pausedRouteTruthStillMatches)
                        put(
                            "resume_policy",
                            when (resumePolicyV1) {
                                BoundaryResumePolicyV1.RESTORE_PAUSED_ROUTE -> "restore_paused_route_boundary"
                                BoundaryResumePolicyV1.RECOMPUTE_FROM_CURRENT_TRUTH -> "recompute_from_current_truth"
                            }
                        )
                    }
                )

                // Explicit return-to-route should flush the detour backlog so
                // stale user heads cannot keep winning arbitration.
                userQ =
                    flushUserDetourBacklogForRouteReturnV1(
                        q = userQ,
                        turnSeq = s.turnSeq
                    ).toMutableList()

                // If a free-talk wrapper is still sitting in front of the app route, pop it too.
                consumeAppAgendaHeadIfMatches { a ->
                    a is AppAgendaItem.Solving.DetourFreeTalk
                }

                val restoredAppQueue =
                    restoreQueuedSolvingHeadFromCheckpointV1(
                        s = s,
                        queue = appQ,
                        checkpoint = checkpoint
                    )

                appQ = restoredAppQueue.toMutableList()

                val restoredPending =
                    restorePendingFromCheckpointV1(
                        s = s,
                        queue = restoredAppQueue,
                        checkpoint = checkpoint,
                        preferred = null
                    )

                newPending = restoredPending

                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = JSONObject().apply {
                        put("kind", "user_agenda_bridge_returned_to_route")
                        put("user_agenda_id", pendingBeforeTurn.userAgendaId)
                        put(
                            "restored_pending_type",
                            restoredPending?.javaClass?.simpleName ?: JSONObject.NULL
                        )
                        put("restored_app_agenda_kind", checkpoint?.appAgendaKind ?: JSONObject.NULL)
                        put(
                            "restored_canonical_position_kind",
                            checkpoint?.canonicalPositionKind?.name ?: JSONObject.NULL
                        )
                        put("resume_reason", "bridge_return_accepted_checkpoint_restoration")
                        put(
                            "detour_failure_recovery_decision_v1",
                            if (s.detourState?.answerState == DetourAnswerStateV1.FAILED_AWAITING_RECOVERY) {
                                DetourFailureRecoveryDecisionV1.RETIRE_AND_RESUME.name
                            } else {
                                JSONObject.NULL
                            }
                        )
                    }
                )

                if (checkpoint != null) {
                    factBundles += FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = JSONObject().apply {
                            put("kind", "route_restored_checkpoint_receipt")
                            put("phase", checkpoint.phase.name)
                            put("app_agenda_kind", checkpoint.appAgendaKind ?: JSONObject.NULL)
                            put("step_id", checkpoint.stepId ?: JSONObject.NULL)
                            put("story_stage", checkpoint.storyStage?.name ?: JSONObject.NULL)
                            put("resume_prompt_hint", checkpoint.resumePromptHint ?: JSONObject.NULL)
                            put("resume_reason", "bridge_return_accepted")
                        }
                    )
                }

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "DETOUR_RETURN_DEBUG_BRIDGE_AFTER",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "bridgeAllowsReturn" to bridgeAllowsReturn,
                            "wantsReturnFromBridge" to wantsReturnFromBridge,
                            "userQSizeAfterBridgeBlock" to userQ.size,
                            "appQSizeAfterBridgeBlock" to appQ.size,
                            "newPendingAfterBridgeBlockType" to (newPending?.javaClass?.simpleName ?: "null"),
                            "restoredPendingType" to (restoredPending?.javaClass?.simpleName ?: "null"),
                            "checkpointStepId" to (checkpoint?.stepId ?: "null"),
                            "checkpointStoryStage" to (checkpoint?.storyStage?.name ?: "null"),
                            "checkpointSummaryV1" to routeCheckpointSummaryV1(checkpoint),
                            "boundaryReturnAcceptedV1" to boundaryReturnAcceptedV1,
                            "boundaryResumePolicyV1" to (boundaryResumePolicyV1?.name ?: "null"),
                            "boundaryTruthChangedOnReturnV1" to boundaryTruthChangedOnReturnV1
                        )
                    )
                }
            } else if (wantsReturnFromBridgeRaw && !returnAllowedByDetourState) {
                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = JSONObject().apply {
                        put("kind", "user_agenda_bridge_return_blocked_v1")
                        put("reason", returnGateReasonV1)
                        put("detour_answer_state_v1", s.detourState?.answerState?.name ?: JSONObject.NULL)
                        put(
                            "failure_recovery_decision_v1",
                            s.detourState?.failureRecoveryDecision?.name ?: JSONObject.NULL
                        )
                        put(
                            "checkpoint_summary_v1",
                            routeCheckpointSummaryV1(s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s))
                        )
                    }
                )

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "DETOUR_RETURN_BLOCKED_V1",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "reason" to returnGateReasonV1,
                            "detour_answer_state_v1" to (s.detourState?.answerState?.name ?: "null"),
                            "failure_recovery_decision_v1" to (s.detourState?.failureRecoveryDecision?.name ?: "null"),
                            "checkpoint_summary_v1" to routeCheckpointSummaryV1(s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s))
                        )
                    )
                }
            }
        }


        // 2A) Pending: ConfirmRetake
        // Rule (VISION): two explicit paths:
        //  - YES => user will tap Retake
        //  - Anything else (NO, "continue", questions, silence after speaking) => stay-and-resolve.
        if (pendingBeforeTurn is Pending.ConfirmRetake) {

            // Phase 1 invariant: ONLY structured intents may answer this CTA.
            // (No yes/no parsing or phrase heuristics in Maps.)
            val chooseRetake = answeredYes || choseRetake
            val chooseKeepScan = answeredNo || choseKeepScan

            if (chooseRetake) {

                // Phase 2: WaypointCommit — retake fork decided this turn.
                retakeDecisionUpdate = RetakeDecisionV1.RETAKE

                // One-CTA rule: must end with a CTA, and "tap retake" is the CTA.
                newPending = Pending.WaitForTap(
                    prompt = "Perfect — tap Retake, and I’ll help you get a clean 1:1 match.",
                    digitHint = null,
                    confidence = 0.8f
                )

                // Consume the retake agenda head (new or legacy)
                consumeAppAgendaHeadIfMatches { a ->
                    a is AppAgendaItem.RetakeDecision || a is AppAgendaItem.ProposeRetake
                }

                // NOTE: we do NOT set retakeDismissed when the user chooses retake.
                // (retakeDismissed remains false)
            } else if (chooseKeepScan) {

                // Phase 2: WaypointCommit — retake fork decided this turn.
                retakeDecisionUpdate = RetakeDecisionV1.KEEP_SCAN

                // User explicitly chose to keep scan — continue agenda to mismatch review.
                newPending = null

                consumeAppAgendaHeadIfMatches { a ->
                    a is AppAgendaItem.RetakeDecision || a is AppAgendaItem.ProposeRetake
                }
                // Step 4 will attach next agenda CTA.

                // PATCH P1.2: mark retakeDismissed via PlanV1 (see Patch 1.5)
            } else {
                // Neither explicit yes nor explicit keep-scan:
                // keep pending ConfirmRetake and let Step 3 answer any question / free talk,
                // but do not consume retake agenda and do not dismiss it.
            }
        }

        // 2B) Pending: ConfirmEdit (YES/NO) — safe resolver using BOTH proposed + current
        if (pendingBeforeTurn is Pending.ConfirmEdit) {
            val cellIdx = pendingBeforeTurn.cellIndex.coerceIn(0, 80)
            val proposed = pendingBeforeTurn.proposedDigit.coerceIn(0, 9)

            // "current" = what the on-screen/scanned grid currently has at this cell.
            // This is the value that "as-is / matches on-screen" refers to.
            val current = (llm?.correctedGrid?.getOrNull(cellIdx) ?: 0).coerceIn(0, 9)

            // -------------------------
            // Helpers (keep conservative)
            // -------------------------
            // Helpers removed (Phase 1): no raw-text parsing/heuristics inside Maps.

            // -------------------------
            // Signals from intents
            // -------------------------
            val explicitDigitFromIntents: Int? = env.intents.firstNotNullOfOrNull { itn ->
                val idx = itn.cellIndexOrNullCompat()
                if (idx != cellIdx) return@firstNotNullOfOrNull null

                when (itn.type) {
                    IntentTypeV1.EDIT_CELL,
                    IntentTypeV1.CONFIRM_CELL_TO_DIGIT,
                    IntentTypeV1.PROVIDE_DIGIT -> itn.digitOrNullCompat()

                    // Clearing is a different “shape”; don’t force it into confirm_edit.
                    IntentTypeV1.CLEAR_CELL -> 0

                    else -> null
                }
            }?.takeIf { it in 0..9 }

            val hasConfirmAsIsIntentForCell =
                env.intents.any { itn ->
                    itn.type == IntentTypeV1.CONFIRM_CELL_AS_IS &&
                            itn.cellIndexOrNullCompat() == cellIdx
                }

            // Phase 1: digits must arrive via structured intents only.
            val digitExplicit: Int? = explicitDigitFromIntents

// "as-is" means: keep CURRENT value (reject proposed edit).
            val saidAsIs: Boolean = hasConfirmAsIsIntentForCell
            // -------------------------
            // Decision logic (safe)
            // -------------------------
            val acceptProposed: Boolean
            val rejectProposed: Boolean
            var clarify: Boolean = false
            var clarifyQuestion: String? = null

            if (digitExplicit != null && digitExplicit in 1..9) {
                when (digitExplicit) {
                    proposed -> {
                        acceptProposed = true
                        rejectProposed = false
                    }

                    current -> {
                        acceptProposed = false
                        rejectProposed = true
                    }

                    else -> {
                        // Neither proposed nor current: ambiguous / conflicting info
                        acceptProposed = false
                        rejectProposed = false
                        clarify = true
                        // Keep question 1-line, deterministic.
                        clarifyQuestion =
                            "Got it — I proposed $proposed for row ${cellIdx / 9 + 1}, col ${cellIdx % 9 + 1}, but you said $digitExplicit. Which should we set: $proposed or $digitExplicit?"
                    }
                }
            } else {
                // No explicit digit: bind to yes/no/as-is semantics.
                // answeredYes/answeredNo come from earlier parsing of intents (ANSWER_YES/ANSWER_NO).
                when {
                    saidAsIs -> {
                        acceptProposed = false
                        rejectProposed = true
                    }

                    answeredGridMatchExact || answeredYes -> {
                        acceptProposed = true
                        rejectProposed = false
                    }

                    answeredNo -> {
                        acceptProposed = false
                        rejectProposed = true
                    }

                    else -> {
                        acceptProposed = false
                        rejectProposed = false
                        clarify = true
                        clarifyQuestion =
                            "Quick check: for row ${cellIdx / 9 + 1}, col ${cellIdx % 9 + 1}, should we set it to $proposed, or keep $current?"
                    }
                }
            }

            if (acceptProposed) {
                // Ensure the edit exists (some NLU flows emit ANSWER_YES without EDIT_CELL)
                val alreadyHasEdit = ops.any { op ->
                    op is PlannedOpV1.ApplyCellEdit && op.cellIndex == cellIdx && op.digit == proposed
                }
                if (!alreadyHasEdit) {
                    ops += PlannedOpV1.ApplyCellEdit(
                        cellIndex = cellIdx,
                        digit = proposed,
                        source = "pending_confirm_edit"
                    )
                }

                ops += PlannedOpV1.ConfirmCellValue(
                    cellIndex = cellIdx,
                    digit = proposed,
                    source = "pending_confirm_edit"
                )

                newFocusIdx = cellIdx
                newPending = null

                consumeAppAgendaHeadIfMatches { a ->
                    when (a) {
                        is AppAgendaItem.MismatchReview -> a.cellIndex == cellIdx
                        is AppAgendaItem.ProposeEdit -> a.cellIndex == cellIdx
                        else -> false
                    }
                }

            } else if (rejectProposed) {
                // Reject: clear pending and advance agenda (do NOT loop same proposal).
                newPending = null
                newFocusIdx = cellIdx

                consumeAppAgendaHeadIfMatches { a ->
                    when (a) {
                        is AppAgendaItem.MismatchReview -> a.cellIndex == cellIdx
                        is AppAgendaItem.ProposeEdit -> a.cellIndex == cellIdx
                        else -> false
                    }
                }

                // If rejected without an explicit digit, we need the book value next.
                // If user gave current digit explicitly, we can proceed to next mismatch.
                if (digitExplicit == null || (digitExplicit in 1..9 && digitExplicit != current && digitExplicit != proposed)) {
                    pushFront(
                        AppAgendaItem.ConflictReview(
                            cellIndex = cellIdx,
                            reason = "mismatch_rejected_need_confirm",
                            createdTurnSeq = s.turnSeq
                        )
                    )
                }

            } else if (clarify) {
                // Keep pending; request clarification deterministically.
                // (Assumes you have a way to enqueue clarification in this scope.)
                val intentForClarify = env.intents.firstOrNull()
                if (intentForClarify != null) {
                    enqueueClarification(
                        intent = intentForClarify,
                        missing = listOf("digit"),
                        prompt = clarifyQuestion ?: "Which digit should it be?",
                        kind = ClarifyKind.DIGIT
                    )
                } else {
                    // No intents at all: clear pending to avoid looping; Step 4 will attach next CTA.
                    newPending = null
                    newFocusIdx = cellIdx
                }
                newFocusIdx = cellIdx
                // newPending stays as is

            } else {
                // Safety: if we got here, do not loop forever — clear pending
                // and let Step 4 attach next agenda CTA.
                newPending = null
                newFocusIdx = cellIdx
            }
        }

        // 2C) Pending: AskCellValue — resolve when a cell edit/confirm op for that cell was produced this turn
        if (pendingBeforeTurn is Pending.AskCellValue) {
            val cellIdx = pendingBeforeTurn.cellIndex.coerceIn(0, 80)

            val producedCellOp =
                ops.any { op ->
                    when (op) {
                        is PlannedOpV1.ApplyCellEdit -> op.cellIndex == cellIdx
                        is PlannedOpV1.ConfirmCellValue -> op.cellIndex == cellIdx
                        else -> false
                    }
                }

            if (producedCellOp) {
                // The user provided a value via an explicit intent, so the pending is satisfied.
                newPending = null
                newFocusIdx = cellIdx

                // Consume the agenda head that created the pending
                consumeAppAgendaHeadIfMatches { a ->
                    when (a) {
                        is AppAgendaItem.ConflictReview -> a.cellIndex == cellIdx
                        is AppAgendaItem.AskConfirmCell -> a.cellIndex == cellIdx
                        else -> false
                    }
                }
                // Step 4 will attach next agenda CTA.
            }




        }



        // ------------------------------------------------------------
        // Exact-match recovery bridge:
        // if the route is still carrying ConfirmValidationExactMatch as the app agenda head,
        // allow CONFIRM_GRID_MATCH_EXACT to resolve it even if an earlier clarification pending
        // is still hanging around from a prior contradictory turn.
        // ------------------------------------------------------------
        if (
            answeredGridMatchExact &&
            appQ.firstOrNull() is AppAgendaItem.ConfirmValidationExactMatch
        ) {
            consumeAppAgendaHeadIfMatches { it is AppAgendaItem.ConfirmValidationExactMatch }

            userConfirmedPerfectMatchUpdate = true
            newPhase = GridPhase.SEALING
            newPending = null

            val llmNow = s.grid?.llm as? LLMGridState
            if (llmNow != null) {
                appQ = buildAppAgendaFromGrid(
                    llm = llmNow,
                    phase = GridPhase.SEALING,
                    createdTurnSeq = s.turnSeq,
                    userConfirmedPerfectMatch = true,
                    retakeDismissed = s.retakeDismissed,
                    startSolvingCtaActive = false
                ).toMutableList()
            }
            // Continue to Step 4 so finalize presentation + ConfirmStartSolving
            // can be attached in this same turn.
        }



        // ------------------------------------------------------------
        // ConfirmValidate = exact-match signoff gate.
        //
        // YES => mark userConfirmedPerfectMatch=true, consume the signoff agenda head,
        //        rebuild confirming agenda from updated truth, and let Step 4 attach
        //        FinalizeValidationStartSolving in the SAME turn.
        //
        // NO  => ask which cells differ and RETURN EARLY. Do not finalize UI and do not
        //        ask to start solving.
        // ------------------------------------------------------------
        if (pendingBeforeTurn is Pending.ConfirmValidate) {

            fun consumeConfirmValidateHeadIfPresent() {
                if (appQ.firstOrNull() is AppAgendaItem.ConfirmValidationExactMatch) {
                    val head = appQ.removeAt(0)
                    agendaConsumedCount += 1
                    agendaConsumedTypes += head::class.java.simpleName
                }
            }

            when {
                answeredYes -> {
                    userConfirmedPerfectMatchUpdate = true
                    newPhase = GridPhase.SEALING
                    newPending = null
                    consumeConfirmValidateHeadIfPresent()

                    val llmNow = s.grid?.llm as? LLMGridState
                    if (llmNow != null) {
                        appQ = buildAppAgendaFromGrid(
                            llm = llmNow,
                            phase = GridPhase.SEALING,
                            createdTurnSeq = s.turnSeq,
                            userConfirmedPerfectMatch = true,
                            retakeDismissed = s.retakeDismissed,
                            startSolvingCtaActive = false
                        ).toMutableList()
                    }
                    // Continue to Step 4 so finalize presentation + ConfirmStartSolving
                    // can be attached in this same turn.
                }

                answeredNo -> {
                    userConfirmedPerfectMatchUpdate = false
                    newPhase = GridPhase.CONFIRMING
                    newPending = Pending.AskClarification(
                        kind = ClarifyKind.WORKFLOW,
                        prompt = "Okay — please compare the screen to your paper and tell me which cell(s) differ and what digit(s) they should be."
                    )

                    emitPrefsSnapshotIfNeeded()

                    emitTurnContractSnapshot(
                        tag = "return_confirm_validate_needs_edits",
                        opsPlannedCount = ops.size
                    )
                    return PlanV1(
                        ops = ops,
                        userAgendaQueue = userQ,
                        appAgendaQueue = appQ,
                        newPending = newPending,
                        newMode = newMode,
                        newPhase = newPhase,
                        newFocusIdx = newFocusIdx,

                        // Phase 5: persist active SOLVING agenda head
                        newActiveSolvingAgenda = newActiveSolvingAgenda,

                        newSolveAtomIndex = newSolveAtomIndex,
                        newSolveGuidanceMode = newSolveGuidanceMode,

                        newSolveSkipRemaining = newSolveSkipRemaining,
                        newSolveSkipTotal = newSolveSkipTotal,

                        newUserConfirmedPerfectMatch = userConfirmedPerfectMatchUpdate,
                        newPrefs = newPrefs,
                        factBundles = factBundles,
                        summary = "confirm_validate_no_need_edits"
                    )
                }

                else -> {
                    // Neither yes/no nor edits — keep pending; Step 4 will keep ConfirmValidate CTA.
                }
            }
        }


        // ------------------------------------------------------------
// PATCH 2.3 (final): Resolve Pending.VisualVerifyMatch deterministically (single source of truth).
//
// YES  => userConfirmedPerfectMatch=true, clear pending, consume VisualVerificationRequest, continue agenda in same turn.
// NO   => ask ONE clarification question (which cells differ) and RETURN EARLY (clarification becomes the CTA).
// EDITS => if we already produced ApplyCellEdit ops this turn, treat as NOT a perfect match, clear pending,
//          consume VisualVerificationRequest, continue agenda in same turn.
// ------------------------------------------------------------
        if (pendingBeforeTurn is Pending.VisualVerifyMatch) {
            val answeredYesVisual = hasIntent(IntentTypeV1.CONFIRM_YES)
            val answeredNoVisual = hasIntent(IntentTypeV1.CONFIRM_NO)

            // Detect whether the user provided edits (already converted to ops by Step 1).
            val producedGridMutation =
                ops.any { op -> op is PlannedOpV1.ApplyCellEdit }

            fun consumeVisualVerificationHeadIfPresent() {
                if (appQ.firstOrNull() is AppAgendaItem.VisualVerificationRequest) {
                    val head = appQ.removeAt(0)
                    agendaConsumedCount += 1
                    agendaConsumedTypes += head::class.java.simpleName
                }
            }

            when {
                answeredYesVisual || answeredGridMatchExact -> {
                    userConfirmedPerfectMatchUpdate = true
                    newPending = null
                    consumeVisualVerificationHeadIfPresent()
                    // Continue to Step 4 to attach next waypoint CTA this turn.
                }

                answeredNoVisual -> {
                    userConfirmedPerfectMatchUpdate = false

                    // Clarification is the ONE CTA; do not proceed to agenda CTA in this reply.
                    newPending = Pending.AskClarification(
                        kind = ClarifyKind.WORKFLOW,
                        prompt = "Okay — which cells are different? Tell me the cell(s) and correct digit(s) (example: row 2 col 5 is 7)."
                    )

                    emitPrefsSnapshotIfNeeded()

                    emitTurnContractSnapshot(
                        tag = "return_visual_verify_needs_edits",
                        opsPlannedCount = ops.size
                    )
                    return PlanV1(
                        ops = ops,
                        userAgendaQueue = userQ,
                        appAgendaQueue = appQ,
                        newPending = newPending,
                        newMode = newMode,
                        newPhase = newPhase,
                        newFocusIdx = newFocusIdx,

                        // Phase 5: persist active SOLVING agenda head
                        newActiveSolvingAgenda = newActiveSolvingAgenda,

                        newSolveAtomIndex = newSolveAtomIndex,
                        newSolveGuidanceMode = newSolveGuidanceMode,

                        newSolveSkipRemaining = newSolveSkipRemaining,
                        newSolveSkipTotal = newSolveSkipTotal,

                        newUserConfirmedPerfectMatch = userConfirmedPerfectMatchUpdate,
                        newPrefs = newPrefs,
                        factBundles = factBundles,
                        summary = "visual_verify_no_need_edits"
                    )
                }

                producedGridMutation -> {
                    userConfirmedPerfectMatchUpdate = false
                    newPending = null
                    consumeVisualVerificationHeadIfPresent()
                    // Continue to Step 4 to attach next waypoint CTA this turn.
                }

                else -> {
                    // Neither yes/no nor edits — keep pending; Step 4 will keep VisualVerify CTA.
                }
            }
        }

        fun bootstrapSolvingAgendaHeadIfNeeded() {
            val phaseAfterBootstrap = newPhase ?: s.phase
            if (phaseAfterBootstrap != GridPhase.SOLVING) return

            val existingHead = appQ.firstOrNull() as? AppAgendaItem.Solving
            if (existingHead != null) {
                newActiveSolvingAgenda = existingHead
                return
            }

            val llmNow = s.grid?.llm as? LLMGridState ?: return

            val seededHead =
                buildAppAgendaFromGrid(
                    llm = llmNow,
                    phase = GridPhase.SOLVING,
                    createdTurnSeq = s.turnSeq,
                    userConfirmedPerfectMatch = userConfirmedPerfectMatchUpdate
                        ?: s.userConfirmedPerfectMatch,
                    retakeDismissed = s.retakeDismissed,
                    startSolvingCtaActive = false
                ).firstOrNull() as? AppAgendaItem.Solving ?: return

            appQ.add(0, seededHead)
            newActiveSolvingAgenda = seededHead

            agendaPushedCount++
            agendaPushedTypes += seededHead::class.java.simpleName
        }

// 2D) Pending: ConfirmStartSolving (YES/NO)
        if (pendingBeforeTurn is Pending.ConfirmStartSolving) {

            if (answeredYes) {
                // Enter SOLVING and immediately seed/preserve the first solving head
                // before Step 4 runs. Without this, Step 4 can see an empty app agenda
                // and incorrectly inject a generic workflow clarification CTA.
                newPhase = GridPhase.SOLVING
                newPending = null
                bootstrapSolvingAgendaHeadIfNeeded()
            } else if (answeredNo) {
                newPending = null
            }
        }

// -----------------------------------------------------------------------------
// 2E) SOLVING pending resolution — Tick1 owns meaning (NO raw-text parsing here)
// -----------------------------------------------------------------------------

// Helpers: intent presence + extract reveal / canonical solving controls.
        val hasSolveContinue = hasIntent(IntentTypeV1.SOLVE_CONTINUE)
        val hasSolvePause = hasIntent(IntentTypeV1.SOLVE_PAUSE)
        val hasSolveRevealDigit = hasIntent(IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT)
        val hasRequestExplanation = hasIntent(IntentTypeV1.REQUEST_EXPLANATION)
        val hasRequestReasoningCheck = hasIntent(IntentTypeV1.REQUEST_REASONING_CHECK)
        val hasAskTechniqueOverview = hasIntent(IntentTypeV1.ASK_TECHNIQUE_OVERVIEW)

        val whyNotDigit: Int? =
            env.intents.firstOrNull { it.type == IntentTypeV1.SOLVE_STEP_WHY_NOT_DIGIT }?.payload?.whyNotDigit

// -----------------------------------------------------------------
// Phase 4 routing (missing routes): skip N, batch edits, mismatch report,
// walkback, technique overview
// -----------------------------------------------------------------

        val skipN: Int? =
            env.intents.firstOrNull { it.type == IntentTypeV1.SOLVE_SKIP_N_STEPS }?.payload?.skipSteps

        val editsJson: org.json.JSONArray? =
            env.intents.firstOrNull { it.type == IntentTypeV1.GRID_EDIT_BATCH }?.payload?.edits

        val hasMismatchReport = hasIntent(IntentTypeV1.GRID_MISMATCH_REPORT)
        val hasWalkback = hasIntent(IntentTypeV1.WALKBACK_REQUEST)
        val hasTeachTechniqueGeneral = hasAskTechniqueOverview

        fun parseCellIndex(cell: String): Int? {
            val t = cell.trim().lowercase()
            // Accept: r2c5, R2C5, row 2 col 5, row2col5
            val m1 = Regex("""r\s*([1-9])\s*c\s*([1-9])""").find(t)
            val m2 = Regex("""row\s*([1-9])\s*col\s*([1-9])""").find(t)
            val m = m1 ?: m2
            val r = m?.groupValues?.getOrNull(1)?.toIntOrNull() ?: return null
            val c = m.groupValues.getOrNull(2)?.toIntOrNull() ?: return null
            return ((r - 1) * 9 + (c - 1)).takeIf { it in 0..80 }
        }

        fun applyBatchEdits(edits: org.json.JSONArray) {
            for (i in 0 until edits.length()) {
                val o = edits.optJSONObject(i) ?: continue
                val cellStr = o.optString("cell", "").takeIf { it.isNotBlank() } ?: continue
                val digit = o.optInt("digit", -1)
                val idx = parseCellIndex(cellStr) ?: continue
                if (digit in 1..9) {
                    ops += PlannedOpV1.ApplyCellEdit(
                        cellIndex = idx,
                        digit = digit,
                        source = "user_batch_edits"
                    )
                }
            }
        }

        // ------------------------------------------------------------
// Helpers (local) — MUST be declared before first use (Kotlin)
// ------------------------------------------------------------
        fun currentJourneyStepNumberOrNull(): Int? {
            val llm0 = s.grid?.llm ?: return null
            val g = grid81FromLLM(llm0)
            val filled = g.count { it in "123456789" }
            return (filled + 1).coerceAtMost(81)
        }

        fun currentGridHash12OrNull(): String? {
            val llm0 = s.grid?.llm ?: return null
            return sha12(grid81FromLLM(llm0)).take(12)
        }

// (1) GRID_EDIT_BATCH: apply immediately (your v1 preference)
        if (editsJson != null && editsJson.length() > 0) {
            applyBatchEdits(editsJson)

            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = org.json.JSONObject().apply {
                    put("kind", "grid_edit_batch_applied")
                    put("count", editsJson.length())
                    put(
                        "note",
                        "Edits applied deterministically; if conflicts exist, validator/agenda will surface them."
                    )
                }
            )

            // Let the normal grid-update → (if SOLVING) solve-prefetch path run.
        }


        // (2) GRID_MISMATCH_REPORT: either keep it as a local user detour inside the paused
        // solving route, or explicitly return to CONFIRMING if the user actually requested that.
        if (hasMismatchReport) {
            val checkpointPhaseForUserHead =
                currentUserHead?.checkpointPhase
                    ?: s.routeCheckpointV1?.phase
                    ?: s.phase

            val explicitRouteAbandonRequested =
                hasIntent(IntentTypeV1.REQUEST_REVALIDATE) ||
                        hasIntent(IntentTypeV1.REQUEST_ONLY_VALIDATE)

            val keepPausedSolvingRoute =
                ownerAfterTick1 == TurnOwnerV1.USER_OWNER &&
                        checkpointPhaseForUserHead == GridPhase.SOLVING &&
                        !routing.isRouteControl &&
                        !explicitRouteAbandonRequested

            if (keepPausedSolvingRoute) {
                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = org.json.JSONObject().apply {
                        put("kind", "grid_mismatch_report_detour")
                        put(
                            "note",
                            "Treat the mismatch complaint as a local user detour inside the paused solving route. Do not switch phase or discard the solving queue unless the user explicitly requests re-validation."
                        )
                    }
                )
            } else {
                // Explicit route mutation back to CONFIRMING lane.
                newPhase = GridPhase.CONFIRMING
                newPending = Pending.ConfirmRetake(
                    strength = "soft",
                    prompt = "" // do not script; Tick2 will speak
                )

                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = org.json.JSONObject().apply {
                        put("kind", "grid_mismatch_report")
                        put(
                            "note",
                            "Offer retake OR keep scan and provide edits; do not script trigger phrases."
                        )
                    }
                )
            }
        }

        // (3) WALKBACK_REQUEST: deterministic undo one step boundary (v1)
        if (hasWalkback) {
            val payload =
                env.intents.firstOrNull { it.type == IntentTypeV1.WALKBACK_REQUEST }?.payload
            val toJourney = payload?.walkbackToJourneyStep
            val steps = payload?.walkbackSteps

            val curJourney = currentJourneyStepNumberOrNull()
            val undoCount: Int =
                when {
                    toJourney != null && curJourney != null -> (toJourney - curJourney).let { delta: Int ->
                        // if cur=50 and want 48 => delta=-2 => undo 2
                        (-delta).coerceAtLeast(1)
                    }

                    steps != null -> steps.coerceAtLeast(1)
                    else -> 1
                }.coerceAtMost(60)

            repeat(undoCount) { k ->
                ops += PlannedOpV1.Undo(source = "walkback_request_${k + 1}of$undoCount")
            }

            // After walkback, recompute a fresh next step if SOLVING
            if (s.phase == GridPhase.SOLVING) {
                newPending = null
                newAdvanceToNextStep = true
            }

            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = org.json.JSONObject().apply {
                    put("kind", "walkback_applied")
                    put("undo_count", undoCount)
                    put("to_journey_step", toJourney ?: org.json.JSONObject.NULL)
                    put("note", "Undo applied deterministically. Continue from updated grid.")
                }
            )
        }

        // (4) ASK_TECHNIQUE_OVERVIEW: inject TEACHING_CARD even outside SOLVING
        if (hasTeachTechniqueGeneral) {
            val requestedTech =
                env.intents.firstOrNull { it.type == IntentTypeV1.ASK_TECHNIQUE_OVERVIEW }?.payload?.technique
                    ?.trim()?.lowercase()

            val lang = s.prefs.language.takeIf { it.isNotBlank() } ?: "en"
            val techniqueId =
                requestedTech
                    ?: s.coachPlan?.techniqueId
                    ?: s.coachPlan?.title?.trim()?.lowercase()

            if (!techniqueId.isNullOrBlank()) {
                val card =
                    com.contextionary.sudoku.conductor.solving.TechniqueCards.bundleFor(
                        techniqueId,
                        lang
                    )
                        ?: com.contextionary.sudoku.conductor.solving.TechniqueCards.fallbackBundleFor(
                            techniqueId,
                            lang
                        )

                if (card != null) {
                    factBundles += card
                }
            }

            if (s.phase == GridPhase.SOLVING && s.activeRouteContext != null) {
                val stepPacket = s.solvingReadyFactBundlesV1
                    .firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
                    ?.payload

                if (stepPacket != null) {
                    factBundles += FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = org.json.JSONObject().apply {
                            put("schema_version", "return_to_route_packet_v1")
                            put("route", org.json.JSONObject().apply {
                                put("step_id", s.activeRouteContext!!.stepId)
                                put("journey_step_number", s.activeRouteContext!!.journeyStepNumber)
                                put("hint_index", s.activeRouteContext!!.atomIndex)
                                put("hint_count", s.activeRouteContext!!.atomsCount)
                                put(
                                    "technique_id",
                                    s.activeRouteContext!!.techniqueId ?: org.json.JSONObject.NULL
                                )
                                put(
                                    "target_cell_index",
                                    s.activeRouteContext!!.targetCellIndex
                                        ?: org.json.JSONObject.NULL
                                )
                            })
                            put("step_packet", stepPacket) // embed, no recompute
                            put(
                                "note",
                                "Detour handled. Return to the exact current solving step without recompute."
                            )
                        }
                    )
                }
            }
        }

// (5) SOLVE_SKIP_N_STEPS: start auto-reveal/apply loop + range semantics (Phase 4 second half)
        if (skipN != null && skipN > 0 && s.phase == GridPhase.SOLVING) {
            val n = skipN.coerceAtMost(50) // safety clamp

            // Range semantics for narration: start=current journey step, end=start+n
            val startJourney = currentJourneyStepNumberOrNull() ?: 0
            val endJourney = if (startJourney in 1..81) (startJourney + n).coerceAtMost(81) else 0

            newSolveSkipTotal = n
            newSolveSkipStartJourneyStep = startJourney
            newSolveSkipEndJourneyStep = endJourney

            // If we can apply the currently loaded reveal right now, do it immediately.
            val cp = s.coachPlan
            val reveal = cp?.reveal
            val curHash12 = currentGridHash12OrNull()
            val boundHash12 = (s.coachPlanGridHash12 ?: curHash12 ?: "").take(12)
            val safeToApplyNow =
                (reveal != null && curHash12 != null && boundHash12.isNotBlank() && curHash12 == boundHash12)

            if (safeToApplyNow) {
                val idx = reveal!!.placementCellIndex
                val digit = reveal.placementDigit
                if (idx in 0..80 && digit in 1..9) {
                    ops += PlannedOpV1.ApplyCellEdit(
                        cellIndex = idx,
                        digit = digit,
                        source = "skip_apply_1ofN"
                    )
                    newSolveSkipRemaining = (n - 1).coerceAtLeast(0)
                } else {
                    newSolveSkipRemaining = n
                }
            } else {
                // Let the next SolveStepUpdated drive the apply loop.
                newSolveSkipRemaining = n
                // Ensure we compute a fresh step if needed
                newPending = null
            }

            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = org.json.JSONObject().apply {
                    put("kind", "solve_skip_requested")
                    put("n", n)
                    put(
                        "note",
                        "Auto-apply N revealed steps without speaking; then present the next step normally."
                    )
                }
            )

            // Attach range facts so Tick2 can say: "I applied up to step X; now we're at Y"
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = org.json.JSONObject().apply {
                    put("kind", "solve_skip_range")
                    put("start_journey_step", startJourney)
                    put("end_journey_step", endJourney)
                }
            )
        }

// ----- Pending: SolvePreference (hint ladder / reveal / why-not) -----
// ============================================================
// Phase 5: SOLVING is agenda-driven (single reducer + transition table)
// Phase 1: NarrativeStoryContext must be kept in sync with SOLVING pending/agenda
// ============================================================
        if ((newPhase ?: s.phase) == GridPhase.SOLVING) {

            // Phase 3 / Phase 9 invariant:
            // if the user owns the turn after Tick1 while SOLVING, the app road is fully frozen.
            // Preserve the current solving head and do NOT advance the route, story, or checkpoint source.
            if (!freezeAppRouteForUserTurn) {
                val solvingRes = handleSolvingAgendaV1(
                    s = s,
                    env = env,
                    routing = routing,
                    hasIntent = { t -> hasIntent(t) },
                    currentGridHash12OrNull = { currentGridHash12OrNull() }
                )

                if (solvingRes.newActiveAgenda != null) {
                    val prevSolvingAgenda = currentQueuedSolvingHead(s)
                    val nextSolvingAgenda = solvingRes.newActiveAgenda
                    newActiveSolvingAgenda = nextSolvingAgenda
                    emitSolvingAgendaTransitionIfChanged(
                        traceState = s,
                        phaseNow = (newPhase ?: s.phase),
                        prev = prevSolvingAgenda,
                        next = nextSolvingAgenda
                    )
                }

                if (solvingRes.newPending != null || solvingRes.advanceToNextStep) {
                    newPending = solvingRes.newPending
                    newAdvanceToNextStep =
                        ((newAdvanceToNextStep == true) || solvingRes.advanceToNextStep)

                    newNarrativeStory =
                        materializeNarrativeStoryForBoundaryV1(
                            s = s,
                            pending = newPending,
                            activeAgenda = newActiveSolvingAgenda ?: currentQueuedSolvingHead(s),
                            previousStory = newNarrativeStory ?: s.narrativeStory,
                            advanceToNextStep = (newAdvanceToNextStep == true),
                            preserveStageOnStayAndElaborate = false
                        )
                }

                if (solvingRes.factBundles.isNotEmpty()) {
                    factBundles += solvingRes.factBundles
                }
            } else {
                // True pause: preserve the current app-road head exactly.
                newActiveSolvingAgenda = currentQueuedSolvingHead(s)

                // Also preserve the current story exactly; user-owned detours must not
                // refresh or re-materialize app story stages during the pause.
                newNarrativeStory = s.narrativeStory
            }

            // ------------------------------------------------------------
            // North Star:
            // boundary-crossing story materialization now happens at the same point
            // where the solving transition result is accepted.
            //
            // During a USER-owned SOLVING turn, this app-story refresh pass is disabled.
            // ------------------------------------------------------------
            runCatching {
                if (!freezeAppRouteForUserTurn) {
                    if (newAdvanceToNextStep == true) {
                        newNarrativeStory = null
                    } else if (
                        routing.solvingRoadSemantic == SolvingRoadSemanticV2.STAY_AND_ELABORATE &&
                        newNarrativeStory == null
                    ) {
                        newNarrativeStory =
                            materializeNarrativeStoryForBoundaryV1(
                                s = s,
                                pending = newPending,
                                activeAgenda = newActiveSolvingAgenda ?: currentQueuedSolvingHead(s),
                                previousStory = s.narrativeStory,
                                advanceToNextStep = false,
                                preserveStageOnStayAndElaborate = true
                            )
                    }
                }
            }.getOrNull()
        }

// ------------------------------------------------------------
// ✅ Pack 4 + Pack 7:
// Commit acceptance is driven by the solving intent / route boundary.
//
// Pack 7 truth gate:
// speaking RESOLUTION requires verified board truth.
// Scheduling ApplyCellEdit is not, by itself, enough to speak resolution.
//
// Therefore:
// - already present on board  -> promote to POST_COMMIT / RESOLUTION
// - apply scheduled only      -> stay in COMMIT_APPLY and wait
// - neither true              -> recover
// ------------------------------------------------------------
        runCatching {
            val phaseNow = (newPhase ?: s.phase)
            if (phaseNow == GridPhase.SOLVING && !freezeAppRouteForUserTurn) {

                val effectiveSolvingHead =
                    newActiveSolvingAgenda ?: currentQueuedSolvingHead(s)

                val effectiveStoryStage =
                    authoritativeStoryStageV1(
                        solvingHead = effectiveSolvingHead,
                        pending = newPending ?: s.pending,
                        story = newNarrativeStory ?: s.narrativeStory
                    )

                val rawIntentTypes = env.intents.map { it.type }.toSet()

                val genericResumeLikeAccept =
                    rawIntentTypes.contains(IntentTypeV1.SOLVE_CONTINUE)

                val explicitCommitAccept =
                    rawIntentTypes.contains(IntentTypeV1.SOLVE_STEP_REVEAL_DIGIT)

                val autoCommitBecauseResolution =
                    (effectiveStoryStage == StoryStage.RESOLUTION)

                val wantsCommit =
                    autoCommitBecauseResolution ||
                            explicitCommitAccept ||
                            (genericResumeLikeAccept && (
                                    effectiveSolvingHead is AppAgendaItem.Solving.CommitDecision ||
                                            effectiveSolvingHead is AppAgendaItem.Solving.CommitApply
                                    ))

                val atCommitBoundary =
                    autoCommitBecauseResolution ||
                            effectiveSolvingHead is AppAgendaItem.Solving.CommitDecision ||
                            effectiveSolvingHead is AppAgendaItem.Solving.CommitApply

                val recoveryAlreadyChosen = newPending is Pending.SolveStepMissing

                if (wantsCommit && atCommitBoundary && !recoveryAlreadyChosen) {

                    val reveal = s.coachPlan?.reveal
                    val idx = reveal?.placementCellIndex ?: -1
                    val digit = reveal?.placementDigit ?: -1

                    val validReveal = (idx in 0..80 && digit in 1..9)

                    val curDigit: Int? = if (validReveal) {
                        runCatching {
                            val llm0 = s.grid?.llm ?: return@runCatching null
                            val g81 = grid81FromLLM(llm0)
                            val ch = g81.getOrNull(idx) ?: return@runCatching null
                            if (ch in '1'..'9') (ch - '0') else 0
                        }.getOrNull()
                    } else null

                    val alreadyApplied = (validReveal && curDigit == digit)
                    var applyScheduled = false

                    resolutionCommitCellIndexV1 = if (validReveal) idx else null
                    resolutionCommitDigitV1 = if (validReveal) digit else null
                    resolutionCommitOutcomeV1 = ResolutionCommitOutcomeV1.NONE

                    if (validReveal && !alreadyApplied) {
                        ops += PlannedOpV1.ApplyCellEdit(
                            cellIndex = idx,
                            digit = digit,
                            source = "solve_resolution_apply"
                        )
                        applyScheduled = true

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = org.json.JSONObject().apply {
                                put("kind", "solve_resolution_apply_scheduled")
                                put("cell_index", idx)
                                put("digit", digit)
                                put("step_id", s.solveStepId ?: JSONObject.NULL)
                                put("grid_hash12", (s.solveStepGridHash12 ?: "").take(12))
                                put("source", "solve_resolution_apply")
                            }
                        )
                    }

                    val route = s.activeRouteContext?.let {
                        ActiveRouteContextV2(
                            gridHash12 = it.gridHash12,
                            stepId = it.stepId,
                            techniqueId = it.techniqueId,
                            targetCell = it.targetCellIndex?.let { targetIdx ->
                                "r${(targetIdx / 9) + 1}c${(targetIdx % 9) + 1}"
                            }
                        )
                    } ?: ActiveRouteContextV2(
                        gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                    )

                    val stepIndex = s.solveStepSeq.toInt()

                    val story0 = (newNarrativeStory ?: s.narrativeStory)
                    if (story0 != null) {
                        val n = story0.atomsCount.coerceAtLeast(1)
                        newNarrativeStory = story0.copy(
                            stage = StoryStage.RESOLUTION,
                            focusAtomIndex = defaultFocusAtomIndexForStageV1(
                                stage = StoryStage.RESOLUTION,
                                atomsCount = n
                            ),
                            discussedAtomIndices = narrationAtomIndicesForStageV1(
                                stage = StoryStage.RESOLUTION,
                                atomsCount = n
                            ),
                            readyForCommit = true
                        )
                    }

                    if (alreadyApplied) {
                        resolutionCommitOutcomeV1 = ResolutionCommitOutcomeV1.APP_AUTO_COMMIT

                        newActiveSolvingAgenda = AppAgendaItem.Solving.PostCommitChoice(
                            agendaId = "sa:post:${s.turnSeq}",
                            createdAtMs = System.currentTimeMillis(),
                            createdTurnSeq = s.turnSeq,
                            stepIndex = stepIndex,
                            route = route
                        )

                        newPending = Pending.AfterResolution(
                            stepId = s.solveStepId ?: "",
                            prompt = "",
                            gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                        )

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = org.json.JSONObject().apply {
                                put("kind", "solve_resolution_apply_verified")
                                put("cell_index", if (validReveal) idx else JSONObject.NULL)
                                put("digit", if (validReveal) digit else JSONObject.NULL)
                                put("already_applied", true)
                                put("apply_scheduled", applyScheduled)
                                put("resolution_commit_outcome_v1", resolutionCommitOutcomeV1.name)
                            }
                        )

                        emitWaveARegressionHookV1(
                            hook = "VERIFIED_COMMIT_ENTERS_POST_COMMIT",
                            data = mapOf(
                                "turn_id" to s.turnSeq,
                                "step_id" to (s.solveStepId ?: ""),
                                "grid_hash12" to (s.solveStepGridHash12 ?: "").take(12),
                                "cell_index" to (if (validReveal) idx else null),
                                "digit" to (if (validReveal) digit else null)
                            )
                        )
                    } else if (applyScheduled) {
                        resolutionCommitOutcomeV1 = ResolutionCommitOutcomeV1.APP_AUTO_COMMIT

                        newActiveSolvingAgenda = AppAgendaItem.Solving.CommitApply(
                            agendaId = "sa:apply:${s.turnSeq}",
                            createdAtMs = System.currentTimeMillis(),
                            createdTurnSeq = s.turnSeq,
                            stepIndex = stepIndex,
                            route = route,
                            commitReason = "resolution_apply_scheduled_waiting_for_confirmation"
                        )

                        newPending = Pending.ApplyHintNow(
                            stepId = s.solveStepId ?: "",
                            prompt = "",
                            gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                        )

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = org.json.JSONObject().apply {
                                put("kind", "solve_resolution_apply_pending_confirmation")
                                put("cell_index", if (validReveal) idx else JSONObject.NULL)
                                put("digit", if (validReveal) digit else JSONObject.NULL)
                                put("already_applied", false)
                                put("apply_scheduled", true)
                                put("resolution_commit_outcome_v1", resolutionCommitOutcomeV1.name)
                            }
                        )

                        emitWaveARegressionHookV1(
                            hook = "APPLY_SCHEDULED_STAYS_COMMIT_APPLY",
                            data = mapOf(
                                "turn_id" to s.turnSeq,
                                "step_id" to (s.solveStepId ?: ""),
                                "grid_hash12" to (s.solveStepGridHash12 ?: "").take(12),
                                "cell_index" to (if (validReveal) idx else null),
                                "digit" to (if (validReveal) digit else null)
                            )
                        )
                    } else {
                        val boundHash12 =
                            (s.coachPlanGridHash12 ?: (s.solveStepGridHash12 ?: "")).take(12)

                        resolutionCommitOutcomeV1 = ResolutionCommitOutcomeV1.COMMIT_UNAVAILABLE

                        newActiveSolvingAgenda = AppAgendaItem.Solving.CommitApply(
                            agendaId = "sa:apply_repair:${s.turnSeq}",
                            createdAtMs = System.currentTimeMillis(),
                            createdTurnSeq = s.turnSeq,
                            stepIndex = stepIndex,
                            route = route,
                            commitReason = "resolution_apply_required_but_unavailable"
                        )

                        newPending = Pending.ApplyHintNow(
                            stepId = s.solveStepId ?: "",
                            prompt = "",
                            gridHash12 = boundHash12
                        )

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = org.json.JSONObject().apply {
                                put("kind", "solve_resolution_apply_required_but_unavailable")
                                put("reason", "resolution_entered_but_apply_not_possible")
                                put("cell_index", if (validReveal) idx else JSONObject.NULL)
                                put("digit", if (validReveal) digit else JSONObject.NULL)
                                put("step_id", s.solveStepId ?: JSONObject.NULL)
                                put("grid_hash12", boundHash12)
                                put("resolution_commit_outcome_v1", resolutionCommitOutcomeV1.name)
                            }
                        )
                    }
                }
            }
        }.getOrNull()


        // ------------------------------------------------------------
// RESOLUTION may already be active before board truth is confirmed.
// This pass only upgrades the internal rail from CommitApply
// to PostCommitChoice once the board actually reflects the edit.
// ------------------------------------------------------------

        runCatching {
            val phaseNow = (newPhase ?: s.phase)
            if (phaseNow == GridPhase.SOLVING && !freezeAppRouteForUserTurn) {
                val effectiveSolvingHead =
                    newActiveSolvingAgenda ?: currentQueuedSolvingHead(s)

                val waitingForBoardTruth =
                    effectiveSolvingHead is AppAgendaItem.Solving.CommitApply

                if (waitingForBoardTruth && isRevealAlreadyAppliedOnBoardV1(s)) {
                    val route = s.activeRouteContext?.let {
                        ActiveRouteContextV2(
                            gridHash12 = it.gridHash12,
                            stepId = it.stepId,
                            techniqueId = it.techniqueId,
                            targetCell = it.targetCellIndex?.let { targetIdx ->
                                "r${(targetIdx / 9) + 1}c${(targetIdx % 9) + 1}"
                            }
                        )
                    } ?: ActiveRouteContextV2(
                        gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                    )

                    val stepIndex = s.solveStepSeq.toInt()

                    newActiveSolvingAgenda = AppAgendaItem.Solving.PostCommitChoice(
                        agendaId = "sa:post:${s.turnSeq}",
                        createdAtMs = System.currentTimeMillis(),
                        createdTurnSeq = s.turnSeq,
                        stepIndex = stepIndex,
                        route = route
                    )

                    newPending = Pending.AfterResolution(
                        stepId = s.solveStepId ?: "",
                        prompt = "",
                        gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                    )

                    val story0 = (newNarrativeStory ?: s.narrativeStory)
                    if (story0 != null) {
                        val n = story0.atomsCount.coerceAtLeast(1)
                        newNarrativeStory = story0.copy(
                            stage = StoryStage.RESOLUTION,
                            focusAtomIndex = defaultFocusAtomIndexForStageV1(
                                stage = StoryStage.RESOLUTION,
                                atomsCount = n
                            ),
                            discussedAtomIndices = narrationAtomIndicesForStageV1(
                                stage = StoryStage.RESOLUTION,
                                atomsCount = n
                            ),
                            readyForCommit = true
                        )
                    }

                    factBundles += FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = org.json.JSONObject().apply {
                            put("kind", "solve_commit_apply_verified_promote_resolution")
                            put("step_id", s.solveStepId ?: JSONObject.NULL)
                            put("grid_hash12", (s.solveStepGridHash12 ?: "").take(12))
                        }
                    )
                }
            }
        }.getOrNull()


// ----- Pending: SolveStepMissing (recovery) -----
        if (pendingBeforeTurn is Pending.SolveStepMissing) {
            val wantsNext =
                hasIntent(IntentTypeV1.SOLVE_CONTINUE)
            if (wantsNext) {
                // Clear pending; reducer will compute next step in SOLVING (compute-then-speak).
                newPending = null
            }
        }

        // ------------------------------------------------------------
// 3) Step 3 — Answer user questions (with App evidence bundles)
// ------------------------------------------------------------
// ✅ Deterministic “best question” selection (fixes ordering sensitivity).
// Priority (high → low):
//  - explicit cell target questions (rXcY)
//  - explicit region target questions (row/col/box)
//  - global completion/status queries
//  - digit queries
//  - everything else
        fun isSelectableQuestionIntent(t: IntentTypeV1): Boolean =
            t == IntentTypeV1.ASK_CELL_VALUE ||
                    t == IntentTypeV1.ASK_CELL_STATUS ||

                    // Contents / house
                    t == IntentTypeV1.ASK_ROW_CONTENTS ||
                    t == IntentTypeV1.ASK_COL_CONTENTS ||
                    t == IntentTypeV1.ASK_BOX_CONTENTS ||
                    t == IntentTypeV1.ASK_HOUSE_COMPLETION ||
                    t == IntentTypeV1.ASK_HOUSE_MISSING_DIGITS ||

                    // Umbrella (inspection)
                    t == IntentTypeV1.ASK_HOUSE_OVERVIEW ||
                    t == IntentTypeV1.ASK_HOUSE_RANKING ||
                    t == IntentTypeV1.ASK_DIGIT_OVERVIEW ||
                    t == IntentTypeV1.ASK_DIGIT_IN_HOUSE_OVERVIEW ||
                    t == IntentTypeV1.ASK_GRID_CONTENTS_OVERVIEW ||

                    // Digits
                    t == IntentTypeV1.ASK_DIGIT_LOCATIONS ||
                    t == IntentTypeV1.ASK_DIGIT_COUNT_GLOBAL ||
                    t == IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE ||

                    // House completion
                    t == IntentTypeV1.ASK_EMPTY_HOUSES ||
                    t == IntentTypeV1.ASK_NEARLY_COMPLETE_HOUSES ||
                    t == IntentTypeV1.ASK_COMPLETE_HOUSES_COUNT ||
                    t == IntentTypeV1.ASK_COMPLETE_HOUSES_LIST ||
                    t == IntentTypeV1.ASK_HOUSES_COMPLETION_RANKING ||

                    // Provenance / trust
                    t == IntentTypeV1.ASK_WHAT_CHANGED_RECENTLY ||
                    t == IntentTypeV1.ASK_SOURCE_OF_DIGIT ||
                    t == IntentTypeV1.ASK_OCR_CONFIDENCE_CELL ||
                    t == IntentTypeV1.ASK_OCR_CONFIDENCE_SUMMARY ||

                    // Umbrella (trust)
                    t == IntentTypeV1.ASK_TRUST_OVERVIEW ||
                    t == IntentTypeV1.ASK_CELL_TRUST_DETAILS ||
                    t == IntentTypeV1.ASK_PROVENANCE_OVERVIEW ||

                    // Candidate inspection
                    t == IntentTypeV1.ASK_CELL_CANDIDATES ||
                    t == IntentTypeV1.ASK_CANDIDATE_COUNT_CELL ||
                    t == IntentTypeV1.ASK_CELLS_WITH_N_CANDIDATES ||
                    t == IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP ||
                    t == IntentTypeV1.ASK_CANDIDATE_FREQUENCY ||

                    // Umbrella (candidates)
                    t == IntentTypeV1.ASK_CANDIDATES_OVERVIEW ||
                    t == IntentTypeV1.ASK_CANDIDATES_CELL_OVERVIEW ||
                    t == IntentTypeV1.ASK_CANDIDATES_DISTRIBUTION ||

                    // Validation & diagnosis
                    t == IntentTypeV1.ASK_STRUCTURAL_VALIDITY ||
                    t == IntentTypeV1.ASK_CONFLICTS_GLOBAL ||
                    t == IntentTypeV1.ASK_CONFLICTS_IN_HOUSE ||
                    t == IntentTypeV1.ASK_CONFLICT_DETAILS_CELL ||
                    t == IntentTypeV1.ASK_DUPLICATES_IN_HOUSE ||
                    t == IntentTypeV1.ASK_IF_RETAKE_NEEDED ||
                    t == IntentTypeV1.ASK_SEAL_STATUS ||
                    t == IntentTypeV1.ASK_UNRESOLVED_CELLS ||

                    // Umbrella (validation)
                    t == IntentTypeV1.ASK_CONFLICTS_OVERVIEW ||
                    t == IntentTypeV1.ASK_VALIDATION_OVERVIEW ||
                    t == IntentTypeV1.ASK_PROBLEM_CELLS_OVERVIEW ||
                    t == IntentTypeV1.ASK_MISMATCH_OVERVIEW ||
                    t == IntentTypeV1.ASK_RETAKE_GUIDANCE ||

                    // Solving/strategy
                    t == IntentTypeV1.ASK_PROGRESS_METRICS ||
                    t == IntentTypeV1.ASK_NAKED_SINGLE_LOCATIONS ||
                    t == IntentTypeV1.ASK_HIDDEN_SINGLE_LOCATIONS ||
                    t == IntentTypeV1.ASK_IF_STUCK ||
                    t == IntentTypeV1.ASK_IF_GUESS_REQUIRED ||
                    t == IntentTypeV1.ASK_DIFFICULTY_ESTIMATE ||
                    t == IntentTypeV1.ASK_TECHNIQUES_NEEDED ||
                    t == IntentTypeV1.ASK_SOLVABILITY_STATUS ||

                    // Umbrella (solving)
                    t == IntentTypeV1.ASK_SOLVING_OVERVIEW ||
                    t == IntentTypeV1.ASK_TECHNIQUE_OVERVIEW ||
                    t == IntentTypeV1.ASK_STUCK_HELP ||
                    t == IntentTypeV1.ASK_ADVANCED_PATTERN_HELP ||

                    // Explain / teaching
                    t == IntentTypeV1.REQUEST_EXPLANATION ||
                    t == IntentTypeV1.REQUEST_REASONING_CHECK ||
                    t == IntentTypeV1.ASK_TECHNIQUE_OVERVIEW ||

                    // Dashboard
                    t == IntentTypeV1.REQUEST_SUMMARY_DASHBOARD ||

                    // UI
                    t == IntentTypeV1.ASK_UI_LEGEND ||
                    t == IntentTypeV1.ASK_HOW_TO_LOCATE_CELL ||
                    t == IntentTypeV1.ASK_BOX_INDEX_MAPPING ||
                    t == IntentTypeV1.ASK_COORDINATE_TRANSLATION ||
                    t == IntentTypeV1.ASK_WHAT_DO_YOU_MEAN_BY_HOUSE ||

                    // Umbrella (UI)
                    t == IntentTypeV1.ASK_UI_HELP ||
                    t == IntentTypeV1.ASK_COORDINATES_HELP ||

                    // Existing V1 questions
                    t == IntentTypeV1.ASK_WHY_THIS_CELL

        fun bestQuestionScore(i: IntentV1): Int {
            val hasCell = i.targets.any { it.cell != null }
            val hasRegion = i.targets.any { it.region != null }
            val missingPenalty = i.missing.size * 20

            val typeScore = when (i.type) {
                // Cell-level / provenance / trust cell
                IntentTypeV1.ASK_CELL_VALUE,
                IntentTypeV1.ASK_CELL_STATUS,
                IntentTypeV1.ASK_SOURCE_OF_DIGIT,
                IntentTypeV1.ASK_OCR_CONFIDENCE_CELL,
                IntentTypeV1.ASK_CELL_CANDIDATES,
                IntentTypeV1.ASK_CELL_TRUST_DETAILS,
                IntentTypeV1.ASK_PROVENANCE_OVERVIEW,
                IntentTypeV1.ASK_CANDIDATES_CELL_OVERVIEW -> 110

                // House-level / contents / overview
                IntentTypeV1.ASK_ROW_CONTENTS,
                IntentTypeV1.ASK_COL_CONTENTS,
                IntentTypeV1.ASK_BOX_CONTENTS,
                IntentTypeV1.ASK_HOUSE_COMPLETION,
                IntentTypeV1.ASK_HOUSE_MISSING_DIGITS,
                IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP,
                IntentTypeV1.ASK_HOUSE_OVERVIEW,
                IntentTypeV1.ASK_GRID_CONTENTS_OVERVIEW,
                IntentTypeV1.ASK_CANDIDATES_OVERVIEW -> 95

                // Completion / ranking
                IntentTypeV1.ASK_COMPLETE_HOUSES_COUNT,
                IntentTypeV1.ASK_COMPLETE_HOUSES_LIST,
                IntentTypeV1.ASK_HOUSES_COMPLETION_RANKING,
                IntentTypeV1.ASK_HOUSE_RANKING -> 85

                // Validation overview / conflicts / retake / trust overview
                IntentTypeV1.ASK_STRUCTURAL_VALIDITY,
                IntentTypeV1.ASK_CONFLICTS_GLOBAL,
                IntentTypeV1.ASK_IF_RETAKE_NEEDED,
                IntentTypeV1.ASK_SEAL_STATUS,
                IntentTypeV1.REQUEST_SUMMARY_DASHBOARD,
                IntentTypeV1.ASK_CONFLICTS_OVERVIEW,
                IntentTypeV1.ASK_VALIDATION_OVERVIEW,
                IntentTypeV1.ASK_RETAKE_GUIDANCE,
                IntentTypeV1.ASK_TRUST_OVERVIEW,
                IntentTypeV1.ASK_OCR_CONFIDENCE_SUMMARY -> 70

                // Digits / distribution
                IntentTypeV1.ASK_DIGIT_COUNT_GLOBAL,
                IntentTypeV1.ASK_DIGIT_LOCATIONS,
                IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE,
                IntentTypeV1.ASK_DIGIT_OVERVIEW,
                IntentTypeV1.ASK_DIGIT_IN_HOUSE_OVERVIEW,
                IntentTypeV1.ASK_CANDIDATES_DISTRIBUTION -> 60

                else -> 40
            }

            val targetBonus = (if (hasCell) 30 else 0) + (if (hasRegion) 20 else 0)
            return (typeScore + targetBonus - missingPenalty)
        }

        // -----------------------------
        // ✅ Multi-question answering (cap)
        // -----------------------------
        val selectableQuestions = intents
            .filter { isSelectableQuestionIntent(it.type) }
            .sortedWith(
                compareByDescending<IntentV1> { bestQuestionScore(it) }
                    .thenByDescending { it.confidence }
                    .thenBy { it.id }
            )

        val answerCap = 6
        val qsToAnswer = selectableQuestions.take(answerCap)
        val primaryQ = qsToAnswer.firstOrNull()

        val deferredQuestions = selectableQuestions.drop(answerCap)

        // Let Tick2 know deterministically what we will answer now vs later (no “one at a time” policy text).
        if (qsToAnswer.isNotEmpty() || deferredQuestions.isNotEmpty()) {
            factBundles += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = JSONObject().apply {
                    put("answered_questions_count", qsToAnswer.size)
                    put(
                        "answered_questions",
                        JSONArray().apply { qsToAnswer.forEach { put(it.type.name) } })
                    put("deferred_questions_count", deferredQuestions.size)
                    put(
                        "deferred_questions",
                        JSONArray().apply {
                            deferredQuestions.take(12).forEach { put(it.type.name) }
                        })
                    put(
                        "note",
                        "Answer all asked questions this turn up to a cap; anything beyond cap is deferred deterministically."
                    )
                }
            )
        }

        if (primaryQ != null && llm != null) {

            fun digitCountsFrom(indices: List<Int>): IntArray {
                val counts = IntArray(10)
                for (idx in indices) {
                    val d = llm.correctedGrid.getOrNull(idx)?.coerceIn(0, 9) ?: 0
                    if (d in 1..9) counts[d]++
                }
                return counts
            }

            fun missingDigitsFrom(indices: List<Int>): List<Int> {
                val present = BooleanArray(10)
                for (idx in indices) {
                    val d = llm.correctedGrid.getOrNull(idx)?.coerceIn(0, 9) ?: 0
                    if (d in 1..9) present[d] = true
                }
                val out = mutableListOf<Int>()
                for (d in 1..9) if (!present[d]) out.add(d)
                return out
            }

            fun houseStatusBundle(region: RegionRefV1): FactBundleV1 {
                val idxs = regionIndices(region)
                val digits = idxs.map { i -> llm.correctedGrid.getOrNull(i)?.coerceIn(0, 9) ?: 0 }
                val filled = digits.count { it in 1..9 }
                val missing = 9 - filled
                val missingDigits = missingDigitsFrom(idxs)
                val counts = digitCountsFrom(idxs)

                val hist = JSONObject().apply {
                    for (d in 1..9) put(d.toString(), counts[d])
                }

                return FactBundleV1(
                    type = FactBundleV1.Type.HOUSE_STATUS_BUNDLE,
                    payload = JSONObject().apply {
                        put("house_ref", houseRefV1(region.kind, region.index))
                        put("cells", JSONArray().apply { idxs.forEach { put(indexToCell(it)) } })
                        put(
                            "cell_refs",
                            jsonArrayOfObjects(idxs.map { cellRefV1(indexToCell(it)) })
                        )
                        put("digits", JSONArray().apply { digits.forEach { put(it) } })
                        put("filled_count", filled)
                        put("missing_count", missing)
                        put(
                            "missing_digits",
                            JSONArray().apply { missingDigits.forEach { put(it) } })
                        put("digit_histogram", hist)
                    }
                )
            }

            // ---------------------------------------------------------
            // ✅ Ranked house completion analytics (rows/cols/boxes)
            // Powers: “closest to completion”, “lowest hanging fruit”, “emptiest house”
            // ---------------------------------------------------------

            data class HouseCompletionStat(
                val kind: RegionKindV1,
                val index: Int,                // 1..9
                val filledCount: Int,          // 0..9
                val missingCount: Int,         // 0..9
                val blanks: List<String>,      // ["r1c4", ...]
                val missingDigits: List<Int>   // [2,5,9]
            )

            fun computeHouseCompletionStats(grid81: IntArray): List<HouseCompletionStat> {

                fun statFor(kind: RegionKindV1, index: Int): HouseCompletionStat {
                    val rr = RegionRefV1(kind, index)
                    val idxs = regionIndices(rr)
                    val digits = idxs.map { i -> grid81.getOrNull(i)?.coerceIn(0, 9) ?: 0 }

                    val filled = digits.count { it in 1..9 }
                    val blanksIdx = idxs.filter { i ->
                        val v = grid81.getOrNull(i)?.coerceIn(0, 9) ?: 0
                        v !in 1..9
                    }

                    val present = BooleanArray(10)
                    digits.filter { it in 1..9 }.forEach { present[it] = true }
                    val missing = (1..9).filter { !present[it] }

                    return HouseCompletionStat(
                        kind = kind,
                        index = index,
                        filledCount = filled,
                        missingCount = 9 - filled,
                        blanks = blanksIdx.map { indexToCell(it) },
                        missingDigits = missing
                    )
                }

                val out = mutableListOf<HouseCompletionStat>()
                for (k in 1..9) {
                    out += statFor(RegionKindV1.ROW, k)
                    out += statFor(RegionKindV1.COL, k)
                    out += statFor(RegionKindV1.BOX, k)
                }
                return out
            }

            fun housesCompletionRankingBundle(grid81: IntArray, topN: Int = 5): FactBundleV1 {
                val stats = computeHouseCompletionStats(grid81)

                fun sortClosest(list: List<HouseCompletionStat>): List<HouseCompletionStat> =
                    list.sortedWith(
                        compareBy<HouseCompletionStat>(
                            { it.missingCount },
                            { -it.filledCount },
                            { it.index })
                    )

                fun sortEmptiest(list: List<HouseCompletionStat>): List<HouseCompletionStat> =
                    list.sortedWith(
                        compareBy<HouseCompletionStat>(
                            { -it.missingCount },
                            { it.filledCount },
                            { it.index })
                    )

                fun top(kind: RegionKindV1): List<HouseCompletionStat> =
                    sortClosest(stats.filter { it.kind == kind }).take(topN)

                fun emptiest(kind: RegionKindV1): HouseCompletionStat =
                    sortEmptiest(stats.filter { it.kind == kind }).first()

                fun closestOverall(): List<HouseCompletionStat> =
                    sortClosest(stats).take(12)

                fun toJson(s: HouseCompletionStat): JSONObject =
                    JSONObject().apply {
                        put("kind", s.kind.name)
                        put("index", s.index)
                        put("house_ref", houseRefV1(s.kind, s.index))
                        put("filled_count", s.filledCount)
                        put("missing_count", s.missingCount)
                        put(
                            "missing_digits",
                            JSONArray().apply { s.missingDigits.forEach { put(it) } })
                        put("blanks", JSONArray().apply { s.blanks.forEach { put(it) } })
                    }

                val topRows = top(RegionKindV1.ROW)
                val topCols = top(RegionKindV1.COL)
                val topBoxes = top(RegionKindV1.BOX)

                val emptiestRow = emptiest(RegionKindV1.ROW)
                val emptiestCol = emptiest(RegionKindV1.COL)
                val emptiestBox = emptiest(RegionKindV1.BOX)

                val closest = closestOverall()

                val highlights = JSONArray().apply {
                    if (closest.isNotEmpty()) {
                        val c0 = closest.first()
                        put("Closest overall: ${c0.kind.name} ${c0.index} (missing ${c0.missingCount})")
                    }
                    put("Emptiest box: BOX ${emptiestBox.index} (filled ${emptiestBox.filledCount}/9)")
                }

                return FactBundleV1(
                    type = FactBundleV1.Type.HOUSES_COMPLETION_RANKING,
                    payload = JSONObject().apply {
                        put("top_n", topN)

                        put(
                            "closest_overall",
                            JSONArray().apply { closest.forEach { put(toJson(it)) } })

                        put("top_rows", JSONArray().apply { topRows.forEach { put(toJson(it)) } })
                        put("top_cols", JSONArray().apply { topCols.forEach { put(toJson(it)) } })
                        put("top_boxes", JSONArray().apply { topBoxes.forEach { put(toJson(it)) } })

                        put("emptiest_row", toJson(emptiestRow))
                        put("emptiest_col", toJson(emptiestCol))
                        put("emptiest_box", toJson(emptiestBox))

                        put("highlights", highlights)
                        put(
                            "note",
                            "Ranked by missing_count asc for closest; desc for emptiest. Use for 'closest to completion' analytics."
                        )
                    }
                )
            }


            fun cellStatusBundle(idx: Int): FactBundleV1 {
                val cell = indexToCell(idx)
                val d = llm.correctedGrid.getOrNull(idx)?.coerceIn(0, 9) ?: 0

                val provenance = when {
                    llm.truthIsGiven.getOrNull(idx) == true -> "GIVEN"
                    llm.confirmedCells.contains(idx) -> "CONFIRMED"
                    llm.manualEdits.any { it.index == idx } -> "USER_EDIT"
                    llm.changedCells.contains(idx) -> "AUTO_CHANGED"
                    else -> "SCAN"
                }

                return FactBundleV1(
                    type = FactBundleV1.Type.CELL_STATUS_BUNDLE,
                    payload = JSONObject().apply {
                        put("cell", cell) // legacy
                        put("cell_ref", cellRefV1(cell))
                        put("digit", d)

                        put("is_given", llm.truthIsGiven.getOrNull(idx) == true)
                        put("is_solution_truth", llm.truthIsSolution.getOrNull(idx) == true)
                        put("is_conflict", llm.conflictCells.contains(idx))
                        put("is_low_confidence", llm.lowConfidenceCells.contains(idx))
                        put("is_unresolved", llm.unresolvedCells.contains(idx))
                        put("is_confirmed", llm.confirmedCells.contains(idx))

                        put("provenance", provenance)
                    }
                )
            }

            fun changelogRecentBundle(n: Int = 8): FactBundleV1 {
                val edits = llm.manualEdits.sortedByDescending { it.whenEpochMs }.take(n)
                val arr = JSONArray()
                for (e in edits) {
                    arr.put(
                        JSONObject().apply {
                            put("seq", e.seq)
                            put("index", e.index)
                            put("cell", e.cellLabel)
                            put("cell_ref", cellRefV1(e.cellLabel))
                            put("from", e.fromDigit)
                            put("to", e.toDigit)
                            put("when_epoch_ms", e.whenEpochMs)
                            put("source", e.source)
                        }
                    )
                }
                return FactBundleV1(
                    type = FactBundleV1.Type.CHANGELOG_RECENT,
                    payload = JSONObject().apply {
                        put("count", edits.size)
                        put("items", arr)
                    }
                )
            }

            fun digitDistributionGlobalBundle(): FactBundleV1 {
                val counts = IntArray(10)
                for (i in 0 until 81) {
                    val d = llm.correctedGrid.getOrNull(i)?.coerceIn(0, 9) ?: 0
                    if (d in 1..9) counts[d]++
                }
                val obj = JSONObject().apply { for (d in 1..9) put(d.toString(), counts[d]) }
                return FactBundleV1(
                    type = FactBundleV1.Type.DIGIT_DISTRIBUTION_GLOBAL,
                    payload = JSONObject().apply { put("counts", obj) }
                )
            }

            fun digitLocationsBundle(digit: Int): FactBundleV1 {
                val d = digit.coerceIn(1, 9)
                val idxs =
                    (0 until 81).filter { llm.correctedGrid.getOrNull(it)?.coerceIn(0, 9) == d }
                return FactBundleV1(
                    type = FactBundleV1.Type.DIGIT_LOCATIONS_BUNDLE,
                    payload = JSONObject().apply {
                        put("digit_ref", digitRefV1(d))
                        put("cells", JSONArray().apply { idxs.forEach { put(indexToCell(it)) } })
                        put(
                            "cell_refs",
                            jsonArrayOfObjects(idxs.map { cellRefV1(indexToCell(it)) })
                        )
                        put("count", idxs.size)
                    }
                )
            }

            fun completeHousesBundle(scopeRaw: String?, includeList: Boolean): FactBundleV1 {
                // scope: "ROW" | "COL" | "BOX" | "ANY" (default ANY)
                val scope = (scopeRaw ?: "ANY").trim().uppercase()

                fun filledInRegion(rr: RegionRefV1): Int {
                    val idxs = regionIndices(rr)
                    return idxs.count { llm.correctedGrid.getOrNull(it)?.coerceIn(0, 9) in 1..9 }
                }

                fun completeOf(kind: RegionKindV1): List<Int> {
                    val complete = mutableListOf<Int>()
                    for (k in 1..9) {
                        val filled = filledInRegion(RegionRefV1(kind, k))
                        if (filled == 9) complete += k
                    }
                    return complete
                }

                val payload = JSONObject().apply {
                    put("definition", "complete = house has no blanks (no 0) in displayed grid")
                    put("scope", scope)
                }

                fun putList(key: String, xs: List<Int>) {
                    payload.put(key, JSONArray().apply { xs.forEach { put(it) } })
                }

                when (scope) {
                    "ROW" -> {
                        val rows = completeOf(RegionKindV1.ROW)
                        payload.put("count", rows.size)
                        if (includeList) putList("rows", rows)
                    }

                    "COL" -> {
                        val cols = completeOf(RegionKindV1.COL)
                        payload.put("count", cols.size)
                        if (includeList) putList("cols", cols)
                    }

                    "BOX" -> {
                        val boxes = completeOf(RegionKindV1.BOX)
                        payload.put("count", boxes.size)
                        if (includeList) putList("boxes", boxes)
                    }

                    else -> {
                        // ANY / unknown: return breakdown across all house kinds
                        val rows = completeOf(RegionKindV1.ROW)
                        val cols = completeOf(RegionKindV1.COL)
                        val boxes = completeOf(RegionKindV1.BOX)

                        payload.put("count", rows.size + cols.size + boxes.size)
                        payload.put("count_rows", rows.size)
                        payload.put("count_cols", cols.size)
                        payload.put("count_boxes", boxes.size)

                        if (includeList) {
                            putList("rows", rows)
                            putList("cols", cols)
                            putList("boxes", boxes)
                        }
                    }
                }

                return FactBundleV1(
                    type = FactBundleV1.Type.COMPLETE_HOUSES_BUNDLE,
                    payload = payload
                )
            }


            fun gridSnapshotBundle(): FactBundleV1 {
                // Digits 0..9 (0 = blank)
                val digits = JSONArray().apply {
                    for (i in 0 until 81) put(llm.correctedGrid.getOrNull(i)?.coerceIn(0, 9) ?: 0)
                }

                fun bitmask81(indices: List<Int>): String {
                    val b = CharArray(81) { '0' }
                    indices.forEach { idx -> if (idx in 0..80) b[idx] = '1' }
                    return String(b)
                }

                fun boolMask81(arr: BooleanArray): String {
                    val b = CharArray(81) { '0' }
                    for (i in 0 until 81) if (arr.getOrNull(i) == true) b[i] = '1'
                    return String(b)
                }

                fun cells(indices: List<Int>): JSONArray =
                    JSONArray().apply { indices.forEach { put(indexToCell(it)) } }

                fun cellRefs(indices: List<Int>): JSONArray =
                    jsonArrayOfObjects(indices.map { cellRefV1(indexToCell(it)) })

                val givenIdxs = (0 until 81).filter { llm.truthIsGiven.getOrNull(it) == true }
                val solutionIdxs = (0 until 81).filter { llm.truthIsSolution.getOrNull(it) == true }

                return FactBundleV1(
                    type = FactBundleV1.Type.GRID_SNAPSHOT,
                    payload = JSONObject().apply {
                        put("digits", digits)

                        // Full truth flags (bitmask81 strings are compact + deterministic)
                        put("flags", JSONObject().apply {
                            put("given_mask81", boolMask81(llm.truthIsGiven))
                            put("solution_mask81", boolMask81(llm.truthIsSolution))
                            put("confirmed_mask81", bitmask81(llm.confirmedCells))
                            put("conflict_mask81", bitmask81(llm.conflictCells))
                            put("mismatch_mask81", bitmask81(llm.mismatchCells))
                            put("low_confidence_mask81", bitmask81(llm.lowConfidenceCells))
                            put("unresolved_mask81", bitmask81(llm.unresolvedCells))
                            put("changed_mask81", bitmask81(llm.changedCells))
                            put("manually_corrected_mask81", bitmask81(llm.manuallyCorrectedCells))
                        })

                        // Also provide full lists (human-friendly, still small enough)
                        put("cells", JSONObject().apply {
                            put("given", cells(givenIdxs))
                            put("solution", cells(solutionIdxs))
                            put("confirmed", cells(llm.confirmedCells))
                            put("conflict", cells(llm.conflictCells))
                            put("mismatch", cells(llm.mismatchCells))
                            put("low_confidence", cells(llm.lowConfidenceCells))
                            put("unresolved", cells(llm.unresolvedCells))
                            put("changed", cells(llm.changedCells))
                            put("manually_corrected", cells(llm.manuallyCorrectedCells))
                        })

                        // Provenance (minimal but truthful)
                        put("provenance_rules", JSONObject().apply {
                            put("given", "SCAN")
                            put("confirmed", "USER_CONFIRM")
                            put("manually_corrected", "USER_EDIT")
                            put("solution", "SOLVER_DERIVED")
                        })

                        put("cell_refs", JSONObject().apply {
                            put("given", cellRefs(givenIdxs))
                            put("confirmed", cellRefs(llm.confirmedCells))
                            put("conflict", cellRefs(llm.conflictCells))
                            put("low_confidence", cellRefs(llm.lowConfidenceCells))
                        })
                    }
                )
            }

            fun summaryDashboardBundle(detailLevel: String = "normal"): FactBundleV1 {
                // Keep it compact but structured.
                val payload = JSONObject().apply {
                    put("detail_level", detailLevel)

                    put("counts", JSONObject().apply {
                        put("conflicts", llm.conflictCells.size)
                        put("mismatches", llm.mismatchCells.size)
                        put("low_confidence", llm.lowConfidenceCells.size)
                        put("unresolved", llm.unresolvedCells.size)
                        put("confirmed", llm.confirmedCells.size)
                    })

                    // Useful highlights for speech (small samples)
                    put("samples", JSONObject().apply {
                        put(
                            "conflict_cells",
                            JSONArray().apply {
                                llm.conflictCells.take(8).forEach { put(indexToCell(it)) }
                            })
                        put(
                            "low_conf_cells",
                            JSONArray().apply {
                                llm.lowConfidenceCells.take(8).forEach { put(indexToCell(it)) }
                            })
                        put(
                            "unresolved_cells",
                            JSONArray().apply {
                                llm.unresolvedCells.take(8).forEach { put(indexToCell(it)) }
                            })
                        put(
                            "mismatch_cells",
                            JSONArray().apply {
                                llm.mismatchCells.take(8).forEach { put(indexToCell(it)) }
                            })
                    })

                    // If you have severity/solvability fields already:
                    put("solvability", llm.solvability)
                    put("is_structurally_valid", llm.isStructurallyValid)
                    put("severity", llm.severity)
                }

                return FactBundleV1(
                    type = FactBundleV1.Type.SUMMARY_DASHBOARD,
                    payload = payload
                )
            }


            fun structuralValidityBundle(): FactBundleV1 {
                // Minimal, structured reasons
                val duplicates = computeDuplicatesByHouse(llm.correctedGrid)
                val hasDupes = duplicates.isNotEmpty()
                val hasContradiction = false // reserved for candidate wipeout checks (see Patch 6)
                val isValid = !hasDupes

                return FactBundleV1(
                    type = FactBundleV1.Type.STRUCTURAL_VALIDITY,
                    payload = JSONObject().apply {
                        put("is_valid", isValid)
                        put("reason_codes", JSONArray().apply {
                            if (hasDupes) put("DUPLICATE_DIGITS")
                            if (hasContradiction) put("CONTRADICTION")
                        })
                        put("duplicate_house_count", duplicates.size)
                    }
                )
            }

            fun duplicatesByHouseBundle(): FactBundleV1 {
                val dupes = computeDuplicatesByHouse(llm.correctedGrid)
                return FactBundleV1(
                    type = FactBundleV1.Type.DUPLICATES_BY_HOUSE,
                    payload = JSONObject().apply {
                        put("houses", JSONArray().apply {
                            dupes.forEach { h ->
                                put(JSONObject().apply {
                                    put("house_kind", h.kind)
                                    put("house_index", h.index)
                                    put("digit", h.digit)
                                    put(
                                        "cells",
                                        JSONArray().apply { h.cells.forEach { put(indexToCell(it)) } })
                                })
                            }
                        })
                        put("count", dupes.size)
                    }
                )
            }

            fun conflictSetBundle(maxCells: Int = 40): FactBundleV1 {
                val conflicts = computeConflictSet(llm.correctedGrid).take(maxCells)
                return FactBundleV1(
                    type = FactBundleV1.Type.CONFLICT_SET,
                    payload = JSONObject().apply {
                        put("items", JSONArray().apply {
                            conflicts.forEach { item ->
                                put(JSONObject().apply {
                                    put("cell", indexToCell(item.cell))
                                    put("digit", item.digit)
                                    put(
                                        "peers",
                                        JSONArray().apply { item.peers.forEach { put(indexToCell(it)) } })
                                    put("reason", item.reason)
                                })
                            }
                        })
                        put("count", conflicts.size)
                        put(
                            "truncated",
                            computeConflictSet(llm.correctedGrid).size > conflicts.size
                        )
                    }
                )
            }

            fun retakeRecommendationBundle(): FactBundleV1 {
                return FactBundleV1(
                    type = FactBundleV1.Type.RETAKE_RECOMMENDATION,
                    payload = JSONObject().apply {
                        put("strength", llm.retakeRecommendation)
                        put("drivers", JSONObject().apply {
                            put("conflicts", llm.conflictCells.size)
                            put("low_confidence", llm.lowConfidenceCells.size)
                            put("mismatches", llm.mismatchCells.size)
                            put("unresolved", llm.unresolvedCells.size)
                        })
                    }
                )
            }

            fun sealStatusBundle(phase: GridPhase): FactBundleV1 {
                return FactBundleV1(
                    type = FactBundleV1.Type.SEAL_STATUS,
                    payload = JSONObject().apply {
                        put("phase", phase.name)
                        put("sealed", phase == GridPhase.SOLVING)
                    }
                )
            }


            // -----------------------------
            // Focus anchoring (best-effort)
            // -----------------------------
            // -----------------------------
            // Answer ALL question intents this turn (bounded)
            // -----------------------------
            for ((qIndex, q) in qsToAnswer.withIndex()) {

                // -----------------------------
                // Focus anchoring (best-effort) per-question
                // -----------------------------
                val idx = q.cellIndexOrNullCompat() ?: (newFocusIdx ?: s.focusCellIndex)
                val region = q.regionOrNullCompat()
                val qDigit = q.digitOrNullCompat()

                if (idx != null) newFocusIdx = idx

                // ✅ Provide ONE primary focus context (avoid spamming multiple contexts)
                if (qIndex == 0) {
                    factBundles += FactBundleV1(
                        type = FactBundleV1.Type.FOCUS_CONTEXT,
                        payload = JSONObject().apply {
                            put("question_intent", q.type.name)
                            if (idx != null) {
                                val cell = indexToCell(idx)
                                put("cell_ref", cellRefV1(cell))
                                put("cell", cell) // legacy
                            }
                            if (region != null) put(
                                "house_ref",
                                houseRefV1(region.kind, region.index)
                            )
                            if (qDigit != null) put("digit_ref", digitRefV1(qDigit))
                        }
                    )
                }

                // -----------------------------
                // Answer Phase-1 query intents (multi)
                // -----------------------------
                when (q.type) {

                    // ---- cell/value/status/provenance ----
                    IntentTypeV1.ASK_CELL_VALUE,
                    IntentTypeV1.ASK_CELL_STATUS,
                    IntentTypeV1.ASK_SOURCE_OF_DIGIT -> {
                        if (idx == null) {
                            enqueueClarification(
                                q,
                                listOf("cell"),
                                "Which cell do you mean?",
                                ClarifyKind.POSITION
                            )
                        } else {
                            factBundles += cellStatusBundle(idx)
                        }
                    }

                    // ---- row/col/box/house ----
                    IntentTypeV1.ASK_ROW_CONTENTS,
                    IntentTypeV1.ASK_COL_CONTENTS,
                    IntentTypeV1.ASK_BOX_CONTENTS,
                    IntentTypeV1.ASK_HOUSE_COMPLETION,
                    IntentTypeV1.ASK_HOUSE_MISSING_DIGITS,
                    IntentTypeV1.ASK_HOUSE_OVERVIEW,
                    IntentTypeV1.ASK_GRID_CONTENTS_OVERVIEW -> {
                        val r0 = region ?: run {
                            enqueueClarification(
                                q,
                                listOf("region"),
                                "Which row, column, or box?",
                                ClarifyKind.POSITION
                            )
                            null
                        }
                        r0?.let { regionRef ->
                            factBundles += houseStatusBundle(regionRef)
                            if (qIndex == 0) newFocusIdx =
                                regionIndices(regionRef).firstOrNull() ?: newFocusIdx
                        }
                    }

                    // ---- structural validity ----
                    IntentTypeV1.ASK_STRUCTURAL_VALIDITY,
                    IntentTypeV1.ASK_VALIDATION_OVERVIEW -> {
                        factBundles += structuralValidityBundle()
                        // Include duplicates detail because it is the primary “why invalid” proof.
                        factBundles += duplicatesByHouseBundle()
                    }

                    // ---- conflicts / duplicates ----
                    IntentTypeV1.ASK_CONFLICTS_GLOBAL,
                    IntentTypeV1.ASK_CONFLICTS_OVERVIEW -> {
                        factBundles += conflictSetBundle(maxCells = 60)
                        factBundles += duplicatesByHouseBundle()
                    }

                    IntentTypeV1.ASK_DUPLICATES_IN_HOUSE -> {
                        // Current bundle is global-by-house; Tick2 can filter by the asked house if needed.
                        factBundles += duplicatesByHouseBundle()
                    }

                    IntentTypeV1.ASK_CONFLICTS_IN_HOUSE -> {
                        val r0 = region ?: run {
                            enqueueClarification(
                                q,
                                listOf("region"),
                                "Which row, column, or box?",
                                ClarifyKind.POSITION
                            )
                            null
                        }
                        r0?.let { regionRef ->
                            val idxs = regionIndices(regionRef).toSet()
                            val items = computeConflictSet(llm.correctedGrid)
                                .filter { idxs.contains(it.cell) }
                                .take(60)

                            factBundles += FactBundleV1(
                                type = FactBundleV1.Type.CONFLICT_SET,
                                payload = JSONObject().apply {
                                    put("scope_house", regionRef.toJson())
                                    put("items", JSONArray().apply {
                                        items.forEach { item ->
                                            put(JSONObject().apply {
                                                put("cell", indexToCell(item.cell))
                                                put("digit", item.digit)
                                                put(
                                                    "peers",
                                                    JSONArray().apply {
                                                        item.peers.forEach {
                                                            put(indexToCell(it))
                                                        }
                                                    })
                                                put("reason", item.reason)
                                            })
                                        }
                                    })
                                }
                            )
                        }
                    }

                    IntentTypeV1.ASK_CONFLICT_DETAILS_CELL -> {
                        if (idx == null) {
                            enqueueClarification(
                                q,
                                listOf("cell"),
                                "Which cell do you mean?",
                                ClarifyKind.POSITION
                            )
                        } else {
                            val item =
                                computeConflictSet(llm.correctedGrid).firstOrNull { it.cell == idx }
                            if (item == null) {
                                factBundles += FactBundleV1(
                                    type = FactBundleV1.Type.LIMITATIONS,
                                    payload = JSONObject().apply {
                                        put("reason", "no_conflict_found_for_cell")
                                        put("cell", indexToCell(idx))
                                    }
                                )
                            } else {
                                factBundles += FactBundleV1(
                                    type = FactBundleV1.Type.CONFLICT_EXPLANATION,
                                    payload = JSONObject().apply {
                                        val cell = indexToCell(idx)
                                        put("cell", cell)
                                        put("cell_ref", cellRefV1(cell))
                                        put("digit", item.digit)
                                        put(
                                            "peers",
                                            JSONArray().apply {
                                                item.peers.forEach {
                                                    put(
                                                        indexToCell(it)
                                                    )
                                                }
                                            })
                                        put("reason", item.reason)
                                        put("conflict_count", llm.conflictCells.size)
                                    }
                                )
                            }
                        }
                    }

// ---- mismatch overview ----
                    IntentTypeV1.ASK_MISMATCH_OVERVIEW -> {
                        val maxCells = 60
                        val cells = llm.mismatchCells.take(maxCells)
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.MISMATCH_SET,
                            payload = JSONObject().apply {
                                put("items", JSONArray().apply {
                                    cells.forEach { mi ->
                                        val cell = indexToCell(mi)
                                        val scanned =
                                            llm.correctedGrid[mi.coerceIn(0, 80)].coerceIn(0, 9)
                                        val expected =
                                            llm.deducedSolutionGrid?.getOrNull(mi)?.coerceIn(0, 9)
                                        put(JSONObject().apply {
                                            put("cell", cell)
                                            put("cell_ref", cellRefV1(cell))
                                            put("scanned_digit", scanned)
                                            put("expected_digit", expected ?: JSONObject.NULL)
                                        })
                                    }
                                })
                                put("count", llm.mismatchCells.size)
                                put("truncated", llm.mismatchCells.size > cells.size)
                                put(
                                    "details_sample",
                                    JSONArray().apply {
                                        llm.mismatchDetails.take(12).forEach { put(it) }
                                    })
                            }
                        )
                    }

                    // ---- unresolved / problem cells (NEW bundle) ----
                    IntentTypeV1.ASK_UNRESOLVED_CELLS,
                    IntentTypeV1.ASK_PROBLEM_CELLS_OVERVIEW -> {
                        val maxCells = 60
                        val cells = llm.unresolvedCells.take(maxCells)
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.UNRESOLVED_SET,
                            payload = JSONObject().apply {
                                put("items", JSONArray().apply {
                                    cells.forEach { ui ->
                                        val cell = indexToCell(ui)
                                        val scanned =
                                            llm.correctedGrid[ui.coerceIn(0, 80)].coerceIn(0, 9)
                                        put(JSONObject().apply {
                                            put("cell", cell)
                                            put("cell_ref", cellRefV1(cell))
                                            put("scanned_digit", scanned)
                                            put(
                                                "note",
                                                "Unresolved means the scan could not confidently determine the digit."
                                            )
                                        })
                                    }
                                })
                                put("count", llm.unresolvedCells.size)
                                put("truncated", llm.unresolvedCells.size > cells.size)
                            }
                        )
                    }

                    // ---- OCR confidence summaries / candidates / dashboard etc (keep your existing cases) ----
                    // NOTE: everything below here is your existing logic, unchanged, just kept under multi-intent loop.

                    IntentTypeV1.ASK_CELL_CANDIDATES -> {
                        val idx2 = q.cellIndexOrNullCompat()
                        if (idx2 != null) {
                            val mask = llm.candidateMask81.getOrNull(idx2)?.takeIf { it != 0 }
                                ?: computeCandidateMask(llm.correctedGrid, idx2)
                            factBundles += FactBundleV1(
                                type = FactBundleV1.Type.CANDIDATE_STATE_CELL,
                                payload = JSONObject().apply {
                                    put("cell", indexToCell(idx2))
                                    put("mask", mask)
                                    put(
                                        "digits",
                                        JSONArray().apply { digitsFromMask(mask).forEach { put(it) } })
                                }
                            )
                        } else {
                            factBundles += FactBundleV1(
                                FactBundleV1.Type.LIMITATIONS,
                                JSONObject().apply {
                                    put("reason", "missing_cell_target")
                                })
                        }
                    }

                    IntentTypeV1.ASK_CELLS_WITH_N_CANDIDATES -> {
                        val n = q.payload.candidateCount ?: q.payload.digit
                        if (n != null) {
                            val idxs = (0 until 81).filter { i ->
                                val m = llm.candidateMask81.getOrNull(i)?.takeIf { it != 0 }
                                    ?: computeCandidateMask(llm.correctedGrid, i)
                                digitsFromMask(m).size == n
                            }
                            factBundles += FactBundleV1(
                                type = FactBundleV1.Type.CELLS_WITH_N_CANDS_SET,
                                payload = JSONObject().apply {
                                    put("n", n)
                                    put(
                                        "cells",
                                        JSONArray().apply { idxs.forEach { put(indexToCell(it)) } })
                                    put("count", idxs.size)
                                }
                            )
                            if (n == 2) {
                                factBundles += FactBundleV1(
                                    FactBundleV1.Type.BIVALUE_CELLS_SET,
                                    JSONObject().apply {
                                        put(
                                            "cells",
                                            JSONArray().apply { idxs.forEach { put(indexToCell(it)) } })
                                        put("count", idxs.size)
                                    })
                            }
                        }
                    }

                    IntentTypeV1.ASK_HOUSE_CANDIDATE_MAP,
                    IntentTypeV1.ASK_CANDIDATES_OVERVIEW -> {
                        val r = q.regionOrNullCompat()
                        if (r != null) {
                            val cells = regionIndices(r)
                            val map = JSONObject()
                            for (d in 1..9) {
                                val poss = cells.filter { id ->
                                    val m = llm.candidateMask81.getOrNull(id)?.takeIf { it != 0 }
                                        ?: computeCandidateMask(llm.correctedGrid, id)
                                    (m and (1 shl (d - 1))) != 0
                                }
                                map.put(
                                    d.toString(),
                                    JSONArray().apply { poss.forEach { put(indexToCell(it)) } })
                            }
                            factBundles += FactBundleV1(
                                FactBundleV1.Type.HOUSE_CANDIDATE_MAP,
                                JSONObject().apply {
                                    put("house", r.toJson())
                                    put("map", map)
                                })
                        }
                    }

                    IntentTypeV1.ASK_CANDIDATE_FREQUENCY,
                    IntentTypeV1.ASK_CANDIDATES_DISTRIBUTION -> {
                        val freq = IntArray(10)
                        for (i in 0 until 81) {
                            val m = llm.candidateMask81.getOrNull(i)?.takeIf { it != 0 }
                                ?: computeCandidateMask(llm.correctedGrid, i)
                            for (d in 1..9) if ((m and (1 shl (d - 1))) != 0) freq[d]++
                        }
                        val obj = JSONObject().apply { for (d in 1..9) put(d.toString(), freq[d]) }
                        factBundles += FactBundleV1(
                            FactBundleV1.Type.DIGIT_CANDIDATE_FREQUENCY,
                            JSONObject().apply {
                                put("counts", obj)
                            })
                    }

                    IntentTypeV1.ASK_DIGIT_COUNT_GLOBAL,
                    IntentTypeV1.ASK_DIGIT_OVERVIEW -> {
                        // ASK_DIGIT_OVERVIEW = broad digit distribution/rarity; do not require a specific digit.
                        if (q.type == IntentTypeV1.ASK_DIGIT_OVERVIEW) {
                            factBundles += digitDistributionGlobalBundle()
                        } else {
                            val d = qDigit
                            if (d == null) enqueueClarification(
                                q,
                                listOf("digit"),
                                "Which digit (1–9)?",
                                ClarifyKind.DIGIT
                            )
                            else factBundles += digitDistributionGlobalBundle()
                        }
                    }

                    IntentTypeV1.ASK_DIGIT_LOCATIONS -> {
                        val d = qDigit
                        if (d == null) enqueueClarification(
                            q,
                            listOf("digit"),
                            "Which digit (1–9)?",
                            ClarifyKind.DIGIT
                        )
                        else factBundles += digitLocationsBundle(d)
                    }

                    IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE,
                    IntentTypeV1.ASK_DIGIT_IN_HOUSE_OVERVIEW -> {
                        val d = qDigit
                        val r = region

                        // For the umbrella, digit is OPTIONAL: house status bundle can still answer a lot.
                        val requireDigit = (q.type == IntentTypeV1.ASK_DIGIT_COUNT_IN_HOUSE)

                        val missing = buildList {
                            if (r == null) add("region")
                            if (requireDigit && d == null) add("digit")
                        }

                        if (missing.isNotEmpty()) {
                            enqueueClarification(
                                q,
                                missing,
                                if (requireDigit) "Which digit and which row/column/box?" else "Which row, column, or box?",
                                ClarifyKind.POSITION
                            )
                        } else {
                            val rr = r!!
                            factBundles += houseStatusBundle(rr)
                            if (qIndex == 0) newFocusIdx =
                                regionIndices(rr).firstOrNull() ?: newFocusIdx
                        }
                    }

                    IntentTypeV1.ASK_COMPLETE_HOUSES_COUNT,
                    IntentTypeV1.ASK_COMPLETE_HOUSES_LIST -> {
                        val scope = q.payload.scope
                        factBundles += completeHousesBundle(
                            scopeRaw = scope,
                            includeList = (q.type == IntentTypeV1.ASK_COMPLETE_HOUSES_LIST)
                        )
                    }

                    IntentTypeV1.ASK_HOUSES_COMPLETION_RANKING,
                    IntentTypeV1.ASK_HOUSE_RANKING -> {
                        // ✅ “closest to completion / lowest hanging fruit / emptiest house” analytics
                        factBundles += housesCompletionRankingBundle(
                            grid81 = llm.correctedGrid,
                            topN = 5
                        )
                    }

                    IntentTypeV1.ASK_EMPTY_HOUSES,
                    IntentTypeV1.ASK_NEARLY_COMPLETE_HOUSES -> {
                        // keep your existing implementation (unchanged)
                        val emptyRows = mutableListOf<Int>()
                        val emptyCols = mutableListOf<Int>()
                        val emptyBoxes = mutableListOf<Int>()

                        val nearlyRows = mutableListOf<Int>()
                        val nearlyCols = mutableListOf<Int>()
                        val nearlyBoxes = mutableListOf<Int>()

                        fun filledInRegion(rr: RegionRefV1): Int {
                            val idxs = regionIndices(rr)
                            return idxs.count {
                                llm.correctedGrid.getOrNull(it)?.coerceIn(0, 9) in 1..9
                            }
                        }

                        for (k in 1..9) {
                            val fr = filledInRegion(RegionRefV1(RegionKindV1.ROW, k))
                            val fc = filledInRegion(RegionRefV1(RegionKindV1.COL, k))
                            val fb = filledInRegion(RegionRefV1(RegionKindV1.BOX, k))

                            if (fr == 0) emptyRows.add(k)
                            if (fc == 0) emptyCols.add(k)
                            if (fb == 0) emptyBoxes.add(k)

                            if (9 - fr in 1..2) nearlyRows.add(k)
                            if (9 - fc in 1..2) nearlyCols.add(k)
                            if (9 - fb in 1..2) nearlyBoxes.add(k)
                        }

                        val payload = JSONObject().apply {
                            put("empty_rows", JSONArray().apply { emptyRows.forEach { put(it) } })
                            put("empty_cols", JSONArray().apply { emptyCols.forEach { put(it) } })
                            put("empty_boxes", JSONArray().apply { emptyBoxes.forEach { put(it) } })
                            put("nearly_rows", JSONArray().apply { nearlyRows.forEach { put(it) } })
                            put("nearly_cols", JSONArray().apply { nearlyCols.forEach { put(it) } })
                            put(
                                "nearly_boxes",
                                JSONArray().apply { nearlyBoxes.forEach { put(it) } })
                        }

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.SUMMARY_DASHBOARD,
                            payload = JSONObject().apply {
                                put("detail_level", "houses_summary")
                                put("houses", payload)
                                put("note", "This is a houses summary (empty/nearly-complete).")
                            }
                        )
                    }

                    IntentTypeV1.REQUEST_SUMMARY_DASHBOARD -> {
                        val dl =
                            q.payload.detailLevel?.trim()?.takeIf { it.isNotBlank() }
                                ?: q.payload.queryKind?.trim()?.takeIf { it.isNotBlank() }
                                ?: "normal"

                        factBundles += summaryDashboardBundle(detailLevel = dl)
                        factBundles += gridSnapshotBundle()
                    }

                    IntentTypeV1.ASK_WHAT_CHANGED_RECENTLY -> {
                        factBundles += changelogRecentBundle()
                    }

                    IntentTypeV1.ASK_OCR_CONFIDENCE_CELL,
                    IntentTypeV1.ASK_CELL_TRUST_DETAILS -> {
                        if (idx == null) {
                            enqueueClarification(
                                q,
                                listOf("cell"),
                                "Which cell do you mean?",
                                ClarifyKind.POSITION
                            )
                        } else {
                            factBundles += FactBundleV1(
                                type = FactBundleV1.Type.OCR_CONFIDENCE_CELL,
                                payload = JSONObject().apply {
                                    val cell = indexToCell(idx)
                                    put("cell_ref", cellRefV1(cell))
                                    put("cell", cell)
                                    put("is_low_confidence", llm.lowConfidenceCells.contains(idx))
                                    put(
                                        "note",
                                        "Digit probability vectors are not available in this build; only low-confidence flag is available."
                                    )
                                }
                            )
                        }
                    }

                    // (Removed) duplicate ASK_OCR_CONFIDENCE_CELL branch.
                    // OCR confidence cell handling is covered by the earlier ASK_OCR_CONFIDENCE_CELL / ASK_CELL_TRUST_DETAILS case.

                    // ---- explanation / teaching (not fully supported in this build) ----
                    IntentTypeV1.REQUEST_EXPLANATION -> {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "explanation_requires_proof_bundle")
                                put(
                                    "note",
                                    "This build does not attach MOVE_JUSTIFICATION_GRAPH automatically. Ask for a next move/hint first, then I can explain based on the provided proof bundles."
                                )
                            }
                        )
                    }

                    IntentTypeV1.REQUEST_EXPLANATION -> {
                        // We can still provide a truthful limitation when a proof / move recommendation is missing.
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "hint_requires_move_recommendation")
                                put(
                                    "note",
                                    "To give a minimal hint safely, I need a move recommendation bundle for this turn."
                                )
                            }
                        )
                    }

                    IntentTypeV1.REQUEST_REASONING_CHECK -> {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.LIMITATIONS,
                            payload = JSONObject().apply {
                                put("reason", "reasoning_check_requires_user_reasoning_bundle")
                                put(
                                    "note",
                                    "To check your reasoning, I need your proposed step (cell + digit/candidate) or the app’s reasoning-check bundle."
                                )
                            }
                        )
                    }

// ---- UI help / coordinates help ----
                    IntentTypeV1.ASK_UI_LEGEND,
                    IntentTypeV1.ASK_UI_HELP -> {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = JSONObject().apply {
                                put("kind", "ui_help")
                                put("topic", "legend")
                                put(
                                    "note",
                                    "Explain the app UI legend / statuses using player-friendly terms."
                                )
                            }
                        )
                    }

                    IntentTypeV1.ASK_HOW_TO_LOCATE_CELL,
                    IntentTypeV1.ASK_COORDINATES_HELP -> {
                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = JSONObject().apply {
                                put("kind", "ui_help")
                                put("topic", "locate_cell")
                                put(
                                    "note",
                                    "Explain how to locate a cell: row 1..9 top-to-bottom, column 1..9 left-to-right; boxes named top-left..bottom-right."
                                )
                            }
                        )
                    }

                    else -> {
                        // leave unsupported question intents for evidence guard to flag deterministically
                    }
                }

                // ------------------------------------------------------------
// Patch 10 — Evidence Guard: enforce minimum required evidence
// ------------------------------------------------------------
                fun hasBundle(t: FactBundleV1.Type): Boolean = factBundles.any { it.type == t }
                fun requireAny(vararg ts: FactBundleV1.Type): Boolean = ts.any { hasBundle(it) }

                fun addMissingEvidenceLimitation(
                    questionIntent: IntentTypeV1,
                    required: List<String>
                ) {
                    factBundles += FactBundleV1(
                        type = FactBundleV1.Type.LIMITATIONS,
                        payload = JSONObject().apply {
                            put("reason", "missing_required_evidence")
                            put("question_intent", questionIntent.name)
                            put("required", JSONArray().apply { required.forEach { put(it) } })
                        }
                    )
                }

                for (q in qsToAnswer) {
                    when (q.type) {

                        IntentTypeV1.ASK_CELL_VALUE,
                        IntentTypeV1.ASK_CELL_STATUS,
                        IntentTypeV1.ASK_SOURCE_OF_DIGIT -> {
                            if (!hasBundle(FactBundleV1.Type.CELL_STATUS_BUNDLE)) {
                                addMissingEvidenceLimitation(q.type, listOf("CELL_STATUS_BUNDLE"))
                            }
                        }

                        IntentTypeV1.ASK_STRUCTURAL_VALIDITY,
                        IntentTypeV1.ASK_VALIDATION_OVERVIEW -> {
                            if (!hasBundle(FactBundleV1.Type.STRUCTURAL_VALIDITY)) {
                                addMissingEvidenceLimitation(q.type, listOf("STRUCTURAL_VALIDITY"))
                            }
                        }

                        IntentTypeV1.ASK_CONFLICTS_GLOBAL,
                        IntentTypeV1.ASK_CONFLICTS_OVERVIEW,
                        IntentTypeV1.ASK_CONFLICTS_IN_HOUSE,
                        IntentTypeV1.ASK_CONFLICT_DETAILS_CELL,
                        IntentTypeV1.ASK_DUPLICATES_IN_HOUSE -> {
                            // Current bundle is global-by-house; Tick2 can filter by the asked house if needed.
                            factBundles += duplicatesByHouseBundle()
                        }

                        // ---- retake guidance ----
                        IntentTypeV1.ASK_IF_RETAKE_NEEDED,
                        IntentTypeV1.ASK_RETAKE_GUIDANCE -> {
                            factBundles += retakeRecommendationBundle()
                            // A tiny status dashboard helps the assistant justify why a retake is suggested.
                            factBundles += summaryDashboardBundle(detailLevel = "normal")
                        }

                        IntentTypeV1.ASK_MISMATCH_OVERVIEW -> {
                            if (!requireAny(
                                    FactBundleV1.Type.MISMATCH_SET,
                                    FactBundleV1.Type.MISMATCH_EXPLANATION
                                )
                            ) {
                                addMissingEvidenceLimitation(
                                    q.type,
                                    listOf("MISMATCH_SET or MISMATCH_EXPLANATION")
                                )
                            }
                        }

                        IntentTypeV1.ASK_HOUSES_COMPLETION_RANKING -> {
                            if (!hasBundle(FactBundleV1.Type.HOUSES_COMPLETION_RANKING)) {
                                addMissingEvidenceLimitation(
                                    q.type,
                                    listOf("HOUSES_COMPLETION_RANKING")
                                )
                            }
                        }

                        IntentTypeV1.ASK_CELL_CANDIDATES,
                        IntentTypeV1.ASK_CANDIDATES_CELL_OVERVIEW -> {
                            if (!hasBundle(FactBundleV1.Type.CANDIDATE_STATE_CELL)) {
                                addMissingEvidenceLimitation(q.type, listOf("CANDIDATE_STATE_CELL"))
                            }
                        }

                        IntentTypeV1.ASK_CELLS_WITH_N_CANDIDATES -> {
                            if (!requireAny(
                                    FactBundleV1.Type.CELLS_WITH_N_CANDS_SET,
                                    FactBundleV1.Type.BIVALUE_CELLS_SET
                                )
                            ) {
                                addMissingEvidenceLimitation(
                                    q.type,
                                    listOf("CELLS_WITH_N_CANDS_SET (and BIVALUE_CELLS_SET if n=2)")
                                )
                            }
                        }

                        IntentTypeV1.ASK_OCR_CONFIDENCE_SUMMARY,
                        IntentTypeV1.ASK_TRUST_OVERVIEW -> {
                            if (!hasBundle(FactBundleV1.Type.OCR_CONFIDENCE_SUMMARY)) {
                                addMissingEvidenceLimitation(
                                    q.type,
                                    listOf("OCR_CONFIDENCE_SUMMARY")
                                )
                            }
                        }

                        IntentTypeV1.ASK_OCR_CONFIDENCE_CELL,
                        IntentTypeV1.ASK_CELL_TRUST_DETAILS -> {
                            if (!hasBundle(FactBundleV1.Type.OCR_CONFIDENCE_CELL)) {
                                addMissingEvidenceLimitation(q.type, listOf("OCR_CONFIDENCE_CELL"))
                            }
                        }

                        IntentTypeV1.ASK_UNRESOLVED_CELLS,
                        IntentTypeV1.ASK_PROBLEM_CELLS_OVERVIEW -> {
                            if (!hasBundle(FactBundleV1.Type.UNRESOLVED_SET)) {
                                addMissingEvidenceLimitation(q.type, listOf("UNRESOLVED_SET"))
                            }
                        }

                        IntentTypeV1.ASK_IF_RETAKE_NEEDED,
                        IntentTypeV1.ASK_RETAKE_GUIDANCE -> {
                            if (!hasBundle(FactBundleV1.Type.RETAKE_RECOMMENDATION)) {
                                addMissingEvidenceLimitation(
                                    q.type,
                                    listOf("RETAKE_RECOMMENDATION")
                                )
                            }
                        }

                        IntentTypeV1.ASK_SOLVING_OVERVIEW,
                        IntentTypeV1.ASK_PROGRESS_METRICS,
                        IntentTypeV1.ASK_IF_STUCK -> {
                            if (!hasBundle(FactBundleV1.Type.NEXT_MOVE_RECOMMENDATION)) {
                                addMissingEvidenceLimitation(
                                    q.type,
                                    listOf("NEXT_MOVE_RECOMMENDATION")
                                )
                            }
                            if (!hasBundle(FactBundleV1.Type.TECHNIQUE_FINDINGS)) {
                                factBundles += FactBundleV1(
                                    type = FactBundleV1.Type.LIMITATIONS,
                                    payload = JSONObject().apply {
                                        put("reason", "missing_technique_findings")
                                        put(
                                            "note",
                                            "A move recommendation should ideally include TECHNIQUE_FINDINGS for proof."
                                        )
                                    }
                                )
                            }
                        }

                        else -> {
                            // no-op
                        }
                    }
                }

                emitPrefsSnapshotIfNeeded()

                // If we scheduled any clarification to ask this turn, stop here (one question max).
                val askedThisTurn = userQ.firstOrNull()
                    .let { it is UserAgendaItem.Clarification && it.askedTurnSeq == s.turnSeq }
                if (askedThisTurn) {
                    emitTurnContractSnapshot(
                        tag = "return_pending_not_addressed",
                        opsPlannedCount = ops.size
                    )
                    return PlanV1(
                        ops = ops,
                        userAgendaQueue = userQ,
                        appAgendaQueue = appQ,
                        newPending = newPending,
                        newMode = newMode,
                        newPhase = newPhase,
                        newFocusIdx = newFocusIdx,

                        // Phase 5: persist active SOLVING agenda head
                        newActiveSolvingAgenda = newActiveSolvingAgenda,

                        newSolveAtomIndex = newSolveAtomIndex,
                        newSolveGuidanceMode = newSolveGuidanceMode,

                        newSolveSkipRemaining = newSolveSkipRemaining,
                        newSolveSkipTotal = newSolveSkipTotal,

                        newUserConfirmedPerfectMatch = userConfirmedPerfectMatchUpdate,
                        newPrefs = newPrefs,
                        factBundles = factBundles,
                        summary = "asked_user_agenda_clarification ops=${ops.size}"
                    )
                }

                emitPrefsSnapshotIfNeeded()

                // Pending remains “not a cage”: do not destroy app agenda; do not force new pending.
                emitTurnContractSnapshot(tag = "return_no_app_agenda", opsPlannedCount = ops.size)
                return PlanV1(
                    ops = ops,
                    userAgendaQueue = userQ,
                    appAgendaQueue = appQ,
                    newPending = newPending,
                    newMode = newMode,
                    newPhase = newPhase,
                    newFocusIdx = newFocusIdx,

                    // Phase 5: persist active SOLVING agenda head
                    newActiveSolvingAgenda = newActiveSolvingAgenda,

                    newSolveAtomIndex = newSolveAtomIndex,
                    newSolveGuidanceMode = newSolveGuidanceMode,

                    newSolveSkipRemaining = newSolveSkipRemaining,
                    newSolveSkipTotal = newSolveSkipTotal,

                    newUserConfirmedPerfectMatch = userConfirmedPerfectMatchUpdate,
                    newPrefs = newPrefs,
                    factBundles = factBundles,
                    summary = buildString {
                        append("answered_questions=")
                        append(qsToAnswer.joinToString(",") { it.type.name })
                        append(" ops=")
                        append(ops.size)
                        if (deferredQuestions.isNotEmpty()) {
                            append(" deferred=")
                            append(deferredQuestions.joinToString(",") { it.type.name })
                        }
                    }
                )
            }


            // ------------------------------------------------------------
// 3.5) Consume app agenda items that were addressed by planned ops.
// - App agenda items do NOT expire.
// - They are consumed when addressed (confirm/edit).
// ------------------------------------------------------------
            if (ops.isNotEmpty()) {
                val touched = ops.mapNotNull { op ->
                    when (op) {
                        is PlannedOpV1.ApplyCellEdit -> op.cellIndex
                        is PlannedOpV1.ConfirmCellValue -> op.cellIndex
                        else -> null
                    }
                }.toSet()

                if (touched.isNotEmpty()) {
                    appQ = appQ.filterNot { item ->
                        when (item) {
                            is AppAgendaItem.ProposeEdit -> touched.contains(item.cellIndex)
                            is AppAgendaItem.AskConfirmCell -> touched.contains(item.cellIndex)
                            // retake and solve CTAs are consumed by their own yes/no & solve-loop flows
                            else -> false
                        }
                    }.toMutableList()
                }
            }


            // 4) Step 4 — App agenda drives when NOT blocked by an in-turn clarification,
//             and we do not already have a control CTA (pending).
//
// Invariant:
// - Exactly ONE CTA per assistant reply (represented as Pending).
// - Every assistant reply MUST end with a CTA.
// - Clarification asked THIS turn blocks and becomes the CTA.
// - Otherwise, proceed with the next App agenda CTA (even if userQ contains older items).
// ------------------------------------------------------------

            // Phase 2: retake fork decision (DecisionMemory). Once decided, never re-surface retake CTA.
            // NOTE: we may also commit a decision within this plan build; prefer that when available.
            val retakeDecisionForStep4: RetakeDecisionV1 =
                retakeDecisionUpdate ?: s.retakeDecision

            val missionActive =
                ((newMode ?: s.mode) == SudoMode.GRID_SESSION) && (s.grid != null)

            val userAgendaBlocking =
                userQ.firstOrNull()
                    .let { it is UserAgendaItem.Clarification && it.askedTurnSeq == s.turnSeq } ||
                        clarificationStillOwnsTurnV1(
                            q = userQ,
                            env = env,
                            newPending = newPending
                        ) ||
                        hasActiveClarificationInQueueV1(userQ)

            val needsCta = (newPending == null) && !userAgendaBlocking

            if (needsCta) {

                // Phase 2 (Gap 4): No-regression guard.
                // Once the retake fork is committed (KEEP_SCAN or RETAKE), never re-surface RetakeDecision for this grid.
                while ((appQ.firstOrNull() is AppAgendaItem.RetakeDecision ||
                            appQ.firstOrNull() is AppAgendaItem.ProposeRetake) &&
                    (retakeDecisionForStep4 != RetakeDecisionV1.UNDECIDED)
                ) {
                    appQ.removeAt(0)
                }

                // ✅ Compute nextApp AFTER repeat-guards mutate the queue.
                val nextApp = appQ.firstOrNull()


                // PATCH 5: Log which agenda item is being selected to drive the CTA.
                if (nextApp != null) {
                    ConversationTelemetry.emitAgendaSelected(
                        turnId = s.turnSeq,
                        tickId = 1,
                        agendaType = nextApp::class.java.simpleName,
                        agendaReason = (nextApp as? AppAgendaItem.RetakeDecision)?.reason
                            ?: (nextApp as? AppAgendaItem.MismatchReview)?.reason
                            ?: (nextApp as? AppAgendaItem.ConflictReview)?.reason
                            ?: (nextApp as? AppAgendaItem.VisualVerificationRequest)?.reason
                            ?: (nextApp as? AppAgendaItem.RecommendDifferentGrid)?.reason
                            ?: (nextApp as? AppAgendaItem.FinalizeValidationStartSolving)?.reason,
                        appQueueSize = appQ.size,
                        userQueueSize = userQ.size,
                        phase = (newPhase ?: s.phase).name
                    )
                }


                if (nextApp == null) {
                    // Phase 3.E: Ban idle CTA when mission is active.
                    // If we are in a grid mission but the app agenda is empty, use a mission-resume CTA
                    // (not “what would you like to do next?”).
                    newPending =
                        if (missionActive) {
                            Pending.AskClarification(
                                kind = ClarifyKind.WORKFLOW,
                                prompt = "Want to continue with the puzzle? You can say “retake” or “keep this scan”."
                            )
                        } else {
                            // True fallback (no route exists)
                            Pending.AskClarification(
                                kind = ClarifyKind.WORKFLOW,
                                prompt = "What would you like to do next?"
                            )
                        }
                } else {
                    when (nextApp) {

                        // PATCH 1: CONFIRMING agenda (TO-BE items)
                        is AppAgendaItem.RetakeDecision -> {
                            newPending = Pending.ConfirmRetake(
                                strength = nextApp.strength,
                                prompt = buildConfirmRetakePrompt(nextApp.strength)
                            )
                        }

                        is AppAgendaItem.MismatchReview -> {
                            newFocusIdx = nextApp.cellIndex
                            newPending = Pending.ConfirmEdit(
                                cellIndex = nextApp.cellIndex,
                                proposedDigit = nextApp.expectedDigit,
                                source = "app_agenda",
                                prompt =
                                    "I think ${indexToCell(nextApp.cellIndex)} should be ${nextApp.expectedDigit} " +
                                            "(it currently shows ${nextApp.scannedDigit}). Should I change it?"
                            )
                        }

                        is AppAgendaItem.ConflictReview -> {
                            newFocusIdx = nextApp.cellIndex
                            newPending = Pending.AskCellValue(
                                cellIndex = nextApp.cellIndex,
                                prompt = "What digit is at ${indexToCell(nextApp.cellIndex)}?"
                            )
                        }


                        is AppAgendaItem.ConfirmValidationExactMatch -> {
                            newPhase = GridPhase.SEALING
                            newPending = Pending.ConfirmValidate(
                                prompt = "The grid looks consistent, and I can solve it uniquely from what’s on screen. Before we begin, does the on-screen grid match your puzzle exactly?"
                            )
                        }

                        is AppAgendaItem.RecommendDifferentGrid -> {
                            newPending = Pending.WaitForTap(
                                prompt =
                                    "Please explain that the on-screen grid now appears to match the paper, but these givens still do not lead to one unique standard solution. Briefly justify why that usually means either an overlooked wrong/missing given or a source puzzle issue, then recommend capturing a different puzzle.",
                                digitHint = null,
                                confidence = 0.90f
                            )
                        }

                        is AppAgendaItem.FinalizeValidationStartSolving -> {
                            newPhase = GridPhase.SEALING

                            ops += PlannedOpV1.FinalizeValidationPresentation(
                                reason = nextApp.reason,
                                source = "agenda_finalize"
                            )

                            // Consume this agenda head so we don't re-run finalize every turn.
                            appQ.removeAt(0)

                            newPending = Pending.ConfirmStartSolving(
                                prompt = "Your grid is uniquely solvable now, and the screen has been finalized. Ready to start solving?"
                            )
                        }

                        is AppAgendaItem.VisualVerificationRequest -> {
                            newPending = Pending.VisualVerifyMatch(
                                prompt =
                                    "Please explain that I’m not seeing rule conflicts on screen, but the current givens still do not produce a single unique solution. Say that the most likely cause is one or more missing or misread givens from the scan, then ask the user to compare paper vs screen carefully and either confirm a perfect match or provide exact cell corrections."
                            )
                        }



                        is AppAgendaItem.Solving.StepIntro -> {
                            val hasSolvingPending =
                                (s.pending is Pending.SolveIntroAction) ||
                                        (s.pending is Pending.AfterResolution) ||
                                        (s.pending is Pending.ApplyHintNow) ||
                                        (s.pending is Pending.SolveStepMissing)

                            if (s.phase == GridPhase.SOLVING && hasSolvingPending) {
                                // Keep StepIntro as the true setup carrier.
                                // Setup must no longer be rewritten into AtomWalk(0),
                                // because AtomWalk is confrontation-native.
                            }
                        }

                        // ✅ IMPORTANT: any other SOLVING head should NOT create a new CTA here.
                        // It already represents the current waypoint; keep pending unchanged.
                        is AppAgendaItem.Solving -> {
                            // no-op
                        }

                        // Legacy items (still supported temporarily)
                        is AppAgendaItem.ProposeRetake -> {
                            newPending = Pending.ConfirmRetake(
                                strength = nextApp.strength,
                                prompt = buildConfirmRetakePrompt(nextApp.strength)
                            )
                        }

                        is AppAgendaItem.ProposeEdit -> {
                            newFocusIdx = nextApp.cellIndex
                            newPending = Pending.ConfirmEdit(
                                cellIndex = nextApp.cellIndex,
                                proposedDigit = nextApp.expectedDigit,
                                source = "app_agenda",
                                prompt =
                                    "I think ${indexToCell(nextApp.cellIndex)} should be ${nextApp.expectedDigit} " +
                                            "(it currently shows ${nextApp.scannedDigit}). Should I change it?"
                            )
                        }

                        is AppAgendaItem.AskConfirmCell -> {
                            newFocusIdx = nextApp.cellIndex
                            newPending = Pending.AskCellValue(
                                cellIndex = nextApp.cellIndex,
                                prompt = "What digit is at ${indexToCell(nextApp.cellIndex)}?"
                            )
                        }

                        else -> {
                            // Safety: do not crash if new agenda items are added later.
                        }
                    }
                }
            }


            // ------------------------------------------------------------
// 5) Free talk: Phase 5 detour mechanism (SOLVING-safe)
// Goal: user can chat freely without breaking the solving route.
// ------------------------------------------------------------


            val isFreeTalkTurn =
                (top?.type == IntentTypeV1.FREE_TALK) || (top == null && isFreeTalkOnly) || hasIntent(
                    IntentTypeV1.SMALL_TALK
                )

            if (isFreeTalkTurn) {

                val inSolving = ((newPhase ?: s.phase) == GridPhase.SOLVING)

                if (inSolving) {

                    // If we are already in a detour pending, don't re-push.
                    val alreadyDetouring = (newPending is Pending.ReturnToRoute) ||
                            (appQ.firstOrNull() is AppAgendaItem.Solving.DetourFreeTalk)

                    if (!alreadyDetouring) {

                        val resumePending = runCatching {
                            derivePendingProjectionV1(
                                s = s,
                                owner = TurnOwnerV1.APP_OWNER,
                                userAgendaQueue = emptyList(),
                                appAgendaQueue = appQ,
                                pendingCandidate = s.pending
                            )
                        }.getOrNull()

                        val route = runCatching {
                            val head = appQ.firstOrNull()
                            when (head) {
                                is AppAgendaItem.Solving -> head.route
                                else -> {
                                    val ar = s.activeRouteContext
                                    ActiveRouteContextV2(
                                        gridHash12 = (ar?.gridHash12 ?: (s.solveStepGridHash12
                                            ?: "")).take(12),
                                        stepId = ar?.stepId ?: s.solveStepId,
                                        stepHash12 = s.coachPlanSha12,
                                        techniqueId = ar?.techniqueId ?: s.coachPlan?.techniqueId,
                                        targetCell = null,
                                        createdAtMs = System.currentTimeMillis(),
                                        routeVersion = 1
                                    )
                                }
                            }
                        }.getOrElse {
                            ActiveRouteContextV2(
                                gridHash12 = (s.solveStepGridHash12 ?: "").take(12),
                                stepId = s.solveStepId,
                                stepHash12 = s.coachPlanSha12,
                                techniqueId = s.coachPlan?.techniqueId,
                                targetCell = null,
                                createdAtMs = System.currentTimeMillis(),
                                routeVersion = 1
                            )
                        }

                        // Push detour agenda head WITHOUT consuming the real solving head.
                        pushFront(
                            AppAgendaItem.Solving.DetourFreeTalk(
                                agendaId = "solving_detour_${s.turnSeq}_${System.currentTimeMillis()}",
                                createdAtMs = System.currentTimeMillis(),
                                createdTurnSeq = s.turnSeq,
                                stepIndex = 0,
                                route = route,
                                detourTopicHint = env.freeTalkTopic?.takeIf { it.isNotBlank() }
                            )
                        )

                        newPending = Pending.ReturnToRoute(
                            resumePending = resumePending,
                            prompt = "" // do not script; Tick2 will be friendly + end with “return” CTA
                        )

                        factBundles += FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = JSONObject().apply {
                                put("kind", "solving_detour_entered")
                                put(
                                    "note",
                                    "Free talk allowed without breaking solving. Resume state is preserved explicitly."
                                )
                                put(
                                    "resume_pending_type",
                                    resumePending?.javaClass?.simpleName ?: JSONObject.NULL
                                )
                            }
                        )
                    }

                } else {
                    // Non-solving free talk: preserve existing behavior (no spam)
                    if (s.mode == SudoMode.FREE_TALK) newMode = SudoMode.FREE_TALK
                }
            }

// We don't have sAfter here; use the planned "after" values we are computing in this method.
// "newPending" is the candidate post-plan pending. "userQ/appQ" are the post-plan queues.
            if (newPending == null) {
                val reason =
                    when {
                        appQ.isEmpty() && userQ.isEmpty() -> "NO_APP_AGENDA_AND_NO_USER_AGENDA"
                        appQ.isEmpty() -> "NO_APP_AGENDA"
                        userQ.isNotEmpty() -> "USER_AGENDA_PRESENT_BUT_NO_PENDING_SET"
                        else -> "NO_PENDING_SET_UNKNOWN"
                    }

                // We also don't have a standalone turnId param here; use s.turnSeq (this method has access to s).
                emitNoPendingReason(
                    tag = "planFromIntentEnvelopeV1",
                    turnId = s.turnSeq,
                    reason = reason,
                    extra = mapOf(
                        "app_agenda_n" to appQ.size,
                        "user_agenda_n" to userQ.size
                    )
                )
            }

            val topLabel =
                top?.type?.name ?: if (isFreeTalkOnly) "FREE_TALK_ONLY" else "NONE"

// PATCH 2.2: If we just resolved VisualVerifyMatch with YES, persist match flag.
            val resolvedVisualVerifyYes =
                (s.pending is Pending.VisualVerifyMatch) &&
                        (newPending == null) &&
                        env.intents.any { it.type == IntentTypeV1.CONFIRM_YES }

// ------------------------------------------------------------
// PATCH 5: Telemetry — agenda transition + ops planned + CTA selected
// ------------------------------------------------------------
            if (agendaConsumedCount > 0 || agendaPushedCount > 0) {
                ConversationTelemetry.emitAgendaTransition(
                    turnId = s.turnSeq,
                    tickId = 1,
                    consumedCount = agendaConsumedCount,
                    pushedCount = agendaPushedCount,
                    consumedTypes = agendaConsumedTypes.toList(),
                    pushedTypes = agendaPushedTypes.toList(),
                    appQueueSizeAfter = appQ.size
                )
            }

            if (ops.isNotEmpty()) {
                val opsSummary = ops.map { it::class.java.simpleName }
                ConversationTelemetry.emitOpsPlanned(
                    turnId = s.turnSeq,
                    tickId = 1,
                    ops = opsSummary
                )
            }

// CTA_SELECTED: log the final pending for Tick2 (if any)
            newPending?.let { p ->
                val pendingOptions: List<String> = when (p) {
                    is Pending.SolveIntroAction -> p.options
                    is Pending.AfterResolution -> p.options
                    is Pending.ApplyHintNow -> p.options
                    is Pending.ReturnToRoute -> p.options
                    else -> emptyList()
                }

                val primaryCtaId: String? = when (p) {
                    is Pending.SolveIntroAction -> PendingChoiceId.SHOW_PROOF
                    is Pending.ApplyHintNow -> PendingChoiceId.LOCK_IT_IN
                    is Pending.AfterResolution -> PendingChoiceId.NEXT_STEP
                    is Pending.ReturnToRoute -> PendingChoiceId.RETURN_TO_ROUTE
                    else -> null
                }

                val isNorthStarSingle: Boolean? = when (p) {
                    is Pending.SolveIntroAction,
                    is Pending.ApplyHintNow,
                    is Pending.AfterResolution -> (pendingOptions.size == 1 && pendingOptions.firstOrNull() == primaryCtaId)

                    is Pending.ReturnToRoute -> (pendingOptions.size == 1 && pendingOptions.firstOrNull() == PendingChoiceId.RETURN_TO_ROUTE)
                    else -> null
                }

                val (pendingType, ctaName, expected) = when (p) {
                    is Pending.ConfirmRetake -> Triple("confirm_retake", "confirm_retake", "YESNO")
                    is Pending.ConfirmEdit -> Triple("confirm_edit", "propose_edit", "YESNO")
                    is Pending.AskCellValue -> Triple(
                        "ask_cell_value",
                        "confirm_cell_value_rc",
                        "DIGIT"
                    )

                    is Pending.VisualVerifyMatch -> Triple(
                        "visual_verify_match",
                        "visual_verify_match",
                        "YESNO_OR_EDITS"
                    )

                    is Pending.ConfirmStartSolving -> Triple(
                        "confirm_start_solving",
                        "start_solving",
                        "YESNO"
                    )

                    is Pending.WaitForTap -> Triple("wait_for_tap", "switch_to_tap", "TAP")
                    is Pending.ConfirmValidate -> Triple(
                        "confirm_validate",
                        "confirm_validate",
                        "YESNO"
                    )

                    is Pending.AskClarification -> Triple(
                        "ask_clarification",
                        "ask_clarifying_question",
                        "FREE_TEXT"
                    )

                    // North Star solving pendings
                    is Pending.SolveIntroAction -> Triple(
                        "solve_intro_action",
                        "ask_solve_intro_action",
                        "STORY_CTA_SETUP_OR_PROOF"
                    )

                    is Pending.AfterResolution -> Triple(
                        "after_resolution",
                        "ask_next_step",
                        "STORY_CTA_RESOLUTION_READY"
                    )

                    is Pending.ApplyHintNow -> Triple(
                        "apply_hint_now",
                        "ask_user_to_apply_hint",
                        "STORY_CTA_RESOLUTION_READY"
                    )

                    is Pending.ReturnToRoute -> Triple(
                        "return_to_route",
                        "return_to_route",
                        "YESNO_OR_CONTINUE"
                    )

                    else -> Triple("other", "unknown", null)
                }

                ConversationTelemetry.emitCtaSelected(
                    turnId = s.turnSeq,
                    tickId = 1,
                    pendingType = pendingType,
                    ctaName = ctaName,
                    expectedAnswerKind = expected,
                    primaryCtaId = primaryCtaId,
                    options = pendingOptions,
                    isNorthStarSingle = isNorthStarSingle
                )
            }

            if (
                resolutionCommitOutcomeV1 == ResolutionCommitOutcomeV1.APP_AUTO_COMMIT &&
                newPending is Pending.ApplyHintNow
            ) {
                val route = s.activeRouteContext?.let {
                    ActiveRouteContextV2(
                        gridHash12 = it.gridHash12,
                        stepId = it.stepId,
                        techniqueId = it.techniqueId,
                        targetCell = it.targetCellIndex?.let { targetIdx ->
                            "r${(targetIdx / 9) + 1}c${(targetIdx % 9) + 1}"
                        }
                    )
                } ?: ActiveRouteContextV2(
                    gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                )

                val stepIndex = s.solveStepSeq.toInt()

                newActiveSolvingAgenda = AppAgendaItem.Solving.PostCommitChoice(
                    agendaId = "sa:post_guard:${s.turnSeq}",
                    createdAtMs = System.currentTimeMillis(),
                    createdTurnSeq = s.turnSeq,
                    stepIndex = stepIndex,
                    route = route
                )

                newPending = Pending.AfterResolution(
                    stepId = s.solveStepId ?: "",
                    prompt = "",
                    gridHash12 = (s.solveStepGridHash12 ?: "").take(12)
                )

                factBundles += FactBundleV1(
                    type = FactBundleV1.Type.OTHER,
                    payload = org.json.JSONObject().apply {
                        put("kind", "solve_resolution_auto_commit_guard_normalized")
                        put("reason", "app_auto_commit_cannot_leave_apply_hint_now")
                        put("resolution_commit_outcome_v1", resolutionCommitOutcomeV1.name)
                    }
                )
            }

            if (
                resolutionCommitOutcomeV1 == ResolutionCommitOutcomeV1.NONE &&
                newPending is Pending.ApplyHintNow
            ) {
                resolutionCommitOutcomeV1 = ResolutionCommitOutcomeV1.MANUAL_APPLY_REQUIRED
            }

            emitTurnContractSnapshot(tag = "return_default", opsPlannedCount = ops.size)
            return PlanV1(
                ops = ops,
                userAgendaQueue = userQ,
                appAgendaQueue = appQ,
                newPending = newPending,
                newMode = newMode,
                newPhase = newPhase,
                newFocusIdx = newFocusIdx,
                freezeAppRouteForUserTurn = freezeAppRouteForUserTurn,

                // Phase 5: persist active SOLVING agenda head
                newActiveSolvingAgenda = newActiveSolvingAgenda,

                newNarrativeStory = newNarrativeStory,

                newSolveAtomIndex = newSolveAtomIndex,
                newSolveGuidanceMode = newSolveGuidanceMode,

                newSolveSkipRemaining = newSolveSkipRemaining,
                newSolveSkipTotal = newSolveSkipTotal,

                boundaryReturnAcceptedV1 = boundaryReturnAcceptedV1,
                boundaryResumePolicyV1 = boundaryResumePolicyV1,
                boundaryResumeCheckpointStepIdV1 = boundaryResumeCheckpointStepIdV1,
                boundaryTruthChangedOnReturnV1 = boundaryTruthChangedOnReturnV1,

                resolutionCommitOutcomeV1 = resolutionCommitOutcomeV1,
                resolutionCommitCellIndexV1 = resolutionCommitCellIndexV1,
                resolutionCommitDigitV1 = resolutionCommitDigitV1,
                delayedAutoCommitEchoSuppressedV1 = delayedAutoCommitEchoSuppressedV1,

                newUserConfirmedPerfectMatch = if (resolvedVisualVerifyYes) true else null,

                // Phase 2 (Gap 4/5): DecisionMemory — persist explicit fork decision; never treat generic speech as a decision.
                newRetakeDecision = retakeDecisionUpdate,

                // Legacy latch kept temporarily (derived from decision when decided).
                newRetakeDismissed =
                    when (retakeDecisionUpdate) {
                        RetakeDecisionV1.KEEP_SCAN -> true
                        RetakeDecisionV1.RETAKE -> false
                        else -> null
                    },

                // Patch 8: persisted user preferences
                newPrefs = if (prefsChanged) (newPrefs ?: s.prefs) else null,
                factBundles = factBundles,
                summary = "plan_from_intent_envelope_v1"
            )
        }



        val fallbackNeedsFinalize =
            (appQ.firstOrNull() is AppAgendaItem.FinalizeValidationStartSolving) &&
                    ops.none { it is PlannedOpV1.FinalizeValidationPresentation }

        var fallbackUserConfirmedPerfectMatch: Boolean? = null

        if (fallbackNeedsFinalize) {
            val finalizeHead = appQ.removeAt(0) as AppAgendaItem.FinalizeValidationStartSolving

            ops += PlannedOpV1.FinalizeValidationPresentation(
                reason = finalizeHead.reason,
                source = "fallback_finalize_guard"
            )

            newPhase = GridPhase.SEALING
            newPending = Pending.ConfirmStartSolving(
                prompt = "Your grid is uniquely solvable now, and the screen has been finalized. Ready to start solving?"
            )
            fallbackUserConfirmedPerfectMatch = true
        }

        emitTurnContractSnapshot(tag = "return_fallback", opsPlannedCount = ops.size)
        return PlanV1(
            ops = ops,
            userAgendaQueue = userQ,
            appAgendaQueue = appQ,
            newPending = newPending,
            newMode = newMode,
            newPhase = newPhase,
            newFocusIdx = newFocusIdx,

            newActiveSolvingAgenda = newActiveSolvingAgenda,
            newNarrativeStory = newNarrativeStory,

            newSolveAtomIndex = newSolveAtomIndex,
            newSolveGuidanceMode = newSolveGuidanceMode,

            newSolveSkipRemaining = newSolveSkipRemaining,
            newSolveSkipTotal = newSolveSkipTotal,

            boundaryReturnAcceptedV1 = boundaryReturnAcceptedV1,
            boundaryResumePolicyV1 = boundaryResumePolicyV1,
            boundaryResumeCheckpointStepIdV1 = boundaryResumeCheckpointStepIdV1,
            boundaryTruthChangedOnReturnV1 = boundaryTruthChangedOnReturnV1,

            resolutionCommitOutcomeV1 = resolutionCommitOutcomeV1,
            resolutionCommitCellIndexV1 = resolutionCommitCellIndexV1,
            resolutionCommitDigitV1 = resolutionCommitDigitV1,
            delayedAutoCommitEchoSuppressedV1 = delayedAutoCommitEchoSuppressedV1,

            newUserConfirmedPerfectMatch =
                fallbackUserConfirmedPerfectMatch ?:
                if (
                    (s.pending is Pending.VisualVerifyMatch) &&
                    (newPending == null) &&
                    env.intents.any { it.type == IntentTypeV1.CONFIRM_YES }
                ) true else null,





            newRetakeDecision = retakeDecisionUpdate,

            newRetakeDismissed =
                when (retakeDecisionUpdate) {
                    RetakeDecisionV1.KEEP_SCAN -> true
                    RetakeDecisionV1.RETAKE -> false
                    else -> null
                },

            newPrefs = if (prefsChanged) (newPrefs ?: s.prefs) else null,
            factBundles = factBundles,
            summary = "plan_from_intent_envelope_v1_fallback"
        )


    }


    private fun replaceQueuedSolvingHead(
        queue: List<AppAgendaItem>,
        newHead: AppAgendaItem.Solving?
    ): List<AppAgendaItem> {
        if (newHead == null) return queue

        val head = queue.firstOrNull()
        return when (head) {
            null -> listOf(newHead)
            is AppAgendaItem.Solving -> queue.toMutableList().apply { this[0] = newHead }
            else -> listOf(newHead) + queue
        }
    }


    private fun checkpointCanonicalPositionV1(
        checkpoint: RouteCheckpointV1?
    ): CanonicalSolvingStepPositionV1? {
        checkpoint ?: return null

        val resolvedKind =
            checkpoint.canonicalPositionKind
                ?: when (checkpoint.storyStage) {
                    StoryStage.SETUP -> CanonicalSolvingPositionKindV1.SETUP
                    StoryStage.CONFRONTATION -> CanonicalSolvingPositionKindV1.CONFRONTATION
                    StoryStage.RESOLUTION ->
                        when {
                            checkpoint.canonicalPendingKind == CanonicalSolvingPendingKindV1.AFTER_RESOLUTION ||
                                    checkpoint.appAgendaKind == "PostCommitChoice" ->
                                CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT

                            else ->
                                CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT
                        }

                    null -> null
                }
                ?: return null

        val resolvedStage =
            when (resolvedKind) {
                CanonicalSolvingPositionKindV1.SETUP -> StoryStage.SETUP
                CanonicalSolvingPositionKindV1.CONFRONTATION -> StoryStage.CONFRONTATION
                CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT,
                CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> StoryStage.RESOLUTION
            }

        val resolvedHeadKind =
            checkpoint.canonicalHeadKind
                ?: when (checkpoint.appAgendaKind) {
                    "StepIntro" -> CanonicalSolvingHeadKindV1.STEP_INTRO
                    "AtomWalk" -> CanonicalSolvingHeadKindV1.ATOM_WALK
                    "CommitDecision" -> CanonicalSolvingHeadKindV1.COMMIT_DECISION
                    "CommitApply" -> CanonicalSolvingHeadKindV1.COMMIT_APPLY
                    "PostCommitChoice" -> CanonicalSolvingHeadKindV1.POST_COMMIT_CHOICE
                    else -> CanonicalSolvingHeadKindV1.NONE
                }

        return CanonicalSolvingStepPositionV1(
            kind = resolvedKind,
            stepId = checkpoint.stepId,
            gridHash12 = checkpoint.gridHash12,
            stage = resolvedStage,
            headKind = resolvedHeadKind,
            pendingKind = checkpoint.canonicalPendingKind ?: CanonicalSolvingPendingKindV1.NONE,
            focusAtomIndex = checkpoint.focusAtomIndex,
            atomsCount = checkpoint.atomsCount,
            readyForCommit = checkpoint.readyForCommit
        )
    }

    private fun restoreQueuedSolvingHeadFromCheckpointV1(
        s: SudoState,
        queue: List<AppAgendaItem>,
        checkpoint: RouteCheckpointV1?
    ): List<AppAgendaItem> {
        val restoredCheckpoint = checkpoint ?: return queue
        if (restoredCheckpoint.phase != GridPhase.SOLVING) return queue

        val canonicalPosition =
            checkpointCanonicalPositionV1(restoredCheckpoint) ?: return queue

        val queuedRoute =
            queue.asSequence()
                .mapNotNull { it as? AppAgendaItem.Solving }
                .firstOrNull { it !is AppAgendaItem.Solving.DetourFreeTalk }
                ?.route

        val route =
            queuedRoute ?: ActiveRouteContextV2(
                gridHash12 = (canonicalPosition.gridHash12 ?: restoredCheckpoint.gridHash12 ?: s.solveStepGridHash12 ?: "").take(12),
                stepId = canonicalPosition.stepId ?: s.solveStepId,
                stepHash12 = s.coachPlanSha12,
                techniqueId = restoredCheckpoint.techniqueId ?: s.coachPlan?.techniqueId,
                targetCell = null,
                createdAtMs = System.currentTimeMillis(),
                routeVersion = restoredCheckpoint.routeVersion
            )

        val currentHead = queue.firstOrNull() as? AppAgendaItem.Solving
        val restoredStepIndex = currentHead?.stepIndex ?: 0
        val restoredAtomsCount =
            (canonicalPosition.atomsCount ?: s.narrativeStory?.atomsCount ?: 1).coerceAtLeast(1)
        val restoredAtomIndex =
            canonicalPosition.focusAtomIndex ?: if (canonicalPosition.kind == CanonicalSolvingPositionKindV1.SETUP) 0 else 1

        val restoredHead: AppAgendaItem.Solving =
            when (canonicalPosition.kind) {
                CanonicalSolvingPositionKindV1.SETUP ->
                    AppAgendaItem.Solving.StepIntro(
                        agendaId = "restore:intro:${s.turnSeq}",
                        createdAtMs = System.currentTimeMillis(),
                        createdTurnSeq = s.turnSeq,
                        stepIndex = restoredStepIndex,
                        route = route,
                        techniqueId = restoredCheckpoint.techniqueId ?: route.techniqueId,
                        techniqueName = null,
                        mission = null,
                        allowAskTechnique = true,
                        allowDetour = true,
                        allowWalkback = true
                    )

                CanonicalSolvingPositionKindV1.CONFRONTATION ->
                    AppAgendaItem.Solving.AtomWalk(
                        agendaId = "restore:atomwalk:${s.turnSeq}:$restoredAtomIndex",
                        createdAtMs = System.currentTimeMillis(),
                        createdTurnSeq = s.turnSeq,
                        stepIndex = restoredStepIndex,
                        route = route,
                        atomIndex = restoredAtomIndex,
                        atomCount = restoredAtomsCount,
                        pacing = AppAgendaItem.Solving.AtomWalk.AtomPacing.ONE_ATOM_PER_TURN,
                        allowDetour = true,
                        allowWalkback = true
                    )

                CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT ->
                    when {
                        canonicalPosition.headKind == CanonicalSolvingHeadKindV1.COMMIT_APPLY ||
                                restoredCheckpoint.appAgendaKind == "CommitApply" ->
                            AppAgendaItem.Solving.CommitApply(
                                agendaId = "restore:apply:${s.turnSeq}",
                                createdAtMs = System.currentTimeMillis(),
                                createdTurnSeq = s.turnSeq,
                                stepIndex = restoredStepIndex,
                                route = route,
                                commitReason = "restore_from_checkpoint"
                            )

                        else ->
                            AppAgendaItem.Solving.CommitDecision(
                                agendaId = "restore:commit:${s.turnSeq}",
                                createdAtMs = System.currentTimeMillis(),
                                createdTurnSeq = s.turnSeq,
                                stepIndex = restoredStepIndex,
                                route = route,
                                commitAtomIndex = restoredAtomIndex,
                                opsCount = 1,
                                allowTrySelf = true,
                                allowExplainMore = true
                            )
                    }

                CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT ->
                    AppAgendaItem.Solving.PostCommitChoice(
                        agendaId = "restore:post:${s.turnSeq}",
                        createdAtMs = System.currentTimeMillis(),
                        createdTurnSeq = s.turnSeq,
                        stepIndex = restoredStepIndex,
                        route = route,
                        allowTeachTechnique = true,
                        allowDetour = true
                    )
            }

        return replaceQueuedSolvingHead(
            queue = queue,
            newHead = restoredHead
        )
    }

    private fun restorePendingFromCheckpointV1(
        s: SudoState,
        queue: List<AppAgendaItem>,
        checkpoint: RouteCheckpointV1?,
        preferred: Pending? = null
    ): Pending? {
        val canonicalPosition = checkpointCanonicalPositionV1(checkpoint)

        val seededState =
            if (canonicalPosition != null) {
                s.copy(
                    appAgendaQueue = queue,
                    canonicalSolvingPositionV1 = canonicalPosition
                )
            } else {
                s.copy(appAgendaQueue = queue)
            }

        return projectPendingFromQueueHead(
            s = seededState,
            queue = queue,
            story = seededState.narrativeStory,
            preferred = preferred
        )
    }


    private fun buildFreshSolveStepAgendaQueue(
        turnSeq: Long,
        inHash12: String,
        stepId: String,
        coachPlanSha12Ready: String,
        techniqueId: String?,
        atomsCount: Int
    ): List<AppAgendaItem> {
        val now = System.currentTimeMillis()

        return listOf(
            AppAgendaItem.Solving.StepIntro(
                agendaId = "solving_step_intro_${turnSeq}_${now}",
                createdAtMs = now,
                createdTurnSeq = turnSeq,
                stepIndex = 0,
                route = ActiveRouteContextV2(
                    gridHash12 = inHash12.take(12),
                    stepId = stepId,
                    stepHash12 = coachPlanSha12Ready,
                    techniqueId = techniqueId,
                    targetCell = null,
                    createdAtMs = now,
                    routeVersion = 1
                ),
                techniqueId = techniqueId,
                techniqueName = null,
                mission = null,
                allowAskTechnique = true,
                allowDetour = true,
                allowWalkback = true
            )
        )
    }



    private fun projectPendingFromQueueHead(
        s: SudoState,
        queue: List<AppAgendaItem>,
        story: NarrativeStoryContext?,
        preferred: Pending?
    ): Pending? {

        when (preferred) {
            is Pending.UserAgendaBridge,
            is Pending.ReturnToRoute,
            is Pending.AskClarification,
            is Pending.SolveStepMissing -> return preferred
            else -> { /* keep going */ }
        }

        val head = queue.firstOrNull() as? AppAgendaItem.Solving ?: return preferred

        fun solveIntroPendingFor(
            atomIndex: Int,
            atomsCountRaw: Int,
            stageOverride: StoryStage? = null,
            stepIdOverride: String? = null,
            gridHash12Override: String? = null
        ): Pending.SolveIntroAction {
            val atomsCount = atomsCountRaw.coerceAtLeast(1)
            val stage =
                stageOverride ?: StoryStage.CONFRONTATION

            val cta = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                .forStoryStage(stage)

            val proofIndices = proofAtomIndicesForStoryV1(atomsCount)
            val lastProofAtomIndex = proofIndices.lastOrNull() ?: 0

            val stepId = stepIdOverride ?: story?.stepId ?: (s.solveStepId ?: "")
            val gridHash12 = (gridHash12Override ?: story?.gridHash12 ?: s.solveStepGridHash12 ?: "").take(12)

            return when (stage) {
                StoryStage.SETUP ->
                    Pending.SolveIntroAction.SetupAction(
                        stepId = stepId,
                        atomIndex = atomIndex.coerceAtLeast(0),
                        atomsCount = atomsCount,
                        isLastHint = proofIndices.isEmpty() || atomIndex >= lastProofAtomIndex,
                        prompt = cta.prompt,
                        gridHash12 = gridHash12,
                        options = cta.options
                    )

                StoryStage.CONFRONTATION ->
                    Pending.SolveIntroAction.ConfrontationAction(
                        stepId = stepId,
                        atomIndex = atomIndex.coerceAtLeast(0),
                        atomsCount = atomsCount,
                        isLastHint = proofIndices.isEmpty() || atomIndex >= lastProofAtomIndex,
                        prompt = cta.prompt,
                        gridHash12 = gridHash12,
                        options = cta.options
                    )

                StoryStage.RESOLUTION ->
                    Pending.SolveIntroAction.ConfrontationAction(
                        stepId = stepId,
                        atomIndex = atomIndex.coerceAtLeast(0),
                        atomsCount = atomsCount,
                        isLastHint = proofIndices.isEmpty() || atomIndex >= lastProofAtomIndex,
                        prompt = cta.prompt,
                        gridHash12 = gridHash12,
                        options = cta.options
                    )
            }
        }

        fun applyHintPending(
            stepIdOverride: String? = null,
            gridHash12Override: String? = null
        ): Pending.ApplyHintNow {
            val cta = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                .forStoryStage(StoryStage.RESOLUTION)

            return Pending.ApplyHintNow(
                stepId = stepIdOverride ?: story?.stepId ?: (s.solveStepId ?: ""),
                prompt = cta.prompt,
                gridHash12 = (gridHash12Override ?: story?.gridHash12 ?: s.solveStepGridHash12 ?: "").take(12),
                options = cta.options
            )
        }

        fun afterResolutionPending(
            stepIdOverride: String? = null,
            gridHash12Override: String? = null
        ): Pending.AfterResolution {
            val cta = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                .afterResolution()

            return Pending.AfterResolution(
                stepId = stepIdOverride ?: story?.stepId ?: (s.solveStepId ?: ""),
                prompt = cta.prompt,
                gridHash12 = (gridHash12Override ?: story?.gridHash12 ?: s.solveStepGridHash12 ?: "").take(12),
                options = cta.options
            )
        }

        fun pendingForCanonicalPosition(
            canonicalPosition: CanonicalSolvingStepPositionV1
        ): Pending {
            val canonicalStepId = canonicalPosition.stepId ?: story?.stepId ?: (s.solveStepId ?: "")
            val canonicalGridHash12 =
                (canonicalPosition.gridHash12 ?: story?.gridHash12 ?: s.solveStepGridHash12 ?: "").take(12)
            val canonicalAtomsCount = (canonicalPosition.atomsCount ?: story?.atomsCount ?: 1).coerceAtLeast(1)

            return when (canonicalPosition.kind) {
                CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT -> {
                    when (preferred) {
                        is Pending.AfterResolution ->
                            preferred.copy(
                                stepId = if (preferred.stepId.isBlank()) canonicalStepId else preferred.stepId,
                                prompt = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .afterResolution()
                                    .prompt,
                                gridHash12 = if (preferred.gridHash12.isBlank()) canonicalGridHash12 else preferred.gridHash12,
                                options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .afterResolution()
                                    .options
                            )

                        else -> afterResolutionPending(
                            stepIdOverride = canonicalStepId,
                            gridHash12Override = canonicalGridHash12
                        )
                    }
                }

                CanonicalSolvingPositionKindV1.RESOLUTION_COMMIT -> {
                    when (preferred) {
                        is Pending.ApplyHintNow ->
                            preferred.copy(
                                stepId = if (preferred.stepId.isBlank()) canonicalStepId else preferred.stepId,
                                prompt = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.RESOLUTION)
                                    .prompt,
                                gridHash12 = if (preferred.gridHash12.isBlank()) canonicalGridHash12 else preferred.gridHash12,
                                options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.RESOLUTION)
                                    .options
                            )

                        else -> applyHintPending(
                            stepIdOverride = canonicalStepId,
                            gridHash12Override = canonicalGridHash12
                        )
                    }
                }

                CanonicalSolvingPositionKindV1.CONFRONTATION -> {
                    when (preferred) {
                        is Pending.SolveIntroAction.ConfrontationAction ->
                            preferred.copy(
                                stepId = if (preferred.stepId.isBlank()) canonicalStepId else preferred.stepId,
                                atomIndex = canonicalPosition.focusAtomIndex ?: preferred.atomIndex,
                                atomsCount = canonicalAtomsCount,
                                isLastHint = proofAtomIndicesForStoryV1(canonicalAtomsCount).lastOrNull()
                                    ?.let { idx -> (canonicalPosition.focusAtomIndex ?: preferred.atomIndex) >= idx }
                                    ?: true,
                                prompt = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.CONFRONTATION)
                                    .prompt,
                                gridHash12 = if (preferred.gridHash12.isBlank()) canonicalGridHash12 else preferred.gridHash12,
                                options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.CONFRONTATION)
                                    .options
                            )

                        is Pending.SolveIntroAction.SetupAction ->
                            Pending.SolveIntroAction.ConfrontationAction(
                                stepId = if (preferred.stepId.isBlank()) canonicalStepId else preferred.stepId,
                                atomIndex = canonicalPosition.focusAtomIndex ?: preferred.atomIndex,
                                atomsCount = canonicalAtomsCount,
                                isLastHint = proofAtomIndicesForStoryV1(canonicalAtomsCount).lastOrNull()
                                    ?.let { idx -> (canonicalPosition.focusAtomIndex ?: preferred.atomIndex) >= idx }
                                    ?: true,
                                prompt = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.CONFRONTATION)
                                    .prompt,
                                gridHash12 = if (preferred.gridHash12.isBlank()) canonicalGridHash12 else preferred.gridHash12,
                                options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.CONFRONTATION)
                                    .options
                            )

                        else -> solveIntroPendingFor(
                            atomIndex = canonicalPosition.focusAtomIndex ?: 1,
                            atomsCountRaw = canonicalAtomsCount,
                            stageOverride = StoryStage.CONFRONTATION,
                            stepIdOverride = canonicalStepId,
                            gridHash12Override = canonicalGridHash12
                        )
                    }
                }

                CanonicalSolvingPositionKindV1.SETUP -> {
                    when (preferred) {
                        is Pending.SolveIntroAction.SetupAction ->
                            preferred.copy(
                                stepId = if (preferred.stepId.isBlank()) canonicalStepId else preferred.stepId,
                                atomIndex = canonicalPosition.focusAtomIndex ?: 0,
                                atomsCount = canonicalAtomsCount,
                                isLastHint = proofAtomIndicesForStoryV1(canonicalAtomsCount).lastOrNull()
                                    ?.let { idx -> (canonicalPosition.focusAtomIndex ?: 0) >= idx }
                                    ?: true,
                                prompt = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.SETUP)
                                    .prompt,
                                gridHash12 = if (preferred.gridHash12.isBlank()) canonicalGridHash12 else preferred.gridHash12,
                                options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.SETUP)
                                    .options
                            )

                        is Pending.SolveIntroAction.ConfrontationAction ->
                            Pending.SolveIntroAction.SetupAction(
                                stepId = if (preferred.stepId.isBlank()) canonicalStepId else preferred.stepId,
                                atomIndex = canonicalPosition.focusAtomIndex ?: 0,
                                atomsCount = canonicalAtomsCount,
                                isLastHint = proofAtomIndicesForStoryV1(canonicalAtomsCount).lastOrNull()
                                    ?.let { idx -> (canonicalPosition.focusAtomIndex ?: 0) >= idx }
                                    ?: true,
                                prompt = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.SETUP)
                                    .prompt,
                                gridHash12 = if (preferred.gridHash12.isBlank()) canonicalGridHash12 else preferred.gridHash12,
                                options = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                                    .forStoryStage(StoryStage.SETUP)
                                    .options
                            )

                        else -> solveIntroPendingFor(
                            atomIndex = canonicalPosition.focusAtomIndex ?: 0,
                            atomsCountRaw = canonicalAtomsCount,
                            stageOverride = StoryStage.SETUP,
                            stepIdOverride = canonicalStepId,
                            gridHash12Override = canonicalGridHash12
                        )
                    }
                }
            }
        }

        val sProjectedBase = s.copy(
            appAgendaQueue = queue,
            narrativeStory = story ?: s.narrativeStory,
            pending = preferred ?: s.pending
        )

        val canonicalPosition = resolveCanonicalSolvingStepPositionV1(sProjectedBase)

        // Canonical position is authoritative.
        // Projection may fill metadata, but it must never cross a stage boundary
        // or recreate an earlier pending kind from a stale queue head.
        if (canonicalPosition != null) {
            return pendingForCanonicalPosition(canonicalPosition)
        }

        // No canonical solving position could be resolved.
        // Fall back to raw queue-head projection only in this case.
        return when (head) {
            is AppAgendaItem.Solving.StepIntro -> {
                solveIntroPendingFor(
                    atomIndex = 0,
                    atomsCountRaw = (story?.atomsCount ?: 1),
                    stageOverride = StoryStage.SETUP
                )
            }

            is AppAgendaItem.Solving.AtomWalk -> {
                solveIntroPendingFor(
                    atomIndex = head.atomIndex,
                    atomsCountRaw = (story?.atomsCount ?: head.atomCount),
                    stageOverride = if (head.atomIndex <= 0) StoryStage.SETUP else StoryStage.CONFRONTATION
                )
            }

            is AppAgendaItem.Solving.CommitDecision,
            is AppAgendaItem.Solving.CommitApply -> {
                applyHintPending()
            }

            is AppAgendaItem.Solving.PostCommitChoice -> {
                afterResolutionPending()
            }

            is AppAgendaItem.Solving.TechniqueTeach -> preferred
            is AppAgendaItem.Solving.DetourFreeTalk -> preferred
            is AppAgendaItem.Solving.Walkback -> preferred
            is AppAgendaItem.Solving.RecoveryRecomputeStep -> preferred
        }
    }




    private fun hasMultipleQueuedSolvingItems(queue: List<AppAgendaItem>): Boolean =
        queue.count { it is AppAgendaItem.Solving } > 1

    private fun emitSolvingInvariantViolations(
        before: SudoState,
        after: SudoState,
        reason: String
    ) {
        if (after.phase != GridPhase.SOLVING) return

        val queueHead = currentQueuedSolvingHead(after)
        val stepId = after.solveStepId
        val queueStepId = queueHead?.route?.stepId

        val beforePos = authoritativeCanonicalSolvingStepPositionV1(before)
        val afterPos = authoritativeCanonicalSolvingStepPositionV1(after)
        val afterStoredPos = after.canonicalSolvingPositionV1
        val afterComputedPos = computeCanonicalSolvingStepPositionV1(after)

        val violations = mutableListOf<String>()

        if (queueHead == null) {
            violations += "missing_queue_solving_head"
        }

        if (hasMultipleQueuedSolvingItems(after.appAgendaQueue)) {
            violations += "multiple_queued_solving_items"
        }

        if (queueHead != null && stepId != null && queueStepId != null && queueStepId != stepId) {
            violations += "queue_head_step_mismatch"
        }

        violations += storedCanonicalDriftViolationsV1(after)
        violations += validateCanonicalSolvingPositionV1(after, afterPos)

        val illegalBoundaryTransition =
            isIllegalCanonicalBoundaryTransitionV1(
                beforePos = beforePos,
                afterPos = afterPos,
                userText = "",
                allowRepeat = false
            )

        if (illegalBoundaryTransition) {
            violations += "illegal_canonical_boundary_transition"
        }

        if (
            afterPos?.kind == CanonicalSolvingPositionKindV1.SETUP &&
            after.pending is Pending.ApplyHintNow
        ) {
            violations += "setup_position_with_apply_hint_pending"
        }

        if (
            afterPos?.kind == CanonicalSolvingPositionKindV1.CONFRONTATION &&
            after.pending is Pending.AfterResolution
        ) {
            violations += "confrontation_position_with_after_resolution_pending"
        }

        if (
            afterPos?.kind == CanonicalSolvingPositionKindV1.RESOLUTION_POST_COMMIT &&
            currentQueuedSolvingHead(after) is AppAgendaItem.Solving.AtomWalk
        ) {
            violations += "post_commit_position_with_atom_walk_head"
        }

        if (violations.isNotEmpty()) {
            runCatching {
                val boundaryContext = buildBoundaryGuardContextV1(
                    sBeforePlan = before,
                    sAfterPlan = after,
                    userText = ""
                )

                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "SOLVING_INVARIANT_VIOLATION",
                    data = mapOf(
                        "turn_id" to after.turnSeq,
                        "reason" to reason,
                        "violations" to violations.distinct().joinToString(","),
                        "queue_head_before" to (currentQueuedSolvingHead(before)?.javaClass?.simpleName ?: "null"),
                        "queue_head_after" to (queueHead?.javaClass?.simpleName ?: "null"),
                        "pending_before" to (before.pending?.javaClass?.simpleName ?: "null"),
                        "pending_after" to (after.pending?.javaClass?.simpleName ?: "null"),
                        "story_stage_before" to (before.narrativeStory?.stage?.name ?: "null"),
                        "story_stage_after" to (after.narrativeStory?.stage?.name ?: "null"),
                        "active_turn_owner_after" to after.activeTurnOwnerV1.name,
                        "active_overlay_owner_after" to after.activeOverlayOwnerV1.name,
                        "solve_step_id_after" to (after.solveStepId ?: "null"),
                        "queue_step_id_after" to (queueStepId ?: "null"),
                        "canonical_before" to canonicalPositionSummaryV1(beforePos),
                        "canonical_after" to canonicalPositionSummaryV1(afterPos),
                        "stored_canonical_after" to canonicalPositionSummaryV1(afterStoredPos),
                        "computed_canonical_after" to canonicalPositionSummaryV1(afterComputedPos),
                        "app_queue_size_after" to after.appAgendaQueue.size,
                        "user_queue_size_after" to after.userAgendaQueue.size,
                        "guard_mode" to boundaryContext.mode.name,
                        "effective_before_source" to boundaryContext.beforeSource.name,
                        "same_step_guard_enabled" to boundaryContext.sameStepGuardEnabled,
                        "trust_source" to boundaryContext.trustSource,
                        "raw_before_summary" to canonicalPositionSummaryV1(boundaryContext.rawBeforePos),
                        "checkpoint_before_summary" to canonicalPositionSummaryV1(boundaryContext.checkpointBeforePos),
                        "restored_route_before_summary" to canonicalPositionSummaryV1(boundaryContext.restoredRouteBeforePos),
                        "effective_before_summary" to canonicalPositionSummaryV1(boundaryContext.effectiveBeforePos),
                        "effective_after_summary" to canonicalPositionSummaryV1(boundaryContext.afterPos)
                    )
                )
            }
        }
    }





    private fun applyPlannedStateV1(
        s: SudoState,
        plan: PlanV1,
        tDecisionStart: Long,
        tDecisionEnd: Long
    ): SudoState {

        val modeAfter = plan.newMode ?: s.mode
        val phaseAfter = plan.newPhase ?: s.phase
        val focusAfter = plan.newFocusIdx ?: s.focusCellIndex

        val atomIndexAfter = plan.newSolveAtomIndex ?: s.solveAtomIndex

        val skipRemainingAfter = plan.newSolveSkipRemaining ?: s.solveSkipRemaining
        val skipTotalAfter = plan.newSolveSkipTotal ?: s.solveSkipTotal
        val skipStartAfter = plan.newSolveSkipStartJourneyStep ?: s.solveSkipStartJourneyStep
        val skipEndAfter = plan.newSolveSkipEndJourneyStep ?: s.solveSkipEndJourneyStep

        // Phase 3/4/8: narrative story is a SOLVING-only structure.
        val narrativeAfter: NarrativeStoryContext? =
            when (phaseAfter) {
                GridPhase.CONFIRMING,
                GridPhase.SEALING -> null

                GridPhase.SOLVING ->
                    if (plan.freezeAppRouteForUserTurn) s.narrativeStory
                    else if (plan.newAdvanceToNextStep == true) null
                    else (plan.newNarrativeStory ?: s.narrativeStory)
            }

        // Phase 2/3/5/8: queue remains the sole owner of route identity across ALL phases.
        val appAgendaAfter: List<AppAgendaItem> =
            when (phaseAfter) {
                GridPhase.CONFIRMING,
                GridPhase.SEALING -> {
                    plan.appAgendaQueue.filterNot { it is AppAgendaItem.Solving }
                }

                GridPhase.SOLVING -> {
                    if (plan.freezeAppRouteForUserTurn) {
                        s.appAgendaQueue
                    } else if (plan.newAdvanceToNextStep == true) {
                        // Critical:
                        // when the app has authoritatively advanced past a completed step,
                        // persist the newly prepared solving head (normally StepIntro for the
                        // next step) instead of dropping all solving heads.
                        //
                        // Dropping the solving head here can leave downstream canonical
                        // interpretation clinging to the previous post-commit boundary,
                        // which reopens RESOLUTION speech instead of handing off to the
                        // next step.
                        replaceQueuedSolvingHead(
                            queue = plan.appAgendaQueue,
                            newHead = plan.newActiveSolvingAgenda
                        )
                    } else {
                        replaceQueuedSolvingHead(
                            queue = plan.appAgendaQueue,
                            newHead = plan.newActiveSolvingAgenda
                        )
                    }
                }
            }

        // Phase 4 / North Star:
        // pending projection is renderer-only whenever canonical solving position exists.
        // In that normal case, projection must materialize the already-decided canonical boundary
        // and must never re-decide boundary kind from queue-head shape or stale pending.
        // Raw queue-head projection is allowed only when no canonical solving position can be resolved.
        val pendingAfter: Pending? =
            if (phaseAfter != GridPhase.SOLVING) {
                plan.newPending
            } else if (plan.newAdvanceToNextStep == true) {
                null
            } else {
                projectPendingFromQueueHead(
                    s = s,
                    queue = appAgendaAfter,
                    story = narrativeAfter,
                    preferred = plan.newPending
                )
            }

        // Phase 2: sticky guidance mode resets when leaving SOLVING or moving to a fresh step
        val solveGuidanceAfter: SolveGuidanceModeV1 =
            if (phaseAfter != GridPhase.SOLVING) SolveGuidanceModeV1.UNSET
            else if (plan.newAdvanceToNextStep == true) SolveGuidanceModeV1.UNSET
            else (plan.newSolveGuidanceMode ?: s.solveGuidanceMode)

        // Phase 6: route context stays in sync with current solving rung
        val activeRouteAfter =
            if (phaseAfter == GridPhase.SOLVING) {
                if (plan.freezeAppRouteForUserTurn) {
                    s.activeRouteContext
                } else {
                    val solvingHeadAfter = appAgendaAfter.firstOrNull() as? AppAgendaItem.Solving

                val stepId =
                    authoritativeStepIdV1(
                        solvingHead = solvingHeadAfter,
                        story = narrativeAfter,
                        activeRoute = s.activeRouteContext,
                        solveStepId = s.solveStepId,
                        coachPlanStepId = s.coachPlanStepId
                    )

                val gridHash12 =
                    authoritativeGridHash12V1(
                        solvingHead = solvingHeadAfter,
                        story = narrativeAfter,
                        activeRoute = s.activeRouteContext,
                        solveStepGridHash12 = s.solveStepGridHash12,
                        coachPlanGridHash12 = s.coachPlanGridHash12
                    )

                val journey = runCatching {
                    val g = s.grid?.llm?.let { grid81FromLLM(it) } ?: ""
                    val filled = g.count { it in "123456789" }
                    (filled + 1).coerceAtMost(81)
                }.getOrElse { 0 }

                val atomsCountAfter =
                    narrativeAfter?.atomsCount
                        ?: when (solvingHeadAfter) {
                            is AppAgendaItem.Solving.AtomWalk -> solvingHeadAfter.atomCount
                            else -> s.solveAtomsCount
                        }

                    if (!stepId.isNullOrBlank() && !gridHash12.isNullOrBlank()) {
                        ActiveRouteContext(
                            stepId = stepId,
                            gridHash12 = gridHash12.take(12),
                            journeyStepNumber = journey,
                            atomIndex = atomIndexAfter,
                            atomsCount = atomsCountAfter.coerceAtLeast(1),
                            techniqueId = solvingHeadAfter?.route?.techniqueId ?: s.coachPlan?.techniqueId,
                            targetCellIndex = s.coachPlan?.targetCellIndex ?: s.activeRouteContext?.targetCellIndex
                        )
                    } else {
                        s.activeRouteContext
                    }
                }
            } else {
                null
            }

        val canonicalPosition =
            authoritativeCanonicalSolvingStepPositionV1(
                s.copy(
                    mode = modeAfter,
                    phase = phaseAfter,
                    focusCellIndex = focusAfter,
                    pending = pendingAfter,
                    appAgendaQueue = appAgendaAfter,
                    narrativeStory = narrativeAfter,
                    activeRouteContext = activeRouteAfter,
                    solveAtomIndex = atomIndexAfter,
                    solveGuidanceMode = solveGuidanceAfter,
                    solveSkipRemaining = skipRemainingAfter,
                    solveSkipTotal = skipTotalAfter,
                    solveSkipStartJourneyStep = skipStartAfter,
                    solveSkipEndJourneyStep = skipEndAfter
                )
            )

        val authorityDecisionAfter = TurnAuthorityArbiterV1.resolve(
            userAgendaQueue = plan.userAgendaQueue,
            appAgendaQueue = appAgendaAfter,
            canonicalPosition = canonicalPosition,
            pending = pendingAfter
        )
        val pendingAfterAuthority = reconcilePendingAfterAuthorityV1(
            pending = pendingAfter,
            authorityDecision = authorityDecisionAfter
        )
        val routeBoundaryDecisionAfter = RouteBoundaryControllerV1.resolve(
            authorityDecision = authorityDecisionAfter,
            canonicalPosition = canonicalPosition,
            pending = pendingAfterAuthority,
            userAgendaQueue = plan.userAgendaQueue
        )
        val ownerAfter = authorityDecisionAfter.owner.toLegacyTurnOwnerV1()

        val solvingRailAfter =
            if (phaseAfter == GridPhase.SOLVING) {
                deriveSolvingRailStateV1(
                    phase = phaseAfter,
                    solvingHead = appAgendaAfter.firstOrNull() as? AppAgendaItem.Solving,
                    pending = pendingAfterAuthority,
                    story = narrativeAfter,
                    activeRoute = activeRouteAfter,
                    solveStepId = s.solveStepId,
                    coachPlanStepId = s.coachPlanStepId,
                    solveStepGridHash12 = s.solveStepGridHash12,
                    coachPlanGridHash12 = s.coachPlanGridHash12,
                    pendingSolveStepAutocoach = s.pendingSolveStepAutocoach,
                    solveStepStatus = s.solveStepStatus,
                    activeTurnOwnerV1 = ownerAfter
                )
            } else {
                null
            }

        // Phase 2: persisted route checkpoint.
        // Keep it fresh while app route exists; preserve the last checkpoint across detours.
        val routeCheckpointBase: RouteCheckpointV1? =
            if (phaseAfter == GridPhase.SOLVING && plan.freezeAppRouteForUserTurn) {
                s.routeCheckpointV1
            } else if (appAgendaAfter.isNotEmpty() || activeRouteAfter != null || narrativeAfter != null) {
                deriveRouteCheckpointV1(
                    s = s,
                    phaseOverride = phaseAfter,
                    focusIdxOverride = focusAfter,
                    appQueueOverride = appAgendaAfter,
                    storyOverride = narrativeAfter,
                    activeRouteOverride = activeRouteAfter
                )
            } else {
                s.routeCheckpointV1
            }

        val routeCheckpointAfter: RouteCheckpointV1? =
            if (phaseAfter == GridPhase.SOLVING && plan.freezeAppRouteForUserTurn) {
                s.routeCheckpointV1
            } else {
                routeCheckpointBase?.copy(
                    overlayFrameIds = storyFramesV1(narrativeAfter).ifEmpty { routeCheckpointBase.overlayFrameIds }
                )
            }

        val pendingProjectedAfter = derivePendingProjectionV1(
            s = s,
            owner = ownerAfter,
            userAgendaQueue = plan.userAgendaQueue,
            appAgendaQueue = appAgendaAfter,
            pendingCandidate = pendingAfterAuthority
        )

        val (overlayOwnerAfter, overlayContractAfter) = resolveOverlayContractV1(
            s = s,
            owner = ownerAfter,
            userAgendaQueue = plan.userAgendaQueue,
            appAgendaQueue = appAgendaAfter,
            story = narrativeAfter,
            checkpoint = routeCheckpointAfter
        )

        val activeOverlayFramesAfter: List<String> = frameIdsFromOverlayContractV1(
            contract = overlayContractAfter,
            checkpoint = routeCheckpointAfter
        )

        // Phase 6 truth: rewrite cached SOLVING_STEP_PACKET_V1 overlays.applied_frame_ids
        // from the ACTIVE OWNER overlay contract, not just from story-stage inertia.
        fun appliedFramesForActiveOwner(): org.json.JSONArray {
            val out = org.json.JSONArray()
            activeOverlayFramesAfter.forEach { fid: String ->
                val t = fid.trim()
                if (t.isNotBlank()) out.put(t)
            }
            return out
        }

        val solvingBundlesAfter: List<FactBundleV1> =
            if (!s.solveOverlayVisible) {
                s.solvingReadyFactBundlesV1
            } else {
                val frames = appliedFramesForActiveOwner()
                s.solvingReadyFactBundlesV1.map { fb ->
                    if (fb.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1) {
                        val j = fb.payload
                        val overlays = j.optJSONObject("overlays") ?: org.json.JSONObject()
                        overlays.put("applied_frame_ids", frames)
                        j.put("overlays", overlays)
                        fb.copy(payload = j)
                    } else {
                        fb
                    }
                }
            }


        // -----------------------------
        // Single choke point: sync SessionStore Step-2 + DiscourseState
        // -----------------------------
        runCatching {
            val step2Phase =
                if (phaseAfter == GridPhase.SOLVING) SessionStore.Step2Phase.LOCKED
                else SessionStore.Step2Phase.CONFIRMING

            SessionStore.setStep2Phase(step2Phase)
            SessionStore.setMediationMode(step2Phase != SessionStore.Step2Phase.LOCKED)

            if (modeAfter != SudoMode.GRID_SESSION || pendingProjectedAfter == null) {
                SessionStore.clearPending()
            } else {
                when (pendingProjectedAfter) {
                    is Pending.AskCellValue -> {
                        SessionStore.setPending(
                            kind = SessionStore.PendingKind.CONFIRM_CELL,
                            cellIdx = pendingProjectedAfter.cellIndex,
                            digit = null
                        )
                    }

                    is Pending.ConfirmEdit -> {
                        SessionStore.setPending(
                            kind = SessionStore.PendingKind.CONFIRM_EDIT,
                            cellIdx = pendingProjectedAfter.cellIndex,
                            digit = pendingProjectedAfter.proposedDigit
                        )
                    }

                    is Pending.ConfirmRetake -> {
                        SessionStore.setPending(
                            kind = SessionStore.PendingKind.CONFIRM_RETAKE,
                            cellIdx = null,
                            digit = null
                        )
                    }

                    is Pending.ConfirmValidate -> {
                        SessionStore.setPending(
                            kind = SessionStore.PendingKind.CONFIRM_SIGNOFF,
                            cellIdx = null,
                            digit = null
                        )
                    }

                    is Pending.ConfirmStartSolving -> {
                        SessionStore.setPending(
                            kind = SessionStore.PendingKind.CONFIRM_SIGNOFF,
                            cellIdx = null,
                            digit = null
                        )
                    }

                    is Pending.UserAgendaBridge -> {
                        SessionStore.clearPending()
                    }

                    is Pending.SolveIntroAction -> {
                        SessionStore.clearPending()
                    }

                    is Pending.AfterResolution -> {
                        SessionStore.clearPending()
                    }

                    is Pending.SolveStepMissing -> {
                        SessionStore.clearPending()
                    }

                    is Pending.ApplyHintNow -> {
                        SessionStore.clearPending()
                    }

                    is Pending.ReturnToRoute -> {
                        SessionStore.clearPending()
                    }

                    else -> {
                        SessionStore.clearPending()
                    }
                }
            }
        }


        val sOutBase = s.copy(
            mode = modeAfter,
            phase = phaseAfter,
            focusCellIndex = focusAfter,
            pending = pendingProjectedAfter,
            activeTurnOwnerV1 = ownerAfter,
            activeTurnAuthorityDecisionV1 = authorityDecisionAfter,
            activeRouteBoundaryDecisionV1 = routeBoundaryDecisionAfter,
            activeOverlayOwnerV1 = overlayOwnerAfter,
            activeAppliedOverlayFrameIdsV1 = activeOverlayFramesAfter,
            activeOverlayReasonV1 = overlayContractAfter.reason,

            narrativeStory = narrativeAfter,
            userAgendaQueue = plan.userAgendaQueue,
            appAgendaQueue = appAgendaAfter,

            // PATCH 2.2: persist visual verification flag
            userConfirmedPerfectMatch = plan.newUserConfirmedPerfectMatch ?: s.userConfirmedPerfectMatch,

            // Phase 2 DecisionMemory: persist the fork decision, and derive legacy latch from it.
            retakeDecision = plan.newRetakeDecision ?: s.retakeDecision,
            retakeDismissed =
                when (plan.newRetakeDecision ?: s.retakeDecision) {
                    RetakeDecisionV1.KEEP_SCAN -> true
                    RetakeDecisionV1.RETAKE -> false
                    RetakeDecisionV1.UNDECIDED -> false
                },

            prefs = plan.newPrefs ?: s.prefs,

            // Phase 2: persist sticky guidance mode
            solveGuidanceMode = solveGuidanceAfter,

            // Persist rewritten solving bundles (truthful overlays.applied_frame_ids)
            solvingReadyFactBundlesV1 = solvingBundlesAfter,

            // SOLVING-only deterministic mutations
            solveAtomIndex = atomIndexAfter,

            // Route context stays in sync with hint rung
            activeRouteContext = activeRouteAfter,
            solvingRailStateV1 = solvingRailAfter,
            routeCheckpointV1 = routeCheckpointAfter,

            // Skip-ahead state + narration range
            solveSkipRemaining = skipRemainingAfter,
            solveSkipTotal = skipTotalAfter,
            solveSkipStartJourneyStep = skipStartAfter,
            solveSkipEndJourneyStep = skipEndAfter,

            lastDecisionStartMs = tDecisionStart,
            lastDecisionEndMs = tDecisionEnd
        )

        val sOut = syncCanonicalSolvingPositionV1(sOutBase)

        emitSolvingInvariantViolations(
            before = s,
            after = sOut,
            reason = "apply_planned_state_v1"
        )

        return sOut
    }

    private fun opToEffectV1(op: PlannedOpV1, turnId: Long): Eff {
        return when (op) {
            is PlannedOpV1.ApplyCellEdit -> Eff.ApplyCellEdit(
                toolCallId = "tc:v1:$turnId:edit:${op.cellIndex}",
                cellIndex = op.cellIndex,
                digit = op.digit,
                source = op.source
            )

            is PlannedOpV1.ConfirmCellValue -> Eff.ConfirmCellValue(
                toolCallId = "tc:v1:$turnId:confirm:${op.cellIndex}",
                cellIndex = op.cellIndex,
                digit = op.digit,
                source = op.source,
                changed = false
            )

            is PlannedOpV1.Undo -> Eff.Undo(
                toolCallId = "tc:v1:$turnId:undo",
                source = op.source
            )

            is PlannedOpV1.Redo -> Eff.Redo(
                toolCallId = "tc:v1:$turnId:redo",
                source = op.source
            )

            is PlannedOpV1.AddCandidate -> Eff.AddCandidate(
                toolCallId = "tc:v1:$turnId:cand_add:${op.cellIndex}:${op.digit}",
                cellIndex = op.cellIndex,
                digit = op.digit,
                source = op.source
            )

            is PlannedOpV1.RemoveCandidate -> Eff.RemoveCandidate(
                toolCallId = "tc:v1:$turnId:cand_rm:${op.cellIndex}:${op.digit}",
                cellIndex = op.cellIndex,
                digit = op.digit,
                source = op.source
            )

            is PlannedOpV1.SetCandidatesMask -> Eff.SetCandidates(
                toolCallId = "tc:v1:$turnId:cand_set:${op.cellIndex}",
                cellIndex = op.cellIndex,
                mask = op.mask,
                source = op.source
            )

            is PlannedOpV1.FinalizeValidationPresentation -> Eff.FinalizeValidationPresentation(
                toolCallId = "tc:v1:$turnId:finalize_validation",
                reason = op.reason
            )

            is PlannedOpV1.ComputeSolveStep -> Eff.ComputeSolveStep(
                grid81 = op.grid81,
                gridHash12 = op.gridHash12,
                reason = op.reason,
                force = op.force
            )
        }
    }



    private fun isRevealAlreadyAppliedOnBoardV1(s: SudoState): Boolean {
        val reveal = s.coachPlan?.reveal ?: return false
        val idx = reveal.placementCellIndex
        val digit = reveal.placementDigit

        if (idx !in 0..80 || digit !in 1..9) return false

        return runCatching {
            val llm0 = s.grid?.llm ?: return@runCatching false
            val g81 = grid81FromLLM(llm0)
            val ch = g81.getOrNull(idx) ?: return@runCatching false
            (ch in '1'..'9') && ((ch - '0') == digit)
        }.getOrDefault(false)
    }







