    private data class RepairInfo(val repairMode: Boolean, val repairReason: String?)

    private fun parseRepairInfo(stateHeader: String): RepairInfo {
        // We keep this for telemetry continuity; B stops producing repair headers locally.
        val repairMode = Regex("(?m)^repair_mode\\s*=\\s*true\\s*$").containsMatchIn(stateHeader)
        val repairReason = Regex("(?m)^repair_reason\\s*=\\s*([^\\n\\r]+)\\s*$")
            .find(stateHeader)
            ?.groupValues
            ?.getOrNull(1)
            ?.trim()
        return RepairInfo(repairMode = repairMode, repairReason = repairReason)
    }

    private fun headerValue(header: String, key: String): String? {
        val re = Regex("""(?im)^\s*${Regex.escape(key)}\s*=\s*([A-Z0-9_]+)\s*$""")
        return re.find(header)?.groupValues?.getOrNull(1)
    }


    private fun previewLocal(s: String, max: Int): String {
        val t = s.trim()
        return if (t.length <= max) t else t.substring(0, max)
    }

    private fun toolExecId(turnId: Long, tickId: Int, policyReqSeq: Long): String =
        "exec_${turnId}_${tickId}_${policyReqSeq}"
    

    private fun emitTick2FactsSummary(
        tag: String,
        sAfter: SudoState,
        turnId: Long,
        tickId: Int,
        policyReqSeq: Long,
        correlationId: String,
        modelCallId: String?,
        toolplanId: String?,
        openingTurn: Boolean,
        pendingBefore: String?,
        pendingAfter: String?,
        facts: List<FactBundleV1>
    ) {
        val types = facts.map { it.type.name }.distinct().sorted()
        val gridPresent = (sAfter.grid != null)
        val llmPresent = runCatching { llmGrid(sAfter) != null }.getOrElse { false }

        val hasStepPacketV1 = facts.any { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
        val hasRecoveryPacketV1 = facts.any { it.type == FactBundleV1.Type.RECOVERY_PACKET_V1 }

        val stepPacketV1 = facts.firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }?.payload
        val overlaysObj = stepPacketV1?.optJSONObject("overlays")
        val appliedFramesArr = overlaysObj?.optJSONArray("applied_frame_ids")
        val appliedFramesCount = appliedFramesArr?.length() ?: 0

        val spoilerObj = stepPacketV1?.optJSONObject("step")?.optJSONObject("spoiler")
        val digitHidden = spoilerObj?.optBoolean("digit_hidden", false) ?: false
        val revealAllowed = spoilerObj?.optBoolean("reveal_allowed", false) ?: false

        val resultObj = stepPacketV1?.optJSONObject("step")?.optJSONObject("result")
        val targetDigit = runCatching {
            if (resultObj == null) null
            else if (resultObj.isNull("digit")) null
            else resultObj.optInt("digit", -1).takeIf { it in 1..9 }
        }.getOrNull()

        ConversationTelemetry.emit(
            mapOf(
                "type" to "TICK2_FACTS_SUMMARY",
                "tag" to tag,
                "turn_id" to turnId,
                "tick_id" to tickId,
                "policy_req_seq" to policyReqSeq,
                "correlation_id" to correlationId,
                "model_call_id" to (modelCallId ?: ""),
                "toolplan_id" to (toolplanId ?: ""),
                "opening_turn" to openingTurn,

                "mode" to sAfter.mode.name,
                "phase" to sAfter.phase.name,
                // (Phase 7+) no legacy solveChoice
                "solve_atom_index" to sAfter.solveAtomIndex,
                "solve_atoms_count" to sAfter.solveAtomsCount,

                "pending_before" to (pendingBefore ?: ""),
                "pending_after" to (pendingAfter ?: ""),

                "facts_count" to facts.size,
                "fact_types" to types.joinToString(","),

                // Phase 7 invariants (auditable)
                "has_step_packet_v1" to hasStepPacketV1,
                "has_recovery_packet_v1" to hasRecoveryPacketV1,
                "overlay_applied_frames_count" to appliedFramesCount,
                "spoiler_digit_hidden" to digitHidden,
                "spoiler_reveal_allowed" to revealAllowed,
                "target_digit_if_available" to (targetDigit ?: -1),

                "grid_present_in_state" to gridPresent,
                "llm_snapshot_present" to llmPresent
            )
        )
    }

    // ============================================================
    // Phase 0 — Turn Contract Snapshot (single, audit-friendly)
    // ============================================================
    // ============================================================
    // Phase 0 — Turn Contract Snapshot (single, audit-friendly)
    // ============================================================
    private fun emitTurnContractSnapshot(
        stage: String,                 // "POST_TICK1" | "POST_DECISION" | "POST_APPLY"
        note: String,
        s: SudoState,
        ctx: PolicyCallCtx?,
        facts: List<FactBundleV1>?,
        tick2CallsForTurn: Int? = null
    ) {
        runCatching {
            // Build once (avoid triple parsing cost + keeps snapshot consistent)
            val header = buildStateHeader(s)

            val pendingKey = headerValue(header, "pending") ?: ""
            val pendingExpectedKind = headerValue(header, "pending_expected_answer_kind") ?: ""
            val pendingTargetCell = headerValue(header, "pending_target_cell") ?: ""

            val rc = s.activeRouteContext
            val routeObj = JSONObject().apply {
                put("is_present", rc != null)
                put("step_id", rc?.stepId ?: JSONObject.NULL)
                put("grid_hash12", rc?.gridHash12 ?: JSONObject.NULL)
                put("journey_step_number", rc?.journeyStepNumber ?: JSONObject.NULL)
                put("hint_index", rc?.atomIndex ?: JSONObject.NULL)
                put("hint_count", rc?.atomsCount ?: JSONObject.NULL)
                put("technique_id", rc?.techniqueId ?: JSONObject.NULL)
                put("target_cell_index", rc?.targetCellIndex ?: JSONObject.NULL)
            }

            val factsArr = JSONArray().apply {
                (facts ?: emptyList()).forEach { fb ->
                    val o = JSONObject()
                    o.put("type", fb.type.name)

                    // keep it light: a few safe keys only
                    runCatching {
                        val p = fb.payload
                        if (p != null) {
                            val schema = p.optString("schema_version", "")
                            if (schema.isNotBlank()) o.put("schema_version", schema)

                            // common step-id patterns (best-effort)
                            val stepId =
                                p.optString("step_id", "").takeIf { it.isNotBlank() }
                                    ?: p.optJSONObject("step")?.optString("step_id", "")?.takeIf { it.isNotBlank() }
                                    ?: p.optJSONObject("step")?.optJSONObject("step")?.optString("step_id", "")?.takeIf { it.isNotBlank() }
                            if (!stepId.isNullOrBlank()) o.put("step_id", stepId)
                        }
                    }
                    put(o)
                }
            }

            // SOLVING breadcrumbs (these are stable + useful for audits)
            val solvingObj = JSONObject().apply {
                put("solve_step_status", s.solveStepStatus.name)
                put("solve_step_id", s.solveStepId ?: JSONObject.NULL)
                put("solve_step_grid_hash12", s.solveStepGridHash12 ?: JSONObject.NULL)
                put("solve_hint_index", s.solveAtomIndex)
                put("solve_hint_count", s.solveAtomsCount)
                put("solve_overlay_visible", s.solveOverlayVisible)
                put("solve_overlay_style", s.solveOverlayStyle)
                put("coach_plan_step_id", s.coachPlanStepId ?: JSONObject.NULL)
                put("coach_plan_grid_hash12", s.coachPlanGridHash12 ?: JSONObject.NULL)
                put("coach_plan_sha12", s.coachPlanSha12 ?: JSONObject.NULL)
            }

            ConversationTelemetry.emit(
                mapOf(
                    "type" to "TURN_CONTRACT_SNAPSHOT",
                    "session_id" to s.sessionId,
                    "turn_id" to (ctx?.turnId ?: s.turnSeq),
                    "tick_id" to (ctx?.tickId ?: 0),
                    "policy_req_seq" to (ctx?.policyReqSeq ?: 0L),
                    "correlation_id" to (ctx?.correlationId ?: ""),
                    "model_call_id" to (ctx?.modelCallId ?: ""),
                    "toolplan_id" to (ctx?.toolplanId ?: ""),

                    "stage" to stage,
                    "note" to note,

                    "mode" to s.mode.name,
                    "phase" to s.phase.name,

                    "pending_kind" to pendingKey,
                    "pending_expected_answer_kind" to pendingExpectedKind,
                    "pending_target_cell" to pendingTargetCell,

                    "route_context" to routeObj.toString(),

                    "facts_count" to (facts?.size ?: 0),
                    "facts_summary" to factsArr.toString(),

                    "solving_summary" to solvingObj.toString(),

                    // If caller provides it, great. Otherwise it remains null and
                    // AndroidEffectRunner emits TURN_TICK2_COUNTER (Patch 0.3) to join by turn_id.
                    "tick2_calls_for_turn" to (tick2CallsForTurn ?: JSONObject.NULL)
                )
            )
        }.onFailure {
            runCatching {
                ConversationTelemetry.emit(
                    mapOf(
                        "type" to "TURN_CONTRACT_SNAPSHOT_FAILED",
                        "stage" to stage,
                        "note" to note,
                        "ex" to (it.javaClass.simpleName ?: "Throwable"),
                        "msg" to (it.message ?: "")
                    )
                )
            }
        }
    }



    fun emitSolvingAgendaTransitionIfChanged(
        traceState: SudoState,
        phaseNow: GridPhase,
        prev: AppAgendaItem.Solving?,
        next: AppAgendaItem.Solving?
    ) {
        if (prev == null && next == null) return
        if (prev?.javaClass?.simpleName == next?.javaClass?.simpleName) return

        runCatching {
            ConversationTelemetry.emit(
                mapOf(
                    "type" to "SOLVING_AGENDA_TRANSITION",
                    "session_id" to traceState.sessionId,
                    "turn_id" to traceState.turnSeq,
                    "phase" to phaseNow.name,
                    "from" to (prev?.javaClass?.simpleName ?: "null"),
                    "to" to (next?.javaClass?.simpleName ?: "null"),
                    "step_id" to (traceState.solveStepId ?: "null"),
                    "grid_hash12" to ((traceState.solveStepGridHash12 ?: "").take(12))
                )
            )
        }
    }


    // ============================================================
// Phase 0/1 — Runtime-enforced turn contracts
// ============================================================
    private data class TurnContractEnforceResult(
        val s: SudoState,
        val facts: List<FactBundleV1>
    )

    private fun enforceTurnContractAndAttachSnapshot(
        stage: String,                 // "POST_DECISION" | "PRE_TICK2" | "POST_APPLY"
        s: SudoState,
        factsIn: List<FactBundleV1>,
        rawTextUsedByMaps: Boolean
    ): TurnContractEnforceResult {

        fun pendingKind(p: Pending?): String? = when (p) {
            null -> null
            else -> p::class.java.simpleName
        }

        val agendaHeadKind: String? = s.appAgendaQueue.firstOrNull()?.let { it::class.java.simpleName }

        // CTA artifacts present (single-contract expectation)
        val hasCtaPacket = factsIn.any { it.type == FactBundleV1.Type.CTA_PACKET_V1 }
        val hasRecoveryPacket = factsIn.any { it.type == FactBundleV1.Type.RECOVERY_PACKET_V1 }



        // Phase 2: CTA contract is bundle-only (CTA_PACKET_V1 or RECOVERY_PACKET_V1). Pending is internal.
        val ctaArtifactsPresent = mutableListOf<String>()
        if (hasRecoveryPacket) ctaArtifactsPresent += "RECOVERY_PACKET_V1"
        if (hasCtaPacket) ctaArtifactsPresent += "CTA_PACKET_V1"


        val ctaArtifactsCount = ctaArtifactsPresent.size

        // Proof bundles present (SOLVING must have proof OR be in recovery)
        val hasSolvingPacketV1 = factsIn.any { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
        val hasLegacySolvingPacket = factsIn.any { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET }
        val proofBundlesPresent = mutableListOf<String>()
        if (hasSolvingPacketV1) proofBundlesPresent += "SOLVING_STEP_PACKET_V1"
        if (hasLegacySolvingPacket) proofBundlesPresent += "SOLVING_STEP_PACKET"

        val proofOkForSolving: Boolean = when {
            s.phase != GridPhase.SOLVING -> true
            hasRecoveryPacket -> true
            hasSolvingPacketV1 -> true
            else -> false
        }

        // -------------------------
        // Hard guards → fail-safe to RECOVERY (do not crash)
        // -------------------------
        var sOut = s
        var factsOut = factsIn

        fun forceRecovery(kind: String, note: String) {
            val factsObj = JSONObject().apply {
                put("note", note)
                put("mode", s.mode.name)
                put("phase", s.phase.name)
            }
            val cta = CtaPacketV1(
                slot = "recovery",
                options = listOf(
                    CtaOptionV1(id = PendingChoiceId.RETURN_TO_ROUTE, label = "Back to Sudoku"),
                    CtaOptionV1(id = PendingChoiceId.NEXT_STEP, label = "Next")
                )
            )

            // Remove any competing CTA artifacts and clear pending to guarantee one CTA contract.
            factsOut = factsOut.filterNot {
                it.type == FactBundleV1.Type.CTA_PACKET_V1 ||
                        it.type == FactBundleV1.Type.NEXT_PENDING_PROMPT ||
                        it.type == FactBundleV1.Type.RECOVERY_PACKET_V1
            } + factRecoveryPacketV1(kind = kind, facts = factsObj, cta = cta)

            sOut = sOut.copy(pending = null)
        }

        // (1) Phase 1 invariant: raw text must not be used by Maps.
        if (rawTextUsedByMaps) {
            forceRecovery(
                kind = "invariant_violation_raw_text_used_by_maps",
                note = "Maps inspected raw user text. This must never happen."
            )
        }

        // (2) One-CTA-per-turn invariant (for GRID_SESSION turns)
        if (sOut.mode == SudoMode.GRID_SESSION) {
            val hasAnyCtaArtifact = factsOut.any {
                it.type == FactBundleV1.Type.CTA_PACKET_V1 || it.type == FactBundleV1.Type.RECOVERY_PACKET_V1
            }

            val ctas = mutableListOf<String>()
            if (factsOut.any { it.type == FactBundleV1.Type.RECOVERY_PACKET_V1 }) ctas += "RECOVERY_PACKET_V1"
            if (factsOut.any { it.type == FactBundleV1.Type.CTA_PACKET_V1 }) ctas += "CTA_PACKET_V1"

            if (hasAnyCtaArtifact && ctas.size != 1) {
                forceRecovery(
                    kind = "invariant_violation_cta_artifacts_count",
                    note = "Expected exactly 1 CTA artifact in Tick2 input, but found ${ctas.size}: ${ctas.joinToString(",")}."
                )
            }
        }

        // (3) SOLVING requires proof (or recovery)
        if (!proofOkForSolving && sOut.phase == GridPhase.SOLVING) {
            forceRecovery(
                kind = "invariant_violation_missing_proof_for_solving",
                note = "SOLVING requires SOLVING_STEP_PACKET_V1 (proof) or an explicit RECOVERY_PACKET_V1."
            )
        }

        // Recompute snapshot fields after enforcement
        val hasCtaPacket2 = factsOut.any { it.type == FactBundleV1.Type.CTA_PACKET_V1 }
        val hasRecoveryPacket2 = factsOut.any { it.type == FactBundleV1.Type.RECOVERY_PACKET_V1 }
        val hasLegacyPendingPrompt2 = factsOut.any { it.type == FactBundleV1.Type.NEXT_PENDING_PROMPT }
        val hasPending2 = (sOut.pending != null)
        val ctaPresent2 = mutableListOf<String>()
        if (hasRecoveryPacket2) ctaPresent2 += "RECOVERY_PACKET_V1"
        if (hasCtaPacket2) ctaPresent2 += "CTA_PACKET_V1"
        if (hasLegacyPendingPrompt2) ctaPresent2 += "NEXT_PENDING_PROMPT"
        if (hasPending2) ctaPresent2 += "PENDING"

        val hasSolvingPacketV12 = factsOut.any { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
        val hasLegacySolvingPacket2 = factsOut.any { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET }
        val proofPresent2 = mutableListOf<String>()
        if (hasSolvingPacketV12) proofPresent2 += "SOLVING_STEP_PACKET_V1"
        if (hasLegacySolvingPacket2) proofPresent2 += "SOLVING_STEP_PACKET"

        val proofOk2 = when {
            sOut.phase != GridPhase.SOLVING -> true
            hasRecoveryPacket2 -> true
            hasSolvingPacketV12 -> true
            else -> false
        }

        val snapshot = TurnContractSnapshotV1(
            stage = stage,
            turnSeq = sOut.turnSeq,
            mode = sOut.mode.name,
            phase = sOut.phase.name,
            pendingKind = pendingKind(sOut.pending),
            agendaItemKind = agendaHeadKind,
            ctaArtifactsPresent = ctaPresent2,
            ctaArtifactsCount = ctaPresent2.size,
            rawTextUsedByMaps = rawTextUsedByMaps,
            proofBundlesPresent = proofPresent2,
            proofOkForSolving = proofOk2
        )

        val snapshotJson = JSONObject().apply {
            put("schema_version", "turn_contract_snapshot_v1")
            put("stage", snapshot.stage)
            put("turn_seq", snapshot.turnSeq)
            put("mode", snapshot.mode)
            put("phase", snapshot.phase)
            put("pending_kind", snapshot.pendingKind ?: JSONObject.NULL)
            put("agenda_item_kind", snapshot.agendaItemKind ?: JSONObject.NULL)
            put("cta_artifacts_present", JSONArray().apply { snapshot.ctaArtifactsPresent.forEach { put(it) } })
            put("cta_artifacts_count", snapshot.ctaArtifactsCount)
            put("raw_text_used_by_maps", snapshot.rawTextUsedByMaps)
            put("proof_bundles_present", JSONArray().apply { snapshot.proofBundlesPresent.forEach { put(it) } })
            put("proof_ok_for_solving", snapshot.proofOkForSolving)
        }

        factsOut = factsOut + FactBundleV1(type = FactBundleV1.Type.TURN_CONTRACT_SNAPSHOT_V1, payload = snapshotJson)
        sOut = sOut.copy(lastTurnContractSnapshot = snapshot)

        return TurnContractEnforceResult(s = sOut, facts = factsOut)
    }



    // ============================================================
// Phase 2 — Single CTA contract: Pending (internal) → CTA_PACKET_V1 (external)
// ============================================================
    private fun ctaOpt(id: String, label: String, intent: String? = null): CtaOptionV1 =
        CtaOptionV1(
            id = id,
            label = label,
            semantics = if (intent != null) org.json.JSONObject().put("intent", intent) else null
        )

    private fun pendingToCtaPacketV1(p: Pending): CtaPacketV1 {
        return when (p) {

            // ----------------------------
            // CONFIRMING: yes/no gates
            // ----------------------------
            is Pending.ConfirmEdit -> CtaPacketV1(
                slot = "confirm_edit",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Change it", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "Keep it", intent = "CONFIRM_NO")
                    // Note: user may also speak PROVIDE_DIGIT; that is handled by Tick1 intents, not an option button.
                )
            )

            is Pending.ConfirmCellAsIs -> CtaPacketV1(
                slot = "confirm_cell_as_is",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Keep it", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "No", intent = "CONFIRM_NO")
                )
            )

            is Pending.ConfirmCellToDigit -> CtaPacketV1(
                slot = "confirm_cell_to_digit",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Change it", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "Keep it", intent = "CONFIRM_NO")
                )
            )

            is Pending.ConfirmRegionAsIs -> CtaPacketV1(
                slot = "confirm_region_as_is",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Keep it", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "No", intent = "CONFIRM_NO")
                )
            )

            is Pending.ConfirmRegionToDigits -> CtaPacketV1(
                slot = "confirm_region_to_digits",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Apply it", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "Keep current", intent = "CONFIRM_NO")
                )
            )

            is Pending.ProvideDigit -> CtaPacketV1(
                slot = "provide_digit",
                options = emptyList() // expects spoken digit / structured digit follow-up
            )

            is Pending.ConfirmRetake -> CtaPacketV1(
                slot = "confirm_retake",
                options = listOf(
                    ctaOpt(id = "choose_retake", label = "Retake photo", intent = "CHOOSE_RETAKE"),
                    ctaOpt(id = "choose_keep_scan", label = "Keep this scan", intent = "CHOOSE_KEEP_SCAN")
                )
            )

            is Pending.ConfirmValidate -> CtaPacketV1(
                slot = "confirm_validate",
                options = listOf(
                    ctaOpt(id = "confirm_grid_match_exact", label = "Validate", intent = "CONFIRM_GRID_MATCH_EXACT"),
                    ctaOpt(id = "confirm_no", label = "Not yet", intent = "CONFIRM_NO")
                )
            )

            is Pending.ConfirmStartSolving -> CtaPacketV1(
                slot = "confirm_start_solving",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Start solving", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "Not yet", intent = "CONFIRM_NO")
                )
            )

            is Pending.VisualVerifyMatch -> CtaPacketV1(
                slot = "visual_verify_match",
                options = listOf(
                    ctaOpt(id = "confirm_grid_match_exact", label = "It matches", intent = "CONFIRM_GRID_MATCH_EXACT"),
                    ctaOpt(id = "confirm_no", label = "There’s a mismatch", intent = "CONFIRM_NO")
                )
            )

            // ----------------------------
            // CONFIRMING/REPAIR: freeform answers
            // ----------------------------
            is Pending.AskCellValue -> CtaPacketV1(
                slot = "ask_cell_value",
                options = emptyList() // expects PROVIDE_DIGIT via speech (or tap pipeline)
            )

            is Pending.ConfirmInterpretation -> CtaPacketV1(
                slot = "confirm_interpretation",
                options = listOf(
                    ctaOpt(id = "confirm_yes", label = "Yes", intent = "CONFIRM_YES"),
                    ctaOpt(id = "confirm_no", label = "No", intent = "CONFIRM_NO")
                )
            )

            is Pending.AskClarification -> CtaPacketV1(
                slot = "ask_clarification",
                options = emptyList() // expects structured follow-up intents (e.g. EDIT_CELL targets)
            )

            is Pending.UserAgendaBridge -> CtaPacketV1(
                slot = "user_agenda_bridge",
                options = p.options.map { optId ->
                    ctaOpt(
                        id = optId,
                        label = optId,
                        intent = when (optId) {
                            PendingChoiceId.RETURN_TO_ROUTE -> "SOLVE_CONTINUE"
                            PendingChoiceId.NEXT_STEP -> "SOLVE_ACCEPT_NEXT_STEP"
                            PendingChoiceId.SHOW_PROOF -> "REQUEST_CURRENT_STAGE_ELABORATION"
                            PendingChoiceId.LOCK_IT_IN -> "SOLVE_ACCEPT_LOCK_IN"
                            else -> null
                        }
                    )
                }
            )

            is Pending.WaitForTap -> CtaPacketV1(
                slot = "wait_for_tap",
                options = emptyList() // expects tap; no “speech escape” here in Maps (Phase 1)
            )

            // ----------------------------
            // SOLVING
            // ----------------------------
            is Pending.SolveStepMissing -> CtaPacketV1(
                slot = if (p.autoApplyFallback) "proof_failure_fallback_commit" else "solve_step_missing",
                options = if (p.autoApplyFallback) {
                    listOf(
                        ctaOpt(
                            id = PendingChoiceId.NEXT_STEP,
                            label = "Continue when ready",
                            intent = "SOLVE_ACCEPT_NEXT_STEP"
                        ),
                        ctaOpt(
                            id = PendingChoiceId.RETURN_TO_ROUTE,
                            label = "Take another look",
                            intent = "SOLVE_CONTINUE"
                        )
                    )
                } else {
                    listOf(
                        ctaOpt(id = PendingChoiceId.NEXT_STEP, label = "Try next step", intent = "SOLVE_ACCEPT_NEXT_STEP"),
                        ctaOpt(id = PendingChoiceId.RETURN_TO_ROUTE, label = "Back", intent = "SOLVE_CONTINUE")
                    )
                }
            )

            is Pending.SolveIntroAction -> CtaPacketV1(
                slot = "solve_intro_action",
                options = p.options.map { optId ->
                    ctaOpt(id = optId, label = optId, intent = when (optId) {
                        PendingChoiceId.SHOW_PROOF,
                        PendingChoiceId.GUIDE_ME -> "REQUEST_CURRENT_STAGE_ELABORATION"

                        PendingChoiceId.READY_FOR_ANSWER,
                        PendingChoiceId.APPLY_NOW -> "SOLVE_ACCEPT_LOCK_IN"

                        PendingChoiceId.NEXT_STEP -> "SOLVE_ACCEPT_NEXT_STEP"
                        PendingChoiceId.RETURN_TO_ROUTE -> "SOLVE_CONTINUE"

                        PendingChoiceId.TRY_SELF,
                        PendingChoiceId.LET_ME_TRY -> "SOLVE_PAUSE"

                        PendingChoiceId.EXPLAIN_MORE -> "REQUEST_CURRENT_STAGE_ELABORATION"
                        PendingChoiceId.ASK_TECHNIQUE -> "REQUEST_CURRENT_TECHNIQUE_EXPLANATION"

                        else -> null
                    })
                }
            )

            is Pending.AfterResolution -> CtaPacketV1(
                slot = "after_resolution",
                options = p.options.map { optId ->
                    ctaOpt(id = optId, label = optId, intent = when (optId) {
                        PendingChoiceId.NEXT_STEP -> "SOLVE_ACCEPT_NEXT_STEP"
                        PendingChoiceId.ASK_TECHNIQUE -> "REQUEST_CURRENT_TECHNIQUE_EXPLANATION"
                        else -> null
                    })
                }
            )

            is Pending.ApplyHintNow -> CtaPacketV1(
                slot = "apply_hint_now",
                options = p.options.map { optId ->
                    ctaOpt(id = optId, label = optId, intent = when (optId) {
                        PendingChoiceId.LOCK_IT_IN,
                        PendingChoiceId.APPLY_NOW -> "SOLVE_ACCEPT_LOCK_IN"

                        PendingChoiceId.TRY_SELF,
                        PendingChoiceId.LET_ME_TRY -> "SOLVE_PAUSE"

                        PendingChoiceId.EXPLAIN_MORE -> "REQUEST_CURRENT_STAGE_ELABORATION"
                        else -> null
                    })
                }
            )

            is Pending.ReturnToRoute -> CtaPacketV1(
                slot = "return_to_route",
                options = listOf(
                    ctaOpt(id = PendingChoiceId.RETURN_TO_ROUTE, label = "Back to Sudoku", intent = "SOLVE_CONTINUE")
                )
            )
        }
    }

    private fun factPendingContextV1(payload: org.json.JSONObject): FactBundleV1 =
        FactBundleV1(type = FactBundleV1.Type.PENDING_CONTEXT_V1, payload = payload)




    private fun emitNoPendingReason(
        tag: String,
        turnId: Long,
        reason: String,
        extra: Map<String, Any?> = emptyMap()
    ) {
        ConversationTelemetry.emit(
            mapOf(
                "type" to "NO_PENDING_REASON",
                "tag" to tag,
                "turn_id" to turnId,
                "reason" to reason
            ) + extra
        )
    }

    private fun nextPolicyCtx(
        s: SudoState,
        tickId: Int,
        reason: String,
        stateHeader: String,
        turnId: Long
    ): Pair<SudoState, PolicyCallCtx> {
        val nextSeq = s.policyReqSeq + 1L
        val correlationId = "turn-$turnId"

        val headerSha12 = runCatching {
            ConversationTelemetry.sha256Hex(stateHeader).take(12)
        }.getOrNull()

        // Stable IDs. Keep them deterministic + joinable.
        val modelCallId = "mc_${turnId}_${tickId}_${nextSeq}"
        val toolplanId  = "tp_${turnId}_${tickId}_${nextSeq}"

        val ctx = PolicyCallCtx(
            sessionId = s.sessionId,
            turnId = turnId,
            tickId = tickId,
            policyReqSeq = nextSeq,
            correlationId = correlationId,
            modelCallId = modelCallId,
            toolplanId = toolplanId,
            mode = s.mode.name,
            reason = reason,
            stateHeaderSha12 = headerSha12
        )

        return s.copy(policyReqSeq = nextSeq) to ctx
    }


    private fun emitAppPlanV1(
        ctx: PolicyCallCtx,
        sBefore: SudoState,
        sAfter: SudoState,
        env: com.contextionary.sudoku.conductor.policy.IntentEnvelopeV1,
        plan: PlanV1
    ) {
        val top = env.intents.maxByOrNull { it.confidence }
        val factTypes = plan.factBundles.map { it.type.name }.distinct()

        fun controlFromPending(p: Pending?): Map<String, Any?>? = when (p) {
            null -> null

            is Pending.ConfirmRetake -> mapOf(
                "ctrl_type" to "RECOMMEND_RETAKE",
                "strength" to p.strength,
                "prompt" to p.prompt
            )

            is Pending.ConfirmEdit -> mapOf(
                "ctrl_type" to "PROPOSE_EDIT",
                "cell_index" to p.cellIndex,
                "cell" to indexToCell(p.cellIndex),
                "proposed_digit" to p.proposedDigit,
                "prompt" to p.prompt
            )

            is Pending.AskCellValue -> mapOf(
                "ctrl_type" to "ASK_CONFIRM_CELL",
                "cell_index" to p.cellIndex,
                "cell" to indexToCell(p.cellIndex),
                "prompt" to p.prompt
            )

            is Pending.AskClarification -> mapOf(
                "ctrl_type" to "ASK_CLARIFYING_QUESTION",
                "kind" to p.kind.name,
                "prompt" to p.prompt
            )

            is Pending.ConfirmValidate -> mapOf(
                "ctrl_type" to "CONFIRM_GRID_MATCH",
                "prompt" to p.prompt
            )

            is Pending.SolveIntroAction -> mapOf(
                "ctrl_type" to "ASK_SOLVE_INTRO_ACTION",
                "step_id" to p.stepId,
                "story_stage" to p.stage.name,
                "hint_index" to p.atomIndex,
                "hint_count" to p.atomsCount,
                "is_last_hint" to p.isLastHint,
                "prompt" to p.prompt
            )

            is Pending.AfterResolution -> mapOf(
                "ctrl_type" to "ASK_NEXT_STEP",
                "step_id" to p.stepId,
                "prompt" to p.prompt
            )

            is Pending.ApplyHintNow -> mapOf(
                "ctrl_type" to "ASK_USER_TO_APPLY_HINT",
                "step_id" to p.stepId,
                "prompt" to p.prompt,
                "options" to p.options
            )

            is Pending.UserAgendaBridge -> mapOf(
                "ctrl_type" to "USER_AGENDA_BRIDGE",
                "user_agenda_id" to p.userAgendaId,
                "agenda_kind" to p.agendaKind,
                "prompt" to p.prompt,
                "agenda_status" to p.agendaStatus,
                "allows_follow_up" to p.allowsFollowUp,
                "cell_ref" to p.cellRef,
                "digit_hint" to p.digitHint,
                "options" to p.options
            )

            else -> mapOf("ctrl_type" to ("PENDING_" + (p.javaClass.simpleName ?: "UNKNOWN")))
        }

        val opsPayload = plan.ops.map { op ->
            when (op) {
                is PlannedOpV1.ApplyCellEdit -> mapOf(
                    "op_type" to "APPLY_CELL_EDIT",
                    "cell_index" to op.cellIndex,
                    "cell" to indexToCell(op.cellIndex),
                    "digit" to op.digit,
                    "source" to op.source
                )

                is PlannedOpV1.ConfirmCellValue -> mapOf(
                    "op_type" to "CONFIRM_CELL_VALUE",
                    "cell_index" to op.cellIndex,
                    "cell" to indexToCell(op.cellIndex),
                    "digit" to op.digit,
                    "source" to op.source
                )

                is PlannedOpV1.Undo -> mapOf("op_type" to "UNDO", "source" to op.source)
                is PlannedOpV1.Redo -> mapOf("op_type" to "REDO", "source" to op.source)

                is PlannedOpV1.AddCandidate -> mapOf(
                    "op_type" to "ADD_CANDIDATE",
                    "cell_index" to op.cellIndex,
                    "cell" to indexToCell(op.cellIndex),
                    "digit" to op.digit,
                    "source" to op.source
                )

                is PlannedOpV1.RemoveCandidate -> mapOf(
                    "op_type" to "REMOVE_CANDIDATE",
                    "cell_index" to op.cellIndex,
                    "cell" to indexToCell(op.cellIndex),
                    "digit" to op.digit,
                    "source" to op.source
                )

                is PlannedOpV1.SetCandidatesMask -> mapOf(
                    "op_type" to "SET_CANDIDATES_MASK",
                    "cell_index" to op.cellIndex,
                    "cell" to indexToCell(op.cellIndex),
                    "mask" to op.mask,
                    "source" to op.source
                )

                is PlannedOpV1.FinalizeValidationPresentation -> mapOf(
                    "op_type" to "FINALIZE_VALIDATION_PRESENTATION",
                    "reason" to op.reason,
                    "source" to op.source
                )

                is PlannedOpV1.ComputeSolveStep -> mapOf(
                    "op_type" to "COMPUTE_SOLVE_STEP"
                )

                else -> mapOf(
                    "op_type" to ("UNKNOWN_" + (op.javaClass.simpleName ?: "OP"))
                )
            }
        }

        // ---- Control payload (0..1 by design) ----
        val ctrlPayload = listOfNotNull(controlFromPending(sAfter.pending))
        val ctrlCount = ctrlPayload.size

        // ---- Agenda diffs ----
        fun userKey(it: UserAgendaItem): String = it.id

        fun appKey(it: AppAgendaItem): String = when (it) {
            is AppAgendaItem.ProposeRetake -> "ProposeRetake:${it.strength}:${it.reason}"
            is AppAgendaItem.ProposeEdit -> "ProposeEdit:${it.cellIndex}:${it.expectedDigit}"
            is AppAgendaItem.AskConfirmCell -> "AskConfirmCell:${it.cellIndex}:${it.reason}"
            else -> (it.javaClass.simpleName ?: "AppAgendaItem")
        }

        val userBeforeKeys = sBefore.userAgendaQueue.map(::userKey).toSet()
        val userAfterKeys = sAfter.userAgendaQueue.map(::userKey).toSet()
        val userRemoved = (userBeforeKeys - userAfterKeys).toList()

        val userAdded = sAfter.userAgendaQueue
            .filter { !userBeforeKeys.contains(userKey(it)) }
            .map { item ->
                when (item) {
                    is UserAgendaItem.Clarification -> mapOf(
                        "id" to item.id,
                        "kind" to "CLARIFICATION",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "missing" to item.missing,
                        "ua_reason" to if (item.missing.contains("intent")) "EMPTY_INTENTS_FALLBACK" else "GRID_INTENT_MISSING_SLOTS",
                        "intent_id" to item.intentId,
                        "prompt" to item.prompt,
                        "created_turn_seq" to item.createdTurnSeq,
                        "asked_turn_seq" to item.askedTurnSeq
                    )

                    is UserAgendaItem.ProofChallenge -> mapOf(
                        "id" to item.id,
                        "kind" to "PROOF_CHALLENGE",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "cell_ref" to item.cellRef,
                        "digit" to item.digit,
                        "house_ref" to item.houseRef,
                        "prompt" to item.prompt,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.CandidateStateQuery -> mapOf(
                        "id" to item.id,
                        "kind" to "CANDIDATE_STATE_QUERY",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "cell_refs" to item.cellRefs,
                        "house_ref" to item.houseRef,
                        "digit" to item.digit,
                        "ask_kind" to item.askKind.name,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.TargetCellQuery -> mapOf(
                        "id" to item.id,
                        "kind" to "TARGET_CELL_QUERY",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "target_cell_ref" to item.targetCellRef,
                        "digit" to item.digit,
                        "ask_kind" to item.askKind.name,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.NeighborCellQuery -> mapOf(
                        "id" to item.id,
                        "kind" to "NEIGHBOR_CELL_QUERY",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "anchor_cell_ref" to item.anchorCellRef,
                        "neighbor_cell_ref" to item.neighborCellRef,
                        "ask_kind" to item.askKind.name,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.UserReasoningCheck -> mapOf(
                        "id" to item.id,
                        "kind" to "USER_REASONING_CHECK",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "cell_ref" to item.cellRef,
                        "proposed_digits" to item.proposedDigits,
                        "prompt" to item.prompt,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.AlternativeTechniqueQuery -> mapOf(
                        "id" to item.id,
                        "kind" to "ALTERNATIVE_TECHNIQUE_QUERY",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "cell_ref" to item.cellRef,
                        "region_ref" to item.regionRef,
                        "requested_technique" to item.requestedTechniqueIdOrLabel,
                        "ask_kind" to item.askKind.name,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.RouteComparisonQuery -> mapOf(
                        "id" to item.id,
                        "kind" to "ROUTE_COMPARISON_QUERY",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "compare_scope" to item.compareScope,
                        "user_idea_label" to item.userIdeaLabel,
                        "ask_kind" to item.askKind.name,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.RouteControl -> mapOf(
                        "id" to item.id,
                        "kind" to "ROUTE_CONTROL",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "control" to item.control.name,
                        "prompt" to item.prompt,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.OverlayControl -> mapOf(
                        "id" to item.id,
                        "kind" to "OVERLAY_CONTROL",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "control" to item.control.name,
                        "focus_cell_ref" to item.focusCellRef,
                        "region_ref" to item.regionRef,
                        "digit" to item.digit,
                        "created_turn_seq" to item.createdTurnSeq
                    )

                    is UserAgendaItem.GeneralQuestion -> mapOf(
                        "id" to item.id,
                        "kind" to "GENERAL_QUESTION",
                        "status" to item.status.name,
                        "parent_agenda_id" to item.parentAgendaId,
                        "allows_follow_up" to item.allowsFollowUp,
                        "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                        "intent_id" to item.intentId,
                        "topic" to item.topic,
                        "prompt" to item.prompt,
                        "created_turn_seq" to item.createdTurnSeq
                    )
                }
            }

        val appBeforeKeys = sBefore.appAgendaQueue.map(::appKey).toSet()
        val appAfterKeys = sAfter.appAgendaQueue.map(::appKey).toSet()
        val appRemoved = (appBeforeKeys - appAfterKeys).toList()
        val appAdded = sAfter.appAgendaQueue
            .filter { !appBeforeKeys.contains(appKey(it)) }
            .map { item ->
                when (item) {
                    is AppAgendaItem.ProposeRetake -> mapOf(
                        "id" to appKey(item),
                        "kind" to "PROPOSE_RETAKE",
                        "strength" to item.strength,
                        "reason" to item.reason
                    )

                    is AppAgendaItem.ProposeEdit -> mapOf(
                        "id" to appKey(item),
                        "kind" to "PROPOSE_EDIT",
                        "cell_index" to item.cellIndex,
                        "cell" to indexToCell(item.cellIndex),
                        "scanned_digit" to item.scannedDigit,
                        "expected_digit" to item.expectedDigit,
                        "reason" to item.reason
                    )

                    is AppAgendaItem.AskConfirmCell -> mapOf(
                        "id" to appKey(item),
                        "kind" to "ASK_CONFIRM_CELL",
                        "cell_index" to item.cellIndex,
                        "cell" to indexToCell(item.cellIndex),
                        "reason" to item.reason
                    )

                    else -> mapOf(
                        "id" to appKey(item),
                        "kind" to (item.javaClass.simpleName ?: "UNKNOWN")
                    )
                }
            }

        val noPendingReason =
            if (sAfter.pending != null) null
            else {
                val hasUserAgenda = sAfter.userAgendaQueue.isNotEmpty()
                val hasAppAgenda = sAfter.appAgendaQueue.isNotEmpty()
                when {
                    hasUserAgenda -> "PENDING_NULL_BUT_USER_AGENDA_EXISTS"
                    hasAppAgenda -> "PENDING_NULL_BUT_APP_AGENDA_EXISTS"
                    else -> "NO_APP_AGENDA_AND_NO_USER_AGENDA"
                }
            }

        val topIntentType = top?.type
        val topIntentBucket =
            topIntentType?.let { agendaIntentConstitutionBucketV1(it).name } ?: "NONE"

        val authorityCarrierKind =
            when {
                sAfter.pending != null &&
                        topIntentType != null &&
                        isRepairCandidateIntentForAgendaV1(topIntentType) ->
                    "REPAIR_PENDING"

                userAdded.isNotEmpty() && userAdded.any { (it["kind"] as? String) == "ROUTE_CONTROL" } ->
                    "USER_ROUTE_JUMP_ITEM"

                userAdded.isNotEmpty() ->
                    "USER_DETOUR_ITEM"

                topIntentType != null && isDirectAppOwnedIntentForAgendaV1(topIntentType) ->
                    "DIRECT_APP_OWNED"

                else ->
                    "NONE"
            }

        val userAgendaMaterializationReason =
            when {
                topIntentType != null && isDirectAppOwnedIntentForAgendaV1(topIntentType) ->
                    "DIRECT_APP_OWNED_TOP_INTENT"

                topIntentType != null && isRepairCandidateIntentForAgendaV1(topIntentType) ->
                    "REPAIR_CANDIDATE_TOP_INTENT"

                userAdded.isNotEmpty() ->
                    "USER_ITEM_ADDED"

                topIntentType == null ->
                    "NO_TOP_INTENT"

                else ->
                    "NO_NEW_USER_ITEM_AFTER_QUEUE_PROCESSING"
            }

        val boundaryContext = buildBoundaryGuardContextV1(
            sBeforePlan = sBefore,
            sAfterPlan = sAfter,
            userText = "",
            boundaryReturnAcceptedV1 = plan.boundaryReturnAcceptedV1,
            boundaryResumePolicyV1 = plan.boundaryResumePolicyV1
        )

        val solveResolutionApplyEmittedV1 =
            plan.ops.any { op ->
                op is PlannedOpV1.ApplyCellEdit && op.source == "solve_resolution_apply"
            }

        val autoCommitApplyHintHybridViolationV1 =
            plan.resolutionCommitOutcomeV1 == ResolutionCommitOutcomeV1.APP_AUTO_COMMIT &&
                    sAfter.pending is Pending.ApplyHintNow

        val manualApplyWithApplyOpViolationV1 =
            plan.resolutionCommitOutcomeV1 == ResolutionCommitOutcomeV1.MANUAL_APPLY_REQUIRED &&
                    solveResolutionApplyEmittedV1

        val postCommitContinuationRequestedV1 =
            env.intents.any {
                it.type == IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP ||
                        it.type == IntentTypeV1.SOLVE_CONTINUE ||
                        it.type == IntentTypeV1.CONFIRM_YES
            }

        val postCommitContinuationAuthorizedV1 =
            plan.newAdvanceToNextStep == true

        val stayedPostCommitWithoutBlockerV1 =
            postCommitContinuationRequestedV1 &&
                    !postCommitContinuationAuthorizedV1 &&
                    sAfter.pending is Pending.AfterResolution &&
                    currentQueuedSolvingHead(sAfter) is AppAgendaItem.Solving.PostCommitChoice &&
                    !hasFactBundleKindV1(plan.factBundles, "post_commit_continuation_blocked_v1")

        val duplicateSameCellApplyWithoutJustificationV1 =
            solveResolutionApplyEmittedV1 &&
                    run {
                        val priorPlacement = currentCommittedResolutionPlacementV1(sBefore)
                        priorPlacement != null &&
                                priorPlacement.first == plan.resolutionCommitCellIndexV1 &&
                                priorPlacement.second == plan.resolutionCommitDigitV1 &&
                                !hasFactBundleKindV1(plan.factBundles, "duplicate_resolution_apply_justified_v1")
                    }

        val contractViolationsV1 = mutableListOf<String>().apply {
            if (autoCommitApplyHintHybridViolationV1) {
                add("auto_commit_cannot_leave_apply_hint_now")
            }
            if (manualApplyWithApplyOpViolationV1) {
                add("manual_apply_required_cannot_emit_resolution_apply_op")
            }
            if (stayedPostCommitWithoutBlockerV1) {
                add("post_commit_continuation_requested_but_stayed_without_blocker")
            }
            if (duplicateSameCellApplyWithoutJustificationV1) {
                add("duplicate_same_cell_apply_without_explicit_justification")
            }
        }

        if (contractViolationsV1.isNotEmpty()) {
            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "APP_PLAN_CONTRACT_VIOLATION_V1",
                    data = mapOf(
                        "turn_id" to ctx.turnId,
                        "violations" to contractViolationsV1.joinToString(","),
                        "resolution_commit_outcome_v1" to plan.resolutionCommitOutcomeV1.name,
                        "pending_after_kind" to pendingSummary(sAfter.pending),
                        "solve_resolution_apply_emitted_v1" to solveResolutionApplyEmittedV1,
                        "post_commit_continuation_requested_v1" to postCommitContinuationRequestedV1,
                        "post_commit_continuation_authorized_v1" to postCommitContinuationAuthorizedV1
                    )
                )
            }
        }

        val summary =
            "ops=${plan.ops.size}(ctrl=$ctrlCount) pending=${if (sAfter.pending == null) "none" else "yes"} " +
                    "facts=${factTypes.size}[${factTypes.joinToString(",")}] " +
                    "focus=${sAfter.focusCellIndex?.let { indexToCell(it) } ?: "none"} " +
                    "ua=${sAfter.userAgendaQueue.size} aa=${sAfter.appAgendaQueue.size}"

        ConversationTelemetry.emit(
            mapOf(
                "type" to "APP_PLAN_V1",
                "schema_version" to "v1.2",

                "session_id" to sAfter.sessionId,
                "turn_id" to ctx.turnId,
                "tick_id" to ctx.tickId,
                "policy_req_seq" to ctx.policyReqSeq,
                "correlation_id" to ctx.correlationId,
                "model_call_id" to ctx.modelCallId,
                "toolplan_id" to ctx.toolplanId,
                "tag" to "Planner",

                "summary" to summary,
                "payload" to mapOf(
                    "input" to mapOf(
                        "turn_id" to ctx.turnId,
                        "tick1_top_intent" to (top?.type?.name ?: "UNKNOWN"),
                        "tick1_intents_count" to env.intents.size,
                        "top_intent_constitution_bucket" to topIntentBucket
                    ),
                    "ops" to opsPayload,
                    "control" to ctrlPayload,
                    "state_transitions" to mapOf(
                        "mode_before" to sBefore.mode.name,
                        "mode_after" to sAfter.mode.name,
                        "phase_before" to sBefore.phase.name,
                        "phase_after" to sAfter.phase.name,
                        "focus_before" to sBefore.focusCellIndex,
                        "focus_after" to sAfter.focusCellIndex
                    ),
                    "pending" to mapOf(
                        "before" to pendingSummary(sBefore.pending),
                        "after" to pendingSummary(sAfter.pending),
                        "no_pending_reason" to noPendingReason
                    ),
                    "agenda_effects" to mapOf(
                        "authority_carrier_kind" to authorityCarrierKind,
                        "user_agenda_materialization_reason" to userAgendaMaterializationReason,
                        "user_agenda_removed_ids" to userRemoved,
                        "user_agenda_added" to userAdded,
                        "app_agenda_removed_ids" to appRemoved,
                        "app_agenda_added" to appAdded
                    ),
                    "evidence_selection" to mapOf(
                        "facts_selected_count" to plan.factBundles.size,
                        "fact_types" to factTypes,
                        "selection_reason_codes" to emptyList<String>()
                    ),
                    "boundary_authority" to mapOf(
                        "boundary_return_accepted_v1" to plan.boundaryReturnAcceptedV1,
                        "boundary_resume_policy_v1" to (plan.boundaryResumePolicyV1?.name ?: "null"),
                        "boundary_resume_checkpoint_step_id_v1" to (plan.boundaryResumeCheckpointStepIdV1 ?: "null"),
                        "boundary_truth_changed_on_return_v1" to plan.boundaryTruthChangedOnReturnV1,
                        "guard_mode" to boundaryContext.mode.name,
                        "effective_before_source" to boundaryContext.beforeSource.name,
                        "same_step_guard_enabled" to boundaryContext.sameStepGuardEnabled,
                        "trust_source" to boundaryContext.trustSource,
                        "recompute_replan_v1" to isBoundaryRecomputeReplanV1(
                            boundaryReturnAcceptedV1 = plan.boundaryReturnAcceptedV1,
                            boundaryResumePolicyV1 = plan.boundaryResumePolicyV1,
                            context = boundaryContext
                        ),
                        "effective_before_summary" to canonicalPositionSummaryV1(boundaryContext.effectiveBeforePos),
                        "effective_after_summary" to canonicalPositionSummaryV1(boundaryContext.afterPos)
                    ),
                    "resolution_commit_authority" to mapOf(
                        "resolution_commit_outcome_v1" to plan.resolutionCommitOutcomeV1.name,
                        "resolution_commit_cell_index_v1" to plan.resolutionCommitCellIndexV1,
                        "resolution_commit_digit_v1" to plan.resolutionCommitDigitV1,
                        "pending_after_kind" to pendingSummary(sAfter.pending),
                        "ops_include_apply_cell_edit" to plan.ops.any { it is PlannedOpV1.ApplyCellEdit },
                        "ops_include_solve_resolution_apply" to plan.ops.any { op ->
                            op is PlannedOpV1.ApplyCellEdit && op.source == "solve_resolution_apply"
                        },
                        "auto_commit_apply_hint_hybrid_violation_v1" to autoCommitApplyHintHybridViolationV1,
                        "manual_apply_with_apply_op_violation_v1" to manualApplyWithApplyOpViolationV1,
                        "duplicate_same_cell_apply_without_justification_v1" to duplicateSameCellApplyWithoutJustificationV1,
                        "delayed_auto_commit_echo_suppressed_v1" to plan.delayedAutoCommitEchoSuppressedV1
                    ),
                    "post_commit_continuation_v1" to mapOf(
                        "requested" to postCommitContinuationRequestedV1,
                        "authorized" to postCommitContinuationAuthorizedV1,
                        "pending_after_kind" to pendingSummary(sAfter.pending),
                        "queue_head_after" to (currentQueuedSolvingHead(sAfter)?.javaClass?.simpleName ?: "null"),
                        "stayed_without_blocker_v1" to stayedPostCommitWithoutBlockerV1
                    ),
                    "contract_audit_v1" to mapOf(
                        "violations" to contractViolationsV1,
                        "violation_count" to contractViolationsV1.size
                    ),
                    "errors" to emptyList<String>(),
                    "warnings" to emptyList<String>()
                )
            )
        )
    }

    private fun emitAgendaStateSnapshotV1(
        ctx: PolicyCallCtx,
        sBefore: SudoState,
        sAfter: SudoState
    ) {
        val userQ = sAfter.userAgendaQueue
        val appQ = sAfter.appAgendaQueue

        val reasonCode =
            if (sAfter.pending == null && userQ.isEmpty() && appQ.isEmpty())
                "NO_APP_AGENDA_AND_NO_USER_AGENDA"
            else if (sAfter.pending == null && userQ.isNotEmpty())
                "USER_AGENDA_PRESENT_NO_PENDING"
            else if (sAfter.pending == null && appQ.isNotEmpty())
                "APP_AGENDA_PRESENT_NO_PENDING"
            else
                "PENDING_PRESENT"

        val queuedSolvingBefore = currentQueuedSolvingHead(sBefore)?.javaClass?.simpleName
        val queuedSolvingAfter = currentQueuedSolvingHead(sAfter)?.javaClass?.simpleName
        val pendingAfterName = sAfter.pending?.javaClass?.simpleName ?: "none"

        val userAgendaRemovedIds =
            sBefore.userAgendaQueue.map { it.id }.toSet() - sAfter.userAgendaQueue.map { it.id }.toSet()
        val userAgendaAddedIds =
            sAfter.userAgendaQueue.map { it.id }.toSet() - sBefore.userAgendaQueue.map { it.id }.toSet()

        val userAgendaResolutionReason =
            when {
                userAgendaRemovedIds.isEmpty() ->
                    "NONE"

                userAgendaAddedIds.isNotEmpty() ->
                    "REPLACED_OR_REPRIORITIZED"

                sAfter.pending is Pending.ReturnToRoute ->
                    "RETURNED_TO_ROUTE"

                sAfter.pending is Pending.UserAgendaBridge ->
                    "USER_AGENDA_BRIDGE_ACTIVE"

                else ->
                    "RESOLVED_OR_CANCELLED"
            }

        val summary =
            "owner=${sAfter.activeTurnOwnerV1.name} " +
                    "overlayOwner=${sAfter.activeOverlayOwnerV1.name} " +
                    "phase=${sAfter.phase.name} " +
                    "pending=$pendingAfterName " +
                    "userQ=${userQ.size} appQ=${appQ.size} " +
                    "solvingHead=${queuedSolvingAfter ?: "none"} " +
                    "reason=$reasonCode"

        ConversationTelemetry.emit(
            mapOf(
                "type" to "AGENDA_STATE_SNAPSHOT",
                "schema_version" to "v1.2",

                "session_id" to sAfter.sessionId,
                "turn_id" to ctx.turnId,
                "tick_id" to ctx.tickId,
                "policy_req_seq" to ctx.policyReqSeq,
                "correlation_id" to ctx.correlationId,
                "model_call_id" to ctx.modelCallId,
                "toolplan_id" to ctx.toolplanId,
                "tag" to "Planner",

                "summary" to summary,
                "payload" to mapOf(
                    "queue_solving_head" to mapOf(
                        "before" to (queuedSolvingBefore ?: "null"),
                        "after" to (queuedSolvingAfter ?: "null")
                    ),

                    "pending" to mapOf(
                        "before" to pendingSummary(sBefore.pending),
                        "after" to pendingSummary(sAfter.pending),
                        "reason_code" to reasonCode,
                        "reason_detail" to mapOf(
                            "app_agenda_n" to appQ.size,
                            "user_agenda_n" to userQ.size,
                            "pending_is_projection_only" to true,
                            "detour_scaffold_active" to (sAfter.detourState?.isActive == true),
                            "detour_scaffold_question_class" to sAfter.detourState?.questionClass?.name,
                            "detour_scaffold_requested_cell" to sAfter.detourState?.requestedCell,
                            "detour_scaffold_requested_digit" to sAfter.detourState?.requestedDigit
                        )
                    ),

                    "user_agenda_resolution" to mapOf(
                        "removed_ids" to userAgendaRemovedIds.toList(),
                        "added_ids" to userAgendaAddedIds.toList(),
                        "reason" to userAgendaResolutionReason
                    ),

                    "user_agenda_queue" to mapOf(
                        "count" to userQ.size,
                        "items" to userQ.map { item ->
                            when (item) {
                                is UserAgendaItem.Clarification -> mapOf(
                                    "id" to item.id,
                                    "kind" to "CLARIFICATION",
                                    "status" to item.status.name,
                                    "parent_agenda_id" to item.parentAgendaId,
                                    "allows_follow_up" to item.allowsFollowUp,
                                    "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                                    "prompt" to item.prompt,
                                    "asked_turn_seq" to item.askedTurnSeq,
                                    "created_turn_seq" to item.createdTurnSeq,
                                    "missing" to item.missing
                                )

                                is UserAgendaItem.ProofChallenge -> mapOf(
                                    "id" to item.id,
                                    "kind" to "PROOF_CHALLENGE",
                                    "status" to item.status.name,
                                    "parent_agenda_id" to item.parentAgendaId,
                                    "allows_follow_up" to item.allowsFollowUp,
                                    "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                                    "cell_ref" to item.cellRef,
                                    "digit" to item.digit,
                                    "house_ref" to item.houseRef,
                                    "created_turn_seq" to item.createdTurnSeq
                                )

                                is UserAgendaItem.CandidateStateQuery -> mapOf(
                                    "id" to item.id,
                                    "kind" to "CANDIDATE_STATE_QUERY",
                                    "status" to item.status.name,
                                    "parent_agenda_id" to item.parentAgendaId,
                                    "allows_follow_up" to item.allowsFollowUp,
                                    "last_touched_turn_seq" to item.lastTouchedTurnSeq,
                                    "cell_refs" to item.cellRefs,
                                    "house_ref" to item.houseRef,
                                    "digit" to item.digit,
                                    "ask_kind" to item.askKind.name,
                                    "created_turn_seq" to item.createdTurnSeq
                                )

                                is UserAgendaItem.TargetCellQuery -> mapOf(
                                    "id" to item.id,
                                    "kind" to "TARGET_CELL_QUERY",
                                    "status" to item.status.name,
