    private fun emitGridFactsNowIfPresent(
        s: SudoState,
        ctx: PolicyCallCtx,
        stage: String,
        note: String? = null
    ) {




        val llm = s.grid?.llm
        if (llm == null) {
            ConversationTelemetry.emitKv(
                "GRID_FACTS_SNAPSHOT_SKIPPED",
                "session_id" to s.sessionId,
                "turn_id" to ctx.turnId,
                "tick_id" to ctx.tickId,
                "policy_req_seq" to ctx.policyReqSeq,
                "model_call_id" to ctx.modelCallId,
                "correlation_id" to ctx.correlationId,
                "toolplan_id" to ctx.toolplanId,
                "stage" to stage,
                "reason" to "grid.llm_null",
                "note" to note
            )
            return
        }

        // ✅ Your helper requires stage
        val payload = buildGridFactsSnapshotV1(llm, stage = stage)

        // ✅ This exists in ConversationTelemetry.kt
        ConversationTelemetry.emitGridFactsSnapshot(
            sessionId = s.sessionId,
            turnId = ctx.turnId,
            tickId = ctx.tickId,
            policyReqSeq = ctx.policyReqSeq,
            modelCallId = ctx.modelCallId,
            correlationId = ctx.correlationId,
            toolplanId = ctx.toolplanId,
            stage = stage,
            payload = payload
        )
    }



