    private fun eventTypeFromUserText(userText: String): String {
        val m = Regex("^\\[EVENT\\]\\s+([a-zA-Z0-9_\\-]+)").find(userText.trim())
        return m?.groupValues?.getOrNull(1) ?: "user_turn"
    }

    private fun pendingType(p: Pending?): String? = when (p) {
        null -> null
        is Pending.ConfirmEdit -> "confirm_edit"
        is Pending.AskCellValue -> "ask_cell_value"
        is Pending.ConfirmRetake -> "confirm_retake"
        is Pending.ConfirmValidate -> "confirm_validate"
        is Pending.ConfirmInterpretation -> "confirm_interpretation"
        is Pending.AskClarification -> "ask_clarification"
        is Pending.UserAgendaBridge -> "user_agenda_bridge"
        is Pending.WaitForTap -> "wait_for_tap"

        // North Star solving pendings
        is Pending.SolveIntroAction -> "solve_intro_action"
        is Pending.AfterResolution -> "after_resolution"
        is Pending.ApplyHintNow -> "apply_hint_now"
        is Pending.SolveStepMissing -> "solve_step_missing"
        is Pending.ReturnToRoute -> "return_to_route"

        else -> "pending_${p.javaClass.simpleName ?: "unknown"}"
    }

    private fun pendingIdx(p: Pending?): Int? = when (p) {
        is Pending.ConfirmEdit -> p.cellIndex
        is Pending.AskCellValue -> p.cellIndex
        else -> null
    }

    private fun pendingRow(p: Pending?): Int? = when (p) {
        is Pending.AskCellValue -> (p.cellIndex.coerceIn(0, 80) / 9) + 1
        is Pending.ConfirmEdit -> (p.cellIndex.coerceIn(0, 80) / 9) + 1
        is Pending.ConfirmInterpretation -> p.row
        is Pending.AskClarification -> p.rowHint
        is Pending.UserAgendaBridge -> p.rowHint
        else -> null
    }

    private fun pendingCol(p: Pending?): Int? = when (p) {
        is Pending.AskCellValue -> (p.cellIndex.coerceIn(0, 80) % 9) + 1
        is Pending.ConfirmEdit -> (p.cellIndex.coerceIn(0, 80) % 9) + 1
        is Pending.ConfirmInterpretation -> p.col
        is Pending.AskClarification -> p.colHint
        is Pending.UserAgendaBridge -> p.colHint
        else -> null
    }

    private fun pendingDigit(p: Pending?): Int? = when (p) {
        is Pending.ConfirmEdit -> p.proposedDigit
        is Pending.ConfirmInterpretation -> p.digit
        is Pending.AskClarification -> p.digitHint
        is Pending.UserAgendaBridge -> p.digitHint
        is Pending.WaitForTap -> p.digitHint
        else -> null
    }

    private fun emitPolicyCallTrace(
        traceState: SudoState,
        userText: String,
        stateHeader: String,
        reason: String,
        turnId: Long,
        ctx: PolicyCallCtx,
        extraData: Map<String, Any?> = emptyMap()
    ) {
        val repair = parseRepairInfo(stateHeader)
        val headerSha12 = try {
            ConversationTelemetry.sha256Hex(stateHeader).take(12)
        } catch (_: Throwable) {
            null
        }

        // Correlation span: deterministic per turn for easy join in audits.
        val correlationId = "turn-$turnId"

        runCatching {
            val turnSeqInt: Int? = traceState.turnSeq
                .coerceIn(0L, Int.MAX_VALUE.toLong())
                .toInt()

            ConversationTelemetry.emitTurnContextBind(
                turnId = turnId,
                turnSeq = turnSeqInt,
                rowId = null,
                correlationId = correlationId,
                note = "policy_call_trace"
            )
        }

        runCatching {
            val inputId = "in-$turnId"
            ConversationTelemetry.emitUserInputClassified(
                inputId = inputId,
                turnId = turnId,
                rowId = null,
                source = "user_turn",
                rawText = userText,
                normalizedText = userText,
                pendingType = pendingType(traceState.pending),
                pendingIdx = pendingIdx(traceState.pending)
            )
        }

        val base = mapOf(
            "event_type" to eventTypeFromUserText(userText),
            "reason" to reason,
            "correlation_id" to correlationId,
            "mode" to traceState.mode.name,
            "turn_seq" to traceState.turnSeq,
            "turn_id" to turnId,

            "model_call_id" to ctx.modelCallId,
            "toolplan_id" to ctx.toolplanId,
            "policy_req_seq" to ctx.policyReqSeq,

            "pending_type" to pendingType(traceState.pending),
            "pending_idx" to pendingIdx(traceState.pending),
            "pending_row" to pendingRow(traceState.pending),
            "pending_col" to pendingCol(traceState.pending),
            "pending_digit" to pendingDigit(traceState.pending),

            "repair_mode" to repair.repairMode,
            "repair_reason" to repair.repairReason,
            "state_header_sha12" to headerSha12
        )

        // Merge in optional diagnostics (kept flat for easy CSV filtering).
        val merged = base + extraData

        ConversationTelemetry.emitPolicyTrace(
            tag = "POLICY_CALL",
            data = merged
        )
    }





    private fun rcFromIdx0(idx: Int): Pair<Int, Int> {
        val r = (idx / 9) + 1
        val c = (idx % 9) + 1
        return r to c
    }



    private fun llmGrid(s: SudoState): LLMGridState? = s.grid?.llm as? LLMGridState


    private fun indexToCell(idx: Int): String {
        val i = idx.coerceIn(0, 80)
        val r = (i / 9) + 1
        val c = (i % 9) + 1
        return "r${r}c${c}"
    }

    private fun chooseFocusIdxForIntake(llm: LLMGridState): Int? {
        // Priority: conflicts > mismatches > low confidence > unresolved
        val c = llm.conflictCells.firstOrNull()
        if (c != null) return c.coerceIn(0, 80)

        val m = llm.mismatchCells.firstOrNull()
        if (m != null) return m.coerceIn(0, 80)

        val l = llm.lowConfidenceCells.firstOrNull()
        if (l != null) return l.coerceIn(0, 80)

        val u = llm.unresolvedCells.firstOrNull()
        if (u != null) return u.coerceIn(0, 80)

        return null
    }

    fun buildAppAgendaFromGrid(
        llm: LLMGridState?,
        phase: GridPhase,
        createdTurnSeq: Long,
        userConfirmedPerfectMatch: Boolean,
        retakeDismissed: Boolean,
        startSolvingCtaActive: Boolean
    ): List<AppAgendaItem> {

        if (llm == null) return emptyList()

        // CONFIRMING/SEALING agenda (capture → confirming → sealing)
        if (phase != GridPhase.SOLVING) {
            val solv = llm.solvability.trim().lowercase()

            // Canonical handover:
            // unique solvability is NOT enough to start solving.
            // First require exact-match human signoff; only afterwards may we
            // finalize presentation and ask to start solving.
            if (solv == "unique") {
                return when {
                    !userConfirmedPerfectMatch ->
                        listOf(
                            AppAgendaItem.ConfirmValidationExactMatch(
                                reason = "solvability_unique_needs_exact_match_signoff",
                                createdTurnSeq = createdTurnSeq
                            )
                        )

                    !startSolvingCtaActive ->
                        listOf(
                            AppAgendaItem.FinalizeValidationStartSolving(
                                reason = "solvability_unique_after_exact_match_signoff",
                                createdTurnSeq = createdTurnSeq
                            )
                        )

                    else -> emptyList()
                }
            }

            if (solv == "multiple") {
                return if (userConfirmedPerfectMatch) {
                    listOf(
                        AppAgendaItem.RecommendDifferentGrid(
                            reason = "not_unique_after_user_confirmed_match",
                            createdTurnSeq = createdTurnSeq
                        )
                    )
                } else {
                    listOf(
                        AppAgendaItem.VisualVerificationRequest(
                            reason = "multiple_solutions_needs_visual_verification",
                            createdTurnSeq = createdTurnSeq
                        )
                    )
                }
            }

            // From here on, solvability == "none": repair agenda only.
            val out = mutableListOf<AppAgendaItem>()

            // AGENDA repair order: mismatch -> conflict -> low confidence -> unresolved
            llm.mismatchCells.forEach { idx0 ->
                val idx = idx0.coerceIn(0, 80)
                val scanned = llm.correctedGrid.getOrNull(idx)?.coerceIn(0, 9) ?: 0
                val expected = llm.deducedSolutionGrid?.getOrNull(idx)?.coerceIn(0, 9) ?: 0
                if (expected in 1..9) {
                    out += AppAgendaItem.MismatchReview(
                        cellIndex = idx,
                        scannedDigit = scanned,
                        expectedDigit = expected,
                        reason = "mismatch_vs_deduced",
                        createdTurnSeq = createdTurnSeq
                    )
                }
            }

            val confirmed = llm.confirmedCells.toSet()
            val mismatch = llm.mismatchCells.toSet()

            fun conflictHouseCount(idx: Int): Int {
                val i = idx.coerceIn(0, 80)
                val d = llm.correctedGrid.getOrNull(i)?.coerceIn(0, 9) ?: 0
                if (d !in 1..9) return 0

                fun rowOf(x: Int) = x / 9
                fun colOf(x: Int) = x % 9

                val r = rowOf(i)
                val c = colOf(i)

                var rowDup = false
                var colDup = false
                var boxDup = false

                for (cc in 0 until 9) {
                    val j = r * 9 + cc
                    if (j != i && (llm.correctedGrid.getOrNull(j)?.coerceIn(0, 9) ?: 0) == d) { rowDup = true; break }
                }
                for (rr in 0 until 9) {
                    val j = rr * 9 + c
                    if (j != i && (llm.correctedGrid.getOrNull(j)?.coerceIn(0, 9) ?: 0) == d) { colDup = true; break }
                }
                val r0 = (r / 3) * 3
                val c0 = (c / 3) * 3
                loop@ for (dr in 0..2) for (dc in 0..2) {
                    val j = (r0 + dr) * 9 + (c0 + dc)
                    if (j != i && (llm.correctedGrid.getOrNull(j)?.coerceIn(0, 9) ?: 0) == d) { boxDup = true; break@loop }
                }

                return (if (rowDup) 1 else 0) + (if (colDup) 1 else 0) + (if (boxDup) 1 else 0)
            }

            fun pushConflictRanked(conflictIdxs: List<Int>) {
                val ranked = conflictIdxs
                    .map { it.coerceIn(0, 80) }
                    .distinct()
                    .filter { idx -> !confirmed.contains(idx) && !mismatch.contains(idx) }
                    .sortedWith(
                        compareByDescending<Int> { conflictHouseCount(it) }
                            .thenBy { if (llm.truthIsGiven.getOrNull(it) == true) 1 else 0 }
                            .thenBy { it }
                    )

                ranked.forEach { idx ->
                    out += AppAgendaItem.ConflictReview(
                        cellIndex = idx,
                        reason = "conflict",
                        createdTurnSeq = createdTurnSeq
                    )
                }
            }

            fun pushConflictUnranked(idxs: List<Int>, reason: String) {
                idxs.forEach { idx0 ->
                    val idx = idx0.coerceIn(0, 80)
                    if (confirmed.contains(idx)) return@forEach
                    if (mismatch.contains(idx)) return@forEach
                    out += AppAgendaItem.ConflictReview(
                        cellIndex = idx,
                        reason = reason,
                        createdTurnSeq = createdTurnSeq
                    )
                }
            }

            pushConflictRanked(llm.conflictCells)
            pushConflictUnranked(llm.lowConfidenceCells, "low_confidence")
            pushConflictUnranked(llm.unresolvedCells, "unresolved")

            val retake = llm.retakeRecommendation.trim().lowercase()
            if (!retakeDismissed && (retake == "strong" || retake == "soft")) {
                out += AppAgendaItem.RetakeDecision(
                    strength = retake,
                    reason = "retake_recommendation_$retake",
                    createdTurnSeq = createdTurnSeq
                )
            }

            return out
        }

        // SOLVING agenda (Phase 1): seed a first-class solving agenda head.
        val gridHash12 = sha12(grid81FromLLM(llm)).take(12)

        return listOf(
            AppAgendaItem.Solving.StepIntro(
                agendaId = "solving_step_intro_${createdTurnSeq}_${System.currentTimeMillis()}",
                createdAtMs = System.currentTimeMillis(),
                createdTurnSeq = createdTurnSeq,
                stepIndex = 0,
                route = ActiveRouteContextV2(
                    gridHash12 = gridHash12,
                    stepId = null,
                    stepHash12 = null,
                    techniqueId = null,
                    targetCell = null,
                    createdAtMs = System.currentTimeMillis(),
                    routeVersion = 1
                ),
                techniqueId = null,
                techniqueName = null,
                mission = null,
                allowAskTechnique = true,
                allowDetour = true,
                allowWalkback = true
            )
        )
    }

    private fun buildIntakeFactBundlesV1(
        llm: LLMGridState,
        pending: Pending?,
        focusIdx: Int?,
        userConfirmedPerfectMatch: Boolean
    ): List<FactBundleV1> {
        val out = mutableListOf<FactBundleV1>()


        // ------------------------------------------------------------
        // PATCH 3.5 helpers: derive row/col/box snapshots + conflict partners
        // from correctedGrid (truthful, no invention).
        // ------------------------------------------------------------

        fun rowOf(idx: Int): Int = idx / 9
        fun colOf(idx: Int): Int = idx % 9
        fun boxOf(idx: Int): Int = (rowOf(idx) / 3) * 3 + (colOf(idx) / 3)

        fun rowIndices(idx: Int): IntArray {
            val r = rowOf(idx)
            return IntArray(9) { c -> r * 9 + c }
        }

        fun colIndices(idx: Int): IntArray {
            val c = colOf(idx)
            return IntArray(9) { r -> r * 9 + c }
        }

        fun boxIndices(idx: Int): IntArray {
            val r0 = (rowOf(idx) / 3) * 3
            val c0 = (colOf(idx) / 3) * 3
            val outIdx = IntArray(9)
            var k = 0
            for (dr in 0..2) for (dc in 0..2) {
                outIdx[k++] = (r0 + dr) * 9 + (c0 + dc)
            }
            return outIdx
        }

        fun cellObj(i: Int, focusIdxLocal: Int?): JSONObject {
            val d = llm.correctedGrid[i.coerceIn(0, 80)].coerceIn(0, 9)
            return JSONObject().apply {
                put("idx", i)
                put("cell", indexToCell(i))
                put("digit", d)
                put("is_focus", focusIdxLocal != null && i == focusIdxLocal)
                put("is_given", llm.truthIsGiven.getOrNull(i) == true)
                put("is_solution", llm.truthIsSolution.getOrNull(i) == true)
                put("is_confirmed", llm.confirmedCells.contains(i))
            }
        }

        fun houseSnapshot(kind: String, idx: Int, focusIdxLocal: Int?): JSONObject {
            val indices = when (kind) {
                "row" -> rowIndices(idx)
                "col" -> colIndices(idx)
                else -> boxIndices(idx) // "box"
            }
            return JSONObject().apply {
                put("kind", kind)
                put("indices", indices.toList())
                put("cells", org.json.JSONArray().apply {
                    indices.forEach { put(cellObj(it, focusIdxLocal)) }
                })
            }
        }

        fun conflictPartnersForIdx(idx: Int): JSONObject {
            val d = llm.correctedGrid[idx.coerceIn(0, 80)].coerceIn(0, 9)
            val r = rowIndices(idx)
            val c = colIndices(idx)
            val b = boxIndices(idx)

            fun sameDigitPartners(indices: IntArray): List<Int> =
                if (d !in 1..9) emptyList()
                else indices.filter { it != idx && llm.correctedGrid[it].coerceIn(0, 9) == d }

            val rowPartners = sameDigitPartners(r)
            val colPartners = sameDigitPartners(c)
            val boxPartners = sameDigitPartners(b)

            val all = (rowPartners + colPartners + boxPartners).distinct().sorted()

            return JSONObject().apply {
                put("focus_digit", d)
                put("row_partners", rowPartners.map { indexToCell(it) })
                put("col_partners", colPartners.map { indexToCell(it) })
                put("box_partners", boxPartners.map { indexToCell(it) })
                put("all_partners", all.map { indexToCell(it) })
                put("all_partner_indices", all)
            }
        }


        // SOLVABILITY_STATUS is extremely important for 183-style behavior.
        out += FactBundleV1(
            type = FactBundleV1.Type.SOLVABILITY_STATUS,
            payload = JSONObject().apply {
                put("solvability", llm.solvability) // "unique"|"multiple"|"none"
                put("is_structurally_valid", llm.isStructurallyValid)
                put("unresolved_count", llm.unresolvedCount)
                put("deduced_solution_count_capped", llm.deducedSolutionCountCapped)
                put("severity", llm.severity)
            }
        )

        // Retake hint (bounded) — do NOT force, just provide.
        out += FactBundleV1(
            type = FactBundleV1.Type.RETAKE_RECOMMENDATION,
            payload = JSONObject().apply {
                put("retake_recommendation", llm.retakeRecommendation) // e.g. "none"|"soft"|"strong"
                put("low_conf_cells", llm.lowConfidenceCells.size)
                put("conflict_cells", llm.conflictCells.size)
                put("mismatch_cells", llm.mismatchCells.size)
            }
        )

        if (focusIdx != null) {
            val cell = indexToCell(focusIdx)
            val digit = llm.correctedGrid[focusIdx.coerceIn(0, 80)].coerceIn(0, 9)

            // ✅ Standardized ref objects (keep legacy string fields too)
            val cellRef = cellRefV1(cell)

            out += FactBundleV1(
                type = FactBundleV1.Type.FOCUS_CELL_SNAPSHOT,
                payload = JSONObject().apply {
                    // legacy
                    put("cell", cell)
                    put("digit", digit)

                    // new standard
                    put("cell_ref", cellRef)
                    put("display_digit", digit)
                    put("is_conflict", llm.conflictCells.contains(focusIdx))
                    put("is_low_confidence", llm.lowConfidenceCells.contains(focusIdx))
                    put("is_unresolved", llm.unresolvedCells.contains(focusIdx))
                    put("is_confirmed", llm.confirmedCells.contains(focusIdx))

                    put("reason_code", when {
                        llm.conflictCells.contains(focusIdx) -> "CONFLICT"
                        llm.mismatchCells.contains(focusIdx) -> "MISMATCH_VS_DEDUCED"
                        llm.lowConfidenceCells.contains(focusIdx) -> "LOW_CONFIDENCE_OCR"
                        llm.unresolvedCells.contains(focusIdx) -> "UNRESOLVED_EMPTY"
                        else -> "UNKNOWN"
                    })

                    // PATCH 3.5: rich context snapshots (truthful derivations)
                    put("row_snapshot", houseSnapshot("row", focusIdx, focusIdx))
                    put("col_snapshot", houseSnapshot("col", focusIdx, focusIdx))
                    put("box_snapshot", houseSnapshot("box", focusIdx, focusIdx))

                    val expected = llm.deducedSolutionGrid?.getOrNull(focusIdx)?.coerceIn(0, 9) ?: 0
                    put("expected_digit_from_deduced", expected)
                }
            )

            if (llm.conflictCells.contains(focusIdx)) {
                val sampleCells = llm.conflictCells.take(6).map { indexToCell(it) }
                val sampleRefs = sampleCells.map { cellRefV1(it) }

                out += FactBundleV1(
                    type = FactBundleV1.Type.CONFLICT_EXPLANATION,
                    payload = JSONObject().apply {
                        // legacy
                        put("cell", cell)
                        put("conflict_cells_sample", sampleCells)

                        // new standard
                        put("cell_ref", cellRef)
                        put("conflict_cell_refs_sample", jsonArrayOfObjects(sampleRefs))
                        put("conflict_count", llm.conflictCells.size)

                        // PATCH 3.5: derive the specific conflict partners for this focused cell
                        // (same digit duplicates in row/col/box).
                        put("conflict_partners", conflictPartnersForIdx(focusIdx))

                        // PATCH 3.5: add row/col/box snapshots for explanation
                        put("row_snapshot", houseSnapshot("row", focusIdx, focusIdx))
                        put("col_snapshot", houseSnapshot("col", focusIdx, focusIdx))
                        put("box_snapshot", houseSnapshot("box", focusIdx, focusIdx))
                    }
                )
            }

            if (llm.mismatchCells.contains(focusIdx)) {
                val sampleCells = llm.mismatchCells.take(6).map { indexToCell(it) }
                val sampleRefs = sampleCells.map { cellRefV1(it) }

                out += FactBundleV1(
                    type = FactBundleV1.Type.MISMATCH_EXPLANATION,
                    payload = JSONObject().apply {
                        // legacy
                        put("cell", cell)
                        put("mismatch_cells_sample", sampleCells)
                        put("mismatch_details_sample", llm.mismatchDetails.take(4))
                        put("mismatch_count", llm.mismatchCells.size)

                        // new standard
                        put("cell_ref", cellRef)
                        put("mismatch_cell_refs_sample", jsonArrayOfObjects(sampleRefs))

                        // PATCH 3.5: enrich mismatch with expected digit + context snapshots
                        val expected = llm.deducedSolutionGrid?.getOrNull(focusIdx)?.coerceIn(0, 9) ?: 0
                        put("expected_digit_from_deduced", expected)
                        put("display_digit_now", digit)

                        put("row_snapshot", houseSnapshot("row", focusIdx, focusIdx))
                        put("col_snapshot", houseSnapshot("col", focusIdx, focusIdx))
                        put("box_snapshot", houseSnapshot("box", focusIdx, focusIdx))

                        // If the current digit duplicates someone in a house, include partners too (may explain “why mismatch creates conflicts”)
                        put("conflict_partners_if_any", conflictPartnersForIdx(focusIdx))
                    }
                )
            }
        }

        // Phase 2: Pending is internal. Tick2 receives:
//  (1) PENDING_CONTEXT_V1 (facts: prompt/targets/expected answer)
//  (2) exactly one CTA_PACKET_V1 (contract)
        if (pending != null) {

            val ctx = JSONObject().apply {
                when (pending) {

                    is Pending.AskCellValue -> {
                        val idx = pending.cellIndex.coerceIn(0, 80)
                        val cell = indexToCell(idx)
                        val r = (idx / 9) + 1
                        val c = (idx % 9) + 1

                        put("pending_type", "ask_cell_value")
                        put("expected_answer_kind", "DIGIT")
                        put("row", r)
                        put("col", c)
                        put("cell_ref", cellRefV1(cell))
                        put("prompt", pending.prompt)
                    }

                    is Pending.ProvideDigit -> {
                        put("pending_type", "provide_digit")
                        put("expected_answer_kind", "DIGIT")
                        put("cell_ref", pending.cellIndex?.let { idx ->
                            cellRefV1(indexToCell(idx.coerceIn(0, 80)))
                        } ?: JSONObject.NULL)
                        put("row_hint", pending.row ?: JSONObject.NULL)
                        put("col_hint", pending.col ?: JSONObject.NULL)
                        put("prompt", pending.prompt)
                    }

                    is Pending.ConfirmEdit -> {
                        val idx = pending.cellIndex.coerceIn(0, 80)
                        val cell = indexToCell(idx)
                        val r = (idx / 9) + 1
                        val c = (idx % 9) + 1

                        put("pending_type", "confirm_edit")
                        put("expected_answer_kind", "YES_NO_OR_DIGIT")
                        put("row", r)
                        put("col", c)
                        put("cell_ref", cellRefV1(cell))
                        put("proposed_digit", pending.proposedDigit)
                        put("prompt", pending.prompt)
                    }

                    is Pending.ConfirmCellAsIs -> {
                        val idx = pending.cellIndex.coerceIn(0, 80)
                        val cell = indexToCell(idx)
                        put("pending_type", "confirm_cell_as_is")
                        put("expected_answer_kind", "YES_NO")
                        put("cell_ref", cellRefV1(cell))
                        put("prompt", pending.prompt)
                        put("source", pending.source)
                    }

                    is Pending.ConfirmCellToDigit -> {
                        val idx = pending.cellIndex.coerceIn(0, 80)
                        val cell = indexToCell(idx)
                        put("pending_type", "confirm_cell_to_digit")
                        put("expected_answer_kind", "YES_NO_OR_DIGIT")
                        put("cell_ref", cellRefV1(cell))
                        put("proposed_digit", pending.proposedDigit)
                        put("prompt", pending.prompt)
                        put("source", pending.source)
                    }

                    is Pending.ConfirmRegionAsIs -> {
                        put("pending_type", "confirm_region_as_is")
                        put("expected_answer_kind", "YES_NO")
                        put("region_kind", pending.regionKind)
                        put("region_index_1based", pending.regionIndex1Based)
                        put("prompt", pending.prompt)
                        put("source", pending.source)
                    }

                    is Pending.ConfirmRegionToDigits -> {
                        put("pending_type", "confirm_region_to_digits")
                        put("expected_answer_kind", "YES_NO_OR_DIGITS")
                        put("region_kind", pending.regionKind)
                        put("region_index_1based", pending.regionIndex1Based)
                        put("digits", JSONArray().apply { pending.digits.forEach { put(it) } })
                        put("prompt", pending.prompt)
                        put("source", pending.source)
                    }

                    is Pending.ConfirmRetake -> {
                        put("pending_type", "confirm_retake")
                        put("expected_answer_kind", "CHOICE")
                        put("strength", pending.strength)
                        put("prompt", pending.prompt)
                    }

                    is Pending.ConfirmValidate -> {
                        put("pending_type", "confirm_validate")
                        put("expected_answer_kind", "YES_NO")
                        put("prompt", pending.prompt)
                    }

                    is Pending.ConfirmStartSolving -> {
                        put("pending_type", "confirm_start_solving")
                        put("expected_answer_kind", "YES_NO")
                        put("prompt", pending.prompt)
                    }

                    is Pending.VisualVerifyMatch -> {
                        put("pending_type", "visual_verify_match")
                        put("expected_answer_kind", "YES_NO_OR_EDITS")
                        put("prompt", pending.prompt)
                    }

                    is Pending.ConfirmInterpretation -> {
                        put("pending_type", "confirm_interpretation")
                        put("expected_answer_kind", "YES_NO")
                        put("row_hint", pending.row ?: JSONObject.NULL)
                        put("col_hint", pending.col ?: JSONObject.NULL)
                        put("digit_hint", pending.digit ?: JSONObject.NULL)
                        put("confidence", pending.confidence.toDouble())
                        put("prompt", pending.prompt)
                    }

                    is Pending.AskClarification -> {
                        put("pending_type", "ask_clarification")
                        put("expected_answer_kind", "FREEFORM_STRUCTURED")
                        put("kind", pending.kind.name)
                        put("row_hint", pending.rowHint ?: JSONObject.NULL)
                        put("col_hint", pending.colHint ?: JSONObject.NULL)
                        put("digit_hint", pending.digitHint ?: JSONObject.NULL)
                        put(
                            "cell_ref",
                            if (pending.rowHint != null && pending.colHint != null) {
                                "r${pending.rowHint}c${pending.colHint}"
                            } else {
                                JSONObject.NULL
                            }
                        )
                        put(
                            "missing_fields",
                            JSONArray().apply {
                                if (pending.rowHint == null && pending.colHint == null) {
                                    put("target")
                                } else {
                                    if (pending.rowHint == null) put("row")
                                    if (pending.colHint == null) put("col")
                                }
                                if (pending.digitHint == null) {
                                    put("digit")
                                }
                            }
                        )
                        put("preferred_user_facing_question", pending.prompt)
                        put("prompt", pending.prompt)
                    }

                    is Pending.UserAgendaBridge -> {
                        put("pending_type", "user_agenda_bridge")
                        put("expected_answer_kind", pending.expectedAnswerKind)
                        put("user_agenda_id", pending.userAgendaId)
                        put("agenda_kind", pending.agendaKind)
                        put("row_hint", pending.rowHint ?: JSONObject.NULL)
                        put("col_hint", pending.colHint ?: JSONObject.NULL)
                        put("digit_hint", pending.digitHint ?: JSONObject.NULL)
                        put("cell_ref", pending.cellRef ?: JSONObject.NULL)
                        put("agenda_status", pending.agendaStatus ?: JSONObject.NULL)
                        put("allows_follow_up", pending.allowsFollowUp)
                        put("options", JSONArray().apply { pending.options.forEach { put(it) } })
                        put("prompt", pending.prompt)
                    }

                    is Pending.WaitForTap -> {
                        put("pending_type", "wait_for_tap")
                        put("expected_answer_kind", "TAP")
                        put("digit_hint", pending.digitHint ?: JSONObject.NULL)
                        put("confidence", pending.confidence.toDouble())
                        put("prompt", pending.prompt)
                    }

                    is Pending.SolveStepMissing -> {
                        put("pending_type", "solve_step_missing")
                        put("expected_answer_kind", "CHOICE")
                        put("grid_hash12", pending.gridHash12 ?: JSONObject.NULL)
                        put("prompt", pending.prompt)

                        put("fallback_commit", pending.autoApplyFallback)
                        put("fallback_step_id", pending.fallbackStepId ?: JSONObject.NULL)
                        put(
                            "fallback_cell",
                            pending.fallbackCellIndex?.let { indexToCell(it) } ?: JSONObject.NULL
                        )
                        put("fallback_digit", pending.fallbackDigit ?: JSONObject.NULL)
                        put("fallback_technique", pending.fallbackTechnique ?: JSONObject.NULL)
                        put("fallback_failure_reason", pending.fallbackFailureReason ?: JSONObject.NULL)
                    }

                    is Pending.SolveIntroAction -> {
                        put("pending_type", "solve_intro_action")
                        put("expected_answer_kind", "CHOICE")
                        put("step_id", pending.stepId)
                        put("atom_index", pending.atomIndex)
                        put("atoms_count", pending.atomsCount)
                        put("is_last_hint", pending.isLastHint)
                        put("grid_hash12", pending.gridHash12)
                        put("options", JSONArray().apply { pending.options.forEach { put(it) } })
                        put("prompt", pending.prompt)
                    }

                    is Pending.AfterResolution -> {
                        put("pending_type", "after_resolution")
                        put("expected_answer_kind", "CHOICE")
                        put("step_id", pending.stepId)
                        put("grid_hash12", pending.gridHash12)
                        put("options", JSONArray().apply { pending.options.forEach { put(it) } })
                        put("prompt", pending.prompt)
                    }

                    is Pending.ApplyHintNow -> {
                        put("pending_type", "apply_hint_now")
                        put("expected_answer_kind", "CHOICE")
                        put("step_id", pending.stepId)
                        put("grid_hash12", pending.gridHash12)
                        put("options", JSONArray().apply { pending.options.forEach { put(it) } })
                        put("prompt", pending.prompt)
                    }

                    is Pending.ReturnToRoute -> {
                        put("pending_type", "return_to_route")
                        put("expected_answer_kind", "CHOICE")
                        put("prompt", pending.prompt)
                        put("options", JSONArray().apply { pending.options.forEach { put(it) } })
                    }
                }
            }

            out += factPendingContextV1(ctx)
            out += FactBundleV1(
                type = FactBundleV1.Type.CTA_PACKET_V1,
                payload = pendingToCtaPacketV1(pending).toJson()
            )
        }

        // ------------------------------------------------------------
        // PATCH 3: Add ONE step-specific CONFIRMING agenda packet per turn.
        // This prevents "evidence missing" and makes narration deterministic.
        // ------------------------------------------------------------
        val solv = llm.solvability.trim().lowercase() // "unique"|"multiple"|"none"

        if (pending != null) {
            when (pending) {

                is Pending.ConfirmRetake -> {
                    out += FactBundleV1(
                        type = FactBundleV1.Type.CONFIRMING_RETAKE_PACKET,
                        payload = JSONObject().apply {
                            put("retake_recommendation", llm.retakeRecommendation)
                            put("strength", pending.strength)
                            put("severity", llm.severity)
                            put("low_conf_cells", llm.lowConfidenceCells.size)
                            put("conflict_cells", llm.conflictCells.size)
                            put("mismatch_cells", llm.mismatchCells.size)
                            put("unresolved_cells", llm.unresolvedCells.size)
                            put("policy", "User may retake or stay to resolve issues one-by-one. Silence defaults to stay-and-fix.")
                        }
                    )
                }

                is Pending.ConfirmEdit -> {
                    val idx = pending.cellIndex.coerceIn(0, 80)
                    val scanned = llm.correctedGrid.getOrNull(idx)?.coerceIn(0, 9) ?: 0
                    val partners = conflictPartnersForIdx(idx)
                    val violatesRow = partners.optJSONArray("row_partners")?.length()?.let { it > 0 } ?: false
                    val violatesCol = partners.optJSONArray("col_partners")?.length()?.let { it > 0 } ?: false
                    val violatesBox = partners.optJSONArray("box_partners")?.length()?.let { it > 0 } ?: false

                    out += FactBundleV1(
                        type = FactBundleV1.Type.CONFIRMING_MISMATCH_PACKET,
                        payload = JSONObject().apply {
                            put("cell", indexToCell(idx))
                            put("cell_index", idx)
                            put("scanned_digit", scanned)
                            put("expected_digit", pending.proposedDigit)
                            put("mismatch_count", llm.mismatchCells.size)
                            put("conflict_count", llm.conflictCells.size)

                            // First-class conflict implications (VISION requirement)
                            put("conflict_implications", JSONObject().apply {
                                put("focus_digit", partners.optInt("focus_digit", 0))
                                put("violated_houses", org.json.JSONArray().apply {
                                    if (violatesRow) put("ROW")
                                    if (violatesCol) put("COL")
                                    if (violatesBox) put("BOX")
                                })
                                put("partners", partners)
                            })

                            // Make the “update paper” instruction hard-requirement for Tick2
                            put("paper_update_required", true)
                            put("paper_update_verbatim", "I applied that change—please update it on your paper too.")

                            put(
                                "instruction",
                                "Explain why it’s a mismatch and propose the edit. If accepted, the app applies immediately. You MUST tell the user to correct the same digit on their paper."
                            )
                        }
                    )
                }

                is Pending.AskCellValue -> {
                    val idx = pending.cellIndex.coerceIn(0, 80)
                    val partners = conflictPartnersForIdx(idx)
                    val violatesRow = partners.optJSONArray("row_partners")?.length()?.let { it > 0 } ?: false
                    val violatesCol = partners.optJSONArray("col_partners")?.length()?.let { it > 0 } ?: false
                    val violatesBox = partners.optJSONArray("box_partners")?.length()?.let { it > 0 } ?: false

                    out += FactBundleV1(
                        type = FactBundleV1.Type.CONFIRMING_CONFLICT_PACKET,
                        payload = JSONObject().apply {
                            put("cell", indexToCell(idx))
                            put("cell_index", idx)
                            put("reason_code", when {
                                llm.conflictCells.contains(idx) -> "CONFLICT"
                                llm.lowConfidenceCells.contains(idx) -> "LOW_CONFIDENCE_OCR"
                                llm.unresolvedCells.contains(idx) -> "UNRESOLVED_EMPTY"
                                else -> "CONFIRM_CELL"
                            })
                            put("conflict_count", llm.conflictCells.size)
                            put("low_conf_count", llm.lowConfidenceCells.size)
                            put("unresolved_count", llm.unresolvedCells.size)

                            // First-class structured tracking (VISION requirement)
                            put("conflict_implications", JSONObject().apply {
                                put("focus_digit", partners.optInt("focus_digit", 0))
                                put("violated_houses", org.json.JSONArray().apply {
                                    if (violatesRow) put("ROW")
                                    if (violatesCol) put("COL")
                                    if (violatesBox) put("BOX")
                                })
                                put("partners", partners)
                            })

                            put("instruction", "Ask user to verify the digit from the book/paper. Mention which house(s) it conflicts with and the partner cell(s). If they provide a new value, the app will apply edit + confirm.")
                        }
                    )
                }

                is Pending.VisualVerifyMatch -> {
                    out += FactBundleV1(
                        type = FactBundleV1.Type.CONFIRMING_VISUAL_VERIFY_PACKET,
                        payload = JSONObject().apply {
                            put("solvability", llm.solvability)
                            put("user_confirmed_match_already", userConfirmedPerfectMatch)
                            put("is_structurally_valid", llm.isStructurallyValid)
                            put("conflict_count", llm.conflictCells.size)
                            put("mismatch_count", llm.mismatchCells.size)
                            put("low_conf_count", llm.lowConfidenceCells.size)
                            put("unresolved_count", llm.unresolvedCount)

                            put("likely_primary_cause", "missing_or_misread_givens")
                            put("likely_causes_ranked", org.json.JSONArray().apply {
                                put("One or more printed givens are missing from the scan and came through blank.")
                                put("One or more givens were misread and now show the wrong digit on screen.")
                                put("Less likely: the source puzzle itself is not a proper uniquely solvable standard Sudoku.")
                            })

                            put(
                                "instruction",
                                "Explain clearly that there are no visible rule conflicts on screen, but the current givens still do not produce a single unique solution. Say that the most likely explanation is a missing or misread given from the scan. Ask the user to compare paper vs screen cell-by-cell and either confirm a perfect match or provide exact cell corrections. Sound confident and diagnostic, not vague."
                            )
                        }
                    )
                }

                is Pending.WaitForTap -> {
                    // This packet is mainly for AGENDA 5: not uniquely solvable after user confirmed perfect match.
                    if (userConfirmedPerfectMatch && (solv == "multiple" || solv == "none")) {
                        out += FactBundleV1(
                            type = FactBundleV1.Type.CONFIRMING_NOT_UNIQUE_PACKET,
                            payload = JSONObject().apply {
                                put("solvability", llm.solvability)
                                put("user_confirmed_perfect_match", true)
                                put("is_structurally_valid", llm.isStructurallyValid)
                                put("conflict_cells", llm.conflictCells.size)
                                put("mismatch_cells", llm.mismatchCells.size)
                                put("low_conf_cells", llm.lowConfidenceCells.size)
                                put("unresolved_cells", llm.unresolvedCount)

                                put("likely_primary_cause", "source_grid_not_uniquely_solvable_if_match_is_true")
                                put("likely_causes_ranked", org.json.JSONArray().apply {
                                    put("The user may still find one or more missing or wrong givens when checking paper against screen.")
                                    put("If the match is truly exact, the source puzzle is likely misprinted, incomplete, variant-style, or otherwise not a standard unique-solution Sudoku.")
                                })

                                put(
                                    "instruction",
                                    "If the user has confirmed the screen matches the paper exactly, explain that the issue is no longer the capture itself: these givens still do not determine one unique standard solution. Briefly remind them of the two main possibilities: an overlooked wrong/missing given, or a source puzzle that is genuinely not uniquely solvable. Recommend moving to a different puzzle capture. Sound authoritative and diagnostic."
                                )
                            }
                        )
                    }
                }

                is Pending.ConfirmValidate -> {
                    out += FactBundleV1(
                        type = FactBundleV1.Type.CONFIRMING_FINALIZE_PACKET,
                        payload = JSONObject().apply {
                            put("solvability", llm.solvability)
                            put("is_structurally_valid", llm.isStructurallyValid)
                            put("conflict_cells", llm.conflictCells.size)
                            put("mismatch_cells", llm.mismatchCells.size)
                            put("low_conf_cells", llm.lowConfidenceCells.size)
                            put("unresolved_cells", llm.unresolvedCount)
                            put(
                                "instruction",
                                "Explain that the current on-screen givens are internally consistent and lead to one unique solution, but before solving we still require the human confirmation that the paper/book matches the screen exactly. Sound confident, concise, and procedural."
                            )
                        }
                    )
                }

                is Pending.ConfirmStartSolving -> {
                    out += FactBundleV1(
                        type = FactBundleV1.Type.CONFIRMING_FINALIZE_PACKET,
                        payload = JSONObject().apply {
                            put("solvability", llm.solvability)
                            put("instruction", "Grid is uniquely solvable; finalize presentation already applied; ask to start solving.")
                        }
                    )
                }

                else -> {
                    // No-op: other pendings are handled by legacy bundles + NEXT_PENDING_PROMPT.
                }
            }
        }

        return out
    }



    // -------------------------------------------------------------------------
    // Humanized retake prompt (canonical)
    // - One-turn, caring, accountable, non-jargony.
    // - Mentions on-screen highlights (user sees them).
    // - Ends with ONE CTA question (required by the app contract).
    // -------------------------------------------------------------------------
    private fun buildConfirmRetakePrompt(strength: String): String {

        val intro =
            "Nice job getting the grid in frame — I know that little “hold-still” moment can be annoying."

        val why =
            if (strength.lowercase() == "strong") {
                "I can see the puzzle, but my scanner didn’t get a clean read in a few of the highlighted squares (usually glare or a tiny shadow), and I don’t want to risk putting a wrong digit into your grid."
            } else {
                "I can see the puzzle, but a few highlighted squares came in a bit unclear (usually glare or a tiny shadow), and I’d rather not guess and accidentally nudge us off-track."
            }

        val fastFix =
            "The fastest fix is a quick retake with slightly flatter lighting — then we’ll be at a perfect 1:1 match with your paper."

        // Keep tips lightweight (2 max) and friendly.
        val tips =
            "Quick tips: keep the whole grid inside the white frame, and avoid glare (tilt the page a touch if you see shine)."

        val optionB =
            "If you’d rather not retake, no problem: we can keep this scan and I’ll guide you through verifying just the highlighted squares."

        // ONE CTA rule: final line must be the question.
        val cta =
            "Do you want the quick retake, or keep this scan and verify together?"

        return listOf(intro, why, fastFix, tips, optionB, cta).joinToString("\n\n")
    }


    private fun intakeReasonFromLlm(llm: LLMGridState): String {
        val retake = llm.retakeRecommendation.lowercase()
        return when {
            retake == "strong" -> "retake"
            llm.conflictCells.isNotEmpty() -> "conflict"
            llm.mismatchCells.isNotEmpty() -> "mismatch"
            llm.lowConfidenceCells.isNotEmpty() -> "low_conf"
            llm.unresolvedCells.isNotEmpty() -> "unresolved"
            else -> "seal" // “nothing obviously wrong”: default to seal/validate path
        }
    }

    private fun intakeDiagMap(llm: LLMGridState): Map<String, Any?> = mapOf(
        "intake_reason" to intakeReasonFromLlm(llm),
        "conflict_count" to llm.conflictCells.size,
        "mismatch_count" to llm.mismatchCells.size,
        "low_conf_count" to llm.lowConfidenceCells.size,
        "unresolved_count" to llm.unresolvedCells.size,
        "solvability" to llm.solvability,
        "is_structurally_valid" to llm.isStructurallyValid
    )

    fun decideGridIntakeOutcomeV1(
        s: SudoState,
        llm: LLMGridState
    ): DecisionOutcomeV1 {

        val focus = chooseFocusIdxForIntake(llm)

        val hasConflicts = llm.conflictCells.isNotEmpty()
        val hasMismatch = llm.mismatchCells.isNotEmpty()
        val hasLowConf = llm.lowConfidenceCells.isNotEmpty()

        val solvability = llm.solvability.trim().lowercase() // "unique"|"multiple"|"none"

        // 1) Hard “retake” suggestion if capture is clearly poor.
        val retakeStrength = llm.retakeRecommendation.lowercase()
        if (retakeStrength == "strong") {
            val p = Pending.ConfirmRetake(
                strength = "strong",
                prompt = buildConfirmRetakePrompt("strong")
            )

            val facts = buildIntakeFactBundlesV1(llm, p, focus, s.userConfirmedPerfectMatch)

            return DecisionOutcomeV1(
                decisionKind = DecisionKindV1.RECOMMENDED_RETAKE,
                summary = "Recommend retake due to unreliable capture.",
                stateMutations = StateMutationsV1(
                    newMode = SudoMode.GRID_SESSION,
                    newPhase = GridPhase.CONFIRMING,
                    newPending = p,
                    newFocusIdx = focus
                ),
                factBundles = facts
            )
        }

        // 2) Solvability-first policy:
        // once the grid is solvable, stop cell-by-cell repair work.
        if (solvability == "unique") {
            val p = Pending.ConfirmValidate(
                prompt = "The grid looks consistent, and I can solve it uniquely from what’s on screen. Before we begin, does the on-screen grid match your puzzle exactly?"
            )
            val facts = buildIntakeFactBundlesV1(llm, p, focus, s.userConfirmedPerfectMatch)
            return DecisionOutcomeV1(
                decisionKind = DecisionKindV1.REQUESTED_SEAL,
                summary = "Request seal: ask user to confirm the grid matches the puzzle before solving.",
                stateMutations = StateMutationsV1(
                    newMode = SudoMode.GRID_SESSION,
                    newPhase = GridPhase.SEALING,
                    newPending = p,
                    newFocusIdx = focus
                ),
                factBundles = facts
            )
        }

        if (solvability == "multiple") {
            val p = Pending.VisualVerifyMatch(
                prompt = "I’m not seeing rule conflicts on screen, but these givens do not lead to a single unique solution yet. Please compare the on-screen grid with your paper carefully. If it matches 100%, say yes. If not, tell me the cells to change."
            )
            val facts = buildIntakeFactBundlesV1(llm, p, focus, s.userConfirmedPerfectMatch)
            return DecisionOutcomeV1(
                decisionKind = DecisionKindV1.ASKED_PENDING,
                summary = "Ask for visual verification because the captured givens are solvable but not uniquely solvable.",
                stateMutations = StateMutationsV1(
                    newMode = SudoMode.GRID_SESSION,
                    newPhase = GridPhase.CONFIRMING,
                    newPending = p,
                    newFocusIdx = focus
                ),
                factBundles = facts
            )
        }

        // 3) From here on, solvability == "none": repair mode only.
        // Priority: mismatches -> conflicts -> low confidence.
        if (hasMismatch) {
            val idx = llm.mismatchCells.firstOrNull()?.coerceIn(0, 80) ?: focus ?: 0
            val p = Pending.AskCellValue(
                cellIndex = idx,
                prompt = "I think the digit at ${indexToCell(idx)} may be misread. What’s the correct digit there?"
            )
            val facts = buildIntakeFactBundlesV1(llm, p, idx, s.userConfirmedPerfectMatch)
            return DecisionOutcomeV1(
                decisionKind = DecisionKindV1.ASKED_PENDING,
                summary = "Ask to confirm a mismatch cell.",
                stateMutations = StateMutationsV1(
                    newMode = SudoMode.GRID_SESSION,
                    newPhase = GridPhase.CONFIRMING,
                    newPending = p,
                    newFocusIdx = idx
                ),
                factBundles = facts
            )
        }

        if (hasConflicts) {
            val idx = llm.conflictCells.firstOrNull()?.coerceIn(0, 80) ?: focus ?: 0
            val p = Pending.AskCellValue(
                cellIndex = idx,
                prompt = "I see a conflict around ${indexToCell(idx)}. What digit is printed there?"
            )

            val facts = buildIntakeFactBundlesV1(llm, p, idx, s.userConfirmedPerfectMatch)
            return DecisionOutcomeV1(
                decisionKind = DecisionKindV1.ASKED_PENDING,
                summary = "Ask to confirm a conflict cell.",
                stateMutations = StateMutationsV1(
                    newMode = SudoMode.GRID_SESSION,
                    newPhase = GridPhase.CONFIRMING,
                    newPending = p,
                    newFocusIdx = idx
                ),
                factBundles = facts
            )
        }

        if (hasLowConf) {
            val idx = llm.lowConfidenceCells.firstOrNull()?.coerceIn(0, 80) ?: focus ?: 0
            val p = Pending.AskCellValue(
                cellIndex = idx,
                prompt = "One cell looks unclear. What digit is at ${indexToCell(idx)}?"
            )
            val facts = buildIntakeFactBundlesV1(llm, p, idx, s.userConfirmedPerfectMatch)
            return DecisionOutcomeV1(
                decisionKind = DecisionKindV1.ASKED_PENDING,
                summary = "Ask to confirm a low-confidence cell.",
                stateMutations = StateMutationsV1(
                    newMode = SudoMode.GRID_SESSION,
                    newPhase = GridPhase.CONFIRMING,
                    newPending = p,
                    newFocusIdx = idx
                ),
                factBundles = facts
            )
        }

        // 4) Fallback for solvability == "none" when no explicit repair bucket is populated.
        val idx = focus ?: 0
        val p = Pending.AskCellValue(
            cellIndex = idx,
            prompt = "I’m seeing an inconsistency. What digit is printed at ${indexToCell(idx)}?"
        )

        val facts = buildIntakeFactBundlesV1(llm, p, idx, s.userConfirmedPerfectMatch)

        return DecisionOutcomeV1(
            decisionKind = DecisionKindV1.ASKED_PENDING,
            summary = "Ask for a critical cell confirmation to resolve inconsistency.",
            stateMutations = StateMutationsV1(
                newMode = SudoMode.GRID_SESSION,
                newPhase = GridPhase.CONFIRMING,
                newPending = p,
                newFocusIdx = idx
            ),
            factBundles = facts
        )
    }


    private fun grid81FromLLM(llm: com.contextionary.sudoku.logic.LLMGridState): String {
        val sb = StringBuilder(81)
        for (i in 0 until 81) {
            val d = llm.correctedGrid[i]
            sb.append(if (d in 1..9) ('0'.code + d).toChar() else '.')
        }
        return sb.toString()
    }

    private fun sha12(s: String): String =
        com.contextionary.sudoku.telemetry.ConversationTelemetry.sha256Hex(s).take(12)

    private fun isConstitutionalAppRouteOwnerV1(s: SudoState): Boolean =
        s.activeTurnAuthorityDecisionV1.owner == TurnAuthorityOwnerV1.APP_ROUTE_OWNER

    private fun isConstitutionalUserDetourOwnerV1(s: SudoState): Boolean =
        s.activeTurnAuthorityDecisionV1.owner == TurnAuthorityOwnerV1.USER_DETOUR_OWNER

    private fun isConstitutionalUserRouteJumpOwnerV1(s: SudoState): Boolean =
        s.activeTurnAuthorityDecisionV1.owner == TurnAuthorityOwnerV1.USER_ROUTE_JUMP_OWNER

    private fun isConstitutionalRepairOwnerV1(s: SudoState): Boolean =
        s.activeTurnAuthorityDecisionV1.owner == TurnAuthorityOwnerV1.REPAIR_OWNER

    private fun continuityLaneNameForReplyV1(sAfter: SudoState): String =
        when {
            isConstitutionalUserDetourOwnerV1(sAfter) -> "user_detour"
            isConstitutionalRepairOwnerV1(sAfter) -> "user_detour"
            isConstitutionalUserRouteJumpOwnerV1(sAfter) -> "route_jump"
            isConstitutionalAppRouteOwnerV1(sAfter) ||
                    sAfter.activeRouteBoundaryDecisionV1.status == RouteBoundaryStatusV1.RELEASED_TO_NEXT_STEP ->
                "app_route"
            else -> "mixed"
        }

    private fun constitutionalCtaOwnerKindV1(sAfter: SudoState): TurnOwnerV1 =
        when {
            isConstitutionalAppRouteOwnerV1(sAfter) ||
                    sAfter.activeRouteBoundaryDecisionV1.status == RouteBoundaryStatusV1.RELEASED_TO_NEXT_STEP ->
                TurnOwnerV1.APP_OWNER

            isConstitutionalUserDetourOwnerV1(sAfter) ||
                    isConstitutionalUserRouteJumpOwnerV1(sAfter) ||
                    isConstitutionalRepairOwnerV1(sAfter) ->
                TurnOwnerV1.USER_OWNER

            else ->
                TurnOwnerV1.NONE
        }

    private fun currentFocusCellRefForCtaV1(sAfter: SudoState): String? {
        val userHead = sAfter.userAgendaQueue.firstOrNull()

        fun cellRefFromIndex(ix: Int?): String? =
            ix?.takeIf { it in 0..80 }?.let { idx -> "r${idx / 9 + 1}c${idx % 9 + 1}" }

        val fromUserHead: String? =
            when (userHead) {
                is UserAgendaItem.ProofChallenge -> userHead.cellRef
                is UserAgendaItem.CandidateStateQuery -> userHead.cellRefs.firstOrNull()
                is UserAgendaItem.TargetCellQuery -> userHead.targetCellRef
                is UserAgendaItem.NeighborCellQuery -> userHead.neighborCellRef ?: userHead.anchorCellRef
                is UserAgendaItem.UserReasoningCheck -> userHead.cellRef
                is UserAgendaItem.AlternativeTechniqueQuery -> userHead.cellRef
                is UserAgendaItem.OverlayControl -> userHead.focusCellRef
                else -> null
            }

        return fromUserHead ?: cellRefFromIndex(sAfter.focusCellIndex)
    }

    private fun currentFocusHouseRefForCtaV1(sAfter: SudoState): String? {
        val userHead = sAfter.userAgendaQueue.firstOrNull()
        return when (userHead) {
            is UserAgendaItem.ProofChallenge -> userHead.houseRef
            is UserAgendaItem.CandidateStateQuery -> userHead.houseRef
            is UserAgendaItem.AlternativeTechniqueQuery -> userHead.regionRef
            is UserAgendaItem.OverlayControl -> userHead.regionRef
            is UserAgendaItem.RouteComparisonQuery -> userHead.compareScope
            else -> null
        }
    }

    private fun currentFocusDigitForCtaV1(sAfter: SudoState): Int? {
        val userHead = sAfter.userAgendaQueue.firstOrNull()
        return when (userHead) {
            is UserAgendaItem.ProofChallenge -> userHead.digit
            is UserAgendaItem.CandidateStateQuery -> userHead.digit
            is UserAgendaItem.TargetCellQuery -> userHead.digit
            is UserAgendaItem.OverlayControl -> userHead.digit
            else -> null
        }
    }

    private fun recentTurnsForAppRouteLaneV1(
        sAfter: SudoState,
        maxTurns: Int = 3
    ): List<TranscriptTurnV1> {
        val all = SessionStore.getRecentTurns(10)
        val checkpoint = sAfter.routeCheckpointV1 ?: deriveRouteCheckpointV1(sAfter)
        val anchorTurnSeq = checkpoint?.createdTurnSeq

        val filtered =
            if (anchorTurnSeq != null) {
                all.filter { it.turnId <= anchorTurnSeq }
            } else {
                all
            }

        return if (filtered.isNotEmpty()) filtered.takeLast(maxTurns) else all.takeLast(maxTurns)
    }

    private fun recentTurnsForUserDetourLaneV1(
        sAfter: SudoState,
        maxTurns: Int = 3
    ): List<TranscriptTurnV1> {
        val all = SessionStore.getRecentTurns(10)
        val userHead = sAfter.userAgendaQueue.firstOrNull()

        val anchorTurnSeq =
            userHead?.lastTouchedTurnSeq
                ?: userHead?.createdTurnSeq

        val filtered =
            if (anchorTurnSeq != null) {
                all.filter { it.turnId >= anchorTurnSeq }
            } else {
                emptyList()
            }

        return when {
            filtered.isNotEmpty() -> filtered.takeLast(maxTurns)
            all.isNotEmpty() -> all.takeLast(maxTurns.coerceAtMost(2))
            else -> emptyList()
        }
    }

    private fun recentTurnsForReplyLaneV1(sAfter: SudoState): List<TranscriptTurnV1> =
        when {
            isConstitutionalUserDetourOwnerV1(sAfter) -> recentTurnsForUserDetourLaneV1(sAfter)
            isConstitutionalRepairOwnerV1(sAfter) -> recentTurnsForUserDetourLaneV1(sAfter)
            isConstitutionalUserRouteJumpOwnerV1(sAfter) -> recentTurnsForUserDetourLaneV1(sAfter)
            isConstitutionalAppRouteOwnerV1(sAfter) ||
                    sAfter.activeRouteBoundaryDecisionV1.status == RouteBoundaryStatusV1.RELEASED_TO_NEXT_STEP ->
                recentTurnsForAppRouteLaneV1(sAfter)
            else -> SessionStore.getLast3Turns()
        }


    private fun headerLineValue(stateHeader: String, key: String): String? {
        return stateHeader
            .lineSequence()
            .map { it.trim() }
            .firstOrNull { it.startsWith("$key=", ignoreCase = true) }
            ?.substringAfter("=", "")
            ?.trim()
            ?.takeIf { it.isNotBlank() && !it.equals("none", ignoreCase = true) }
    }


    private fun emitTurnContextV1Telemetry(
        s: SudoState,
        ctx: PolicyCallCtx,
        reason: String,
        turnCtxJson: String
    ) {
        // Keep it resilient: never crash the turn because of telemetry.
        runCatching {
            val json = turnCtxJson.ifBlank { "{}" }

            ConversationTelemetry.emitPolicyTrace(
                tag = "TURN_CONTEXT_V1",
                data = mapOf(
                    "session_id" to s.sessionId,
                    "turn_id" to ctx.turnId,
                    "tick_id" to ctx.tickId,
                    "policy_req_seq" to ctx.policyReqSeq,
                    "correlation_id" to ctx.correlationId,
                    "model_call_id" to ctx.modelCallId,
                    "toolplan_id" to ctx.toolplanId,
                    "reason" to reason,

                    // Raw TurnContext (authoritative, as used for Tick1 binding)
                    "turn_ctx_sha12" to sha12(json),
                    "turn_ctx_len" to json.length,
                    "turn_ctx_preview" to previewLocal(json, 1200),
                    "turn_ctx_json" to json
                )
            )
        }
    }


    private fun callPolicyWithTrace(
        traceState: SudoState,
        userText: String,
        stateHeader: String,
        mode: SudoMode,
        reason: String,
        turnId: Long
    ): Pair<SudoState, Eff> {

        val (s2, ctx) = nextPolicyCtx(
            s = traceState,
            tickId = 1,
            reason = reason,
            stateHeader = stateHeader,
            turnId = turnId
        )

        emitPolicyCallTrace(
            traceState = traceState,
            userText = userText,
            stateHeader = stateHeader,
            reason = reason,
            turnId = turnId,
            ctx = ctx
        )

        emitModelCallBegin(ctx)

        // ✅ Patch 5.5: capture phase + (SOLVING-only) summary
        val phase = traceState.phase
        val engineStepSummary = engineStepSummaryForPrompt(traceState)

        // ✅ Always emit PRE snapshot for auditability when in GRID_SESSION
        // NOTE: we use the "mode" parameter (SudoMode) and traceState (not "s")
        if (ctx.tickId == 1 && mode == SudoMode.GRID_SESSION) {
            emitGridFactsNowIfPresent(
                s = traceState,
                ctx = ctx,
                stage = "PRE_TICK1",
                note = "before_meaning_extract_v1"
            )
        }


        // ------------------------------------------------------------
        // Phase-2: persist the exact TurnContextV1 JSON for deterministic binding
        // (we keep Eff.CallMeaningExtractV1.userText as raw user text for planning,
        //  but store TurnContextV1 JSON in state for binder use on receipt).
        // ------------------------------------------------------------
        val pendingBefore = headerLineValue(stateHeader, "pending")
        val pendingExpectedKind = headerLineValue(stateHeader, "pending_expected_answer_kind")
        val pendingTargetCell = headerLineValue(stateHeader, "pending_target_cell")
        val focusCell = headerLineValue(stateHeader, "focus_cell")
        val lastQuestionKey = headerLineValue(stateHeader, "last_assistant_question_key")
        val canonicalSolvingPositionKind =
            resolveCanonicalSolvingStepPositionV1(s2)?.kind?.name

        val turnCtxJson = runCatching {
            com.contextionary.sudoku.SessionStore.snapshotTurnContextV1(
                turnId = turnId,
                mode = mode.name,
                phase = phase.name,
                userText = userText,
                pendingBefore = pendingBefore,
                pendingExpectedAnswerKind = pendingExpectedKind,
                pendingTargetCell = pendingTargetCell,
                focusCell = focusCell,
                lastAssistantQuestionKey = lastQuestionKey,
                canonicalSolvingPositionKind = canonicalSolvingPositionKind
            ).toJsonString()
        }.getOrElse { "" }

        val s2WithCtx = s2.copy(
            lastTick1TurnCtxJson = turnCtxJson.takeIf { it.isNotBlank() }
        )

// ✅ NEW: emit TurnContextV1 telemetry (this is the Tick1 payload contract)
        emitTurnContextV1Telemetry(
            s = traceState,           // session_id lives on state
            ctx = ctx,                // tick_id=1 ctx
            reason = reason,
            turnCtxJson = turnCtxJson
        )

        return s2WithCtx to Eff.CallMeaningExtractV1(
            ctx = ctx,
            userText = userText,
            stateHeader = stateHeader,
            mode = mode,
            reason = reason,
            turnId = turnId,
            phase = phase
        )


    }



    private fun pendingSummary(p: Pending?): String = when (p) {
        null -> "none"
        is Pending.ConfirmEdit -> "confirm_edit(idx=${p.cellIndex},digit=${p.proposedDigit})"
        is Pending.AskCellValue -> "ask_cell_value(idx=${p.cellIndex})"
        is Pending.ConfirmRetake -> "confirm_retake(strength=${p.strength})"
        is Pending.ConfirmValidate -> "confirm_validate"
        is Pending.ConfirmInterpretation -> "confirm_interpretation(r=${p.row},c=${p.col},d=${p.digit},conf=${p.confidence})"
        is Pending.AskClarification -> "ask_clarification(kind=${p.kind},r=${p.rowHint},c=${p.colHint},d=${p.digitHint})"
        is Pending.WaitForTap -> "wait_for_tap(digitHint=${p.digitHint},conf=${p.confidence})"
        else -> "pending:${p.javaClass.simpleName ?: "unknown"}"
    }


    private fun pendingPromptFactV1(p: Pending?): FactBundleV1? {
        if (p == null) return null

        fun idxToCell(idx0: Int): String {
            val idx = idx0.coerceIn(0, 80)
            val row = (idx / 9) + 1
            val col = (idx % 9) + 1
            return "r${row}c${col}"
        }

        fun spokenCell(cell: String): String {
            val r = cell.substringAfter("r").substringBefore("c").toIntOrNull() ?: 0
            val c = cell.substringAfter("c").toIntOrNull() ?: 0
            return "row $r, column $c"
        }

        // IMPORTANT: Never return “pending request” — always produce a human couch-buddy CTA.
        return when (p) {

            is Pending.AskCellValue -> {
                val cell = idxToCell(p.cellIndex)
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "Quick check: on your book, what’s in ${spokenCell(cell)} — blank, or a number?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "ask_cell_value")
                        put("cta_kind", "ask_cell_value")
                        put("expects", "digit_or_blank")
                        put("cell", cell)
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.ConfirmEdit -> {
                val cell = idxToCell(p.cellIndex)
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "Just to confirm: should I set ${spokenCell(cell)} to ${p.proposedDigit}?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "confirm_edit")
                        put("cta_kind", "confirm_edit")
                        put("expects", "yes_no")
                        put("cell", cell)
                        put("proposed_digit", p.proposedDigit)
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.ConfirmValidate -> {
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "Ready for me to validate the grid (check it’s consistent and solvable)?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "confirm_validate")
                        put("cta_kind", "confirm_validate")
                        put("expects", "yes_no")
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.ConfirmRetake -> {
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: buildConfirmRetakePrompt(p.strength)

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "confirm_retake")
                        put("cta_kind", "confirm_retake")
                        put("expects", "retake_or_fix")
                        put("strength", p.strength)
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.VisualVerifyMatch -> {
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "Before we solve: does the on-screen grid match your book everywhere?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "visual_verify_match")
                        put("cta_kind", "visual_verify_match")
                        put("expects", "yes_no_or_edits")
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.ConfirmStartSolving -> {
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "All set — want me to start solving and guide you step by step?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "confirm_start_solving")
                        put("cta_kind", "confirm_start_solving")
                        put("expects", "yes_no")
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.ConfirmInterpretation -> {
                val cell = if (p.row != null && p.col != null) "r${p.row}c${p.col}" else null
                val guess = buildString {
                    if (cell != null) append("${spokenCell(cell)} ")
                    if (p.digit != null) append("= ${p.digit}")
                }.trim().takeIf { it.isNotBlank() }

                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: if (guess != null) "Just to confirm — did you mean: $guess?" else "Just to confirm — is that what you meant?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "confirm_interpretation")
                        put("cta_kind", "confirm_interpretation")
                        put("expects", "yes_no")
                        if (cell != null) put("cell", cell)
                        if (p.digit != null) put("digit", p.digit)
                        put("confidence", p.confidence)
                        put("prompt", prompt)
                    }
                )
            }

            is Pending.AskClarification -> {
                val cell = if (p.rowHint != null && p.colHint != null) "r${p.rowHint}c${p.colHint}" else null

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "ask_clarification")
                        put("cta_kind", "ask_clarification")
                        put("expects", "free_text")
                        put("clarify_kind", p.kind.name)
                        if (cell != null) put("cell", cell)
                        if (p.digitHint != null) put("digit_hint", p.digitHint)
                        put("preferred_user_facing_question", p.prompt)
                        put("prompt", p.prompt)
                        put(
                            "missing_fields",
                            JSONArray().apply {
                                if (p.rowHint == null && p.colHint == null) {
                                    put("target")
                                } else {
                                    if (p.rowHint == null) put("row")
                                    if (p.colHint == null) put("col")
                                }
                                if (p.digitHint == null) {
                                    put("digit")
                                }
                            }
                        )
                        put("response_shape", "one_short_user_facing_question")
                        put("fallback_response_policy", "ask_bounded_question_not_meta_status")
                        put("cta_options", JSONArray().apply {
                            put("answer_free_text")
                        })
                    }
                )
            }

            is Pending.UserAgendaBridge -> {
                val cell = p.cellRef?.takeIf { it.isNotBlank() }
                    ?: if (p.rowHint != null && p.colHint != null) "r${p.rowHint}c${p.colHint}" else null

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "user_agenda_bridge")
                        put("cta_kind", "user_agenda_bridge")
                        put("expects", p.expectedAnswerKind)
                        put("user_agenda_id", p.userAgendaId)
                        put("agenda_kind", p.agendaKind)
                        if (cell != null) put("cell", cell)
                        if (p.digitHint != null) put("digit_hint", p.digitHint)
                        put("prompt", p.prompt)
                        put("cta_options", JSONArray().apply {
                            if (p.options.isEmpty()) {
                                put("answer_user_detour")
                            } else {
                                p.options.forEach { put(it) }
                            }
                        })
                    }
                )
            }

            is Pending.WaitForTap -> {
                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "wait_for_tap")
                        put("cta_kind", "wait_for_tap")
                        put("expects", "tap")
                        put("confidence", p.confidence)
                        if (p.digitHint != null) put("digit_hint", p.digitHint)

                        put("cta_options", JSONArray().apply {
                            put("tap_cell")
                        })
                    }
                )
            }

            is Pending.SolveStepMissing -> {
                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "solve_step_missing")
                        put(
                            "cta_kind",
                            if (p.autoApplyFallback) "proof_failure_fallback_commit" else "solve_step_missing"
                        )
                        put(
                            "expects",
                            if (p.autoApplyFallback) "continue_when_ready" else "next_step_or_tap"
                        )
                        if (!p.gridHash12.isNullOrBlank()) put("grid_hash12", p.gridHash12)
                        put("prompt", p.prompt)

                        put("fallback_commit", p.autoApplyFallback)
                        put("fallback_step_id", p.fallbackStepId ?: JSONObject.NULL)
                        put(
                            "cell",
                            p.fallbackCellIndex?.let { indexToCell(it) } ?: JSONObject.NULL
                        )
                        put("fallback_digit", p.fallbackDigit ?: JSONObject.NULL)
                        put("fallback_technique", p.fallbackTechnique ?: JSONObject.NULL)
                        put("fallback_failure_reason", p.fallbackFailureReason ?: JSONObject.NULL)

                        put("cta_options", JSONArray().apply {
                            put("next_step")
                            put("tap_cell")
                        })
                    }
                )
            }


            is Pending.AfterResolution -> {
                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "after_resolution")
                        put("cta_kind", "after_resolution")
                        put("expects", "story_cta")
                        put("step_id", p.stepId)
                        put("grid_hash12", p.gridHash12)

                        put("cta_options", JSONArray().apply {
                            p.options.forEach { put(it) }
                        })

                        put("cta_semantics", JSONArray().apply {
                            p.options.forEach { opt ->
                                put(JSONObject().apply {
                                    put("id", opt)
                                    put(
                                        "intent",
                                        when (opt) {
                                            PendingChoiceId.NEXT_STEP ->
                                                IntentTypeV1.SOLVE_ACCEPT_NEXT_STEP.name

                                            PendingChoiceId.ASK_TECHNIQUE ->
                                                IntentTypeV1.REQUEST_CURRENT_TECHNIQUE_EXPLANATION.name
                                            else -> "UNKNOWN"
                                        }
                                    )
                                })
                            }
                        })
                    }
                )
            }


            is Pending.ApplyHintNow -> {
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "We’ve proved the answer logically. Want me to lock it in?"

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "apply_hint_now")
                        put("cta_kind", "apply_hint_now")
                        put("expects", "commit_choice")
                        put("step_id", p.stepId)
                        put("grid_hash12", p.gridHash12)
                        put("prompt", prompt)
                        put("story_stage", "CONFRONTATION")
                        put("commit_boundary", "PRE_COMMIT")
                        put("placement_committed", false)

                        put("cta_options", JSONArray().apply { p.options.forEach { put(it) } })

                        put("cta_semantics", JSONArray().apply {
                            p.options.forEach { opt ->
                                put(JSONObject().apply {
                                    put("id", opt)
                                    put(
                                        "intent",
                                        when (opt) {
                                            PendingChoiceId.LOCK_IT_IN ->
                                                IntentTypeV1.SOLVE_ACCEPT_LOCK_IN.name

                                            PendingChoiceId.TRY_SELF ->
                                                IntentTypeV1.SOLVE_PAUSE.name
                                            PendingChoiceId.EXPLAIN_MORE ->
                                                IntentTypeV1.REQUEST_CURRENT_STAGE_ELABORATION.name

                                            PendingChoiceId.APPLY_NOW ->
                                                IntentTypeV1.SOLVE_ACCEPT_LOCK_IN.name
                                            PendingChoiceId.LET_ME_TRY ->
                                                IntentTypeV1.SOLVE_PAUSE.name
                                            else -> "UNKNOWN"
                                        }
                                    )
                                })
                            }
                        })
                    }
                )
            }




            is Pending.ReturnToRoute -> {
                val prompt = p.prompt.takeIf { it.isNotBlank() }
                    ?: "Totally — quick detour. When you’re ready, just say “back to Sudoku” and we’ll continue exactly where we left off."

                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "return_to_route")
                        put("cta_kind", "return_to_route")
                        put("expects", "return_to_route")
                        put("prompt", prompt)

                        // UI choices
                        put("cta_options", JSONArray().apply { p.options.forEach { put(it) } })

                        // ✅ Map the return CTA to an existing intent (no new IntentType required)
                        put("cta_semantics", JSONArray().apply {
                            p.options.forEach { opt ->
                                put(JSONObject().apply {
                                    put("id", opt)
                                    put(
                                        "intent",
                                        when (opt) {
                                            PendingChoiceId.RETURN_TO_ROUTE ->
                                                IntentTypeV1.SOLVE_CONTINUE.name
                                            else -> "UNKNOWN"
                                        }
                                    )
                                })
                            }
                        })
                    }
                )
            }

            else -> {
                FactBundleV1(
                    type = FactBundleV1.Type.NEXT_PENDING_PROMPT,
                    payload = JSONObject().apply {
                        put("pending_type", "fallback_safe_generic")
                        put("cta_kind", "fallback_safe_generic")
                        put("expects", "retake_or_verify")
                        put("prompt", "No worries — do you want to retake the photo, or verify a couple of cells together from your book?")
                    }
                )
            }
        }
    }




    /**
     * Phase-6 HARD RULE: "No claims without proof"
     *
     * Ensure Tick2 always receives the minimum evidence bundles needed
     * to render the current pending + state safely.
     *
     * - Always include NEXT_PENDING_PROMPT for pendingAfter (if any).
     * - If a grid exists, always include SOLVABILITY_STATUS + RETAKE_RECOMMENDATION (bounded).
     * - If focusAfter is set, ensure FOCUS_CELL_SNAPSHOT exists (bounded).
     * - If focusAfter indicates conflict/mismatch and the reply might discuss it, include the explanation bundle.
     *
     * This prevents LLM from inventing, and makes the reply contract stable.
     */
    private fun enforceMinimumEvidenceBundlesV1(
        sAfter: SudoState,
        pendingAfter: Pending?,
        focusAfter: Int?,
        factsIn: List<FactBundleV1>
    ): List<FactBundleV1> {

        val facts = factsIn.toMutableList()

        fun has(t: FactBundleV1.Type): Boolean = facts.any { it.type == t }

        // ✅ Grab LLM grid snapshot ONCE (used by multiple injectors)
        val llm: LLMGridState? = llmGrid(sAfter)

        // ✅ Always include the player-language glossary bridge for Tick2
        if (!has(FactBundleV1.Type.GLOSSARY_BUNDLE)) {
            facts += GlossaryBundleV1.toFactBundle()
        }

        // ✅ Milestone 7 — Tick2 "driver voice" contract (always-on, auditable)
        if (!has(FactBundleV1.Type.PROMPT_CONTRACT_V1)) {
            facts += FactBundleV1(
                type = FactBundleV1.Type.PROMPT_CONTRACT_V1,
                payload = org.json.JSONObject().apply {
                    put("name", "tick2_driver_voice_contract_v1")
                    put(
                        "rules",
                        org.json.JSONArray().apply {
                            put("Do NOT invent digits, candidates, houses, or patterns. Use only provided FactBundles.")
                            put("If the user asked WHY (validity / elimination): cite concrete evidence from SOLVING_STEP_PACKET (proof/houses/candidates) when present.")
                            put("If the user asked TEACH ME THE TECHNIQUE: use TEACHING_CARD only (recognition/application/pitfalls). Do not invent extra steps.")
                            put("If required evidence bundle is missing, say you don't have enough evidence yet and ask for the next step / deeper hint (do not guess).")
                        }
                    )
                }
            )
        }

        // ✅ CONFIRMING FRAME (neighbor-on-couch): paper/book is the truth.
        // Insert once per reply (idempotent by "name").
        fun hasOtherNamed(name: String): Boolean =
            facts.any { it.type == FactBundleV1.Type.OTHER && it.payload.optString("name") == name }

        if (sAfter.phase == GridPhase.CONFIRMING && !hasOtherNamed("confirming_frame_v1")) {
            facts += FactBundleV1(
                type = FactBundleV1.Type.OTHER,
                payload = org.json.JSONObject().apply {
                    put("name", "confirming_frame_v1")
                    put(
                        "text",
                        "CONFIRMING PHASE: Treat the user’s paper/book as ground truth. " +
                                "Verify the scan calmly, one small check at a time. " +
                                "Ask what they see on their paper/book. " +
                                "Do NOT say 'pending request'. Do NOT claim an 'expected answer'."
                    )
                }
            )
        }

        // 1) Always anchor the exact pending ask (if any)
        if (pendingAfter != null && !has(FactBundleV1.Type.NEXT_PENDING_PROMPT)) {
            pendingPromptFactV1(pendingAfter)?.let { facts += it }
        }

        // 2) Always include solvability + retake rec when we have a grid
        // (bounded: these bundles are already compact and safe)
        if (llm != null) {
            if (!has(FactBundleV1.Type.SOLVABILITY_STATUS)) {
                facts += FactBundleV1(
                    type = FactBundleV1.Type.SOLVABILITY_STATUS,
                    payload = org.json.JSONObject().apply {
                        put("solvability", llm.solvability)
                        put("is_structurally_valid", llm.isStructurallyValid)
                        put("unresolved_count", llm.unresolvedCount)
                        put("deduced_solution_count_capped", llm.deducedSolutionCountCapped)
                        put("severity", llm.severity)
                    }
                )
            }
            // Avoid “retake / unreliable” duplication:
            // If the current pending is already ConfirmRetake, the CTA + confirming packet cover it.
            if (pendingAfter !is Pending.ConfirmRetake && !has(FactBundleV1.Type.RETAKE_RECOMMENDATION)) {
                facts += FactBundleV1(
                    type = FactBundleV1.Type.RETAKE_RECOMMENDATION,
                    payload = org.json.JSONObject().apply {
                        put("retake_recommendation", llm.retakeRecommendation)
                        put("low_conf_cells", llm.lowConfidenceCells.size)
                        put("conflict_cells", llm.conflictCells.size)
                        put("mismatch_cells", llm.mismatchCells.size)
                    }
                )
            }
        }

        // 3) If we have a focus cell and a grid, ensure a focus snapshot exists
        if (llm != null && focusAfter != null && focusAfter in 0..80 && !has(FactBundleV1.Type.FOCUS_CELL_SNAPSHOT)) {
            val idx = focusAfter
            facts += FactBundleV1(
                type = FactBundleV1.Type.FOCUS_CELL_SNAPSHOT,
                payload = org.json.JSONObject().apply {
                    val cell = indexToCell(idx)
                    val d = llm.correctedGrid[idx].coerceIn(0, 9)
                    put("cell", cell)
                    put("digit", d)
                    put("display_digit", d)
                    put("is_conflict", llm.conflictCells.contains(idx))
                    put("is_low_confidence", llm.lowConfidenceCells.contains(idx))
                    put("is_unresolved", llm.unresolvedCells.contains(idx))
                    put("is_confirmed", llm.confirmedCells.contains(idx))
                    put("reason_code", when {
                        llm.conflictCells.contains(idx) -> "CONFLICT"
                        llm.mismatchCells.contains(idx) -> "MISMATCH_VS_DEDUCED"
                        llm.lowConfidenceCells.contains(idx) -> "LOW_CONFIDENCE_OCR"
                        llm.unresolvedCells.contains(idx) -> "UNRESOLVED_EMPTY"
                        else -> "UNKNOWN"
                    })
                }
            )
        }

        // 4) If focus is conflict/mismatch and we didn't include explanation, include bounded explanation
        if (llm != null && focusAfter != null && focusAfter in 0..80) {
            val idx = focusAfter
            val cell = indexToCell(idx)

            if (llm.conflictCells.contains(idx) && !has(FactBundleV1.Type.CONFLICT_EXPLANATION)) {
                facts += FactBundleV1(
                    type = FactBundleV1.Type.CONFLICT_EXPLANATION,
                    payload = org.json.JSONObject().apply {
                        put("cell", cell)
                        put("conflict_count", llm.conflictCells.size)
                        put("conflict_cells_sample", llm.conflictCells.take(6).map { indexToCell(it) })
                    }
                )
            }

            if (llm.mismatchCells.contains(idx) && !has(FactBundleV1.Type.MISMATCH_EXPLANATION)) {
                facts += FactBundleV1(
                    type = FactBundleV1.Type.MISMATCH_EXPLANATION,
                    payload = org.json.JSONObject().apply {
                        put("cell", cell)
                        put("mismatch_count", llm.mismatchCells.size)
                        put("mismatch_cells_sample", llm.mismatchCells.take(6).map { indexToCell(it) })
                        put("mismatch_details_sample", llm.mismatchDetails.take(4))
                    }
                )
            }
        }



        // 5) Keep it bounded (dedupe after any injection/scrub)
        val out = mutableListOf<FactBundleV1>()
        val seen = mutableSetOf<String>()
        for (b in facts) {
            val key = b.type.name + ":" + runCatching { b.payload.toString() }.getOrElse { "" }
            if (seen.add(key)) out += b
        }

        // Hard cap
        return if (out.size <= 18) out else out.take(18)
    }


    // ------------------------------------------------------------
    // Phase 3 — Anti-repeat guardrail (North Star)
    // ------------------------------------------------------------

    private fun userExplicitlyAskedRepeatV1(userText: String): Boolean {
        val t = userText.trim().lowercase()
        if (t.isBlank()) return false
        return listOf(
            "repeat", "again", "say again", "one more time", "once more",
            "repeat that", "can you repeat", "tell me again"
        ).any { t.contains(it) }
    }

    // ---------------------------------------------------------------------
    // Story atom grouping helpers
    // Part 2:
    // Keep atom granularity fully intact, but define a reusable stage-based
    // interpretation for narration vs full story scope.
    // ---------------------------------------------------------------------

    private fun setupAtomIndicesForStoryV1(atomsCount: Int): List<Int> {
        val n = atomsCount.coerceAtLeast(1)
        return if (n >= 1) listOf(0) else emptyList()
    }

    private fun proofAtomIndicesForStoryV1(atomsCount: Int): List<Int> {
        val n = atomsCount.coerceAtLeast(1)
        val lastProof = (n - 2).coerceAtLeast(0)
        return if (n >= 3 && lastProof >= 1) (1..lastProof).toList() else emptyList()
    }

    private fun resolutionAtomIndicesForStoryV1(atomsCount: Int): List<Int> {
        val n = atomsCount.coerceAtLeast(1)
        val commitIdx = (n - 1).coerceAtLeast(0)
        return listOf(commitIdx)
    }

    // Atoms explicitly narrated in the current stage.
    private fun narrationAtomIndicesForStageV1(stage: StoryStage, atomsCount: Int): List<Int> =
        when (stage) {
            StoryStage.SETUP -> setupAtomIndicesForStoryV1(atomsCount)
            StoryStage.CONFRONTATION -> proofAtomIndicesForStoryV1(atomsCount)
            StoryStage.RESOLUTION -> resolutionAtomIndicesForStoryV1(atomsCount)
        }

    // Full story scope visible/available for the stage.
    private fun atomsInScopeForStageV1(stage: StoryStage, atomsCount: Int): List<Int> =
        when (stage) {
            StoryStage.SETUP -> setupAtomIndicesForStoryV1(atomsCount)

            StoryStage.CONFRONTATION ->
                proofAtomIndicesForStoryV1(atomsCount)

            StoryStage.RESOLUTION ->
                (proofAtomIndicesForStoryV1(atomsCount) + resolutionAtomIndicesForStoryV1(atomsCount)).distinct()
        }

    private fun defaultFocusAtomIndexForStageV1(
        stage: StoryStage,
        atomsCount: Int,
        preferredProofAtomIndex: Int? = null
    ): Int {
        val n = atomsCount.coerceAtLeast(1)
        val proof = proofAtomIndicesForStoryV1(n)

        return when (stage) {
            StoryStage.SETUP -> 0

            StoryStage.CONFRONTATION -> when {
                proof.isEmpty() -> 0
                preferredProofAtomIndex != null && preferredProofAtomIndex in proof -> preferredProofAtomIndex
                else -> proof.last()
            }

            StoryStage.RESOLUTION -> (n - 1).coerceAtLeast(0)
        }
    }

    private fun storyScopeAndCtasFromStoryV1(ns: NarrativeStoryContext): Pair<List<Int>, List<String>> {

        val inScope: List<Int> = atomsInScopeForStageV1(
            stage = ns.stage,
            atomsCount = ns.atomsCount
        )

        val requiredCtaOptions: List<String> =
            com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                .forStoryStage(ns.stage)
                .options

        return inScope to requiredCtaOptions
    }

    private fun computeStorySignatureV1(
        stepId: String,
        stage: String,
        atomsInScope: List<Int>,
        requiredCtas: List<String>
    ): String {
        val raw = buildString {
            append(stepId).append("|")
            append(stage).append("|")
            append(atomsInScope.joinToString(",")).append("|")
            append(requiredCtas.joinToString(","))
        }
        return sha12(raw).take(12)
    }

    private fun storyOverlayFrameIdsFromStoryV1(ns: NarrativeStoryContext): List<String> {
        val (inScope, _) = storyScopeAndCtasFromStoryV1(ns)
        return inScope.map { "ov:atom:$it" }.distinct()
    }

    private fun rewriteSolvingPacketAppliedFramesV1(
        bundles: List<FactBundleV1>,
        appliedFrameIds: List<String>
    ): List<FactBundleV1> {
        if (appliedFrameIds.isEmpty()) return bundles
        val out = mutableListOf<FactBundleV1>()
        for (b in bundles) {
            if (b.type != FactBundleV1.Type.SOLVING_STEP_PACKET_V1) {
                out += b
                continue
            }
            val p = runCatching { org.json.JSONObject(b.payload.toString()) }.getOrNull()
            if (p == null) { out += b; continue }

            val overlays = p.optJSONObject("overlays") ?: org.json.JSONObject().also { p.put("overlays", it) }
            overlays.put(
                "applied_frame_ids",
                org.json.JSONArray().apply { appliedFrameIds.forEach { put(it) } }
            )

            out += b.copy(payload = p)
        }
        return out
    }

    private fun storySignatureToStoreForTurnV1(s: SudoState): String? {
        if (s.phase != GridPhase.SOLVING) return null
        if (!isConstitutionalAppRouteOwnerV1(s)) return null

        val userHead = s.userAgendaQueue.firstOrNull()
        val postResolutionMismatchActive =
            userHead is UserAgendaItem.TargetCellQuery &&
                    userHead.checkpointPhase == GridPhase.SOLVING &&
                    userHead.checkpointStoryStage == StoryStage.RESOLUTION &&
                    userHead.status != UserAgendaStatusV1.RESOLVED &&
                    userHead.status != UserAgendaStatusV1.CANCELLED

        if (postResolutionMismatchActive) return null

        val ns = s.narrativeStory ?: return null
        val (inScope, ctas) = storyScopeAndCtasFromStoryV1(ns)
        return computeStorySignatureV1(ns.stepId, ns.stage.name, inScope, ctas)
    }

    /**
     * Enforce the "no repeat" invariant by forcing story progression *before* Tick2 is called.
     * Returns the updated state and a small debug map (for telemetry / audit).
     */
    private fun enforceNoRepeatStoryV1(
        s: SudoState,
        userText: String,
        allowRepeat: Boolean = false
    ): Pair<SudoState, Map<String, Any?>> {

        if (s.phase != GridPhase.SOLVING) return s to emptyMap()
        if (!isConstitutionalAppRouteOwnerV1(s)) return s to emptyMap()

        val ns0 = s.narrativeStory ?: return s to emptyMap()

        val explicitRepeatRequested =
            allowRepeat || userExplicitlyAskedRepeatV1(userText)

        if (explicitRepeatRequested) {
            return s to mapOf(
                "repeat_allowed" to true,
                "repeat_source" to if (allowRepeat) "solving_road_semantic" else "user_text_lexical"
            )
        }


        val atomsCount = ns0.atomsCount.coerceAtLeast(1)
        val proofIndices = proofAtomIndicesForStoryV1(atomsCount)
        val commitIdx = (atomsCount - 1).coerceAtLeast(0)

        fun applyStoryProgression(
            ns1: NarrativeStoryContext,
            diag: Map<String, Any?>
        ): Pair<SudoState, Map<String, Any?>> {
            val solveAtomIndex1 = when (ns1.stage) {
                StoryStage.SETUP -> 0
                StoryStage.CONFRONTATION -> ns1.focusAtomIndex ?: 0
                StoryStage.RESOLUTION -> commitIdx
            }

            val appliedFrames = storyOverlayFrameIdsFromStoryV1(ns1)

            val bundles1 = rewriteSolvingPacketAppliedFramesV1(
                bundles = s.solvingReadyFactBundlesV1,
                appliedFrameIds = appliedFrames
            )

            val s1 = s.copy(
                narrativeStory = ns1,
                solveAtomIndex = solveAtomIndex1,
                solvingReadyFactBundlesV1 = bundles1
            )

            return s1 to (diag + mapOf(
                "forced_stage" to ns1.stage.name,
                "forced_focus_atom_index" to (ns1.focusAtomIndex ?: 0),
                "forced_applied_frame_ids" to appliedFrames.joinToString(",")
            ))
        }

        // ------------------------------------------------------------
        // Pack 3 invariant:
        // APP-owned story beats are counted only on the app road.
        // Once a beat has already been delivered for this step, the next
        // APP-owned turn must move to the next legal beat unless the user
        // explicitly asked for repetition.
        // ------------------------------------------------------------
        val sameScoredStep = (s.storyScoreStepIdV1 == ns0.stepId)
        val setupAlreadyDelivered = sameScoredStep && s.storyDeliveredSetupV1

        val firstProofAtom = proofIndices.firstOrNull()
        val confrontationAlreadyDelivered =
            sameScoredStep &&
                    firstProofAtom != null &&
                    s.storyDeliveredProofMaxAtomV1 >= firstProofAtom

        when (ns0.stage) {
            StoryStage.SETUP -> {
                if (setupAlreadyDelivered) {
                    val forcedProofAtom = firstProofAtom ?: 0

                    val ns1 = ns0.copy(
                        stage = StoryStage.CONFRONTATION,
                        focusAtomIndex = forcedProofAtom,
                        discussedAtomIndices =
                            if (proofIndices.isEmpty()) emptyList() else proofIndices,
                        readyForCommit = proofIndices.isEmpty()
                    )

                    return applyStoryProgression(
                        ns1 = ns1,
                        diag = mapOf(
                            "three_beat_progressed" to true,
                            "three_beat_reason" to "setup_already_delivered_on_app_road"
                        )
                    )
                }
            }

            StoryStage.CONFRONTATION -> {
                if (confrontationAlreadyDelivered || ns0.readyForCommit) {
                    val resolutionFocus = commitIdx

                    val ns1 = ns0.copy(
                        stage = StoryStage.RESOLUTION,
                        focusAtomIndex = resolutionFocus,
                        discussedAtomIndices = narrationAtomIndicesForStageV1(
                            stage = StoryStage.RESOLUTION,
                            atomsCount = atomsCount
                        ),
                        readyForCommit = true
                    )

                    return applyStoryProgression(
                        ns1 = ns1,
                        diag = mapOf(
                            "three_beat_progressed" to true,
                            "three_beat_reason" to "confrontation_complete_promoted_to_resolution"
                        )
                    )
                }
            }

            StoryStage.RESOLUTION -> {
                // Nothing to do.
            }
        }

        // ------------------------------------------------------------
        // Legacy repeat prevention remains in place, but only after the
        // strict 3-beat accounting check above.
        // ------------------------------------------------------------
        val (inScope0, ctas0) = storyScopeAndCtasFromStoryV1(ns0)
        val sig0 = computeStorySignatureV1(ns0.stepId, ns0.stage.name, inScope0, ctas0)

        if (s.lastStorySignatureV1 != null && s.lastStorySignatureV1 == sig0) {

            val ns1: NarrativeStoryContext = when (ns0.stage) {

                StoryStage.SETUP -> {
                    val firstProof = proofIndices.firstOrNull() ?: 0

                    ns0.copy(
                        stage = StoryStage.CONFRONTATION,
                        focusAtomIndex = firstProof,
                        discussedAtomIndices =
                            if (proofIndices.isEmpty()) emptyList() else listOf(firstProof),
                        readyForCommit = proofIndices.isEmpty()
                    )
                }

                StoryStage.CONFRONTATION -> {
                    if (proofIndices.isEmpty()) {
                        ns0.copy(
                            stage = StoryStage.RESOLUTION,
                            focusAtomIndex = commitIdx,
                            discussedAtomIndices = narrationAtomIndicesForStageV1(
                                stage = StoryStage.RESOLUTION,
                                atomsCount = atomsCount
                            ),
                            readyForCommit = true
                        )
                    } else {
                        val currentFocus = ns0.focusAtomIndex ?: proofIndices.first()
                        val currentPos = proofIndices.indexOf(currentFocus)
                        val nextProofAtom =
                            when {
                                currentPos < 0 -> proofIndices.first()
                                currentPos >= proofIndices.lastIndex -> proofIndices.last()
                                else -> proofIndices[currentPos + 1]
                            }

                        if (currentFocus >= proofIndices.last() || nextProofAtom >= proofIndices.last()) {
                            ns0.copy(
                                stage = StoryStage.RESOLUTION,
                                focusAtomIndex = commitIdx,
                                discussedAtomIndices = narrationAtomIndicesForStageV1(
                                    stage = StoryStage.RESOLUTION,
                                    atomsCount = atomsCount
                                ),
                                readyForCommit = true
                            )
                        } else {
                            ns0.copy(
                                stage = StoryStage.CONFRONTATION,
                                focusAtomIndex = nextProofAtom,
                                discussedAtomIndices = proofIndices.filter { it <= nextProofAtom },
                                readyForCommit = false
                            )
                        }
                    }
                }

                StoryStage.RESOLUTION -> ns0
            }

            return applyStoryProgression(
                ns1 = ns1,
                diag = mapOf(
                    "repeat_prevented" to true,
                    "sig_repeated" to sig0
                )
            )
        }

        return s to emptyMap()
    }



    private fun enforceNoRepeatStoryFinalV1(
        sBeforePlan: SudoState,
        sAfterPlan: SudoState,
        userText: String,
        allowRepeat: Boolean = false,
        boundaryReturnAcceptedV1: Boolean = false,
        boundaryResumePolicyV1: BoundaryResumePolicyV1? = null
    ): Pair<SudoState, Map<String, Any?>> {
        if (allowRepeat) return sAfterPlan to emptyMap()
        if (sAfterPlan.phase != GridPhase.SOLVING) return sAfterPlan to emptyMap()
        if (!isConstitutionalAppRouteOwnerV1(sAfterPlan)) return sAfterPlan to emptyMap()

        val context = buildBoundaryGuardContextV1(
            sBeforePlan = sBeforePlan,
            sAfterPlan = sAfterPlan,
            userText = userText,
            boundaryReturnAcceptedV1 = boundaryReturnAcceptedV1,
            boundaryResumePolicyV1 = boundaryResumePolicyV1
        )

        val beforePos = context.effectiveBeforePos
        val afterPos0 = context.afterPos

        val illegalSameStageRepeat =
            context.sameStepGuardEnabled &&
                    beforePos != null &&
                    afterPos0 != null &&
                    beforePos.stepId != null &&
                    beforePos.stepId == afterPos0.stepId &&
                    beforePos.kind == afterPos0.kind &&
                    !userExplicitlyAskedRepeatV1(userText)

        val illegalBoundaryTransition =
            context.sameStepGuardEnabled &&
                    isIllegalCanonicalBoundaryTransitionV1(
                        beforePos = beforePos,
                        afterPos = afterPos0,
                        userText = userText,
                        allowRepeat = allowRepeat
                    )

        if (!context.sameStepGuardEnabled) {
            val isRecomputeReplan = isBoundaryRecomputeReplanV1(
                boundaryReturnAcceptedV1 = boundaryReturnAcceptedV1,
                boundaryResumePolicyV1 = boundaryResumePolicyV1,
                context = context
            )

            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "SOLVING_BOUNDARY_GUARD_SKIPPED",
                    data = mapOf(
                        "turn_id" to sAfterPlan.turnSeq,
                        "guard_mode" to context.mode.name,
                        "effective_before_source" to context.beforeSource.name,
                        "trust_source" to context.trustSource,
                        "effective_before_summary" to canonicalPositionSummaryV1(context.effectiveBeforePos),
                        "effective_after_summary" to canonicalPositionSummaryV1(context.afterPos),
                        "boundary_return_accepted_v1" to boundaryReturnAcceptedV1,
                        "boundary_resume_policy_v1" to (boundaryResumePolicyV1?.name ?: "null"),
                        "recompute_replan_v1" to isRecomputeReplan
                    )
                )
            }

            if (isRecomputeReplan) {
                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "SOLVING_ROUTE_REPLAN_V1",
                        data = mapOf(
                            "turn_id" to sAfterPlan.turnSeq,
                            "reason" to "detour_return_truth_changed",
                            "guard_mode" to context.mode.name,
                            "boundary_return_accepted_v1" to boundaryReturnAcceptedV1,
                            "boundary_resume_policy_v1" to (boundaryResumePolicyV1?.name ?: "null"),
                            "effective_after_summary" to canonicalPositionSummaryV1(context.afterPos)
                        )
                    )
                }
            }
        }

        if (illegalBoundaryTransition) {
            val beforePosNonNull = beforePos ?: return sAfterPlan to emptyMap()
            val afterPos0NonNull = afterPos0 ?: return sAfterPlan to emptyMap()

            runCatching {
                com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                    tag = "SOLVING_BOUNDARY_GUARD_BLOCK",
                    data = mapOf(
                        "turn_id" to sAfterPlan.turnSeq,
                        "guard_mode" to context.mode.name,
                        "effective_before_source" to context.beforeSource.name,
                        "trust_source" to context.trustSource,
                        "raw_before_summary" to canonicalPositionSummaryV1(context.rawBeforePos),
                        "checkpoint_before_summary" to canonicalPositionSummaryV1(context.checkpointBeforePos),
                        "restored_route_before_summary" to canonicalPositionSummaryV1(context.restoredRouteBeforePos),
                        "before_kind" to beforePosNonNull.kind.name,
                        "before_summary" to canonicalPositionSummaryV1(beforePosNonNull),
                        "illegal_after_kind" to afterPos0NonNull.kind.name,
                        "illegal_after_summary" to canonicalPositionSummaryV1(afterPos0NonNull),
                        "same_step_id" to (beforePosNonNull.stepId ?: "null"),
                        "same_step_guard_enabled" to context.sameStepGuardEnabled,
                        "boundary_return_accepted_v1" to boundaryReturnAcceptedV1,
                        "boundary_resume_policy_v1" to (boundaryResumePolicyV1?.name ?: "null"),
                        "user_text_repeat_allowed" to userExplicitlyAskedRepeatV1(userText)
                    )
                )
            }

            val softened = softenBoundaryGuardRollbackV1(
                sBeforePlan = sBeforePlan,
                sAfterPlan = sAfterPlan,
                context = context,
                boundaryReturnAcceptedV1 = boundaryReturnAcceptedV1,
                boundaryResumePolicyV1 = boundaryResumePolicyV1
            )

            if (softened != null) {
                val (softenedState, softenedDiag) = softened

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "SOLVING_BOUNDARY_GUARD_SOFTENED",
                        data = mapOf(
                            "turn_id" to softenedState.turnSeq,
                            "guard_mode" to context.mode.name,
                            "effective_before_source" to context.beforeSource.name,
                            "trust_source" to context.trustSource,
                            "before_summary" to canonicalPositionSummaryV1(beforePosNonNull),
                            "illegal_after_summary" to canonicalPositionSummaryV1(afterPos0NonNull),
                            "softened_after_summary" to canonicalPositionSummaryV1(
                                resolveCanonicalSolvingStepPositionV1(softenedState)
                            ),
                            "boundary_return_accepted_v1" to boundaryReturnAcceptedV1,
                            "boundary_resume_policy_v1" to (boundaryResumePolicyV1?.name ?: "null")
                        )
                    )
                }

                return softenedState to softenedDiag
            }

            return sBeforePlan to mapOf(
                "final_boundary_guard_blocked" to true,
                "guard_mode" to context.mode.name,
                "effective_before_source" to context.beforeSource.name,
                "before_kind" to beforePosNonNull.kind.name,
                "illegal_after_kind" to afterPos0NonNull.kind.name,
                "same_step_id" to beforePosNonNull.stepId
            )
        }

        if (!illegalSameStageRepeat) return sAfterPlan to emptyMap()

        val (repaired, diag) = enforceNoRepeatStoryV1(
            s = sAfterPlan,
            userText = userText,
            allowRepeat = false
        )

        val afterPos1 = resolveCanonicalSolvingStepPositionV1(repaired)
        val beforePosNonNull = beforePos ?: return sAfterPlan to emptyMap()
        val afterPos0NonNull = afterPos0 ?: return sAfterPlan to emptyMap()

        return if (afterPos1 != null && afterPos1.kind != afterPos0NonNull.kind) {
            repaired to (diag + mapOf(
                "final_no_repeat_enforced" to true,
                "guard_mode" to context.mode.name,
                "effective_before_source" to context.beforeSource.name,
                "before_kind" to beforePosNonNull.kind.name,
                "stale_after_kind" to afterPos0NonNull.kind.name,
                "repaired_kind" to afterPos1.kind.name
            ))
        } else {
            sAfterPlan to emptyMap()
        }
    }


    private data class ReplyExecutionSpecV1(
        val replyRequest: ReplyRequestV1,
        val planResult: ReplyAssemblyPlannerV1.PlanResultV1
    )

    /**
     * Build Tick2 request for natural-language reply generation (ALWAYS LLM).
     * The app provides only small, structured facts (bounded).
     */
    private fun buildReplyRequestV1(
        sBefore: SudoState,
        sAfter: SudoState,
        turnId: Long,
        userText: String,
        decision: DecisionOutcomeV1,
        factBundles: List<FactBundleV1>,
        envelope: IntentEnvelopeV1? = null
    ): ReplyExecutionSpecV1 {

        val safeTurnId = runCatching { turnId.toInt() }.getOrElse { Int.MAX_VALUE }

        val assistantStyleHeader =
            "You are Sudo: the user’s friendly companion and Sudoku coach (light wit level 3). No emojis. " +
                    "Two lanes: (A) Free talk = you can chat about any topic and be personable; (B) Grid talk = truth-first, never invent grid facts beyond provided bundles. " +
                    "CRITICAL (grid talk): Use the provided GLOSSARY_BUNDLE and the CONFIRMING_* packets to translate app terms into natural Sudoku-player speech. " +
                    "" +
                    "DEFINITIONS (Invariant E): " +
                    "A MISMATCH means a filled digit that does not match the expected value implied by the givens/solver (often a scan confusion like 4 vs 6). " +
                    "A CONFLICT means a Sudoku rule violation (duplicate digit in a row, column, or box). " +
                    "Never blur these concepts. Never invent new labels like 'tangled spots'. " +
                    "" +
                    "Speak coordinates as 'row X column Y' (avoid rXcY in spoken text unless user explicitly asks). " +
                    "Name boxes as top-left/top-middle/top-right/middle-left/center/middle-right/bottom-left/bottom-middle/bottom-right. " +
                    "" +
                    "NO-REPEAT GUARANTEE (critical): Never ask the same decision or the same cell-confirmation twice once resolved. " +
                    "If you must reference a resolved item, acknowledge it briefly ('We already set row 1 column 8 to 6—next…') and move forward. " +
                    "" +
                    "EVIDENCE RULE (critical): Any claim about the grid must be grounded in the provided fact bundles (conflict partners, mismatch details, confidence, solvability status). " +
                    "Do not invent counts, examples, or 'most tangled' areas beyond what the bundles contain. " +
                    "TRUTHFUL COMMIT RULE (critical): In solving, never say a digit is already showing, already placed, or about to appear unless the current turn facts support that board state. If board-sync is disputed, acknowledge it and switch to repair-first wording. " +
                    "" +
                    "AGENDA RULE (critical): active owner always wins. If the turn is user-owned, answer the user-owned detour first and do NOT continue the app story body in that same reply. If the turn is app-owned, follow the app agenda. NEXT_PENDING_PROMPT / PENDING_CONTEXT are projections, not controllers. End with exactly ONE CTA consistent with NEXT_CTA_KIND / NEXT_CTA_EXPECTS / NEXT_CTA_CELL. "
                    "" +
                    "RETAKE RULE (critical): Only mention retake if NEXT_CTA_KIND indicates a retake action (confirm_retake OR a tap CTA targeted to Retake), " +
                    "or if the user explicitly asks about retaking. Never re-open the 'retake vs keep' debate otherwise. " +
                    "" +
                    "ORDER: If the user asked a direct question, answer it first. If the user gave a clear instruction, confirm execution first. " +
                    "INVARIANT: Every assistant reply MUST end with exactly ONE CTA (one question / one request). " +
                    "If you answered a question or executed an instruction successfully, you MUST still end with the next app-agenda CTA in the same reply. " +
                    "If you cannot answer or cannot execute because details are missing, ask ONE clarification question only (that clarification is the CTA) and do NOT proceed to agenda CTA in that reply. " +
                    "Do not list blanks unless asked. Tone: warm, human, and concise; avoid dismissive jokes or robot"

        val userTally = SessionStore.getUserTally()
        val assistantTally = SessionStore.getAssistantTally()
        val relationshipMemory = SessionStore.getRelationshipMemory()
        val recentTurns = recentTurnsForReplyLaneV1(sAfter)

        val factsOut = enforceMinimumEvidenceBundlesV1(
            sAfter = sAfter,
            pendingAfter = sAfter.pending,
            focusAfter = sAfter.focusCellIndex,
            factsIn = factBundles
        )

        // PATCH 0.4 (revised): Keep the “exactly one CTA” invariant, but do NOT force verbatim text.
        // We pass CTA intent signals from NEXT_PENDING_PROMPT (type/cell/expects) and allow natural phrasing.
        val nextPendingPayload: JSONObject? =
            factsOut.firstOrNull { it.type == FactBundleV1.Type.NEXT_PENDING_PROMPT }?.payload

        val nextCtaHint: String? = nextPendingPayload?.optString("prompt")?.takeIf { it.isNotBlank() }
        val nextCtaKind: String? = nextPendingPayload?.optString("cta_kind")?.takeIf { it.isNotBlank() }
            ?: nextPendingPayload?.optString("pending_type")?.takeIf { it.isNotBlank() }
        val nextCtaCell: String? = nextPendingPayload?.optString("cell")?.takeIf { it.isNotBlank() }
        val nextCtaExpects: String? = nextPendingPayload?.optString("expects")?.takeIf { it.isNotBlank() }

        val decisionSummaryWithCta = buildString {
            append(decision.summary)


            val commitSuccessFact = factsOut.firstOrNull {
                it.type == FactBundleV1.Type.OTHER &&
                        it.payload.optString("kind") == "solve_commit_atomic_success"
            }

            val commitBlockedFact = factsOut.firstOrNull {
                it.type == FactBundleV1.Type.OTHER &&
                        it.payload.optString("kind") == "solve_commit_atomic_blocked"
            }

            val repairPreemptFact = factsOut.firstOrNull {
                it.type == FactBundleV1.Type.OTHER &&
                        it.payload.optString("kind") == "repair_detour_preempted_solving_route"
            }

            if (commitSuccessFact != null) {
                append("\n\nCOMMIT_STATUS: Placement is confirmed for this turn. Speak in present-state wording, not future promise wording.")
            }

            if (commitBlockedFact != null || repairPreemptFact != null) {
                append("\n\nCOMMIT_STATUS: Do NOT speak as if the placement is already visible on the board. Use repair-first wording and keep the reply focused on syncing the target cell before moving on.")
            }

            val fallbackCommitPending =
                nextPendingPayload?.optBoolean("fallback_commit", false) == true

            if (fallbackCommitPending) {
                append(
                    "\n\nFALLBACK_COMMIT_MODE: The solver move is still valid, but the proof packet had an internal issue. " +
                            "Be honest about that internal explanation issue. " +
                            "Do NOT invent or paraphrase a full proof chain. " +
                            "State the exact answer, name the technique, say you are placing it now, " +
                            "and close with one forward CTA such as continuing when the user is ready."
                )
            }

            // PATCH A2 (revised): If we accepted a proposed mismatch edit, require a paper-update reminder,

            // but DO NOT use "verbatim" meta-instructions that might leak into the user-facing reply.
            val mustTellPaperUpdate =
                (sBefore.pending is Pending.ConfirmEdit) && (decision.mutationApplied != null)

            if (mustTellPaperUpdate) {
                append(
                    "\n\nPAPER_UPDATE_REMINDER: Before your final CTA, include a short, natural reminder that the user should update their paper too (example: “I applied that change—please update it on your paper as well.”)."
                )
            }

            append("\n\nONE_CTA_RULE: Your reply MUST end with exactly ONE CTA (one question / one action request).")

            // ✅ Blueprint latch visibility (prevents “retake drift” / repeated debates)
            append("\nRETAKE_LATCH: retakeDismissed=")
            append(sAfter.retakeDismissed)
            append(" (If true, do NOT re-ask retake; only proceed with fix/verify agenda unless user explicitly asks about retake.)")

            // ✅ Intent-based CTA (human phrasing allowed; no internal jargon)
            if (!nextCtaKind.isNullOrBlank() || !nextCtaCell.isNullOrBlank()) {
                append("\nCTA_INTENT: End with a friendly neighbor-on-the-couch CTA consistent with:")
                append("\n- NEXT_CTA_KIND: ").append(nextCtaKind ?: "none")
                append("\n- NEXT_CTA_CELL: ").append(nextCtaCell ?: "none")
                append("\n- NEXT_CTA_EXPECTS: ").append(nextCtaExpects ?: "none")

                // ✅ SOLVING: never surface legacy "hint" scripts; story CTAs come from STORY_CONTEXT_V1.
                if (!nextCtaHint.isNullOrBlank() && sAfter.phase != GridPhase.SOLVING) {
                    append("\nCTA_HINT_EXAMPLE: You may paraphrase this example naturally (DO NOT quote verbatim unless it already sounds human):\n\"")
                    append(nextCtaHint)
                    append("\"")
                }

                append("\nCTA_STYLE: Do NOT say “pending request”. In CONFIRMING, always ground truth in the user’s paper/book (ask what they see there).")

                if (sAfter.phase == GridPhase.SOLVING) {
                    append("\nSOLVING_CTA_WORDING: Avoid the word \"hint\". Use the story CTAs only: \"try\", \"keep guiding\", \"ready for the answer\", \"next step\", \"teach the technique\".")
                }

                append("\nIf you cannot proceed because required details are missing, ask ONE clarification question only (that becomes the CTA) and DO NOT also include the agenda CTA.")
            } else {
                // Safety valve if injection failed
                append("\nCTA_STYLE: End with one friendly question that moves the agenda forward (retake vs verify cells).")
                append("\nIf you cannot proceed because required details are missing, ask ONE clarification question only (that becomes the CTA).")
            }
        }

        // --------------------------------------------------------------------
        // ✅ Phase 1: Explicit story header + story-scoped atom leash for Tick2
        // --------------------------------------------------------------------
        val canonicalStoryPosition = resolveCanonicalSolvingStepPositionV1(sAfter)

        val storyHeader: ReplyStoryCtxV1? =
            if (sAfter.phase == GridPhase.SOLVING && (sAfter.narrativeStory != null || canonicalStoryPosition != null)) {
                val ns = sAfter.narrativeStory
                ReplyStoryCtxV1(
                    present = true,
                    stage = (canonicalStoryPosition?.stage ?: ns?.stage)?.name,
                    stepId = canonicalStoryPosition?.stepId ?: ns?.stepId,
                    gridHash12 = canonicalStoryPosition?.gridHash12 ?: ns?.gridHash12,
                    atomsCount = canonicalStoryPosition?.atomsCount ?: ns?.atomsCount,
                    focusAtomIndex = canonicalStoryPosition?.focusAtomIndex ?: ns?.focusAtomIndex,
                    discussedAtomIndices = ns?.discussedAtomIndices ?: emptyList(),
                    readyForCommit = canonicalStoryPosition?.readyForCommit ?: ns?.readyForCommit,
                    canonicalPositionKind = canonicalStoryPosition?.kind?.name,
                    canonicalHeadKind = canonicalStoryPosition?.headKind?.name,
                    canonicalPendingKind = canonicalStoryPosition?.pendingKind?.name
                )
            } else {
                sAfter.narrativeStory?.let { ns ->
                    ReplyStoryCtxV1(
                        present = true,
                        stage = ns.stage.name,
                        stepId = ns.stepId,
                        gridHash12 = ns.gridHash12,
                        atomsCount = ns.atomsCount,
                        focusAtomIndex = ns.focusAtomIndex,
                        discussedAtomIndices = ns.discussedAtomIndices,
                        readyForCommit = ns.readyForCommit
                    )
                }
            }

        // STORY_CONTEXT_V1: tells Tick2 exactly which atoms are in scope this turn,
        // what the stage is trying to accomplish, and which CTA options it must end with.
        val storyContextBundle: FactBundleV1? = sAfter.narrativeStory?.let { ns ->
            if (sAfter.phase == GridPhase.SOLVING) {
                val inScope: List<Int> = atomsInScopeForStageV1(
                    stage = ns.stage,
                    atomsCount = ns.atomsCount
                )

                val requiredCtaOptions: List<String> =
                    com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                        .forStoryStage(ns.stage)
                        .options

                val stageGoal: String = when (ns.stage) {
                    StoryStage.SETUP ->
                        "Sell the solving lens for this step: direct attention to the target area, name the technique, and explain why this part of the grid is ripe for that technique. If atom 0 carries advanced trigger truth, setup may name the trigger pattern and its significance, but must still hold back the detailed proof chain and the answer."

                    StoryStage.CONFRONTATION ->
                        "Use the already-established pattern or trigger to deliver the proof chain in one continuous spoken turn: state the trigger's effect, combine it with the remaining target blockers, and reach the logical answer without committing the final placement yet."

                    StoryStage.RESOLUTION ->
                        "Commit the answer cleanly: state the placement in present-state language, recap the whole story in compact form, name the technique contribution honestly, and hand off to the next step."
                }

                val stageContract: String = when (ns.stage) {
                    StoryStage.SETUP ->
                        "Setup only. Pattern-first when atom 0 provides advanced trigger truth: orient the target, name the trigger pattern, and say why it matters, but do not unpack the full trigger explanation, do not do the proof sweep, and do not reveal the answer. End with exactly one normal CTA that advances into guided proof for this step."

                    StoryStage.CONFRONTATION ->
                        "Confrontation only. Do not re-explain how the pattern forms. Treat the pattern or trigger as already established. Use it, combine it with the target blocker network, and carry the logic to a single surviving answer. Do not commit the placement yet. End with exactly one normal CTA that invites lock-in / commit."

                    StoryStage.RESOLUTION ->
                        "Resolution only. The placement is now commit-authorized. Speak in present-state language, do not restart setup, do not replay the full proof, and keep the recap compact. Name both layers honestly when the finish is two-layer. End with exactly one normal CTA that advances to the next step."
                }

                FactBundleV1(
                    type = FactBundleV1.Type.STORY_CONTEXT_V1,
                    payload = JSONObject().apply {
                        put("story_present", true)
                        put("story_stage", ns.stage.name)
                        put("story_stage_goal", stageGoal)
                        put("story_stage_contract", stageContract)
                        put(
                            "story_setup_usage_rule",
                            when (ns.stage) {
                                StoryStage.SETUP ->
                                    "In setup, use atom 0 to orient the target, name the trigger pattern if present, and say why it matters; hold back detailed trigger explanation for confrontation."
                                StoryStage.CONFRONTATION ->
                                    "In confrontation, reference the already-established pattern briefly, explain its effect on the target, combine it with the remaining blocker rows, and stop at pre-commit."
                                StoryStage.RESOLUTION ->
                                    "In resolution, commit the placement, recap the logic compactly, and move to the next step without restarting setup or replaying the whole proof."
                            }
                        )

                        put("commit_boundary_pending", sAfter.isCommitBoundaryPendingV1())
                        put("post_commit_pending", sAfter.isPostCommitPendingV1())
                        put("reveal_available", sAfter.coachPlan?.reveal != null)
                        put("reveal_edit_executed", sAfter.hasExecutedRevealEditV1())
                        put("step_id", ns.stepId)
                        put("grid_hash12", ns.gridHash12)
                        put("atoms_count", ns.atomsCount)
                        put("focus_atom_index", ns.focusAtomIndex ?: JSONObject.NULL)
                        put("discussed_atom_indices", JSONArray().apply { ns.discussedAtomIndices.forEach { put(it) } })
                        put("ready_for_commit", ns.readyForCommit)

                        // -------------------------------
                        // SETUP guidance (Atom 0 summary)
                        // -------------------------------
                        runCatching {
                            val atomsArr = narrativeAtomsArrayFromState(sAfter)
                            val atom0 = atomsArr?.optJSONObject(0)
                            val spoiler0 = atom0?.optString("spoiler_level", "") ?: ""
                            val focus0 = atom0?.optJSONObject("focus")
                            val claim0 = atom0?.optJSONObject("claim")
                            val args0 = claim0?.optJSONObject("args")

                            val targetCell0 = focus0?.optJSONObject("target_cell")
                            val primaryHouse0 = focus0?.optJSONObject("primary_house")
                            val targetDigit0 =
                                runCatching { focus0?.optInt("target_digit", -1) }
                                    .getOrNull()
                                    ?.takeIf { it > 0 }

                            val setupRole0 = args0?.optString("setup_role", "") ?: ""
                            val triggerPattern0 = args0?.optJSONObject("trigger_pattern")
                            val triggerExplanation0 = args0?.optJSONObject("trigger_explanation")
                            val triggerBridge0 = args0?.optJSONObject("trigger_bridge")
                            val advancedSetupPayload0 = args0?.optJSONObject("advanced_setup_payload")

                            val triggerKind0 =
                                triggerPattern0?.optString("kind")
                                    ?.takeIf { it.isNotBlank() }

                            val triggerWhyMatters0 =
                                triggerBridge0?.optString("why_this_matters")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: args0?.optString("why_this_matters")
                                        ?.takeIf { it.isNotBlank() }

                            put("setup_spoiler_level", spoiler0)
                            put("setup_can_say_target_digit", spoiler0.equals("NONE", ignoreCase = true) && targetDigit0 != null)
                            put("setup_target_digit", targetDigit0 ?: JSONObject.NULL)
                            put("setup_target_cell", targetCell0 ?: JSONObject.NULL)
                            put("setup_primary_house", primaryHouse0 ?: JSONObject.NULL)
                            put("setup_claim_code", claim0?.optString("code", "") ?: "")

                            // Phase 6:
                            // Make setup-stage consumers explicitly aware of trigger truth,
                            // while also marking that detailed trigger explanation belongs to confrontation.
                            put("setup_role", setupRole0.ifBlank { JSONObject.NULL })
                            put("setup_has_advanced_trigger", triggerPattern0 != null)
                            put("setup_trigger_kind", triggerKind0 ?: JSONObject.NULL)
                            put("setup_trigger_pattern", triggerPattern0 ?: JSONObject.NULL)
                            put("setup_trigger_bridge", triggerBridge0 ?: JSONObject.NULL)
                            put("setup_why_this_matters", triggerWhyMatters0 ?: JSONObject.NULL)

                            put(
                                "setup_can_name_pattern",
                                triggerPattern0 != null
                            )

                            put(
                                "setup_can_summarize_significance",
                                triggerBridge0 != null || !triggerWhyMatters0.isNullOrBlank()
                            )

                            val introDerived0 = advancedSetupPayload0?.optJSONObject("intro_derived")
                            val introNarrationContract0 =
                                advancedSetupPayload0?.optJSONObject("intro_narration_contract")
                            val introOverlayContract0 =
                                advancedSetupPayload0?.optJSONObject("intro_overlay_contract")

                            put(
                                "setup_must_include_bounded_trigger_member_explanation",
                                introNarrationContract0?.optBoolean(
                                    "must_include_bounded_trigger_member_explanation",
                                    false
                                ) ?: false
                            )

                            put(
                                "setup_trigger_explanation_summary_only",
                                introDerived0?.optString("trigger_explanation_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_trigger_member_explanation_rows",
                                introDerived0?.optJSONArray("trigger_member_explanation_rows")
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_trigger_explanation_payload",
                                triggerExplanation0 ?: JSONObject.NULL
                            )

                            put(
                                "setup_intro_route",
                                advancedSetupPayload0?.optJSONArray("intro_route") ?: JSONObject.NULL
                            )

                            put(
                                "setup_target_orientation_summary",
                                introDerived0?.optString("target_orientation_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_technique_lens_summary",
                                introDerived0?.optString("technique_lens_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_trigger_summary",
                                introDerived0?.optString("trigger_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_bridge_summary",
                                introDerived0?.optString("bridge_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_final_resolution_setup_summary",
                                introDerived0?.optString("final_resolution_setup_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_honesty_note",
                                introDerived0?.optString("honesty_note")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_cta_kind",
                                introDerived0?.optString("cta_kind")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put(
                                "setup_intro_narration_contract",
                                introNarrationContract0 ?: JSONObject.NULL
                            )

                            put(
                                "setup_intro_overlay_contract",
                                introOverlayContract0 ?: JSONObject.NULL
                            )

                            put(
                                "setup_overlay_variant",
                                introOverlayContract0?.optString("setup_variant")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: JSONObject.NULL
                            )

                            put("setup_advanced_payload", advancedSetupPayload0 ?: JSONObject.NULL)

                            // -------------------------------
                            // CONFRONTATION guidance
                            // Pattern / trigger is already established by setup.
                            // Confrontation should USE it, not re-explain its formation.
                            // -------------------------------
                            val confrontationProfile0 = resolveConfrontationProofProfileV1(sAfter)
                            val atom0ConfrontationSummary =
                                args0?.optJSONObject("confrontation_summary") ?: JSONObject()

                            val preferredProofAtomIndex0 =
                                when {
                                    (ns.focusAtomIndex ?: -1) >= 1 -> ns.focusAtomIndex ?: 1
                                    else -> inScope.firstOrNull { it >= 1 } ?: 1
                                }

                            val proofAtom0 =
                                atomsArr?.optJSONObject(preferredProofAtomIndex0)

                            val proofFocus0 = proofAtom0?.optJSONObject("focus")
                            val proofClaim0 = proofAtom0?.optJSONObject("claim")
                            val proofSpoiler0 = proofAtom0?.optString("spoiler_level", "") ?: ""

                            val proofArgs0 = preferredProofAtomArgsV1(sAfter)

                            val proofHouseClaim0 =
                                proofArgs0.optJSONObject("house_claim") ?: JSONObject()
                            val proofSupport0 =
                                proofArgs0.optJSONObject("support") ?: JSONObject()

                            val confrontationTargetCell0 =
                                proofFocus0?.optJSONObject("target_cell")
                                    ?: proofArgs0.optJSONObject("target_cell")
                                    ?: targetCell0
                            val confrontationPrimaryHouse0 =
                                proofFocus0?.optJSONObject("primary_house")
                                    ?: proofArgs0.optJSONObject("primary_house")
                                    ?: proofHouseClaim0.optJSONObject("house")
                                    ?: primaryHouse0

                            val proofTargetDigit0 =
                                runCatching { proofFocus0?.optInt("target_digit", -1) }
                                    .getOrNull()
                                    ?.takeIf { it > 0 }
                                    ?: runCatching { proofArgs0.optInt("digit", -1) }
                                        .getOrNull()
                                        ?.takeIf { it > 0 }
                                    ?: runCatching { proofHouseClaim0.optInt("digit", -1) }
                                        .getOrNull()
                                        ?.takeIf { it > 0 }

                            val blockerRows0 =
                                proofArgs0.optJSONArray("blocker_rows")
                                    ?: proofSupport0.optJSONArray("blocker_rows")
                                    ?: JSONArray()

                            val peerWitnessRows0 =
                                proofArgs0.optJSONArray("peer_witness_rows")
                                    ?: proofSupport0.optJSONArray("peer_witness_rows")
                                    ?: JSONArray()

                            val peerWitnessPairs0 =
                                proofArgs0.optJSONArray("peer_witness_pairs")
                                    ?: proofSupport0.optJSONArray("peer_witness_pairs")
                                    ?: JSONArray()

                            val witnessByCell0 =
                                proofArgs0.optJSONArray("witness_by_cell")
                                    ?: proofSupport0.optJSONArray("witness_by_cell")
                                    ?: JSONArray()

                            val targetProofRows0 =
                                when {
                                    blockerRows0.length() > 0 -> blockerRows0
                                    peerWitnessRows0.length() > 0 -> peerWitnessRows0
                                    peerWitnessPairs0.length() > 0 -> peerWitnessPairs0
                                    witnessByCell0.length() > 0 -> witnessByCell0
                                    else -> JSONArray()
                                }

                            val forcingSummary0 =
                                proofArgs0.optJSONObject("forcing_summary")
                                    ?: proofSupport0.optJSONObject("forcing_summary")
                                    ?: JSONObject()

                            val remainingCandidateDigits0 =
                                proofArgs0.optJSONArray("remaining_candidate_digits")
                                    ?: proofArgs0.optJSONArray("remaining_digits")
                                    ?: proofSupport0.optJSONArray("remaining_candidate_digits")
                                    ?: forcingSummary0.optJSONArray("remaining_candidate_digits")
                                    ?: JSONArray()

                            val survivingDigit0 =
                                firstPositiveIntInArrayV1(remainingCandidateDigits0)
                                    ?: proofTargetDigit0

                            val confrontationHonestyNote0 =
                                forcingSummary0.optString("forcing_note")
                                    .takeIf { it.isNotBlank() }
                                    ?: proofArgs0?.optString("forcing_honesty_note")
                                        ?.takeIf { it.isNotBlank() }
                                    ?: introDerived0?.optString("honesty_note")
                                        ?.takeIf { it.isNotBlank() }

                            val confrontationTriggerReferenceSummary0 =
                                introDerived0?.optString("trigger_summary")
                                    ?.takeIf { it.isNotBlank() }
                                    ?: defaultConfrontationTriggerReferenceSummaryV1(
                                        confrontationProfile0
                                    )

                            val confrontationTriggerEffectSummary0 =
                                atom0ConfrontationSummary.optString("why_this_matters")
                                    .takeIf { it.isNotBlank() }
                                    ?: defaultConfrontationTriggerEffectSummaryV1(
                                        confrontationProfile0
                                    )

                            val confrontationCollapseSummary0 =
                                when {
                                    survivingDigit0 != null ->
                                        "After combining the established pattern effect with the remaining blockers on the target, only $survivingDigit0 survives."

                                    remainingCandidateDigits0.length() == 1 ->
                                        "After combining the established pattern effect with the remaining blockers on the target, only one candidate survives."

                                    else ->
                                        "The established pattern effect and the remaining blockers now squeeze the target down to its final answer, but it is not committed yet."
                                }

                            put("confrontation_proof_profile", confrontationProfile0.name)
                            put("confrontation_focus_atom_index", preferredProofAtomIndex0)
                            put("confrontation_pattern_reteach_forbidden", true)
                            put("confrontation_trigger_reference_only", true)

                            put("confrontation_trigger_kind", triggerKind0 ?: JSONObject.NULL)
                            put("confrontation_trigger_pattern", triggerPattern0 ?: JSONObject.NULL)

                            put(
                                "confrontation_trigger_reference_summary",
                                confrontationTriggerReferenceSummary0
                            )

                            put(
                                "confrontation_trigger_effect_summary",
                                confrontationTriggerEffectSummary0
                            )

                            put(
                                "confrontation_summary_payload",
                                if (atom0ConfrontationSummary.length() > 0) {
                                    atom0ConfrontationSummary
                                } else {
                                    JSONObject.NULL
                                }
                            )

                            put(
                                "confrontation_target_cell",
                                confrontationTargetCell0 ?: JSONObject.NULL
                            )

                            put(
                                "confrontation_primary_house",
                                confrontationPrimaryHouse0 ?: JSONObject.NULL
                            )

                            put(
                                "confrontation_claim_code",
                                proofClaim0?.optString("code", "") ?: ""
                            )

                            put(
                                "confrontation_spoiler_level",
                                proofSpoiler0.ifBlank { JSONObject.NULL }
                            )

                            put(
                                "confrontation_target_proof_rows",
                                if (targetProofRows0.length() > 0) {
                                    targetProofRows0
                                } else {
                                    JSONObject.NULL
                                }
                            )

                            put(
                                "confrontation_target_proof_row_count",
                                targetProofRows0.length()
                            )

                            put(
                                "confrontation_forcing_summary",
                                if (forcingSummary0.length() > 0) {
                                    forcingSummary0
                                } else {
                                    JSONObject.NULL
                                }
                            )

                            put(
                                "confrontation_remaining_candidate_digits",
                                if (remainingCandidateDigits0.length() > 0) {
                                    remainingCandidateDigits0
                                } else {
                                    JSONObject.NULL
                                }
                            )

                            put(
                                "confrontation_surviving_digit",
                                survivingDigit0 ?: JSONObject.NULL
                            )

                            put(
                                "confrontation_can_say_target_digit",
                                survivingDigit0 != null
                            )

                            put(
                                "confrontation_target_digit",
                                survivingDigit0 ?: JSONObject.NULL
                            )

                            put(
                                "confrontation_collapse_summary",
                                confrontationCollapseSummary0
                            )

                            put(
                                "confrontation_two_layer_honesty_line",
                                confrontationHonestyNote0 ?: JSONObject.NULL
                            )

                            put(
                                "confrontation_pre_commit_line",
                                "We have the answer logically, but we have not locked it into the grid yet."
                            )

                            put(
                                "confrontation_cta_kind",
                                requiredCtaOptions.firstOrNull() ?: "LOCK_IT_IN"
                            )

                            put(
                                "confrontation_overlay_variant",
                                defaultConfrontationOverlayVariantV1(confrontationProfile0)
                            )

                            // -------------------------------
                            // RESOLUTION guidance
                            // Resolution should COMMIT + RECAP compactly + HAND OFF.
                            // It should not restart setup or replay confrontation in full.
                            // -------------------------------
                            val resolutionProfile0 = resolveResolutionProfileV1(sAfter)

                            val commitAtomIndex0 =
                                when {
                                    (ns.focusAtomIndex ?: -1) >= 0 -> ns.focusAtomIndex ?: 0
                                    else -> {
                                        var found = -1
                                        if (atomsArr != null) {
                                            for (i in 0 until atomsArr.length()) {
                                                val a = atomsArr.optJSONObject(i)
                                                if (a?.optString("beat_kind", "") == "COMMIT") {
                                                    found = i
                                                    break
                                                }
                                            }
                                        }
                                        if (found >= 0) found else inScope.lastOrNull() ?: 0
                                    }
                                }

                            val commitAtom0 = atomsArr?.optJSONObject(commitAtomIndex0)
                            val commitFocus0 = commitAtom0?.optJSONObject("focus")
                            val commitClaim0 = commitAtom0?.optJSONObject("claim")
                            val commitArgs0 = commitClaim0?.optJSONObject("args")
                            val commitSpoiler0 = commitAtom0?.optString("spoiler_level", "") ?: ""

                            val resolutionCommitCell0 =
                                commitFocus0?.optJSONObject("target_cell")
                                    ?: proofFocus0?.optJSONObject("target_cell")
                                    ?: targetCell0

                            val resolutionCommitDigit0 =
                                runCatching { commitFocus0?.optInt("target_digit", -1) }
                                    .getOrNull()
                                    ?.takeIf { it > 0 }
                                    ?: survivingDigit0
                                    ?: targetDigit0

                            val resolutionCommitAuthorized0 =
                                ns.stage == StoryStage.RESOLUTION

                            val resolutionRecapSummary0 =
                                atom0ConfrontationSummary.optString("compact_resolution_summary")
                                    .takeIf { it.isNotBlank() }
                                    ?: defaultResolutionRecapSummaryV1(resolutionProfile0)

                            val resolutionTechniqueContributionSummary0 =
                                atom0ConfrontationSummary.optString("technique_contribution_summary")
                                    .takeIf { it.isNotBlank() }
                                    ?: defaultResolutionTechniqueContributionSummaryV1(
                                        resolutionProfile0
                                    )

                            val resolutionFinalForcingSummary0 =
                                forcingSummary0.optString("final_forcing_summary")
                                    .takeIf { it.isNotBlank() }
                                    ?: forcingSummary0.optString("forcing_note")
                                        .takeIf { it.isNotBlank() }
                                    ?: defaultResolutionFinalForcingSummaryV1(
                                        resolutionProfile0
                                    )

                            val resolutionHonestyLine0 =
                                confrontationHonestyNote0
                                    ?: introDerived0?.optString("honesty_note")
                                        ?.takeIf { it.isNotBlank() }

                            val resolutionPresentStateLine0 =
                                if (resolutionCommitDigit0 != null && resolutionCommitCell0 != null) {
                                    val rr = resolutionCommitCell0.optInt("r", -1)
                                    val cc = resolutionCommitCell0.optInt("c", -1)
                                    if (rr in 1..9 && cc in 1..9) {
                                        "So now we can place it: r${rr}c${cc} = $resolutionCommitDigit0."
                                    } else {
                                        "So now we can place the value $resolutionCommitDigit0 in the target cell."
                                    }
                                } else {
                                    "So now we can commit the answer on the target cell."
                                }

                            val resolutionPostCommitGridDeltaSummary0 =
                                when {
                                    resolutionCommitDigit0 != null ->
                                        "That target is now fixed, so we can move to the next solving step."

                                    else ->
                                        "This move is now committed, so we can move to the next solving step."
                                }

                            put("resolution_profile", resolutionProfile0.name)
                            put("resolution_focus_atom_index", commitAtomIndex0)
                            put("resolution_setup_reteach_forbidden", true)
                            put("resolution_proof_replay_forbidden", true)
                            put("resolution_commit_authorized", resolutionCommitAuthorized0)
                            put(
                                "resolution_present_state_language_required",
                                resolutionCommitAuthorized0
                            )
                            put(
                                "resolution_commit_truth_source",
                                if (commitAtom0 != null) "story_commit_atom" else "resolution_stage_default"
                            )

                            put(
                                "resolution_commit_cell",
                                resolutionCommitCell0 ?: JSONObject.NULL
                            )

                            put(
                                "resolution_commit_digit",
                                resolutionCommitDigit0 ?: JSONObject.NULL
                            )

                            put(
                                "resolution_claim_code",
                                commitClaim0?.optString("code", "") ?: ""
                            )

                            put(
                                "resolution_spoiler_level",
                                commitSpoiler0.ifBlank { JSONObject.NULL }
                            )

                            put(
                                "resolution_recap_summary",
                                resolutionRecapSummary0
                            )

                            put(
                                "resolution_technique_contribution_summary",
                                resolutionTechniqueContributionSummary0
                            )

                            put(
                                "resolution_final_forcing_summary",
                                resolutionFinalForcingSummary0
                            )

                            put(
                                "resolution_two_layer_honesty_line",
                                resolutionHonestyLine0 ?: JSONObject.NULL
                            )

                            put(
                                "resolution_present_state_line",
                                resolutionPresentStateLine0
                            )

                            put(
                                "resolution_post_commit_grid_delta_summary",
                                resolutionPostCommitGridDeltaSummary0
                            )

                            put(
                                "resolution_cta_kind",
                                "NEXT_STEP"
                            )

                            put(
                                "resolution_next_stage_ready",
                                true
                            )

                            put(
                                "resolution_commit_choice_reopen_forbidden",
                                true
                            )

                            put(
                                "resolution_overlay_variant",
                                defaultResolutionOverlayVariantV1(resolutionProfile0)
                            )

                            put(
                                "resolution_overlay_commit_state",
                                if (resolutionCommitAuthorized0) "committed" else "pre_commit"
                            )

                            put(
                                "resolution_overlay_arrival_emphasis",
                                "target_commit"
                            )
                        }.onFailure {
                            // keep story bundle valid even if parsing fails
                        }

                        put("atoms_in_scope_this_turn", JSONArray().apply { inScope.forEach { put(it) } })

                        put("required_end_cta_options", JSONArray().apply { requiredCtaOptions.forEach { put(it) } })

                        // Overlay rule helper: keep spotlight + include overlays for atoms in scope.
                        put("required_overlay_frame_ids", JSONArray().apply {
                            val frameIds = inScope.map { "ov:atom:$it" }.distinct()
                            frameIds.forEach { put(it) }
                        })
                    }
                )
            } else null
        }

        val setupReplyPacketBundle = buildSetupReplyPacketBundleV1(
            sAfter = sAfter,
            storyContextBundle = storyContextBundle
        )

        val confrontationReplyPacketBundle = buildConfrontationReplyPacketBundleV1(
            sAfter = sAfter,
            storyContextBundle = storyContextBundle
        )

        val resolutionReplyPacketBundle = buildResolutionReplyPacketBundleV1(
            sAfter = sAfter,
            storyContextBundle = storyContextBundle
        )

        val factsOutWithStory = if (storyContextBundle != null) {
            // Ensure only one STORY_CONTEXT_V1 / stage reply packet exists.
            val base = (
                    factsOut.filterNot {
                        it.type == FactBundleV1.Type.STORY_CONTEXT_V1 ||
                                it.type == FactBundleV1.Type.SETUP_REPLY_PACKET_V1 ||
                                it.type == FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1 ||
                                it.type == FactBundleV1.Type.RESOLUTION_REPLY_PACKET_V1
                    } + storyContextBundle
                    )

            // ✅ Phase 3 audit: STORY_SIGNATURE_V1 (hash + expanded fields)
            val p = storyContextBundle.payload
            val stepId = p.optString("step_id", "")
            val stage = p.optString("story_stage", "")
            val atomsInScope = runCatching {
                val a = p.optJSONArray("atoms_in_scope_this_turn") ?: org.json.JSONArray()
                buildList {
                    for (i in 0 until a.length()) add(a.optInt(i))
                }
            }.getOrElse { emptyList() }

            val ctas = runCatching {
                val a = p.optJSONArray("required_end_cta_options") ?: org.json.JSONArray()
                buildList {
                    for (i in 0 until a.length()) add(a.optString(i))
                }.filter { it.isNotBlank() }
            }.getOrElse { emptyList() }

            val sig = computeStorySignatureV1(
                stepId = stepId,
                stage = stage,
                atomsInScope = atomsInScope,
                requiredCtas = ctas
            )

            val withStorySignature = base + FactBundleV1(
                type = FactBundleV1.Type.STORY_SIGNATURE_V1,
                payload = org.json.JSONObject().apply {
                    put("signature_v1", sig)
                    put("step_id", stepId)
                    put("story_stage", stage)
                    put("atoms_in_scope_this_turn", org.json.JSONArray().apply { atomsInScope.forEach { put(it) } })
                    put("required_end_cta_options", org.json.JSONArray().apply { ctas.forEach { put(it) } })
                    put("last_story_signature_in_state", sAfter.lastStorySignatureV1 ?: org.json.JSONObject.NULL)
                }
            )

            when {
                setupReplyPacketBundle != null ->
                    withStorySignature + setupReplyPacketBundle

                confrontationReplyPacketBundle != null ->
                    withStorySignature + confrontationReplyPacketBundle

                resolutionReplyPacketBundle != null ->
                    withStorySignature + resolutionReplyPacketBundle

                else ->
                    withStorySignature
            }
        } else {
            val baseFacts = factsOut.filterNot {
                it.type == FactBundleV1.Type.SETUP_REPLY_PACKET_V1 ||
                        it.type == FactBundleV1.Type.CONFRONTATION_REPLY_PACKET_V1 ||
                        it.type == FactBundleV1.Type.RESOLUTION_REPLY_PACKET_V1
            }

            when {
                setupReplyPacketBundle != null ->
                    baseFacts + setupReplyPacketBundle

                confrontationReplyPacketBundle != null ->
                    baseFacts + confrontationReplyPacketBundle

                resolutionReplyPacketBundle != null ->
                    baseFacts + resolutionReplyPacketBundle

                else ->
                    baseFacts
            }
        }


        val replyDemand = resolveReplyDemandCategoryV1(
            sBefore = sBefore,
            sAfter = sAfter,
            userText = userText,
            openingTurn = false,
            decision = decision,
            envelope = envelope
        )

        runCatching {
            if (replyDemand.category == ReplyDemandCategoryV1.PENDING_CLARIFICATION) {
                ConversationTelemetry.emit(
                    mapOf(
                        "type" to "CLARIFICATION_SOVEREIGNTY_APPLIED_V1",
                        "turn_id" to sAfter.turnSeq,
                        "phase" to sAfter.phase.name,
                        "pending_after" to pendingSummary(sAfter.pending),
                        "user_agenda_head" to (sAfter.userAgendaQueue.firstOrNull()?.javaClass?.simpleName ?: "null"),
                        "reason" to replyDemand.reason
                    )
                )
            }
        }

        val phase2DetourBundles = buildPhase2DetourBundlesV1(
            sAfter = sAfter,
            facts = factsOutWithStory
        )

        val factsOutPreRepair =
            if (phase2DetourBundles.isNotEmpty()) {
                factsOutWithStory.filterNot {
                    it.type == FactBundleV1.Type.STEP_CLARIFICATION_PACKET_V1 ||
                            it.type == FactBundleV1.Type.PROOF_CHALLENGE_PACKET_V1 ||
                            it.type == FactBundleV1.Type.USER_REASONING_CHECK_PACKET_V1 ||
                            it.type == FactBundleV1.Type.ALTERNATIVE_TECHNIQUE_PACKET_V1 ||
                            it.type == FactBundleV1.Type.TARGET_CELL_QUERY_PACKET_V1 ||
                            it.type == FactBundleV1.Type.CANDIDATE_STATE_PACKET_V1 ||
                            it.type == FactBundleV1.Type.NEIGHBOR_CELL_QUERY_PACKET_V1 ||
                            it.type == FactBundleV1.Type.RETURN_TO_ROUTE_PACKET_V1
                } + phase2DetourBundles
            } else {
                factsOutWithStory
            }

        val factsOutFinal =
            when (replyDemand.category) {
                ReplyDemandCategoryV1.REPAIR_CONTRADICTION -> {
                    val stripped = stripRepairForbiddenFactsV1(factsOutPreRepair)
                    val strippedTypeNames = repairForbiddenFactTypeNamesV1(factsOutPreRepair)

                    stripped + FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = org.json.JSONObject().apply {
                            put("kind", "repair_fence_applied")
                            put(
                                "stripped_fact_types",
                                org.json.JSONArray().apply {
                                    strippedTypeNames.forEach { put(it) }
                                }
                            )
                            put(
                                "note",
                                "Repair demand stripped solving-story and solver-backed packets so Tick2 cannot leak a fresh solving route."
                            )
                        }
                    )
                }

                ReplyDemandCategoryV1.PENDING_CLARIFICATION -> {
                    val stripped = stripClarificationForbiddenFactsV1(factsOutPreRepair)
                    val strippedTypeNames = clarificationForbiddenFactTypeNamesV1(factsOutPreRepair)

                    stripped + FactBundleV1(
                        type = FactBundleV1.Type.OTHER,
                        payload = org.json.JSONObject().apply {
                            put("kind", "clarification_fence_applied")
                            put(
                                "stripped_fact_types",
                                org.json.JSONArray().apply {
                                    strippedTypeNames.forEach { put(it) }
                                }
                            )
                            put(
                                "note",
                                "Clarification demand stripped story, detour, and route packets so Tick2 can only ask the missing bounded clarification."
                            )
                        }
                    )
                }

                else -> {
                    factsOutPreRepair
                }
            }

        val ctaContractV1: CtaContractV1? = run {
            val banned = listOf(
                "setup",
                "confrontation",
                "resolution",
                "route checkpoint",
                "agenda",
                "owner",
                "detour",
                "packet",
                "story stage"
            )

            val ctaOwnerKind = constitutionalCtaOwnerKindV1(sAfter)

            val routeMoment = ReplyDemandContractsV1.deriveCtaRouteMomentV1(
                ownerKind = ctaOwnerKind,
                phase = sAfter.phase,
                pending = sAfter.pending,
                replyDemand = replyDemand,
                currentUserAgendaHead = sAfter.userAgendaQueue.firstOrNull(),
                facts = factsOutFinal
            )

            ReplyDemandContractsV1.buildCtaContractV1(
                ownerKind = ctaOwnerKind,
                routeMoment = routeMoment,
                focusCellRef = currentFocusCellRefForCtaV1(sAfter),
                focusHouseRef = currentFocusHouseRefForCtaV1(sAfter),
                focusDigit = currentFocusDigitForCtaV1(sAfter),
                techniqueName = null,
                bannedPhrases = banned
            )
        }

        val decisionSummaryFinal =
            if (replyDemand.category == ReplyDemandCategoryV1.PENDING_CLARIFICATION) {
                decisionSummaryWithCta +
                        "\n\nCLARIFICATION_SOVEREIGNTY: This turn is a bounded clarification turn." +
                        "\n- Ask exactly ONE clarification question only." +
                        "\n- Do NOT answer the underlying detour / solving question yet." +
                        "\n- Do NOT continue the app route or story body in this reply." +
                        "\n- Do NOT add a second CTA after the clarification question."
            } else {
                decisionSummaryWithCta
            }

        val finalReplyStyle = chooseReplyStyleForFactsV1(factsOutFinal)

        runCatching {
            val constitutionalCtaOwner = constitutionalCtaOwnerKindV1(sAfter)
            if (constitutionalCtaOwner != sAfter.activeTurnOwnerV1) {
                ConversationTelemetry.emit(
                    mapOf(
                        "type" to "LANE_ALIGNMENT_TRACE_V1",
                        "turn_id" to sAfter.turnSeq,
                        "legacy_owner" to sAfter.activeTurnOwnerV1.name,
                        "constitutional_cta_owner" to constitutionalCtaOwner.name,
                        "turn_authority_owner" to sAfter.activeTurnAuthorityDecisionV1.owner.name,
                        "route_boundary_status" to sAfter.activeRouteBoundaryDecisionV1.status.name,
                        "reason" to "cta_lane_uses_constitutional_owner_instead_of_legacy_owner"
                    )
                )
            }
        }

        runCatching {
            ConversationTelemetry.emitPolicyTrace(
                tag = "FINAL_REPLY_STYLE_V1",
                data = mapOf(
                    "turn_id" to sAfter.turnSeq,
                    "style_source" to "factsOutFinal",
                    "decision_style" to decision.replyStyle.toJson().toString(),
                    "final_style" to finalReplyStyle.toJson().toString(),
                    "fact_bundle_types" to factsOutFinal.joinToString(",") { it.type.name },
                    "fact_bundle_count" to factsOutFinal.size
                )
            )
        }

        val rr = ReplyRequestV1.build(
            turnId = safeTurnId,
            mode = sAfter.mode.name,
            phase = sAfter.phase.name,
            userText = userText,
            pendingBefore = pendingSummary(sBefore.pending),
            pendingAfter = pendingSummary(sAfter.pending),
            focusBefore = sBefore.focusCellIndex,
            focusAfter = sAfter.focusCellIndex,
            decisionKind = decision.decisionKind,
            decisionSummary = decisionSummaryFinal,
            mutationApplied = decision.mutationApplied,
            facts = factsOutFinal,
            style = finalReplyStyle,
            assistantStyleHeader = assistantStyleHeader,
            userTally = userTally,
            assistantTally = assistantTally,
            relationshipMemory = relationshipMemory,
            recentTurns = recentTurns,
            openingTurn = false,
            turnAuthorityOwner = sAfter.activeTurnAuthorityDecisionV1.owner.name,
            turnAuthorityReason = sAfter.activeTurnAuthorityDecisionV1.reason,
            turnPendingStatus = sAfter.activeTurnAuthorityDecisionV1.pendingAuthorityStatus.name,
            turnResumedPendingKind = sAfter.activeTurnAuthorityDecisionV1.resumedPendingKind,
            turnRouteReturnAllowed = sAfter.activeTurnAuthorityDecisionV1.routeReturnAllowed,
            turnBoundaryStatus = sAfter.activeRouteBoundaryDecisionV1.status.name,
            turnBoundaryReason = sAfter.activeRouteBoundaryDecisionV1.reason,
            replyDemandCategory = replyDemand.category,
            story = storyHeader
        )

        emitControlTruthInvariantAuditV1(
            turnId = safeTurnId.toLong(),
            tickId = 2,
            sAfter = sAfter,
            replyDemand = replyDemand,
            facts = factsOutFinal,
            storyHeader = storyHeader
        )

        runCatching {
            val cta = rr.ctaContract
            ConversationTelemetry.emitCtaPolicyTrace(
                turnId = turnId,
                tickId = 2,
                ownerKind = cta?.ownerKind ?: constitutionalCtaOwnerKindV1(sAfter).name,
                phase = sAfter.phase.name,
                storyStage = storyHeader?.stage ?: sAfter.narrativeStory?.stage?.name,
                pendingAfter = pendingSummary(sAfter.pending),
                ctaFamily = cta?.family?.name,
                ctaRouteMoment = cta?.routeMoment?.name,
                ctaExpectedResponseType = cta?.expectedResponseType?.name,
                ctaAskMode = cta?.askMode?.name,
                ctaFocusCellRef = cta?.focusCellRef,
                ctaFocusHouseRef = cta?.focusHouseRef,
                ctaFocusDigit = cta?.focusDigit,
                ctaTechniqueName = cta?.techniqueName,
                ctaAllowFollowUp = cta?.allowFollowUp,
                ctaAllowReturnToRoute = cta?.allowReturnToRoute,
                ctaAllowRouteMutation = cta?.allowRouteMutation,
                ctaMustOfferFollowUpChoice = cta?.policy?.mustOfferFollowUpChoice,
                ctaMustOfferReturnChoice = cta?.policy?.mustOfferReturnChoice,
                ctaMustNotAdvanceStage = cta?.policy?.mustNotAdvanceStage,
                ctaMustReferenceFocusScope = cta?.policy?.mustReferenceFocusScope,
                ctaAllowInternalJargon = cta?.policy?.allowInternalJargon,
                ctaBannedPhrases = cta?.bannedPhrases ?: emptyList()
            )
        }

        ConversationTelemetry.emitReplyDemandResolved(
            turnId = turnId,
            tickId = 2,
            category = replyDemand.category.name,
            reason = reasonWithDemandProfilesV1(replyDemand),
            phase = replyDemand.phase,
            pendingKind = replyDemand.pendingKind,
            storyStage = replyDemand.storyStage,
            openingTurn = replyDemand.openingTurn
        )

        val replyPlan = ReplyAssemblyPlannerV1.plan(
            demand = replyDemand,
            replyRequest = rr
        )

        val replyContract = replyPlan.plan.contract
            ?: resolveReplyDemandContractV1(replyDemand)

        ConversationTelemetry.emitReplyAssemblyPlan(
            turnId = turnId,
            tickId = 2,
            demandCategory = replyContract.demandCategory.name,
            requiredPromptModules = replyContract.requiredPromptModules.map { it.name }.sorted(),
            requiredChannels = replyContract.requiredChannels.map { it.name }.sorted(),
            optionalChannels = replyContract.optionalChannels.map { it.name }.sorted(),
            forbiddenChannels = replyContract.forbiddenChannels.map { it.name }.sorted(),
            selectedPromptModules = replyPlan.plan.selectedPromptModules.map { it.name },
            selectedChannels = replyPlan.plan.selectedChannels.map { it.name },
            rolloutMode = replyPlan.plan.rolloutMode,
            softCharBudget = replyContract.budget.softCharBudget,
            softTokenBudget = replyContract.budget.softTokenBudget,
            notes = notesWithDemandProfilesV1(replyContract.notes, replyDemand)
        )

        emitSetupCoverageTelemetryV1(
            turnId = turnId,
            demand = replyDemand,
            replyRequest = rr,
            planResult = replyPlan
        )

        emitConfrontationCoverageTelemetryV1(
            turnId = turnId,
            demand = replyDemand,
            replyRequest = rr,
            planResult = replyPlan
        )

        emitResolutionCoverageTelemetryV1(
            turnId = turnId,
            demand = replyDemand,
            replyRequest = rr,
            planResult = replyPlan
        )

        emitProjectedReplyChannelsV1(
            turnId = turnId,
            demand = replyDemand,
            planResult = replyPlan
        )

        emitReplyWasteAuditV1(
            turnId = turnId,
            demand = replyDemand,
            planResult = replyPlan
        )

        emitTick2FactsSummary(
            tag = "buildReplyRequestV1",
            sAfter = sAfter,
            turnId = turnId,
            tickId = 2,
            policyReqSeq = -1L,
            correlationId = "",
            modelCallId = null,
            toolplanId = null,
            openingTurn = false,
            pendingBefore = pendingSummary(sBefore.pending),
            pendingAfter = pendingSummary(sAfter.pending),
            facts = factsOutWithStory
        )

        return ReplyExecutionSpecV1(
            replyRequest = rr,
            planResult = replyPlan
        )
    }



    fun reduce(s: SudoState, e: Evt): Next {


        fun isRepairDetourIntent(t: IntentTypeV1): Boolean =
            t == IntentTypeV1.GRID_MISMATCH_REPORT ||
                    t == IntentTypeV1.EDIT_CELL ||
                    t == IntentTypeV1.CLEAR_CELL ||
                    t == IntentTypeV1.CONFIRM_CELL_AS_IS ||
                    t == IntentTypeV1.CONFIRM_CELL_TO_DIGIT ||
                    t == IntentTypeV1.ASK_CELL_VALUE ||
                    t == IntentTypeV1.ASK_CELL_STATUS

        fun hasRepairDetourIntent(envelope: IntentEnvelopeV1?): Boolean =
            envelope?.intents?.any { isRepairDetourIntent(it.type) } == true

        fun isRepairSensitivePending(p: Pending?): Boolean =
            p is Pending.ApplyHintNow || p is Pending.AfterResolution


        return when (e) {

            is Evt.AppStarted -> {
                Next(
                    s.copy(
                        mode = SudoMode.FREE_TALK,
                        pending = null,
                        repairAttempt = 0,
                        phase = GridPhase.CONFIRMING
                    ),
                    emptyList()
                )
            }




            is Evt.CameraActive -> {
                Next(
                    s.copy(
                        mode = SudoMode.FREE_TALK,
                        grid = null,
                        pending = null,
                        repairAttempt = 0,
                        phase = GridPhase.CONFIRMING
                    ),
                    listOf(Eff.StopAsr("camera_active"))
                )
            }

            is Evt.GridCaptured -> {
                // Base capture state
                val s1Base = s.copy(
                    mode = SudoMode.GRID_SESSION,
                    grid = e.grid,
                    pending = null,
                    repairAttempt = 0,
                    turnSeq = s.turnSeq + 1,
                    phase = GridPhase.CONFIRMING,

                    // Phase 2 DecisionMemory: new grid resets retake fork decision.
                    retakeDecision = RetakeDecisionV1.UNDECIDED,
                    retakeDismissed = false
                )

                // ✅ Seed App agenda immediately after capture (2B)
                val llmCapture = e.grid.llm as? LLMGridState
                val seededAgenda = buildAppAgendaFromGrid(
                    llm = llmCapture,
                    phase = GridPhase.CONFIRMING,
                    createdTurnSeq = s1Base.turnSeq,
                    userConfirmedPerfectMatch = false,
                    retakeDismissed = false,
                    startSolvingCtaActive = (s1Base.pending is Pending.ConfirmStartSolving)
                )

                val s1 = s1Base.copy(appAgendaQueue = seededAgenda)

                // ------------------------------------------------------------
                // Onboarding opening turn (still uses seeded state)
                // ------------------------------------------------------------
                if (!SessionStore.isOnboardingDone()) {
                    SessionStore.setOnboardingDone(true)

                    val header = buildStateHeader(s1)
                    val (s2, ctx2) = nextPolicyCtx(
                        s = s1,
                        tickId = 2,
                        reason = "opening_turn_after_grid_capture",
                        stateHeader = header,
                        turnId = s1.turnSeq
                    )

                    emitModelCallBegin(ctx2)

                    // ✅ Audit: PRE_TICK2 facts (no-op path)
                    runCatching {
                        emitGridFactsNowIfPresent(
                            s = s2,
                            ctx = ctx2,
                            stage = "PRE_TICK2",
                            note = "v1_no_ops"
                        )
                    }

                    val openingDemand = resolveReplyDemandCategoryV1(
                        sBefore = s,
                        sAfter = s2,
                        userText = "",
                        openingTurn = true,
                        decision = null,
                        envelope = null
                    )

                    val rr = ReplyRequestV1.build(
                        turnId = s1.turnSeq.toInt(),
                        mode = s1.mode.name,
                        phase = s1.phase.name,
                        userText = "",
                        pendingBefore = "none",
                        pendingAfter = "none",
                        focusBefore = s1.focusCellIndex,
                        focusAfter = s1.focusCellIndex,
                        decisionKind = DecisionKindV1.NO_OP,
                        decisionSummary =
                            "OPENING TURN: Welcome the user. Introduce yourself (Sudo) and persona. " +
                                    "Explain why we’re here: the user captured a scan/photo of their current Sudoku grid so you can guide them to the next best cell/value and keep them moving toward the solution. " +
                                    "Explain how we’ll work together: first, confirm that the on-screen grid from the scan matches the user’s paper grid exactly; next, verify the puzzle is valid and has a unique solution; then move into step-by-step solving and coaching. " +
                                    "Lead the conversation so the user doesn’t need to worry about what to do next. Use clear turn-taking: when you stop speaking, it’s the user’s turn— they can talk about the grid or any other topic. " +
                                    "Position yourself as a friendly Sudoku expert who always responds, and who updates the on-screen grid whenever needed so the user can see changes in real time. " +
                                    "Ask for the user's name, Sudoku experience level, and whether they are wolving on paper, in a book, on a tablet, or on a board. " +
                                    "Tell them we'll start discussing this captured puzzle right after.",
                        mutationApplied = null,
                        facts = emptyList(),
                        style = ReplyStyleV1(
                            voice = ReplyVoiceV1.story_coach,
                            tone = ReplyToneV1.warm,
                            maxWords = 200,
                            askOneQuestionMax = true
                        ),
                        assistantStyleHeader = "You are Sudo: witty Sudoku coach (light wit level 3). No emojis.",
                        userTally = SessionStore.getUserTally(),
                        assistantTally = SessionStore.getAssistantTally(),
                        recentTurns = SessionStore.getLast3Turns(),
                        openingTurn = true
                    )

                    ConversationTelemetry.emitReplyDemandResolved(
                        turnId = s1.turnSeq,
                        tickId = 2,
                        category = openingDemand.category.name,
                        reason = openingDemand.reason,
                        phase = openingDemand.phase,
                        pendingKind = openingDemand.pendingKind,
                        storyStage = openingDemand.storyStage,
                        openingTurn = openingDemand.openingTurn
                    )

                    val openingPlan = ReplyAssemblyPlannerV1.plan(
                        demand = openingDemand,
                        replyRequest = rr
                    )

                    val openingContract = openingPlan.plan.contract
                        ?: resolveReplyDemandContractV1(openingDemand)

                    ConversationTelemetry.emitReplyAssemblyPlan(
                        turnId = s1.turnSeq,
                        tickId = 2,
                        demandCategory = openingContract.demandCategory.name,
                        requiredPromptModules = openingContract.requiredPromptModules.map { it.name }.sorted(),
                        requiredChannels = openingContract.requiredChannels.map { it.name }.sorted(),
                        optionalChannels = openingContract.optionalChannels.map { it.name }.sorted(),
                        forbiddenChannels = openingContract.forbiddenChannels.map { it.name }.sorted(),
                        selectedPromptModules = openingPlan.plan.selectedPromptModules.map { it.name },
                        selectedChannels = openingPlan.plan.selectedChannels.map { it.name },
                        rolloutMode = openingPlan.plan.rolloutMode,
                        softCharBudget = openingContract.budget.softCharBudget,
                        softTokenBudget = openingContract.budget.softTokenBudget,
                        notes = openingContract.notes
                    )

                    emitProjectedReplyChannelsV1(
                        turnId = s1.turnSeq,
                        demand = openingDemand,
                        planResult = openingPlan
                    )
                    emitReplyWasteAuditV1(
                        turnId = s1.turnSeq,
                        demand = openingDemand,
                        planResult = openingPlan
                    )

                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "OPENING_TURN_SUPPRESSED_INTAKE",
                            "turn_id" to s1.turnSeq,
                            "tick_id" to 2,
                            "reason" to "onboarding_opening_turn",
                            "onboarding_done_before" to false,
                            "facts_count" to 0,
                            "pending_set" to false,
                            "decideGridIntakeOutcomeV1_called" to false
                        )
                    )

                    // Also log the Tick2 facts contract for the opening call (should always be empty facts).
                    emitTick2FactsSummary(
                        tag = "opening_turn",
                        sAfter = s2,
                        turnId = s1.turnSeq,
                        tickId = 2,
                        policyReqSeq = ctx2.policyReqSeq,
                        correlationId = ctx2.correlationId,
                        modelCallId = ctx2.modelCallId,
                        toolplanId = ctx2.toolplanId,
                        openingTurn = true,
                        pendingBefore = "none",
                        pendingAfter = "none",
                        facts = emptyList()
                    )

                    // ✅ If the SOLVING hint rung changed (MORE_HINT), refresh overlay deterministically
                    // BEFORE Tick2 speaks, so the UI matches what Tick2 can truthfully reference.
                    val extraEffs = mutableListOf<Eff>()
                    val hintIndexChanged =
                        (s1.solveAtomIndex != s2.solveAtomIndex) &&
                                (s2.pending is Pending.SolveIntroAction)

                    if (s2.phase == GridPhase.SOLVING &&
                        hintIndexChanged &&
                        s2.solveOverlayVisible &&
                        !s2.solveStepJson.isNullOrBlank()
                    ) {
                        val style = s2.solveOverlayStyle.ifBlank { "full" }

                        val applied =
                            authoritativeAppliedOverlayFrameIdsForRenderV1(s2)
                                .ifEmpty { listOf(currentSolveOverlayFrameId(s2, s2.solveAtomIndex)) }

                        val renderDetourNative =
                            shouldRenderDetourNativeOverlayV1(
                                s = s2,
                                appliedFrameIds = applied
                            )

                        val frameJson =
                            if (renderDetourNative) {
                                buildDetourOverlayCompositeFrameJsonV1(
                                    s = s2,
                                    frameIds = applied,
                                    style = style,
                                    reason = "solve_more_hint_overlay_refresh"
                                )
                            } else {
                                buildSolveOverlayCompositeFrameJsonV1(
                                    s = s2,
                                    frameIds = applied,
                                    style = style,
                                    reason = "solve_more_hint_overlay_refresh"
                                )
                            }

                        runCatching {
                            val cell66Summary = summarizeOverlayForCellV1(frameJson, 66)

                            ConversationTelemetry.emit(
                                mapOf(
                                    "type" to "OVERLAY_RENDER_REQUESTED",
                                    "session_id" to s2.sessionId,
                                    "turn_id" to s1.turnSeq,
                                    "tick_id" to 2,
                                    "phase" to s2.phase.name,
                                    "reason" to "solve_more_hint_overlay_refresh",
                                    "frame_id" to (applied.lastOrNull() ?: "none"),
                                    "applied_frame_ids" to applied.joinToString(","),
                                    "frame_json_sha12" to sha12(frameJson).take(12),
                                    "frame_json_len" to frameJson.length,
                                    "cell66_summary" to cell66Summary,
                                    "frame_json" to frameJson
                                )
                            )
                        }

                        extraEffs += Eff.RenderSolveOverlay(
                            frameJson = frameJson,
                            style = style,
                            reason = "solve_more_hint_overlay_refresh"
                        )
                    }

                    //val effs = mutableListOf<Eff>()

                    // ✅ Phase 2 North Star:
                    // If SOLVING overlay is visible, render the composite overlay for THIS turn
                    // BEFORE Tick2 speaks, so the visuals match the atom scope.
                    val sEnforced = s2  // <-- define it (opening turn has no contract enforcement anyway)

                    val effs = mutableListOf<Eff>()

// (Optional) Opening turn normally isn't SOLVING; keep this guard harmless.
                    if (sEnforced.phase == GridPhase.SOLVING &&
                        sEnforced.solveOverlayVisible &&
                        !sEnforced.solveStepJson.isNullOrBlank()
                    ) {
                        val style = sEnforced.solveOverlayStyle.ifBlank { "full" }
                        val applied = currentAppliedOverlayFrameIdsOrNull(sEnforced)
                            ?: listOf(currentSolveOverlayFrameId(sEnforced, sEnforced.solveAtomIndex))

                        val frameJson = buildSolveOverlayCompositeFrameJsonV1(
                            s = sEnforced,
                            frameIds = applied,
                            style = style,
                            reason = "pre_tick2_overlay_choreography"
                        )

                        effs += Eff.RenderSolveOverlay(
                            frameJson = frameJson,
                            style = style,
                            reason = "pre_tick2_overlay_choreography"
                        )
                    }

                    effs += Eff.CallReplyGenerateV1(
                        ctx = ctx2,
                        replyRequest = rr,
                        planResult = openingPlan,
                        reason = "opening_turn_after_grid_capture",
                        turnId = s1.turnSeq   // ✅ GridCaptured has no e.ctx; use the turn we created
                    )

                    return Next(sEnforced, effs)
                }

                // ------------------------------------------------------------
                // Tick2 after capture (non-onboarding)
                // ------------------------------------------------------------
                val llm = llmGrid(s1)
                if (llm == null) {
                    // Very rare: no LLMGridState snapshot. Fall back to a simple prompt.
                    val header = buildStateHeader(s1)
                    val (s2, ctx2) = nextPolicyCtx(
                        s = s1,
                        tickId = 2,
                        reason = "grid_captured_tick2_fallback",
                        stateHeader = header,
                        turnId = s1.turnSeq
                    )

                    emitPolicyCallTrace(
                        traceState = s1,
                        userText = "",
                        stateHeader = header,
                        reason = "grid_captured_tick2_fallback",
                        turnId = s1.turnSeq,
                        ctx = ctx2,
                        extraData = mapOf(
                            "decision_kind" to DecisionKindV1.NO_OP.name,
                            "fact_bundle_types" to ""
                        )
                    )
                    emitModelCallBegin(ctx2)

                    val rr = ReplyRequestV1.build(
                        turnId = s1.turnSeq.toInt(),
                        mode = s1.mode.name,
                        phase = s1.phase.name,
                        userText = "",
                        pendingBefore = "none",
                        pendingAfter = "none",
                        focusBefore = s1.focusCellIndex,
                        focusAfter = s1.focusCellIndex,
                        decisionKind = DecisionKindV1.NO_OP,
                        decisionSummary = "Grid captured.",
                        mutationApplied = null,
                        facts = emptyList(),
                        style = ReplyStyleV1()
                    )

                    Next(
                        s2,
                        listOf(
                            Eff.CallReplyGenerateV1(
                                ctx = ctx2,
                                replyRequest = rr,
                                reason = "grid_captured_tick2_fallback",
                                turnId = s1.turnSeq
                            )
                        )
                    )
                } else {
                    // ✅ Deterministic intake (183-quality behavior)
                    val sBefore = s1

                    val tDecisionStart = System.currentTimeMillis()
                    val decision = decideGridIntakeOutcomeV1(s1, llm)
                    val tDecisionEnd = System.currentTimeMillis()

                    // Route state mutations through SAME choke point as Tick1-plan:
                    val intakePlan = PlanV1(
                        summary = "grid_intake_v1",
                        ops = emptyList(),
                        factBundles = decision.factBundles,

                        newMode = decision.stateMutations.newMode,
                        newPhase = decision.stateMutations.newPhase,
                        newPending = decision.stateMutations.newPending,
                        newFocusIdx = decision.stateMutations.newFocusIdx,

                        // ✅ Keep seeded queues as-is on intake (unless you explicitly want otherwise)
                        userAgendaQueue = s1.userAgendaQueue,
                        appAgendaQueue = s1.appAgendaQueue,

                        newPrefs = null
                    )

                    val sAfterPlan = applyPlannedStateV1(
                        s = s1,
                        plan = intakePlan,
                        tDecisionStart = tDecisionStart,
                        tDecisionEnd = tDecisionEnd
                    ).copy(
                        lastDecisionKind = decision.decisionKind,
                        lastFactBundleTypes = decision.factBundles.map { it.type.name }
                    )

                    val headerAfter = buildStateHeader(sAfterPlan)
                    val (s2, ctx2) = nextPolicyCtx(
                        s = sAfterPlan,
                        tickId = 2,
                        reason = "grid_intake_tick2",
                        stateHeader = headerAfter,
                        turnId = sAfterPlan.turnSeq
                    )

                    emitPolicyCallTrace(
                        traceState = sAfterPlan,
                        userText = "",
                        stateHeader = headerAfter,
                        reason = "grid_intake_tick2",
                        turnId = sAfterPlan.turnSeq,
                        ctx = ctx2,
                        extraData = intakeDiagMap(llm) + mapOf(
                            "decision_kind" to decision.decisionKind.name,
                            "fact_bundle_types" to decision.factBundles.joinToString(",") { it.type.name }
                        )
                    )
                    emitModelCallBegin(ctx2)

                    val replyExec = buildReplyRequestV1(
                        sBefore = sBefore,
                        sAfter = s2, // policyReqSeq bumped only
                        turnId = sAfterPlan.turnSeq,
                        userText = "",
                        decision = decision,
                        factBundles = decision.factBundles
                    )

                    Next(
                        s2, // IMPORTANT: do NOT re-apply pending/mode/phase/focus here; already applied + synced
                        listOf(
                            Eff.CallReplyGenerateV1(
                                ctx = ctx2,
                                replyRequest = replyExec.replyRequest,
                                planResult = replyExec.planResult,
                                reason = "grid_intake_tick2",
                                turnId = sAfterPlan.turnSeq
                            )
                        )
                    )
                }
            }


            is Evt.IntentEnvelopeReceived -> {
                val sBefore = s

                // ✅ Audit: PRE_TICK1 facts (truth at the moment Tick1 planning runs)
                runCatching {
                    emitGridFactsNowIfPresent(
                        s = sBefore,
                        ctx = e.ctx,
                        stage = "PRE_TICK1",
                        note = "intent_envelope_received_before_plan"
                    )
                }

                // ------------------------------------------------------------
                // ✅ Tick-1 memory updates (LLM-provided deltas)
                // ------------------------------------------------------------
                runCatching {
                    // Always lock in the first user speech once per session
                    com.contextionary.sudoku.SessionStore.ensureFirstUserSpeech(e.userText)

                    // Apply LLM-inferred deltas (if present)
                    e.env.userTallyDelta?.let { delta ->
                        com.contextionary.sudoku.SessionStore.mergeUserTallyDelta(delta)
                    }
                    e.env.assistantTallyDelta?.let { delta ->
                        com.contextionary.sudoku.SessionStore.mergeAssistantTallyDelta(delta)
                    }
                    e.env.relationshipDelta?.let { delta ->
                        if (delta.observations.isNotEmpty() || delta.candidateUpdates.isNotEmpty()) {
                            com.contextionary.sudoku.SessionStore.mergeRelationshipDelta(delta)
                            android.util.Log.d("SudoConductor", "Tick1 relationship_delta merged: ${delta.toJson()}")
                        }
                    }
                }

                // ------------------------------------------------------------
                // Phase-2: deterministic post-processing (IntentBinderV1)
                // ------------------------------------------------------------
                val turnCtx: com.contextionary.sudoku.conductor.policy.TurnContextV1 =
                    runCatching {
                        val j = sBefore.lastTick1TurnCtxJson
                        val parsed = j?.let { com.contextionary.sudoku.conductor.policy.TurnContextV1.fromJsonString(it) }
                        parsed ?: run {
                            // fallback (best-effort) — still deterministic for this turn
                            val header = buildStateHeader(sBefore)
                            val pendingBefore = headerLineValue(header, "pending")
                            val pendingExpectedKind = headerLineValue(header, "pending_expected_answer_kind")
                            val pendingTargetCell = headerLineValue(header, "pending_target_cell")
                            val focusCell = headerLineValue(header, "focus_cell")
                            val lastQuestionKey = headerLineValue(header, "last_assistant_question_key")
                            val canonicalSolvingPositionKind =
                                resolveCanonicalSolvingStepPositionV1(sBefore)?.kind?.name

                            com.contextionary.sudoku.SessionStore.snapshotTurnContextV1(
                                turnId = sBefore.turnSeq,
                                mode = sBefore.mode.name,
                                phase = sBefore.phase.name,
                                // Phase 1 invariant: raw user text must not be consumed by Maps.
// TurnContextV1 is used only to deterministically bind intent targets.
                                userText = "",
                                pendingBefore = pendingBefore,
                                pendingExpectedAnswerKind = pendingExpectedKind,
                                pendingTargetCell = pendingTargetCell,
                                focusCell = focusCell,
                                lastAssistantQuestionKey = lastQuestionKey,
                                canonicalSolvingPositionKind = canonicalSolvingPositionKind
                            )
                        }
                    }.getOrElse {
                        // ultra-safe fallback
                        com.contextionary.sudoku.SessionStore.snapshotTurnContextV1(
                            turnId = sBefore.turnSeq,
                            mode = sBefore.mode.name,
                            phase = sBefore.phase.name,
                            // Phase 1 invariant: raw user text must not be consumed by Maps.
// TurnContextV1 is used only to deterministically bind intent targets.
                            userText = "",
                            pendingBefore = null,
                            pendingExpectedAnswerKind = null,
                            pendingTargetCell = null,
                            focusCell = null,
                            lastAssistantQuestionKey = null
                        )
                    }



                val bindRes = com.contextionary.sudoku.conductor.policy.IntentBinderV1.bind(e.env, turnCtx)
                val envBound = bindRes.envelope
                val detourRouting = classifyDetourRoutingSnapshotV1(envBound, bindRes)

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "INTENT_BINDER_V1",
                        data = mapOf(
                            "turn_id" to sBefore.turnSeq,
                            "did_bind_yesno_to_pending" to bindRes.diag.didBindYesNoToPending,
                            "did_fill_target_from_focus" to bindRes.diag.didFillTargetFromFocus,
                            "did_merge_duplicates" to bindRes.diag.didMergeDuplicates,
                            "did_bind_assistant_question_followup" to bindRes.diag.didBindAssistantQuestionFollowup,
                            "assistant_followup_disposition" to (bindRes.diag.assistantFollowupDisposition ?: "null"),
                            "is_route_following_intent" to bindRes.diag.isRouteFollowingIntent,
                            "is_route_control_intent" to bindRes.diag.isRouteControlIntent,

                            "detour_question_class" to (bindRes.diag.detourQuestionClass?.name ?: "null"),
                            "solving_road_semantic" to (bindRes.diag.solvingRoadSemantic?.name ?: "null"),
                            "repeat_semantic_active" to (bindRes.diag.solvingRoadSemantic == SolvingRoadSemanticV2.REPEAT_CURRENT_STAGE),
                            "top_intent_type" to (detourRouting.topIntentType?.name ?: "null"),
                            "notes" to bindRes.diag.notes.joinToString(" | ")


                        )
                    )
                }

                val tDecisionStart = System.currentTimeMillis()

                // ------------------------------------------------------------
                // ✅ Native pipeline (no “Meaning”):
                // - expiry of user agenda clarifications
                // - consume addressed clarification head (if applicable)
                // - build PlanV1 from IntentEnvelopeV1 (single Tick1 contract)
                // ------------------------------------------------------------
                val sExpired = expireUserAgendaIfStale(sBefore, envBound)
                val sConsumed = consumeUserAgendaHeadIfAddressed(sExpired, envBound)

                // Stage progression must happen before planning so planner/pending/op selection
                // consume the authoritative current stage for this turn.
                val (sPrePlanned, diagPrePlanNoRepeat) = enforceNoRepeatStoryV1(
                    s = sConsumed,
                    userText = e.userText,
                    allowRepeat = (detourRouting.solvingRoadSemantic == SolvingRoadSemanticV2.REPEAT_CURRENT_STAGE)
                )

                runCatching {
                    if (diagPrePlanNoRepeat.isNotEmpty()) {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "STORY_REPEAT_PREVENTED",
                                "session_id" to sPrePlanned.sessionId,
                                "turn_id" to sPrePlanned.turnSeq,
                                "tick_id" to 1,
                                "diag" to diagPrePlanNoRepeat.toString(),
                                "phase" to "PRE_PLANNING"
                            )
                        )
                    }
                }

                val detourStateForTurn = buildDetourStateScaffoldV1(
                    s = sPrePlanned,
                    env = envBound,
                    routing = detourRouting
                )

                if (
                    detourStateForTurn?.answerState == DetourAnswerStateV1.FAILED_AWAITING_RECOVERY &&
                    detourStateForTurn.failureRecoveryDecision != DetourFailureRecoveryDecisionV1.NONE
                ) {
                    runCatching {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "DETOUR_FAILURE_RECOVERY_DECISION_V1",
                            data = mapOf(
                                "turn_id" to sPrePlanned.turnSeq,
                                "decision" to detourStateForTurn.failureRecoveryDecision.name,
                                "failure_reason" to (detourStateForTurn.answerFailureReason ?: "null"),
                                "question_class" to (detourStateForTurn.questionClass?.name ?: "null"),
                                "anchor_step_id" to (detourStateForTurn.anchorStepId ?: "null"),
                                "anchor_stage" to (detourStateForTurn.anchorStage?.name ?: "null")
                            )
                        )
                    }
                }

                val repairDetourNow =
                    (sPrePlanned.phase == GridPhase.SOLVING) &&
                            isRepairSensitivePending(sPrePlanned.pending) &&
                            hasRepairDetourIntent(envBound)

                val plan = planFromIntentEnvelopeV1(
                    s = sPrePlanned,
                    env = envBound,
                    routing = detourRouting
                )

                val tDecisionEnd = System.currentTimeMillis()


                val detourStateForTurnWithAgendaSemantics =
                    attachDetourAgendaSemanticsToStateV1(
                        detourState = detourStateForTurn,
                        item = plan.userAgendaQueue.firstOrNull()
                    )

                // Apply planned state (mode/phase/focus/pending/queues + timings)
                val sAfterPlanBaseRaw = applyPlannedStateV1(
                    s = sPrePlanned,
                    plan = plan,
                    tDecisionStart = tDecisionStart,
                    tDecisionEnd = tDecisionEnd
                ).copy(
                    lastDecisionKind = when {
                        plan.userAgendaQueue.firstOrNull().let { it is UserAgendaItem.Clarification && it.askedTurnSeq == sPrePlanned.turnSeq } ->
                            DecisionKindV1.ASKED_CLARIFICATION
                        plan.factBundles.isNotEmpty() ->
                            DecisionKindV1.ANSWERED_GRID_QUESTION
                        plan.ops.isNotEmpty() ->
                            DecisionKindV1.APPLIED_MUTATION
                        else ->
                            DecisionKindV1.NO_OP
                    },
                    lastFactBundleTypes = plan.factBundles.map { it.type.name },
                    detourState = detourStateForTurnWithAgendaSemantics,
                    detourNarrativeContextV1 =
                        if (detourStateForTurn?.isActive == true) {
                            sPrePlanned.detourNarrativeContextV1
                        } else {
                            null
                        }
                )

                val sAfterPlanBase = sAfterPlanBaseRaw.copy(
                    pending = reconcilePendingFromActiveDetourStateV1(
                        pending = sAfterPlanBaseRaw.pending,
                        detourState = detourStateForTurnWithAgendaSemantics
                    )
                )

                runCatching {
                    emitDetourIsolationInvariantV1(
                        s = sAfterPlanBase,
                        stage = "POST_PLAN_PENDING_RECONCILE"
                    )
                }

                val sAfterPlanRaw =
                    if (repairDetourNow) {
                        val repairedQueue =
                            sAfterPlanBase.appAgendaQueue.filterNot {
                                it is AppAgendaItem.Solving.DetourFreeTalk
                            }

                        val repairedStory =
                            sAfterPlanBase.narrativeStory?.let { story0 ->
                                val n = story0.atomsCount.coerceAtLeast(1)

                                story0.copy(
                                    stage = StoryStage.CONFRONTATION,
                                    focusAtomIndex = defaultFocusAtomIndexForStageV1(
                                        stage = StoryStage.CONFRONTATION,
                                        atomsCount = n
                                    ),
                                    discussedAtomIndices = narrationAtomIndicesForStageV1(
                                        stage = StoryStage.CONFRONTATION,
                                        atomsCount = n
                                    ),
                                    readyForCommit = true
                                )
                            }

                        val repairedPending =
                            projectPendingFromQueueHead(
                                s = sAfterPlanBase,
                                queue = repairedQueue,
                                story = repairedStory,
                                preferred = null
                            )

                        syncCanonicalSolvingPositionV1(
                            sAfterPlanBase.copy(
                                appAgendaQueue = repairedQueue,
                                narrativeStory = repairedStory,
                                pending = repairedPending
                            )
                        )
                    } else {
                        sAfterPlanBase
                    }

                val sAfterPlanOverlay = syncCanonicalSolvingPositionV1(
                    applyDetourOverlayOverrideToStateV1(sAfterPlanRaw)
                )

                val (sAfterPlan, diagPostPlanNoRepeat) = enforceNoRepeatStoryFinalV1(
                    sBeforePlan = sPrePlanned,
                    sAfterPlan = sAfterPlanOverlay,
                    userText = e.userText,
                    allowRepeat = (detourRouting.solvingRoadSemantic == SolvingRoadSemanticV2.REPEAT_CURRENT_STAGE),
                    boundaryReturnAcceptedV1 = plan.boundaryReturnAcceptedV1,
                    boundaryResumePolicyV1 = plan.boundaryResumePolicyV1
                )

                runCatching {

                    val boundaryContext = buildBoundaryGuardContextV1(
                        sBeforePlan = sPrePlanned,
                        sAfterPlan = sAfterPlanOverlay,
                        userText = e.userText,
                        boundaryReturnAcceptedV1 = plan.boundaryReturnAcceptedV1,
                        boundaryResumePolicyV1 = plan.boundaryResumePolicyV1
                    )
                    val boundaryBefore = boundaryContext.effectiveBeforePos
                    val boundaryRawBefore = boundaryContext.rawBeforePos
                    val boundaryCheckpointBefore = boundaryContext.checkpointBeforePos
                    val boundaryRestoredBefore = boundaryContext.restoredRouteBeforePos
                    val boundaryProposedAfter = resolveCanonicalSolvingStepPositionV1(sAfterPlanOverlay)
                    val boundaryFinalAfter = resolveCanonicalSolvingStepPositionV1(sAfterPlan)

                    val recomputeReplanV1 = isBoundaryRecomputeReplanV1(
                        boundaryReturnAcceptedV1 = plan.boundaryReturnAcceptedV1,
                        boundaryResumePolicyV1 = plan.boundaryResumePolicyV1,
                        context = boundaryContext
                    )

                    runCatching {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "SOLVING_BOUNDARY_MATRIX_V1",
                            data = mapOf(
                                "turn_id" to sAfterPlan.turnSeq,
                                "guard_mode" to boundaryContext.mode.name,
                                "effective_before_source" to boundaryContext.beforeSource.name,
                                "same_step_guard_enabled" to boundaryContext.sameStepGuardEnabled,
                                "trust_source" to boundaryContext.trustSource,
                                "recompute_replan_v1" to recomputeReplanV1,
                                "before" to canonicalPositionSummaryV1(boundaryBefore),
                                "raw_before" to canonicalPositionSummaryV1(boundaryRawBefore),
                                "checkpoint_before" to canonicalPositionSummaryV1(boundaryCheckpointBefore),
                                "restored_route_before" to canonicalPositionSummaryV1(boundaryRestoredBefore),
                                "proposed_after" to canonicalPositionSummaryV1(boundaryProposedAfter),
                                "final_after" to canonicalPositionSummaryV1(boundaryFinalAfter),
                                "pending_final" to (sAfterPlan.pending?.javaClass?.simpleName ?: "null"),
                                "queue_head_final" to (currentQueuedSolvingHead(sAfterPlan)?.javaClass?.simpleName ?: "null"),
                                "story_stage_final" to (sAfterPlan.narrativeStory?.stage?.name ?: "null")
                            )
                        )
                    }


                    val boundaryBlocked =
                        (diagPostPlanNoRepeat["final_boundary_guard_blocked"] as? Boolean) == true
                    val boundaryRepaired =
                        (diagPostPlanNoRepeat["final_no_repeat_enforced"] as? Boolean) == true
                    val boundaryLegal =
                        !boundaryBlocked &&
                                validateCanonicalSolvingPositionV1(sAfterPlan, boundaryFinalAfter).isEmpty()

                    if (
                        sAfterPlan.phase == GridPhase.SOLVING &&
                        (
                                boundaryBefore != null ||
                                        boundaryProposedAfter != null ||
                                        boundaryFinalAfter != null ||
                                        diagPostPlanNoRepeat.isNotEmpty()
                                )
                    ) {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "SOLVING_BOUNDARY_TRANSITION",
                                "session_id" to sAfterPlan.sessionId,
                                "turn_id" to sAfterPlan.turnSeq,
                                "tick_id" to 1,
                                "phase" to "POST_PLANNING",
                                "before_kind" to (boundaryBefore?.kind?.name ?: "null"),
                                "proposed_after_kind" to (boundaryProposedAfter?.kind?.name ?: "null"),
                                "final_after_kind" to (boundaryFinalAfter?.kind?.name ?: "null"),
                                "before_step_id" to (boundaryBefore?.stepId ?: "null"),
                                "proposed_after_step_id" to (boundaryProposedAfter?.stepId ?: "null"),
                                "final_after_step_id" to (boundaryFinalAfter?.stepId ?: "null"),
                                "before_ready_for_commit" to (boundaryBefore?.readyForCommit ?: false),
                                "proposed_after_ready_for_commit" to (boundaryProposedAfter?.readyForCommit ?: false),
                                "final_after_ready_for_commit" to (boundaryFinalAfter?.readyForCommit ?: false),
                                "boundary_blocked" to boundaryBlocked,
                                "boundary_repaired" to boundaryRepaired,
                                "boundary_legal" to boundaryLegal,
                                "diag" to diagPostPlanNoRepeat.toString()
                            )
                        )
                    }
                }

                // Emit plan contract (audit-critical)
                runCatching { emitAppPlanV1(ctx = e.ctx, sBefore = sBefore, sAfter = sAfterPlan, env = envBound, plan = plan) }


                // Keep agenda snapshot telemetry
                runCatching { emitAgendaStateSnapshotV1(ctx = e.ctx, sBefore = sBefore, sAfter = sAfterPlan) }

                runCatching {
                    if (repairDetourNow) {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "REPAIR_DETOUR_PREEMPT",
                            data = mapOf(
                                "turn_id" to sBefore.turnSeq,
                                "pending_before" to (sPrePlanned.pending?.javaClass?.simpleName ?: "null"),
                                "queue_solving_head_before" to (currentQueuedSolvingHead(sPrePlanned)?.javaClass?.simpleName ?: "null"),
                                "queue_solving_head_after" to (currentQueuedSolvingHead(sAfterPlan)?.javaClass?.simpleName ?: "null"),
                                "decision_kind" to (sAfterPlan.lastDecisionKind?.name ?: "null")
                            )
                        )
                    }
                }

                // ✅ Phase 0: Turn Contract Snapshot — POST_TICK1
                runCatching {
                    emitTurnContractSnapshot(
                        stage = "POST_TICK1",
                        note = "after_plan_applied_before_post_decision",
                        s = sAfterPlan,
                        ctx = e.ctx,
                        facts = plan.factBundles,
                        tick2CallsForTurn = null
                    )
                }

                // ------------------------------------------------------------
                // DecisionOutcomeV1 (kept for ReplyRequestV1 builder compatibility)
                // ------------------------------------------------------------
                val decisionKind = when {
                    plan.userAgendaQueue.firstOrNull().let { it is UserAgendaItem.Clarification && it.askedTurnSeq == sConsumed.turnSeq } ->
                        DecisionKindV1.ASKED_CLARIFICATION
                    plan.factBundles.isNotEmpty() ->
                        DecisionKindV1.ANSWERED_GRID_QUESTION
                    plan.ops.isNotEmpty() ->
                        DecisionKindV1.APPLIED_MUTATION
                    else ->
                        DecisionKindV1.NO_OP
                }

                // Best-effort: only “SET/CLEAR” mutationApplied applies to ApplyCellEdit (confirms are NOT edits)
                val mutationApplied: MutationAppliedV1? =
                    (plan.ops.firstOrNull() as? PlannedOpV1.ApplyCellEdit)?.let { op ->
                        val cell = indexToCell(op.cellIndex)
                        MutationAppliedV1(
                            op = if (op.digit == 0) com.contextionary.sudoku.conductor.policy.MutationOpV1.CLEAR
                            else com.contextionary.sudoku.conductor.policy.MutationOpV1.SET,
                            cell = cell,
                            value = op.digit
                        )
                    }

                val outcome = DecisionOutcomeV1(
                    decisionKind = decisionKind,
                    summary = plan.summary ?: "plan",
                    mutationApplied = mutationApplied,
                    stateMutations = StateMutationsV1(
                        newMode = plan.newMode,
                        newPhase = plan.newPhase,
                        newPending = plan.newPending,
                        newFocusIdx = plan.newFocusIdx
                    ),
                    factBundles = plan.factBundles,
                    replyStyle = chooseReplyStyleForFactsV1(plan.factBundles),
                    needsClarification = (decisionKind == DecisionKindV1.ASKED_CLARIFICATION),
                    clarificationQuestionHint = (plan.userAgendaQueue.firstOrNull() as? UserAgendaItem.Clarification)?.prompt
                )

                // ✅ Audit: POST_DECISION facts (state mutations chosen, before apply tools run)
                runCatching {
                    emitGridFactsNowIfPresent(
                        s = sAfterPlan,
                        ctx = e.ctx,
                        stage = "POST_DECISION",
                        note = "after_plan_before_apply"
                    )
                }

                // ✅ Phase 0: Turn Contract Snapshot — POST_DECISION
                runCatching {
                    emitTurnContractSnapshot(
                        stage = "POST_DECISION",
                        note = "after_post_decision_gridfacts_before_apply_or_tick2",
                        s = sAfterPlan,
                        ctx = e.ctx,
                        facts = plan.factBundles,
                        tick2CallsForTurn = null
                    )
                }



                // ------------------------------------------------------------
                // Build operational effects from ALL planned ops
                // ------------------------------------------------------------
                val opEffs = plan.ops.map { op -> opToEffectV1(op, turnId = e.ctx.turnId) }

                // ------------------------------------------------------------
                // If ops exist -> latch reply until ALL tools executed
                // ------------------------------------------------------------
                if (opEffs.isNotEmpty()) {
                    val toolIds = opEffs.mapNotNull { eff ->
                        when (eff) {
                            is Eff.ApplyCellEdit -> eff.toolCallId
                            is Eff.ConfirmCellValue -> eff.toolCallId
                            is Eff.Undo -> eff.toolCallId
                            is Eff.Redo -> eff.toolCallId
                            is Eff.AddCandidate -> eff.toolCallId
                            is Eff.RemoveCandidate -> eff.toolCallId
                            is Eff.SetCandidates -> eff.toolCallId

                            // ✅ GAP-1 FIX: finalize tool must also participate in the reply latch
                            is Eff.FinalizeValidationPresentation -> eff.toolCallId

                            else -> null
                        }
                    }.toSet()

                    val sLatched = sAfterPlan.copy(
                        // ✅ Arm POST_APPLY snapshot: will be emitted on Evt.GridSnapshotUpdated after tools mutate truth
                        pendingGridFactsSnapshot = PendingGridFactsSnapshot(
                            ctx = e.ctx,
                            stage = "POST_APPLY"
                        ),
                        pendingReplyV1 = PendingReplyV1(
                            ctx = e.ctx,
                            turnId = e.ctx.turnId,
                            userText = e.userText,
                            sBefore = sBefore,
                            decision = outcome,
                            factBundles = plan.factBundles,
                            pendingToolCallIds = toolIds,
                            doneToolCallIds = emptySet()
                        )
                    )

                    return Next(
                        sLatched,
                        opEffs
                    )
                }


                // ------------------------------------------------------------
// ✅ Phase 7: Clean exit — Next step MUST actually request a fresh solve step.
// Even if we are already READY for the same grid hash, a user "Next step" means:
// compute again (the engine will return the next step for the current grid).
// ------------------------------------------------------------
                val llmForSolve = sAfterPlan.grid?.llm
                val deferSolveProgressionForUserDetour =
                    shouldDeferSolveProgressionForUserDetourV1(sAfterPlan)

                if (llmForSolve != null &&
                    sAfterPlan.phase == GridPhase.SOLVING &&
                    !deferSolveProgressionForUserDetour
                ) {
                    val g81 = grid81FromLLM(llmForSolve)
                    val h12 = sha12(g81).take(12)

                    val alreadyReadyForHash =
                        (sAfterPlan.solveStepStatus == SolveStepStatus.READY) &&
                                (sAfterPlan.solveStepGridHash12?.take(12) == h12)

                    val alreadyComputingForHash =
                        (sAfterPlan.solveStepStatus == SolveStepStatus.COMPUTING) &&
                                (sAfterPlan.pendingSolveStepAutocoach?.gridHash12?.take(12) == h12)

                    val alreadyFailedForHash =
                        (sAfterPlan.solveStepStatus == SolveStepStatus.FAILED) &&
                                (sAfterPlan.solveStepGridHash12?.take(12) == h12)

                    // Batch A:
                    // a real post-commit / next-step-ready boundary must force the
                    // next solving step compute. This removes dependence on stale
                    // pending/queue lag at the step handoff.
                    val readyForNextStepBoundary =
                        isReadyForNextStepBoundaryV1(sAfterPlan) && !repairDetourNow

                    val forceNextStep =
                        ((plan.newAdvanceToNextStep == true) || readyForNextStepBoundary) &&
                                !repairDetourNow

                    if ((forceNextStep && !alreadyComputingForHash && !alreadyFailedForHash) ||
                        (!alreadyReadyForHash && !alreadyComputingForHash && !alreadyFailedForHash)) {

                        val reason = if (forceNextStep) "solve_next_step_requested" else "enter_solving_prefetch"
                        val forceFlag = forceNextStep

                        val sLatched = sAfterPlan.copy(
                            solveStepStatus = SolveStepStatus.COMPUTING,

                            // Wave 2:
                            // clear stale READY/current-step payloads so a next-step request
                            // cannot accidentally keep projecting the just-finished step.
                            solveStepSummary = null,
                            solvingReadyFactBundlesV1 = emptyList(),
                            solveStepJson = null,

                            coachPlan = null,
                            coachPlanGridHash12 = null,
                            coachPlanStepId = null,
                            coachPlanSha12 = null,
                            coachPlanJson = null,

                            // Latch “compute then speak” so SolveStepUpdated autotriggers Tick2.
                            pendingSolveStepAutocoach = PendingSolveStepAutocoach(
                                reason = reason,
                                gridHash12 = h12,
                                origin = reason,
                                turnSeq = sAfterPlan.turnSeq,
                                requestKind =
                                    if (forceNextStep) SolveStepRequestKindV1.NEXT_STEP_CONTINUATION
                                    else SolveStepRequestKindV1.PREFETCH_CURRENT_GRID,
                                requestToken =
                                    if (forceNextStep) "next_step:$h12:${sAfterPlan.turnSeq}"
                                    else null,
                                allowReplaceLockedStep = forceNextStep
                            ),

                            // While computing, don't keep POST_COMMIT pending around.
                            pending = null
                        )

                        return Next(
                            sLatched,
                            listOf(
                                Eff.ComputeSolveStep(
                                    grid81 = g81,
                                    gridHash12 = h12,
                                    reason = reason,
                                    force = forceFlag
                                )
                            )
                        )
                    }
                }




                // ------------------------------------------------------------
                // Batch A no-silence guard:
                // after an app-owned post-resolution continuation, we must launch
                // either:
                //   1) a fresh next-step compute, or
                //   2) immediate Tick2 reply generation.
                //
                // If we reach this point still sitting on a true next-step-ready
                // boundary with no compute launch and no ops, recover by forcing
                // the next-step compute instead of merely emitting telemetry.
                // ------------------------------------------------------------
                runCatching {
                    val stillNextStepReadyBoundary =
                        isReadyForNextStepBoundaryV1(sAfterPlan) && !repairDetourNow

                    if (stillNextStepReadyBoundary && plan.newAdvanceToNextStep != true) {
                        ConversationTelemetry.emitKv(
                            "POST_COMMIT_CONTINUITY_RECOVERY_FORCE_NEXTSTEP",
                            "session_id" to sAfterPlan.sessionId,
                            "turn_id" to e.ctx.turnId,
                            "pending" to (sAfterPlan.pending?.javaClass?.simpleName ?: "null"),
                            "queue_head" to (currentQueuedSolvingHead(sAfterPlan)?.javaClass?.simpleName ?: "null"),
                            "top_intent" to (envBound.intents.firstOrNull()?.type?.name ?: "null"),
                            "phase" to sAfterPlan.phase.name
                        )

                        val llm0 = sAfterPlan.grid?.llm ?: return@runCatching
                        val g81Recover = grid81FromLLM(llm0)
                        val h12Recover = sha12(g81Recover).take(12)

                        val alreadyComputingRecover =
                            (sAfterPlan.solveStepStatus == SolveStepStatus.COMPUTING) &&
                                    (sAfterPlan.pendingSolveStepAutocoach?.gridHash12?.take(12) == h12Recover)

                        if (!alreadyComputingRecover) {
                            val sRecovered = sAfterPlan.copy(
                                solveStepStatus = SolveStepStatus.COMPUTING,
                                solveStepSummary = null,
                                solvingReadyFactBundlesV1 = emptyList(),
                                solveStepJson = null,
                                coachPlan = null,
                                coachPlanGridHash12 = null,
                                coachPlanStepId = null,
                                coachPlanSha12 = null,
                                coachPlanJson = null,
                                pendingSolveStepAutocoach = PendingSolveStepAutocoach(
                                    reason = "solve_next_step_requested",
                                    gridHash12 = h12Recover,
                                    origin = "post_commit_continuity_recovery",
                                    turnSeq = sAfterPlan.turnSeq,
                                    requestKind = SolveStepRequestKindV1.NEXT_STEP_CONTINUATION,
                                    requestToken = "next_step:$h12Recover:${sAfterPlan.turnSeq}",
                                    allowReplaceLockedStep = true
                                ),
                                pending = null
                            )

                            return Next(
                                sRecovered,
                                listOf(
                                    Eff.ComputeSolveStep(
                                        grid81 = g81Recover,
                                        gridHash12 = h12Recover,
                                        reason = "solve_next_step_requested",
                                        force = true
                                    )
                                )
                            )
                        }
                    }
                }

                val headerAfter = buildStateHeader(sAfterPlan)
                val (s2, ctx2) = nextPolicyCtx(
                    s = sAfterPlan,
                    tickId = 2,
                    reason = "v1_no_ops",
                    stateHeader = headerAfter,
                    turnId = e.ctx.turnId
                )

                emitPolicyCallTrace(
                    traceState = sAfterPlan,
                    userText = e.userText,
                    stateHeader = headerAfter,
                    reason = "v1_no_ops",
                    turnId = e.ctx.turnId,
                    ctx = ctx2,
                    extraData = mapOf(
                        "decision_kind" to outcome.decisionKind.name,
                        "fact_bundle_types" to plan.factBundles.joinToString(",") { it.type.name }
                    )
                )
                emitModelCallBegin(ctx2)

                val solvingPacket = s2.solvingReadyFactBundlesV1
                val facts0 = if (solvingPacket.isNotEmpty()) solvingPacket + plan.factBundles else plan.factBundles


                // ✅ Phase 0/1: enforce turn contracts + attach single TURN_CONTRACT_SNAPSHOT_V1
                val enforced = enforceTurnContractAndAttachSnapshot(
                    stage = "PRE_TICK2",
                    s = s2,
                    factsIn = facts0,
                    rawTextUsedByMaps = false
                )
                val sEnforced = enforced.s
                val factsFinal = enforced.facts

                val sigToStore = storySignatureToStoreForTurnV1(sEnforced)

                val sFinal = if (!sigToStore.isNullOrBlank()) {
                    sEnforced.copy(lastStorySignatureV1 = sigToStore)
                } else sEnforced


                runCatching {
                    emitDetourIsolationInvariantV1(
                        s = sFinal,
                        stage = "PRE_TICK2_OR_DETOUR_QUERY"
                    )
                }

                val detourSolverSpec = buildDetourSolverQuerySpecV1(sFinal)





                if (detourSolverSpec != null) {
                    val sQuerying = sFinal.copy(
                        detourState = sFinal.detourState?.copy(
                            pendingSolverQueryId = detourSolverSpec.queryId,
                            pendingSolverQueryOp = detourSolverSpec.op
                        )
                    )

                    runCatching {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "DETOUR_SOLVER_QUERY_LAUNCHED_V1",
                            data = mapOf(
                                "turn_id" to e.ctx.turnId,
                                "query_id" to detourSolverSpec.queryId,
                                "op" to detourSolverSpec.op,
                                "reason" to detourSolverSpec.reason,
                                "question_class" to (sQuerying.detourState?.questionClass?.name ?: "null"),
                                "requested_cell" to (sQuerying.detourState?.requestedCell ?: "null"),
                                "requested_digit" to (sQuerying.detourState?.requestedDigit?.toString() ?: "null"),
                                "requested_technique" to (sQuerying.detourState?.requestedTechniqueIdOrLabel ?: "null"),
                                "payload_len" to detourSolverSpec.payloadJson.length
                            )
                        )
                    }

                    return Next(
                        sQuerying,
                        listOf(
                            Eff.RunDetourSolverQuery(
                                queryId = detourSolverSpec.queryId,
                                op = detourSolverSpec.op,
                                payloadJson = detourSolverSpec.payloadJson,
                                reason = detourSolverSpec.reason
                            )
                        )
                    )
                }

                val replyExec = buildReplyRequestV1(
                    sBefore = sBefore,
                    sAfter = sFinal,
                    turnId = e.ctx.turnId,
                    userText = e.userText,
                    decision = outcome,
                    factBundles = factsFinal,
                    envelope = envBound
                )

                return Next(
                    sFinal,
                    listOf(
                        Eff.CallReplyGenerateV1(
                            ctx = ctx2,
                            replyRequest = replyExec.replyRequest,
                            planResult = replyExec.planResult,
                            reason = "v1_no_ops",
                            turnId = e.ctx.turnId
                        )
                    )
                )
            }



            is Evt.GridCleared -> {
                val s1 = s.copy(
                    mode = SudoMode.FREE_TALK,
                    grid = null,
                    pending = null,
                    repairAttempt = 0,
                    turnSeq = s.turnSeq + 1,
                    phase = GridPhase.CONFIRMING
                )

                val header = buildStateHeader(s1)

                val (s2, eff) = callPolicyWithTrace(
                    traceState = s1,
                    userText = "[EVENT] grid_cleared",
                    stateHeader = header,
                    mode = s1.mode,
                    reason = "grid_cleared",
                    turnId = s1.turnSeq
                )

                Next(s2, listOf(eff))
            }

            is Evt.GridSnapshotUpdated -> {
                // ✅ If tools just mutated the canonical grid, the UI thread will emit
                // GridSnapshotUpdated. This is our single, race-free point to emit
                // POST_APPLY truth snapshot (grid has been recomputed).
                val pendingSnap = s.pendingGridFactsSnapshot
                if (pendingSnap != null) {
                    runCatching {
                        val llm = e.grid.llm
                        if (llm != null) {
                            val payload = buildGridFactsSnapshotV1(llm, stage = pendingSnap.stage)
                            ConversationTelemetry.emitGridFactsSnapshot(
                                sessionId = s.sessionId,
                                turnId = pendingSnap.ctx.turnId,
                                tickId = pendingSnap.ctx.tickId,
                                policyReqSeq = pendingSnap.ctx.policyReqSeq,
                                modelCallId = pendingSnap.ctx.modelCallId,
                                correlationId = pendingSnap.ctx.correlationId,
                                toolplanId = pendingSnap.ctx.toolplanId,
                                stage = pendingSnap.stage,
                                payload = payload
                            )


                            // ✅ Phase 0: Turn Contract Snapshot — POST_APPLY
                            emitTurnContractSnapshot(
                                stage = pendingSnap.stage, // expected "POST_APPLY"
                                note = "after_tools_applied_grid_recomputed",
                                s = s.copy(grid = e.grid), // ✅ reflect post-recomputed canonical grid in snapshot state
                                ctx = pendingSnap.ctx,
                                facts = s.pendingReplyV1?.factBundles,
                                tick2CallsForTurn = null
                            )

                        } else {
                            ConversationTelemetry.emitKv(
                                "GRID_FACTS_SNAPSHOT_SKIPPED",
                                "session_id" to s.sessionId,
                                "turn_id" to pendingSnap.ctx.turnId,
                                "tick_id" to pendingSnap.ctx.tickId,
                                "stage" to pendingSnap.stage,
                                "reason" to "grid.llm_null"
                            )
                        }
                    }
                }

                val s1Base = s.copy(
                    grid = e.grid,
                    pendingGridFactsSnapshot = null
                )

                // ✅ Refresh App agenda after each apply (2C)
                val llm1 = e.grid.llm as? LLMGridState
                val refreshedAgenda = buildAppAgendaFromGrid(
                    llm = llm1,
                    phase = s1Base.phase,
                    createdTurnSeq = s1Base.turnSeq,
                    userConfirmedPerfectMatch = s1Base.userConfirmedPerfectMatch,
                    retakeDismissed = s1Base.retakeDismissed,
                    startSolvingCtaActive = (s1Base.pending is Pending.ConfirmStartSolving)
                )
                val s1 = s1Base.copy(appAgendaQueue = refreshedAgenda)

                // ✅ PATCH 4: in SOLVING, recompute step on grid change with same latch (compute-then-speak)
                val llm = e.grid.llm
                val deferSolveProgressionForUserDetour =
                    shouldDeferSolveProgressionForUserDetourV1(s1)

                if (llm != null &&
                    s1.phase == GridPhase.SOLVING &&
                    !deferSolveProgressionForUserDetour
                ) {
                    val g81 = grid81FromLLM(llm)
                    val h12 = sha12(g81)

                    val shouldCompute = (s1.solveStepGridHash12 != h12)

                    // ✅ Phase 8: Do NOT compute the next step while we're still resolving the current step.
                    // This prevents "Step 2 spotlight" from entering the same user turn as "Step 1 resolution".
                    val isResolving = (s1.narrativeStory?.stage == StoryStage.RESOLUTION)

                    if (shouldCompute && !isResolving) {
                        val sLatched = s1.copy(
                            solveStepStatus = SolveStepStatus.COMPUTING,

                            // ✅ PATCH 6.3.D: clear cached packet when requesting a new step
                            solvingReadyFactBundlesV1 = emptyList(),

                            pendingSolveStepAutocoach = PendingSolveStepAutocoach(
                                reason = "grid_snapshot_updated_in_solving",
                                gridHash12 = h12.take(12),
                                origin = "grid_snapshot_updated_in_solving",
                                turnSeq = s1.turnSeq,
                                requestKind = SolveStepRequestKindV1.GRID_REFRESH,
                                requestToken = null,
                                allowReplaceLockedStep = false
                            )
                        )
                        return Next(
                            sLatched,
                            listOf(
                                Eff.ComputeSolveStep(
                                    grid81 = g81,
                                    gridHash12 = h12,
                                    reason = "grid_snapshot_updated_in_solving",
                                    force = false
                                )
                            )
                        )
                    }
                }

                Next(s1, emptyList())
            }

            // =========================================================================
            // PATCH 3A: SolveStepUpdated — mark READY + autotrigger policy (compute then speak)
            // =========================================================================
            is Evt.SolveStepUpdated -> {
                // Step binding is authoritative
                val llm = s.grid?.llm
                val curHash12 = if (llm != null) sha12(grid81FromLLM(llm)).take(12) else null
                val inHash12 = e.gridHash12.take(12)

                // Drop stale step updates (Phase 1 “no time travel”)
                if (curHash12 != null && inHash12 != curHash12.take(12)) {
                    runCatching {
                        ConversationTelemetry.emitKv(
                            "SOLVE_STEP_DROPPED_STALE",
                            "session_id" to s.sessionId,
                            "grid_hash12_in" to inHash12,
                            "grid_hash12_cur" to curHash12.take(12)
                        )
                    }
                    return Next(s, emptyList())
                }


                // Wave 1 hard rule:
                // while the current step is locked at commit / post-commit,
                // incoming solve-step updates must not replace the active story.
                //
                // Batch C structured exception:
                // if we ourselves explicitly requested the NEXT STEP and the
                // current latch marks that request as allowed to replace the
                // locked current step, then the returning SolveStepUpdated is
                // the expected continuation and must be allowed through.
                val explicitNextStepAutocoach =
                    isExplicitNextStepAutocoachV1(s, inHash12)

                if (isSolveStepLockedForResolutionV1(s) && !explicitNextStepAutocoach) {
                    runCatching {
                        ConversationTelemetry.emitKv(
                            "SOLVE_STEP_DROPPED_LOCKED_CURRENT_STEP",
                            "session_id" to s.sessionId,
                            "grid_hash12_in" to inHash12,
                            "active_step_id" to (s.solveStepId ?: "null"),
                            "pending" to (s.pending?.javaClass?.simpleName ?: "null"),
                            "queue_head" to (currentQueuedSolvingHead(s)?.javaClass?.simpleName ?: "null"),
                            "story_stage" to (s.narrativeStory?.stage?.name ?: "null"),
                            "autocoach_kind" to (s.pendingSolveStepAutocoach?.requestKind?.name ?: "null"),
                            "autocoach_allow_replace_locked" to (s.pendingSolveStepAutocoach?.allowReplaceLockedStep?.toString() ?: "null"),
                            "autocoach_token" to (s.pendingSolveStepAutocoach?.requestToken ?: "null")
                        )
                    }
                    return Next(s, emptyList())
                }





                // Determine step seq.
                //
                // Wave 2:
                // A user-accepted "next step" may recompute on the SAME grid hash
                // (because the prior step is already committed on-board and we now
                // want the next solving step for that same post-commit grid).
                //
                // In that case, keeping the old sequence would falsely preserve the
                // old step identity and can block fresh-story initialization.

                val nextSeq =
                    if (s.solveStepGridHash12?.take(12) != inHash12) {
                        s.solveStepSeq + 1L
                    } else if (explicitNextStepAutocoach) {
                        s.solveStepSeq + 1L
                    } else {
                        s.solveStepSeq
                    }

                // Canonical step id (stable within a step, fresh across explicit next-step recomputes)
                val stepId = "$inHash12:$nextSeq"



                // Build deterministic coach plan (typed, authoritative) — V2 only
                val translated = runCatching {
                    com.contextionary.sudoku.conductor.solving.CoachPlanTranslator.translate(
                        solveStepJson = e.stepJson,
                        gridHash12Fallback = inHash12
                    )
                }.getOrNull()

                val plan = translated?.plan

                // atomsCount will be computed after we unwrap stepObj below (single source of truth).



                // ------------------------------------------------------------
                // Phase 4: Skip-ahead loop (silent auto-apply)
                // If solveSkipRemaining > 0, apply reveal immediately and DO NOT speak.
                // GridSnapshotUpdated will trigger the next compute.
                // ------------------------------------------------------------
                val skipRem = s.solveSkipRemaining
                if (skipRem > 0) {
                    val reveal = plan?.reveal
                    if (reveal != null &&
                        reveal.placementCellIndex in 0..80 &&
                        reveal.placementDigit in 1..9
                    ) {
                        val s2 = s.copy(
                            solveStepJson = e.stepJson,
                            solveStepGridHash12 = inHash12,
                            solveStepId = stepId,
                            solveStepSeq = nextSeq,
                            solveGuidanceMode = SolveGuidanceModeV1.UNSET,
                            coachPlan = plan,
                            coachPlanGridHash12 = inHash12,
                            coachPlanStepId = stepId,
                            solveSkipRemaining = (skipRem - 1).coerceAtLeast(0),
                            solveSkipTotal = s.solveSkipTotal.coerceAtLeast(skipRem)
                        )

                        return Next(
                            s2,
                            listOf(
                                Eff.ApplyCellEdit(
                                    toolCallId = "internal:skip_apply",
                                    cellIndex = reveal.placementCellIndex,
                                    digit = reveal.placementDigit,
                                    source = "skip_apply"
                                )
                            )
                        )
                    } else {
                        // If reveal is unavailable, stop skipping and fall back to normal behavior.
                        val s2 = s.copy(
                            solveSkipRemaining = 0,
                            solveSkipTotal = 0
                        )
                        // continue to normal packet/pending build using s2 by just reassigning s via local var style
                        // (minimal change: overwrite s reference not possible; instead rely on normal flow but cleared state next turn)
                    }
                }

// If V2 parse failed, keep state stable but mark step as unusable.
                if (plan == null) {
                    // Optional telemetry: translated?.warnings
                }



                // ------------------------------
// PATCH 6.3.B: Build + cache packet bundles exactly once when step becomes READY
// ------------------------------
                val envObj = safeJsonObjectFromString(e.stepJson, tag = "engine_step_env")

// Unwrap { ok, status, step:{...} } if present; otherwise assume already a step object.
                val stepObj = runCatching {
                    envObj.optJSONObject("step") ?: envObj
                }.getOrNull() ?: envObj



                // --- Phase 1: Narrative Atom ladder is the authoritative "hint" ladder ---
                val grid81Now = runCatching { s.grid?.llm?.let { grid81FromLLM(it) } }.getOrNull()

                val narrativeAtomsV1 = runCatching {
                    com.contextionary.sudoku.conductor.solving.NarrativeAtomGeneratorV1.buildNarrativeAtomsV1(
                        stepObj = stepObj,
                        grid81 = grid81Now
                    )
                }.getOrElse {
                    org.json.JSONObject().apply {
                        put("schema_version", "narrative_atoms_v1")
                        put("archetype", "UNKNOWN")
                        put("atoms", org.json.JSONArray())
                        put("version_note", "emit_failed:${it.javaClass.simpleName}")
                    }
                }

// Exclude the final COMMIT atom from "hint ladder" so MORE_HINT never spills the digit.
                // Atom-native semantics (Phase 8):
// - atomsCount includes COMMIT (last atom)
// - proof beats are atoms 1..(atomsCount-2)
// - commit is atom (atomsCount-1)
                val atomsArr = narrativeAtomsV1.optJSONArray("atoms") ?: org.json.JSONArray()
                val atomsCount = atomsArr.length().coerceAtLeast(1)

                val commitAtomIndex = (atomsCount - 1).coerceAtLeast(0)
                val lastProofAtomIndex = (atomsCount - 2).coerceAtLeast(0)
                val proofBeatsCount = (atomsCount - 1).coerceAtLeast(1) // exclude commit; used only to feed legacy stepIntro signature

                // ✅ Phase 1/8: establish story context (SETUP always Atom 0)
                val storyCtx = NarrativeStoryContext(
                    stepId = stepId,
                    gridHash12 = inHash12.take(12),
                    stage = StoryStage.SETUP,
                    atomsCount = atomsCount,
                    focusAtomIndex = defaultFocusAtomIndexForStageV1(
                        stage = StoryStage.SETUP,
                        atomsCount = atomsCount
                    ),
                    discussedAtomIndices = narrationAtomIndicesForStageV1(
                        stage = StoryStage.SETUP,
                        atomsCount = atomsCount
                    ),
                    readyForCommit = false,
                    createdTurnSeq = s.turnSeq
                )

                    // ✅ North Star CTA doctrine:
                    // solving entry must be stage-native, not atom-menu-native.
                    // The opening turn is SETUP, so the only normal CTA family here is SHOW_PROOF.
                    // No try-vs-guide branching is allowed in the intro rail.
                    val cta = com.contextionary.sudoku.conductor.solving.SolvingPromptParts
                    .forStoryStage(StoryStage.SETUP)

                // ✅ Install stage-native setup pending immediately.
                // isLastHint now effectively means: "there are no proof beats to guide"
                // (i.e., atomsCount < 2 => lastProofAtomIndex == 0)
                val pendingSolve = Pending.SolveIntroAction.SetupAction(
                    stepId = stepId,
                    atomIndex = 0,
                    atomsCount = atomsCount,
                    isLastHint = (atomsCount < 2),
                    prompt = cta.prompt,
                    gridHash12 = inHash12.take(12),
                    options = cta.options
                )






// Best-effort technique name (prefer translated plan title, else JSON fallback from nested step)
                val techniqueName: String =
                    (plan?.title?.takeIf { it.isNotBlank() })
                        ?: runCatching {
                            stepObj.optJSONObject("technique")
                                ?.optString("technique_name")
                                ?.takeIf { !it.isNullOrBlank() }
                        }.getOrNull()
                        ?: runCatching {
                            stepObj.optJSONObject("technique")
                                ?.optString("technique_id")
                                ?.takeIf { !it.isNullOrBlank() }
                        }.getOrNull()
                        ?: stepObj.optString("technique", "").takeIf { it.isNotBlank() }
                        ?: stepObj.optString("rule", "").takeIf { it.isNotBlank() }
                        ?: "a classic technique"

// Best-effort target from nested step.target.cell + step.target.digit (keep nullable if missing)
                val targetObj = runCatching { stepObj.optJSONObject("target") }.getOrNull()
                val cellObj = runCatching { targetObj?.optJSONObject("cell") }.getOrNull()

                val targetCellR1C1: String? =
                    runCatching {
                        val r = cellObj?.optInt("r", -1) ?: -1
                        val c = cellObj?.optInt("c", -1) ?: -1
                        if (r in 1..9 && c in 1..9) "r${r}c${c}" else null
                    }.getOrNull()
                        ?: stepObj.optString("target_cell", "").takeIf { it.isNotBlank() }
                        ?: stepObj.optString("cell", "").takeIf { it.isNotBlank() }

                val targetDigit: Int? =
                    runCatching {
                        val d = targetObj?.optInt("digit", -1) ?: -1
                        if (d in 1..9) d else null
                    }.getOrNull()
                        ?: stepObj.optInt("target_digit", -1).takeIf { it in 1..9 }
                        ?: stepObj.optInt("digit", -1).takeIf { it in 1..9 }

// NEXT_MOVE_RECOMMENDATION payload: make it deterministic from the CTA you already built
                val nextMovePayload = org.json.JSONObject().apply {
                    put("step_id", stepId)
                    put("technique", techniqueName)
                    // Phase 1/2: never inject deterministic “assistant prompt” text into fact bundles.
                    put("prompt", JSONObject.NULL)
                    put("options", org.json.JSONArray().apply {
                        pendingSolve.options.forEach { opt -> put(opt) }
                    })
                    put("grid_hash12", inHash12.take(12))
                }

// TECHNIQUE_FINDINGS payload: best-effort from plan/step JSON; never empty
                val techniqueFindingsPayload = org.json.JSONObject().apply {
                    put("step_id", stepId)
                    put("technique", techniqueName)
                    put("summary", plan?.title ?: org.json.JSONObject.NULL)
                    put("engine_fields_present", org.json.JSONArray(stepObj.keys().asSequence().toList()))
                }

// CANDIDATES_SNAPSHOT payload: “proof” placeholder unless you already have a richer builder.
// (This satisfies the contract without forcing a new heavy implementation right now.)
                val candidatesSnapshotPayload = org.json.JSONObject().apply {
                    put("step_id", stepId)
                    put("grid_hash12", inHash12.take(12))
                    put("note", "Snapshot placeholder; replace with full candidates export if/when available.")
                }

// OVERLAY_FRAMES payload: if you already can build frame JSON deterministically, include it.
                // Build an overlay base-state for deterministic frame generation
                val sOverlayBase = s.copy(
                    solveStepJson = e.stepJson,
                    solveStepGridHash12 = inHash12.take(12),
                    coachPlan = plan,
                    coachPlanGridHash12 = inHash12.take(12),
                    coachPlanStepId = stepId,
                    solveAtomIndex = 0,
                    solveAtomsCount = atomsCount
                )

                val overlayFramesPayload = org.json.JSONObject().apply {
                    put("step_id", stepId)
                    put("style", s.solveOverlayStyle.ifBlank { "full" })
                    put("frames", org.json.JSONArray().apply {
                        // ✅ Phase 1: include ALL narrative atom frames so UI can switch instantly.
                        for (i in 0 until atomsCount) {
                            val frameId = currentSolveOverlayFrameId(sOverlayBase, i)
                            val frameJson = buildSolveOverlayFrameJsonV1(
                                s = sOverlayBase,
                                frameId = frameId,
                                style = s.solveOverlayStyle.ifBlank { "full" },
                                reason = "solve_step_ready_packet"
                            )
                            put(org.json.JSONObject(frameJson))
                        }

                        // Also include reveal frame if available (optional)
                        if (plan?.reveal != null) {
                            val frameJson = buildSolveOverlayFrameJsonV1(
                                s = sOverlayBase,
                                frameId = "reveal",
                                style = s.solveOverlayStyle.ifBlank { "full" },
                                reason = "solve_step_ready_packet"
                            )
                            put(org.json.JSONObject(frameJson))
                        }
                    })
                }

// TEACHING_CARD payload: build a short deterministic teaching card from plan hint 0
                val teachingCardPayload = org.json.JSONObject().apply {
                    put("step_id", stepId)
                    put("technique", techniqueName)
                    put("hint_index", 0)
                    put("atoms_count", atomsCount)
                    // Phase 1/2: no deterministic fallback scripts.
// Teaching text may be empty; the Driver uses structured evidence.
                    put(
                        "text",
                        plan?.hints?.getOrNull(0)?.text?.takeIf { it.isNotBlank() }
                            ?: stepObj.optString("explanation", "").takeIf { it.isNotBlank() }
                            ?: ""
                    )
                }


                // ------------------------------------------------------------
// Phase 2: Build frozen SOLVING_STEP_PACKET_V1 + CTA_PACKET_V1 + TEACHING_CARD_V1
// ------------------------------------------------------------

                val filledCountNow = runCatching {
                    val g = grid81Now ?: ""
                    g.count { it in "123456789" }
                }.getOrElse { 0 }
                val remainingCountNow = (81 - filledCountNow).coerceAtLeast(0)
                val journeyStepNumberNow = (filledCountNow + 1).coerceAtMost(81)

// Technique id (best effort)
                val techniqueId: String =
                    runCatching {
                        stepObj.optJSONObject("technique")?.optString("technique_id")?.takeIf { it.isNotBlank() }
                    }.getOrNull()
                        ?: runCatching {
                            stepObj.optJSONObject("technique")?.optString("id")?.takeIf { it.isNotBlank() }
                        }.getOrNull()
                        ?: techniqueName.lowercase().replace(' ', '-')

// Evidence houses (from normalize_step.py -> proof.house_summaries)
                val houseSummariesJson = runCatching {
                    stepObj.optJSONObject("proof")?.optJSONArray("house_summaries") ?: org.json.JSONArray()
                }.getOrElse { org.json.JSONArray() }

                val evidencePayloadV1 = org.json.JSONObject().apply {
                    put("primary_proof_kind", "house_missing_one")
                    put("houses", houseSummariesJson)

                    // Phase 3: evidence-first hint ladder (from Python proof.hint_ladder_v1)
                    put(
                        "hint_ladder_v1",
                        runCatching {
                            stepObj.optJSONObject("proof")?.optJSONArray("hint_ladder_v1") ?: org.json.JSONArray()
                        }.getOrElse { org.json.JSONArray() }
                    )

                    // ✅ Phase 0: deterministic narrative atoms (Singles only; expands in later phases)
                    put(
                        "narrative_atoms_v1",
                        runCatching {
                            NarrativeAtomGeneratorV1.buildNarrativeAtomsV1(
                                stepObj = stepObj,
                                grid81 = grid81Now
                            )
                        }.getOrElse {
                            org.json.JSONObject().apply {
                                put("schema_version", "narrative_atoms_v1")
                                put("archetype", "UNKNOWN")
                                put("atoms", org.json.JSONArray())
                                put("version_note", "emit_failed:${it.javaClass.simpleName}")
                            }
                        }
                    )

                    // ✅ Phase 1 additive: emit the new proof-normalized narrative truth beside atoms.
                    put(
                        "narrative_truth_v2",
                        runCatching {
                            NarrativeAtomGeneratorV1.buildNarrativeTruthV2(
                                stepObj = stepObj,
                                grid81 = grid81Now
                            )
                        }.getOrElse {
                            org.json.JSONObject().apply {
                                put("schema_version", "narrative_truth_v2")
                                put("source_of_truth", "packet.evidence.narrative_truth_v2")
                                put("build_status", "emit_failed:${it.javaClass.simpleName}")
                            }
                        }
                    )

                    // Candidate view remains optional; narrative atoms carry proof beats.
                    put("candidate_view", org.json.JSONObject().apply {
                        put("is_known", false)
                        put("candidates_by_cell", org.json.JSONArray())
                    })

                    put("why_not", org.json.JSONArray())
                }

                // ------------------------------------------------------------
// Phase 3: Validate narrative atoms proof (enforce "Maps authors proof")
// ------------------------------------------------------------
                val narrativeAtomsPacketV1: org.json.JSONObject? = evidencePayloadV1.optJSONObject("narrative_atoms_v1")
                val proofVerdictV1: org.json.JSONObject =
                    runCatching {
                        com.contextionary.sudoku.conductor.solving.ProofValidatorV1.validateNarrativeAtomsV1(narrativeAtomsPacketV1)
                    }.getOrElse {
                        org.json.JSONObject().apply {
                            put("schema_version", "proof_verdict_v1")
                            put("ok", false)
                            put("atoms_count", 0)
                            put("problems", org.json.JSONArray().put(
                                org.json.JSONObject().apply {
                                    put("code", "validator_exception")
                                    put("atom_index", org.json.JSONObject.NULL)
                                    put("note", it.javaClass.simpleName + ":" + (it.message ?: ""))
                                }
                            ))
                        }
                    }

                evidencePayloadV1.put("proof_verdict_v1", proofVerdictV1)
                val proofOkV1: Boolean = proofVerdictV1.optBoolean("ok", false)

                val overlayVisibleNow = true // keep overlay default ON (we may disable below on failure)




                val overlaysPayloadV1 = org.json.JSONObject().apply {
                    val applied = org.json.JSONArray()
                    if (overlayVisibleNow) {

                        // ✅ Phase 5: Use the solver-authored frame id for atom 0 when available.
                        val atom0FrameId: String =
                            runCatching {
                                atomsArr
                                    .optJSONObject(0)
                                    ?.optJSONObject("overlay")
                                    ?.optString("frame_id")
                                    ?.trim()
                                    ?.takeIf { it.isNotBlank() }
                            }.getOrNull()
                                ?: currentSolveOverlayFrameId(sOverlayBase, 0)

                        if (atom0FrameId.isNotBlank()) applied.put(atom0FrameId)
                    }
                    put("applied_frame_ids", applied)
                    put("legend", org.json.JSONArray())
                }

                val allowRevealNowV1 = (plan?.reveal != null) && (targetDigit != null)

                // Phase 2: CTA packet is derived solely from Pending via pendingToCtaPacketV1(...).

                // ✅ Rich technique info from SolveStepV2 (Python) — this is what Tick2 should see.
                val techniqueInfoObj: org.json.JSONObject =
                    (stepObj.optJSONObject("technique") ?: org.json.JSONObject()).let { t ->
                        // normalize keys so downstream code can rely on them
                        if (!t.has("technique_id") && t.has("id")) t.put("technique_id", t.optString("id"))
                        if (!t.has("technique_name") && t.has("name")) t.put("technique_name", t.optString("name"))
                        t
                    }

// Optional: derive some “minimal” display fields from the rich object
                val techniqueFamilyForPacket: String =
                    techniqueInfoObj.optString("family", "unknown").ifBlank { "unknown" }

                val techniqueDifficultyForPacket: Int =
                    runCatching { techniqueInfoObj.optInt("difficulty_weight", 1) }.getOrElse { 1 }
                        .let { w -> if (w > 0) w else 1 }

                val solvingStepPacketPayloadV1 = org.json.JSONObject().apply {
                    put("schema_version", "solving_step_packet_v1")
                    put("puzzle", org.json.JSONObject().apply {
                        put("puzzle_id", s.sessionId ?: "")
                        put("filled_count", filledCountNow)
                        put("remaining_count", remainingCountNow)
                        put("journey_step_number", journeyStepNumberNow)
                    })
                    put("step", org.json.JSONObject().apply {
                        put("step_id", stepId)

                        // legacy minimal technique (keep)
                        put("technique", org.json.JSONObject().apply {
                            put("id", techniqueId)
                            put("name", techniqueName)
                            put("family", techniqueFamilyForPacket)
                            put("difficulty", techniqueDifficultyForPacket)
                        })

                        // ✅ NEW: full rich technique object for Tick2 + audits
                        put("technique_info", techniqueInfoObj)

                        put("target", org.json.JSONObject().apply {
                            val r = runCatching { cellObj?.optInt("r", -1) ?: -1 }.getOrElse { -1 }
                            val c = runCatching { cellObj?.optInt("c", -1) ?: -1 }.getOrElse { -1 }
                            put("r", r)
                            put("c", c)
                            put("cell_index_1to81", runCatching {
                                if (r in 1..9 && c in 1..9) ((r - 1) * 9 + c) else JSONObject.NULL
                            }.getOrElse { JSONObject.NULL })
                            put("box", runCatching {
                                if (r in 1..9 && c in 1..9) (((r - 1) / 3) * 3 + ((c - 1) / 3) + 1) else JSONObject.NULL
                            }.getOrElse { JSONObject.NULL })
                        })
                        put("spoiler", org.json.JSONObject().apply {
                            put("digit_hidden", true)
                            put("reveal_allowed", allowRevealNowV1)
                            put("reveal_kind", if (allowRevealNowV1) "digit_plus_reason" else "digit_only")
                        })
                        put("result", org.json.JSONObject().apply {
                            put("digit", targetDigit ?: JSONObject.NULL)
                            put("is_available_if_revealed", allowRevealNowV1)
                        })
                    })
                    put("evidence", evidencePayloadV1)
                    put("overlays", overlaysPayloadV1)
// Phase 2: CTA contract is ONLY FactBundleV1.Type.CTA_PACKET_V1; do not embed CTA here.
                }

                val teachingCardPayloadV1 = org.json.JSONObject().apply {
                    val richTechnique = org.json.JSONObject(techniqueInfoObj.toString())

                    val techniqueNameForCard =
                        richTechnique.optString("technique_name")
                            .ifBlank { richTechnique.optString("real_name") }
                            .ifBlank { richTechnique.optString("app_name") }
                            .ifBlank { richTechnique.optString("technique_id") }

                    val familyDescription =
                        richTechnique.optString("family_description").takeIf { it.isNotBlank() }

                    val difficultyLevel =
                        richTechnique.optString("difficulty_level").takeIf { it.isNotBlank() }

                    val definitionObj = richTechnique.optJSONObject("definition") ?: org.json.JSONObject()
                    val commentsObj = richTechnique.optJSONObject("comments") ?: org.json.JSONObject()

                    val oneLiner =
                        definitionObj.optString("what").takeIf { it.isNotBlank() }
                            ?: "Use the supplied technique truth to explain what kind of move this is."

                    put("schema_version", "teaching_card_v1")

                    put("title", techniqueNameForCard.ifBlank { org.json.JSONObject.NULL })
                    put("short_explanation", org.json.JSONArray().apply {
                        if (definitionObj.optString("what").isNotBlank()) put(definitionObj.optString("what"))
                        if (definitionObj.optString("why").isNotBlank()) put(definitionObj.optString("why"))
                    })

                    put("technique", org.json.JSONObject().apply {
                        put("technique_id", richTechnique.opt("technique_id") ?: org.json.JSONObject.NULL)
                        put("technique_name", richTechnique.opt("technique_name") ?: org.json.JSONObject.NULL)
                        put("real_name", richTechnique.opt("real_name") ?: richTechnique.opt("realName") ?: org.json.JSONObject.NULL)
                        put("family", richTechnique.opt("family") ?: org.json.JSONObject.NULL)
                        put("archetype", readSetupArchetypeWireV1(s) ?: org.json.JSONObject.NULL)
                        put("is_base", richTechnique.opt("is_base") ?: richTechnique.opt("isBase") ?: org.json.JSONObject.NULL)
                        put("difficulty_level", richTechnique.opt("difficulty_level") ?: richTechnique.opt("difficultyLevel") ?: org.json.JSONObject.NULL)
                        put("family_description", familyDescription ?: org.json.JSONObject.NULL)
                    })

                    put("definition", org.json.JSONObject().apply {
                        put("one_liner", oneLiner)
                        put("what", definitionObj.opt("what") ?: org.json.JSONObject.NULL)
                        put("why", definitionObj.opt("why") ?: org.json.JSONObject.NULL)
                        put("when", definitionObj.opt("when") ?: org.json.JSONObject.NULL)
                        put("how", definitionObj.opt("how") ?: org.json.JSONObject.NULL)
                    })

                    put("synonyms", commentsObj.optJSONArray("synonyms") ?: org.json.JSONArray())
                    put("interesting_facts", commentsObj.optJSONArray("interesting_facts") ?: org.json.JSONArray())
                    put("notes", commentsObj.opt("notes") ?: org.json.JSONObject.NULL)

                    put("tip", org.json.JSONObject().apply {
                        put(
                            "summary",
                            definitionObj.optString("how").takeIf { it.isNotBlank() } ?: org.json.JSONObject.NULL
                        )
                    })

                    put("family_description", familyDescription ?: org.json.JSONObject.NULL)
                    put("difficulty_level", difficultyLevel ?: org.json.JSONObject.NULL)

                    put("how_to_spot", org.json.JSONArray())
                    put("common_confusions", org.json.JSONArray())
                    put("proof_shapes", org.json.JSONArray())
                    put("style_hints", org.json.JSONObject())
                }


                var bundles = buildSolvingStepPacketBundlesV1(
                    stepId = stepId,
                    technique = techniqueName,            // legacy string
                    techniqueInfo = techniqueInfoObj,     // ✅ rich object
                    targetCell = targetCellR1C1,
                    targetDigit = targetDigit,
                    techniqueFindingsPayload = techniqueFindingsPayload,
                    nextMovePayload = nextMovePayload,
                    candidatesSnapshotPayload = candidatesSnapshotPayload,
                    overlayFramesPayload = overlayFramesPayload,
                    teachingCardPayload = teachingCardPayload,

                    solvingStepPacketV1Payload = solvingStepPacketPayloadV1,
                    teachingCardV1Payload = teachingCardPayloadV1,

                    gridHash12Before = inHash12.take(12),
                    gridHash12After = inHash12.take(12)
                )

                // ------------------------------------------------------------
                // ✅ Phase 4: Story→Story handover note (structured, not a script)
                // Compare previous step technique (from s.solveStepJson) vs this new step.
                // ------------------------------------------------------------
                runCatching {
                    val prev = extractTechniqueMetaFromStepJsonV1(s.solveStepJson)
                    val next = extractTechniqueMetaFromStepObjV1(stepObj)

                    val prevFam = prev.family?.lowercase()
                    val nextFam = next.family?.lowercase()

                    // Only emit if we truly have "next" info (otherwise no-op)
                    if (!nextFam.isNullOrBlank() || !next.realName.isNullOrBlank() || !next.techniqueId.isNullOrBlank()) {

                        val relation =
                            if (!prevFam.isNullOrBlank() && !nextFam.isNullOrBlank() && prevFam == nextFam) "same_family"
                            else if (!prevFam.isNullOrBlank() && !nextFam.isNullOrBlank() && prevFam != nextFam) "different_family"
                            else "unknown"

                        val payload = org.json.JSONObject().apply {
                            put("schema_version", "handover_note_v1")
                            put("relation", relation)

                            put("prev", org.json.JSONObject().apply {
                                put("technique_id", prev.techniqueId ?: org.json.JSONObject.NULL)
                                put("family", prev.family ?: org.json.JSONObject.NULL)
                                put("real_name", prev.realName ?: org.json.JSONObject.NULL)
                                put("app_name", prev.appName ?: org.json.JSONObject.NULL)
                            })

                            put("next", org.json.JSONObject().apply {
                                put("technique_id", next.techniqueId ?: org.json.JSONObject.NULL)
                                put("family", next.family ?: org.json.JSONObject.NULL)
                                put("real_name", next.realName ?: org.json.JSONObject.NULL)
                                put("app_name", next.appName ?: org.json.JSONObject.NULL)
                            })

                            // Optional “bridge hints” — still facts, not a spoken sentence.
                            // The LLM uses these to produce ONE short contrast/continuity line.
                            put(
                                "bridge_hints",
                                org.json.JSONArray().apply {
                                    when (relation) {
                                        "different_family" -> {
                                            put("contrast: new lens vs last move")
                                            put("keep momentum: same target-first pacing")
                                        }
                                        "same_family" -> {
                                            put("continuity: keep scanning with the same rule family")
                                            put("momentum: cascade likely after placements")
                                        }
                                        else -> {
                                            put("neutral: next move is ready; keep going")
                                        }
                                    }
                                }
                            )
                        }

                        // Ensure only one HANDOVER_NOTE_V1 exists
                        bundles = (bundles.filterNot { it.type == FactBundleV1.Type.HANDOVER_NOTE_V1 } +
                                FactBundleV1(FactBundleV1.Type.HANDOVER_NOTE_V1, payload))
                    }
                }.getOrNull()

                // ------------------------------------------------------------
// Phase 3 gate: if proof invalid, block Tick2 and force recovery
// ------------------------------------------------------------
                var pendingForReady: Pending? = pendingSolve
                var solveStepStatusForReady: SolveStepStatus = SolveStepStatus.READY
                var solveStepSummaryForReady: String? = buildEngineStepSummary(solveStepJson = e.stepJson, coachPlan = plan)
                var solveOverlayVisibleForReady: Boolean = true

                if (!proofOkV1) {

                    // Emit proof verdict telemetry (hard evidence for why we blocked)
                    runCatching {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PROOF_VERDICT_V1",
                                "session_id" to s.sessionId,
                                "turn_id" to s.turnSeq,
                                "tick_id" to 0,
                                "phase" to GridPhase.SOLVING.name,
                                "grid_hash12" to inHash12.take(12),
                                "step_id" to stepId,
                                "ok" to false,
                                "atoms_count" to proofVerdictV1.optInt("atoms_count", 0),
                                "problems_len" to (proofVerdictV1.optJSONArray("problems")?.length() ?: 0),
                                "verdict_json" to proofVerdictV1.toString()
                            )
                        )
                    }

                    val fallbackCellIndex: Int? =
                        runCatching {
                            val r = cellObj?.optInt("r", -1) ?: -1
                            val c = cellObj?.optInt("c", -1) ?: -1
                            if (r in 1..9 && c in 1..9) ((r - 1) * 9 + (c - 1)) else null
                        }.getOrNull()

                    val existingDigitAtFallback: Int? =
                        runCatching {
                            fallbackCellIndex
                                ?.let { idx -> grid81Now?.getOrNull(idx) }
                                ?.digitToIntOrNull()
                                ?.takeIf { it in 1..9 }
                        }.getOrNull()

                    val fallbackCommitAllowed =
                        (fallbackCellIndex != null) &&
                                ((targetDigit ?: -1) in 1..9) &&
                                (existingDigitAtFallback == null)

                    val facts = org.json.JSONObject().apply {
                        put("note", "Proof packet invalid/incomplete. Do not invent the explanation.")
                        put("step_id", stepId)
                        put("grid_hash12", inHash12.take(12))
                        put("proof_verdict_v1", proofVerdictV1)
                        put("fallback_commit_allowed", fallbackCommitAllowed)
                        put("target_cell", targetCellR1C1 ?: org.json.JSONObject.NULL)
                        put("target_digit", targetDigit ?: org.json.JSONObject.NULL)
                        put("technique", techniqueName)
                    }

                    bundles = listOf(
                        FactBundleV1(
                            type = FactBundleV1.Type.OTHER,
                            payload = org.json.JSONObject().apply {
                                put(
                                    "kind",
                                    if (fallbackCommitAllowed) "proof_invalid_fallback_commit_ready" else "proof_invalid"
                                )
                                put("step_id", stepId)
                                put("grid_hash12", inHash12.take(12))
                                put("proof_verdict_v1", proofVerdictV1)
                                put("fallback_commit_allowed", fallbackCommitAllowed)
                                put("target_cell", targetCellR1C1 ?: org.json.JSONObject.NULL)
                                put("target_digit", targetDigit ?: org.json.JSONObject.NULL)
                                put("technique", techniqueName)
                                put("facts", facts)
                            }
                        )
                    )

                    pendingForReady = Pending.SolveStepMissing(
                        prompt =
                            if (fallbackCommitAllowed)
                                "I hit an internal issue while packaging the explanation for this move, but the move itself is still solid."
                            else
                                "I hit an internal issue while packaging the explanation for the next move.",
                        gridHash12 = inHash12.take(12),
                        fallbackStepId = stepId,
                        fallbackCellIndex = fallbackCellIndex,
                        fallbackDigit = targetDigit,
                        fallbackTechnique = techniqueName,
                        fallbackFailureReason = "proof_invalid",
                        autoApplyFallback = fallbackCommitAllowed
                    )

                    solveStepStatusForReady = SolveStepStatus.FAILED
                    solveStepSummaryForReady =
                        if (fallbackCommitAllowed) "Proof invalid — fallback commit." else "Proof invalid — recovery."
                    solveOverlayVisibleForReady = false
                } else {
                    // Telemetry on pass (optional but helpful)
                    runCatching {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PROOF_VERDICT_V1",
                                "session_id" to s.sessionId,
                                "turn_id" to s.turnSeq,
                                "tick_id" to 0,
                                "phase" to GridPhase.SOLVING.name,
                                "grid_hash12" to inHash12.take(12),
                                "step_id" to stepId,
                                "ok" to true,
                                "atoms_count" to proofVerdictV1.optInt("atoms_count", 0)
                            )
                        )
                    }
                }


                val coachPlanSha12Ready: String = plan?.source?.engineStepSha12 ?: ""

                val readyQueue = buildFreshSolveStepAgendaQueue(
                    turnSeq = s.turnSeq,
                    inHash12 = inHash12,
                    stepId = stepId,
                    coachPlanSha12Ready = coachPlanSha12Ready,
                    techniqueId = techniqueId,
                    atomsCount = atomsCount
                )

                val pendingReadyProjected: Pending? =
                    projectPendingFromQueueHead(
                        s = s,
                        queue = readyQueue,
                        story = storyCtx,
                        preferred = pendingForReady
                    )




                val activeRouteCtx =
                    ActiveRouteContext(
                        stepId = stepId,
                        gridHash12 = inHash12.take(12),
                        journeyStepNumber = runCatching {
                            val g = s.grid?.llm?.let { grid81FromLLM(it) } ?: ""
                            val filled = g.count { it in "123456789" }
                            (filled + 1).coerceAtMost(81)
                        }.getOrElse { 0 },
                        atomIndex = 0,
                        atomsCount = atomsCount,
                        techniqueId = techniqueId,
                        targetCellIndex = s.coachPlan?.targetCellIndex
                    )



                val sReadySeed = s.copy(
                    phase = GridPhase.SOLVING,
                    mode = SudoMode.GRID_SESSION,

                    solveStepStatus = solveStepStatusForReady,
                    solveStepJson = e.stepJson,
                    solveStepGridHash12 = inHash12.take(12),
                    solveStepId = stepId,
                    solveStepSeq = nextSeq,
                    solveGuidanceMode = SolveGuidanceModeV1.UNSET,

                    coachPlan = plan,
                    coachPlanGridHash12 = inHash12.take(12),
                    coachPlanStepId = stepId,

                    narrativeStory = storyCtx,
                    activeRouteContext = activeRouteCtx,

                    solveStepSummary = solveStepSummaryForReady,
                    pending = pendingReadyProjected,

                    // Fresh step = fresh atom ladder root.
                    solveAtomIndex = 0,
                    solveAtomsCount = atomsCount,

                    // ✅ Phase 3: new solve step owns a fresh route shell.
                    // We do not preserve any old queue items across step birth.
                    appAgendaQueue = readyQueue,

                    // ✅ PATCH 6.3: cache the “packet + friends” bundles so Tick2 can always include them
                    solvingReadyFactBundlesV1 = bundles,

                    // Phase 3: ensure UI overlay is actually applied when the packet says it's applied
                    solveOverlayVisible = solveOverlayVisibleForReady,

                    // Root-cause fix for session 368:
                    // a fresh SolveStepUpdated must not inherit stale post-commit boundary carriers.
                    solvingRailStateV1 = null,
                    canonicalSolvingPositionV1 = null
                )

                val sReadyBase = sReadySeed.copy(
                    routeCheckpointV1 = deriveRouteCheckpointV1(
                        s = sReadySeed,
                        phaseOverride = GridPhase.SOLVING,
                        appQueueOverride = readyQueue,
                        storyOverride = storyCtx,
                        activeRouteOverride = activeRouteCtx
                    ),
                    solvingRailStateV1 = deriveSolvingRailStateV1(
                        phase = GridPhase.SOLVING,
                        solvingHead = currentQueuedSolvingHead(sReadySeed),
                        pending = pendingReadyProjected,
                        story = storyCtx,
                        activeRoute = activeRouteCtx,
                        solveStepId = stepId,
                        coachPlanStepId = stepId,
                        solveStepGridHash12 = inHash12.take(12),
                        coachPlanGridHash12 = inHash12.take(12),
                        pendingSolveStepAutocoach = s.pendingSolveStepAutocoach,
                        solveStepStatus = solveStepStatusForReady,
                        activeTurnOwnerV1 = sReadySeed.activeTurnOwnerV1
                    )
                )

                val sReady = syncCanonicalSolvingPositionV1(sReadyBase)




                runCatching {
                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "SOLVING_ROUTE_REBASED",
                            "session_id" to s.sessionId,
                            "turn_id" to s.turnSeq,
                            "grid_hash12" to inHash12.take(12),
                            "step_id" to stepId,
                            "queue_size_after" to sReady.appAgendaQueue.size,
                            "queue_head_after" to (currentQueuedSolvingHead(sReady)?.javaClass?.simpleName ?: "null"),
                            "pending_after" to (sReady.pending?.javaClass?.simpleName ?: "null"),
                            "reason" to "solve_step_updated_fresh_queue"
                        )
                    )
                }



                // ✅ AUDIT: emit the FULL engine step JSON accepted by the conductor (after stale-drop + stepId computed),
// and ALSO emit the exact SOLVING_STEP_PACKET bundle that Tick2 will consume (plus bundle inventory).
                runCatching {
                    val rawStep = e.stepJson ?: ""

                    // 1) Full solve step JSON (engine->conductor authoritative)
                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "SOLVE_STEP_JSON_READY",
                            "session_id" to sReady.sessionId,
                            "turn_id" to sReady.turnSeq,
                            "tick_id" to 0, // not a policy tick; engine->conductor binding
                            "phase" to sReady.phase.name,
                            "reason" to e.reason,
                            "grid_hash12" to inHash12.take(12),
                            "step_id" to stepId,
                            "solve_step_status" to sReady.solveStepStatus.name,
                            "step_json_len" to rawStep.length,
                            "step_json_sha12" to sha12(rawStep).take(12),
                            "step_json" to rawStep
                        )
                    )

                    // 2) Inventory what Tick2 will receive (bundle types + counts)
                    // (super useful when you're verifying that richer JSON is actually making it into packets)
                    val bundleTypeNames: List<String> = bundles.map { it.type.name }
                    val bundleTypeCounts: Map<String, Int> = bundleTypeNames.groupingBy { it }.eachCount()

                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "SOLVING_FACT_BUNDLES_READY",
                            "session_id" to sReady.sessionId,
                            "turn_id" to sReady.turnSeq,
                            "tick_id" to 0,
                            "phase" to sReady.phase.name,
                            "grid_hash12" to inHash12.take(12),
                            "step_id" to stepId,
                            "bundle_count" to bundles.size,
                            "bundle_types" to bundleTypeNames,
                            "bundle_type_counts" to bundleTypeCounts
                        )
                    )

                    // 3) Emit the exact SOLVING_STEP_PACKET_V1 bundle (this is what Tick2 should cite from)
                    val stepPacket: FactBundleV1? = bundles.firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }

// Log BOTH:
// - bundle JSON (includes type + payload) = exact FactBundle object Tick2 receives
// - payload-only JSON (easier diffing / reading)
                    val packetBundleJsonStr: String = stepPacket?.toJson()?.toString() ?: ""
                    val packetPayloadJsonStr: String = stepPacket?.payload?.toString() ?: ""

                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "SOLVING_STEP_PACKET_READY",
                            "session_id" to sReady.sessionId,
                            "turn_id" to sReady.turnSeq,
                            "tick_id" to 0,
                            "phase" to sReady.phase.name,
                            "grid_hash12" to inHash12.take(12),
                            "step_id" to stepId,
                            "packet_found" to (stepPacket != null),
                            "packet_type" to (stepPacket?.type?.name ?: "null"),

                            "packet_bundle_len" to packetBundleJsonStr.length,
                            "packet_bundle_sha12" to sha12(packetBundleJsonStr).take(12),
                            "packet_bundle_json" to packetBundleJsonStr,

                            "packet_payload_len" to packetPayloadJsonStr.length,
                            "packet_payload_sha12" to sha12(packetPayloadJsonStr).take(12),
                            "packet_payload_json" to packetPayloadJsonStr
                        )
                    )
                }.onFailure {
                    // Best-effort; never break solving on telemetry errors
                    runCatching {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "SOLVING_TELEMETRY_EMIT_FAILED",
                                "session_id" to s.sessionId,
                                "grid_hash12" to inHash12.take(12),
                                "step_id" to stepId,
                                "error" to (it.javaClass.simpleName ?: "Throwable"),
                                "msg" to (it.message ?: "")
                            )
                        )
                    }
                }

// Capture + clear latch before running policy to avoid loops
                val latch = sReady.pendingSolveStepAutocoach
                val sCleared = sReady.copy(pendingSolveStepAutocoach = null)

                val effs = mutableListOf<Eff>()

                val fallbackPending = sCleared.pending as? Pending.SolveStepMissing
                if (
                    fallbackPending != null &&
                    fallbackPending.autoApplyFallback &&
                    (fallbackPending.fallbackCellIndex in 0..80) &&
                    ((fallbackPending.fallbackDigit ?: -1) in 1..9)
                ) {
                    val fallbackCellLabel = indexToCell(fallbackPending.fallbackCellIndex!!)
                    val fallbackDigit = fallbackPending.fallbackDigit!!
                    val fallbackTechnique =
                        fallbackPending.fallbackTechnique?.takeIf { it.isNotBlank() } ?: "a valid solver move"

                    runCatching {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "PROOF_FAILURE_FALLBACK_COMMIT_DISPATCH",
                                "session_id" to sCleared.sessionId,
                                "turn_id" to sCleared.turnSeq,
                                "phase" to sCleared.phase.name,
                                "step_id" to (fallbackPending.fallbackStepId ?: "null"),
                                "grid_hash12" to (fallbackPending.gridHash12 ?: "null"),
                                "cell" to fallbackCellLabel,
                                "digit" to fallbackDigit,
                                "technique" to fallbackTechnique
                            )
                        )
                    }

                    val header = buildString {
                        append(buildStateHeader(sCleared))
                        append("\n")
                        append(
                            "fallback_ctx=proof_failure_fallback_commit " +
                                    "stepId=${fallbackPending.fallbackStepId ?: "unknown"} " +
                                    "cell=$fallbackCellLabel digit=$fallbackDigit technique=$fallbackTechnique"
                        )
                    }

                    val (s2, eff) = callPolicyWithTrace(
                        traceState = sCleared,
                        userText = "[EVENT] proof_failure_fallback_commit",
                        stateHeader = header,
                        mode = sCleared.mode,
                        reason = "proof_failure_fallback_commit",
                        turnId = sCleared.turnSeq
                    )

                    effs += Eff.ApplyCellEdit(
                        toolCallId = "tc:${sCleared.turnSeq}:proof_fallback_commit:${fallbackPending.fallbackCellIndex}:${fallbackDigit}",
                        cellIndex = fallbackPending.fallbackCellIndex,
                        digit = fallbackDigit,
                        source = "proof_failure_fallback_commit"
                    )
                    effs += eff
                    return Next(s2, effs)
                }

// ✅ Refresh overlay deterministically (if visible)
                if (sCleared.solveOverlayVisible && !sCleared.solveStepJson.isNullOrBlank()) {
                    val style = sCleared.solveOverlayStyle.ifBlank { "full" }

                    // Prefer applied_frame_ids from the solving packet (already rewritten by story stage).
                    val applied = currentAppliedOverlayFrameIdsOrNull(sCleared)
                        ?: run {
                            val story = sCleared.narrativeStory
                            if (story != null) {
                                storyOverlayFrameIdsFromStoryV1(story)
                                    .takeIf { it.isNotEmpty() }
                                    ?: listOf(currentSolveOverlayFrameId(sCleared, sCleared.solveAtomIndex))
                            } else {
                                listOf(currentSolveOverlayFrameId(sCleared, sCleared.solveAtomIndex))
                            }
                        }

                    val frameJson = buildSolveOverlayCompositeFrameJsonV1(
                        s = sCleared,
                        frameIds = applied,
                        style = style,
                        reason = "solve_step_updated_overlay_refresh"
                    )

                    runCatching {
                        val cell66Summary = summarizeOverlayForCellV1(frameJson, 66)

                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "OVERLAY_RENDER_REQUESTED",
                                "session_id" to sCleared.sessionId,
                                "turn_id" to sCleared.turnSeq,
                                "tick_id" to 2,
                                "phase" to sCleared.phase.name,
                                "reason" to "solve_step_updated_overlay_refresh",
                                "frame_id" to (applied.lastOrNull() ?: "none"),
                                "applied_frame_ids" to applied.joinToString(","),
                                "frame_json_sha12" to sha12(frameJson).take(12),
                                "frame_json_len" to frameJson.length,
                                "cell66_summary" to cell66Summary,
                                "frame_json" to frameJson
                            )
                        )
                    }

                    effs += Eff.RenderSolveOverlay(
                        frameJson = frameJson,
                        style = style,
                        reason = "solve_step_updated_overlay_refresh"
                    )
                }

// ✅ If we were computing for an autocoach reason, immediately ask policy to speak,
// but only when no live user detour / bridge state is blocking solve progression.
                if (latch != null) {
                    if (sCleared.solveStepStatus != SolveStepStatus.READY) {
                        runCatching {
                            ConversationTelemetry.emit(
                                mapOf(
                                    "type" to "SOLVE_STEP_READY_AUTOSPEAK_BLOCKED",
                                    "session_id" to sCleared.sessionId,
                                    "turn_id" to sCleared.turnSeq,
                                    "phase" to sCleared.phase.name,
                                    "reason" to "solve_step_not_ready",
                                    "solve_step_status" to sCleared.solveStepStatus.name,
                                    "grid_hash12" to (latch.gridHash12.take(12)),
                                    "request_kind" to latch.requestKind.name
                                )
                            )
                        }
                        return Next(sCleared, effs)
                    }

                    val deferSolveProgressionForUserDetour =
                        shouldDeferSolveProgressionForUserDetourV1(sCleared)

                    if (deferSolveProgressionForUserDetour) {
                        runCatching {
                            ConversationTelemetry.emit(
                                mapOf(
                                    "type" to "SOLVE_STEP_READY_AUTOSPEAK_DEFERRED",
                                    "session_id" to sCleared.sessionId,
                                    "turn_id" to sCleared.turnSeq,
                                    "phase" to sCleared.phase.name,
                                    "reason" to "live_user_detour_blocks_autocoach_dispatch",
                                    "pending_kind" to (sCleared.pending?.javaClass?.simpleName ?: "null"),
                                    "owner" to sCleared.activeTurnOwnerV1.name,
                                    "user_queue_size" to sCleared.userAgendaQueue.size,
                                    "grid_hash12" to latch.gridHash12.take(12),
                                    "request_kind" to latch.requestKind.name
                                )
                            )
                        }
                        return Next(sCleared, effs)
                    }

                    val autocoachReasonCode =
                        when (latch.reason) {
                            "solve_next_step_requested" -> "R_NEXT"
                            "enter_solving_prefetch" -> "R_ENTER"
                            else -> "R_OTHER"
                        }

                    val header = buildString {
                        append(buildStateHeader(sCleared))
                        append("\n")
                        append("autocoach_ctx=solve_step_ready origin=${latch.origin} reason_code=$autocoachReasonCode gridHash12=${latch.gridHash12}")
                    }

                    val (s2, eff) = callPolicyWithTrace(
                        traceState = sCleared,
                        // Root-cause fix for session 368:
                        // keep solve-step-ready autocoach semantically neutral so Tick-1
                        // speaks the freshly installed boundary instead of re-requesting
                        // another "next step".
                        userText = "[EVENT] solve_step_ready",
                        stateHeader = header,
                        mode = sCleared.mode,
                        reason = "solve_step_ready_autocoach",
                        turnId = sCleared.turnSeq
                    )

                    effs += eff
                    return Next(s2, effs)
                }

                return Next(sCleared, effs)
            }


            is Evt.SolveStepFailed -> {

                val inHash12 = runCatching { e.gridHash12.take(12) }.getOrNull()

                runCatching {
                    ConversationTelemetry.emitKv(
                        "SOLVE_STEP_FAILED",
                        "session_id" to s.sessionId,
                        "turn_seq" to s.turnSeq,
                        "grid_hash12" to (inHash12 ?: "null"),
                        "reason" to (e.reason ?: "null"),
                        "error" to (e.error ?: "null")
                    )
                }

                val sMissing = s.copy(
                    solveStepStatus = SolveStepStatus.FAILED,
                    solveStepSummary = null,
                    solvingReadyFactBundlesV1 = emptyList(),

                    // Clear any stale evidence/plan
                    coachPlan = null,
                    coachPlanGridHash12 = null,
                    coachPlanStepId = null,
                    coachPlanSha12 = null,
                    coachPlanJson = null,

                    // Do NOT auto-speak via deterministic text on failure.
                    pendingSolveStepAutocoach = null,

                    // Semantic-only pending (no script)
                    pending = Pending.SolveStepMissing(
                        prompt = "",
                        gridHash12 = inHash12
                    )
                )

                // Phase 1: no deterministic assistant speech. Let the next policy reply handle phrasing.
                return Next(sMissing, emptyList())
            }

            is Evt.ToolExecuted -> {


                // ✅ v1: if we are waiting for deterministic ops, only trigger Tick2 when ALL are done.
                val pr = s.pendingReplyV1
                if (pr != null && pr.isWaiting() && pr.pendingToolCallIds.contains(e.toolCallId)) {

                    val pr2 = pr.withDone(e.toolCallId)

                    // Not all tools done yet → keep waiting deterministically (NO Tick2).
                    if (!pr2.isDone()) {
                        return Next(
                            s.copy(pendingReplyV1 = pr2),
                            emptyList()
                        )
                    }


                    // ------------------------------------------------------------
// Post-apply agenda promotion BEFORE Tick2
//
// Canonical handover:
// if post-apply truth now becomes uniquely solvable, DO NOT jump directly
// to start-solving. First promote to the exact-match signoff gate.
// Only after that signoff succeeds may finalize cleanup + start-solving CTA occur.
// ------------------------------------------------------------
                    val sBase = s.copy(pendingReplyV1 = null)

                    val llmNow = sBase.grid?.llm as? LLMGridState
                    val refreshedAgenda =
                        if (llmNow != null) {
                            buildAppAgendaFromGrid(
                                llm = llmNow,
                                phase = sBase.phase,
                                createdTurnSeq = sBase.turnSeq,
                                userConfirmedPerfectMatch = sBase.userConfirmedPerfectMatch,
                                retakeDismissed = sBase.retakeDismissed,
                                startSolvingCtaActive = (sBase.pending is Pending.ConfirmStartSolving)
                            )
                        } else {
                            sBase.appAgendaQueue
                        }

                    val head = refreshedAgenda.firstOrNull()

                    val shouldPromoteToConfirmValidate =
                        (sBase.phase != GridPhase.SOLVING) && (head is AppAgendaItem.ConfirmValidationExactMatch)

                    val shouldPromoteToFinalize =
                        (sBase.phase != GridPhase.SOLVING) && (head is AppAgendaItem.FinalizeValidationStartSolving)

                    if (shouldPromoteToConfirmValidate) {

                        val promotedPending = Pending.ConfirmValidate(
                            prompt = "The grid looks consistent, and I can solve it uniquely from what’s on screen. Before we begin, does the on-screen grid match your puzzle exactly?"
                        )

                        val sPromoted = sBase.copy(
                            pending = promotedPending,
                            focusCellIndex = null
                        )

                        val promotedDecision = pr2.decision.copy(
                            summary = "post_apply_promoted_confirm_validate",
                            stateMutations = pr2.decision.stateMutations.copy(
                                newPending = promotedPending,
                                newFocusIdx = null,
                                newPhase = GridPhase.SEALING,
                                newMode = sBase.mode
                            )
                        )

                        val solvingPacket = sPromoted.solvingReadyFactBundlesV1
                        val factsFinal =
                            if (solvingPacket.isNotEmpty()) solvingPacket + pr2.factBundles else pr2.factBundles

                        val sigToStore = storySignatureToStoreForTurnV1(sPromoted)
                        val sFinal =
                            if (!sigToStore.isNullOrBlank()) sPromoted.copy(lastStorySignatureV1 = sigToStore) else sPromoted

                        val replyExec = buildReplyRequestV1(
                            sBefore = pr2.sBefore,
                            sAfter = sFinal,
                            turnId = pr2.turnId,
                            userText = pr2.userText,
                            decision = promotedDecision,
                            factBundles = factsFinal
                        )

                        val headerAfter = buildStateHeader(sPromoted)
                        val (sTick2, ctx2) = nextPolicyCtx(
                            s = sFinal,
                            tickId = 2,
                            reason = "v1_after_ops_promoted_confirm_validate",
                            stateHeader = headerAfter,
                            turnId = pr2.turnId
                        )

                        runCatching {
                            emitGridFactsNowIfPresent(
                                s = sTick2,
                                ctx = ctx2,
                                stage = "PRE_TICK2",
                                note = "after_ops_promoted_confirm_validate"
                            )
                        }

                        emitPolicyCallTrace(
                            traceState = sPromoted,
                            userText = pr2.userText,
                            stateHeader = headerAfter,
                            reason = "v1_after_ops_promoted_confirm_validate",
                            turnId = pr2.turnId,
                            ctx = ctx2,
                            extraData = mapOf(
                                "decision_kind" to pr2.decision.decisionKind.name,
                                "fact_bundle_types" to pr2.factBundles.joinToString(",") { it.type.name },
                                "op_count" to pr2.pendingToolCallIds.size
                            )
                        )
                        emitModelCallBegin(ctx2)

                        return Next(
                            sTick2,
                            listOf(
                                Eff.CallReplyGenerateV1(
                                    ctx = ctx2,
                                    replyRequest = replyExec.replyRequest,
                                    planResult = replyExec.planResult,
                                    reason = "v1_after_ops_promoted_confirm_validate",
                                    turnId = pr2.turnId
                                )
                            )
                        )

                    } else if (shouldPromoteToFinalize) {

                        val agendaAfter = refreshedAgenda.drop(1)

                        val promotedPending = Pending.ConfirmStartSolving(
                            prompt = "Your grid is uniquely solvable now, and the screen has been finalized. Ready to start solving?"
                        )

                        val sPromoted = sBase.copy(
                            appAgendaQueue = agendaAfter,
                            pending = promotedPending,
                            focusCellIndex = null
                        )

                        val finalizeEff = opToEffectV1(
                            PlannedOpV1.FinalizeValidationPresentation(
                                reason = (head as AppAgendaItem.FinalizeValidationStartSolving).reason,
                                source = "post_apply_promotion"
                            ),
                            turnId = pr2.turnId
                        )

                        val finalizeToolId = (finalizeEff as? Eff.FinalizeValidationPresentation)?.toolCallId

                        val promotedDecision = pr2.decision.copy(
                            summary = "post_apply_promoted_finalize_start_solving",
                            stateMutations = pr2.decision.stateMutations.copy(
                                newPending = promotedPending,
                                newFocusIdx = null,
                                newPhase = GridPhase.SEALING,
                                newMode = sPromoted.mode
                            )
                        )

                        val prPromoted =
                            if (finalizeToolId != null) {
                                pr2.copy(
                                    decision = promotedDecision,
                                    pendingToolCallIds = setOf(finalizeToolId),
                                    doneToolCallIds = emptySet()
                                )
                            } else {
                                pr2.copy(decision = promotedDecision)
                            }

                        return if (finalizeToolId != null) {
                            Next(
                                sPromoted.copy(pendingReplyV1 = prPromoted),
                                listOf(finalizeEff)
                            )
                        } else {
                            val solvingPacket = sPromoted.solvingReadyFactBundlesV1
                            val factsFinal =
                                if (solvingPacket.isNotEmpty()) solvingPacket + pr2.factBundles else pr2.factBundles

                            val sigToStore = storySignatureToStoreForTurnV1(sPromoted)
                            val sFinal =
                                if (!sigToStore.isNullOrBlank()) sPromoted.copy(lastStorySignatureV1 = sigToStore) else sPromoted

                            val replyExec = buildReplyRequestV1(
                                sBefore = pr2.sBefore,
                                sAfter = sFinal,
                                turnId = pr2.turnId,
                                userText = pr2.userText,
                                decision = promotedDecision,
                                factBundles = factsFinal
                            )

                            val headerAfter = buildStateHeader(sPromoted)
                            val (sTick2, ctx2) = nextPolicyCtx(
                                s = sFinal,
                                tickId = 2,
                                reason = "v1_after_ops_promoted_finalize",
                                stateHeader = headerAfter,
                                turnId = pr2.turnId
                            )

                            runCatching {
                                emitGridFactsNowIfPresent(
                                    s = sTick2,
                                    ctx = ctx2,
                                    stage = "PRE_TICK2",
                                    note = "after_ops_promoted_finalize"
                                )
                            }

                            emitPolicyCallTrace(
                                traceState = sPromoted,
                                userText = pr2.userText,
                                stateHeader = headerAfter,
                                reason = "v1_after_ops_promoted_finalize",
                                turnId = pr2.turnId,
                                ctx = ctx2,
                                extraData = mapOf(
                                    "decision_kind" to pr2.decision.decisionKind.name,
                                    "fact_bundle_types" to pr2.factBundles.joinToString(",") { it.type.name },
                                    "op_count" to pr2.pendingToolCallIds.size
                                )
                            )
                            emitModelCallBegin(ctx2)

                            Next(
                                sTick2,
                                listOf(
                                    Eff.CallReplyGenerateV1(
                                        ctx = ctx2,
                                        replyRequest = replyExec.replyRequest,
                                        planResult = replyExec.planResult,
                                        reason = "v1_after_ops_promoted_finalize",
                                        turnId = pr2.turnId
                                    )
                                )
                            )
                        }
                    }

// ------------------------------------------------------------
// Default path (no promotion): proceed with original behavior
// ------------------------------------------------------------



                    val sAfter = sBase

                    val solvingPacket = sAfter.solvingReadyFactBundlesV1
                    val factsFinal = if (solvingPacket.isNotEmpty()) solvingPacket + pr2.factBundles else pr2.factBundles



                    val sigToStore = storySignatureToStoreForTurnV1(sAfter)
                    val sFinal = if (!sigToStore.isNullOrBlank()) sAfter.copy(lastStorySignatureV1 = sigToStore) else sAfter


                    val replyExec = buildReplyRequestV1(
                        sBefore = pr2.sBefore,
                        sAfter = sFinal,
                        turnId = pr2.turnId,
                        userText = pr2.userText,
                        decision = pr2.decision,
                        factBundles = factsFinal
                    )

// ✅ create a fresh tick2 ctx (so we get MODEL_CALL_BEGIN/END with tick_id=2)
                    val headerAfter = buildStateHeader(sFinal)
                    val (sTick2, ctx2) = nextPolicyCtx(
                        s = sFinal,
                        tickId = 2,
                        reason = "v1_after_ops",
                        stateHeader = headerAfter,
                        turnId = pr2.turnId
                    )

// ✅ Audit: PRE_TICK2 facts
                    runCatching {
                        emitGridFactsNowIfPresent(
                            s = sTick2,
                            ctx = ctx2,
                            stage = "PRE_TICK2",
                            note = "after_ops_default"
                        )
                    }

                    emitPolicyCallTrace(
                        traceState = sFinal,
                        userText = pr2.userText,
                        stateHeader = headerAfter,
                        reason = "v1_after_ops",
                        turnId = pr2.turnId,
                        ctx = ctx2,
                        extraData = mapOf(
                            "decision_kind" to pr2.decision.decisionKind.name,
                            "fact_bundle_types" to pr2.factBundles.joinToString(",") { it.type.name },
                            "op_count" to pr2.pendingToolCallIds.size
                        )
                    )
                    emitModelCallBegin(ctx2)

                    return Next(
                        sTick2,
                        listOf(
                            Eff.CallReplyGenerateV1(
                                ctx = ctx2,
                                replyRequest = replyExec.replyRequest,
                                planResult = replyExec.planResult,
                                reason = "v1_after_ops",
                                turnId = pr2.turnId
                            )
                        )
                    )
                }


                // ---------------------------------------------
                // A) Keep your existing Tick2 tool-result accumulation
                // ---------------------------------------------
                val pt = s.pendingTick2
                val sAfterTick2 = if (pt == null) {
                    // No tick2 pending; still useful for telemetry but no state update needed
                    s
                } else {
                    val ids = pt.toolResultIds.toMutableList()
                    val lines = pt.toolResults.toMutableList()

                    val i = ids.indexOf(e.toolResultId)
                    if (i >= 0) {
                        // Replace in-place (keeps alignment between ids and lines)
                        if (i < lines.size) lines[i] = e.toolResultText
                        else {
                            // Defensive: if lists got out of sync, append
                            ids += e.toolResultId
                            lines += e.toolResultText
                        }
                    } else {
                        ids += e.toolResultId
                        lines += e.toolResultText
                    }

                    s.copy(
                        pendingTick2 = pt.copy(
                            toolResultIds = ids,
                            toolResults = lines
                        )
                    )
                }

                // ---------------------------------------------
                // B) Phase 4 latch: commit phase ONLY when the seal tool is confirmed complete
                // ---------------------------------------------
                val sealResultId = sAfterTick2.pendingSealToolResultId
                val phaseAfterSeal = sAfterTick2.pendingPhaseAfterSeal

                val isSealCompletion = (sealResultId != null && sealResultId == e.toolResultId)

                if (isSealCompletion && phaseAfterSeal != null) {
                    // Commit SOLVING (or whatever phaseAfterSeal is) ONLY now.
                    val committedPhase = phaseAfterSeal

                    runCatching {
                        ConversationTelemetry.emitPhaseTransition(
                            turnId = e.turnId,
                            tickId = e.tickId,
                            phaseBefore = sAfterTick2.phase.name,
                            phaseAfter = committedPhase.name,
                            reason = "seal_completed_tool_executed",
                        )
                    }

                    val sCommittedBase = sAfterTick2.copy(
                        phase = committedPhase,
                        pendingPhaseAfterSeal = null,
                        pendingSealToolResultId = null,
                        focusCellIndex = if (committedPhase == GridPhase.SOLVING) null else sAfterTick2.focusCellIndex
                    )

                    // ✅ PATCH 4: SOLVING entry compute uses exact same latch (compute-then-speak)
                    val llm = sCommittedBase.grid?.llm
                    return if (committedPhase == GridPhase.SOLVING && llm != null) {
                        val g81 = grid81FromLLM(llm)
                        val h12 = sha12(g81)

                        val sCommitted = sCommittedBase.copy(
                            solveStepStatus = SolveStepStatus.COMPUTING,

                            // ✅ PATCH 6.3.D: entering solving → request new step → clear stale packet
                            solvingReadyFactBundlesV1 = emptyList(),

                            pendingSolveStepAutocoach = PendingSolveStepAutocoach(
                                reason = "enter_solving_after_seal",
                                gridHash12 = h12.take(12),
                                origin = "enter_solving_after_seal",
                                turnSeq = sCommittedBase.turnSeq,
                                requestKind = SolveStepRequestKindV1.SOLVING_ENTRY,
                                requestToken = null,
                                allowReplaceLockedStep = false
                            )
                        )

                        Next(
                            sCommitted,
                            listOf(
                                Eff.ComputeSolveStep(
                                    grid81 = g81,
                                    gridHash12 = h12,
                                    reason = "enter_solving_after_seal",
                                    force = true
                                )
                            )
                        )
                    } else {
                        Next(sCommittedBase, emptyList())
                    }
                }

                Next(sAfterTick2, emptyList())
            }


            is Evt.ReplyReceived -> {
                val t = e.text.trim()
                val finalText = if (t.isNotBlank()) t else SURVIVAL_REPLY


                runCatching {
                    // Pull the currently cached step packet flags (if any)
                    val stepPacketV1 = s.solvingReadyFactBundlesV1
                        .firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
                        ?.payload

                    val overlaysObj = stepPacketV1?.optJSONObject("overlays")
                    val appliedFramesArr = overlaysObj?.optJSONArray("applied_frame_ids")
                    val appliedFramesCount = appliedFramesArr?.length() ?: 0

                    val spoilerObj = stepPacketV1?.optJSONObject("step")?.optJSONObject("spoiler")
                    val digitHidden = spoilerObj?.optBoolean("digit_hidden", false) ?: false
                    val revealAllowed = spoilerObj?.optBoolean("reveal_allowed", false) ?: false

                    val resultObj = stepPacketV1?.optJSONObject("step")?.optJSONObject("result")
                    val targetDigit = runCatching {
                        if (resultObj == null) null
                        else if (resultObj.isNull("digit")) null
                        else resultObj.optInt("digit", -1).takeIf { it in 1..9 }
                    }.getOrNull()

                    // Heuristics for audits
                    val textLower = finalText.lowercase()
                    val mentionsHighlight = textLower.contains("highlight")
                            || textLower.contains("highlighted")
                            || textLower.contains("green")
                            || textLower.contains("grey")
                            || textLower.contains("gray")

                    val mapsVoiceLeak = textLower.contains("say \"next step\"")
                            || textLower.contains("say 'next step'")
                            || textLower.contains("just say next step")
                            || textLower.contains("say next step")

                    // very simple digit detection (auditor will do stricter parsing)
                    val hasStandaloneDigit = Regex("""\b[1-9]\b""").containsMatchIn(finalText)

                    ConversationTelemetry.emit(
                        mapOf(
                            "type" to "TICK2_REPLY_TEXT",
                            "session_id" to s.sessionId,
                            "turn_id" to s.turnSeq,
                            "tick_id" to 2,
                            "mode" to s.mode.name,
                            "phase" to s.phase.name,
                            "reply_len" to finalText.length,
                            "reply_preview" to previewLocal(finalText, 320),

                            "has_step_packet_v1" to s.solvingReadyFactBundlesV1.any { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 },
                            "has_recovery_packet_v1" to s.solvingReadyFactBundlesV1.any { it.type == FactBundleV1.Type.RECOVERY_PACKET_V1 },

                            "overlay_applied_frames_count" to appliedFramesCount,
                            "spoiler_digit_hidden" to digitHidden,
                            "spoiler_reveal_allowed" to revealAllowed,
                            "target_digit_if_available" to (targetDigit ?: -1),

                            "mentions_highlight" to mentionsHighlight,
                            "maps_voice_leak" to mapsVoiceLeak,
                            "has_standalone_digit" to hasStandaloneDigit
                        )
                    )

                    ConversationTelemetry.emitCtaRenderAudit(
                        turnId = s.turnSeq,
                        tickId = 2,
                        ownerKind = s.activeTurnOwnerV1.name,
                        phase = s.phase.name,
                        storyStage = s.narrativeStory?.stage?.name,
                        assistantText = finalText,
                        bannedPhrases = listOf(
                            "setup",
                            "confrontation",
                            "resolution",
                            "detour",
                            "checkpoint",
                            "agenda",
                            "owner",
                            "packet",
                            "story stage"
                        )
                    )
                }

                // ✅ App brain records transcript (keep last 3)
                runCatching {
                    val user = s.lastUserText.orEmpty()
                    if (user.isNotBlank()) {
                        SessionStore.appendTurnToTranscript(
                            turnId = s.turnSeq,
                            userText = user,
                            assistantText = finalText
                        )
                    }
                    SessionStore.ensureFirstAssistantSpeech(finalText)
                }

                // ✅ NEW: emit per-turn memory snapshot after transcript append
                runCatching {
                    val mem = SessionStore.snapshotMemoryJson()

                    ConversationTelemetry.emitPolicyTrace(
                        tag = "TURN_SUMMARY_SNAPSHOT",
                        data = mapOf(
                            "session_id" to s.sessionId,
                            "turn_id" to s.turnSeq,
                            "tick_id" to 2,

                            // show the actual spoken text briefly
                            "user_preview" to previewLocal(s.lastUserText.orEmpty(), 240),
                            "assistant_preview" to previewLocal(finalText, 300),

                            // --- user tally ---
                            "user_tally_sha12" to sha12(mem.userTallyJson),
                            "user_tally_len" to mem.userTallyJson.length,
                            "user_tally_json" to mem.userTallyJson,

                            // --- assistant tally ---
                            "assistant_tally_sha12" to sha12(mem.assistantTallyJson),
                            "assistant_tally_len" to mem.assistantTallyJson.length,
                            "assistant_tally_json" to mem.assistantTallyJson,

                            // --- relationship memory ---
                            "relationship_memory_sha12" to sha12(mem.relationshipMemoryJson),
                            "relationship_memory_len" to mem.relationshipMemoryJson.length,
                            "relationship_memory_json" to mem.relationshipMemoryJson,

                            // --- recent turns ---
                            "recent_turns_sha12" to sha12(mem.recentTurnsJson),
                            "recent_turns_len" to mem.recentTurnsJson.length,
                            "recent_turns_json" to mem.recentTurnsJson
                        )
                    )
                }

                // ------------------------------------------------------------
                // ✅ Phase 5 North Star: overlay → UI text → speak ordering
                // AND step-level scorecard emission for audit.
                // ------------------------------------------------------------

                // Update scorecard flags based on the story stage we just delivered.
                val ns = s.narrativeStory
                val stepIdNow = ns?.stepId

                // Reset scorecard if we switched to a new stepId.
                val scoreStepId = if (stepIdNow != null && stepIdNow != s.storyScoreStepIdV1) stepIdNow else s.storyScoreStepIdV1
                val reset = (stepIdNow != null && stepIdNow != s.storyScoreStepIdV1)

                var deliveredSetup = if (reset) false else s.storyDeliveredSetupV1
                var proofMax = if (reset) 0 else s.storyDeliveredProofMaxAtomV1
                var deliveredCommit = if (reset) false else s.storyDeliveredCommitV1

                if (isConstitutionalAppRouteOwnerV1(s) && ns != null && stepIdNow != null) {
                    when (ns.stage) {
                        StoryStage.SETUP -> deliveredSetup = true

                        StoryStage.CONFRONTATION -> {
                            val proofAtoms = ns.discussedAtomIndices
                                .filter { it in proofAtomIndicesForStoryV1(ns.atomsCount) }

                            val deliveredProofMax =
                                proofAtoms.maxOrNull()
                                    ?: defaultFocusAtomIndexForStageV1(
                                        stage = StoryStage.CONFRONTATION,
                                        atomsCount = ns.atomsCount,
                                        preferredProofAtomIndex = ns.focusAtomIndex
                                    )

                            if (deliveredProofMax > proofMax) proofMax = deliveredProofMax
                        }

                        StoryStage.RESOLUTION -> deliveredCommit = true
                    }
                }

                val unresolvedClarificationHeadBeforeReply =
                    unresolvedClarificationHeadV1(s.userAgendaQueue)

                val detourStateAfterReply =
                    if (s.pending is Pending.UserAgendaBridge && s.detourState != null) {
                        if (unresolvedClarificationHeadBeforeReply != null) {
                            s.detourState.copy(
                                answerState = DetourAnswerStateV1.ACTIVE_UNANSWERED,
                                answerFailureReason = null,
                                answeredTurnSeq = null,
                                failedTurnSeq = null
                            )
                        } else {
                            s.detourState.copy(
                                answerState = DetourAnswerStateV1.ANSWERED_READY_TO_RETURN,
                                answerFailureReason = null,
                                answeredTurnSeq = s.turnSeq,
                                failedTurnSeq = null
                            )
                        }
                    } else {
                        s.detourState
                    }


                val detourHistoryAfterReply =
                    if (s.pending is Pending.UserAgendaBridge) {
                        appendDetourTurnHistoryV1(
                            history = s.detourTurnHistoryV1,
                            record = detourTurnRecordFromStateV1(
                                detourState = detourStateAfterReply,
                                turnSeq = s.turnSeq
                            )
                        )
                    } else {
                        s.detourTurnHistoryV1
                    }

                val userAgendaAfterReply =
                    if (s.pending is Pending.UserAgendaBridge) {
                        pruneNonPersistentUserAgendaItemsV1(s.userAgendaQueue)
                    } else {
                        s.userAgendaQueue
                    }

                if (s.pending is Pending.UserAgendaBridge && detourStateAfterReply != null) {
                    runCatching {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "DETOUR_ANSWER_STATE_V1",
                            data = mapOf(
                                "turn_id" to s.turnSeq,
                                "state" to detourStateAfterReply.answerState.name,
                                "reason" to (
                                        if (unresolvedClarificationHeadBeforeReply != null)
                                            "clarification_reply_keeps_detour_active"
                                        else
                                            "reply_received_for_user_agenda_bridge"
                                        ),
                                "question_class" to (detourStateAfterReply.questionClass?.name ?: "null"),
                                "anchor_step_id" to (detourStateAfterReply.anchorStepId ?: "null"),
                                "anchor_stage" to (detourStateAfterReply.anchorStage?.name ?: "null")
                            )
                        )
                    }
                }

                // Compose next state with updated scorecard + last assistant text.
                val s2 = s.copy(
                    lastAssistantText = finalText,
                    lastReplyLen = finalText.length,
                    userAgendaQueue = userAgendaAfterReply,
                    detourTurnHistoryV1 = detourHistoryAfterReply,

                    storyScoreStepIdV1 = scoreStepId,
                    storyDeliveredSetupV1 = deliveredSetup,
                    storyDeliveredProofMaxAtomV1 = proofMax,
                    storyDeliveredCommitV1 = deliveredCommit,
                    detourState = detourStateAfterReply
                )

                runCatching {
                    emitDetourIsolationInvariantV1(
                        s = s2,
                        stage = "POST_DETOUR_REPLY_SUCCESS"
                    )
                }

                val effs = mutableListOf<Eff>()

                // ✅ Always render the composite overlay BEFORE speaking in SOLVING
                if (s2.phase == GridPhase.SOLVING &&
                    s2.solveOverlayVisible &&
                    !s2.solveStepJson.isNullOrBlank()
                ) {
                    val style = s2.solveOverlayStyle.ifBlank { "full" }
                    val applied = currentAppliedOverlayFrameIdsOrNull(s2)
                        ?: listOf(currentSolveOverlayFrameId(s2, s2.solveAtomIndex))

                    val renderDetourNative =
                        s2.activeOverlayOwnerV1 == OverlayOwnerV1.USER_OWNER &&
                                s2.detourState?.isActive == true &&
                                s2.detourNarrativeContextV1 != null &&
                                applied.any { it.startsWith("detour:", ignoreCase = true) }

                    val frameJson =
                        if (renderDetourNative) {
                            buildDetourOverlayCompositeFrameJsonV1(
                                s = s2,
                                frameIds = applied,
                                style = style,
                                reason = "reply_received_pre_speak_overlay"
                            )
                        } else {
                            buildSolveOverlayCompositeFrameJsonV1(
                                s = s2,
                                frameIds = applied,
                                style = style,
                                reason = "reply_received_pre_speak_overlay"
                            )
                        }

                    runCatching {
                        val cell66Summary = summarizeOverlayForCellV1(frameJson, 66)

                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "OVERLAY_RENDER_REQUESTED",
                                "session_id" to s2.sessionId,
                                "turn_id" to s2.turnSeq,
                                "tick_id" to 2,
                                "phase" to s2.phase.name,
                                "reason" to "reply_received_pre_speak_overlay",
                                "frame_id" to (applied.lastOrNull() ?: "none"),
                                "applied_frame_ids" to applied.joinToString(","),
                                "frame_json_sha12" to sha12(frameJson).take(12),
                                "frame_json_len" to frameJson.length,
                                "cell66_summary" to cell66Summary,
                                "frame_json" to frameJson
                            )
                        )
                    }

                    effs += Eff.RenderSolveOverlay(
                        frameJson = frameJson,
                        style = style,
                        reason = "reply_received_pre_speak_overlay"
                    )
                }

                // Then update UI and speak
                effs += Eff.UpdateUiMessage(finalText)
                effs += Eff.Speak(finalText, listenAfter = true)

                // ✅ Emit step-level scorecard + evidence bundle once COMMIT has been delivered
                if (s2.phase == GridPhase.SOLVING &&
                    deliveredCommit &&
                    scoreStepId != null
                ) {
                    val payload = org.json.JSONObject().apply {
                        put("schema_version", "step_story_scorecard_v1")
                        put("step_id", scoreStepId)
                        put("delivered_setup", deliveredSetup)
                        put("delivered_proof_max_atom", proofMax)
                        put("delivered_commit", deliveredCommit)

                        val ns2 = s2.narrativeStory
                        put("story_stage_now", ns2?.stage?.name ?: org.json.JSONObject.NULL)
                        put("atoms_count", ns2?.atomsCount ?: org.json.JSONObject.NULL)

                        val applied = currentAppliedOverlayFrameIdsOrNull(s2) ?: emptyList()
                        put("applied_frame_ids", org.json.JSONArray().apply { applied.forEach { put(it) } })

                        put("last_story_signature_v1", s2.lastStorySignatureV1 ?: org.json.JSONObject.NULL)
                    }

                    // Persist the evidence bundle inside solvingReadyFactBundlesV1 for audit logs.
                    val bundles = (s2.solvingReadyFactBundlesV1.filterNot { it.type == FactBundleV1.Type.STEP_STORY_SCORECARD_V1 } +
                            FactBundleV1(FactBundleV1.Type.STEP_STORY_SCORECARD_V1, payload))

                    // Emit telemetry scorecard as well (one-line truth source)
                    runCatching {
                        ConversationTelemetry.emit(
                            mapOf(
                                "type" to "NORTHSTAR_STEP_SCORECARD",
                                "session_id" to s2.sessionId,
                                "turn_id" to s2.turnSeq,
                                "step_id" to scoreStepId,
                                "delivered_setup" to deliveredSetup,
                                "delivered_proof_max_atom" to proofMax,
                                "delivered_commit" to deliveredCommit,
                                "last_story_signature_v1" to (s2.lastStorySignatureV1 ?: "")
                            )
                        )
                    }

                    return Next(
                        s2.copy(solvingReadyFactBundlesV1 = bundles),
                        effs
                    )
                }

                Next(s2, effs)
            }

            // ============================================================
            // PHASE 5: Tick2 continuation removed
            // - We no longer run "continuation tick2" at all.
            // - All assistant speech/UI updates come ONLY from Evt.ReplyReceived,
            //   which is produced by Eff.CallReplyGenerateV1.
            // ============================================================
            is Evt.PolicyContinuationReply -> {
                // Ignore any legacy events that might still be emitted by old runners.
                Next(s, emptyList())
            }

            is Evt.PolicyContinuationFailed -> {
                val pendingTick2 = s.pendingTick2
                val finalText = pendingTick2?.fallbackText ?: SURVIVAL_REPLY
                val listenAfter = pendingTick2?.listenAfter ?: true

                val detourStateAfterFailure =
                    if (s.pending is Pending.UserAgendaBridge && s.detourState != null) {
                        s.detourState.copy(
                            answerState = DetourAnswerStateV1.FAILED_AWAITING_RECOVERY,
                            answerFailureReason = "reply_generation_failed",
                            failedTurnSeq = s.turnSeq
                        )
                    } else {
                        s.detourState
                    }

                val detourHistoryAfterFailure =
                    if (s.pending is Pending.UserAgendaBridge) {
                        appendDetourTurnHistoryV1(
                            history = s.detourTurnHistoryV1,
                            record = detourTurnRecordFromStateV1(
                                detourState = detourStateAfterFailure,
                                turnSeq = s.turnSeq
                            )
                        )
                    } else {
                        s.detourTurnHistoryV1
                    }

                val userAgendaAfterFailure =
                    if (s.pending is Pending.UserAgendaBridge) {
                        pruneNonPersistentUserAgendaItemsV1(s.userAgendaQueue)
                    } else {
                        s.userAgendaQueue
                    }

                runCatching {
                    ConversationTelemetry.emitKv(
                        "TICK2_FAILED_FALLBACK_USED",
                        "turn_seq" to s.turnSeq,
                        "mode" to s.mode.name
                    )
                }

                if (s.pending is Pending.UserAgendaBridge && detourStateAfterFailure != null) {
                    val checkpointSummaryV1 =
                        routeCheckpointSummaryV1(s.routeCheckpointV1 ?: deriveRouteCheckpointV1(s))

                    runCatching {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "DETOUR_ANSWER_STATE_V1",
                            data = mapOf(
                                "turn_id" to s.turnSeq,
                                "state" to detourStateAfterFailure.answerState.name,
                                "reason" to (detourStateAfterFailure.answerFailureReason ?: "null"),
                                "question_class" to (detourStateAfterFailure.questionClass?.name ?: "null"),
                                "anchor_step_id" to (detourStateAfterFailure.anchorStepId ?: "null"),
                                "anchor_stage" to (detourStateAfterFailure.anchorStage?.name ?: "null")
                            )
                        )
                    }

                    runCatching {
                        com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                            tag = "DETOUR_PAUSED_ROUTE_PRESERVED_V1",
                            data = mapOf(
                                "turn_id" to s.turnSeq,
                                "reason" to "detour_answer_failed_checkpoint_preserved",
                                "detour_answer_state_v1" to detourStateAfterFailure.answerState.name,
                                "checkpoint_summary_v1" to checkpointSummaryV1
                            )
                        )
                    }
                }

                // ✅ MODEL_CALL_END for tick2 error
                runCatching {
                    emitModelCallEnd(
                        ctx = e.ctx,
                        status = "error",
                        errorCode = null,
                        errorMsg = null
                    )
                }

                val sAfterFailure = s.copy(
                    lastAssistantText = finalText,
                    pendingTick2 = null,
                    userAgendaQueue = userAgendaAfterFailure,
                    detourTurnHistoryV1 = detourHistoryAfterFailure,
                    detourState = detourStateAfterFailure
                )

                runCatching {
                    emitDetourIsolationInvariantV1(
                        s = sAfterFailure,
                        stage = "POST_DETOUR_REPLY_FAILURE"
                    )
                }

                Next(
                    sAfterFailure,
                    listOf(
                        Eff.UpdateUiMessage(finalText),
                        Eff.Speak(finalText, listenAfter = listenAfter)
                    )
                )
            }

            is Evt.AsrError -> {
                Next(s, listOf(Eff.RequestListen("asr_error_${e.code}_${e.name}")))
            }

            is Evt.TtsStarted -> Next(s, emptyList())
            is Evt.TtsFinished -> Next(s, emptyList())

            Evt.CancelTts -> {
                Next(s, listOf(Eff.StopAsr("cancel_tts_evt")))
            }


            is Evt.DetourSolverQuerySucceeded -> {
                val ds = s.detourState
                if (ds == null) return Next(s, emptyList())
                if (ds.pendingSolverQueryId != e.queryId) return Next(s, emptyList())

                val solverBundles = buildSolverBackedDetourBundlesFromResultV1(
                    op = e.op,
                    resultJson = e.resultJson
                )

                val nativeDetourNarrativeContext =
                    buildNativeDetourNarrativeContextFromFactsV1(
                        turnSeq = s.turnSeq,
                        factBundles = solverBundles
                    )

                val nativeDetourNarrativeBundle =
                    buildNativeDetourNarrativeFactBundleV1(nativeDetourNarrativeContext)

                val solverBundlesFinal =
                    if (nativeDetourNarrativeBundle != null) {
                        solverBundles + nativeDetourNarrativeBundle
                    } else {
                        solverBundles
                    }

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "DETOUR_SOLVER_QUERY_SUCCEEDED_V1",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "phase" to demandRoutingPhaseV1(s).name,
                            "query_id" to e.queryId,
                            "op" to e.op,
                            "reason" to e.reason,
                            "question_class" to (ds.questionClass?.name ?: "null"),
                            "bundle_types" to solverBundlesFinal.joinToString(",") { it.type.name },
                            "bundle_count" to solverBundlesFinal.size,
                            "result_len" to e.resultJson.length,
                            "native_detour_narrative_built" to (nativeDetourNarrativeContext != null),
                            "native_detour_archetype" to (nativeDetourNarrativeContext?.archetype?.name ?: "null")
                        )
                    )
                }

                val dsClearedBase = ds.copy(
                    pendingSolverQueryId = null,
                    pendingSolverQueryOp = null
                )

                val sNative = s.copy(
                    detourState = dsClearedBase,
                    detourNarrativeContextV1 = nativeDetourNarrativeContext
                )

                val detourFramesApplied =
                    if (dsClearedBase.isActive) {
                        chooseDetourOverlayFrameIdsV1(
                            state = sNative,
                            nativeCtx = nativeDetourNarrativeContext,
                            restoredCheckpointFrameIds = dsClearedBase.pausedStoryAppliedFrameIds
                        )
                    } else {
                        emptyList()
                    }

                val sCleared = applyDetourOverlayOverrideToStateV1(
                    sNative.copy(
                        detourState = dsClearedBase.copy(
                            detourAppliedFrameIds = detourFramesApplied
                        )
                    )
                )

                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "DETOUR_OVERLAY_CONTEXT_APPLIED_V1",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "question_class" to (ds.questionClass?.name ?: "null"),
                            "native_detour_archetype" to (nativeDetourNarrativeContext?.archetype?.name ?: "null"),
                            "detour_story_kind" to (detourOverlayStoryKindV1(nativeDetourNarrativeContext) ?: "null"),
                            "overlay_mode" to (nativeDetourNarrativeContext?.overlayPolicy?.overlayMode?.name ?: "null"),
                            "handover_mode" to (nativeDetourNarrativeContext?.handbackPolicy?.handoverMode?.name ?: "null"),
                            "primary_focus_cells" to (nativeDetourNarrativeContext?.overlayPolicy?.primaryFocusCells?.joinToString(",") ?: ""),
                            "secondary_focus_cells" to (nativeDetourNarrativeContext?.overlayPolicy?.secondaryFocusCells?.joinToString(",") ?: ""),
                            "primary_focus_houses" to (nativeDetourNarrativeContext?.overlayPolicy?.primaryFocusHouses?.joinToString(",") ?: ""),
                            "applied_frame_ids" to detourFramesApplied.joinToString(","),
                            "restored_checkpoint_frame_ids" to dsClearedBase.pausedStoryAppliedFrameIds.joinToString(","),
                            "current_overlay_frame_ids_before_apply" to currentAppliedOverlayFrameIdsOrNull(s).orEmpty().joinToString(",")
                        )
                    )
                }

                val user = s.lastUserText.orEmpty()
                return buildDetourSolverFollowUpNextV1(
                    sBefore = sCleared,
                    userText = user,
                    reason = "detour_solver_query_ready",
                    factBundles = solverBundlesFinal
                )
            }

            is Evt.DetourSolverQueryFailed -> {
                val ds = s.detourState
                if (ds == null) return Next(s, emptyList())
                if (ds.pendingSolverQueryId != e.queryId) return Next(s, emptyList())


                runCatching {
                    com.contextionary.sudoku.telemetry.ConversationTelemetry.emitPolicyTrace(
                        tag = "DETOUR_SOLVER_QUERY_FAILED_V1",
                        data = mapOf(
                            "turn_id" to s.turnSeq,
                            "query_id" to e.queryId,
                            "op" to e.op,
                            "reason" to e.reason,
                            "question_class" to (ds.questionClass?.name ?: "null"),
                            "error" to e.error
                        )
                    )
                }




                val sCleared = s.copy(
                    detourState = ds.copy(
                        pendingSolverQueryId = null,
                        pendingSolverQueryOp = null
                    ),
                    detourNarrativeContextV1 = null
                )

                val user = s.lastUserText.orEmpty()
                return buildDetourSolverFollowUpNextV1(
                    sBefore = sCleared,
                    userText = user,
                    reason = "detour_solver_query_failed_fallback",
                    factBundles = emptyList()
                )
            }


            is Evt.CellTapped -> {
                if (s.mode != SudoMode.GRID_SESSION) return Next(s, emptyList())

                val idx = e.cellIndex.coerceIn(0, 80)

                val s1 = s.copy(
                    pending = Pending.AskCellValue(cellIndex = idx, prompt = ""),
                    repairAttempt = 0,
                    turnSeq = s.turnSeq + 1
                )

                val header = buildStateHeader(s1)

                val (s2, eff) = callPolicyWithTrace(
                    traceState = s1,
                    userText = "[EVENT] cell_tapped idx=$idx",
                    stateHeader = header,
                    mode = s1.mode,
                    reason = "cell_tapped",
                    turnId = s1.turnSeq
                )

                Next(s2, listOf(eff))
            }



            is Evt.DigitPicked -> {
                if (s.mode != SudoMode.GRID_SESSION) return Next(s, emptyList())

                val idx = e.cellIndex.coerceIn(0, 80)
                val d = e.digit.coerceIn(0, 9)

                val s1 = s.copy(
                    pending = null,
                    repairAttempt = 0,
                    turnSeq = s.turnSeq + 1
                )

                val header = buildStateHeader(s1)
                val toolCallId = "tc:${s1.turnSeq}:0:0:local:digit_picked"

                val (s2, eff) = callPolicyWithTrace(
                    traceState = s1,
                    userText = "[EVENT] digit_picked idx=$idx digit=$d",
                    stateHeader = header,
                    mode = s1.mode,
                    reason = "digit_picked",
                    turnId = s1.turnSeq
                )

                Next(
                    s2,
                    listOf(
                        Eff.ApplyCellEdit(
                            toolCallId = toolCallId,
                            cellIndex = idx,
                            digit = d,
                            source = "digit_picked"
                        ),
                        eff
                    )
                )
            }

            is Evt.AsrFinal -> {
                val text = e.text.trim()
                if (text.isBlank()) {
                    return Next(s, listOf(Eff.RequestListen("asr_final_blank")))
                }

                val s1 = s.copy(
                    lastUserText = text,
                    repairAttempt = 0,
                    turnSeq = s.turnSeq + 1
                )

                // Phase 1 invariant:
                // - Do NOT parse raw user text in Maps/App-brain.
                // - Do NOT call handlePendingB (pending is resolved via Tick1 intents in planFromIntentEnvelopeV1).
                // - Any "revalidate / return to confirming" must be requested via Tick1 intent REQUEST_REVALIDATE.

                val header = buildStateHeader(s1)

                val (s2, eff) = callPolicyWithTrace(
                    traceState = s1,
                    userText = text,
                    stateHeader = header,
                    mode = s1.mode,
                    reason = if (s1.mode == SudoMode.GRID_SESSION) "user_turn_grid_session" else "user_turn_free_talk",
                    turnId = s1.turnSeq
                )

                Next(s2, listOf(eff))
            }

            // Phase 6: legacy toolplan path retired (tool-schema planning removed).
// If anything still emits PolicyTools, ignore it (or keep telemetry here if you want).
            is Evt.PolicyTools -> {
                runCatching {
                    ConversationTelemetry.emitKv(
                        "PHASE6_IGNORED_LEGACY_POLICYTOOLS_EVENT",
                        "turn_seq" to s.turnSeq,
                        "mode" to s.mode.name,
                        "phase" to s.phase.name
                    )
                }
                Next(s, emptyList())
            }

            else -> Next(s, emptyList())
        }
    }


    private fun buildEngineStepSummary(
        solveStepJson: String?,
        coachPlan: com.contextionary.sudoku.conductor.solving.CoachPlan?
    ): String? {
        // Prefer typed plan if it exposes anything useful (keep this deterministic + short).
        // We don’t know your exact CoachPlan fields, so we use reflection-safe access patterns.
        // If you DO have explicit fields like technique/title/summary, replace this with direct reads.

        fun clean(s: String): String =
            s.replace("\r\n", "\n").replace('\r', '\n')
                .lines()
                .map { it.trim() }
                .filter { it.isNotBlank() }
                .take(3)
                .joinToString("\n")
                .take(420)

        // 1) Try common CoachPlan fields if they exist (edit to match your real schema)
        runCatching {
            val cls = coachPlan?.javaClass ?: return@runCatching
            val candidates = listOf("summary", "title", "technique", "headline", "oneLiner")
            for (name in candidates) {
                val f = runCatching { cls.getDeclaredField(name).apply { isAccessible = true } }.getOrNull()
                val v = f?.get(coachPlan) as? String
                if (!v.isNullOrBlank()) return clean(v)
            }
        }

        // 2) Fallback: parse solveStepJson and extract a couple of common keys
        if (solveStepJson.isNullOrBlank()) return null

        return runCatching {
            val obj = org.json.JSONObject(solveStepJson)

            fun pick(vararg keys: String): String? {
                for (k in keys) {
                    val v = obj.optString(k, "").trim()
                    if (v.isNotBlank()) return v
                }
                return null
            }

            // Typical solver outputs often have something like technique/name/summary/action
            val a = pick("summary", "headline", "title", "technique", "rule", "strategy")
            val b = pick("action", "move", "instruction", "what_to_do", "explanation_short")

            val combined = when {
                !a.isNullOrBlank() && !b.isNullOrBlank() -> "$a\n$b"
                !a.isNullOrBlank() -> a
                !b.isNullOrBlank() -> b
                else -> null
            }

            combined?.let(::clean)
        }.getOrNull()
    }





    // ------------------------------------------------------------
    // Phase 4 — Technique handover (North Star)
    // ------------------------------------------------------------
    private data class TechniqueMetaV1(
        val techniqueId: String? = null,
        val family: String? = null,
        val realName: String? = null,
        val appName: String? = null
    )

    private fun extractTechniqueMetaFromStepObjV1(stepObj: org.json.JSONObject?): TechniqueMetaV1 {
        if (stepObj == null) return TechniqueMetaV1()
        val t = stepObj.optJSONObject("technique") ?: return TechniqueMetaV1()
        // normalize a bit
        val id = t.optString("technique_id", t.optString("id", "")).takeIf { it.isNotBlank() }
        val fam = t.optString("family", "").takeIf { it.isNotBlank() }
        val real = t.optString("real_name", t.optString("realName", "")).takeIf { it.isNotBlank() }
        val app = t.optString("app_name", t.optString("appName", "")).takeIf { it.isNotBlank() }
        return TechniqueMetaV1(techniqueId = id, family = fam, realName = real, appName = app)
    }

    private fun extractTechniqueMetaFromStepJsonV1(stepJson: String?): TechniqueMetaV1 {
        if (stepJson.isNullOrBlank()) return TechniqueMetaV1()
        val envObj = safeJsonObjectFromString(stepJson, tag = "tech_meta_env")
        val stepObj = runCatching { envObj.optJSONObject("step") ?: envObj }.getOrNull() ?: envObj
        return extractTechniqueMetaFromStepObjV1(stepObj)
    }


    private fun buildSolvingStepPacketBundlesV1(
        stepId: String,
        technique: String,
        techniqueInfo: org.json.JSONObject,
        targetCell: String?,
        targetDigit: Int?,
        techniqueFindingsPayload: org.json.JSONObject,
        nextMovePayload: org.json.JSONObject,
        candidatesSnapshotPayload: org.json.JSONObject,
        overlayFramesPayload: org.json.JSONObject,
        teachingCardPayload: org.json.JSONObject,

        // Phase 2: frozen contracts payloads
        solvingStepPacketV1Payload: org.json.JSONObject,
        teachingCardV1Payload: org.json.JSONObject,

        gridHash12Before: String? = null,
        gridHash12After: String? = null
    ): List<FactBundleV1> {

        val out = mutableListOf<FactBundleV1>()

        // 1) Core bundles (these are the “friends”)
        out += FactBundleV1(FactBundleV1.Type.NEXT_MOVE_RECOMMENDATION, nextMovePayload)
        out += FactBundleV1(FactBundleV1.Type.TECHNIQUE_FINDINGS, techniqueFindingsPayload)
        out += FactBundleV1(FactBundleV1.Type.CANDIDATES_SNAPSHOT, candidatesSnapshotPayload)
        out += FactBundleV1(FactBundleV1.Type.OVERLAY_FRAMES, overlayFramesPayload)
        out += FactBundleV1(FactBundleV1.Type.TEACHING_CARD, teachingCardPayload)

        // 2) Top-level “packet” (table-of-contents + stable metadata)
        out += FactBundleV1(
            type = FactBundleV1.Type.SOLVING_STEP_PACKET,
            payload = org.json.JSONObject().apply {
                put("step_id", stepId)
                put("technique", technique) // legacy string
                put("technique_info", techniqueInfo) // ✅ rich object for Tick2
                put("target_cell", targetCell ?: org.json.JSONObject.NULL)
                put("target_digit", targetDigit ?: org.json.JSONObject.NULL)
                put("grid_hash12_before", gridHash12Before ?: org.json.JSONObject.NULL)
                put("grid_hash12_after", gridHash12After ?: org.json.JSONObject.NULL)
                put(
                    "bundles",
                    org.json.JSONArray().apply {
                        put("NEXT_MOVE_RECOMMENDATION")
                        put("TECHNIQUE_FINDINGS")
                        put("CANDIDATES_SNAPSHOT")
                        put("OVERLAY_FRAMES")
                        put("TEACHING_CARD")
                    }
                )
                put("note", "Computed deterministically when step becomes READY; Tick2 must not recompute.")
            }
        )


        // ------------------------------------------------------------
// Phase 2: Frozen Roadmap v1 bundles (preferred by Tick2)
// ------------------------------------------------------------
        out += FactBundleV1(FactBundleV1.Type.TEACHING_CARD_V1, teachingCardV1Payload)
        out += FactBundleV1(FactBundleV1.Type.SOLVING_STEP_PACKET_V1, solvingStepPacketV1Payload)

        return out
    }


    // ------------------------------------------------------------
// Phase 4 — Narrative atoms: deterministic cell → atom mapping (zoom)
// ------------------------------------------------------------

    private fun narrativeAtomsArrayFromState(s: SudoState): org.json.JSONArray? {
        val stepPacket = s.solvingReadyFactBundlesV1
            .firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
            ?.payload

        val evidence = stepPacket?.optJSONObject("evidence") ?: return null
        val atomsV1 = evidence.optJSONObject("narrative_atoms_v1") ?: return null
        return atomsV1.optJSONArray("atoms")
    }


    /**
     * ✅ Phase 1: Atom-native CTA authority.
     *
     * Read the current atom's user_prompt.code from the frozen SOLVING_STEP_PACKET_V1.
     * Returns null if unavailable.
     */
    private fun atomPromptCodeFromState(s: SudoState, atomIndex: Int): String? {
        val atoms = narrativeAtomsArrayFromState(s) ?: return null
        val a = atoms.optJSONObject(atomIndex) ?: return null
        val code = a.optJSONObject("user_prompt")?.optString("code")?.trim()
        return code?.takeIf { it.isNotBlank() }
    }

    /**
     * Find the first atom index that references the given cellIndex in any meaningful role:
     * - focus.target_cell
     * - claim.args.cell (peer cell)
     * - witnesses[].because.witness_cell
     * - witnesses[].because.explains_peer
     *
     * Returns null if not found.
     */
    private fun findAtomIndexForCell(s: SudoState, cellIndex: Int): Int? {
        val atoms = narrativeAtomsArrayFromState(s) ?: return null
        for (i in 0 until atoms.length()) {
            val a = atoms.optJSONObject(i) ?: continue

            fun matchesCell(o: org.json.JSONObject?): Boolean {
                val idx = o?.optInt("cellIndex", -1) ?: -1
                return idx == cellIndex
            }

            // focus.target_cell
            val focus = a.optJSONObject("focus")
            if (matchesCell(focus?.optJSONObject("target_cell"))) return i

            // claim.args.cell
            val claimArgs = a.optJSONObject("claim")?.optJSONObject("args")
            if (matchesCell(claimArgs?.optJSONObject("cell"))) return i

            // witnesses
            val w = a.optJSONArray("witnesses") ?: org.json.JSONArray()
            for (j in 0 until w.length()) {
                val wj = w.optJSONObject(j) ?: continue
                val because = wj.optJSONObject("because") ?: continue
                val witnessCell = because.optJSONObject("witness_cell")
                val explainsPeer = because.optJSONObject("explains_peer")
                if (matchesCell(witnessCell)) return i
                if (matchesCell(explainsPeer)) return i
            }
        }
        return null
    }



    // Small helper: always return a JSONObject (even if parsing fails)
    private fun safeJsonObjectFromString(raw: String?, tag: String): org.json.JSONObject {
        if (raw.isNullOrBlank()) {
            return org.json.JSONObject().put("tag", tag).put("raw", org.json.JSONObject.NULL)
        }
        return runCatching { org.json.JSONObject(raw) }
            .getOrElse { org.json.JSONObject().put("tag", tag).put("raw", raw) }
    }




    private fun buildSolveOverlayFrameJsonV1(
        s: SudoState,
        frameId: String,
        style: String,
        reason: String
    ): String {
        val obj = org.json.JSONObject()
            .put("v", 1)
            .put(
                "meta",
                org.json.JSONObject()
                    .put("reason", reason)
                    .put("style", style)
                    .put("frame_id", frameId)
                    .put("grid_hash12", (s.coachPlanGridHash12 ?: s.solveStepGridHash12 ?: "").take(12))
            )

        // Focus cell: prefer CoachPlan focus if present, else state focus
        val cp = s.coachPlan
        val focusIdx = (cp?.focusCellIndex ?: s.focusCellIndex).takeIf { it in 0..80 }
        obj.put("focus", org.json.JSONObject().put("cellIndex", focusIdx ?: org.json.JSONObject.NULL))



        // ✅ Phase 1: Narrative Atom frames (ov:atom:<index>) are generated deterministically here.
        if (frameId.startsWith("ov:atom:", ignoreCase = true)) {
            val atomIndex = frameId.substringAfterLast(":").toIntOrNull()
            val stepJson0 = s.solveStepJson

            if (atomIndex == null || stepJson0.isNullOrBlank()) {
                obj.put("highlights", org.json.JSONArray())
                return obj.toString()
            }

            return runCatching {
                val env = org.json.JSONObject(stepJson0)
                val stepObj = env.optJSONObject("step") ?: env
                val grid81Now = s.grid?.llm?.let { grid81FromLLM(it) }

                val packet = com.contextionary.sudoku.conductor.solving.NarrativeAtomGeneratorV1
                    .buildNarrativeAtomsV1(stepObj, grid81Now)

                val atoms = packet.optJSONArray("atoms") ?: org.json.JSONArray()
                val atom = atoms.optJSONObject(atomIndex)

                val hi = org.json.JSONArray()

                fun putHouse(type: String, index1to9: Int, role: String) {
                    hi.put(
                        org.json.JSONObject().apply {
                            put("kind", "house")
                            put("role", role)
                            put("house", org.json.JSONObject().apply {
                                put("type", type)
                                put("index1to9", index1to9)
                            })
                        }
                    )
                }

                fun putCell(
                    cellIndex: Int,
                    role: String,
                    digit: Int? = null,
                    candidates: List<Int>? = null
                ) {
                    hi.put(
                        org.json.JSONObject().apply {
                            put("kind", "cell")
                            put("cellIndex", cellIndex)
                            put("role", role)
                            if (digit != null) put("digit", digit)
                            if (!candidates.isNullOrEmpty()) {
                                put("candidates", org.json.JSONArray().apply {
                                    candidates
                                        .filter { it in 1..9 }
                                        .distinct()
                                        .sorted()
                                        .forEach { put(it) }
                                })
                            }
                        }
                    )
                }

                // Always show focus + primary house if present
                val focus = atom?.optJSONObject("focus")
                val targetCell = focus?.optJSONObject("target_cell")
                val focusIdx = targetCell?.optInt("cellIndex", -1) ?: -1
                if (focusIdx in 0..80) putCell(focusIdx, "focus")

                val primaryHouse = focus?.optJSONObject("primary_house")
                val hType = primaryHouse?.optString("type").orEmpty()
                val hIdx = primaryHouse?.optInt("index1to9", -1) ?: -1
                if (hType.isNotBlank() && hIdx in 1..9) putHouse(hType, hIdx, "primary_house")

                val beatKind = atom?.optString("beat_kind").orEmpty()

                val claim = atom?.optJSONObject("claim") ?: org.json.JSONObject()
                val claimCode = claim.optString("code").orEmpty()

                // Phase 9 North Star:
                // Advanced atom-0 intro overlays must be rendered from the atom's
                // own intro_overlay_contract, not from family-specific hardcoding.
                if (atomIndex == 0) {
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val advancedSetupPayload =
                        args.optJSONObject("advanced_setup_payload") ?: org.json.JSONObject()
                    val introOverlayContract =
                        advancedSetupPayload.optJSONObject("intro_overlay_contract")
                    val setupRole =
                        advancedSetupPayload.optString("setup_role")
                            .ifBlank { args.optString("setup_role") }

                    val isAdvancedIntroSetup =
                        setupRole == "advanced_trigger_setup" &&
                                introOverlayContract != null &&
                                introOverlayContract.optString("intent")
                                    .ifBlank { "SHOW_SPOTLIGHT" } == "SHOW_SPOTLIGHT"

                    if (isAdvancedIntroSetup) {
                        val hiSetup = org.json.JSONArray()

                        fun putHouseSetup(type: String, index1to9: Int, role: String) {
                            if (type.isBlank() || index1to9 !in 1..9) return
                            hiSetup.put(
                                org.json.JSONObject().apply {
                                    put("kind", "house")
                                    put("role", role)
                                    put("house", org.json.JSONObject().apply {
                                        put("type", type)
                                        put("index1to9", index1to9)
                                    })
                                }
                            )
                        }

                        fun putCellSetup(
                            cellIndex: Int,
                            role: String,
                            digit: Int? = null,
                            candidates: List<Int>? = null
                        ) {
                            if (cellIndex !in 0..80) return
                            hiSetup.put(
                                org.json.JSONObject().apply {
                                    put("kind", "cell")
                                    put("cellIndex", cellIndex)
                                    put("role", role)
                                    if (digit != null) put("digit", digit)
                                    if (!candidates.isNullOrEmpty()) {
                                        put("candidates", org.json.JSONArray().apply {
                                            candidates
                                                .filter { it in 1..9 }
                                                .distinct()
                                                .sorted()
                                                .forEach { put(it) }
                                        })
                                    }
                                }
                            )
                        }

                        fun toCellIndex(cellObj: org.json.JSONObject?): Int {
                            if (cellObj == null) return -1
                            val explicit = cellObj.optInt("cellIndex", -1)
                            if (explicit in 0..80) return explicit
                            val r = cellObj.optInt("r", -1)
                            val c = cellObj.optInt("c", -1)
                            return if (r in 1..9 && c in 1..9) ((r - 1) * 9 + (c - 1)) else -1
                        }

                        fun digitsFrom(arr: org.json.JSONArray?): List<Int> =
                            buildList {
                                if (arr != null) {
                                    for (i in 0 until arr.length()) {
                                        val d = arr.optInt(i, -1)
                                        if (d in 1..9) add(d)
                                    }
                                }
                            }.distinct().sorted()

                        fun firstValidDigitFrom(vararg values: Int?): Int? =
                            values.firstOrNull { it != null && it in 1..9 }

                        val triggerPattern =
                            advancedSetupPayload.optJSONObject("trigger_pattern")
                                ?: args.optJSONObject("trigger_pattern")
                                ?: org.json.JSONObject()

                        val triggerExplanation =
                            advancedSetupPayload.optJSONObject("trigger_explanation")
                                ?: args.optJSONObject("trigger_explanation")
                                ?: org.json.JSONObject()

                        val triggerBridge =
                            advancedSetupPayload.optJSONObject("trigger_bridge")
                                ?: args.optJSONObject("trigger_bridge")
                                ?: org.json.JSONObject()

                        val overlayFocusDigit =
                            firstValidDigitFrom(
                                advancedSetupPayload.optJSONObject("focus")
                                    ?.optInt("digit", -1)
                                    ?.takeIf { it in 1..9 },
                                args.optJSONObject("focus")
                                    ?.optInt("digit", -1)
                                    ?.takeIf { it in 1..9 },
                                triggerPattern.optInt("digit", -1).takeIf { it in 1..9 },
                                triggerExplanation.optInt("digit", -1).takeIf { it in 1..9 }
                            )

                        if (introOverlayContract.optBoolean("show_target_focus", false) && focusIdx in 0..80) {
                            putCellSetup(focusIdx, "focus")
                        }

                        if (introOverlayContract.optBoolean("show_subset_house", false)) {
                            val subsetHouse = triggerPattern.optJSONObject("house")
                                ?: args.optJSONObject("house")
                            putHouseSetup(
                                subsetHouse?.optString("type").orEmpty(),
                                subsetHouse?.optInt("index1to9", -1) ?: -1,
                                "subset_house"
                            )
                        }

                        if (introOverlayContract.optBoolean("show_subset_cells", false) ||
                            introOverlayContract.optBoolean("show_subset_candidates", false)
                        ) {
                            val subsetCells =
                                triggerPattern.optJSONArray("subset_cells")
                                    ?: args.optJSONArray("subset_cells")
                                    ?: org.json.JSONArray()

                            val subsetCellCandidates =
                                triggerPattern.optJSONArray("subset_cell_candidates")
                                    ?: args.optJSONArray("subset_cell_candidates")
                                    ?: org.json.JSONArray()

                            val candidateMap = linkedMapOf<Int, List<Int>>()
                            for (i in 0 until subsetCellCandidates.length()) {
                                val row = subsetCellCandidates.optJSONObject(i) ?: continue
                                val cellObj = row.optJSONObject("cell") ?: continue
                                val idx = toCellIndex(cellObj)
                                if (idx !in 0..80) continue
                                val digits = digitsFrom(row.optJSONArray("digits"))
                                if (digits.isNotEmpty()) candidateMap[idx] = digits
                            }

                            for (i in 0 until subsetCells.length()) {
                                val idx = when (val raw = subsetCells.opt(i)) {
                                    is Int -> raw
                                    is org.json.JSONObject -> toCellIndex(raw)
                                    else -> -1
                                }
                                if (idx !in 0..80) continue

                                val cands = candidateMap[idx].orEmpty()
                                when {
                                    introOverlayContract.optBoolean("show_subset_candidates", false) && cands.isNotEmpty() ->
                                        putCellSetup(idx, "subset_candidates", candidates = cands)

                                    introOverlayContract.optBoolean("show_subset_cells", false) ->
                                        putCellSetup(idx, "subset_member")
                                }
                            }
                        }

                        if (introOverlayContract.optBoolean("show_source_house", false)) {
                            val sourceHouse = triggerPattern.optJSONObject("source_house")
                            putHouseSetup(
                                sourceHouse?.optString("type").orEmpty(),
                                sourceHouse?.optInt("index1to9", -1) ?: -1,
                                "source_house"
                            )
                        }

                        if (
                            introOverlayContract.optBoolean("show_cross_house", false) ||
                            introOverlayContract.optBoolean("show_target_house", false)
                        ) {
                            val crossHouse =
                                triggerPattern.optJSONObject("cross_house")
                                    ?: triggerPattern.optJSONObject("target_house")
                            putHouseSetup(
                                crossHouse?.optString("type").orEmpty(),
                                crossHouse?.optInt("index1to9", -1) ?: -1,
                                "cross_house"
                            )
                        }

                        if (introOverlayContract.optBoolean("show_box_house", false)) {
                            val boxHouse = triggerPattern.optJSONObject("box_house")
                            putHouseSetup(
                                boxHouse?.optString("type").orEmpty(),
                                boxHouse?.optInt("index1to9", -1) ?: -1,
                                "box_house"
                            )
                        }

                        if (introOverlayContract.optBoolean("show_line_house", false)) {
                            val lineHouse = triggerPattern.optJSONObject("line_house")
                            putHouseSetup(
                                lineHouse?.optString("type").orEmpty(),
                                lineHouse?.optInt("index1to9", -1) ?: -1,
                                "line_house"
                            )
                        }

                        if (introOverlayContract.optBoolean("show_overlap_cells", false)) {
                            val overlapCells =
                                triggerPattern.optJSONArray("overlap_cells")
                                    ?: triggerPattern.optJSONArray("locked_cells")
                                    ?: org.json.JSONArray()

                            for (i in 0 until overlapCells.length()) {
                                val cellObj = overlapCells.optJSONObject(i) ?: continue
                                val idx = toCellIndex(cellObj)
                                if (idx in 0..80) putCellSetup(idx, "overlap_cell")
                            }
                        }

                        if (introOverlayContract.optBoolean("show_pattern_cells", false)) {
                            val patternCells =
                                triggerPattern.optJSONArray("pattern_cells")
                                    ?: triggerPattern.optJSONArray("overlap_cells")
                                    ?: triggerPattern.optJSONArray("locked_cells")
                                    ?: org.json.JSONArray()

                            for (i in 0 until patternCells.length()) {
                                val cellObj = patternCells.optJSONObject(i) ?: continue
                                val idx = toCellIndex(cellObj)
                                if (idx in 0..80) putCellSetup(idx, "pattern_cell")
                            }
                        }

                        if (introOverlayContract.optBoolean("show_confined_overlap_digits", false)) {
                            val overlapSurvivors =
                                triggerExplanation.optJSONArray("overlap_survivor_cells")
                                    ?: triggerExplanation.optJSONObject("source_confinement_proof")
                                        ?.optJSONArray("overlap_survivor_cells")
                                    ?: triggerPattern.optJSONArray("pattern_cells")
                                    ?: triggerPattern.optJSONArray("overlap_cells")
                                    ?: triggerPattern.optJSONArray("locked_cells")
                                    ?: org.json.JSONArray()

                            val confinedDigit =
                                firstValidDigitFrom(
                                    triggerPattern.optInt("digit", -1).takeIf { it in 1..9 },
                                    triggerExplanation.optInt("digit", -1).takeIf { it in 1..9 },
                                    overlayFocusDigit
                                )

                            if (confinedDigit != null) {
                                for (i in 0 until overlapSurvivors.length()) {
                                    val cellObj = overlapSurvivors.optJSONObject(i) ?: continue
                                    val idx = toCellIndex(cellObj)
                                    if (idx in 0..80) {
                                        putCellSetup(idx, "confined_digit", digit = confinedDigit)
                                    }
                                }
                            }
                        }

                        if (introOverlayContract.optBoolean("show_source_outside_overlap_cells", false)) {
                            val sourceOutsideCells =
                                triggerPattern.optJSONArray("source_outside_overlap_cells")
                                    ?: org.json.JSONArray()

                            for (i in 0 until sourceOutsideCells.length()) {
                                val cellObj = sourceOutsideCells.optJSONObject(i) ?: continue
                                val idx = toCellIndex(cellObj)
                                if (idx in 0..80) putCellSetup(idx, "audit_cell")
                            }
                        }

                        if (introOverlayContract.optBoolean("show_forbidden_cross_cells_preview", false)) {
                            val forbiddenCrossCells =
                                triggerBridge.optJSONArray("forbidden_elsewhere_cells")
                                    ?: triggerPattern.optJSONArray("forbidden_cross_cells")
                                    ?: org.json.JSONArray()

                            for (i in 0 until forbiddenCrossCells.length()) {
                                val cellObj = forbiddenCrossCells.optJSONObject(i) ?: continue
                                val idx = toCellIndex(cellObj)
                                if (idx in 0..80) putCellSetup(idx, "forbidden_preview")
                            }
                        }

                        if (introOverlayContract.optBoolean("show_sweep_cells", false)) {
                            val sweepCells =
                                triggerBridge.optJSONObject("sweep_relation")?.optJSONArray("sweep_cells")
                                    ?: triggerPattern.optJSONArray("sweep_cells")
                                    ?: triggerPattern.optJSONArray("affected_cells")
                                    ?: org.json.JSONArray()

                            for (i in 0 until sweepCells.length()) {
                                val cellObj = sweepCells.optJSONObject(i) ?: continue
                                val idx = toCellIndex(cellObj)
                                if (idx in 0..80) putCellSetup(idx, "sweep_cell")
                            }
                        }

                        if (introOverlayContract.optBoolean("show_source_outside_audit_witnesses", false)) {
                            val auditRows =
                                triggerExplanation.optJSONArray("source_house_outside_overlap_audit")
                                    ?: triggerExplanation.optJSONObject("source_confinement_proof")
                                        ?.optJSONArray("outside_audit_rows")
                                    ?: org.json.JSONArray()

                            val seenWitnessCells = linkedSetOf<Int>()
                            val seenHouses = linkedSetOf<String>()

                            for (i in 0 until auditRows.length()) {
                                val row = auditRows.optJSONObject(i) ?: continue
                                val digit = row.optInt("digit", -1).takeIf { it in 1..9 }

                                val witnessCell = row.optJSONObject("witness_cell")
                                val witnessIdx = toCellIndex(witnessCell)
                                if (witnessIdx in 0..80 && seenWitnessCells.add(witnessIdx)) {
                                    if (digit != null) {
                                        putCellSetup(witnessIdx, "audit_witness", digit = digit)
                                    } else {
                                        putCellSetup(witnessIdx, "audit_witness")
                                    }
                                }

                                val viaHouse =
                                    row.optJSONObject("house")
                                        ?: row.optJSONObject("via_house")
                                val houseType = viaHouse?.optString("type").orEmpty()
                                val houseIdx = viaHouse?.optInt("index1to9", -1) ?: -1
                                val houseKey = "$houseType:$houseIdx"
                                if (houseType.isNotBlank() && houseIdx in 1..9 && seenHouses.add(houseKey)) {
                                    putHouseSetup(houseType, houseIdx, "audit_house")
                                }
                            }
                        }

                        if (introOverlayContract.optBoolean("show_blocker_network", false)) {
                            val memberProofs =
                                triggerExplanation.optJSONArray("pattern_member_proofs")
                                    ?: triggerExplanation.optJSONArray("member_proofs")
                                    ?: org.json.JSONArray()

                            val seenWitnessCells = linkedSetOf<Int>()
                            val seenHouses = linkedSetOf<String>()

                            for (i in 0 until memberProofs.length()) {
                                val proof = memberProofs.optJSONObject(i) ?: continue
                                val witnessByDigit =
                                    proof.optJSONArray("witness_by_digit") ?: org.json.JSONArray()

                                for (j in 0 until witnessByDigit.length()) {
                                    val row = witnessByDigit.optJSONObject(j) ?: continue
                                    val digit = row.optInt("digit", -1).takeIf { it in 1..9 }

                                    val witnessCell = row.optJSONObject("witness_cell")
                                    val witnessIdx = toCellIndex(witnessCell)
                                    if (witnessIdx in 0..80 && seenWitnessCells.add(witnessIdx)) {
                                        if (digit != null) {
                                            putCellSetup(witnessIdx, "witness", digit = digit)
                                        } else {
                                            putCellSetup(witnessIdx, "witness")
                                        }
                                    }

                                    val viaHouse = row.optJSONObject("via_house")
                                    val houseType = viaHouse?.optString("type").orEmpty()
                                    val houseIdx = viaHouse?.optInt("index1to9", -1) ?: -1
                                    val houseKey = "$houseType:$houseIdx"
                                    if (houseType.isNotBlank() && houseIdx in 1..9 && seenHouses.add(houseKey)) {
                                        putHouseSetup(houseType, houseIdx, "secondary_house")
                                    }
                                }
                            }
                        }

                        obj.put("highlights", hiSetup)
                        obj.put(
                            "meta",
                            obj.optJSONObject("meta")
                                ?.put("beat_kind", beatKind)
                                ?.put("claim_code", claimCode)
                                ?.put("archetype", atom?.optString("archetype").orEmpty())
                                ?.put("setup_invariant_enforced", true)
                                ?.put(
                                    "setup_variant",
                                    introOverlayContract.optString("setup_variant").ifBlank {
                                        "advanced_pattern_tableau"
                                    }
                                )
                                ?.put(
                                    "intersection_setup_contract",
                                    introOverlayContract.optString("setup_variant")
                                        .takeIf { it.contains("intersection", ignoreCase = true) }
                                        ?: JSONObject.NULL
                                )
                                ?.put("setup_highlight_count", hiSetup.length())
                        )
                        return@runCatching obj.toString()
                    }

                    // Default setup invariant for non-advanced/non-contract steps.
                    obj.put("highlights", hi)
                    obj.put(
                        "meta",
                        obj.optJSONObject("meta")
                            ?.put("beat_kind", beatKind)
                            ?.put("claim_code", claimCode)
                            ?.put("archetype", atom?.optString("archetype").orEmpty())
                            ?.put("setup_invariant_enforced", true)
                            ?.put("setup_highlight_count", hi.length())
                    )
                    return@runCatching obj.toString()
                }

                if (beatKind == "WITNESS_ELIMINATION" && claimCode == "CELL_CANNOT_BE_DIGIT") {
                    // --- Singles witness beat (Phase 1) ---
                    val digit = claim.optJSONObject("args")?.optInt("digit", -1)?.takeIf { it in 1..9 }

                    // Peer cell
                    val peerCell = claim.optJSONObject("args")?.optJSONObject("cell")
                    val peerIdx = peerCell?.optInt("cellIndex", -1) ?: -1
                    if (peerIdx in 0..80) putCell(peerIdx, "peer")
                    if (peerIdx in 0..80 && digit != null) putCell(peerIdx, "eliminate_digit", digit)

                    // Witness cell + relation house highlight
                    val w0 = atom.optJSONArray("witnesses")?.optJSONObject(0)
                    val because = w0?.optJSONObject("because")
                    val wCell = because?.optJSONObject("witness_cell")
                    val wIdx = wCell?.optInt("cellIndex", -1) ?: -1
                    if (wIdx in 0..80) putCell(wIdx, "witness", digit)

                    val relation = because?.optString("relation").orEmpty()
                    if (peerIdx in 0..80) {
                        val pr = (peerIdx / 9) + 1
                        val pc = (peerIdx % 9) + 1
                        when (relation) {
                            "SAME_COL" -> putHouse("col", pc, "secondary_house")
                            "SAME_ROW" -> putHouse("row", pr, "secondary_house")
                            "SAME_BOX" -> {
                                val bi = (((pr - 1) / 3) * 3 + ((pc - 1) / 3) + 1)
                                putHouse("box", bi, "secondary_house")
                            }
                        }
                    }
                } else if (claimCode == "INTERSECTION_SOURCE_OUTSIDE_AUDIT") {
                    // --- Intersection setup atom 1: explicit source-house outside-overlap audit ---
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }

                    val sourceHouse = args.optJSONObject("source_house")
                    val crossHouse = args.optJSONObject("cross_house")
                    val overlapCells = args.optJSONArray("overlap_cells") ?: org.json.JSONArray()
                    val outsideAuditRows = args.optJSONArray("outside_audit_rows") ?: org.json.JSONArray()

                    if (sourceHouse != null) {
                        putHouse(
                            sourceHouse.optString("type"),
                            sourceHouse.optInt("index1to9", -1),
                            "source_house"
                        )
                    }
                    if (crossHouse != null) {
                        putHouse(
                            crossHouse.optString("type"),
                            crossHouse.optInt("index1to9", -1),
                            "cross_house"
                        )
                    }

                    fun auditCellIndex(raw: Any?): Int = when (raw) {
                        is Int -> raw
                        is org.json.JSONObject -> {
                            val explicit = raw.optInt("cellIndex", -1)
                            if (explicit in 0..80) explicit
                            else {
                                val r = raw.optInt("r", -1)
                                val c = raw.optInt("c", -1)
                                if (r in 1..9 && c in 1..9) ((r - 1) * 9 + (c - 1)) else -1
                            }
                        }
                        else -> -1
                    }

                    for (i in 0 until overlapCells.length()) {
                        val idx = auditCellIndex(overlapCells.opt(i))
                        if (idx in 0..80) {
                            putCell(idx, "overlap_cell")
                            if (digit != null) putCell(idx, "lock_digit", digit)
                        }
                    }

                    for (i in 0 until outsideAuditRows.length()) {
                        val row = outsideAuditRows.optJSONObject(i) ?: continue

                        val auditedCell = row.optJSONObject("cell")
                        val auditedIdx = auditedCell?.optInt("cellIndex", -1) ?: -1
                        if (auditedIdx in 0..80) {
                            putCell(auditedIdx, "audit_cell")
                            if (digit != null) putCell(auditedIdx, "eliminate_digit", digit)
                        }

                        val witnessCell = row.optJSONObject("witness_cell")
                        val witnessIdx = witnessCell?.optInt("cellIndex", -1) ?: -1
                        val rowDigit = row.optInt("digit", -1).takeIf { it in 1..9 } ?: digit
                        if (witnessIdx in 0..80) {
                            putCell(witnessIdx, "audit_witness", rowDigit)
                        }

                        val house = row.optJSONObject("house") ?: row.optJSONObject("via_house")
                        val houseType = house?.optString("type").orEmpty()
                        val houseIdx = house?.optInt("index1to9", -1) ?: -1
                        if (houseType.isNotBlank() && houseIdx in 1..9) {
                            putHouse(houseType, houseIdx, "audit_house")
                        }
                    }
                } else if (claimCode == "INTERSECTION_TERRITORIAL_CONTROL") {
                    // --- Intersection setup atom 2: territorial significance / permission change ---
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }

                    val sourceHouse = args.optJSONObject("source_house")
                    val crossHouse = args.optJSONObject("cross_house")
                    val overlapCells = args.optJSONArray("overlap_cells") ?: org.json.JSONArray()
                    val forbiddenCrossCells = args.optJSONArray("forbidden_cross_cells") ?: org.json.JSONArray()

                    if (sourceHouse != null) {
                        putHouse(
                            sourceHouse.optString("type"),
                            sourceHouse.optInt("index1to9", -1),
                            "source_house"
                        )
                    }
                    if (crossHouse != null) {
                        putHouse(
                            crossHouse.optString("type"),
                            crossHouse.optInt("index1to9", -1),
                            "cross_house"
                        )
                    }

                    fun territorialCellIndex(raw: Any?): Int = when (raw) {
                        is Int -> raw
                        is org.json.JSONObject -> {
                            val explicit = raw.optInt("cellIndex", -1)
                            if (explicit in 0..80) explicit
                            else {
                                val r = raw.optInt("r", -1)
                                val c = raw.optInt("c", -1)
                                if (r in 1..9 && c in 1..9) ((r - 1) * 9 + (c - 1)) else -1
                            }
                        }
                        else -> -1
                    }

                    for (i in 0 until overlapCells.length()) {
                        val idx = territorialCellIndex(overlapCells.opt(i))
                        if (idx in 0..80) {
                            putCell(idx, "overlap_cell")
                            if (digit != null) putCell(idx, "lock_digit", digit)
                        }
                    }

                    for (i in 0 until forbiddenCrossCells.length()) {
                        val idx = territorialCellIndex(forbiddenCrossCells.opt(i))
                        if (idx in 0..80) {
                            putCell(idx, "forbidden_cross_cell")
                            if (digit != null) putCell(idx, "eliminate_digit", digit)
                        }
                    }
                } else if (claimCode == "DIGIT_LOCKED_TO_LINE_IN_BOX") {
                    // --- Backward-compatible legacy intersection lock overlay ---
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }

                    val box = args.optJSONObject("box")
                    val line = args.optJSONObject("line")
                    val locked = args.optJSONArray("locked_cells") ?: org.json.JSONArray()

                    if (box != null) putHouse("box", box.optInt("index1to9", -1), "primary_house")
                    if (line != null) putHouse(line.optString("type"), line.optInt("index1to9", -1), "secondary_house")

                    for (i in 0 until locked.length()) {
                        val idx = locked.optInt(i, -1)
                        if (idx in 0..80) {
                            putCell(idx, "peer")
                            if (digit != null) putCell(idx, "lock_digit", digit)
                        }
                    }
                } else if (claimCode == "SWEEP_REMOVE_DIGIT_FROM_CELLS") {
                    // --- Intersections sweep: show eliminations on sweep cells, plus box+line context if present in witnesses ---
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }
                    val cells = args.optJSONArray("cells") ?: org.json.JSONArray()

                    for (i in 0 until cells.length()) {
                        val idx = cells.optInt(i, -1)
                        if (idx in 0..80) {
                            putCell(idx, "peer")
                            if (digit != null) putCell(idx, "eliminate_digit", digit)
                        }
                    }
                } else if (claimCode == "SUBSET_LOCKS_DIGITS") {
                    // --- Subset identify: show exact subset-cell candidate content in the subset cells ---
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val subsetCells = args.optJSONArray("subset_cells") ?: org.json.JSONArray()
                    val subsetCellCandidates = args.optJSONArray("subset_cell_candidates") ?: org.json.JSONArray()

                    // Build exact per-cell candidate map if present.
                    val candidateMap = linkedMapOf<Int, List<Int>>()
                    for (i in 0 until subsetCellCandidates.length()) {
                        val row = subsetCellCandidates.optJSONObject(i) ?: continue
                        val cellObj = row.optJSONObject("cell") ?: continue
                        val idx = cellObj.optInt("cellIndex", -1)
                        if (idx !in 0..80) continue

                        val digitsArr = row.optJSONArray("digits") ?: org.json.JSONArray()
                        val digits = buildList {
                            for (j in 0 until digitsArr.length()) {
                                val d = digitsArr.optInt(j, -1)
                                if (d in 1..9) add(d)
                            }
                        }.distinct().sorted()

                        if (digits.isNotEmpty()) {
                            candidateMap[idx] = digits
                        }
                    }

                    // Emit exactly one surviving highlight per subset cell.
                    for (i in 0 until subsetCells.length()) {
                        val idx = subsetCells.optInt(i, -1)
                        if (idx !in 0..80) continue

                        val cands = candidateMap[idx].orEmpty()
                        if (cands.isNotEmpty()) {
                            putCell(idx, "subset_candidates", candidates = cands)
                        } else {
                            // Defensive fallback: still show the subset member cell even if candidates are absent.
                            putCell(idx, "peer")
                        }
                    }
                } else if (claimCode == "SUBSET_SWEEP") {
                    // --- Subset sweep: eliminate locked digits from other house cells ---
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val sweepCells = args.optJSONArray("sweep_cells") ?: org.json.JSONArray()
                    val lockedDigits = args.optJSONArray("locked_digits") ?: org.json.JSONArray()

                    for (i in 0 until sweepCells.length()) {
                        val idx = sweepCells.optInt(i, -1)
                        if (idx in 0..80) putCell(idx, "peer")
                        for (j in 0 until lockedDigits.length()) {
                            val d = lockedDigits.optInt(j, -1)
                            if (idx in 0..80 && d in 1..9) putCell(idx, "eliminate_digit", d)
                        }
                    }

                } else if (claimCode == "SUBSET_TARGET_COLLAPSE") {
                    // --- Phase 5 North Star proof screen for subsets ---
                    // Keep the setup tableau visible, then add blocker witnesses and target collapse cues.
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()

                    val subsetHouse = args.optJSONObject("house")
                    val subsetCells = args.optJSONArray("subset_cells") ?: org.json.JSONArray()
                    val subsetCellCandidates = args.optJSONArray("subset_cell_candidates") ?: org.json.JSONArray()
                    val peerWitnessRows = args.optJSONArray("peer_witness_rows") ?: org.json.JSONArray()
                    val remainingCandidateDigits = args.optJSONArray("remaining_candidate_digits") ?: org.json.JSONArray()

                    // 1) Keep the subset tableau persistent.
                    val shType = subsetHouse?.optString("type").orEmpty()
                    val shIdx = subsetHouse?.optInt("index1to9", -1) ?: -1
                    if (shType.isNotBlank() && shIdx in 1..9) {
                        putHouse(shType, shIdx, "subset_house")
                    }

                    val candidateMap = linkedMapOf<Int, List<Int>>()
                    for (i in 0 until subsetCellCandidates.length()) {
                        val row = subsetCellCandidates.optJSONObject(i) ?: continue
                        val cellObj = row.optJSONObject("cell") ?: continue
                        val idx = cellObj.optInt("cellIndex", -1)
                        if (idx !in 0..80) continue

                        val digitsArr = row.optJSONArray("digits") ?: org.json.JSONArray()
                        val digits = buildList {
                            for (j in 0 until digitsArr.length()) {
                                val d = digitsArr.optInt(j, -1)
                                if (d in 1..9) add(d)
                            }
                        }.distinct().sorted()

                        if (digits.isNotEmpty()) {
                            candidateMap[idx] = digits
                        }
                    }

                    for (i in 0 until subsetCells.length()) {
                        val idx = subsetCells.optInt(i, -1)
                        if (idx !in 0..80) continue
                        val cands = candidateMap[idx].orEmpty()
                        if (cands.isNotEmpty()) {
                            putCell(idx, "subset_candidates", candidates = cands)
                        } else {
                            putCell(idx, "subset_member")
                        }
                    }

                    // 2) Add blocker witnesses + relation houses.
                    for (i in 0 until peerWitnessRows.length()) {
                        val row = peerWitnessRows.optJSONObject(i) ?: continue
                        val digit = row.optInt("digit", -1).takeIf { it in 1..9 }
                        val witnessCell = row.optJSONObject("witness_cell")
                        val witnessIdx = witnessCell?.optInt("cellIndex", -1) ?: -1
                        if (witnessIdx in 0..80) {
                            putCell(witnessIdx, "witness", digit)
                        }

                        val relationHouse = row.optJSONObject("relation_house")
                        val rhType = relationHouse?.optString("type").orEmpty()
                        val rhIdx = relationHouse?.optInt("index1to9", -1) ?: -1
                        if (rhType.isNotBlank() && rhIdx in 1..9) {
                            putHouse(rhType, rhIdx, "secondary_house")
                        }
                    }

                    // 3) Show the target collapse cue as remaining candidate(s), but do not commit the digit yet.
                    if (focusIdx in 0..80) {
                        val remaining = buildList {
                            for (i in 0 until remainingCandidateDigits.length()) {
                                val d = remainingCandidateDigits.optInt(i, -1)
                                if (d in 1..9) add(d)
                            }
                        }.distinct().sorted()

                        if (remaining.isNotEmpty()) {
                            putCell(focusIdx, "target_remaining", candidates = remaining)
                        }
                    }

                } else if (claimCode == "FISH_LOCKS_DIGIT") {
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }

                    val base = args.optJSONObject("base")
                    val cover = args.optJSONObject("cover")
                    val corners = args.optJSONArray("corners") ?: org.json.JSONArray()
                    val sweep = args.optJSONArray("sweep_cells") ?: org.json.JSONArray()

                    // Highlight base houses + cover houses
                    if (base != null) {
                        val t = base.optString("type")
                        val idxs = base.optJSONArray("indices") ?: org.json.JSONArray()
                        for (i in 0 until idxs.length()) {
                            val h = idxs.optInt(i, -1)
                            if (h in 1..9) putHouse(t, h, "primary_house")
                        }
                    }
                    if (cover != null) {
                        val t = cover.optString("type")
                        val idxs = cover.optJSONArray("indices") ?: org.json.JSONArray()
                        for (i in 0 until idxs.length()) {
                            val h = idxs.optInt(i, -1)
                            if (h in 1..9) putHouse(t, h, "secondary_house")
                        }
                    }

                    // Corner cells (also add links between adjacent corners if possible)
                    val cornerIdxs = ArrayList<Int>()
                    for (i in 0 until corners.length()) {
                        val idx = corners.optInt(i, -1)
                        if (idx in 0..80) {
                            cornerIdxs += idx
                            putCell(idx, "link_a", digit)
                        }
                    }

                    // Emit link highlights for consecutive corners (visual sugar; safe if renderer ignores kind=link)
                    if (cornerIdxs.size >= 2) {
                        for (i in 0 until cornerIdxs.size - 1) {
                            hi.put(
                                org.json.JSONObject().apply {
                                    put("kind", "link")
                                    put("fromCellIndex", cornerIdxs[i])
                                    put("toCellIndex", cornerIdxs[i + 1])
                                    put("role", "inference_link")
                                    if (digit != null) put("digit", digit)
                                }
                            )
                        }
                    }

                    // Sweep eliminations
                    for (i in 0 until sweep.length()) {
                        val idx = sweep.optInt(i, -1)
                        if (idx in 0..80) {
                            putCell(idx, "peer")
                            if (digit != null) putCell(idx, "eliminate_digit", digit)
                        }
                    }

                } else if (claimCode == "EITHER_WAY_ELIMINATION") {
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }
                    val hinge = args.optInt("hinge", -1).takeIf { it in 0..80 }
                    val pincers = args.optJSONArray("pincers") ?: org.json.JSONArray()
                    val target = args.optInt("target_eliminate", -1).takeIf { it in 0..80 }

                    if (hinge != null) putCell(hinge, "link_a", digit)

                    val pList = ArrayList<Int>()
                    for (i in 0 until pincers.length()) {
                        val idx = pincers.optInt(i, -1)
                        if (idx in 0..80) {
                            pList += idx
                            putCell(idx, "link_b", digit)
                            // Optional link from hinge to pincer
                            if (hinge != null) {
                                hi.put(
                                    org.json.JSONObject().apply {
                                        put("kind", "link")
                                        put("fromCellIndex", hinge)
                                        put("toCellIndex", idx)
                                        put("role", "inference_link")
                                        if (digit != null) put("digit", digit)
                                    }
                                )
                            }
                        }
                    }

                    if (target != null) {
                        putCell(target, "peer")
                        if (digit != null) putCell(target, "eliminate_digit", digit)
                    }

                } else if (claimCode == "CHAIN_COLORING" || claimCode == "CONTRADICTION_IMPLES_NOT") {
                    val args = claim.optJSONObject("args") ?: org.json.JSONObject()
                    val digit = args.optInt("digit", -1).takeIf { it in 1..9 }

                    val a = args.optJSONArray("colorA") ?: org.json.JSONArray()
                    val b = args.optJSONArray("colorB") ?: org.json.JSONArray()

                    for (i in 0 until a.length()) {
                        val idx = a.optInt(i, -1)
                        if (idx in 0..80) putCell(idx, "link_a", digit)
                    }
                    for (i in 0 until b.length()) {
                        val idx = b.optInt(i, -1)
                        if (idx in 0..80) putCell(idx, "link_b", digit)
                    }

                    val eliminate = args.optInt("eliminate_cell", -1).takeIf { it in 0..80 }
                    if (eliminate != null) {
                        putCell(eliminate, "peer")
                        if (digit != null) putCell(eliminate, "eliminate_digit", digit)
                    }



                } else if (beatKind == "LOCK_IN") {
                    // --- Lock-in generic:
                    // Hidden singles: eliminated_peer_cell_indices[]
                    // Naked singles: eliminated_digits[] + remaining_digit on the focus cell
                    val w0 = atom.optJSONArray("witnesses")?.optJSONObject(0)
                    val because = w0?.optJSONObject("because") ?: org.json.JSONObject()

                    // (A) House-centric lock-in (Hidden Single): eliminate target digit from peer cells
                    val eliminatedPeers = because.optJSONArray("eliminated_peer_cell_indices") ?: org.json.JSONArray()
                    val targetDigit = atom.optJSONObject("focus")?.optInt("target_digit", -1)?.takeIf { it in 1..9 }

                    for (i in 0 until eliminatedPeers.length()) {
                        val eIdx = eliminatedPeers.optInt(i, -1)
                        if (eIdx in 0..80) {
                            putCell(eIdx, "peer")
                            if (targetDigit != null) putCell(eIdx, "eliminate_digit", targetDigit)
                        }
                    }

                    // (B) Cell-centric lock-in:
                    // show a clean collapse cue on the target cell instead of stacking many overlapping top-right digits.
                    val eliminatedDigits = because.optJSONArray("eliminated_digits")
                    if (eliminatedDigits != null && focusIdx in 0..80) {
                        val eliminated = buildList {
                            for (i in 0 until eliminatedDigits.length()) {
                                val d = eliminatedDigits.optInt(i, -1)
                                if (d in 1..9) add(d)
                            }
                        }.distinct().sorted()

                        if (eliminated.isNotEmpty()) {
                            putCell(focusIdx, "target_eliminations", candidates = eliminated)
                        }

                        val remainingDigit = because.optInt("remaining_digit", -1)
                        if (remainingDigit in 1..9) {
                            putCell(focusIdx, "target_remaining", candidates = listOf(remainingDigit))
                        }
                    }
                } else {
                    // SPOTLIGHT / TEACHING_NOTE: focus + house context already present.
                }

                val storyPayload = currentStoryContextPayloadOrNull(s)
                val storyStageMeta = storyPayload?.optString("story_stage").orEmpty()
                val confrontationOverlayVariant =
                    storyPayload?.optString("confrontation_overlay_variant").orEmpty()
                val resolutionOverlayVariant =
                    storyPayload?.optString("resolution_overlay_variant").orEmpty()

                obj.put("highlights", hi)
                obj.put(
                    "meta",
                    obj.optJSONObject("meta")
                        ?.put("beat_kind", beatKind)
                        ?.put("claim_code", claimCode)
                        ?.put("archetype", atom?.optString("archetype").orEmpty())
                        ?.put(
                            "story_stage",
                            storyStageMeta.ifBlank { JSONObject.NULL }
                        )
                        ?.put(
                            "confrontation_overlay_variant",
                            confrontationOverlayVariant.ifBlank { JSONObject.NULL }
                        )
                        ?.put(
                            "confrontation_proof_frame",
                            storyStageMeta == StoryStage.CONFRONTATION.name && atomIndex >= 1
                        )
                        ?.put(
                            "confrontation_visual_contract_enforced",
                            storyStageMeta == StoryStage.CONFRONTATION.name &&
                                    atomIndex >= 1 &&
                                    confrontationOverlayVariant.isNotBlank()
                        )
                        ?.put(
                            "resolution_overlay_variant",
                            resolutionOverlayVariant.ifBlank { JSONObject.NULL }
                        )
                        ?.put(
                            "resolution_commit_frame",
                            storyStageMeta == StoryStage.RESOLUTION.name &&
                                    (beatKind == "COMMIT" || atomIndex >= 0)
                        )
                        ?.put(
                            "resolution_visual_contract_enforced",
                            storyStageMeta == StoryStage.RESOLUTION.name &&
                                    resolutionOverlayVariant.isNotBlank()
                        )
                )
                obj.toString()
            }.getOrElse {
                obj.put("highlights", org.json.JSONArray())
                obj.toString()
            }
        }


        // Try to find overlay frame in SolveStepV2 JSON
        val stepJson = s.solveStepJson
        if (stepJson.isNullOrBlank()) {
            // Fallback to reveal-only payload (still valid JSON contract)
            val rev = cp?.reveal
            if (rev != null) {
                val ridx = rev.placementCellIndex
                val rdig = rev.placementDigit
                if (ridx in 0..80 && rdig in 1..9) {
                    obj.put(
                        "reveal",
                        org.json.JSONObject()
                            .put("cellIndex", ridx)
                            .put("digit", rdig)
                            .put("explain", rev.explain ?: "")
                    )
                }
            }
            obj.put("highlights", org.json.JSONArray())
            return obj.toString()
        }

        return runCatching {
            val root = org.json.JSONObject(stepJson)

            // overlay_frames[] expected (SolveStepV2)
            val frames = root.optJSONArray("overlay_frames")
            val picked: org.json.JSONObject? = frames?.let {
                var found: org.json.JSONObject? = null
                for (i in 0 until it.length()) {
                    val f = it.optJSONObject(i) ?: continue
                    val fid = f.optString("frame_id").trim()
                    if (fid.equals(frameId, ignoreCase = true)) {
                        found = f
                        break
                    }
                }
                found
            }

            // Put reveal ONLY if this is reveal frame (or the frame explicitly contains reveal)
            val revealFromFrame = picked?.optJSONObject("reveal")
            val wantReveal = frameId.equals("reveal", ignoreCase = true)

            val rev = when {
                revealFromFrame != null -> revealFromFrame
                wantReveal && cp?.reveal != null -> {
                    org.json.JSONObject()
                        .put("cellIndex", cp.reveal.placementCellIndex)
                        .put("digit", cp.reveal.placementDigit)
                        .put("explain", cp.reveal.explain ?: "")
                }
                else -> null
            }

            if (rev != null) obj.put("reveal", rev)

            // Copy highlights straight through (your view already consumes: kind/cellIndex/house/role/digit)
            val hi = picked?.optJSONArray("highlights") ?: org.json.JSONArray()
            obj.put("highlights", hi)

            obj.toString()
        }.getOrElse {
            // Defensive fallback
            obj.put("highlights", org.json.JSONArray())
            obj.toString()
        }
    }

    // ------------------------------------------------------------
    // Phase 2 North Star: overlay choreography must match story scope.
    // We render a composite overlay built from overlays.applied_frame_ids
    // (which is authored deterministically by Maps / conductor).
    // ------------------------------------------------------------
    private fun currentAppliedOverlayFrameIdsOrNull(s: SudoState): List<String>? {
        s.activeAppliedOverlayFrameIdsV1
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .distinct()
            .takeIf { it.isNotEmpty() }
            ?.let { return it }

        // Transitional fallback for older paths that may still rewrite bundles directly.
        val packet = s.solvingReadyFactBundlesV1.firstOrNull { it.type == FactBundleV1.Type.SOLVING_STEP_PACKET_V1 }
        val overlaysObj = packet?.payload?.optJSONObject("overlays")
        val arr = overlaysObj?.optJSONArray("applied_frame_ids") ?: return null

        val out = mutableListOf<String>()
        for (i in 0 until arr.length()) {
            val id = arr.optString(i, "").trim()
            if (id.isNotBlank()) out.add(id)
        }
        return out.takeIf { it.isNotEmpty() }
    }

    private fun authoritativeAppliedOverlayFrameIdsForRenderV1(
        s: SudoState
    ): List<String> {
        val liveUserDetour =
            s.pending is Pending.UserAgendaBridge &&
                    s.activeOverlayOwnerV1 == OverlayOwnerV1.USER_OWNER &&
                    s.detourState?.isActive == true

        if (liveUserDetour) {
            val detourFrames =
                s.detourState?.detourAppliedFrameIds
                    .orEmpty()
                    .map { it.trim() }
                    .filter { it.isNotBlank() }
                    .distinct()

            if (detourFrames.isNotEmpty()) return detourFrames

            val activeDetourFrames =
                s.activeAppliedOverlayFrameIdsV1
                    .map { it.trim() }
                    .filter { it.isNotBlank() && it.startsWith("detour:", ignoreCase = true) }
                    .distinct()

            if (activeDetourFrames.isNotEmpty()) return activeDetourFrames
        }

        return currentAppliedOverlayFrameIdsOrNull(s).orEmpty()
    }

    private fun shouldRenderDetourNativeOverlayV1(
        s: SudoState,
        appliedFrameIds: List<String>
    ): Boolean {
        val liveUserDetour =
            s.pending is Pending.UserAgendaBridge &&
                    s.activeOverlayOwnerV1 == OverlayOwnerV1.USER_OWNER &&
                    s.detourState?.isActive == true &&
                    s.detourNarrativeContextV1 != null

        if (!liveUserDetour) return false

        if (appliedFrameIds.any { it.startsWith("detour:", ignoreCase = true) }) return true

        return s.detourState?.detourAppliedFrameIds
            .orEmpty()
            .any { it.startsWith("detour:", ignoreCase = true) }
    }

    private fun currentStoryContextPayloadOrNull(s: SudoState): org.json.JSONObject? {
        return s.solvingReadyFactBundlesV1
            .firstOrNull { it.type == FactBundleV1.Type.STORY_CONTEXT_V1 }
            ?.payload
    }


    private fun summarizeOverlayForCellV1(
        frameJson: String,
        targetCellIndex: Int
    ): Map<String, Any?> {
        return runCatching {
            val root = org.json.JSONObject(frameJson)
            val highlights = root.optJSONArray("highlights") ?: org.json.JSONArray()

            val hits = mutableListOf<Map<String, Any?>>()

            for (i in 0 until highlights.length()) {
                val h = highlights.optJSONObject(i) ?: continue
                if (h.optString("kind") != "cell") continue
                if (h.optInt("cellIndex", -1) != targetCellIndex) continue

                hits += mapOf(
                    "i" to i,
                    "role" to h.optString("role"),
                    "digit" to if (h.has("digit")) h.optInt("digit", -1) else null
                )
            }

            mapOf(
                "target_cell_index" to targetCellIndex,
                "hits" to hits,
                "last_hit" to hits.lastOrNull()
            )
        }.getOrElse { t ->
            mapOf(
                "target_cell_index" to targetCellIndex,
                "error" to (t.message ?: t.javaClass.simpleName)
            )
        }

    }



    private fun detourOverlayCellRoleFromVisualRoleV1(role: String?): String {
        val normalized = role?.trim()?.lowercase().orEmpty()
        return when (normalized) {
            "focus",
            "pattern_member",
            "candidate_focus",
            "occupied",
            "surviving_seat" -> "focus"

            "witness",
            "blocker",
            "rival",
            "scan_point" -> "witness"

            "eliminated_seat",
            "blocked",
            "eliminated" -> "elimination"

            "target_remaining",
            "survives" -> "target_remaining"

            "peer" -> "peer"

            else -> if (normalized.isNotEmpty()) normalized else "focus"
        }
    }

    private fun detourOverlayHouseRoleFromVisualRoleV1(role: String?): String {
        val normalized = role?.trim()?.lowercase().orEmpty()
        return when (normalized) {
            "arena",
            "blocking_house",
            "target_house",
            "supporting_house",
            "comparison_house",
            "pattern_house",
            "scan_house" -> "primary_house"

            else -> "primary_house"
        }
    }


    private fun buildDetourOverlayCompositeFrameJsonV1(
        s: SudoState,
        frameIds: List<String>,
        style: String,
        reason: String
    ): String {
        val ctx = s.detourNarrativeContextV1
        val normalizedFrameIds =
            frameIds
                .filter { it.isNotBlank() }
                .distinct()

        val effectiveFrameIds =
            if (normalizedFrameIds.isNotEmpty()) {
                normalizedFrameIds
            } else {
                detourNativeOverlayFrameIdsV1(s, ctx)
            }

        val enabledLayers = effectiveFrameIds.toSet()
        val metaFrameId = "detour:stack:${sha12(effectiveFrameIds.joinToString("|")).take(12)}"

        val obj = org.json.JSONObject()
            .put("v", 1)
            .put(
                "meta",
                org.json.JSONObject()
                    .put("reason", reason)
                    .put("style", style)
                    .put("frame_id", metaFrameId)
                    .put("applied_frame_ids", org.json.JSONArray(effectiveFrameIds))
                    .put("grid_hash12", (s.coachPlanGridHash12 ?: s.solveStepGridHash12 ?: "").take(12))
                    .put("story_stage", JSONObject.NULL)
                    .put("detour_archetype", ctx?.archetype?.name ?: JSONObject.NULL)
                    .put("detour_overlay_mode", ctx?.overlayPolicy?.overlayMode?.name ?: JSONObject.NULL)
                    .put("detour_story_kind", ctx?.visualContract?.storyKind ?: JSONObject.NULL)
            )

        if (ctx == null) {
            obj.put("focus", org.json.JSONObject().put("cellIndex", org.json.JSONObject.NULL))
            obj.put("highlights", org.json.JSONArray())
            return obj.toString()
        }

        val hi = org.json.JSONArray()
        val emitted = linkedSetOf<String>()
        val visual = ctx.visualContract

        fun layerEnabled(layer: String): Boolean =
            enabledLayers.isEmpty() || enabledLayers.contains(layer)

        fun putHouse(
            houseRef: String?,
            role: String
        ) {
            val parsed = parseDetourHouseRefForOverlayV1(houseRef) ?: return
            val (type, idx) = parsed
            if (type.isBlank() || idx !in 1..9) return

            val key = "house|$type|$idx|$role"
            if (!emitted.add(key)) return

            hi.put(
                org.json.JSONObject().apply {
                    put("kind", "house")
                    put("role", role)
                    put(
                        "house",
                        org.json.JSONObject().apply {
                            put("type", type)
                            put("index1to9", idx)
                        }
                    )
                }
            )
        }

        fun putCell(
            cellRef: String?,
            role: String,
            digit: Int? = null,
            candidates: List<Int>? = null
        ) {
            val cellIndex = parseCellRefToIndexV1(cellRef) ?: return
            val normalizedCandidates =
                candidates
                    ?.filter { it in 1..9 }
                    ?.distinct()
                    ?.sorted()
                    .orEmpty()

            val key =
                buildString {
                    append("cell|")
                    append(cellIndex)
                    append("|")
                    append(role)
                    append("|")
                    append(digit ?: "null")
                    append("|")
                    append(normalizedCandidates.joinToString(","))
                }

            if (!emitted.add(key)) return

            hi.put(
                org.json.JSONObject().apply {
                    put("kind", "cell")
                    put("cellIndex", cellIndex)
                    put("role", role)
                    if (digit != null) put("digit", digit)
                    if (normalizedCandidates.isNotEmpty()) {
                        put(
                            "candidates",
                            org.json.JSONArray().apply {
                                normalizedCandidates.forEach { put(it) }
                            }
                        )
                    }
                }
            )
        }

        val primaryCells = linkedSetOf<String>()
        val secondaryCells = linkedSetOf<String>()
        val houseRefs = linkedSetOf<String>()
        val deemphasizeCells = linkedSetOf<String>()

        if (layerEnabled("detour:primary")) {
            visual.primaryCells
                .map { it.cellRef.trim() }
                .filter { it.isNotEmpty() }
                .forEach { primaryCells += it }
        }

        if (layerEnabled("detour:secondary")) {
            visual.secondaryCells
                .map { it.cellRef.trim() }
                .filter { it.isNotEmpty() }
                .forEach { secondaryCells += it }
        }

        if (layerEnabled("detour:houses")) {
            visual.houses
                .map { it.houseRef.trim() }
                .filter { it.isNotEmpty() }
                .forEach { houseRefs += it }
        }

        if (layerEnabled("detour:deemphasize")) {
            visual.deemphasizeCells
                .map { it.trim() }
                .filter { it.isNotEmpty() }
                .forEach { deemphasizeCells += it }
        }

        if (primaryCells.isEmpty() && layerEnabled("detour:primary")) {
            choosePrimaryDetourFocusCellV1(ctx)?.let { primaryCells += it }
        }

        if (secondaryCells.isEmpty() && layerEnabled("detour:secondary")) {
            chooseSecondaryDetourFocusCellsV1(ctx).forEach { secondaryCells += it }
        }

        if (houseRefs.isEmpty() && layerEnabled("detour:houses")) {
            detourVisualHouseRefsV1(ctx).forEach { houseRefs += it }
            if (houseRefs.isEmpty()) {
                ctx.overlayPolicy.primaryFocusHouses
                    .map { it.trim() }
                    .filter { it.isNotEmpty() }
                    .forEach { houseRefs += it }
            }
            if (houseRefs.isEmpty()) {
                detourGenericFallbackHouseRefsV1(ctx).forEach { houseRefs += it }
            }
        }

        if (deemphasizeCells.isEmpty() && layerEnabled("detour:deemphasize")) {
            ctx.overlayPolicy.deemphasizeCells
                .map { it.trim() }
                .filter { it.isNotEmpty() }
                .forEach { deemphasizeCells += it }
        }

        val focusCellRef =
            choosePrimaryDetourFocusCellV1(ctx)
                ?: primaryCells.firstOrNull()

        val focusCellIndex = parseCellRefToIndexV1(focusCellRef)
        obj.put("focus", org.json.JSONObject().put("cellIndex", focusCellIndex ?: org.json.JSONObject.NULL))

        if (layerEnabled("detour:houses")) {
            visual.houses.forEach { house ->
                putHouse(
                    houseRef = house.houseRef,
                    role = detourOverlayHouseRoleFromVisualRoleV1(house.role)
                )
            }

            houseRefs
                .filter { ref -> visual.houses.none { it.houseRef.equals(ref, ignoreCase = true) } }
                .forEach { putHouse(it, "primary_house") }
        }

        if (layerEnabled("detour:primary")) {
            visual.primaryCells.forEach { cell ->
                val overlayRole = detourOverlayCellRoleFromVisualRoleV1(cell.role)
                if (cell.candidateDigits.isNotEmpty()) {
                    putCell(
                        cellRef = cell.cellRef,
                        role = overlayRole,
                        candidates = cell.candidateDigits
                    )
                } else {
                    putCell(
                        cellRef = cell.cellRef,
                        role = overlayRole,
                        digit = cell.digit
                    )
                }
            }

            primaryCells
                .filter { ref -> visual.primaryCells.none { it.cellRef.equals(ref, ignoreCase = true) } }
                .forEach { putCell(it, "focus") }
        }

        if (layerEnabled("detour:secondary")) {
            visual.secondaryCells.forEach { cell ->
                val overlayRole = detourOverlayCellRoleFromVisualRoleV1(cell.role)
                if (cell.candidateDigits.isNotEmpty()) {
                    putCell(
                        cellRef = cell.cellRef,
                        role = overlayRole,
                        candidates = cell.candidateDigits
                    )
                } else {
                    putCell(
                        cellRef = cell.cellRef,
                        role = overlayRole,
                        digit = cell.digit
                    )
                }
            }

            secondaryCells
                .filter { ref ->
                    visual.secondaryCells.none { it.cellRef.equals(ref, ignoreCase = true) } &&
                            ref !in primaryCells
                }
                .forEach { putCell(it, "witness") }
        }

        visual.candidateMarks.forEach { mark ->
            val overlayRole = detourOverlayCellRoleFromVisualRoleV1(mark.role)
            when (overlayRole) {
                "elimination",
                "target_remaining" ->
                    putCell(
                        cellRef = mark.cellRef,
                        role = overlayRole,
                        candidates = listOf(mark.digit)
                    )

                else ->
                    putCell(
                        cellRef = mark.cellRef,
                        role = overlayRole,
                        digit = mark.digit
                    )
            }
        }

        if (layerEnabled("detour:deemphasize")) {
            deemphasizeCells
                .filter { it !in primaryCells && it !in secondaryCells }
                .forEach { putCell(it, "peer") }
        }

        obj.put("highlights", hi)
        return obj.toString()
    }



    private fun buildSolveOverlayCompositeFrameJsonV1(
        s: SudoState,
        frameIds: List<String>,
        style: String,
        reason: String
    ): String {

        val normalizedFrameIds =
            frameIds
                .filter { it.isNotBlank() }
                .distinct()

        if (normalizedFrameIds.any { it.startsWith("detour:", ignoreCase = true) }) {
            return buildDetourOverlayCompositeFrameJsonV1(
                s = s,
                frameIds = normalizedFrameIds,
                style = style,
                reason = reason
            )
        }

        // Fallback: render single frame if list is empty
        if (normalizedFrameIds.isEmpty()) {
            val fid = currentSolveOverlayFrameId(s, s.solveAtomIndex)
            return buildSolveOverlayFrameJsonV1(s, fid, style, reason = "$reason:fallback_single")
        }

        // Base object (v=1) consumed by SudokuResultView.setSolveOverlayFromJson()
        val storyPayload = currentStoryContextPayloadOrNull(s)

        val storyStageMeta = storyPayload?.optString("story_stage").orEmpty()
        val confrontationOverlayVariant =
            storyPayload?.optString("confrontation_overlay_variant").orEmpty()
        val resolutionOverlayVariant =
            storyPayload?.optString("resolution_overlay_variant").orEmpty()

        val metaFrameId = "ov:stack:${sha12(normalizedFrameIds.joinToString("|")).take(12)}"
        val obj = org.json.JSONObject()
            .put("v", 1)
            .put(
                "meta",
                org.json.JSONObject()
                    .put("reason", reason)
                    .put("style", style)
                    .put("frame_id", metaFrameId)
                    .put("applied_frame_ids", org.json.JSONArray(normalizedFrameIds))
                    .put("grid_hash12", (s.coachPlanGridHash12 ?: s.solveStepGridHash12 ?: "").take(12))
                    .put("story_stage", storyStageMeta.ifBlank { JSONObject.NULL })
                    .put(
                        "confrontation_overlay_variant",
                        confrontationOverlayVariant.ifBlank { JSONObject.NULL }
                    )
                    .put(
                        "confrontation_visual_contract_enforced",
                        storyStageMeta == StoryStage.CONFRONTATION.name &&
                                confrontationOverlayVariant.isNotBlank()
                    )
                    .put(
                        "resolution_overlay_variant",
                        resolutionOverlayVariant.ifBlank { JSONObject.NULL }
                    )
                    .put(
                        "resolution_visual_contract_enforced",
                        storyStageMeta == StoryStage.RESOLUTION.name &&
                                resolutionOverlayVariant.isNotBlank()
                    )
            )

        // Keep focus in JSON so MainActivity can still drive the separate yellow confirmation ring.
        val cp = s.coachPlan
        val focusIdx = (cp?.focusCellIndex ?: s.focusCellIndex).takeIf { it in 0..80 }
        obj.put("focus", org.json.JSONObject().put("cellIndex", focusIdx ?: org.json.JSONObject.NULL))

        val hiOut = org.json.JSONArray()

        fun keyOf(h: org.json.JSONObject): String {
            val kind = h.optString("kind", "")
            val role = h.optString("role", "")
            val cellIndex = h.optInt("cellIndex", -1)
            val digit = if (h.has("digit")) h.optInt("digit", -1) else -1
            val house = h.optJSONObject("house")
                ?.let { "${it.optString("type", "")}:${it.optInt("index1to9", -1)}" }
                ?: ""
            val fromIdx = when {
                h.has("fromCellIndex") -> h.optInt("fromCellIndex", -1)
                h.has("from_cell_index") -> h.optInt("from_cell_index", -1)
                else -> -1
            }
            val toIdx = when {
                h.has("toCellIndex") -> h.optInt("toCellIndex", -1)
                h.has("to_cell_index") -> h.optInt("to_cell_index", -1)
                else -> -1
            }
            return "$kind|$role|$cellIndex|$digit|$house|$fromIdx|$toIdx"
        }

        fun roleRank(roleRaw: String): Int {
            return when (roleRaw.trim().lowercase()) {
                // strongest / latest semantic state first
                "result_place" -> 700
                "reveal" -> 650
                "subset_candidates" -> 650
                "confined_digit" -> 640
                "lock_digit" -> 600

                // proof roles
                "witness" -> 500
                "eliminate_digit" -> 400

                // weaker contextual cell roles
                "peer" -> 200
                "focus" -> 100

                else -> 0
            }
        }

        fun betterCellHighlight(newH: org.json.JSONObject, oldH: org.json.JSONObject?): Boolean {
            if (oldH == null) return true

            val newRole = newH.optString("role", "")
            val oldRole = oldH.optString("role", "")

            val nr = roleRank(newRole)
            val orr = roleRank(oldRole)

            if (nr != orr) return nr > orr

            // Tie-breakers:
            // 1) prefer highlight carrying a digit
            val newHasDigit = newH.has("digit")
            val oldHasDigit = oldH.has("digit")
            if (newHasDigit != oldHasDigit) return newHasDigit

            // 2) if still tied, later one wins
            return true
        }

        var revealPicked: org.json.JSONObject? = null

        // Non-cell highlights still union across all applied frames.
        val nonCellSeen = HashSet<String>()

        // Cell ownership = highest frame touching that cell wins.
        val ownerFramePosByCell = HashMap<Int, Int>()

        // Within the owner frame, exactly ONE strongest cell-level highlight survives per cell.
        val ownerBestCellHighlightByCell = HashMap<Int, org.json.JSONObject>()

        for ((framePos, fid) in normalizedFrameIds.withIndex()) {
            val one = runCatching {
                org.json.JSONObject(
                    buildSolveOverlayFrameJsonV1(
                        s = s,
                        frameId = fid,
                        style = style,
                        reason = "$reason:piece:$fid"
                    )
                )
            }.getOrNull() ?: continue

            // Carry reveal if any piece has it (prefer the last one)
            val rev = one.optJSONObject("reveal")
            if (rev != null) revealPicked = rev

            val hi = one.optJSONArray("highlights") ?: org.json.JSONArray()
            for (i in 0 until hi.length()) {
                val h = hi.optJSONObject(i) ?: continue
                val kind = h.optString("kind", "").trim().lowercase()

                if (kind == "cell") {
                    val idx = if (h.has("cellIndex")) h.optInt("cellIndex", -1) else -1
                    if (idx !in 0..80) continue

                    val currentOwnerPos = ownerFramePosByCell[idx]

                    when {
                        currentOwnerPos == null || framePos > currentOwnerPos -> {
                            // Higher frame takes ownership of this cell.
                            ownerFramePosByCell[idx] = framePos
                            ownerBestCellHighlightByCell[idx] = h
                        }

                        framePos == currentOwnerPos -> {
                            // Same owner frame: keep only the strongest cell highlight.
                            val currentBest = ownerBestCellHighlightByCell[idx]
                            if (betterCellHighlight(h, currentBest)) {
                                ownerBestCellHighlightByCell[idx] = h
                            }
                        }

                        else -> {
                            // Lower frame lost ownership for this cell.
                        }
                    }
                } else {
                    val k = keyOf(h)
                    if (nonCellSeen.add(k)) hiOut.put(h)
                }
            }
        }

        // Append owned cell highlights in frame order, then cell index order for stability.
        val orderedCells = ownerFramePosByCell.entries
            .sortedWith(compareBy<Map.Entry<Int, Int>>({ it.value }, { it.key }))

        for ((cellIdx, _) in orderedCells) {
            val h = ownerBestCellHighlightByCell[cellIdx] ?: continue
            hiOut.put(h)
        }

        obj.put("highlights", hiOut)
        if (revealPicked != null) obj.put("reveal", revealPicked)

        return obj.toString()
    }

    private fun currentSolveOverlayFrameId(s: SudoState, atomIndex: Int): String {
        val explicitFrames =
            currentAppliedOverlayFrameIdsOrNull(s)
                .orEmpty()
                .filter { it.isNotBlank() }

        if (explicitFrames.isNotEmpty()) {
            return explicitFrames.first()
        }

        // Prefer narrative-atom overlays when atoms exist (Phase 1+ truth).
        val stepJson = s.solveStepJson
        if (!stepJson.isNullOrBlank()) {
            val env = safeJsonObjectFromString(stepJson, tag = "solve_step_for_frame")
            val stepObj = runCatching { env.optJSONObject("step") ?: env }.getOrNull() ?: env
            val grid81Now = runCatching { s.grid?.llm?.let { grid81FromLLM(it) } }.getOrNull()
            val atoms = runCatching {
                com.contextionary.sudoku.conductor.solving.NarrativeAtomGeneratorV1
                    .buildNarrativeAtomsV1(stepObj, grid81Now)
                    .optJSONArray("atoms")
            }.getOrNull()

            if (atoms != null && atoms.length() > 0) {
                return "ov:atom:$atomIndex"
            }
        }

        // Fallback: CoachPlan pinned frame ids (legacy)
        val hint = s.coachPlan?.hints?.getOrNull(atomIndex)
        val pinned = hint?.overlayFrameId?.trim().orEmpty()
        if (pinned.isNotEmpty()) return pinned

        // Final fallback: old frame ids
        return "h$atomIndex"
    }

    // 1–3 lines, deterministic, safe for prompt.
    private fun engineStepSummaryForPrompt(s: SudoState): String? {
        // Prefer typed plan if present
        s.coachPlan?.let { plan ->
            val title = plan.title?.trim().orEmpty()
            val firstHint = plan.hints.firstOrNull()?.text?.trim().orEmpty()
            val a = title.takeIf { it.isNotBlank() } ?: "Next step"
            val b = firstHint.takeIf { it.isNotBlank() } ?: return a
            return listOf(a, b).joinToString("\n").lines().take(3).joinToString("\n").trim()
        }

        // Fallback: raw engine JSON/text already stored
        val raw = s.solveStepJson?.trim().orEmpty()
        if (raw.isBlank()) return null

        // Take first 3 non-empty lines, cap each line length.
        val lines = raw
            .replace("\r\n", "\n")
            .split('\n')
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .take(3)
            .map { it.take(140) }

        return lines.joinToString("\n").trim().takeIf { it.isNotBlank() }
    }




    private fun buildStateHeader(s: SudoState): String {

        // --- Pending (human + machine friendly) ---
        val pendingHuman = when (val pending = s.pending) {
            null -> "pending:none"

            is Pending.ConfirmEdit -> {
                val idx = pending.cellIndex.coerceIn(0, 80)
                val row = (idx / 9) + 1
                val col = (idx % 9) + 1
                "pending:confirm_edit idx=$idx row=$row col=$col digit=${pending.proposedDigit}"
            }

            is Pending.AskCellValue -> {
                val idx = pending.cellIndex.coerceIn(0, 80)
                val row = (idx / 9) + 1
                val col = (idx % 9) + 1
                "pending:ask_cell_value idx=$idx row=$row col=$col"
            }

            is Pending.ConfirmRetake -> "pending:confirm_retake strength=${pending.strength}"
            is Pending.ConfirmValidate -> "pending:confirm_validate"
            is Pending.VisualVerifyMatch -> "pending:visual_verify_match"
            is Pending.ConfirmStartSolving -> "pending:confirm_start_solving"
            is Pending.ConfirmInterpretation -> "pending:confirm_interpretation row=${pending.row} col=${pending.col} digit=${pending.digit}"
            is Pending.AskClarification -> "pending:ask_clarification kind=${pending.kind} row=${pending.rowHint} col=${pending.colHint} digit=${pending.digitHint}"
            is Pending.WaitForTap -> "pending:wait_for_tap digitHint=${pending.digitHint}"

            else -> "pending:other type=${pending.javaClass.simpleName ?: "unknown"}"
        }

        // Explicit key for parsing (recommended)
        val pendingKey = when (val p = s.pending) {
            null -> "NONE"
            is Pending.ConfirmEdit -> "CONFIRM_EDIT"
            is Pending.AskCellValue -> "ASK_CELL_VALUE"
            is Pending.ConfirmRetake -> "CONFIRM_RETAKE"
            is Pending.ConfirmValidate -> "CONFIRM_VALIDATE"
            is Pending.VisualVerifyMatch -> "VISUAL_VERIFY_MATCH"
            is Pending.ConfirmStartSolving -> "CONFIRM_START_SOLVING"
            is Pending.ConfirmInterpretation -> "CONFIRM_INTERPRETATION"
            is Pending.AskClarification -> "ASK_CLARIFICATION"
            is Pending.WaitForTap -> "WAIT_FOR_TAP"

            // ✅ SOLVING CTA pendings (stage-native)
            is Pending.SolveIntroAction.SetupAction -> "SOLVE_SETUP_ACTION"
            is Pending.SolveIntroAction.ConfrontationAction -> "SOLVE_CONFRONTATION_ACTION"
            is Pending.AfterResolution -> "AFTER_RESOLUTION"
            is Pending.SolveStepMissing -> "SOLVE_STEP_MISSING"
            is Pending.ApplyHintNow -> "APPLY_HINT_NOW"

            else -> "OTHER_${p.javaClass.simpleName ?: "UNKNOWN"}"
        }

        val guidanceKey =
            if (s.phase == GridPhase.SOLVING) "solve_guidance_mode:${s.solveGuidanceMode.name}"
            else "solve_guidance_mode:NA"

        // --- Step 6 flags: validation_mode + pending_policy ---
        val g = llmGrid(s)




        val solvable = (g?.solvability == "unique" || g?.solvability == "multiple")

        val conflictEmpty = (g?.conflictCells?.isEmpty() != false) // true if null or empty
        val mismatchEmpty  = (g?.mismatchCells?.isEmpty() != false) // true if null or empty

        val validationMode =
            if (solvable && conflictEmpty && mismatchEmpty) "GLOBAL" else "CELL_CHECK"

        val pendingPolicy =
            if (validationMode == "GLOBAL") "CANCEL_ON_GLOBAL_VALIDATION" else "NONE"

        // Multiline header (easy to parse by regex)
        val focusIdx = s.focusCellIndex
        val focusCell = focusIdx?.let { indexToCell(it) } ?: ""

// Pending “target cell” + “expected answer kind” are deterministic from Pending type
        val (pendingExpectedKind, pendingTargetCell) = when (val p = s.pending) {
            is Pending.AskCellValue -> "DIGIT" to indexToCell(p.cellIndex)
            is Pending.ConfirmEdit -> "YESNO" to indexToCell(p.cellIndex)
            is Pending.ConfirmRetake -> "YESNO" to ""
            is Pending.ConfirmValidate -> "YESNO" to ""
            is Pending.VisualVerifyMatch -> "YESNO_OR_EDITS" to ""
            is Pending.ConfirmStartSolving -> "YESNO" to ""
            is Pending.ConfirmInterpretation -> "YESNO" to
                    ((p.row?.let { r -> p.col?.let { c -> "r${r}c${c}" } }) ?: "")
            is Pending.AskClarification -> p.kind.name to
                    ((p.rowHint?.let { r -> p.colHint?.let { c -> "r${r}c${c}" } }) ?: "")
            is Pending.WaitForTap -> "TAP" to ""

            // ✅ SOLVING: expose story stage + readiness to Tick1 binder (deterministic CTA binding)
            is Pending.SolveIntroAction -> {
                val stage = p.stage.name
                val ready = (s.narrativeStory?.readyForCommit == true)
                val ek = when (stage) {
                    "CONFRONTATION" -> if (ready) "STORY_CTA_CONFRONTATION_READY" else "STORY_CTA_CONFRONTATION"
                    "RESOLUTION" -> "STORY_CTA_RESOLUTION"
                    else -> "STORY_CTA_SETUP"
                }
                val targetCell =
                    s.activeRouteContext?.targetCellIndex?.let { indexToCell(it) }
                        ?: s.coachPlan?.targetCellIndex?.let { indexToCell(it) }
                        ?: ""
                ek to targetCell
            }

            is Pending.AfterResolution -> {
                val targetCell =
                    s.activeRouteContext?.targetCellIndex?.let { indexToCell(it) }
                        ?: s.coachPlan?.targetCellIndex?.let { indexToCell(it) }
                        ?: ""
                "STORY_POST_COMMIT" to targetCell
            }

            is Pending.SolveStepMissing -> {
                "STORY_STEP_MISSING" to ""
            }

            is Pending.ApplyHintNow -> {
                val targetCell =
                    s.activeRouteContext?.targetCellIndex?.let { indexToCell(it) }
                        ?: s.coachPlan?.targetCellIndex?.let { indexToCell(it) }
                        ?: ""
                "STORY_APPLY_HINT" to targetCell
            }

            else -> "" to ""
        }

        val lastQuestionKey = pendingKey // good enough v1: the pending key *is* the last question key

        return buildString {
            appendLine("mode=${s.mode}")
            appendLine("grid_phase=${s.phase}")
            appendLine("phase=${s.phase}")

            // ✅ NEW: focus (Tick1 needs it; Adapter already expects parseFocusIdxFromHeader)
            appendLine("focus=${focusIdx ?: "none"}")
            appendLine("focus_cell=$focusCell")

            // ✅ NEW: rich pending context for Tick1
            appendLine("pending=$pendingKey")
            appendLine("pending_expected_answer_kind=$pendingExpectedKind")
            appendLine("pending_target_cell=$pendingTargetCell")
            appendLine("last_assistant_question_key=$lastQuestionKey")

            appendLine(guidanceKey)

            // ✅ Phase 1: narrative story context (auditable + Tick2-visible)
            val story = s.narrativeStory

            appendLine("story_present=${story != null}")
            appendLine("story_stage_projection=${story?.stage?.name ?: "NONE"}")
            appendLine("story_step_id=${story?.stepId ?: ""}")

            appendLine("story_grid_hash12=${story?.gridHash12 ?: ""}")
            appendLine("story_atoms_count=${story?.atomsCount ?: 0}")
            appendLine("story_focus_atom_index=${story?.focusAtomIndex?.toString() ?: "none"}")
            appendLine("story_discussed_atoms=${story?.discussedAtomIndices?.joinToString(",") ?: ""}")
            appendLine("story_ready_for_commit=${story?.readyForCommit ?: false}")

            appendLine("validation_mode=$validationMode")
            appendLine("pending_policy=$pendingPolicy")
            appendLine("repairAttempt=${s.repairAttempt}")
            appendLine("turnSeq=${s.turnSeq}")


            appendLine("prefs_language=${s.prefs.language}")
            appendLine("prefs_notation=${s.prefs.notation}")
            appendLine("prefs_evidence_verbosity=${s.prefs.evidenceVerbosity}")
            appendLine("prefs_hint_level=${s.prefs.hintLevel}")
            appendLine("prefs_teach_mode=${s.prefs.teachMode}")
            appendLine("prefs_fast_mode=${s.prefs.fastMode}")
            appendLine("prefs_one_question_max=${s.prefs.oneQuestionMax}")
            appendLine("prefs_only_validate=${s.prefs.onlyValidate}")
            appendLine("prefs_only_solve=${s.prefs.onlySolve}")

            // keep the human line (debug-friendly)
            appendLine(pendingHuman)
        }.trim()
    }
}